local function applyRowLabelStyle(label, styleKeyOrOpts)
    if not label or not label:IsA("TextLabel") then
        return label
    end

    local cfg = ROW_LABEL_THEMES.default
    if type(styleKeyOrOpts) == "string" then
        cfg = ROW_LABEL_THEMES[styleKeyOrOpts] or ROW_LABEL_THEMES.default
    elseif type(styleKeyOrOpts) == "table" then
        cfg = styleKeyOrOpts
    end

    label.TextColor3 = cfg.color or ROW_LABEL_THEMES.default.color
    label.Font = cfg.font or ROW_LABEL_THEMES.default.font
    label.TextSize = cfg.size or ROW_LABEL_THEMES.default.size
    -- no TextStroke — stroke on small labels looks blurry in Roblox
    label.TextStrokeTransparency = 1

    return label
end

