local function createStroke(parent, color, thickness, transparency)
    local s = Instance.new("UIStroke")
    s.Color = color
    s.Thickness = thickness or 1
    s.Transparency = transparency or 0
    s.ApplyStrokeMode = Enum.ApplyStrokeMode.Border
    s.Parent = parent
    return s
end

local function createCorner(parent, radius)
    local c = Instance.new("UICorner")
    c.CornerRadius = UDim.new(0, radius or 8)
    c.Parent = parent
    return c
end

local function tweenColor(obj, prop, to, time)
    time = time or 0.12
    TweenService:Create(obj, TweenInfo.new(time, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {
        [prop] = to
    }):Play()
end



local function makeDraggable(frame, dragHandle)
    dragHandle = dragHandle or frame
    dragHandle.Active = true            -- penting

    local dragging = false
    local dragStart
    local startPos

    dragHandle.InputBegan:Connect(function(input)
        if input.UserInputType == Enum.UserInputType.MouseButton1
        or input.UserInputType == Enum.UserInputType.Touch then
            dragging  = true
            dragStart = input.Position
            startPos  = frame.Position
        end
    end)

    dragHandle.InputEnded:Connect(function(input)
        if input.UserInputType == Enum.UserInputType.MouseButton1
        or input.UserInputType == Enum.UserInputType.Touch then
            dragging  = false
            dragStart = nil
            startPos  = nil
        end
    end)

    UserInputService.InputChanged:Connect(function(input)
        if not dragging then return end

        if input.UserInputType ~= Enum.UserInputType.MouseMovement
        and input.UserInputType ~= Enum.UserInputType.Touch then
            return
        end

        -- 🔐 Guard biar gak error "attempt to index nil with 'X'"
        if not dragStart or not startPos then
            return
        end

        local delta = input.Position - dragStart
        frame.Position = UDim2.new(
            startPos.X.Scale,
            startPos.X.Offset + delta.X,
            startPos.Y.Scale,
            startPos.Y.Offset + delta.Y
        )
    end)
end

local function saveMiniIconPos(frame)
    if not frame then return end
    local G = (getgenv and getgenv()) or _G
    local ap = frame.AnchorPoint
    local pos = frame.Position
    local saved = {
        ax = ap.X, ay = ap.Y,
        xs = pos.X.Scale, xo = pos.X.Offset,
        ys = pos.Y.Scale, yo = pos.Y.Offset,
    }
    G.__GAG2_MINI_ICON_POS = saved
    _G.__GAG2_MINI_ICON_POS = saved
end

local function loadMiniIconPos(frame)
    if not frame then return end
    local G = (getgenv and getgenv()) or _G
    local saved = G.__GAG2_MINI_ICON_POS or _G.__GAG2_MINI_ICON_POS
    if type(saved) ~= "table" then return end
    if saved.ax ~= nil and saved.ay ~= nil then
        frame.AnchorPoint = Vector2.new(tonumber(saved.ax) or 0, tonumber(saved.ay) or 1)
    end
    frame.Position = UDim2.new(
        tonumber(saved.xs) or 0, tonumber(saved.xo) or 16,
        tonumber(saved.ys) or 1, tonumber(saved.yo) or -16
    )
end

-- Drag + klik (restore) — geser > threshold = drag, else = click
local function makeDraggableClickable(frame, dragHandle, onClick, dragThreshold)
    dragHandle = dragHandle or frame
    dragHandle.Active = true
    dragThreshold = tonumber(dragThreshold) or 8

    local dragging = false
    local moved = false
    local dragStart
    local startPos

    dragHandle.InputBegan:Connect(function(input)
        if input.UserInputType == Enum.UserInputType.MouseButton1
        or input.UserInputType == Enum.UserInputType.Touch then
            dragging = true
            moved = false
            dragStart = input.Position
            startPos = frame.Position
        end
    end)

    dragHandle.InputEnded:Connect(function(input)
        if input.UserInputType == Enum.UserInputType.MouseButton1
        or input.UserInputType == Enum.UserInputType.Touch then
            if dragging and not moved and type(onClick) == "function" then
                onClick()
            end
            if dragging and moved then
                saveMiniIconPos(frame)
            end
            dragging = false
            dragStart = nil
            startPos = nil
        end
    end)

    UserInputService.InputChanged:Connect(function(input)
        if not dragging then return end
        if input.UserInputType ~= Enum.UserInputType.MouseMovement
        and input.UserInputType ~= Enum.UserInputType.Touch then
            return
        end
        if not dragStart or not startPos then return end

        local delta = input.Position - dragStart
        if not moved and (math.abs(delta.X) > dragThreshold or math.abs(delta.Y) > dragThreshold) then
            moved = true
        end
        if not moved then return end

        frame.Position = UDim2.new(
            startPos.X.Scale,
            startPos.X.Offset + delta.X,
            startPos.Y.Scale,
            startPos.Y.Offset + delta.Y
        )
    end)
end
