----------------------------------------------------------
function MainUI:CreateRowLabel(parent, text, desc, order, styleKey)
    local row = Instance.new("Frame")
    row.Name = "RowLabel"
    row.BackgroundTransparency = 1
    row.Size = UDim2.new(1, 0, 0, desc and 34 or 22)
    row.AutomaticSize = Enum.AutomaticSize.None
    row.LayoutOrder = order or (#parent:GetChildren() + 1)
    row.Parent = parent

    local title = Instance.new("TextLabel")
    title.BackgroundTransparency = 1
    title.Position = UDim2.new(0, 0, 0, 0)
    title.Size = UDim2.new(1, 0, 0, 18)
    title.Font = Enum.Font.Gotham
    title.TextXAlignment = Enum.TextXAlignment.Left
    title.TextSize = 12
    title.Text = text or ""
    title.Parent = row
    applyRowLabelStyle(title, styleKey or "default")

    if desc and desc ~= "" then
        local sub = Instance.new("TextLabel")
        sub.BackgroundTransparency = 1
        sub.Position = UDim2.new(0, 0, 0, 18)
        sub.Size = UDim2.new(1, 0, 0, 14)
        sub.Font = Enum.Font.Gotham
        sub.TextXAlignment = Enum.TextXAlignment.Left
        sub.TextSize = 11
        sub.Text = desc
        sub.Parent = row
        applyRowLabelStyle(sub, "info")
    end

    -- ⬅️ Tambah return kedua (title)
    return row, title
end


----------------------------------------------------------
-- ROW: TOGGLE (pill kanan)
--
-- Return: row, setGet, api
--   setGet(value, silent)  — set state; silent=true tidak panggil onChanged
--   api.set / api.setOn / api.setOff / api.get — sama, untuk dipakai di modul lain
--
-- momentary (arg7):
--   true  = ON lalu auto OFF setelah 1 detik (mode pulse)
--   number = ON lalu auto OFF setelah N detik
-- Untuk auto OFF setelah event eksternal (mis. save selesai), pakai api.setOff(true)
----------------------------------------------------------
function MainUI:CreateRowToggle(parent, labelText, initial, onChanged, order, labelStyle, momentary)
    local row = Instance.new("Frame")
    row.Name = "RowToggle"
    row.BackgroundTransparency = 1
    row.Size = UDim2.new(1, 0, 0, 26)
    row.LayoutOrder = order or (#parent:GetChildren() + 1)
    row.Parent = parent

    local label = Instance.new("TextLabel")
    label.Name = "Label"
    label.BackgroundTransparency = 1
    label.Position = UDim2.new(0, 0, 0, 0)
    label.Size = UDim2.new(1, -70, 1, 0)
    label.Font = Enum.Font.Gotham
    label.TextXAlignment = Enum.TextXAlignment.Left
    label.TextSize = 12
    label.Text = labelText or "Toggle"
    label.Parent = row
    applyRowLabelStyle(label, labelStyle or "toggle")

    local toggleBtn = Instance.new("TextButton")
    toggleBtn.Name = "Toggle"
    toggleBtn.AutoButtonColor = false
    toggleBtn.BackgroundColor3 = Color3.fromRGB(30,30,30)
    toggleBtn.Size = UDim2.new(0, 48, 0, 20)
    toggleBtn.Position = UDim2.new(1, -52, 0.5, -10)
    toggleBtn.Text = ""
    toggleBtn.BorderSizePixel = 0
    toggleBtn.Parent = row
    createCorner(toggleBtn, 10)
    createStroke(toggleBtn, Color3.fromRGB(60,60,60), 1, 0.6)

    local knob = Instance.new("Frame")
    knob.Name = "Knob"
    knob.Size = UDim2.new(0, 18, 0, 18)
    knob.Position = UDim2.new(0, 1, 0, 1)
    knob.BackgroundColor3 = Color3.fromRGB(220,220,220)
    knob.BorderSizePixel = 0
    knob.Parent = toggleBtn
    createCorner(knob, 9)

    local state = initial and true or false
    local bgTween = nil

    local function stopBgTween()
        if bgTween then
            pcall(function() bgTween:Cancel() end)
            bgTween = nil
        end
    end

    local function applyState(animate)
        stopBgTween()
        if state then
            knob.Position = UDim2.new(1, -19, 0, 1)
            if animate then
                bgTween = TweenService:Create(
                    toggleBtn,
                    TweenInfo.new(0.12, Enum.EasingStyle.Quad, Enum.EasingDirection.Out),
                    { BackgroundColor3 = COLOR_YELLOW }
                )
                bgTween:Play()
            else
                toggleBtn.BackgroundColor3 = COLOR_YELLOW
            end
        else
            knob.Position = UDim2.new(0, 1, 0, 1)
            if animate then
                bgTween = TweenService:Create(
                    toggleBtn,
                    TweenInfo.new(0.12, Enum.EasingStyle.Quad, Enum.EasingDirection.Out),
                    { BackgroundColor3 = Color3.fromRGB(30, 30, 30) }
                )
                bgTween:Play()
            else
                toggleBtn.BackgroundColor3 = Color3.fromRGB(30, 30, 30)
            end
        end
    end

    applyState(false)

    toggleBtn.MouseButton1Click:Connect(function()
        local pulseSec = nil
        if momentary == true then
            pulseSec = 1
        elseif type(momentary) == "number" and momentary > 0 then
            pulseSec = momentary
        end

        if pulseSec then
            if state then
                return
            end
            state = true
            applyState(true)
            if onChanged then
                pcall(onChanged, true)
            end
            task.delay(pulseSec, function()
                state = false
                applyState(false)
            end)
            return
        end

        state = not state
        applyState(true)
        if onChanged then
            onChanged(state)
        end
    end)

    -- getter/setter
    local function setGet(value, silent)
        if value ~= nil then
            state = value and true or false
            applyState(false)

            if (not silent) and onChanged then
                onChanged(state)
            end
        end

        return state
    end

    local api = {}

    function api.get()
        return state
    end

    function api.set(value, silent)
        return setGet(value, silent)
    end

    function api.setOn(silent)
        return setGet(true, silent)
    end

    function api.setOff(silent)
        return setGet(false, silent)
    end

    return row, setGet, api
end

----------------------------------------------------------
-- ROW: INPUT (text box dengan label kiri)
-- FIX:
--  ✅ text tidak keluar box (clip + padding)
--  ✅ bisa truncate "..." kalau kepanjangan
--  ✅ clearOnFocus opsional (arg5 boolean)
--  ✅ kalau clearOnFocus=false dan user klik doang (tanpa ngetik),
--     value BALIK ke currentValue (tidak jadi kosong)
--  ✅ allow empty kalau user memang sengaja mengosongkan (touched=true)
--
-- Signature:
--   CreateRowInput(parent, label, defaultText, onChanged, [clearOnFocusOrOrder], [maybeOrder])
--   arg5 number  => order
--   arg5 boolean => clearOnFocus (true=clear seperti lama, false=tidak clear)
----------------------------------------------------------
function MainUI:CreateRowInput(parent, labelText, defaultText, onChanged, noClearOrOrder, maybeOrder)
    local order = nil
    local clearOnFocus = true

    if type(noClearOrOrder) == "number" then
        order = noClearOrOrder
    elseif type(noClearOrOrder) == "boolean" then
        clearOnFocus = (noClearOrOrder == true)
        order = maybeOrder
    else
        clearOnFocus = true
        order = maybeOrder
    end

    local row = Instance.new("Frame")
    row.Name = "RowInput"
    row.BackgroundTransparency = 1
    row.Size = UDim2.new(1, 0, 0, 28)
    row.LayoutOrder = order or (#parent:GetChildren() + 1)
    row.Parent = parent

    local label = Instance.new("TextLabel")
    label.Name = "Label"
    label.BackgroundTransparency = 1
    label.Position = UDim2.new(0, 0, 0, 0)
    label.Size = UDim2.new(0.6, 0, 1, 0)
    label.Font = Enum.Font.Gotham
    label.TextXAlignment = Enum.TextXAlignment.Left
    label.TextSize = 12
    label.TextColor3 = COLOR_GRAY_TEXT
    label.Text = labelText or "Input"
    label.Parent = row

    local currentValue = (defaultText ~= nil) and tostring(defaultText) or ""
    local beforeFocusValue = currentValue
    local liveText = currentValue
    local committed = false

    local box = Instance.new("TextBox")
    box.Name = "Input"
    box.BackgroundColor3 = Color3.fromRGB(18,18,18)
    box.Size = UDim2.new(0.2, 0, 1, -5)
    box.Position = UDim2.new(0.79, 4, 0, 3)
    box.Font = Enum.Font.Gotham
    box.TextXAlignment = Enum.TextXAlignment.Center
    box.ClearTextOnFocus = false -- biar kita kontrol sendiri
    box.TextSize = 12
    box.TextColor3 = Color3.fromRGB(230,230,230)
    box.PlaceholderText = ""
    box.ClipsDescendants = true
    box.Parent = row

    local pad = Instance.new("UIPadding")
    pad.PaddingLeft  = UDim.new(0, 6)
    pad.PaddingRight = UDim.new(0, 6)
    pad.Parent = box

    pcall(function()
        box.TextTruncate = Enum.TextTruncate.AtEnd
    end)

    createCorner(box, 6)
    createStroke(box, Color3.fromRGB(60,60,60), 1, 0.6)

    local function trim(s)
        return (s and s:match("^%s*(.-)%s*$")) or ""
    end

    -- touched detection (lebih aman)
    local touched = false
    local internalSet = false

    local function setBoxText(v)
        internalSet = true
        box.Text = v
        internalSet = false
    end

    setBoxText(currentValue)

    local function commitPending()
        if committed then return end
        if not onChanged then return end

        local newText = liveText
        if box and box.Parent then
            newText = trim(box.Text)
        end
        newText = trim(newText)

        if newText == trim(currentValue) then return end

        committed = true
        currentValue = newText
        liveText = newText
        if box and box.Parent then
            setBoxText(currentValue)
        end
        onChanged(currentValue)
    end

    box:GetPropertyChangedSignal("Text"):Connect(function()
        if internalSet then return end
        liveText = trim(box.Text)
        if box:IsFocused() then
            touched = true
        end
    end)

    box.Focused:Connect(function()
        tweenColor(box, "BackgroundColor3", Color3.fromRGB(24,24,24))
        beforeFocusValue = currentValue
        touched = false
        committed = false

        if clearOnFocus and trim(box.Text) == trim(currentValue) then
            setBoxText("")
            liveText = ""
        end
    end)

    box.FocusLost:Connect(function(enterPressed)
        tweenColor(box, "BackgroundColor3", Color3.fromRGB(18,18,18))

        local newText = trim(box.Text)

        if not touched and newText == trim(currentValue) then
            setBoxText(currentValue)
            liveText = currentValue
            return
        end

        commitPending()
    end)

    box.Destroying:Connect(commitPending)

    self._pendingInputCommits = self._pendingInputCommits or {}
    table.insert(self._pendingInputCommits, commitPending)

    row.Destroying:Connect(function()
        for i = #self._pendingInputCommits, 1, -1 do
            if self._pendingInputCommits[i] == commitPending then
                table.remove(self._pendingInputCommits, i)
                break
            end
        end
    end)

    -- setter/getter
    local function setGet(value)
        if value ~= nil then
            currentValue = tostring(value)
            liveText = currentValue
            committed = false
            setBoxText(currentValue)
        end
        return currentValue
    end

    return row, setGet, commitPending
end


----------------------------------------------------------
-- ROW: SIMPLE LIST (list of toggle-buttons)
-- entries: { "Item A", "Item B", ... } atau
--          { {name="Item A", key="a"}, ... }
----------------------------------------------------------
function MainUI:CreateRowList(parent, titleText, entries, onItemToggle, order, labelStyle)
    entries      = entries or {}
    onItemToggle = onItemToggle or function() end

    --------------------------------------------------
    -- ROW + TITLE
    --------------------------------------------------
    local row = Instance.new("Frame")
    row.Name = "RowList"
    row.BackgroundTransparency = 1
    row.Size = UDim2.new(1, 0, 0, 0)
    row.AutomaticSize = Enum.AutomaticSize.Y
    row.LayoutOrder = order or (#parent:GetChildren() + 1)
    row.Parent = parent


    local title = Instance.new("TextLabel")
    title.Name = "Title"
    title.BackgroundTransparency = 1
    title.Position = UDim2.new(0, 0, 0, 0)
    title.Size = UDim2.new(1, 0, 0, 18)
    title.Font = Enum.Font.Gotham
    title.TextXAlignment = Enum.TextXAlignment.Left
    title.TextSize = 12
    title.Text = titleText or "List"
    title.Parent = row
    applyRowLabelStyle(title, labelStyle or "list")

    --------------------------------------------------
    -- CONTAINER LIST
    --------------------------------------------------
    local container = Instance.new("Frame")
    container.Name = "ListContainer"
    container.BackgroundColor3 = Color3.fromRGB(15, 15, 15)
    container.Position = UDim2.new(0, 0, 0, 20)
    container.Size = UDim2.new(1, 0, 0, 0)
    container.AutomaticSize = Enum.AutomaticSize.Y
    container.Parent = row

    createCorner(container, 6)
    createStroke(container, Color3.fromRGB(40, 40, 40), 1, 0.5)

    local pad = Instance.new("UIPadding")
    pad.PaddingTop    = UDim.new(0, 4)
    pad.PaddingBottom = UDim.new(0, 4)
    pad.PaddingLeft   = UDim.new(0, 4)
    pad.PaddingRight  = UDim.new(0, 4)
    pad.Parent = container

    local layout = Instance.new("UIListLayout")
    layout.FillDirection = Enum.FillDirection.Vertical
    layout.SortOrder = Enum.SortOrder.LayoutOrder
    layout.Padding = UDim.new(0, 2)
    layout.Parent = container

--------------------------------------------------
-- SEARCH BOX (FIX POSITION)
--------------------------------------------------
local searchText = ""

local searchWrap = Instance.new("Frame")
searchWrap.Name = "SearchWrap"
searchWrap.Parent = container
searchWrap.BackgroundTransparency = 1
searchWrap.Size = UDim2.new(1, 0, 0, 26)
searchWrap.LayoutOrder = -1

local searchBox = Instance.new("TextBox")
searchBox.Name = "SearchBox"
searchBox.Parent = searchWrap
searchBox.BackgroundColor3 = Color3.fromRGB(18, 18, 18)
searchBox.BorderSizePixel = 0
searchBox.Size = UDim2.new(1, 0, 0, 22)
searchBox.Position = UDim2.new(0, 0, 0, 0)
searchBox.Font = Enum.Font.Gotham
searchBox.TextSize = 11
searchBox.TextColor3 = Color3.fromRGB(210, 210, 210)
searchBox.PlaceholderText = "Search..."
searchBox.PlaceholderColor3 = Color3.fromRGB(105, 105, 105)
searchBox.TextXAlignment = Enum.TextXAlignment.Center
searchBox.Text = ""
searchBox.ClearTextOnFocus = false

createCorner(searchBox, 4)
createStroke(searchBox, Color3.fromRGB(32, 32, 32), 1, 0.45)


local searchPad = Instance.new("UIPadding")
searchPad.PaddingBottom = UDim.new(0, 4) -- jarak bawah (atur 3–6 sesuai selera)
searchPad.Parent = searchBox
    --------------------------------------------------
    -- STATE INTERNAL
    --------------------------------------------------
    local selectedMap    = {}           -- [key] = true/false
    local currentEntries = entries      -- list aktif sekarang

    local function normalizeEntry(e)
        if type(e) == "table" then
            return e.key or e.name, e.name or tostring(e.key)
        else
            return e, tostring(e)
        end
    end

local function norm(s)
    s = tostring(s or ""):lower()
    s = s:gsub("%s+", " ")
    return s
end

local function parsePet(label)
    label = tostring(label or "")

    -- ambil KG
    local kg = tonumber(label:match("([%d%.]+)%s*KG")) or 0

    -- hapus [Mutation]
    label = label:gsub("^%b[]%s*", "")

    -- ambil petType
    local petType = label:match("^(.-)%s*|") or label

    return petType, kg
end

local function filterAndSort(list)
    local result = {}
    local q = norm(searchText)

    for _, e in ipairs(list) do
        local key, label = normalizeEntry(e)

        if q == "" 
            or norm(label):find(q, 1, true)
            or norm(key):find(q, 1, true)
        then
            table.insert(result, e)
        end
    end

    table.sort(result, function(a, b)
        local ak = normalizeEntry(a)
        local bk = normalizeEntry(b)

        local aSel = selectedMap[ak] == true
        local bSel = selectedMap[bk] == true

        if aSel ~= bSel then
            return aSel
        end

        local _, aLabel = normalizeEntry(a)
local _, bLabel = normalizeEntry(b)

local aType, aKg = parsePet(aLabel)
local bType, bKg = parsePet(bLabel)

-- 1. selected tetap di atas (jangan diubah)
-- ini sudah ada di atas, jangan dihapus

-- 2. sort petType
if aType ~= bType then
    return aType < bType
end

-- 3. sort KG (besar dulu)
return aKg < bKg


    end)

    return result
end
    --------------------------------------------------
    -- BUILD BUTTONS
    --------------------------------------------------
    local function buildButtons(listOpt)
        -- kalau dipanggil dengan list baru → update currentEntries
        if listOpt then
            currentEntries = listOpt
        end

        local list = filterAndSort(currentEntries or {})

        -- clear lama
        for _, child in ipairs(container:GetChildren()) do
            if child:IsA("TextButton") then
                child:Destroy()
            end
        end

        for i, e in ipairs(list) do
            local key, labelText = normalizeEntry(e)

            -- kalau belum ada state, lihat dari field entry (selected / on)
            if selectedMap[key] == nil then
                if type(e) == "table" and (e.selected or e.on) then
                    selectedMap[key] = true
                else
                    selectedMap[key] = false
                end
            end

            local btn = Instance.new("TextButton")
            btn.Name = "Item_" .. tostring(key)
            btn.AutoButtonColor = false
            btn.BackgroundColor3 = Color3.fromRGB(22, 22, 22)
            btn.Size = UDim2.new(1, 0, 0, 22)
            btn.Text = "  " .. labelText
            btn.Font = Enum.Font.Gotham
            btn.TextXAlignment = Enum.TextXAlignment.Left
            btn.TextSize = 12
            btn.TextColor3 = Color3.fromRGB(200, 200, 200)
            btn.LayoutOrder = i
            btn.Parent = container
            createCorner(btn, 4)

            local function applyVisual()
                if selectedMap[key] then
                    tweenColor(btn, "BackgroundColor3", COLOR_YELLOW)
                    btn.TextColor3 = Color3.fromRGB(0, 0, 0)
                else
                    tweenColor(btn, "BackgroundColor3", Color3.fromRGB(22, 22, 22))
                    btn.TextColor3 = Color3.fromRGB(200, 200, 200)
                end
            end
            applyVisual()

            btn.MouseButton1Click:Connect(function()
                selectedMap[key] = not selectedMap[key]
                applyVisual()
                buildButtons()
                onItemToggle(key, selectedMap[key], labelText)
            end)
            

        end
    end

    -- build pertama
    buildButtons(currentEntries)
    searchBox:GetPropertyChangedSignal("Text"):Connect(function()
    searchText = searchBox.Text
    buildButtons()
    end)
    --------------------------------------------------
    -- API
    --------------------------------------------------
    local function api(action, payload)
        if action == "setList" or action == "setItems" then
            -- ganti isi list + rebuild
            buildButtons(payload or {})

        elseif action == "setSelected" and type(payload) == "table" then
            -- ganti state selectedMap sesuai payload
            selectedMap = {}
            for k, v in pairs(payload) do
                if v then
                    selectedMap[k] = true
                end
            end
            -- redraw pakai currentEntries
            buildButtons()

        elseif action == "getSelected" then
            local result = {}
            for k, v in pairs(selectedMap) do
                if v then
                    table.insert(result, k)
                end
            end
            return result
        end
    end

    return row, api
end



----------------------------------------------------------
-- ROW: DROPDOWN (single / multi) dgn overlay + search
----------------------------------------------------------
-- opts:
-- {
--   label       = "Target Player",
--   placeholder = "Select...",
--   mode        = "single" / "multi"  (default: "single")
--   getItems    = function() return { "A", "B" } end
--                -- ATAU langsung table: { "A","B" } / { {key="a",name="A"}, ... }
--   initial     =   -- SINGLE: "key" / "name"
--                 -- MULTI : { [key]=true, [key2]=true }
--   onChanged   = function(mode, selected) end
--   emptyUntilSearch = false  -- true: list kosong sampai user ketik search
--   deferItemLoad = false     -- true: skip scan getItems saat create; load saat dropdown dibuka
--   maxResults  = nil         -- number: batas item (mis. 10)
--   searchGetItems = function(query) return {} end  -- override sumber item saat search
--   searchPlaceholder = "Search..."
--   hintText    = "..."       -- keterangan di bawah row (English)
-- }
function MainUI:CreateRowDropdown(parent, opts)
    opts = opts or {}
    local mode        = (opts.mode == "multi") and "multi" or "single"
    local labelText   = opts.label or "Dropdown"
    local panelTitle  = opts.panelTitle or opts.dropdownTitle or labelText
    local placeholder = opts.placeholder or "Select..."
    local emptyUntilSearch = opts.emptyUntilSearch == true
    local deferItemLoad = opts.deferItemLoad == true
    local maxResults = tonumber(opts.maxResults)
    local searchGetItems = opts.searchGetItems

    local api = {}
    local itemsLoaded = false

    -- Sumber item bisa function atau table
    local itemsSource = opts.getItems or {}

    local function getItemsList()
        if type(itemsSource) == "function" then
            local ok, res = pcall(itemsSource)
            if ok and type(res) == "table" then
                return res
            else
                warn("[NodeHubDropdown] getItems() tidak mengembalikan table, pakai {}")
                return {}
            end
        elseif type(itemsSource) == "table" then
            return itemsSource
        else
            warn("[NodeHubDropdown] getItems bukan function/table, pakai {}")
            return {}
        end
    end

    local onChanged   = opts.onChanged
    local onClose     = opts.onClose

    -- state
    local currentItems = {}
    local keyToLabel   = {}

    local selectedKey  = nil
    local selectedMap  = {}

    if mode == "single" then
        if opts.initial ~= nil then
            selectedKey = tostring(opts.initial)
        end
    else
        if type(opts.initial) == "table" then
            for k, v in pairs(opts.initial) do
                if v == true or v == 1 or v == "true" then
                    selectedMap[tostring(k)] = true
                end
            end
        end
    end

    ------------------------------------------------------
    -- ROW + LABEL + BUTTON
    ------------------------------------------------------
    local row = Instance.new("Frame")
    row.Name = "RowDropdown"
    row.BackgroundTransparency = 1
    row.Size = UDim2.new(1, 0, 0, 34)
    row.LayoutOrder = tonumber(opts.order) or (#parent:GetChildren() + 1)
    row.Parent = parent

    local label = Instance.new("TextLabel")
    label.Name = "Label"
    label.BackgroundTransparency = 1
    label.Position = UDim2.new(0, 0, 0, 0)
    label.Size = UDim2.new(0.6, 0, 1, 0)
    label.Font = Enum.Font.Gotham
    label.TextXAlignment = Enum.TextXAlignment.Left
    label.TextSize = 12
    label.Text = labelText
    label.Parent = row
    applyRowLabelStyle(label, opts.labelStyle or "default")

    local button = Instance.new("TextButton")
    button.Name = "DropdownButton"
    button.AutoButtonColor = false
    button.BackgroundColor3 = Color3.fromRGB(18,18,18)
    button.Size = UDim2.new(0.4, 0, 1, -8)
    button.Position = UDim2.new(0.60, 0, 0, 3)
    button.Font = Enum.Font.Gotham
    button.TextXAlignment = Enum.TextXAlignment.Center
    button.TextSize = 11
    button.TextColor3 = Color3.fromRGB(230,230,230)
    button.Text = "  " .. placeholder
    button.Parent = row
    createCorner(button, 6)
    createStroke(button, Color3.fromRGB(60,60,60), 1, 0.6)

    local arrow = Instance.new("TextLabel")
    arrow.Name = "Arrow"
    arrow.BackgroundTransparency = 1
    arrow.Size = UDim2.new(0, 16, 1, 0)
    arrow.Position = UDim2.new(1, -18, 0, 0)
    arrow.Font = Enum.Font.GothamBold
    arrow.TextSize = 12
    arrow.TextXAlignment = Enum.TextXAlignment.Center
    arrow.TextColor3 = Color3.fromRGB(200,200,200)
    arrow.Text = "▼"
    arrow.Parent = button

    local function normalizeItem(e)
        if type(e) == "table" then
            local key = e.key or e.name
            local lbl = e.name or tostring(e.key)
            key = tostring(key)
            local icon = e.icon or e.image
            if type(icon) == "number" then
                icon = "rbxassetid://" .. tostring(math.floor(icon))
            elseif type(icon) == "string" and icon:match("^%d+$") then
                icon = "rbxassetid://" .. icon
            end
            return key, lbl, icon
        else
            local key = tostring(e)
            return key, key, nil
        end
    end

    local function syncItemLabels()
        keyToLabel = {}
        for _, e in ipairs(getItemsList() or {}) do
            local k, lbl = normalizeItem(e)
            keyToLabel[k] = lbl
        end
        itemsLoaded = true
        if type(opts.labelForKey) == "function" then
            if mode == "multi" then
                for k, on in pairs(selectedMap) do
                    if on and not keyToLabel[k] then
                        local ok, lbl = pcall(opts.labelForKey, k)
                        if ok and type(lbl) == "string" and lbl ~= "" then
                            keyToLabel[k] = lbl
                        end
                    end
                end
            elseif mode == "single" and selectedKey and not keyToLabel[selectedKey] then
                local ok, lbl = pcall(opts.labelForKey, selectedKey)
                if ok and type(lbl) == "string" and lbl ~= "" then
                    keyToLabel[selectedKey] = lbl
                end
            end
        end
    end

    local function resolveItemLabel(key)
        key = tostring(key or "")
        if key == "" then return key end
        if keyToLabel[key] and keyToLabel[key] ~= "" then
            return keyToLabel[key]
        end
        if type(opts.labelForKey) == "function" then
            local ok, lbl = pcall(opts.labelForKey, key)
            if ok and type(lbl) == "string" and lbl ~= "" then
                keyToLabel[key] = lbl
                return lbl
            end
        end
        return key
    end

    local function refreshButtonText()
        if mode == "single" then
            if not selectedKey then
                button.Text = "  " .. placeholder
                return
            end
            local label = resolveItemLabel(selectedKey)
            button.Text = "  " .. label
            return
        end

        local names = {}
        for k, on in pairs(selectedMap) do
            if on then
                table.insert(names, resolveItemLabel(k))
            end
        end
        table.sort(names)

        if #names == 0 then
            button.Text = "  " .. placeholder
            return
        end

        local maxChars = 25
        local total = table.concat(names, ", ")
        if #total <= maxChars then
            button.Text = "  " .. total
            return
        end

        local shown, used = {}, 0
        for i, name in ipairs(names) do
            local part = (i == 1) and name or (", " .. name)
            if used + #part > maxChars then break end
            table.insert(shown, name)
            used += #part
        end
        local rest = #names - #shown
        local txt = table.concat(shown, ", ")
        if rest > 0 then
            txt ..= (" +%d"):format(rest)
        end
        button.Text = "  " .. txt
    end

    local function resolveSelectedKey(key)
        if not key or mode ~= "single" then
            return key
        end
        key = tostring(key)
        if keyToLabel[key] then
            return key
        end
        local lower = key:lower()
        for k, lbl in pairs(keyToLabel) do
            if k:lower() == lower or lbl:lower() == lower then
                return k
            end
        end
        local compact = lower:gsub("[^%w]", "")
        for k, lbl in pairs(keyToLabel) do
            if k:lower():gsub("[^%w]", "") == compact then
                return k
            end
            if lbl:lower():gsub("[^%w]", "") == compact then
                return k
            end
        end
        return key
    end

local function openDropdown()
    if deferItemLoad and not itemsLoaded then
        syncItemLabels()
    end
    -- parent: panel kanan / main frame NodeHub
    local parentFrame = self.right or self.mainFrame

    --------------------------------------------------
    -- OVERLAY DI DALAM NODEHUB (BLOCK CLICK DI BAWAH)
    --------------------------------------------------
    local overlay = Instance.new("TextButton")
    overlay.Name = "NodeHubDropdownOverlay"
    overlay.BackgroundColor3 = Color3.fromRGB(0,0,0)
    overlay.BackgroundTransparency = 0.25      -- agak gelap
    overlay.AutoButtonColor = false
    overlay.BorderSizePixel = 0
    overlay.Text = ""
    overlay.Size = UDim2.new(1, 0, 1, 0)
    overlay.Position = UDim2.new(0, 0, 0, 0)
    overlay.ZIndex = 98
    overlay.Active = true
    overlay.Parent = parentFrame

    --------------------------------------------------
    -- PANEL DROPDOWN (TENGAH NODEHUB)
    --------------------------------------------------
    local panel = Instance.new("Frame")
    panel.Name = "DropdownPanel"
    panel.Size = UDim2.new(0, 280, 0, 260)
    panel.AnchorPoint = Vector2.new(0.5, 0.5)
    panel.Position = UDim2.new(0.5, 0, 0.5, 0)
    panel.BackgroundColor3 = COLOR_PANEL
    panel.ZIndex = 99                 -- di atas overlay
    panel.Active = true
    panel.Parent = overlay
    createCorner(panel, 10)
    createStroke(panel, COLOR_YELLOW, 1, 0.3)

    local pad = Instance.new("UIPadding")
    pad.PaddingTop    = UDim.new(0, 8)
    pad.PaddingBottom = UDim.new(0, 8)
    pad.PaddingLeft   = UDim.new(0, 8)
    pad.PaddingRight  = UDim.new(0, 8)
    pad.Parent = panel

    --------------------------------------------------
    -- HEADER: LABEL (KIRI) + TOMBOL X (KANAN)
    --------------------------------------------------
    local header = Instance.new("Frame")
    header.Name = "Header"
    header.BackgroundTransparency = 1
    header.Size = UDim2.new(1, 0, 0, 24)
    header.Position = UDim2.new(0, 0, 0, 0)
    header.ZIndex = 100
    header.Parent = panel

    local headerLabel = Instance.new("TextLabel")
    headerLabel.Name = "HeaderLabel"
    headerLabel.BackgroundTransparency = 1
    headerLabel.Size = UDim2.new(1, -28, 1, 0) -- sisakan space untuk X
    headerLabel.Position = UDim2.new(0, 0, 0, 0)
    headerLabel.Font = Enum.Font.Gotham
    headerLabel.TextSize = 12
    headerLabel.TextXAlignment = Enum.TextXAlignment.Left
    headerLabel.TextColor3 = COLOR_GRAY_TEXT
    headerLabel.Text = panelTitle
    headerLabel.ZIndex = 101
    headerLabel.Parent = header

    local closeBtn = Instance.new("TextButton")
    closeBtn.Name = "CloseButton"
    closeBtn.Size = UDim2.new(0, 22, 0, 22)
    closeBtn.AnchorPoint = Vector2.new(1, 0.5)
    closeBtn.Position = UDim2.new(1, 0, 0.5, 0)
    closeBtn.BackgroundColor3 = Color3.fromRGB(18,18,18)
    closeBtn.AutoButtonColor = false
    closeBtn.BorderSizePixel = 0
    closeBtn.Text = "X"
    closeBtn.Font = Enum.Font.GothamBold
    closeBtn.TextSize = 12
    closeBtn.TextColor3 = COLOR_WHITE
    closeBtn.ZIndex = 101
    closeBtn.Parent = header
    createCorner(closeBtn, 6)
    createStroke(closeBtn, COLOR_YELLOW, 1, 0.4)

    --------------------------------------------------
    -- SEARCH (DI BAWAH HEADER, FULL WIDTH)
    --------------------------------------------------
    local search = Instance.new("TextBox")
    search.Name = "SearchBox"
    search.Size = UDim2.new(1, 0, 0, 24)
    -- 24 (header) + 4 margin = 28
    search.Position = UDim2.new(0, 0, 0, 28)
    search.BackgroundColor3 = Color3.fromRGB(18,18,18)
    search.PlaceholderText = opts.searchPlaceholder or "Search..."
    search.ClearTextOnFocus = false
    search.Font = Enum.Font.Gotham
    search.TextSize = 12
    search.TextXAlignment = Enum.TextXAlignment.Center
    search.TextColor3 = Color3.fromRGB(230,230,230)
    search.ZIndex = 100
    search.Parent = panel
    createCorner(search, 6)
    createStroke(search, Color3.fromRGB(60,60,60), 1, 0.6)

    --------------------------------------------------
    -- LIST (DI BAWAH SEARCH)
    --------------------------------------------------
    -- total tinggi header+margin+search+margin = 24 + 4 + 24 + 8 = 60
    local listTopOffset = 60

    local list = Instance.new("ScrollingFrame")
    list.Name = "List"
    list.Size = UDim2.new(1, 0, 1, -listTopOffset)
    list.Position = UDim2.new(0, 0, 0, listTopOffset)
    list.BackgroundTransparency = 1
    list.ScrollBarThickness = 4
    list.ScrollBarImageTransparency = 0
    list.AutomaticCanvasSize = Enum.AutomaticSize.Y
    list.CanvasSize = UDim2.new(0, 0, 0, 0)
    list.ZIndex = 100
    list.Parent = panel

    local layout = Instance.new("UIListLayout")
    layout.FillDirection = Enum.FillDirection.Vertical
    layout.SortOrder = Enum.SortOrder.LayoutOrder
    layout.Padding = UDim.new(0, 3)
    layout.Parent = list

    --------------------------------------------------
    -- REBUILD LIST (SAMA KAYAK KODEMU SEBELUMNYA)
    --------------------------------------------------
    local function trimSearchText(s)
        return tostring(s or ""):gsub("^%s+", ""):gsub("%s+$", "")
    end

    local rebuildGen = 0

local function rebuildList()
    rebuildGen += 1
    local myGen = rebuildGen

    currentItems = {}
    keyToLabel   = {}
    local onDeleteItem = opts.onDeleteItem

    local rawItems = {}
    local qTrim = trimSearchText(search.Text)
    local useSearchProvider = type(searchGetItems) == "function"
    if useSearchProvider then
        if emptyUntilSearch and qTrim == "" then
            rawItems = {}
        else
            local ok, res = pcall(searchGetItems, qTrim)
            if myGen ~= rebuildGen then return end
            if ok and type(res) == "table" then
                rawItems = res
            else
                rawItems = {}
            end
        end
    else
        rawItems = getItemsList() or {}
    end

    if myGen ~= rebuildGen then return end

  -- build items + label map (dedupe by key)
    local itemKeysSeen = {}
    for _, e in ipairs(rawItems) do
        local k, lbl, icon = normalizeItem(e)
        if k ~= "" and not itemKeysSeen[k] then
            itemKeysSeen[k] = true
            local sortKey = nil
            if type(e) == "table" then
                sortKey = tonumber(e.order) or tonumber(e.sort) or tonumber(e.key)
            end
            table.insert(currentItems, { key = k, label = lbl, icon = icon, sortKey = sortKey })
            keyToLabel[k] = lbl
        end
    end

    for _, e in ipairs(getItemsList() or {}) do
        local k, lbl = normalizeItem(e)
        if k ~= "" and lbl ~= "" then
            keyToLabel[k] = keyToLabel[k] or lbl
        end
    end

    local knownKeys = {}
    for _, info in ipairs(currentItems) do
        knownKeys[info.key] = true
    end
    if mode == "multi" then
        for k, on in pairs(selectedMap) do
            if on and not knownKeys[k] then
                local lbl = resolveItemLabel(k)
                table.insert(currentItems, { key = k, label = lbl })
                keyToLabel[k] = lbl
                knownKeys[k] = true
            end
        end
    elseif mode == "single" and selectedKey and not knownKeys[selectedKey] then
        local lbl = resolveItemLabel(selectedKey)
        table.insert(currentItems, { key = selectedKey, label = lbl })
        keyToLabel[selectedKey] = lbl
    end

    if myGen ~= rebuildGen then return end

    -- clear old list children (buttons/labels/frames)
    for _, c in ipairs(list:GetChildren()) do
        if not c:IsA("UIListLayout") and not c:IsA("UIPadding") then
            c:Destroy()
        end
    end

    local q = (search.Text or ""):lower()

    -- helper: check selected
    local function isSelected(k)
        if mode == "single" then
            return selectedKey == k
        else
            return selectedMap[k] == true
        end
    end

    if emptyUntilSearch and qTrim == "" and #currentItems == 0 then
        local hintItem = Instance.new("TextLabel")
        hintItem.Name = "EmptySearchHint"
        hintItem.BackgroundTransparency = 1
        hintItem.Size = UDim2.new(1, 0, 0, 36)
        hintItem.Font = Enum.Font.Gotham
        hintItem.TextSize = 11
        hintItem.TextColor3 = COLOR_GRAY_TEXT
        hintItem.TextWrapped = true
        hintItem.TextXAlignment = Enum.TextXAlignment.Center
        hintItem.Text = "Type to search..."
        hintItem.LayoutOrder = 1
        hintItem.ZIndex = 101
        hintItem.Parent = list
        return
    end

    -- filter + split selected/rest
    local picked, rest = {}, {}
    for _, info in ipairs(currentItems) do
        local lbl = tostring(info.label or "")
        local low = lbl:lower()
        local passFilter = useSearchProvider or q == "" or low:find(q, 1, true)
        if passFilter then
            if isSelected(info.key) then
                table.insert(picked, info)
            else
                table.insert(rest, info)
            end
        end
    end

    -- optional: sort per group biar rapi (numeric order > label A-Z)
    local function bySort(a, b)
        local sa, sb = a.sortKey, b.sortKey
        if sa and sb and sa ~= sb then return sa < sb end
        if sa and not sb then return true end
        if sb and not sa then return false end
        return tostring(a.label):lower() < tostring(b.label):lower()
    end
    table.sort(picked, bySort)
    table.sort(rest, bySort)

