    { key = "AutoClaimDrop",           name = "Auto Claim Drop",         factory = function() -- AutoClaimDrop — claim items in workspace.DroppedItems (ProximityPrompt + Networking)

local Players = game:GetService("Players")
local ProximityPromptService = game:GetService("ProximityPromptService")
local ReplicatedStorage = game:GetService("ReplicatedStorage")

local LP = Players.LocalPlayer
local G = (getgenv and getgenv()) or _G

local M = {}

local enabled, loopToken, recent = false, 0, {}
local claimBusy = false
local stats = { claimed = 0, lastStatus = "Ready", lastMethod = "" }
local droppedItemNet, pickupRemotes = nil, {}

local MIN_INTERVAL = 0
local RECENT_SEC = 0.05
local SCAN_RANGE = 80
local NUDGE_RANGE = 80
local NEAR_DIST = 8
local NUDGE_MIN_DIST = 14
local WAIT_POLL = 0.015

local PICKUP_REMOTE_KEYS = {
    "RequestPickup", "RequestPickUp", "Pickup", "PickUp", "Claim", "Collect", "Take",
}

local function _disconnectGlobal()
    local c = G.__GAG2_AUTO_CLAIM_DROP_CONN or rawget(_G, "__GAG2_AUTO_CLAIM_DROP_CONN")
    if c then pcall(function() c:Disconnect() end) end
    G.__GAG2_AUTO_CLAIM_DROP_CONN = nil
    rawset(_G, "__GAG2_AUTO_CLAIM_DROP_CONN", nil)
end

_disconnectGlobal()

local function _setStatus(msg, method)
    stats.lastStatus = tostring(msg or "")
    if method then stats.lastMethod = tostring(method) end
    G.AUTO_CLAIM_DROP_STATUS = stats.lastStatus
    rawset(_G, "AUTO_CLAIM_DROP_STATUS", stats.lastStatus)
end

local function _promptFn()
    if type(fireproximityprompt) == "function" then return fireproximityprompt end
    return rawget(_G, "fireproximityprompt")
end

local function _getConnectionsFn()
    if type(getconnections) == "function" then return getconnections end
    return rawget(_G, "getconnections")
end

local function _loadNetworking()
    if droppedItemNet then return true end
    local ok, net = pcall(function() return require(ReplicatedStorage.SharedModules.Networking) end)
    if not ok or type(net) ~= "table" or type(net.DroppedItem) ~= "table" then return false end
    droppedItemNet = net.DroppedItem
    pickupRemotes = {}
    local seen = {}
    for _, key in ipairs(PICKUP_REMOTE_KEYS) do
        local r = droppedItemNet[key]
        if r and not seen[r] then
            seen[r] = true
            pickupRemotes[#pickupRemotes + 1] = { key = key, remote = r }
        end
    end
    for key, r in pairs(droppedItemNet) do
        if key ~= "RequestDrop" and key ~= "PickupFx" and not seen[r] then
            local lk = string.lower(tostring(key))
            if lk:find("pick") or lk:find("claim") or lk:find("collect") or lk:find("take") then
                seen[r] = true
                pickupRemotes[#pickupRemotes + 1] = { key = tostring(key), remote = r }
            end
        end
    end
    return true
end

local function _netFire(remote, ...)
    if not remote then return false end
    local args = table.pack(...)
    local ok = pcall(function()
        if type(remote.Fire) == "function" then
            remote:Fire(table.unpack(args, 1, args.n))
            return
        end
        if typeof(remote) == "Instance" then
            if remote:IsA("RemoteFunction") then
                remote:InvokeServer(table.unpack(args, 1, args.n))
                return
            end
            remote:FireServer(table.unpack(args, 1, args.n))
        end
    end)
    return ok
end

local function _getDroppedFolder()
    return workspace:FindFirstChild("DroppedItems")
end

local function _visualPart(model)
    if not model or not model:IsA("Model") then return nil end
    local visual = model:FindFirstChild("Visual")
    if not visual then return nil end
    if visual:IsA("BasePart") then return visual end
    if visual:IsA("Model") then
        if visual.PrimaryPart then return visual.PrimaryPart end
        return visual:FindFirstChildWhichIsA("BasePart", true)
    end
    return nil
end

local function _dropPosition(model)
    local part = _visualPart(model)
    if part then return part.Position end
    local anchor = model:FindFirstChild("PromptAnchor")
    if anchor and anchor:IsA("BasePart") then return anchor.Position end
    if model.PrimaryPart then return model.PrimaryPart.Position end
    return nil
end

local function _distanceToModel(model, hrp)
    local pos = _dropPosition(model)
    if not pos or not hrp then return math.huge end
    return (hrp.Position - pos).Magnitude
end

local function _findNearestDrop(hrp, maxDist)
    local folder = _getDroppedFolder()
    if not hrp or not folder then return nil, nil, folder end
    maxDist = tonumber(maxDist) or SCAN_RANGE
    local best, bestDist = nil, math.huge
    for _, m in ipairs(folder:GetChildren()) do
        if not m:IsA("Model") then continue end
        local d = _distanceToModel(m, hrp)
        if d <= maxDist and d < bestDist then best, bestDist = m, d end
    end
    return best, bestDist, folder
end

local function _waitVisualPart(model, timeout)
    timeout = tonumber(timeout) or 5
    local deadline = os.clock() + timeout
    while os.clock() < deadline do
        if not model or not model.Parent then return nil end
        local part = _visualPart(model)
        if part then return part end
        task.wait(WAIT_POLL)
    end
    return _visualPart(model)
end

local function _findPrompt(model)
    if not model then return nil end
    local anchor = model:FindFirstChild("PromptAnchor")
    if anchor then
        local pp = anchor:FindFirstChildWhichIsA("ProximityPrompt", true)
        if pp then return pp end
    end
    local visual = model:FindFirstChild("Visual")
    if visual then
        local pp = visual:FindFirstChildWhichIsA("ProximityPrompt", true)
        if pp then return pp end
    end
    return model:FindFirstChildWhichIsA("ProximityPrompt", true)
end

local function _waitPrompt(model, timeout)
    timeout = tonumber(timeout) or 2
    local deadline = os.clock() + timeout
    while os.clock() < deadline do
        if not model or not model.Parent then return nil end
        local pp = _findPrompt(model)
        if pp then return pp end
        task.wait(WAIT_POLL)
    end
    return _findPrompt(model)
end

local function _pickupArgs(model)
    local cat = model:GetAttribute("ItemCategory")
    local id = model:GetAttribute("ItemId") or model:GetAttribute("Id") or model:GetAttribute("UUID")
    return {
        { model },
        { cat, id },
        { tostring(cat or ""), tostring(id or "") },
        { id },
        { tostring(id or "") },
        { model.Name },
    }
end

local function _prepPrompt(pp)
    if not pp then return end
    pcall(function()
        pp.Enabled = true
        pp.RequiresLineOfSight = false
        pp.MaxActivationDistance = math.max(tonumber(pp.MaxActivationDistance) or 10, 9999)
    end)
end

local function _firePromptFast(pp)
    if not pp then return false, "no_prompt" end
    pcall(function() ProximityPromptService.Enabled = true end)
    _prepPrompt(pp)
    local fn = _promptFn()
    if type(fn) == "function" then
        if pcall(fn, pp, true) then return true, "hold" end
        if pcall(fn, pp) then return true, "tap" end
    end
    return _firePrompt(pp)
end

local function _boostPrompt(pp)
    if not pp then return {} end
    local saved = {
        MaxActivationDistance = pp.MaxActivationDistance,
        RequiresLineOfSight = pp.RequiresLineOfSight,
        Enabled = pp.Enabled,
    }
    pcall(function()
        pp.Enabled = true
        pp.RequiresLineOfSight = false
        pp.MaxActivationDistance = math.max(tonumber(pp.MaxActivationDistance) or 10, 9999)
    end)
    return saved
end

local function _restorePrompt(pp, saved)
    if not pp or type(saved) ~= "table" then return end
    pcall(function()
        if saved.MaxActivationDistance ~= nil then pp.MaxActivationDistance = saved.MaxActivationDistance end
        if saved.RequiresLineOfSight ~= nil then pp.RequiresLineOfSight = saved.RequiresLineOfSight end
        if saved.Enabled ~= nil then pp.Enabled = saved.Enabled end
    end)
end

local function _firePrompt(pp)
    if not pp then return false, "no_prompt" end
    pcall(function() ProximityPromptService.Enabled = true end)

    local saved = _boostPrompt(pp)
    local fn = _promptFn()
    local okMethod = nil

    if type(fn) == "function" then
        if pcall(fn, pp, true) then okMethod = "fireproximityprompt_hold" end
        if not okMethod and pcall(fn, pp) then okMethod = "fireproximityprompt" end
        if not okMethod then
            local hold = tonumber(pp.HoldDuration) or 0
            if hold > 0 and pcall(fn, pp, hold + 0.25) then okMethod = "fireproximityprompt_duration" end
        end
    end

    if not okMethod then
        local getconn = _getConnectionsFn()
        if type(getconn) == "function" then
            for _, ev in ipairs({ pp.Triggered, pp.TriggerEnded, pp.PromptButtonHoldEnded }) do
                for _, c in ipairs(getconn(ev)) do
                    if c.Function and pcall(c.Function) then okMethod = "prompt_conn" break end
                    if c.fire and pcall(c.fire) then okMethod = "prompt_conn_fire" break end
                end
                if okMethod then break end
            end
        end
    end

    if not okMethod and (tonumber(pp.HoldDuration) or 0) > 0 then
        task.spawn(function()
            pcall(function() pp:InputHoldBegin() end)
            task.wait((tonumber(pp.HoldDuration) or 0) + 0.15)
            pcall(function() pp:InputHoldEnd() end)
        end)
        okMethod = "input_hold_spawn"
    end

    _restorePrompt(pp, saved)
    return okMethod ~= nil, okMethod or "prompt_fail"
end

local function _tryPickupRemotes(model)
    if not _loadNetworking() or #pickupRemotes == 0 then return false, "no_remote" end
    local argSets = _pickupArgs(model)
    for _, entry in ipairs(pickupRemotes) do
        for _, args in ipairs(argSets) do
            if _netFire(entry.remote, table.unpack(args)) then
                return true, "remote:" .. tostring(entry.key)
            end
        end
    end
    return false, "remote_fail"
end

local function _unequipHeld()
    local char = LP.Character
    if not char then return end
    local hum = char:FindFirstChildOfClass("Humanoid")
    if hum then pcall(function() hum:UnequipTools() end) end
end

local function _nudgeNear(model, hrp)
    local part = _visualPart(model)
    if not part or not hrp then return false, "no_part" end
    local delta = hrp.Position - part.Position
    local dist = delta.Magnitude
    if dist <= NEAR_DIST then return true, "already_near" end
    if dist > NUDGE_RANGE then return false, "too_far" end
    local flat = Vector3.new(delta.X, 0, delta.Z)
    if flat.Magnitude < 0.05 then flat = Vector3.new(1, 0, 0) else flat = flat.Unit end
    local stand = part.Position + flat * 3.5 + Vector3.new(0, 2.5, 0)
    pcall(function() hrp.CFrame = CFrame.new(stand, part.Position) end)
    return true, "nudged"
end

local function _attemptClaim(model, hrp)
    if not model or not model.Parent then return false, "gone" end
    local char = LP.Character
    hrp = (char and char:FindFirstChild("HumanoidRootPart")) or hrp
    if not hrp then return false, "no_hrp" end

    local pp = _findPrompt(model)
    if not pp and not _visualPart(model) then
        _waitVisualPart(model, 0.12)
    end
    pp = pp or _findPrompt(model) or _waitPrompt(model, 0.08)
    if not pp then return false, "no_prompt" end

    if pp.Enabled == false or model:GetAttribute("OwnerRestricted") == true then
        _prepPrompt(pp)
        pcall(function()
            for _, d in ipairs(model:GetDescendants()) do
                if d:IsA("ProximityPrompt") then
                    d.Enabled = true
                    d.RequiresLineOfSight = false
                end
            end
        end)
    end

    if char and char:FindFirstChildOfClass("Tool") then
        _unequipHeld()
    end

    if _distanceToModel(model, hrp) > NUDGE_MIN_DIST then
        _nudgeNear(model, hrp)
    end

    local ok, method = _firePromptFast(pp)
    if ok then return true, method end

    return _tryPickupRemotes(model)
end

local function _modelCollected(model, folder)
    if not model then return true end
    if not model.Parent then return true end
    if folder and model.Parent ~= folder then return true end
    return false
end

local function _resolveEnabledFromStore()
    local api = G.__GAG2_AUTO_GIFT_CLAIM_DROP_API or rawget(_G, "__GAG2_AUTO_GIFT_CLAIM_DROP_API")
    if G.__GAG2_AUTO_GIFT_UI_READY == true and type(api) == "table" and type(api.get) == "function" then
        local ok, v = pcall(api.get, api)
        if ok and v ~= nil then return v == true end
    end
    local s = G.__GAG2_AUTO_GIFT or rawget(_G, "__GAG2_AUTO_GIFT")
    if type(s) == "table" then return s.auto_claim_drop == true end
    local main = G.MAIN or rawget(_G, "MAIN")
    if type(main) == "table" and type(main.auto) == "table" and type(main.auto.gift) == "table" then
        return main.auto.gift.auto_claim_drop == true
    end
    return false
end

function M.Stop()
    enabled = false
    claimBusy = false
    loopToken += 1
    _disconnectGlobal()
    _setStatus("Stopped")
end

function M.Start()
    M.Stop()
    enabled = true
    local myToken = loopToken
    pcall(function() ProximityPromptService.Enabled = true end)
    _loadNetworking()
    _setStatus("Running")

    task.spawn(function()
        while enabled and loopToken == myToken do
            if not claimBusy then
                local hrp = LP.Character and LP.Character:FindFirstChild("HumanoidRootPart")
                local best, bestDist, folder = _findNearestDrop(hrp, SCAN_RANGE)
                local now = os.clock()
                if best and folder and not (recent[best] and now - recent[best] < RECENT_SEC) then
                    claimBusy = true
                    local target = best
                    local ok, method = _attemptClaim(target, hrp)
                    claimBusy = false
                    if enabled and loopToken == myToken then
                        if ok then
                            if _modelCollected(target, folder) then
                                recent[target] = nil
                                stats.claimed = (stats.claimed or 0) + 1
                                _setStatus(string.format("Claimed (%d)", stats.claimed), method)
                            else
                                recent[target] = os.clock()
                                _setStatus("Retry claim...", method)
                            end
                        else
                            _setStatus(string.format("Claim failed (%.0f studs) — %s", bestDist or 0, tostring(method)), method)
                        end
                    end
                end
            end
            if MIN_INTERVAL > 0 then task.wait(MIN_INTERVAL) else task.wait() end
        end
    end)
end

function M.ApplyRuntime(on)
    if on == true then M.Start() else M.Stop() end
end
M.ApplyPickupRuntime = M.ApplyRuntime

function M.SyncFromStore()
    M.ApplyRuntime(_resolveEnabledFromStore())
end

function M.IsRunning()
    return enabled == true
end

function M.GetStats()
    _loadNetworking()
    local keys = {}
    if droppedItemNet then
        for k in pairs(droppedItemNet) do keys[#keys + 1] = tostring(k) end
        table.sort(keys)
    end
    return {
        running = enabled == true,
        claimed = stats.claimed or 0,
        lastStatus = stats.lastStatus,
        lastMethod = stats.lastMethod or "",
        pickupRemotes = #pickupRemotes,
        droppedItemKeys = keys,
        hasFirePrompt = type(_promptFn()) == "function",
        hasGetConnections = type(_getConnectionsFn()) == "function",
    }
end

local function _scanDrops(hrp)
    local folder = _getDroppedFolder()
    local rows = {}
    if not folder then return folder, rows end
    for _, m in ipairs(folder:GetChildren()) do
        if not m:IsA("Model") then continue end
        local part = _visualPart(m)
        local dist = hrp and part and (hrp.Position - part.Position).Magnitude or nil
        rows[#rows + 1] = {
            name = m.Name,
            dist = dist,
            hasVisual = m:FindFirstChild("Visual") ~= nil,
            hasPrompt = _findPrompt(m) ~= nil,
            category = tostring(m:GetAttribute("ItemCategory") or ""),
            ownerRestricted = m:GetAttribute("OwnerRestricted") == true,
            droppedBy = m:GetAttribute("DroppedBy"),
        }
    end
    table.sort(rows, function(a, b)
        return (a.dist or math.huge) < (b.dist or math.huge)
    end)
    return folder, rows
end

function M.GetDiagnostics()
    local hrp = LP.Character and LP.Character:FindFirstChild("HumanoidRootPart")
    local folder, drops = _scanDrops(hrp)
    local st = M.GetStats()
    return {
        loaded = true,
        running = enabled == true,
        claimBusy = claimBusy == true,
        storeEnabled = _resolveEnabledFromStore(),
        folder = folder and folder:GetFullName() or nil,
        dropCount = #drops,
        drops = drops,
        stats = st,
        statusGlobal = G.AUTO_CLAIM_DROP_STATUS or rawget(_G, "AUTO_CLAIM_DROP_STATUS"),
    }
end

function M.PrintDiagnostics()
    return M.GetDiagnostics()
end
M.PrintStats = M.PrintDiagnostics
M.Debug = M.PrintDiagnostics

function M.DebugClaimNearest()
    _loadNetworking()
    local hrp = LP.Character and LP.Character:FindFirstChild("HumanoidRootPart")
    if not hrp then return false, "no_hrp" end
    local best, dist, folder = _findNearestDrop(hrp, math.huge)
    if not folder then return false, "no_folder" end
    if not best then return false, "no_drop" end
    local hasPrompt = _findPrompt(best) ~= nil
    local ok, method = _attemptClaim(best, hrp)
    return ok, method or "fail", best.Name, dist, hasPrompt
end

G.AutoClaimDrop = M
G.AutoClaimDropModule = M
rawset(_G, "AutoClaimDrop", M)
rawset(_G, "AutoClaimDropModule", M)
G.__GAG2_AUTO_CLAIM_DROP_READY = true
rawset(_G, "__GAG2_AUTO_CLAIM_DROP_READY", true)
G.__GAG2_SYNC_AUTO_CLAIM_DROP = function() M.SyncFromStore() end
rawset(_G, "__GAG2_SYNC_AUTO_CLAIM_DROP", G.__GAG2_SYNC_AUTO_CLAIM_DROP)

task.defer(function()
    task.wait(0.5)
    M.SyncFromStore()
end)

return M
 end,                required = false },
    { key = "SectionAutoGift",         name = "Section Auto Gift",       factory = function() -- section_auto_gift.lua — Auto Gift tab (store + Gift Mail UI)
