local bodyGiftOnce = ui:CreateSection("Gift Mail (Once)", false)
local targetDdApi = createGiftTargetDropdown(bodyGiftOnce, "once", FriendStealList)

local statusRow, statusLabel = ui:CreateRowLabel(bodyGiftOnce, "Status: Ready", nil, nil, "info")
setupGiftStatusLabel(statusRow, statusLabel)
G.__GAG2_REFRESH_GIFT_ONCE_STATUS = function()
    refreshStatusLabel(statusLabel, "once")
end
_G.__GAG2_REFRESH_GIFT_ONCE_STATUS = G.__GAG2_REFRESH_GIFT_ONCE_STATUS
task.spawn(function()
    while statusLabel and statusLabel.Parent do
        refreshStatusLabel(statusLabel, "once")
        task.wait(giftStatusPollInterval(getAutoGiftModule(), "once"))
    end
end)

local onceSendTotalRow = nil
local onceSendTotalLabel = nil
local onceSendTotalSetFn = nil
local onceSendTotalActiveMode = "total"
local onceCatRow = nil
local onceHarvestConfigLabel = nil
local onceHarvestPriceRows = {}

local function setOnceSendTotalInputValue(sendMode, categories, store)
    if type(onceSendTotalSetFn) ~= "function" then return end
    store = store or ensureAutoGiftStore()
    categories = type(categories) == "table" and categories or store.once.categories
    sendMode = normalizeOnceSendMode(sendMode or store.once.send_mode)
    if giftOnceUsesPriceMode(categories, sendMode) then
        pcall(onceSendTotalSetFn, formatGiftSendTotalDisplay(store.once.send_total or 1000))
    else
        pcall(onceSendTotalSetFn, giftOnceSendCountDisplay(categories, store))
    end
end

local function refreshOnceSendTotalRows(categories, sendMode)
    local store = ensureAutoGiftStore()
    categories = type(categories) == "table" and categories or store.once.categories
    sendMode = normalizeOnceSendMode(sendMode or readOnceSendModeFromUi())
    onceSendTotalActiveMode = sendMode
    local priceMode = giftOnceUsesPriceMode(categories, sendMode)
    if onceSendTotalLabel then
        onceSendTotalLabel.Text = priceMode and "Send total price (1K / 1M)" or "Send total"
    end
    setOnceSendTotalInputValue(sendMode, categories, store)
end

local function refreshOnceSendModeUi(sendMode)
    local store = ensureAutoGiftStore()
    sendMode = normalizeOnceSendMode(sendMode or readOnceSendModeFromUi())
    local priceMode = onceSendModeIsPrice(sendMode)

    if onceHarvestConfigLabel then
        onceHarvestConfigLabel.Visible = true
    end
    for _, row in ipairs(onceHarvestPriceRows) do
        if row then row.Visible = priceMode end
    end

    refreshOnceSendTotalRows(store.once.categories, sendMode)

    if G.__GAG2_GIFT_SKIP_DROPDOWN_REFRESH ~= true then
        local refreshFn = G.__GAG2_REFRESH_ONCE_CATEGORY_LISTS or rawget(_G, "__GAG2_REFRESH_ONCE_CATEGORY_LISTS")
        if type(refreshFn) == "function" then
            pcall(refreshFn, sendMode)
        end
    end
end

local function applyOnceSendTotalInputsFromProfile(prof, store)
    store = store or ensureAutoGiftStore()
    prof = normalizeGiftProfileFields(prof, true)
    refreshOnceSendTotalRows(prof.categories, prof.send_mode)
end

local function syncGiftProfileFromUi(profileKey)
    if G.__GAG2_AUTO_GIFT_UI_READY ~= true then return end
    local opts = flushGiftProfileFromUi(profileKey)
    mergeGiftProfileOpts(profileKey, opts)
end

local function readOnceSendTotalTarget(store)
    store = store or ensureAutoGiftStore()
    local mode = normalizeOnceSendMode(store.once.send_mode)
    if giftOnceUsesPriceMode(store.once.categories, mode) then
        return math.floor(tonumber(store.once.send_total) or 1000)
    end
    local catKey = firstEnabledCategoryKey(store.once.categories)
    if catKey and type(store.send_totals) == "table" then
        return math.floor(tonumber(store.send_totals[catKey]) or 20)
    end
    return 20
end

local function checkGiftSendTotalAvailability(profileKey, targetN, priceMode)
    profileKey = (profileKey == "loop") and "loop" or "once"
    targetN = math.floor(tonumber(targetN) or 0)
    if targetN < 1 then return end
    syncGiftProfileFromUi(profileKey)
    if profileKey == "loop" then
        applyGiftLoopRuntime()
    else
        applyGiftOnceRuntime()
    end
    local ag = getAutoGiftModule()
    if type(ag) ~= "table" then return end
    if type(ag.CheckSendTotalAvailability) == "function" then
        local ok, pass, err = pcall(function()
            return ag.CheckSendTotalAvailability(ag, targetN, priceMode == true)
        end)
        if ok then
            if pass == false then
                setGiftAvailabilityStatus(tostring(err or "Item kurang"))
                return
            end
            local cur = tostring(G.AUTO_GIFT_ONCE_STATUS or rawget(_G, "AUTO_GIFT_ONCE_STATUS") or "")
            if cur:find("kurang", 1, true) or cur:find("Tidak ada item giftable", 1, true) then
                setGiftAvailabilityStatus("Ready")
            end
            return
        end
    end
    local available = getGiftSendableMax(profileKey)
    if available < 1 then
        setGiftAvailabilityStatus("Tidak ada item giftable di inventory untuk category terpilih")
        return
    end
    if targetN > available then
        local msg = (priceMode == true)
            and ("Value kurang: punya " .. formatGiftSendTotalDisplay(available)
                .. ", butuh " .. formatGiftSendTotalDisplay(targetN))
            or ("Item kurang: punya " .. tostring(available) .. ", butuh " .. tostring(targetN))
        setGiftAvailabilityStatus(msg)
    else
        local cur = tostring(G.AUTO_GIFT_ONCE_STATUS or rawget(_G, "AUTO_GIFT_ONCE_STATUS") or "")
        if cur:find("kurang", 1, true) then
            setGiftAvailabilityStatus("Ready")
        end
    end
end

G.__GAG2_CHECK_GIFT_SEND_TOTAL = function()
    local store = ensureAutoGiftStore()
    local mode = normalizeOnceSendMode(store.once.send_mode)
    local priceMode = giftOnceUsesPriceMode(store.once.categories, mode)
    checkGiftSendTotalAvailability("once", readOnceSendTotalTarget(store), priceMode)
end
_G.__GAG2_CHECK_GIFT_SEND_TOTAL = G.__GAG2_CHECK_GIFT_SEND_TOTAL

local function getGiftSendableMax(profile)
    syncGiftProfileFromUi(profile)
    local ag = getAutoGiftModule()
    if type(ag) ~= "table" then return 0 end
    local store = ensureAutoGiftStore()
    local prof = (profile == "loop") and store.loop or store.once
    local priceMode = false
    if profile ~= "loop" then
        local ok, v = pcall(
            giftOnceUsesPriceMode,
            prof.categories,
            prof.send_mode or store.once.send_mode
        )
        priceMode = ok and v == true
    end
    if type(ag.ApplyConfig) == "function" then
        pcall(ag.ApplyConfig, ag, giftConfigFromProfile(store, profile or "once"))
    end
    if type(ag.InvalidateHarvestFruitCache) == "function" then
        pcall(ag.InvalidateHarvestFruitCache, ag)
    end
    if priceMode and type(ag.CountSendablePrice) == "function" then
        local ok, n = pcall(ag.CountSendablePrice, ag)
        if ok and type(n) == "number" then
            return math.max(0, math.floor(n))
        end
    end
    if type(ag.CountSendableUnits) == "function" then
        local ok, n = pcall(ag.CountSendableUnits, ag)
        if ok and type(n) == "number" then
            return math.max(0, math.floor(n))
        end
    end
    return 0
end

local function buildGiftMailProfileUi(body, profileKey)
    local prefix = string.upper(profileKey)
    local allowMultiMode = (profileKey == "loop")
    local store = ensureAutoGiftStore()
    local profile = (profileKey == "loop") and store.loop or store.once
    local itemDropdowns = {}
    local syncingCategoryUi = false
    local catMultiDd = nil
    local catModeDd = nil

    local function applyCategorySelection(selectedMap, persist)
        selectedMap = type(selectedMap) == "table" and selectedMap or {}
        local cats = {}
        for _, def in ipairs(buildGiftCatUiDefs()) do
            cats[def.key] = selectedMap[def.key] == true
        end
        local onceSendMode = (profileKey == "once") and readOnceSendModeFromUi() or "total"
        for _, def in ipairs(buildGiftCatUiDefs()) do
            local entry = itemDropdowns[def.key]
            if entry then
                local showList = onceCategoryShowsItemList(profileKey, def.key, onceSendMode)
                local show = cats[def.key] == true and showList
                if entry.row then
                    local wasVisible = entry.row.Visible
                    entry.row.Visible = show
                    if show and not wasVisible and G.__GAG2_GIFT_UI_BOOTSTRAP ~= true
                        and type(entry.dd) == "table" and type(entry.dd.refreshItems) == "function" then
                        pcall(entry.dd.refreshItems, entry.dd)
                    end
                end
            end
        end
        if profileKey == "once" then
            refreshOnceSendTotalRows(cats, onceSendMode)
        end
        if persist and not syncingCategoryUi then
            local patch = { categories = cats }
            patchGiftProfile(profileKey, patch, function()
                if profileKey == "loop" then
                    applyGiftLoopRuntime()
                else
                    applyGiftOnceRuntime()
                end
            end)
        end
    end

    local function applyGiftCategoryMode(mode, persist)
        if not allowMultiMode then return end
        mode = (mode == "multi") and "multi" or "single"
        if type(catMultiDd) == "table" and type(catMultiDd.setMode) == "function" then
            catMultiDd.setMode(mode)
            if mode == "multi" and type(catMultiDd.getSelected) == "function" then
                local sel = safeDdGetSelected(catMultiDd)
                if type(sel) == "string" and sel ~= "" then
                    catMultiDd.setSelected({ [sel] = true })
                end
            elseif mode == "single" and type(catMultiDd.getSelected) == "function" then
                local sel = safeDdGetSelected(catMultiDd)
                if type(sel) == "table" then
                    catMultiDd.setSelected(firstEnabledCategoryKey(sel))
                end
            end
        end
        if persist then
            patchGiftProfile(profileKey, { category_mode = mode }, function() applyGiftLoopRuntime() end)
        end
        if type(catMultiDd) == "table" and type(catMultiDd.getSelected) == "function" then
            local sel = safeDdGetSelected(catMultiDd)
            if mode == "single" then
                local key = sel
                if type(key) == "table" then key = firstEnabledCategoryKey(key) end
                local map = {}
                for _, def in ipairs(buildGiftCatUiDefs()) do
                    map[def.key] = (key ~= nil and def.key == tostring(key))
                end
                applyCategorySelection(map, false)
            elseif type(sel) == "table" then
                applyCategorySelection(sel, false)
            end
        end
    end

    if allowMultiMode then
        local _, catModeDdApi = ui:CreateRowDropdown(body, {
            label = "Category mode",
            placeholder = "Single",
            mode = "single",
            getItems = function()
                return {
                    { key = "single", name = "Single" },
                    { key = "multi", name = "Multi" },
                }
            end,
            initial = giftCategoryModeFromProfile(profile, false),
            onChanged = function(_, key)
                applyGiftCategoryMode(tostring(key or "single"), true)
            end,
        })
        catModeDd = catModeDdApi
        G["__GAG2_AUTO_GIFT_" .. prefix .. "_CATEGORY_MODE"] = catModeDdApi
        _G["__GAG2_AUTO_GIFT_" .. prefix .. "_CATEGORY_MODE"] = catModeDdApi
    end

    local catInitMode = allowMultiMode and giftCategoryModeFromProfile(profile, false) or "single"
    onceCatRow, catMultiDd = ui:CreateRowDropdown(body, {
        label = "Categories",
        placeholder = allowMultiMode and "Select categories..." or "Select category...",
        mode = catInitMode,
        getItems = function()
            local items = {}
            for _, def in ipairs(buildGiftCatUiDefs()) do
                items[#items + 1] = { key = def.key, name = def.label }
            end
            return items
        end,
        initial = (catInitMode == "single")
            and firstEnabledCategoryKey(profile.categories)
            or categoriesToMultiMap(profile.categories),
        onChanged = function(ddMode, value)
            ddMode = tostring(ddMode or "single")
            if ddMode == "single" then
                local key = value
                local map = {}
                for _, def in ipairs(buildGiftCatUiDefs()) do
                    map[def.key] = (key ~= nil and def.key == tostring(key))
                end
                applyCategorySelection(map, true)
            elseif type(value) == "table" then
                applyCategorySelection(value, true)
            end
        end,
    })
    if profileKey ~= "once" then
        onceCatRow = nil
    end
    G["__GAG2_AUTO_GIFT_" .. prefix .. "_CAT"] = catMultiDd
    _G["__GAG2_AUTO_GIFT_" .. prefix .. "_CAT"] = catMultiDd

    for _, def in ipairs(buildGiftCatUiDefs()) do
        local catKey = def.key
        if profileKey == "loop" and isGiftCategoryNoList(catKey) then
            itemDropdowns[catKey] = { row = nil, dd = nil, noList = true }
        else
            local row, itemDd = ui:CreateRowDropdown(body, {
                label = def.itemLabel,
                placeholder = def.placeholder,
                mode = "multi",
                deferItemLoad = true,
                labelForKey = function(key)
                    return tostring(key or "")
                end,
                getItems = function()
                    local ag = getAutoGiftModule()
                    if type(ag) == "table" and type(ag.BuildInventoryItems) == "function" then
                        local ok, items = pcall(ag.BuildInventoryItems, ag, catKey)
                        if ok and type(items) == "table" then return items end
                    end
                    return {}
                end,
                initial = cleanSelectedMap(profile.selected[catKey]),
                onChanged = function(_, value)
                    patchGiftProfile(profileKey, {
                        selected = { [catKey] = cleanSelectedMap(value) },
                    }, function()
                        if profileKey == "loop" then
                            applyGiftLoopRuntime()
                        else
                            applyGiftOnceRuntime()
                        end
                    end)
                    if profileKey == "once" then
                        local checkFn = G.__GAG2_CHECK_GIFT_SEND_TOTAL or rawget(_G, "__GAG2_CHECK_GIFT_SEND_TOTAL")
                        if type(checkFn) == "function" then
                            pcall(checkFn)
                        end
                    end
                end,
            })
            row.Visible = false
            itemDropdowns[catKey] = { row = row, dd = itemDd, noList = false }
            G["__GAG2_AUTO_GIFT_" .. prefix .. "_DD_" .. catKey] = itemDd
            _G["__GAG2_AUTO_GIFT_" .. prefix .. "_DD_" .. catKey] = itemDd
        end
    end

    applyCategorySelection(profile.categories, false)

    if profileKey == "once" then
        G.__GAG2_REFRESH_ONCE_CATEGORY_LISTS = function(mode)
            local sm = normalizeOnceSendMode(mode or readOnceSendModeFromUi())
            local cats = {}
            local store = ensureAutoGiftStore()
            for _, def in ipairs(buildGiftCatUiDefs()) do
                cats[def.key] = store.once.categories[def.key] == true
            end
            applyCategorySelection(cats, false)
            if G.__GAG2_GIFT_UI_BOOTSTRAP ~= true and G.__GAG2_GIFT_SKIP_DROPDOWN_REFRESH ~= true then
                refreshItems(true)
            end
        end
        _G.__GAG2_REFRESH_ONCE_CATEGORY_LISTS = G.__GAG2_REFRESH_ONCE_CATEGORY_LISTS
    end

    local function refreshItems(visibleOnly)
        local ag = getAutoGiftModule()
        if type(ag) == "table" and type(ag.InvalidateHarvestFruitCache) == "function" then
            pcall(ag.InvalidateHarvestFruitCache, ag)
        end
        for _, def in ipairs(buildGiftCatUiDefs()) do
            local entry = itemDropdowns[def.key]
            if entry and not entry.noList and type(entry.dd) == "table" and type(entry.dd.refreshItems) == "function" then
                local show = not visibleOnly or (entry.row and entry.row.Visible)
                if show then
                    pcall(entry.dd.refreshItems, entry.dd)
                end
            end
        end
    end

    local function restoreUi()
        store = ensureAutoGiftStore()
        profile = (profileKey == "loop") and store.loop or store.once
        if type(catMultiDd) == "table" and type(catMultiDd.setSelected) == "function" then
            syncingCategoryUi = true
            local cm = allowMultiMode and giftCategoryModeFromProfile(profile, false) or "single"
            if cm == "single" then
                catMultiDd.setSelected(firstEnabledCategoryKey(profile.categories))
            else
                catMultiDd.setSelected(categoriesToMultiMap(profile.categories))
            end
            syncingCategoryUi = false
        end
        applyCategorySelection(profile.categories, false)
        for _, def in ipairs(buildGiftCatUiDefs()) do
            local entry = itemDropdowns[def.key]
            if entry and not entry.noList and type(entry.dd) == "table" and type(entry.dd.setSelected) == "function" then
                entry.dd.setSelected(cleanSelectedMap(profile.selected[def.key]))
            end
        end
    end

    return {
        itemDropdowns = itemDropdowns,
        catMultiDd = catMultiDd,
        catModeDd = catModeDd,
        applyCategorySelection = applyCategorySelection,
        applyGiftCategoryMode = applyGiftCategoryMode,
        refreshItems = refreshItems,
        restoreUi = restoreUi,
        syncingCategoryUi = function() return syncingCategoryUi end,
        setSyncing = function(v) syncingCategoryUi = v == true end,
    }
end

