        or giftOnceSendCountDisplay(initStore.once.categories, initStore),
    function(txt)
        local store = ensureAutoGiftStore()
        local mode = normalizeOnceSendMode(onceSendTotalActiveMode or readOnceSendModeFromUi())
        if giftOnceUsesPriceMode(store.once.categories, mode) then
            local n = parseGiftSendTotalPrice(txt)
