    function(isOn)
        if isOn == true then
            local onceApi = G.__GAG2_AUTO_GIFT_SEND_API or rawget(_G, "__GAG2_AUTO_GIFT_SEND_API")
            if type(onceApi) == "table" and type(onceApi.set) == "function" then
                pcall(onceApi.set, false, true)
            end
            local ag = getAutoGiftModule()
            if type(ag) == "table" and type(ag.StopSendJob) == "function" then
                pcall(ag.StopSendJob, ag)
            end
            patchGift({ auto_send = true }, function() applyGiftLoopRuntime() end)
        else
            patchGift({ auto_send = false }, function() applyAutoGiftRuntime(nil) end)
        end
    end
)
G.__GAG2_AUTO_GIFT_AUTO_SEND_API = loopSendApi
