local function applyOnceUiFromProfile(prof)
    prof = normalizeGiftProfileFields(prof, true)
    onceUi.setSyncing(true)
    if type(targetDdApi) == "table" and type(targetDdApi.setSelected) == "function" then
        local uid = math.floor(tonumber(prof.recipient_user_id) or 0)
        pcall(targetDdApi.setSelected, uid > 0 and tostring(uid) or nil)
    end
    local afterDd = G.__GAG2_AUTO_GIFT_ONCE_AFTER_SEND_MODE or rawget(_G, "__GAG2_AUTO_GIFT_ONCE_AFTER_SEND_MODE")
    if type(afterDd) == "table" and type(afterDd.setSelected) == "function" then
        pcall(afterDd.setSelected, (prof.after_send_mode == "reset") and "reset" or "keep")
    end
    applyOnceSendTotalInputsFromProfile(prof)
    local thresholdFn = G.__GAG2_AUTO_GIFT_ONCE_HARVEST_THRESHOLD or rawget(_G, "__GAG2_AUTO_GIFT_ONCE_HARVEST_THRESHOLD")
    if type(thresholdFn) == "function" then
        pcall(thresholdFn, tostring(prof.harvest_price_threshold_pct or 10))
    end
    local calcDd = G.__GAG2_AUTO_GIFT_ONCE_HARVEST_CALC_MODE or rawget(_G, "__GAG2_AUTO_GIFT_ONCE_HARVEST_CALC_MODE")
    if type(calcDd) == "table" and type(calcDd.setSelected) == "function" then
        pcall(calcDd.setSelected, normalizeGiftOnceHarvestCalcMode(prof.harvest_price_calc_mode))
    end
    onceUi.applyCategorySelection(prof.categories, false)
    for _, def in ipairs(buildGiftCatUiDefs()) do
        local entry = onceUi.itemDropdowns[def.key]
        if entry and not entry.noList and type(entry.dd) == "table" and type(entry.dd.setSelected) == "function" then
            pcall(entry.dd.setSelected, cleanSelectedMap(prof.selected[def.key]))
        end
    end
    onceUi.setSyncing(false)
end

local function applyLoopUiFromProfile(prof)
    prof = normalizeGiftProfileFields(prof, false)
    loopUi.setSyncing(true)
    if type(loopTargetDdApi) == "table" and type(loopTargetDdApi.setSelected) == "function" then
        local uid = math.floor(tonumber(prof.recipient_user_id) or 0)
        pcall(loopTargetDdApi.setSelected, uid > 0 and tostring(uid) or nil)
    end
    local afterDd = G.__GAG2_AUTO_GIFT_LOOP_AFTER_SEND_MODE or rawget(_G, "__GAG2_AUTO_GIFT_LOOP_AFTER_SEND_MODE")
    if type(afterDd) == "table" and type(afterDd.setSelected) == "function" then
        pcall(afterDd.setSelected, (prof.after_send_mode == "reset") and "reset" or "keep")
    end
    if type(loopUi.catModeDd) == "table" and type(loopUi.catModeDd.setSelected) == "function" then
        local cm = giftCategoryModeFromProfile(prof, false)
        pcall(loopUi.catModeDd.setSelected, cm)
    end
    loopUi.applyGiftCategoryMode(giftCategoryModeFromProfile(prof, false), false)
    loopUi.applyCategorySelection(prof.categories, false)
    for _, def in ipairs(buildGiftCatUiDefs()) do
        local entry = loopUi.itemDropdowns[def.key]
        if entry and not entry.noList and type(entry.dd) == "table" and type(entry.dd.setSelected) == "function" then
            pcall(entry.dd.setSelected, cleanSelectedMap(prof.selected[def.key]))
        end
    end
    loopUi.setSyncing(false)
end

local function resetGiftOnceUi()
    G.__GAG2_RESETTING = true
    _G.__GAG2_RESETTING = true

    local s = ensureAutoGiftStore()
    local keepAfterSend = s.once and s.once.after_send_mode or "keep"
    local keepCategories = copyGiftCategoryMap(s.once and s.once.categories)
    local keepThreshold = s.once and s.once.harvest_price_threshold_pct or 10
    local keepCalcMode = s.once and s.once.harvest_price_calc_mode or "base"
    s.once = defaultGiftProfile(true)
    s.once.after_send_mode = keepAfterSend
    s.once.categories = keepCategories
    s.once.harvest_price_threshold_pct = keepThreshold
    s.once.harvest_price_calc_mode = keepCalcMode
    s.recipient_username = s.once.recipient_username
    s.recipient_user_id = s.once.recipient_user_id
    s.recipient_display = s.once.recipient_display

    applyOnceUiFromProfile(s.once)
    writeAutoGiftToMain()
    applyGiftOnceRuntime()

    G.__GAG2_RESETTING = false
    _G.__GAG2_RESETTING = false
    saveNow()
end
G.__GAG2_RESET_GIFT_ONCE = resetGiftOnceUi
_G.__GAG2_RESET_GIFT_ONCE = resetGiftOnceUi

local function resetGiftLoopUi()
    G.__GAG2_RESETTING = true
    _G.__GAG2_RESETTING = true

    local s = ensureAutoGiftStore()
    local keepAfterSend = s.loop and s.loop.after_send_mode or "keep"
    local keepCategories = copyGiftCategoryMap(s.loop and s.loop.categories)
    local keepCategoryMode = (s.loop and s.loop.category_mode == "multi") and "multi" or "single"
    s.auto_send = false
    s.loop = defaultGiftProfile(false)
    s.loop.after_send_mode = keepAfterSend
    s.loop.categories = keepCategories
    s.loop.category_mode = keepCategoryMode
    if type(G.__GAG2_AUTO_GIFT_AUTO_SEND_API) == "table"
        and type(G.__GAG2_AUTO_GIFT_AUTO_SEND_API.set) == "function" then
        pcall(G.__GAG2_AUTO_GIFT_AUTO_SEND_API.set, false, true)
    end

    applyLoopUiFromProfile(s.loop)
    writeAutoGiftToMain()
    applyGiftLoopRuntime()

    G.__GAG2_RESETTING = false
    _G.__GAG2_RESETTING = false
    saveNow()
end
G.__GAG2_RESET_GIFT_LOOP = resetGiftLoopUi
_G.__GAG2_RESET_GIFT_LOOP = resetGiftLoopUi

