    local function ensureBuyPetStore()
        local s = G.__GAG2_BUY_PET
        if type(s) ~= "table" then
            s = {
                enabled = false,
                auto_tame = false,
                max_steal_price = 100000000,
                selected = {},
                targets = {},
                skip_steal_friends = {},
            }
            G.__GAG2_BUY_PET = s
        end

        s.enabled = (s.enabled == true)
        s.auto_tame = (s.auto_tame == true)
        local SectionBuyPet = G.SectionAutoBuyPet or rawget(_G, "SectionAutoBuyPet")
        if type(SectionBuyPet) == "table" and type(SectionBuyPet.normalizeMaxStealPrice) == "function" then
            s.max_steal_price = SectionBuyPet.normalizeMaxStealPrice(s.max_steal_price)
        else
            s.max_steal_price = math.floor(tonumber(s.max_steal_price) or 100000000)
        end
        s.selected = cleanSelectedMap(s.selected or {})
        s.targets = type(s.targets) == "table" and s.targets or {}
        s.skip_steal_friends = type(s.skip_steal_friends) == "table" and s.skip_steal_friends or {}

        if not s._hydrated then
            local m = getMainRef()
            if type(m) == "table" and type(m.auto) == "table"
                and type(m.auto.buy) == "table" and type(m.auto.buy.pet) == "table" then
                local pet = m.auto.buy.pet
                s.enabled = (pet.enabled == true)
                s.auto_tame = (pet.auto_tame == true)
                local sp = tonumber(pet.max_steal_price)
                if sp and sp > 0 then s.max_steal_price = sp end
                if type(pet.items) == "table" and next(pet.items) then
                    s.selected = cleanSelectedMap(arrayToMap(pet.items))
                end
                if type(pet.targets) == "table" and #pet.targets > 0 then
                    s.targets = pet.targets
                end
                if type(pet.skip_steal_friends) == "table" then
                    s.skip_steal_friends = pet.skip_steal_friends
                end
            end
            s._hydrated = true
        end

        if type(SectionBuyPet) == "table" then
            if type(SectionBuyPet.deserializeTargets) == "function" then
                s.targets = SectionBuyPet.deserializeTargets(s.targets)
            end
            if (#s.targets == 0) and next(s.selected) and type(SectionBuyPet.migrateFromSelected) == "function" then
                s.targets = SectionBuyPet.migrateFromSelected(s.selected)
            end
            if type(SectionBuyPet.normalizeTargets) == "function" then
                s.targets = SectionBuyPet.normalizeTargets(s.targets)
            end
            -- Legacy global ON Ã¢â€ â€™ per-target ON, sekali saja (jangan ulang tiap commit / add pet)
            if s.enabled == true and s._legacyGlobalMigrated ~= true and type(SectionBuyPet) == "table" then
                for _, t in ipairs(s.targets) do
                    if type(t) == "table" and t.enabled ~= true then
                        t.enabled = true
                    end
                end
                s._legacyGlobalMigrated = true
                s.enabled = false
            end
            if type(SectionBuyPet.targetsToSelected) == "function" then
                s.selected = SectionBuyPet.targetsToSelected(s.targets)
            end
        end

        G.__GAG2_BUY_PET = s
        _G.__GAG2_BUY_PET = s
        return s
    end

    local function writeBuyPetToMain()
        local s = ensureBuyPetStore()
        local SectionBuyPet = G.SectionAutoBuyPet or rawget(_G, "SectionAutoBuyPet")
        if type(SectionBuyPet) == "table" and type(SectionBuyPet.anyTargetEnabled) == "function" then
            s.enabled = SectionBuyPet.anyTargetEnabled(s.targets) == true
        else
            local anyOn = false
            for _, t in ipairs(s.targets or {}) do
                if type(t) == "table" and t.enabled == true then
                    anyOn = true
                    break
                end
            end
            s.enabled = anyOn
        end
        G.__GAG2_BUY_PET = s
        _G.__GAG2_BUY_PET = s

        G.AUTO_BUY_PET_ENABLED = s.enabled
        _G.AUTO_BUY_PET_ENABLED = s.enabled
        G.AUTO_TAME_PET_ENABLED = s.auto_tame
        _G.AUTO_TAME_PET_ENABLED = s.auto_tame
        G.AUTO_BUY_PET_MAX_STEAL_PRICE = s.max_steal_price
        _G.AUTO_BUY_PET_MAX_STEAL_PRICE = s.max_steal_price
        G.BUY_PET_SELECTED = s.selected
        _G.BUY_PET_SELECTED = s.selected
        G.GAG2_PET_LIST = mapToArray(s.selected)
        _G.GAG2_PET_LIST = G.GAG2_PET_LIST

        local serializedTargets = s.targets
        local SectionBuyPet = G.SectionAutoBuyPet or rawget(_G, "SectionAutoBuyPet")
        if type(SectionBuyPet) == "table" and type(SectionBuyPet.serializeTargets) == "function" then
            serializedTargets = SectionBuyPet.serializeTargets(s.targets)
        end
        G.BUY_PET_TARGETS = serializedTargets
        _G.BUY_PET_TARGETS = serializedTargets

        local m = getMainRef()
        if type(m) == "table" then
            m.auto = m.auto or {}
            m.auto.buy = m.auto.buy or {}
            m.auto.buy.pet = {
                enabled = s.enabled,
                auto_tame = s.auto_tame,
                max_steal_price = s.max_steal_price,
                items = mapToArray(s.selected),
                targets = serializedTargets,
                skip_steal_friends = s.skip_steal_friends,
            }
            G.MAIN = m
            _G.MAIN = m
        end

        patchAutoOnly("buy", {
            pet = {
                enabled = s.enabled,
                auto_tame = s.auto_tame,
                max_steal_price = s.max_steal_price,
                items = mapToArray(s.selected),
                targets = serializedTargets,
                skip_steal_friends = s.skip_steal_friends,
            },
        })

        return s
    end

    local function writeBuyPetState(opts)
        local s = ensureBuyPetStore()
        if type(opts) == "table" then
            if opts.enabled ~= nil then s.enabled = (opts.enabled == true) end
            if opts.auto_tame ~= nil then s.auto_tame = (opts.auto_tame == true) end
            if opts.max_steal_price ~= nil then
                local SectionBuyPet = G.SectionAutoBuyPet or rawget(_G, "SectionAutoBuyPet")
                if type(SectionBuyPet) == "table" and type(SectionBuyPet.normalizeMaxStealPrice) == "function" then
                    s.max_steal_price = SectionBuyPet.normalizeMaxStealPrice(opts.max_steal_price)
                else
                    s.max_steal_price = math.floor(tonumber(opts.max_steal_price) or 100000000)
                end
            end
            if opts.selected ~= nil then
                s.selected = cleanSelectedMap(opts.selected)
            end
            if opts.targets ~= nil then
                local SectionBuyPet = G.SectionAutoBuyPet or rawget(_G, "SectionAutoBuyPet")
                if type(SectionBuyPet) == "table" and type(SectionBuyPet.deserializeTargets) == "function" then
                    s.targets = SectionBuyPet.deserializeTargets(opts.targets)
                    if type(SectionBuyPet.normalizeTargets) == "function" then
                        s.targets = SectionBuyPet.normalizeTargets(s.targets)
                    end
                    if type(SectionBuyPet.targetsToSelected) == "function" then
                        s.selected = SectionBuyPet.targetsToSelected(s.targets)
                    end
                else
                    s.targets = opts.targets
                end
            end
            if opts.skip_steal_friends ~= nil then
                s.skip_steal_friends = opts.skip_steal_friends
            end
        end
        return writeBuyPetToMain()
    end

    local function readBuyPetAutoTame()
        local s = ensureBuyPetStore()
        if s.auto_tame == true then return true end

        local m = getMainRef()
        if type(m) == "table" and type(m.auto) == "table"
            and type(m.auto.buy) == "table" and type(m.auto.buy.pet) == "table" then
            if m.auto.buy.pet.auto_tame == true then
                s.auto_tame = true
                G.__GAG2_BUY_PET = s
                _G.__GAG2_BUY_PET = s
                return true
            end
        end

        if G.AUTO_TAME_PET_ENABLED == true or rawget(_G, "AUTO_TAME_PET_ENABLED") == true then
            s.auto_tame = true
            G.__GAG2_BUY_PET = s
            _G.__GAG2_BUY_PET = s
            return true
        end

        return false
    end

    local function readBuyPetEnabled()
        local s = ensureBuyPetStore()
        local SectionBuyPet = G.SectionAutoBuyPet or rawget(_G, "SectionAutoBuyPet")
        local hasTargets = type(s.targets) == "table" and #s.targets > 0
        if hasTargets then
            if type(SectionBuyPet) == "table" and type(SectionBuyPet.anyTargetEnabled) == "function" then
                return SectionBuyPet.anyTargetEnabled(s.targets) == true
            end
            for _, t in ipairs(s.targets) do
                if type(t) == "table" and t.enabled == true then return true end
            end
            return false
        end

        if s.enabled == true then return true end

        local m = getMainRef()
        if type(m) == "table" and type(m.auto) == "table"
            and type(m.auto.buy) == "table" and type(m.auto.buy.pet) == "table" then
            if m.auto.buy.pet.enabled == true then
                s.enabled = true
                G.__GAG2_BUY_PET = s
                _G.__GAG2_BUY_PET = s
                return true
            end
        end

        if G.AUTO_BUY_PET_ENABLED == true or rawget(_G, "AUTO_BUY_PET_ENABLED") == true then
            s.enabled = true
            G.__GAG2_BUY_PET = s
            _G.__GAG2_BUY_PET = s
            return true
        end

        return false
    end

    local function getAutoBuyPetModule()
        return G.AutoBuyPetModule or G.AutoBuyPet or _G.AutoBuyPetModule or _G.AutoBuyPet
    end

    local function syncBuyPetStoreFromMain()
        local s = ensureBuyPetStore()
        local SectionBuyPet = G.SectionAutoBuyPet or rawget(_G, "SectionAutoBuyPet")
        local hasTargets = type(s.targets) == "table" and #s.targets > 0
        local m = getMainRef()
        if type(m) == "table" and type(m.auto) == "table"
            and type(m.auto.buy) == "table" and type(m.auto.buy.pet) == "table" then
            local pet = m.auto.buy.pet
            if not hasTargets and pet.enabled == true then s.enabled = true end
            if pet.auto_tame == true then s.auto_tame = true end
            local sp = tonumber(pet.max_steal_price)
            if sp and sp > 0 then s.max_steal_price = sp end
            if not hasTargets and type(pet.items) == "table" and next(pet.items) then
                local fromMain = cleanSelectedMap(arrayToMap(pet.items))
                if next(fromMain) then
                    if not next(s.selected) then
                        s.selected = fromMain
                    end
                end
            end
        end
        if not hasTargets and (G.AUTO_BUY_PET_ENABLED == true or rawget(_G, "AUTO_BUY_PET_ENABLED") == true) then
            s.enabled = true
        end
        if G.AUTO_TAME_PET_ENABLED == true or rawget(_G, "AUTO_TAME_PET_ENABLED") == true then
            s.auto_tame = true
        end
        local petMap = G.BUY_PET_SELECTED or rawget(_G, "BUY_PET_SELECTED")
        if type(petMap) == "table" and next(petMap) and not next(s.selected) then
            s.selected = cleanSelectedMap(petMap)
        end
        G.__GAG2_BUY_PET = s
        _G.__GAG2_BUY_PET = s
        return s
    end

    local function applyBuyPetRuntime(on)
        if on == nil then
            syncBuyPetStoreFromMain()
            on = readBuyPetEnabled()
        else
            on = (on == true)
        end
        local s = ensureBuyPetStore()

        s = writeBuyPetState({
            enabled = on,
            selected = s.selected,
            targets = (function()
                local SectionBuyPet = G.SectionAutoBuyPet or rawget(_G, "SectionAutoBuyPet")
                if type(SectionBuyPet) == "table" and type(SectionBuyPet.serializeTargets) == "function" then
                    return SectionBuyPet.serializeTargets(s.targets)
                end
                return s.targets
            end)(),
        })

        local abp = getAutoBuyPetModule()
        if type(abp) ~= "table" then return end

        if type(abp.SetSelected) == "function" then
            pcall(abp.SetSelected, abp, s.selected)
        end
        if on then
            if type(abp.ApplyRuntime) == "function" then
                pcall(abp.ApplyRuntime, abp, true)
            elseif type(abp.Start) == "function" then
                pcall(abp.Start, abp)
            end
            if type(abp.EnsureRunning) == "function" then
                pcall(abp.EnsureRunning, abp)
            end
        else
            if type(abp.ApplyRuntime) == "function" then
                pcall(abp.ApplyRuntime, abp, false)
            elseif type(abp.Stop) == "function" then
                pcall(abp.Stop, abp)
            end
        end
    end

    local function flushBuyPetFromUI()
        if G.__GAG2_RESETTING == true then return end
        local opts = {}
        local targetsApi = G.__GAG2_BUY_PET_TARGETS_API or rawget(_G, "__GAG2_BUY_PET_TARGETS_API")
        if type(targetsApi) == "table" and type(targetsApi.getTargets) == "function" then
            opts.targets = targetsApi.getTargets()
        end
        local dd = G.__GAG2_BUY_PET_DROPDOWN_API or rawget(_G, "__GAG2_BUY_PET_DROPDOWN_API")
        if type(dd) == "table" and type(dd.getSelected) == "function" and opts.targets == nil then
            opts.selected = cleanSelectedMap(dd.getSelected())
        end
        if opts.targets ~= nil then
            local SectionBuyPet = G.SectionAutoBuyPet or rawget(_G, "SectionAutoBuyPet")
            if type(SectionBuyPet) == "table" and type(SectionBuyPet.anyTargetEnabled) == "function" then
                local targets = opts.targets
                if type(SectionBuyPet.deserializeTargets) == "function" then
                    targets = SectionBuyPet.deserializeTargets(targets)
                end
                opts.enabled = SectionBuyPet.anyTargetEnabled(targets) == true
            end
        end

        if next(opts) ~= nil then
            writeBuyPetState(opts)
        else
            syncBuyPetStoreFromMain()
            writeBuyPetToMain()
        end
    end

    local function syncAutoBuyPetAll()
        if G.__GAG2_RESETTING == true then
            syncBuyPetStoreFromMain()
            writeBuyPetToMain()
            applyBuyPetRuntime(false)
            return
        end
        flushBuyPetFromUI()
        applyBuyPetRuntime(readBuyPetEnabled())
    end

    local function saveBuyPetNow()
        flushBuyPetFromUI()
        saveNow()
    end

    local function patchBuyPet(opts, syncFn)
        writeBuyPetState(opts)
        if syncFn then pcall(syncFn) end
        saveNow()
    end

