        MAIN.auto.plant = MAIN.auto.plant or {}
        local AP_STATE = getAuto("plant")
        AP_STATE.seeds = type(AP_STATE.seeds) == "table" and AP_STATE.seeds or {}
        AP_STATE.positions = type(AP_STATE.positions) == "table" and AP_STATE.positions or {}
        AP_STATE.mode = tostring(AP_STATE.mode or "random"):lower()
        if AP_STATE.mode ~= "manual" then AP_STATE.mode = "random" end

        local function normalizePlantPositionId(v)
            if v == nil then return nil end
            if type(v) == "table" then
                v = v.id or v.key
            end
            v = tostring(v)
            if v == "" or v:sub(1, 6) == "table:" then return nil end
            return v
        end

        AP_STATE.selectedPosition = normalizePlantPositionId(AP_STATE.selectedPosition)
        if not AP_STATE.selectedPosition and #AP_STATE.positions > 0 then
            local first = AP_STATE.positions[1]
            if type(first) == "table" and first.id then
                AP_STATE.selectedPosition = tostring(first.id)
            end
        end
        AP_STATE.savePosition = false
        if AP_STATE.plantTotal ~= nil then
            AP_STATE.plantTotal = tonumber(AP_STATE.plantTotal)
        end
        if AP_STATE.plantTotal == nil then AP_STATE.plantTotal = 0 end
        if AP_STATE.plantTotal < 0 then AP_STATE.plantTotal = 0 end
        AP_STATE.plantTotal = math.floor(AP_STATE.plantTotal)

        AUTO_PLANT_SEEDS_SELECTED = cleanSelectedMap(arrayToMap(AP_STATE.seeds))
        G.AUTO_PLANT_SEEDS_SELECTED = AUTO_PLANT_SEEDS_SELECTED
        _G.AUTO_PLANT_SEEDS_SELECTED = AUTO_PLANT_SEEDS_SELECTED

        local function plantDelayDisplay()
            local n = tonumber(AP_STATE.delay)
            return (n ~= nil) and n or 0.5
        end

        local function plantTotalDisplay()
            local n = tonumber(AP_STATE.plantTotal)
            return (n ~= nil) and math.floor(n) or 0
        end

        local function buildPositionItems()
            local items = {}
            local positions = AP_STATE.positions
            if type(positions) ~= "table" then return items end
            for i, entry in ipairs(positions) do
                if type(entry) == "table" and entry.id then
                    local x = tonumber(entry.x) or 0
                    local z = tonumber(entry.z) or 0
                    items[#items + 1] = {
                        key = tostring(entry.id),
                        name = ("Pos %d (%.0f, %.0f)"):format(i, x, z),
                    }
                end
            end
            return items
        end

        local function writePlantGlobals()
            local api = G.__GAG2_PLANT_ENABLE_API or rawget(_G, "__GAG2_PLANT_ENABLE_API")
            if type(api) == "table" and type(api.get) == "function" then
                AP_STATE.enabled = (api.get() == true)
            end
            G.AUTO_PLANT_ENABLED = (AP_STATE.enabled == true)
            _G.AUTO_PLANT_ENABLED = G.AUTO_PLANT_ENABLED
            if AP_STATE.delay ~= nil then
                G.AUTO_PLANT_DELAY = tonumber(AP_STATE.delay)
                _G.AUTO_PLANT_DELAY = G.AUTO_PLANT_DELAY
            end
            G.AUTO_PLANT_SEEDS_SELECTED = AUTO_PLANT_SEEDS_SELECTED
            _G.AUTO_PLANT_SEEDS_SELECTED = AUTO_PLANT_SEEDS_SELECTED
            G.AUTO_PLANT_MODE = AP_STATE.mode
            _G.AUTO_PLANT_MODE = AP_STATE.mode
            G.AUTO_PLANT_SELECTED_POSITION = AP_STATE.selectedPosition
            _G.AUTO_PLANT_SELECTED_POSITION = AP_STATE.selectedPosition
            G.AUTO_PLANT_SAVE_POSITION = (AP_STATE.savePosition == true)
            _G.AUTO_PLANT_SAVE_POSITION = G.AUTO_PLANT_SAVE_POSITION
            G.AUTO_PLANT_AUTO_MANUAL = (AP_STATE.autoManual == true)
            _G.AUTO_PLANT_AUTO_MANUAL = G.AUTO_PLANT_AUTO_MANUAL
            G.AUTO_PLANT_TOTAL = plantTotalDisplay()
            _G.AUTO_PLANT_TOTAL = G.AUTO_PLANT_TOTAL
            patchAutoOnly("plant", {
                enabled = (AP_STATE.enabled == true),
                seeds = mapToArray(AUTO_PLANT_SEEDS_SELECTED),
                positions = type(AP_STATE.positions) == "table" and AP_STATE.positions or {},
                mode = AP_STATE.mode,
                delay = AP_STATE.delay,
                autoManual = (AP_STATE.autoManual == true),
                selectedPosition = AP_STATE.selectedPosition,
                savePosition = false,
                plantTotal = plantTotalDisplay(),
            })
        end
        G.__GAG2_PUSH_PLANT = writePlantGlobals
        _G.__GAG2_PUSH_PLANT = writePlantGlobals

        registerFlush("plant", function()
            writePlantGlobals()
        end)

