        local function applyPlantSeedCache(items)
            if type(items) ~= "table" then return end
            plantSeedListCache = items
            G.__GAG2_PLANT_SEED_LIST_CACHE = items
            _G.__GAG2_PLANT_SEED_LIST_CACHE = items
            if plantSeedDropdownApi and type(plantSeedDropdownApi.refreshItems) == "function" then
                pcall(plantSeedDropdownApi.refreshItems, plantSeedDropdownApi)
            end
            pcall(refreshPlantSeedStatus)
        end

        local function prefetchPlantSeeds()
            if plantSeedPrefetching then return end
            plantSeedPrefetching = true
            task.spawn(function()
                task.wait(0.5)
                local ag = G.AutoGiftModule or G.AutoGift or rawget(_G, "AutoGiftModule") or rawget(_G, "AutoGift")
                if type(ag) == "table" and type(ag.BuildInventoryItems) == "function" then
                    local ok, items = pcall(ag.BuildInventoryItems, ag, "Seeds")
                    if ok and type(items) == "table" then
                        applyPlantSeedCache(items)
                    end
                end
                plantSeedPrefetching = false
            end)
        end

        task.spawn(function()
            prefetchPlantSeeds()
        end)

        G.__GAG2_ON_PLANT_SEED_STATS_CHANGED = refreshPlantSeedStatus
