            getItems = function()
                return {
                    { key = "random", name = "Random" },
                    { key = "manual", name = "Manual" },
                }
            end,
            initial = AP_STATE.mode,
            onChanged = function(_, selectedKey)
                AP_STATE.mode = tostring(selectedKey or "random"):lower()
                if AP_STATE.mode ~= "manual" then AP_STATE.mode = "random" end
                setManualRowsVisible(AP_STATE.mode == "manual")
                patchAuto("plant", { mode = AP_STATE.mode }, syncAutoPlantModule)
            end,
