        manualPosRow, positionDropdownApi = ui:CreateRowDropdown(bodyPlant, {
            label       = "Position",
            placeholder = "Select position...",
            mode        = "single",
            getItems = function()
                return buildPositionItems()
            end,
            initial = AP_STATE.selectedPosition,
            onDeleteItem = function(key)
                key = tostring(key or "")
                if key == "" then return end

                local positions = AP_STATE.positions
                if type(positions) ~= "table" then return end

                local removed = false
                for i = #positions, 1, -1 do
                    local entry = positions[i]
                    if type(entry) == "table" and tostring(entry.id) == key then
                        table.remove(positions, i)
                        removed = true
                    end
                end
                if not removed then return end

                AP_STATE.positions = positions
                if tostring(AP_STATE.selectedPosition) == key then
                    AP_STATE.selectedPosition = nil
                    if #positions > 0 and type(positions[1]) == "table" and positions[1].id then
                        AP_STATE.selectedPosition = tostring(positions[1].id)
                    end
                end

                MAIN.auto.plant.positions = positions
                MAIN.auto.plant.selectedPosition = AP_STATE.selectedPosition
                G.MAIN = MAIN
                _G.MAIN = MAIN
                writePlantGlobals()

                local ap = G.AutoPlant or G.AutoPlantModule
                if type(ap) == "table" and type(ap.SetSelectedPosition) == "function" then
                    pcall(ap.SetSelectedPosition, ap, AP_STATE.selectedPosition)
                end

                if positionDropdownApi and positionDropdownApi.refreshItems then
                    positionDropdownApi.refreshItems()
