        local function getFruitStatusText(useHeavy)
            local count, maxCap, total
            local filtered
            local AS = G.AutoSellFruit
            if useHeavy and AS and type(AS.GetFruitStats) == "function" then
                local ok, c, m, t = pcall(function() return AS:GetFruitStats() end)
                if ok then
                    count, maxCap, total = c, m, t
                end
            end
            if count == nil then
                local LP = game:GetService("Players").LocalPlayer
                count = tonumber(LP:GetAttribute("FruitCount")) or 0
                maxCap = tonumber(LP:GetAttribute("MaxFruitCapacity"))
                total = count
            end
            if useHeavy and AS and type(AS.HasFilterActive) == "function" then
                local ok, on = pcall(AS.HasFilterActive, AS)
                if ok and on == true then
                    filtered = count
                    count = total or count
                end
            end
            local base = (maxCap and maxCap > 0) and ("Fruit: %d / %d"):format(count, maxCap)
                or ("Fruit: %d"):format(count)
            if filtered ~= nil then
                base = base .. (" - match filter: %d"):format(filtered)
            end
            if AS_STATE.sellWhenFull == true then
                if filtered ~= nil then
                    return base .. " - sell match when full"
                end
                return base .. " - sell when full"
            end
            if filtered ~= nil then
                return base .. (" - sell match at >= %d"):format(sellMinCountDisplay())
            end
            return base .. (" - sell at >= %d"):format(sellMinCountDisplay())
        end

        local _, setSellWhenFullToggle

        local function syncAutoSellModule()
            writeSellGlobals()

            local as = G.AutoSellFruit
            if type(as) ~= "table" then return end

            local function __callSell(fn, ...)
                if type(as[fn]) == "function" then
                    pcall(as[fn], ...)
                end
            end

            __callSell("SetMinCount", G.AUTO_SELL_MIN_COUNT)
            __callSell("setMinCount", G.AUTO_SELL_MIN_COUNT)
            __callSell("SetDelay", G.AUTO_SELL_DELAY)
            __callSell("setDelay", G.AUTO_SELL_DELAY)
            __callSell("SetSellWhenFull", G.AUTO_SELL_WHEN_FULL == true)
            __callSell("setSellWhenFull", G.AUTO_SELL_WHEN_FULL == true)
            __callSell("SetFilterMode", "rules")
            __callSell("setFilterMode", "rules")
            __callSell("SetRules", G.AUTO_SELL_RULES, G.AUTO_SELL_RULES_ORDER)
            __callSell("setRules", G.AUTO_SELL_RULES, G.AUTO_SELL_RULES_ORDER)

            if G.AUTO_SELL_ENABLED then
                __callSell("Start")
                __callSell("start")
            else
                __callSell("Stop")
                __callSell("stop")
            end

            task.defer(function()
                __callSell("CheckNow")
                __callSell("checkNow")
            end)
        end

