                if selectedMap._none then selectedMap._none = nil end

                local wantOn = readShovelEnabled()
                if countShovelSelected(selectedMap) < 1 then
                    wantOn = false
                    writeShovelState(false, selectedMap)
                    applyShovelRuntime(false)
                    if shovelToggleApi and type(shovelToggleApi.set) == "function" then
                        shovelToggleApi.set(false, true)
