end

G.PlantListView = M
_G.PlantListView = M

return M
 end,                  required = false },
    { key = "FruitSellValue",          name = "FruitSellValue",          factory = function() -- FruitSellValue.lua — harga jual buah (100% dari module game)
-- Sumber: SharedModules.FruitValueCalc, SellValueData, SeedData, MutationData
-- Tidak ada hardcode harga/rarity — ikut update game otomatis.

local Players           = game:GetService("Players")
local ReplicatedStorage = game:GetService("ReplicatedStorage")

local M = {}

local LP = Players.LocalPlayer
local G  = (getgenv and getgenv()) or _G

local SharedModules = ReplicatedStorage:WaitForChild("SharedModules", 15)

local function _requireChild(name)
    if not SharedModules then return nil end
    local inst = SharedModules:FindFirstChild(name)
    if inst and inst:IsA("ModuleScript") then
        local ok, mod = pcall(require, inst)
        if ok then return mod end
    end
    return nil
end

local _calcFn       = nil
local _sellFlagsMod = nil
local _seedByName   = {} -- [SeedName] = entry SeedData
local _rarityRank   = {} -- [Rarity string] = rank (dari PurchasePrice game)
local _lastRefresh  = 0
local REFRESH_SEC   = 30
local _fruitViz   = nil
local _fruitVizAt = 0
local VIZ_CACHE_SEC = 30
local _getFruitBidFn = nil
local _bidCache = {}
local BID_CACHE_SEC = 45
local FRIEND_BOOST_PER_FRIEND = 0.1

local _noFriendCalcInst = {
    GetAttribute = function(_, attr)
        if attr == "Friends" then return 0 end
        if LP then return LP:GetAttribute(attr) end
        return nil
    end,
}

local function _friendBoostMultiplier(friendCount)
    if friendCount == nil then
        friendCount = LP and LP:GetAttribute("Friends") or 0
    end
    friendCount = tonumber(friendCount) or 0
    return 1 + friendCount * FRIEND_BOOST_PER_FRIEND
end

local function _stripFriendBoost(price, friendCount)
    price = tonumber(price) or 0
    if price <= 0 then return 0 end
    local mult = _friendBoostMultiplier(friendCount)
    if mult <= 1 then return price end
    return math.floor(price / mult + 0.5)
end

local function _includesFriendBoost()
    return G.FRUIT_PRICE_INCLUDE_FRIEND_BOOST == true
        or rawget(_G, "FRUIT_PRICE_INCLUDE_FRIEND_BOOST") == true
end

function M.includesFriendBoost()
    return _includesFriendBoost()
end

function M.setIncludeFriendBoost(on)
    on = (on == true)
    G.FRUIT_PRICE_INCLUDE_FRIEND_BOOST = on
    _G.FRUIT_PRICE_INCLUDE_FRIEND_BOOST = on
    M.clearBidCache()
end

function M.getEspPriceMode()
    local mode = G.FRUIT_BACKPACK_ESP_PRICE_MODE or rawget(_G, "FRUIT_BACKPACK_ESP_PRICE_MODE")
    if mode == nil then
        local MAIN = G.MAIN or rawget(_G, "MAIN")
        local st = MAIN and MAIN.misc and MAIN.misc.fruit_backpack_esp
        if type(st) == "table" then
            mode = st.price_mode
        end
    end
    if tostring(mode or ""):lower() == "stock" then
        return "stock"
    end
    return "base"
end

function M.setEspPriceMode(mode)
    mode = (tostring(mode or ""):lower() == "stock") and "stock" or "base"
    G.FRUIT_BACKPACK_ESP_PRICE_MODE = mode
    _G.FRUIT_BACKPACK_ESP_PRICE_MODE = mode
    G.FRUIT_PRICE_INCLUDE_FRIEND_BOOST = (mode == "stock")
    _G.FRUIT_PRICE_INCLUDE_FRIEND_BOOST = (mode == "stock")
    M.clearBidCache()
end

local function _ensureSellFlagsMod()
    if _sellFlagsMod == false then
        return nil
    end
    if type(_sellFlagsMod) == "table" then
        return _sellFlagsMod
    end
    if not SharedModules then return nil end

    local candidates = {}
    local flagsRoot = SharedModules:FindFirstChild("Flags")
    if flagsRoot then
        local inst = flagsRoot:FindFirstChild("SellFlags")
        if inst then candidates[#candidates + 1] = inst end
    end
    local direct = SharedModules:FindFirstChild("SellFlags")
    if direct then candidates[#candidates + 1] = direct end

    for _, inst in ipairs(candidates) do
        if inst:IsA("ModuleScript") then
            local ok, mod = pcall(require, inst)
            if ok and type(mod) == "table" then
                _sellFlagsMod = mod
                return _sellFlagsMod
            end
        end
    end

    if flagsRoot then
        for _, inst in ipairs(flagsRoot:GetChildren()) do
            if inst:IsA("ModuleScript") then
                local n = inst.Name:lower()
                if n:find("sell", 1, true) or n:find("stock", 1, true) or n:find("price", 1, true) then
                    local ok, mod = pcall(require, inst)
                    if ok and type(mod) == "table" then
                        _sellFlagsMod = mod
                        return _sellFlagsMod
                    end
                end
            end
        end
    end
    _sellFlagsMod = false
    return nil
end

local function _resolveFruitNames(fruitName)
    local out, seen = {}, {}
    local function add(n)
        n = tostring(n or "")
        if n == "" or seen[n] then return end
        seen[n] = true
        out[#out + 1] = n
    end
    add(fruitName)
    if fruitName == "" then return out end

    local okEntry, got = pcall(function()
        return M.getSeedEntry(fruitName)
    end)
    if okEntry and type(got) == "table" then
        add(got.SeedName)
        add(got.Name)
        add(got.FruitName)
    end

    local svd = _requireChild("SellValueData")
    if type(svd) == "table" then
        for _, name in ipairs(out) do
            if svd[name] ~= nil then return out end
        end
        local nk = M.normKey(fruitName)
        for key in pairs(svd) do
            if type(key) == "string" and M.normKey(key) == nk then
                add(key)
            end
        end
    end
    return out
end

local function _readFlagMapNumber(flagObj, fruitName, names)
    if type(flagObj) ~= "table" then return nil end
    local data
    if type(flagObj.Get) == "function" then
        local ok, v = pcall(flagObj.Get, flagObj)
        if ok then data = v end
    elseif rawget(flagObj, "Value") ~= nil then
        data = flagObj.Value
    end
    if type(data) == "number" and data > 0 then
        return data
    end
    if type(data) ~= "table" then return nil end
    names = names or _resolveFruitNames(fruitName)
    for _, name in ipairs(names) do
        local v = data[name]
        if type(v) == "number" and v > 0 then return v end
    end
    local nk = M.normKey(fruitName)
    for key, v in pairs(data) do
        if type(key) == "string" and type(v) == "number" and v > 0 and M.normKey(key) == nk then
            return v
        end
    end
    return nil
end

function M.getStockMultiplier(fruitName)
    fruitName = tostring(fruitName or "")
    if fruitName == "" then return 1 end

    local mod = _ensureSellFlagsMod()
    local names = _resolveFruitNames(fruitName)

    if type(mod) == "table" then
        local apiNames = {
            "GetStockMultiplier", "GetPriceStockMultiplier", "GetPriceStock",
            "GetMultiplier", "GetRate", "GetStockRate",
        }
        for _, api in ipairs(apiNames) do
            local fn = mod[api]
            if type(fn) == "function" then
                for _, name in ipairs(names) do
                    local ok, v = pcall(fn, name)
                    if ok and type(v) == "number" and v > 0 then return v end
                    ok, v = pcall(fn, mod, name)
                    if ok and type(v) == "number" and v > 0 then return v end
                end
            end
        end

        local flagKeys = {
            "PriceStockMultipliers", "StockMultipliers", "PriceStock",
            "SellPriceMultipliers", "Multipliers", "Rates", "StockRates",
        }
        for _, key in ipairs(flagKeys) do
            local v = _readFlagMapNumber(mod[key], fruitName, names)
            if type(v) == "number" and v > 0 then return v end
        end

        for key, obj in pairs(mod) do
            if type(key) == "string" and type(obj) == "table" and type(obj.Get) == "function" then
                local v = _readFlagMapNumber(obj, fruitName, names)
                if type(v) == "number" and v > 0 then return v end
            end
        end

        if type(mod.Apply) == "function" then
            local probe = 10000
            for _, name in ipairs(names) do
                local ok, result = pcall(mod.Apply, name, probe)
                if ok and type(result) == "number" and result > 0 then
                    return result / probe
                end
                ok, result = pcall(mod.Apply, mod, name, probe)
                if ok and type(result) == "number" and result > 0 then
                    return result / probe
                end
            end
        end
    end

    return 1
end

local function _callSellFlagsApply(mod, fruitName, baseValue)
    baseValue = tonumber(baseValue) or 0
    if baseValue <= 0 or type(mod) ~= "table" then return baseValue end

    local mult = M.getStockMultiplier(fruitName)
    if type(mult) == "number" and mult > 0 and mult ~= 1 then
        return math.floor(baseValue * mult + 0.5)
    end

    local fn = mod.Apply
    if type(fn) ~= "function" then return baseValue end

    for _, name in ipairs(_resolveFruitNames(fruitName)) do
        local ok, value = pcall(fn, name, baseValue)
        if ok and type(value) == "number" then
            return value
        end
        ok, value = pcall(fn, mod, name, baseValue)
        if ok and type(value) == "number" then
            return value
        end
    end
    return baseValue
end

function M.applyStockRate(fruitName, baseValue)
    baseValue = tonumber(baseValue) or 0
    if baseValue <= 0 then return 0 end
    local mod = _ensureSellFlagsMod()
    if not mod then
        local mult = M.getStockMultiplier(fruitName)
        if mult ~= 1 then
            return math.floor(baseValue * mult + 0.5)
        end
        return baseValue
    end
    local ok, value = pcall(_callSellFlagsApply, mod, fruitName, baseValue)
    if ok and type(value) == "number" then
        return value
    end
    return baseValue
end

function M.getBackpackEspPrice(name, multi, mutation, decayAlpha, mode, fruitId, bidPrice)
    mode = tostring(mode or M.getEspPriceMode()):lower()
    if mode ~= "stock" then mode = "base" end

    multi = tonumber(multi) or 0
    name = tostring(name or "")
    fruitId = tostring(fruitId or "")
    if name == "" or multi <= 0 then return 0 end

    if mode == "base" then
        local base = M.calculate(name, multi, mutation, _noFriendCalcInst, decayAlpha)
        if base <= 0 then return 0 end
        local bid = tonumber(bidPrice) or 0
        if bid > 0 then
            return math.floor(base + bid + 0.5)
        end
        return base
    end

    -- Stock: harga server Steven (sudah include friend + hot rate)
    if fruitId ~= "" then
        local bid = M.getNpcBidRaw(fruitId)
        if bid > 0 then return bid end
    end

    local price = M.calculate(name, multi, mutation, LP, decayAlpha)
    if price <= 0 then
        price = M.calculate(name, multi, mutation, _noFriendCalcInst, decayAlpha)
    end
    if price <= 0 then return 0 end

    local mult = M.getStockMultiplier(name)
    if type(mult) == "number" and mult > 0 and mult ~= 1 then
        return math.floor(price * mult + 0.5)
    end

    local ok, adjusted = pcall(M.applyStockRate, name, price)
    if ok and type(adjusted) == "number" and adjusted > 0 then
        return adjusted
    end
    return price
end

local function _calcInst()
    if _includesFriendBoost() then
        return LP
    end
    return _noFriendCalcInst
end

local function _applyPricePolicy(price)
    price = tonumber(price) or 0
    if price <= 0 or _includesFriendBoost() then
        return price
    end
    return _stripFriendBoost(price)
end

local function _ensureNpcNetworking()
    if _getFruitBidFn then return true end
    if not SharedModules then return false end
    local ok, net = pcall(function()
        return require(SharedModules:WaitForChild("Networking"))
    end)
    if not ok or type(net) ~= "table" or type(net.NPCS) ~= "table" then
        return false
    end
    local remote = net.NPCS.GetFruitBid
    if type(remote) == "function" then
        _getFruitBidFn = remote
    elseif type(remote) == "table" and type(remote.Fire) == "function" then
        _getFruitBidFn = function(fruitId)
            return remote:Fire(fruitId)
        end
    elseif type(remote) == "userdata" and type(remote.InvokeServer) == "function" then
        _getFruitBidFn = function(fruitId)
            return remote:InvokeServer(fruitId)
        end
    end
    return _getFruitBidFn ~= nil
end

function M.clearBidCache()
    table.clear(_bidCache)
end

function M.getNpcBidRaw(fruitId)
    fruitId = tostring(fruitId or "")
    if fruitId == "" then return 0 end

    local now = os.clock()
    local cached = _bidCache[fruitId]
    if cached and (now - cached.at) < BID_CACHE_SEC then
        return cached.raw
    end

    if not _ensureNpcNetworking() then return 0 end

    local ok, bid = pcall(_getFruitBidFn, fruitId)
    if not ok or type(bid) ~= "table" then return 0 end

    local raw = tonumber(bid.CurrentSellValue or bid.currentSellValue
        or bid.SellValue or bid.sellValue) or 0
    if raw > 0 then
        _bidCache[fruitId] = { raw = raw, at = now }
    end
    return raw
end

function M.getNpcBid(fruitId)
    return _applyPricePolicy(M.getNpcBidRaw(fruitId))
end

function M.applyFriendBoost(price, friendCount)
    price = tonumber(price) or 0
    if price <= 0 then return 0 end
    return math.floor(price * _friendBoostMultiplier(friendCount) + 0.5)
end

function M.normKey(s)
    return tostring(s or ""):lower():gsub("[%s_%-%.'']+", "")
end

----------------------------------------------------------------
-- load / refresh dari game
----------------------------------------------------------------
local function _ingestSeedEntry(entry, into, rarityMaxPrice)
    if type(entry) ~= "table" then return end
    local seedName = entry.SeedName or entry.Name
    if not seedName or tostring(seedName) == "" then return end
    seedName = tostring(seedName)
    into[seedName] = entry
    local rarity = entry.Rarity
    if rarity then
        local price = tonumber(entry.PurchasePrice) or 0
        rarityMaxPrice[rarity] = math.max(rarityMaxPrice[rarity] or 0, price)
    end
end

local function _rebuildRarityRank(rarityMaxPrice)
    local list = {}
    for rarity, price in pairs(rarityMaxPrice) do
        list[#list + 1] = { rarity = rarity, price = price }
    end
    table.sort(list, function(a, b)
        if a.price ~= b.price then return a.price > b.price end
        return tostring(a.rarity) < tostring(b.rarity)
    end)
    local rank = {}
    local total = #list
    for i, item in ipairs(list) do
        -- i=1 = tier termahal/terbaik → score tertinggi (sort desc)
        rank[item.rarity] = total - i + 1
    end
    return rank
end

local function _indexSeedData(seedData)
    local byName = {}
    local rarityMaxPrice = {}
    if type(seedData) ~= "table" then
        return byName, _rebuildRarityRank(rarityMaxPrice)
    end
    if #seedData > 0 then
        for _, entry in ipairs(seedData) do
            _ingestSeedEntry(entry, byName, rarityMaxPrice)
        end
    else
        for _, entry in pairs(seedData) do
            _ingestSeedEntry(entry, byName, rarityMaxPrice)
        end
    end
    return byName, _rebuildRarityRank(rarityMaxPrice)
end

function M.refresh(force)
    local now = os.clock()
    if not force and _calcFn and (now - _lastRefresh) < REFRESH_SEC then
        return _calcFn ~= nil
    end

    _calcFn = nil
    local calcMod = _requireChild("FruitValueCalc")
    if type(calcMod) == "function" then
        _calcFn = calcMod
    elseif type(calcMod) == "table" then
        if type(calcMod.Calculate) == "function" then
            _calcFn = calcMod.Calculate
        elseif type(calcMod.calculate) == "function" then
            _calcFn = calcMod.calculate
        end
    end

    local seedData = _requireChild("SeedData")
    _seedByName, _rarityRank = _indexSeedData(seedData)

    -- PlantListView juga dari SeedData game — merge kalau ada
    local PLV = G.PlantListView or _G.PlantListView
    if type(PLV) == "table" and type(PLV.getCatalogMap) == "function" then
        local ok, catalog = pcall(PLV.getCatalogMap, PLV)
        if ok and type(catalog) == "table" then
            local rarityMaxPrice = {}
            for seedName, info in pairs(_seedByName) do
                if info.Rarity then
                    local price = tonumber(info.PurchasePrice) or 0
                    rarityMaxPrice[info.Rarity] = math.max(rarityMaxPrice[info.Rarity] or 0, price)
                end
            end
            for seedName, info in pairs(catalog) do
                if type(info) == "table" and not _seedByName[seedName] then
                    _seedByName[seedName] = info.raw or info
                end
                local r = type(info) == "table" and (info.Rarity or (info.raw and info.raw.Rarity))
                local p = type(info) == "table" and (
                    info.PurchasePrice or (info.raw and info.raw.PurchasePrice)
                )
                if r then
                    rarityMaxPrice[r] = math.max(rarityMaxPrice[r] or 0, tonumber(p) or 0)
                end
            end
            _rarityRank = _rebuildRarityRank(rarityMaxPrice)
        end
    end

    _lastRefresh = now
    return _calcFn ~= nil
end

local function _ensureCalc()
    if not _calcFn then
        M.refresh(true)
    end
    return _calcFn
end

----------------------------------------------------------------
-- resolve dari model buah
----------------------------------------------------------------
local function _looksLikeId(s)
    s = tostring(s or "")
    if s == "" then return true end
    if s:match("^%d+_[%x%-]+") then return true end
    if #s >= 32 and s:match("^[%x%-]+$") then return true end
    if s:find("_", 1, true) and s:find("-", 1, true) and not s:match("^[%a][%a ]*$") then
        return true
    end
    return false
end

local function _attrText(model, key)
    if not model then return nil end
    local v = model:GetAttribute(key)
    if type(v) ~= "string" or v == "" then return nil end
    return v
end

local function _pickNameFromModel(model)
    if not model then return nil end
    local keys = {
        "CorePartName", "FruitType", "FruitName", "ItemName", "SeedName",
    }
    for _, key in ipairs(keys) do
        local v = _attrText(model, key)
        if v and not _looksLikeId(v) then
            return v
        end
    end
    local cfg = _attrText(model, "ConfigPathName")
    if cfg and not _looksLikeId(cfg) then
        return cfg
    end
    return nil
end

function M.resolveSeedName(model)
    if not model then return "" end

    local name = _pickNameFromModel(model)
    if name then return tostring(name) end

    local p = model.Parent
    for _ = 1, 8 do
        if not p then break end
        local pn = _pickNameFromModel(p)
        if pn then return tostring(pn) end
        if p.Name == "Plants" or p.Name == "Gardens" then break end
        p = p.Parent
    end

    local cfg = _attrText(model, "ConfigPathName") or _attrText(model, "SeedName")
    if cfg then
        local tail = cfg:match("([^/]+)$")
        if tail and not _looksLikeId(tail) then
            return tail
        end
    end

    local fallback = tostring(model.Name or "")
    if fallback ~= "" and not _looksLikeId(fallback) then
        return fallback
    end
    return ""
end

local function _getFruitVisualizer()
    local now = os.clock()
    if _fruitViz and (now - _fruitVizAt) <= VIZ_CACHE_SEC then
        return _fruitViz
    end
    _fruitVizAt = now
    _fruitViz = nil

    local ps = LP:FindFirstChild("PlayerScripts")
    local controllers = ps and ps:FindFirstChild("Controllers")
    local mod = controllers and controllers:FindFirstChild("FruitVisualizerController")
    if mod and mod:IsA("ModuleScript") then
        local ok, ctrl = pcall(require, mod)
        if ok and type(ctrl) == "table" then
            _fruitViz = ctrl
        end
    end
    return _fruitViz
end

local function _vizWeight(viz, model)
    if not viz or not model then return nil end
    local ok, kg = pcall(viz.CalculateFruitWeight, viz, model)
    if ok and type(kg) == "number" and kg > 0 then
        return kg
    end
    if type(viz.CalculatePlantWeight) == "function" then
        ok, kg = pcall(viz.CalculatePlantWeight, viz, model)
        if ok and type(kg) == "number" and kg > 0 then
            return kg
        end
    end
    return nil
end

-- Garden: display kg (billboard / BaseWeight×SizeMulti). Bukan SizeMultiplier (multi harga).
function M.resolveWeight(model)
    if not model then return 0 end

    if model:IsA("Tool") then
        local harvestKg = tonumber(model:GetAttribute("Weight"))
        if harvestKg and harvestKg > 0 then
            return harvestKg
        end
    end

    local viz = _getFruitVisualizer()
    if viz then
        local kg = _vizWeight(viz, model)
        if kg then return kg end
        local parent = model.Parent
        if parent and parent:IsA("Model") then
            kg = _vizWeight(viz, parent)
            if kg then return kg end
        end
    end

    local node, depth = model, 0
    while node and depth < 8 do
        if node:IsA("Model") then
            local bw = tonumber(node:GetAttribute("BaseWeight"))
            local sm = tonumber(node:GetAttribute("SizeMulti") or node:GetAttribute("SizeMultiplier"))
            local og = tonumber(node:GetAttribute("OvertimeGrowth")) or 1
            if bw and bw > 0 and sm and sm > 0 then
                return bw * sm * og
            end
            local harvestKg = tonumber(node:GetAttribute("Weight"))
            if harvestKg and harvestKg > 0 then
                return harvestKg
            end
        end
        if node.Name == "Gardens" then break end
        node = node.Parent
        depth += 1
    end
    return 0
end

function M.resolveMulti(model)
    if not model then return 0 end
    local node, depth = model, 0
    while node and depth < 8 do
        if node:IsA("Model") or node:IsA("Tool") then
            local multi = tonumber(node:GetAttribute("SizeMultiplier") or node:GetAttribute("SizeMulti"))
            if multi and multi > 0 then
                return multi
            end
        end
        if node.Name == "Gardens" then break end
        node = node.Parent
        depth += 1
    end
    return 0
end

local function _isWeightBracket(token)
    local t = tostring(token or ""):match("^%s*(.-)%s*$")
    if t == "" then return true end
    if t:lower():match("^[%d%.]+%s*kg$") then return true end
    return tonumber(t) ~= nil
end

local function _mutationFromToolName(model)
    if not model then return nil end
    local raw = tostring(model.Name or "")
    if raw == "" then return nil end
    local parts = {}
    for bracket in string.gmatch(raw, "%[([^%]]+)%]") do
        local token = tostring(bracket):match("^%s*(.-)%s*$")
        if token and token ~= "" and not _isWeightBracket(token) then
            parts[#parts + 1] = token
        end
    end
    if #parts == 0 then return nil end
    if #parts == 1 then return parts[1] end
    return table.concat(parts, "+")
end

function M.resolveMutation(model)
    if not model then return nil end
    local raw = model:GetAttribute("Mutation")
    if type(raw) == "string" and raw ~= "" then return raw end
    return _mutationFromToolName(model)
end

function M.resolveBidPrice(model)
    if not model or type(model.GetAttribute) ~= "function" then return 0 end
    local bid = tonumber(model:GetAttribute("BidPrice"))
    if bid and bid > 0 then
        return bid
    end
    local node, depth = model.Parent, 1
    while node and depth < 8 do
        if type(node.GetAttribute) == "function" then
            bid = tonumber(node:GetAttribute("BidPrice"))
            if bid and bid > 0 then
                return bid
            end
        end
        if node.Name == "Gardens" then break end
        node = node.Parent
        depth += 1
    end
    return 0
end

function M.getSeedEntry(seedName)
    _ensureCalc()
    seedName = tostring(seedName or "")
    if seedName == "" then return nil end
    return _seedByName[seedName]
end

function M.getRarity(seedName)
    local entry = M.getSeedEntry(seedName)
    if type(entry) == "table" and entry.Rarity then
        return tostring(entry.Rarity)
    end
    return nil
end

----------------------------------------------------------------
-- Calculate — delegate ke FruitValueCalc game
-- Calculate(seedName, weight, mutation, inst, discount)
----------------------------------------------------------------
function M.calculate(seedName, weight, mutation, inst, discount)
    local calc = _ensureCalc()
    if not calc then return 0 end
    seedName = tostring(seedName or "")
    weight = tonumber(weight) or 0
    if seedName == "" then return 0 end
    local ok, value = pcall(calc, seedName, weight, mutation, inst or _calcInst(), discount)
    if ok and type(value) == "number" then return value end
    return 0
end

function M.getBackpackPrice(name, weight, mutation, fruitId, decayAlpha)
    if fruitId ~= nil and tostring(fruitId) ~= "" then
        local bid = M.getNpcBid(fruitId)
        if bid > 0 then return bid end
    end
    return M.calculate(name, weight, mutation, _calcInst(), decayAlpha)
end

function M.fromFruit(model, _inst)
    if not model then return 0 end
    local name = model:GetAttribute("FruitName")
    if type(name) ~= "string" or name == "" then
        name = M.resolveSeedName(model)
    else
        name = tostring(name)
    end
    local multi = M.resolveMulti(model)
    local fruitId = model:GetAttribute("Id") or model:GetAttribute("id")
        or model:GetAttribute("UUID") or model:GetAttribute("FruitId")
    if fruitId then
        local bid = M.getNpcBid(fruitId)
        if bid > 0 then return bid end
    end
    if not multi or multi <= 0 then
        return 0
    end
    return M.calculate(name, multi, M.resolveMutation(model), _calcInst(), model:GetAttribute("DecayAlpha"))
end

function M.rarityScore(model)
    if not model then return 0 end
    _ensureCalc()
    local seedName = M.resolveSeedName(model)
    local entry = _seedByName[seedName]
    local rarity = type(entry) == "table" and entry.Rarity
    if not rarity then return 0 end
    return _rarityRank[rarity] or 0
end

function M.priorityScore(model, mode, inst)
    mode = tostring(mode or "off"):lower()
    if mode == "price" then
        return M.fromFruit(model, inst)
    elseif mode == "rarity" then
        return M.rarityScore(model) * 1e9 + M.fromFruit(model, inst)
    elseif mode == "weight" then
        return M.resolveWeight(model)
    end
    return 0
end

function M.isReady()
    return _ensureCalc() ~= nil
end

M.isready = M.isReady

-- init
pcall(function() M.refresh(true) end)
pcall(function() M.setEspPriceMode(M.getEspPriceMode()) end)

G.FruitSellValue = M
_G.FruitSellValue = M

return M
 end,                 required = false },
    { key = "AutoCollect",             name = "Auto Collect",            factory = function() -- AutoCollect.lua — Grow A Garden 2 (lightweight batch cache)
-- Pola: isi cache plot sendiri → fire satu per delay → scan ulang saat batch habis

local Players           = game:GetService("Players")
local ReplicatedStorage = game:GetService("ReplicatedStorage")
local CollectionService = game:GetService("CollectionService")

local LP = Players.LocalPlayer
local G  = (getgenv and getgenv()) or _G
local M  = {}

local CollectFruit = nil

local function _remoteCanFire(remote)
    if not remote then return false end
    if type(remote.Fire) == "function" then return true end
    if type(remote.FireServer) == "function" then return true end
    if type(remote.InvokeServer) == "function" then return true end
    return false
end

local function _ensureCollectRemote()
    if CollectFruit and _remoteCanFire(CollectFruit) then
        return true
    end
    CollectFruit = nil

    local ok, net = pcall(function()
        local sm = ReplicatedStorage:WaitForChild("SharedModules", 8)
        return sm and require(sm:WaitForChild("Networking", 8))
    end)
    if ok and type(net) == "table" and type(net.Garden) == "table" then
        CollectFruit = net.Garden.CollectFruit
    end
    return _remoteCanFire(CollectFruit)
end

local FruitSellValue
pcall(function()
    FruitSellValue = require(script.Parent.FruitSellValue)
end)
if type(FruitSellValue) ~= "table" then
    FruitSellValue = G.FruitSellValue or _G.FruitSellValue
end

local HARVEST_TAG      = "HarvestPrompt"
local COUNT_CACHE_SEC  = 4.0
local AC_CACHE_SEC     = 0.4
local PROMPT_SCAN_CACHE_SEC = 1.2
local SCAN_MIN_SEC     = 0.5
local IDLE_WAIT_SEC    = 0.45

local running            = false
local loopId             = 0
local loopAliveId        = 0
local batchList          = {}
local batchIdx           = 1
local cachedAC           = nil
local cachedACAt         = 0
local cachedPlot         = nil
local cachedPlotAt       = 0
local PLOT_CACHE_SEC     = 3.0
local _lastTickCollected = 0
local _totalCollected    = 0
local _readyCache        = 0
local _readyCacheAt      = 0
local _filteredCache     = 0
local _filteredCacheAt   = 0
local weightCache        = {}
local WEIGHT_CACHE_SEC   = 30
local promptScanCache    = { plot = nil, at = 0, list = {} }
local _fruitViz          = nil
local _fruitVizAt        = 0
local VIZ_CACHE_SEC      = 30

local function _getFruitVisualizer()
    local now = os.clock()
    if _fruitViz and (now - _fruitVizAt) <= VIZ_CACHE_SEC then
        return _fruitViz
    end
    _fruitVizAt = now
    _fruitViz = nil
    local ps = LP:FindFirstChild("PlayerScripts")
    local c = ps and ps:FindFirstChild("Controllers")
    local m = c and c:FindFirstChild("FruitVisualizerController")
    if m and m:IsA("ModuleScript") then
        local ok, mod = pcall(require, m)
        if ok and type(mod) == "table" then
            _fruitViz = mod
        end
    end
    return _fruitViz
end

local function _kgFromViz(viz, model)
    if not viz or not model then return nil end
    local ok, w = pcall(viz.CalculateFruitWeight, viz, model)
    if ok and type(w) == "number" and w > 0 then return w end
    ok, w = pcall(function() return viz:CalculateFruitWeight(model) end)
    if ok and type(w) == "number" and w > 0 then return w end
    if type(viz.CalculatePlantWeight) == "function" then
        ok, w = pcall(viz.CalculatePlantWeight, viz, model)
        if ok and type(w) == "number" and w > 0 then return w end
        ok, w = pcall(function() return viz:CalculatePlantWeight(model) end)
        if ok and type(w) == "number" and w > 0 then return w end
    end
    return nil
end

local function _attrId(inst, name)
    if not inst then return "" end
    local v = inst:GetAttribute(name)
    if v == nil then return "" end
    v = tostring(v)
    if v == "" then return "" end
    return v
end

-- Match HarvestPromptController: IDs from the harvest model ancestor of the prompt.
local function _resolvePlotFruitIds(model)
    if not model then return "", "" end

    local plantId = _attrId(model, "PlantId")
    local fruitId = _attrId(model, "FruitId")
    if plantId ~= "" then
        return plantId, fruitId
    end

    local node, depth = model.Parent, 0
    while node and depth < 12 do
        if node:IsA("Model") then
            if plantId == "" then
                plantId = _attrId(node, "PlantId")
            end
            if fruitId == "" then
                fruitId = _attrId(node, "FruitId")
            end
            if plantId ~= "" then
                return plantId, fruitId
            end
        end
        if node.Name == "Gardens" then break end
        node = node.Parent
        depth += 1
    end
    return plantId, fruitId
end

local function _idsFromPrompt(prompt)
    if not prompt or not prompt.Parent then return "", "" end
    local model = prompt.Parent:FindFirstAncestorWhichIsA("Model")
    if not model then return "", "" end
    return _resolvePlotFruitIds(model)
end

----------------------------------------------------------------
-- debug
----------------------------------------------------------------
local function _dbg()
    return G.AUTO_COLLECT_DEBUG == true or _G.AUTO_COLLECT_DEBUG == true
end

local function _log(...)
    if _dbg() then print("[GAG2-AC]", ...) end
end

local function _warn(...)
    print("[GAG2-AC]", ...)
end

local function _normalizeDelay(v, default)
    default = default or 0.1
    local d = tonumber(v)
    if d == nil then return default end
    if d < 0 then return 0 end
    return d
end

local function _liveDelay()
    local raw = G.AUTO_COLLECT_DELAY
    if raw == nil then raw = rawget(_G, "AUTO_COLLECT_DELAY") end
    if raw == nil then
        local MAIN = rawget(_G, "MAIN") or G.MAIN
        local ac = MAIN and MAIN.auto and MAIN.auto.collect
        raw = ac and ac.delay
    end
    return _normalizeDelay(raw, 0.1)
end

local function _fireDelaySec(ac)
    local d = tonumber(ac and ac.delay)
    if d == nil then
        d = _liveDelay()
    end
    d = tonumber(d) or 0
    if d < 0 then d = 0 end
    return d
end

local function _waitAfterFire(ac)
    local d = _fireDelaySec(ac)
    if d > 0 then
        task.wait(d)
    else
        task.wait()
    end
end

local function _clearBatchCaches()
    batchIdx = 1
    table.clear(batchList)
    _readyCacheAt = 0
    _filteredCacheAt = 0
end

local function _invalidatePromptScan()
    promptScanCache.plot = nil
    promptScanCache.at = 0
    table.clear(promptScanCache.list)
end

----------------------------------------------------------------
-- state
----------------------------------------------------------------
local function _hasAny(map)
    if type(map) ~= "table" then return false end
    for _, v in pairs(map) do
        if v == true then return true end
    end
    return false
end

local function _normalizeSet(src)
    if type(src) ~= "table" then return {} end
    local out = {}
    for i = 1, #src do
        local v = src[i]
        if v ~= nil and tostring(v) ~= "" then out[tostring(v)] = true end
    end
    if next(out) then return out end
    for k, v in pairs(src) do
        if v == true or v == 1 or v == "true" then out[tostring(k)] = true end
    end
    return out
end

local function _setToArray(map)
    local out = {}
    if type(map) ~= "table" then return out end
    for k, v in pairs(map) do
        if v == true then out[#out + 1] = tostring(k) end
    end
    table.sort(out)
    return out
end

local function _batchFilterKey(ac)
    if type(ac) ~= "table" then return "" end
    local parts = { tostring(ac.priority or "off"), tostring(#(ac.rules or {})) }
    for _, r in ipairs(ac.rules or {}) do
        parts[#parts + 1] = table.concat({
            tostring(r.id or ""),
            (r.enabled == false) and "0" or "1",
            (r.requireMut == true) and "1" or "0",
            table.concat(_setToArray(r.fruits), ","),
            table.concat(_setToArray(r.mutations), ","),
            tostring(r.kg or 0),
            tostring(r.kgMode or "above"),
            tostring(r.minPrice or 0),
            tostring(r.minPriceMode or "above"),
        }, ":")
    end
    return table.concat(parts, "|")
end

local function _canon(s)
    return tostring(s or ""):lower():gsub("[^%w]+", "")
end

local function _normalizeKgFilter(kg, mode)
    kg = tonumber(kg) or 0
    mode = tostring(mode or "above")
    if kg < 0 then
        kg = math.abs(kg)
        mode = "below"
    end
    if mode ~= "below" then
        mode = "above"
    end
    return kg, mode
end

local function _parseKgRuleInput(txt)
    txt = tostring(txt or ""):gsub("%s+", "")
    if txt == "" then
        return 0, "above"
    end
    local n = tonumber(txt)
    if not n then
        return 0, "above"
    end
    if n < 0 then
        return math.abs(n), "below"
    end
    return n, "above"
end

local function _liveKgFilter()
    local rule = G.AUTO_COLLECT_KG_RULE or rawget(_G, "AUTO_COLLECT_KG_RULE")
    if type(rule) == "string" and rule:gsub("%s+", "") ~= "" then
        return _parseKgRuleInput(rule)
    end
    return _normalizeKgFilter(
        G.AUTO_COLLECT_KG or rawget(_G, "AUTO_COLLECT_KG"),
        G.AUTO_COLLECT_KG_MODE or rawget(_G, "AUTO_COLLECT_KG_MODE")
    )
end

local function _formatKgRule(kg, mode)
    kg = tonumber(kg) or 0
    mode = tostring(mode or "above")
    if kg <= 0 then
        return "0"
    end
    if mode == "below" then
        return "-" .. tostring(kg)
    end
    return tostring(kg)
end

local function _normalizePriceFilter(price, mode)
    price = tonumber(price) or 0
    mode = tostring(mode or "above")
    if price < 0 then
        price = math.floor(math.abs(price))
        mode = "below"
    end
    if mode ~= "below" then
        mode = "above"
    end
    return math.floor(math.max(0, price)), mode
end

local function _parseScaledNumber(txt)
    txt = tostring(txt or ""):lower():gsub("%s+", ""):gsub(",", "")
    if txt == "" then return nil end
    local sign = 1
    if txt:sub(1, 1) == "-" then
        sign = -1
        txt = txt:sub(2)
    end
    local suffixes = {
        { "juta", 1000000 }, { "jt", 1000000 },
        { "ribu", 1000 }, { "rb", 1000 },
        { "b", 1000000000 }, { "m", 1000000 }, { "k", 1000 },
    }
    for _, pair in ipairs(suffixes) do
        local suf, mult = pair[1], pair[2]
        if #txt > #suf and txt:sub(-#suf) == suf then
            local n = tonumber(txt:sub(1, -#suf - 1))
            if n then return n * mult * sign end
        end
    end
    local n = tonumber(txt)
    if n then return n * sign end
    return nil
end

local function _parsePriceRuleInput(txt)
    txt = tostring(txt or ""):gsub("%s+", "")
    if txt == "" then
        return 0, "above"
    end
    local n = _parseScaledNumber(txt) or tonumber(txt)
    if not n then
        return 0, "above"
    end
    if n < 0 then
        return math.abs(n), "below"
    end
    return n, "above"
end

local function _formatPriceRule(price, mode)
    price = tonumber(price) or 0
    mode = tostring(mode or "above")
    if price <= 0 then return "0" end
    if mode == "below" then return "-" .. tostring(price) end
    return tostring(price)
end

local function _getFruitPrice(fruit)
    if type(FruitSellValue) == "table" and type(FruitSellValue.fromFruit) == "function" then
        local ok, price = pcall(FruitSellValue.fromFruit, fruit)
        if ok then return tonumber(price) or 0 end
    end
    return 0
end

local _loadCollectRules

local function _readEnabled()
    if G.AUTO_COLLECT_FRUIT_ENABLED == true or rawget(_G, "AUTO_COLLECT_FRUIT_ENABLED") == true then
        return true
    end
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    local ac = MAIN and MAIN.auto and MAIN.auto.collect
    return type(ac) == "table" and ac.enabled == true
end

local function getACState()
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    local ac = MAIN and MAIN.auto and MAIN.auto.collect
    ac = type(ac) == "table" and ac or {}

    local rawDelay = G.AUTO_COLLECT_DELAY
    if rawDelay == nil then rawDelay = rawget(_G, "AUTO_COLLECT_DELAY") end
    if rawDelay == nil then rawDelay = ac.delay end
    local delay = _normalizeDelay(rawDelay, 0.1)

    local enabled = _readEnabled()

    local priority = tostring(
        G.AUTO_COLLECT_PRIORITY or rawget(_G, "AUTO_COLLECT_PRIORITY") or ac.priority or "off"
    ):lower()
    if priority ~= "price" and priority ~= "rarity" and priority ~= "weight" then
        priority = "off"
    end

    local _, rules = _loadCollectRules(ac)

    return {
        enabled = enabled,
        delay = delay,
        priority = priority,
        filterMode = "rules",
        rules = rules,
        useRules = #rules > 0,
    }
end

local function _applyLiveFilters(ac)
    if type(ac) ~= "table" then return end
    ac.filterMode = "rules"
    ac.rules = select(2, _loadCollectRules(ac))
    ac.useRules = #(ac.rules or {}) > 0
end

local function getACStateCached()
    local now = os.clock()
    if cachedAC and (now - cachedACAt) <= AC_CACHE_SEC then
        cachedAC.enabled = _readEnabled()
        cachedAC.delay = _liveDelay()
        local pr = G.AUTO_COLLECT_PRIORITY or rawget(_G, "AUTO_COLLECT_PRIORITY")
        if pr then
            pr = tostring(pr):lower()
            if pr == "price" or pr == "rarity" or pr == "weight" then
                cachedAC.priority = pr
            end
        end
        _applyLiveFilters(cachedAC)
        return cachedAC
    end
    cachedAC = getACState()
    cachedAC.delay = _liveDelay()
    cachedACAt = now
    return cachedAC
end

local function _invalidateACCache()
    cachedAC = nil
    cachedACAt = 0
    _clearBatchCaches()
    _invalidatePromptScan()
    table.clear(weightCache)
end

local function _writeMainCollect(patch)
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    if type(MAIN) ~= "table" then return end
    MAIN.auto = MAIN.auto or {}
    MAIN.auto.collect = MAIN.auto.collect or {}
    for k, v in pairs(patch) do
        MAIN.auto.collect[k] = v
    end
    G.MAIN = MAIN
    _G.MAIN = MAIN
end

----------------------------------------------------------------
-- garden + fruit
----------------------------------------------------------------
local function _plotOwnedByLocal(plot)
    if not plot then return false end
    local uid, name = LP.UserId, LP.Name
    local function match(v)
        if v == nil then return false end
        return v == uid or v == name or tostring(v) == tostring(uid) or tostring(v) == name
    end
    if match(plot:GetAttribute("OwnerId")) then return true end
    if match(plot:GetAttribute("Owner")) then return true end
    if match(plot:GetAttribute("UserId")) then return true end
    return false
end

local function getPlayerPlot(force)
    local now = os.clock()
    if not force and cachedPlot and cachedPlot.Parent and (now - cachedPlotAt) <= PLOT_CACHE_SEC then
        return cachedPlot
    end

    local gardens = workspace:FindFirstChild("Gardens")
    if not gardens then
        cachedPlot = nil
        cachedPlotAt = now
        return nil
    end

    local plotId = LP:GetAttribute("PlotId")
    if plotId ~= nil then
        local byId = gardens:FindFirstChild("Plot" .. tostring(plotId))
        if byId then
            cachedPlot = byId
            cachedPlotAt = now
            return byId
        end
    end

    for _, plot in ipairs(gardens:GetChildren()) do
        if _plotOwnedByLocal(plot) then
            cachedPlot = plot
            cachedPlotAt = now
            return plot
        end
    end

    local byName = gardens:FindFirstChild("Plot" .. LP.Name)
    cachedPlot = byName
    cachedPlotAt = now
    return byName
end

local function _fruitFromPrompt(prompt)
    if not prompt or not prompt.Parent then return nil end
    local model = prompt.Parent:FindFirstAncestorWhichIsA("Model")
    if model and _attrId(model, "PlantId") ~= "" then
        return model
    end
    local node, best = prompt.Parent, nil
    while node do
        if node:IsA("Model") then
            local pid = _attrId(node, "PlantId")
            if pid ~= "" then
                best = node
                if _attrId(node, "FruitId") ~= "" then
                    return node
                end
            end
        end
        if node.Name == "Gardens" then break end
        node = node.Parent
    end
    return best or model
end

local function _parseKgText(text)
    return tonumber(tostring(text or ""):match("([%d%.]+)%s*[kK][gG]"))
end

local function _weightFromBillboard(model)
    if not model then return nil end
    local node, depth = model, 0
    while node and depth < 6 do
        if node:IsA("Model") then
            for _, ch in ipairs(node:GetChildren()) do
                if ch:IsA("BillboardGui") or ch:IsA("SurfaceGui") then
                    for _, d in ipairs(ch:GetDescendants()) do
                        if d:IsA("TextLabel") then
                            local w = _parseKgText(d.Text)
                            if w and w > 0 then return w end
                        end
                    end
                elseif ch:IsA("TextLabel") then
                    local w = _parseKgText(ch.Text)
                    if w and w > 0 then return w end
                end
            end
        end
        if node.Name == "Gardens" then break end
        node = node.Parent
        depth += 1
    end
    return nil
end

local function _weightFromAttrs(model)
    if not model then return nil end
    local node, depth = model, 0
    while node and depth < 10 do
        if node:IsA("Model") then
            local bw = tonumber(node:GetAttribute("BaseWeight"))
            local sm = tonumber(node:GetAttribute("SizeMulti") or node:GetAttribute("SizeMultiplier"))
            local og = tonumber(node:GetAttribute("OvertimeGrowth")) or 1
            if bw and bw > 0 and sm and sm > 0 then
                return bw * sm * og
            end
            local w = tonumber(node:GetAttribute("Weight"))
            if w and w > 0 then return w end
        end
        if node.Name == "Gardens" then break end
        node = node.Parent
        depth += 1
    end
    return nil
end

local function _getName(model)
    if type(FruitSellValue) == "table" and type(FruitSellValue.resolveSeedName) == "function" then
        local ok, name = pcall(FruitSellValue.resolveSeedName, model)
        if ok and type(name) == "string" and name ~= "" then
            return name
        end
    end
    return model:GetAttribute("CorePartName")
        or model:GetAttribute("FruitType")
        or model:GetAttribute("FruitName")
        or model:GetAttribute("ItemName")
        or model:GetAttribute("SeedName")
        or model:GetAttribute("ConfigPathName")
        or model.Name
end

local function _getWeight(model)
    if not model then return 0 end

    local plantId, fruitId = _resolvePlotFruitIds(model)
    if plantId == "" then return 0 end

    local cacheKey = plantId .. "|" .. fruitId
    local now = os.clock()
    local cached = weightCache[cacheKey]
    if cached and (now - cached.at) <= WEIGHT_CACHE_SEC then
        return cached.w
    end

    local w = _weightFromAttrs(model)
    if not w then
        local viz = _getFruitVisualizer()
        w = _kgFromViz(viz, model)
        if not w and model.Parent and model.Parent:IsA("Model") then
            w = _kgFromViz(viz, model.Parent)
        end
    end
    if not w and type(FruitSellValue) == "table" and type(FruitSellValue.resolveWeight) == "function" then
        local ok, val = pcall(FruitSellValue.resolveWeight, model)
        if ok and type(val) == "number" and val > 0 then
            w = val
        end
    end
    if not w then
        w = _weightFromBillboard(model)
    end
    w = tonumber(w) or 0
    weightCache[cacheKey] = { w = w, at = now }
    return w
end

local function _parseMutationList(inst)
    local raw = inst and inst:GetAttribute("Mutation")
    if type(raw) ~= "string" or raw == "" then return {} end
    local out = {}
    for token in string.gmatch(raw, "[^%+%,]+") do
        token = tostring(token):match("^%s*(.-)%s*$")
        if token and token ~= "" then out[#out + 1] = token end
    end
    return out
end

local NO_MUTATION_LABEL = "No Mutation"

local function _isNoMutationKey(name)
    local c = _canon(name)
    return c == "nomutation" or c == "none" or tostring(name or "") == NO_MUTATION_LABEL
end

local _mutNameList = nil

local function _getMutationNames()
    if _mutNameList then return _mutNameList end
    _mutNameList = {}
    local PLV = G.PlantListView or _G.PlantListView
    if type(PLV) == "table" and type(PLV.listMutationNames) == "function" then
        local ok, list = pcall(PLV.listMutationNames, PLV)
        if ok and type(list) == "table" then
            for _, n in ipairs(list) do
                if not _isNoMutationKey(n) then
                    _mutNameList[#_mutNameList + 1] = n
                end
            end
        end
    end
    if #_mutNameList == 0 then
        _mutNameList = { "Gold", "Rainbow" }
    end
    return _mutNameList
end

local function _fruitHasMutation(inst)
    if not inst then return false end
    if type(FruitSellValue) == "table" and type(FruitSellValue.resolveMutation) == "function" then
        local ok, mut = pcall(FruitSellValue.resolveMutation, inst)
        if ok and type(mut) == "string" and mut ~= "" then
            return true
        end
    end
    for _, mutName in ipairs(_parseMutationList(inst)) do
        local lower = mutName:lower()
        if lower ~= "none" and lower ~= "normal" and not _isNoMutationKey(mutName) then
            return true
        end
    end
    for _, name in ipairs(_getMutationNames()) do
        if inst:GetAttribute(name) == true then
            return true
        end
    end
    return false
end

local function matchSet(selectedMap, value)
    if not _hasAny(selectedMap) then return true end
    local needle = _canon(value)
    for k, v in pairs(selectedMap) do
        if v == true and _canon(k) == needle then return true end
    end
    return false
end

local function matchMutation(selectedMap, inst)
    if not _hasAny(selectedMap) then return true end
    if not inst then return false end

    if selectedMap[NO_MUTATION_LABEL] == true and not _fruitHasMutation(inst) then
        return true
    end

    for mutName, on in pairs(selectedMap) do
        if on == true and not _isNoMutationKey(mutName) and inst:GetAttribute(mutName) == true then
            return true
        end
    end
    for _, mutName in ipairs(_parseMutationList(inst)) do
        if not _isNoMutationKey(mutName) and matchSet(selectedMap, mutName) then
            return true
        end
    end
    if type(FruitSellValue) == "table" and type(FruitSellValue.resolveMutation) == "function" then
        local ok, raw = pcall(FruitSellValue.resolveMutation, inst)
        if ok and type(raw) == "string" and raw ~= "" then
            for token in string.gmatch(raw, "[^%+%,]+") do
                if matchSet(selectedMap, token) then
                    return true
                end
            end
        end
    end
    return false
end

local function matchKg(weight, kg, mode)
    kg, mode = _normalizeKgFilter(kg, mode)
    weight = tonumber(weight) or 0
    if kg <= 0 then
        return true
    end
    if mode == "below" then
        return weight > 0 and weight <= kg
    end
    return weight >= kg
end

local function _matchesAllFilters(fruit, ac)
    if ac.anyFruit and not matchSet(ac.fruits, _getName(fruit)) then return false end
    if ac.anyMut and not matchMutation(ac.mutations, fruit) then return false end
    if ac.anyKg and not matchKg(_getWeight(fruit), ac.kg, ac.kgMode) then return false end
    return true
end

local function matchPrice(price, filterPrice, mode)
    filterPrice = tonumber(filterPrice) or 0
    if filterPrice <= 0 then return true end
    price = tonumber(price) or 0
    mode = tostring(mode or "above")
    if mode == "below" then
        return price > 0 and price <= filterPrice
    end
    return price >= filterPrice
end

local function _ruleToPersist(rule)
    return {
        id = rule.id,
        enabled = rule.enabled,
        fruits = _setToArray(rule.fruits),
        mutations = _setToArray(rule.mutations),
        kg = rule.kg,
        kgMode = rule.kgMode,
        kgRule = rule.kgRule,
        minPrice = rule.minPrice,
        minPriceMode = rule.minPriceMode,
        priceRule = rule.priceRule,
        requireMut = rule.requireMut,
    }
end

local function _normalizeCollectRule(raw)
    raw = type(raw) == "table" and raw or {}
    local fruits = _normalizeSet(raw.fruits)
    local mutations = _normalizeSet(raw.mutations)
    local kg, kgMode = _normalizeKgFilter(raw.kg, raw.kgMode)
    if type(raw.kgRule) == "string" and raw.kgRule:gsub("%s+", "") ~= "" then
        kg, kgMode = _parseKgRuleInput(raw.kgRule)
    end
    local minPrice, minPriceMode = _normalizePriceFilter(raw.minPrice, raw.minPriceMode)
    if type(raw.priceRule) == "string" and raw.priceRule:gsub("%s+", "") ~= "" then
        minPrice, minPriceMode = _parsePriceRuleInput(raw.priceRule)
    end
    local requireMut = raw.requireMut == true
    return {
        id = tostring(raw.id or ""),
        enabled = raw.enabled ~= false,
        fruits = fruits,
        mutations = mutations,
        kg = kg,
        kgMode = kgMode,
        kgRule = type(raw.kgRule) == "string" and raw.kgRule or _formatKgRule(kg, kgMode),
        minPrice = minPrice,
        minPriceMode = minPriceMode,
        priceRule = type(raw.priceRule) == "string" and raw.priceRule or _formatPriceRule(minPrice, minPriceMode),
        requireMut = requireMut,
        anyFruit = _hasAny(fruits),
        anyMut = _hasAny(mutations),
        anyPrice = minPrice > 0,
    }
end

_loadCollectRules = function(ac)
    ac = type(ac) == "table" and ac or {}
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    local mainAc = MAIN and MAIN.auto and MAIN.auto.collect

    local rawRules = G.AUTO_COLLECT_RULES or rawget(_G, "AUTO_COLLECT_RULES")
        or ac.rules or (mainAc and mainAc.rules)
    local order = G.AUTO_COLLECT_RULES_ORDER or rawget(_G, "AUTO_COLLECT_RULES_ORDER")
        or ac.rulesOrder or (mainAc and mainAc.rulesOrder)

    local byId = {}
    if type(rawRules) == "table" then
        if #rawRules > 0 then
            for _, r in ipairs(rawRules) do
                local norm = _normalizeCollectRule(r)
                if norm.id == "" then
                    norm.id = "r" .. tostring(_)
                end
                byId[norm.id] = norm
            end
        else
            for id, r in pairs(rawRules) do
                if type(r) == "table" then
                    local norm = _normalizeCollectRule(r)
                    norm.id = tostring(norm.id ~= "" and norm.id or id)
                    byId[norm.id] = norm
                end
            end
        end
    end

    local out, seen = {}, {}
    if type(order) == "table" then
        for _, id in ipairs(order) do
            id = tostring(id or "")
            local rule = byId[id]
            if rule and not seen[id] then
                seen[id] = true
                out[#out + 1] = rule
            end
        end
    end
    for id, rule in pairs(byId) do
        if not seen[id] then
            out[#out + 1] = rule
        end
    end
    return "rules", out
end

local function _matchesCollectRule(fruit, rule)
    if type(rule) ~= "table" or rule.enabled == false then return false end
    if rule.anyFruit and not matchSet(rule.fruits, _getName(fruit)) then return false end
    if rule.kg > 0 and not matchKg(_getWeight(fruit), rule.kg, rule.kgMode) then return false end
    if rule.requireMut == true then
        if rule.anyMut then
            if not matchMutation(rule.mutations, fruit) then return false end
        elseif not _fruitHasMutation(fruit) then
            return false
        end
    elseif rule.anyMut and not matchMutation(rule.mutations, fruit) then
        return false
    end
    if rule.anyPrice and not matchPrice(_getFruitPrice(fruit), rule.minPrice, rule.minPriceMode) then return false end
    return true
end

local function _matchesRulesMode(fruit, ac)
    local rules = ac.rules
    if type(rules) ~= "table" or #rules == 0 then
        return true
    end
    for _, rule in ipairs(rules) do
        if _matchesCollectRule(fruit, rule) then
            return true
        end
    end
    return false
end

local function _allowed(fruit, ac)
    if not fruit or not fruit.Parent then return false end
    return _matchesRulesMode(fruit, ac)
end

local function _promptCollectable(prompt, ac, applyFilter)
    if not prompt or not prompt.Parent or not prompt:IsA("ProximityPrompt") then return false end
    if prompt:GetAttribute("Collected") then return false end
    local fruit = _fruitFromPrompt(prompt)
    if not fruit or not fruit.Parent then return false end
    local plantId = select(1, _idsFromPrompt(prompt))
    if plantId == "" then
        plantId = select(1, _resolvePlotFruitIds(fruit))
    end
    if plantId == "" then return false end
    if applyFilter and ac and not _allowed(fruit, ac) then return false end
    return true
end

local function _makeKey(plantId, fruitId)
    return tostring(plantId) .. "|" .. tostring(fruitId or "")
end

----------------------------------------------------------------
-- scan plot (GetTagged HarvestPrompt, filter plot sendiri)
----------------------------------------------------------------
local function _iterPlotHarvestPrompts(plot, force)
    if not plot then return {} end

    local now = os.clock()
    if not force
        and promptScanCache.plot == plot
        and (now - promptScanCache.at) <= PROMPT_SCAN_CACHE_SEC
        and #promptScanCache.list > 0 then
        return promptScanCache.list
    end

    local out = {}
    local checked = 0
    for _, prompt in ipairs(CollectionService:GetTagged(HARVEST_TAG)) do
        if prompt:IsA("ProximityPrompt") and prompt:IsDescendantOf(plot) then
            out[#out + 1] = prompt
        end
        checked += 1
        if checked >= 200 then
            checked = 0
            task.wait()
        end
    end

    promptScanCache.plot = plot
    promptScanCache.at = now
    promptScanCache.list = out
    return out
end

local function _scanPlotTargets(ac, applyFilter)
    local plot = getPlayerPlot()
    if not plot then return 0, nil end

    local n = 0
    local seen = {}
    local list = applyFilter and {} or nil
    local needScore = applyFilter and ac.priority ~= "off"

    for _, prompt in ipairs(_iterPlotHarvestPrompts(plot)) do
        if not _promptCollectable(prompt, ac, applyFilter) then continue end

        local fruit = _fruitFromPrompt(prompt)
        local plantId, fruitId = _idsFromPrompt(prompt)
        if plantId == "" then
            plantId, fruitId = _resolvePlotFruitIds(fruit)
        end
        local key = _makeKey(plantId, fruitId)
        if seen[key] then continue end
        seen[key] = true
        n += 1

        if list then
            local score = 0
            if needScore and type(FruitSellValue) == "table"
                and type(FruitSellValue.priorityScore) == "function" then
                local ok, sc = pcall(FruitSellValue.priorityScore, fruit, ac.priority, fruit)
                if ok and type(sc) == "number" then score = sc end
            end
            list[#list + 1] = {
                plantId = plantId,
                fruitId = fruitId,
                key = key,
                score = score,
            }
        end
    end

    if list and ac.priority ~= "off" and #list > 1 then
        table.sort(list, function(a, b)
            return (a.score or 0) > (b.score or 0)
        end)
    end

    return n, list
end

local function countReadyTargets()
    local now = os.clock()
    if now - _readyCacheAt <= COUNT_CACHE_SEC then
        return _readyCache
    end
    _readyCache = _scanPlotTargets(nil, false)
    _readyCacheAt = now
    return _readyCache
end

local function countFilteredTargets()
    local now = os.clock()
    if now - _filteredCacheAt <= COUNT_CACHE_SEC then
        return _filteredCache
    end
    _filteredCache = _scanPlotTargets(getACStateCached(), true)
    _filteredCacheAt = now
    return _filteredCache
end

----------------------------------------------------------------
-- batch cache + collect
----------------------------------------------------------------
local _consecutiveFireFail = 0
local FIRE_FAIL_SKIP      = 8

local function _isBackpackFull()
    local count = tonumber(LP:GetAttribute("FruitCount"))
    local maxCap = tonumber(LP:GetAttribute("MaxFruitCapacity"))
    if count == nil or maxCap == nil or maxCap <= 0 then return false end
    return count >= maxCap
end

local function _collectPacketOk(fireResult)
    if fireResult == false then return false end
    if type(fireResult) == "table" then
        if fireResult.Success == false or fireResult.success == false then return false end
    end
    return true
end

local function _tryCollectRemote(fn, ...)
    if type(fn) ~= "function" then return false end
    local args = table.pack(...)
    local results = table.pack(pcall(function()
        return fn(CollectFruit, table.unpack(args, 1, args.n))
    end))
    if not results[1] then return false end
    return _collectPacketOk(results[2])
end

local function _fireCollect(plantId, fruitId)
    plantId = tostring(plantId or "")
    fruitId = tostring(fruitId or "")
    if plantId == "" then return false end
    if not _ensureCollectRemote() then return false end
    if _isBackpackFull() then return false end

    -- HarvestPromptController always passes (PlantId, FruitId or "").
    if type(CollectFruit.Fire) == "function" then
        return _tryCollectRemote(CollectFruit.Fire, plantId, fruitId)
    end
    if type(CollectFruit.FireServer) == "function" then
        return _tryCollectRemote(CollectFruit.FireServer, plantId, fruitId)
    end
    if type(CollectFruit.InvokeServer) == "function" then
        return _tryCollectRemote(CollectFruit.InvokeServer, plantId, fruitId)
    end
    return false
end

local function _refillBatch(ac)
    batchIdx = 1
    table.clear(batchList)

    local _, list = _scanPlotTargets(ac, true)
    if not list then return 0 end

    for i = 1, #list do
        batchList[i] = list[i]
    end

    batchIdx = 1
    return #batchList
end

local function _batchEmpty()
    return batchIdx > #batchList
end

local function _fireNextFromBatch()
    if _batchEmpty() then return 0 end

    local item = batchList[batchIdx]
    if not item then
        batchIdx += 1
        return 0
    end

    if _fireCollect(item.plantId, item.fruitId) then
        batchIdx += 1
        _consecutiveFireFail = 0
        _totalCollected += 1
        _lastTickCollected = 1
        _invalidatePromptScan()
        _readyCacheAt = 0
        _filteredCacheAt = 0
        return 1
    end

    _lastTickCollected = 0
    _consecutiveFireFail += 1
    if _consecutiveFireFail >= FIRE_FAIL_SKIP then
        _consecutiveFireFail = 0
        batchIdx += 1
    end
    return 0
end

local function collectLoop(myId)
    loopAliveId = myId
    _log("loop start", myId)

    local lastFilterKey = ""
    local plotWaitAt = 0
    local lastScanAt = 0

    while running and myId == loopId do
        local ac = getACStateCached()
        local filterKey = _batchFilterKey(ac)
        if filterKey ~= lastFilterKey then
            if lastFilterKey ~= "" then
                _clearBatchCaches()
                table.clear(weightCache)
            end
            lastFilterKey = filterKey
        end

        if not ac.enabled then
            task.wait(0.35)
        elseif _isBackpackFull() then
            task.wait(0.75)
        elseif not _ensureCollectRemote() then
            task.wait(0.5)
        elseif _batchEmpty() then
            local plot = getPlayerPlot()
            if not plot then
                if os.clock() - plotWaitAt >= 2 then
                    plotWaitAt = os.clock()
                    cachedPlot = nil
                    cachedPlotAt = 0
                    _invalidatePromptScan()
                    getPlayerPlot(true)
                end
                task.wait(0.35)
            else
                local now = os.clock()
                if (now - lastScanAt) < SCAN_MIN_SEC then
                    task.wait(0.12)
                else
                    lastScanAt = now
                    local n = _refillBatch(ac)
                    if n == 0 then
                        task.wait(IDLE_WAIT_SEC)
                    end
                end
            end
        else
            _fireNextFromBatch()
            _waitAfterFire(ac)
        end
    end

    if loopAliveId == myId then loopAliveId = 0 end
    _log("loop end", myId)
end

----------------------------------------------------------------
-- public API
----------------------------------------------------------------
local function _coerceOn(a, b)
    if type(a) == "table" then return b == true end
    return a == true
end

function M.SetEnabled(a, b)
    local on = _coerceOn(a, b)
    G.AUTO_COLLECT_FRUIT_ENABLED = on
    _G.AUTO_COLLECT_FRUIT_ENABLED = on
    _writeMainCollect({ enabled = on })
    _invalidateACCache()

    if on then
        running = true
        if loopAliveId > 0 and loopAliveId == loopId then return end
        loopId += 1
        local myId = loopId
        task.spawn(function()
            local ok, err = pcall(collectLoop, myId)
            if not ok then
                _warn("loop error:", err)
                if loopAliveId == myId then loopAliveId = 0 end
            end
        end)
    else
        running = false
        loopId += 1
    end
end

M.setEnabled = M.SetEnabled
M.Start = function() return M.SetEnabled(true) end
M.start = M.Start
M.Stop = function() return M.SetEnabled(false) end
M.stop = M.Stop
M.IsRunning = function()
    return running == true and loopAliveId > 0
end
M.isRunning = M.IsRunning

function M.EnsureRunning()
    if not _readEnabled() then
        M.Stop()
        return false
    end
    if running and loopAliveId > 0 and loopAliveId == loopId then
        return true
    end
    M.Start()
    return running and loopAliveId > 0
end
M.ensureRunning = M.EnsureRunning

local function _applySet(keyGlobal, keyMain, map)
    map = _normalizeSet(map)
    G[keyGlobal] = map
    _G[keyGlobal] = map
    _writeMainCollect({ [keyMain] = _setToArray(map) })
    _invalidateACCache()
    return map
end

function M.SetFruits(a, b)
    local map = (type(a) == "table" and b ~= nil) and b or a
    return _applySet("AUTO_COLLECT_FRUITS_SELECTED", "fruits", map)
end

M.SetSelected = M.SetFruits
M.setSelected = M.SetFruits
M.setFruits   = M.SetFruits

function M.SetMutations(a, b)
    local map = (type(a) == "table" and b ~= nil) and b or a
    return _applySet("AUTO_COLLECT_MUTATIONS_SELECTED", "mutations", map)
end

M.setMutations = M.SetMutations

function M.SetKgFilter(a, b, c)
    local kg, mode
    if type(a) == "table" then
        kg, mode = b, c
    else
        kg, mode = a, b
    end
    kg, mode = _normalizeKgFilter(kg, mode)
    local rule = _formatKgRule(kg, mode)
    local curRule = G.AUTO_COLLECT_KG_RULE or rawget(_G, "AUTO_COLLECT_KG_RULE")
    if tonumber(G.AUTO_COLLECT_KG or rawget(_G, "AUTO_COLLECT_KG")) == kg
        and tostring(G.AUTO_COLLECT_KG_MODE or rawget(_G, "AUTO_COLLECT_KG_MODE") or "") == mode
        and tostring(curRule or "") == rule then
        return
    end
    G.AUTO_COLLECT_KG = kg
    G.AUTO_COLLECT_KG_MODE = mode
    G.AUTO_COLLECT_KG_RULE = rule
    _G.AUTO_COLLECT_KG = kg
    _G.AUTO_COLLECT_KG_MODE = mode
    _G.AUTO_COLLECT_KG_RULE = rule
    _writeMainCollect({ kg = kg, kgMode = mode, kgRule = rule })
    _invalidateACCache()
end

M.setKgFilter = M.SetKgFilter

function M.SetFilterMode(_mode)
    G.AUTO_COLLECT_FILTER_MODE = "rules"
    _G.AUTO_COLLECT_FILTER_MODE = "rules"
    _writeMainCollect({ filterMode = "rules" })
    _invalidateACCache()
    return "rules"
end

M.setFilterMode = M.SetFilterMode

function M.SetRules(rules, order)
    rules = type(rules) == "table" and rules or {}
    order = type(order) == "table" and order or {}
    G.AUTO_COLLECT_RULES = rules
    _G.AUTO_COLLECT_RULES = rules
    G.AUTO_COLLECT_RULES_ORDER = order
    _G.AUTO_COLLECT_RULES_ORDER = order
    _writeMainCollect({ rules = rules, rulesOrder = order })
    _invalidateACCache()
end

M.setRules = M.SetRules

function M.AddRule(rule)
    rule = _normalizeCollectRule(rule)
    if rule.id == "" then
        rule.id = "r" .. tostring(math.floor(os.clock() * 1000)) .. "_" .. tostring(math.random(1000, 9999))
    end
    local ac = getACStateCached()
    local rules, order = {}, {}
    for _, r in ipairs(ac.rules or {}) do
        rules[#rules + 1] = _ruleToPersist(r)
        order[#order + 1] = r.id
    end
    rules[#rules + 1] = _ruleToPersist(rule)
    order[#order + 1] = rule.id
    M.SetRules(rules, order)
    return rule.id
end

M.addRule = M.AddRule

function M.RemoveRule(ruleId)
    ruleId = tostring(ruleId or "")
    if ruleId == "" then return end
    local ac = getACStateCached()
    local rules, order = {}, {}
    for _, r in ipairs(ac.rules or {}) do
        if r.id ~= ruleId then
            rules[#rules + 1] = _ruleToPersist(r)
            order[#order + 1] = r.id
        end
    end
    M.SetRules(rules, order)
end

M.removeRule = M.RemoveRule

function M.GetRules()
    local ac = getACStateCached()
    return ac.rules or {}, "rules"
end

M.getRules = M.GetRules

function M.SetDelay(a, b)
    local n = _normalizeDelay(type(a) == "table" and b or a, 0.1)
    G.AUTO_COLLECT_DELAY = n
    _G.AUTO_COLLECT_DELAY = n
    _writeMainCollect({ delay = n })
    _invalidateACCache()
end

M.setDelay = M.SetDelay

function M.SetPriority(a, b)
    local mode = (type(a) == "table" and b) or a
    mode = tostring(mode or "off"):lower()
    if mode ~= "price" and mode ~= "rarity" and mode ~= "weight" then
        mode = "off"
    end
    G.AUTO_COLLECT_PRIORITY = mode
    _G.AUTO_COLLECT_PRIORITY = mode
    _writeMainCollect({ priority = mode })
    _invalidateACCache()
    return mode
end

M.setPriority = M.SetPriority

function M.EstimateFruitValue(model)
    if type(FruitSellValue) == "table" and type(FruitSellValue.fromFruit) == "function" then
        return FruitSellValue.fromFruit(model)
    end
    return 0
end

M.estimateFruitValue = M.EstimateFruitValue

function M.SyncFromState()
    local ac = getACState()
    M.SetFilterMode("rules")
    if type(ac.rules) == "table" then
        local rules, order = {}, {}
        for _, r in ipairs(ac.rules) do
            rules[#rules + 1] = _ruleToPersist(r)
            order[#order + 1] = r.id
        end
        local MAIN = rawget(_G, "MAIN") or G.MAIN
        local mainRules = MAIN and MAIN.auto and MAIN.auto.collect and MAIN.auto.collect.rules
        local mainOrder = MAIN and MAIN.auto and MAIN.auto.collect and MAIN.auto.collect.rulesOrder
        if type(mainRules) == "table" and #mainRules > 0 then
            M.SetRules(mainRules, mainOrder or {})
        else
            M.SetRules(rules, order)
        end
    end
    M.SetDelay(ac.delay)
    M.SetPriority(ac.priority)
    if ac.enabled then
        G.AUTO_COLLECT_FRUIT_ENABLED = true
        _G.AUTO_COLLECT_FRUIT_ENABLED = true
        running = true
        M.EnsureRunning()
    else
        M.SetEnabled(false)
    end
end

