        pcall(M.EnsureRunning)
    end
end)

return M
 end,                    required = false },
    { key = "AutoSell",                name = "Auto Sell",               factory = function() -- AutoSell.lua — Grow A Garden 2
-- Tanpa filter: Networking.NPCS.PreviewSellAll / SellAll
-- Dengan filter: scan backpack → SellFruit(fruitId) satu per satu

local Players           = game:GetService("Players")
