    FruitProxyUtil = require(ReplicatedStorage.SharedModules.FruitProxyUtil)
end)

local LOOP_MIN_SEC          = 0.5
local SELL_BUSY_SEC         = 1.0
local FILTER_SELL_BUSY_SEC  = 0.3
local FILTER_LOOP_MIN_SEC   = 0.2
local PRE_SELL_SYNC_WALL    = 10
local HEAVY_INVENTORY_COUNT = 2500
local EMPTY_SELL_BACKOFF    = 2.5
