local FILTER_CACHE_SEC      = 1.5
local FILTER_EMPTY_BACKOFF  = 0.6
local SINGLE_SELL_GAP       = 0.03
local SINGLE_SELL_GAP_MAX   = 0.07
local NO_MUTATION_LABEL     = "No Mutation"
local MODULE_VERSION        = "20250702h"

local running         = false
local loopId          = 0
local busySelling     = false
