local lastEmptySellAt = 0
local attrConns       = {}
local invConns        = {}
local childAddedConn  = nil
local previewCache    = { n = 0, at = 0 }
local filterCache     = { n = 0, at = 0, key = "", items = nil }

----------------------------------------------------------------
local function _getEspBackpack()
    return G.EspFruitBackpack or _G.EspFruitBackpack
end

local function _fsv()
    if type(FruitSellValue) == "table" then return FruitSellValue end
    FruitSellValue = G.FruitSellValue or _G.FruitSellValue
    if type(FruitSellValue) == "table" then return FruitSellValue end
    pcall(function() FruitSellValue = require(script.Parent.FruitSellValue) end)
    if type(FruitSellValue) == "table" then return FruitSellValue end
