G.AutoSellFruit = M
_G.AutoSellFruit = M

return M
 end,                       required = false },
    { key = "AutoPlant",               name = "Auto Plant",              factory = function() -- AutoPlant.lua — Grow A Garden 2
-- Plant: Networking.Plant.PlantSeed:Fire(position, seedToolId, tool)

local Players            = game:GetService("Players")
local ReplicatedStorage  = game:GetService("ReplicatedStorage")
local CollectionService  = game:GetService("CollectionService")
local UserInputService   = game:GetService("UserInputService")
local GuiService         = game:GetService("GuiService")

local LP = Players.LocalPlayer
local G  = (getgenv and getgenv()) or _G
local M  = {}

local Networking = require(ReplicatedStorage.SharedModules.Networking)
local PlantSeed  = Networking.Plant.PlantSeed

local Gardens = workspace:WaitForChild("Gardens")

local LOOP_MIN_SEC     = 0.5
local PLANT_MIN_GAP    = 0.05
local MIN_PLANT_DIST   = 0.45
local RANDOM_MIN_PLANT_DIST = 0.35
local RANDOM_MAX_TRY   = 48
local RANDOM_PART_MARGIN = 0.92
local MANUAL_SLOT_SPACING = MIN_PLANT_DIST * 1.05
local MANUAL_GRID_MAX  = 300
local MANUAL_MAX_TRY_PER_TICK = 48
local PLOT_CACHE_SEC   = 2

local running          = false
local loopId           = 0
local lastPlantAt      = 0
local manualPosIndex   = 1
local manualGridSlot   = 1
local saveInputConn    = nil
local saveEnableAt     = 0
local saveModeActive   = false
local lastClickAt      = 0
local cachedPlot       = nil
local cachedPlotAt     = 0
local randomWarnAt     = 0
local skippedSeedUntil = {}
local seedToolRotate   = 0
local sessionStartTotal = 0
local sessionPlanted    = 0
local sessionUserLimit  = 0

----------------------------------------------------------------
local function _dbg()
    return G.AUTO_PLANT_DEBUG == true or _G.AUTO_PLANT_DEBUG == true
end

local function _log(...)
    if not _dbg() then return end
    print("[GAG2-AP]", ...)
end

local function _notifyPositionsChanged()
    if type(G.__GAG2_ON_PLANT_POSITIONS_CHANGED) == "function" then
        pcall(G.__GAG2_ON_PLANT_POSITIONS_CHANGED)
    end
end

local function _notifySeedStatsChanged()
    if type(G.__GAG2_ON_PLANT_SEED_STATS_CHANGED) == "function" then
        pcall(G.__GAG2_ON_PLANT_SEED_STATS_CHANGED)
    end
end

local function _writeMainPlant(patch)
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    if type(MAIN) ~= "table" then return end
    MAIN.auto = MAIN.auto or {}
    MAIN.auto.plant = MAIN.auto.plant or {}
    for k, v in pairs(patch) do
        MAIN.auto.plant[k] = v
    end
    G.MAIN = MAIN
    _G.MAIN = MAIN
end

local function _normalizeSet(src)
    if type(src) ~= "table" then return {} end
    local out = {}
    for i = 1, #src do
        local v = src[i]
        if v ~= nil and tostring(v) ~= "" then
            out[tostring(v)] = true
        end
    end
    if next(out) then return out end
    for k, v in pairs(src) do
        if v == true or v == 1 or v == "true" then
            out[tostring(k)] = true
        end
    end
    return out
end

local function _safeStr(v)
    if v == nil then return "" end
    return tostring(v)
end

local function _canon(s)
    return _safeStr(s):lower():gsub("[^%w]+", "")
end

local function _strMatch(a, b)
    a = _canon(a)
    b = _canon(b)
    if a == "" or b == "" then return false end
    if a == b then return true end
    return string.find(a, b, 1, true) ~= nil or string.find(b, a, 1, true) ~= nil
end

local function _normSeedKey(v)
    v = _canon(v)
    if v:sub(-4) == "seed" then
        v = v:sub(1, -5)
    end
    return v
end

local function _getPlantListView()
    return G.PlantListView or rawget(_G, "PlantListView")
end

local function _isMutationSeedTool(tool)
    if not tool then return false end
    if tool:GetAttribute("MutationSeed") == true then return true end

    local seedName = tool:GetAttribute("SeedName") or tool.Name
    local plv = _getPlantListView()
    if plv and type(plv.findBySeedName) == "function" then
        local ok, entry = pcall(plv.findBySeedName, plv, seedName)
        if ok and type(entry) == "table" and entry.MutationSeed == true then
            return true
        end
    end

    local muts = {}
    if plv and type(plv.listMutationNames) == "function" then
        local ok, list = pcall(plv.listMutationNames, plv)
        if ok and type(list) == "table" then
            for _, n in ipairs(list) do
                muts[_normSeedKey(n)] = true
            end
        end
    end

    local key = _normSeedKey(seedName)
    return muts[key] == true
end

local function _isAvatarBlockedError(err)
    err = tostring(err or ""):lower()
    return err:find("avatar", 1, true) ~= nil
        or err:find("equip the", 1, true) ~= nil
end

local function _seedToolId(tool)
    return tostring(tool and tool:GetAttribute("SeedTool") or tool and tool.Name or "")
end

local function _isSeedToolSkipped(tool)
    local id = _seedToolId(tool)
    if id == "" then return false end
    local untilAt = skippedSeedUntil[id]
    if not untilAt then return false end
    if os.clock() >= untilAt then
        skippedSeedUntil[id] = nil
        return false
    end
    return true
end

local function _markSeedToolSkipped(tool, seconds)
    local id = _seedToolId(tool)
    if id == "" then return end
    skippedSeedUntil[id] = os.clock() + (tonumber(seconds) or 90)
end

local function _iterInventoryContainers()
    local out = {}
    local seen = {}

    local function add(c)
        if c and not seen[c] then
            seen[c] = true
            out[#out + 1] = c
        end
    end

    add(LP:FindFirstChildOfClass("Backpack"))
    add(LP:FindFirstChild("Backpack"))
    add(LP:FindFirstChild("TasRansel"))
    add(LP.Character)

    for _, ch in ipairs(LP:GetChildren()) do
        if ch:IsA("Folder") or ch:IsA("Model") or ch:IsA("Backpack") then
            local n = ch.Name:lower()
            if n:find("backpack") or n:find("ransel") or n:find("tas") or n:find("inventory") then
                add(ch)
            end
        end
    end

    return out
end

local function _normalizePositionId(v)
    if v == nil then return nil end
    if type(v) == "table" then
        v = v.id or v.key
    end
    v = tostring(v)
    if v == "" or v:sub(1, 6) == "table:" then return nil end
    return v
end

local function getPlantState()
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    local ap = MAIN and MAIN.auto and MAIN.auto.plant
    ap = type(ap) == "table" and ap or {}

    local seeds = G.AUTO_PLANT_SEEDS_SELECTED
        or rawget(_G, "AUTO_PLANT_SEEDS_SELECTED")
        or _normalizeSet(ap.seeds)

    local delay = tonumber(ap.delay)
    if delay == nil then
        delay = tonumber(G.AUTO_PLANT_DELAY or rawget(_G, "AUTO_PLANT_DELAY")) or 0.5
    end
    if delay < LOOP_MIN_SEC then delay = LOOP_MIN_SEC end

    local mode = tostring(ap.mode or G.AUTO_PLANT_MODE or "random"):lower()
    if mode ~= "manual" then mode = "random" end

    local positions = type(ap.positions) == "table" and ap.positions or {}

    local selectedPosition = _normalizePositionId(ap.selectedPosition)
    if selectedPosition == nil then
        selectedPosition = _normalizePositionId(G.AUTO_PLANT_SELECTED_POSITION)
    end

    local enabled = (G.AUTO_PLANT_ENABLED == true)
        or (rawget(_G, "AUTO_PLANT_ENABLED") == true)
        or (ap.enabled == true)

    local savePosition = (G.AUTO_PLANT_SAVE_POSITION == true)
        or (rawget(_G, "AUTO_PLANT_SAVE_POSITION") == true)
        or (ap.savePosition == true)

    local autoManual = (G.AUTO_PLANT_AUTO_MANUAL == true)
        or (rawget(_G, "AUTO_PLANT_AUTO_MANUAL") == true)
        or (ap.autoManual == true)

    local plantTotal = tonumber(ap.plantTotal)
    if plantTotal == nil then
        plantTotal = tonumber(G.AUTO_PLANT_TOTAL or rawget(_G, "AUTO_PLANT_TOTAL")) or 0
    end
    if plantTotal < 0 then plantTotal = 0 end
    plantTotal = math.floor(plantTotal)

    return {
        enabled          = enabled,
        seeds            = _normalizeSet(seeds),
        delay            = delay,
        mode             = mode,
        positions        = positions,
        selectedPosition = selectedPosition,
        savePosition     = savePosition,
        autoManual       = autoManual,
        plantTotal       = plantTotal,
    }
end

----------------------------------------------------------------
----------------------------------------------------------------
local function _plotOwnedByLocal(plot)
    if not plot then return false end
    local uid, name = LP.UserId, LP.Name
    local function match(v)
        if v == nil then return false end
        return v == uid or v == name or tostring(v) == tostring(uid) or tostring(v) == name
    end
    if match(plot:GetAttribute("OwnerId")) then return true end
    if match(plot:GetAttribute("Owner")) then return true end
    if match(plot:GetAttribute("OwnerUserId")) then return true end
    if match(plot:GetAttribute("UserId")) then return true end
    return false
end

local function getPlayerPlot()
    local now = os.clock()
    if cachedPlot and cachedPlot.Parent and (now - cachedPlotAt) <= PLOT_CACHE_SEC then
        return cachedPlot
    end

    if not Gardens or not Gardens.Parent then
        cachedPlot = nil
        cachedPlotAt = now
        return nil
    end

    local plotId = LP:GetAttribute("PlotId")
    if plotId ~= nil then
        local plot = Gardens:FindFirstChild("Plot" .. tostring(plotId))
        if plot then
            cachedPlot = plot
            cachedPlotAt = now
            return plot
        end
    end

    for _, plot in ipairs(Gardens:GetChildren()) do
        if _plotOwnedByLocal(plot) then
            cachedPlot = plot
            cachedPlotAt = now
            return plot
        end
    end

    local byName = Gardens:FindFirstChild("Plot" .. LP.Name)
    cachedPlot = byName
    cachedPlotAt = now
    return byName
end

local function isOwnPlot(plot)
    if not plot then return false end
    local myPlot = getPlayerPlot()
    return myPlot ~= nil and plot == myPlot
end

local function collectPlotSurfaces(plot)
    local list = {}
    local seen = {}

    local function add(inst)
        if inst and not seen[inst] then
            seen[inst] = true
            list[#list + 1] = inst
        end
    end

    for _, inst in ipairs(CollectionService:GetTagged("PlantArea")) do
        if inst:IsDescendantOf(plot) then
            add(inst)
        end
    end
    if #list > 0 then return list end

    for _, desc in ipairs(plot:GetDescendants()) do
        if desc:IsA("BasePart") and desc.Name == "Can_Plant" then
            add(desc)
        end
    end
    if #list > 0 then return list end

    for _, desc in ipairs(plot:GetDescendants()) do
        if desc:IsA("BasePart") then
            local n = desc.Name:lower()
            if n:find("soil") or n:find("dirt") or n:find("ground")
                or n:find("farm") or n:find("plot") or n:find("grass") then
                add(desc)
            end
        end
    end
    if #list > 0 then return list end

    for _, desc in ipairs(plot:GetDescendants()) do
        if desc:IsA("BasePart") and desc.CanQuery ~= false then
            add(desc)
        end
    end
    return list
end

local function createPlantAreaParams(plot)
    local params = RaycastParams.new()
    params.FilterType = Enum.RaycastFilterType.Include
    local list = collectPlotSurfaces(plot)
    params.FilterDescendantsInstances = list
    return params, list
end

local function _getPlantGroundXZ(plant)
    if not plant then return nil end

    if plant:IsA("BasePart") then
        local p = plant.Position
        return p.X, p.Z
    end

    local pos = nil
    if plant:IsA("Model") then
        local ok, pivot = pcall(function()
            return plant:GetPivot().Position
        end)
        if ok and typeof(pivot) == "Vector3" then
            pos = pivot
        elseif plant.PrimaryPart then
            pos = plant.PrimaryPart.Position
        end
    end

    if not pos then
        local part = plant:FindFirstChildWhichIsA("BasePart", true)
        if part then pos = part.Position end
    end

    if pos then
        return pos.X, pos.Z
    end
    return nil
end

local function _countPlantsOnPlot(plot)
    plot = plot or getPlayerPlot()
    if not plot then return 0 end
    local plants = plot:FindFirstChild("Plants")
    if not plants then return 0 end
    return #plants:GetChildren()
end

local function isBlockedPlantSpot(pos, minDist, plot)
    minDist = tonumber(minDist) or MIN_PLANT_DIST
    if not pos then return true end

    plot = plot or getPlayerPlot()
    if not plot then return false end

    local plants = plot:FindFirstChild("Plants")
    if not plants then return false end

    local minDist2 = minDist * minDist
    local px, pz = pos.X, pos.Z

    for _, plant in ipairs(plants:GetChildren()) do
        local gx, gz = _getPlantGroundXZ(plant)
        if gx and gz then
            local dx = gx - px
            local dz = gz - pz
            if (dx * dx + dz * dz) < minDist2 then
                return true
            end
        end
    end

    return false
end

local function raycastPlantArea(origin, direction, plot)
    local params, list = createPlantAreaParams(plot)
    if #list == 0 then return nil end

    local filter = params.FilterDescendantsInstances
    for _ = 1, 5 do
        local hit = workspace:Raycast(origin, direction, params)
        if not hit then return nil end
        if hit.Instance.Transparency < 1 then
            return hit
        end
        local idx = table.find(filter, hit.Instance)
        if not idx then return hit end
        table.remove(filter, idx)
        params.FilterDescendantsInstances = filter
        if #filter == 0 then return nil end
    end
    return nil
end

local function vecFromSaved(entry)
    if type(entry) ~= "table" then return nil end
    local x, y, z = tonumber(entry.x), tonumber(entry.y), tonumber(entry.z)
    if x and y and z then return Vector3.new(x, y, z) end
    return nil
end

local function _getStandingPlotPosition(plot)
    local char = LP.Character
    local hrp = char and char:FindFirstChild("HumanoidRootPart")
    if not hrp or not plot then return nil end

    local surfaces = collectPlotSurfaces(plot)
    if #surfaces == 0 then return nil end

    local params = RaycastParams.new()
    params.FilterType = Enum.RaycastFilterType.Include
    params.FilterDescendantsInstances = surfaces

    local hit = workspace:Raycast(hrp.Position + Vector3.new(0, 10, 0), Vector3.new(0, -40, 0), params)
    if hit and hit.Instance:IsDescendantOf(plot) then
        return hit.Position
    end

    for _, part in ipairs(surfaces) do
        if part:IsA("BasePart") then
            local lp = part.CFrame:PointToObjectSpace(hrp.Position)
            local halfX = part.Size.X * 0.55
            local halfZ = part.Size.Z * 0.55
            if math.abs(lp.X) <= halfX and math.abs(lp.Z) <= halfZ then
                return Vector3.new(
                    hrp.Position.X,
                    part.Position.Y + part.Size.Y * 0.5 + 0.05,
                    hrp.Position.Z
                )
            end
        end
    end

    return nil
end

local function seedMatchesTool(tool, selectedSeeds)
    if not tool or not tool:IsA("Tool") then return false end
    local seedAttr = tool:GetAttribute("SeedTool")
    if seedAttr == nil then return false end

    if not next(selectedSeeds) then
        return not _isMutationSeedTool(tool)
    end

    local toolKeys = {
        [_normSeedKey(seedAttr)] = true,
        [_normSeedKey(tool.Name)] = true,
        [_normSeedKey(tool:GetAttribute("SeedName"))] = true,
    }

    for sel, on in pairs(selectedSeeds) do
        if on == true and toolKeys[_normSeedKey(sel)] then
            return true
        end
    end
    return false
end

local function findAllSeedTools(selectedSeeds)
    local found = {}
    local seen = {}

    local function scan(container)
        if not container then return end
        for _, inst in ipairs(container:GetChildren()) do
            if inst:IsA("Tool") and seedMatchesTool(inst, selectedSeeds) and not _isSeedToolSkipped(inst) then
                local id = _seedToolId(inst)
                if id ~= "" and not seen[id] then
                    seen[id] = true
                    found[#found + 1] = inst
                end
            end
        end
    end

    for _, container in ipairs(_iterInventoryContainers()) do
        scan(container)
    end
    return found
end

local function _countSeedTools(selectedSeeds)
    return #findAllSeedTools(selectedSeeds)
end

local function _countInventorySeeds(selectedSeeds)
    local cached = G.__GAG2_PLANT_SEED_LIST_CACHE or rawget(_G, "__GAG2_PLANT_SEED_LIST_CACHE")
    if type(cached) == "table" and #cached > 0 then
        local plv = _getPlantListView()
        if plv and type(plv.countOwnedSeeds) == "function" then
            local ok, n = pcall(plv.countOwnedSeeds, plv, selectedSeeds)
            if ok and type(n) == "number" and n > 0 then
                return math.max(0, math.floor(n))
            end
        end
        local sum = 0
        for _, it in ipairs(cached) do
            sum += math.max(0, math.floor(tonumber(it.count) or tonumber(it.right) or 0))
        end
        if sum > 0 then return sum end
    end
    local plv = _getPlantListView()
    if plv and type(plv.countOwnedSeeds) == "function" then
        local ok, n = pcall(plv.countOwnedSeeds, plv, selectedSeeds)
        if ok and type(n) == "number" and n > 0 then
            return math.max(0, math.floor(n))
        end
    end
    return _countSeedTools(selectedSeeds)
end

local function _resetSessionSeedStats(st)
    st = st or getPlantState()
    sessionStartTotal = _countInventorySeeds(st.seeds)
    sessionPlanted = 0
    sessionUserLimit = math.max(0, math.floor(tonumber(st.plantTotal) or 0))
    _notifySeedStatsChanged()
end

local function _canPlantMore()
    if sessionUserLimit > 0 then
        return sessionPlanted < sessionUserLimit
    end
    return true
end

local function _isPlantSessionDone(st)
    st = st or getPlantState()
    if sessionUserLimit > 0 and sessionPlanted >= sessionUserLimit then
        return true, "limit"
    end
    if _countInventorySeeds(st.seeds) == 0 and _countSeedTools(st.seeds) == 0 then
        return true, "empty"
    end
    return false, nil
end

local function _autoStopPlantSession(st, reason)
    st = st or getPlantState()
    if not st.enabled then return end

    M.SetEnabled(false)
    _writeMainPlant({ enabled = false })

    local api = G.__GAG2_PLANT_ENABLE_API or rawget(_G, "__GAG2_PLANT_ENABLE_API")
    if type(api) == "table" and type(api.setOff) == "function" then
        pcall(api.setOff, true)
    end

    if type(G.__GAG2_SYNC_AUTO_PLANT) == "function" then
        pcall(G.__GAG2_SYNC_AUTO_PLANT)
    end

    if type(G.__GAG2_ON_PLANT_AUTO_FINISHED) == "function" then
        pcall(G.__GAG2_ON_PLANT_AUTO_FINISHED)
    end

    _notifySeedStatsChanged()
end

local function findSeedTool(selectedSeeds)
    local tools = findAllSeedTools(selectedSeeds)
    if #tools == 0 then return nil end
    seedToolRotate = (seedToolRotate % #tools) + 1
    return tools[seedToolRotate]
end

local function equipTool(tool)
    if not tool then return false end
    local char = LP.Character
    local hum = char and char:FindFirstChildOfClass("Humanoid")
    if not hum then return false end
    pcall(function() hum:EquipTool(tool) end)
    return tool.Parent == char
end

local function plantAtPosition(pos, tool)
    if not tool or not tool.Parent then return false, "no_tool" end
    if not _canPlantMore() then return false, "limit" end
    if os.clock() - lastPlantAt < PLANT_MIN_GAP then return false, "cooldown" end

    local seedId = tool:GetAttribute("SeedTool")
    if seedId == nil then return false, "no_seed_attr" end

    local ok, err = pcall(function()
        PlantSeed:Fire(pos, seedId, tool)
    end)
    if ok then
        lastPlantAt = os.clock()
        sessionPlanted += 1
        _notifySeedStatsChanged()
        _log("plant", seedId, pos)
        return true
    end
    return false, err
end

local function tryPlantAt(pos, st, opts)
    st = st or getPlantState()
    opts = type(opts) == "table" and opts or {}
    local plot = getPlayerPlot()
    if not plot then return false, "no_plot" end
    local minDist = tonumber(opts.minDist) or MIN_PLANT_DIST
    if isBlockedPlantSpot(pos, minDist, plot) then return false, "blocked" end

    local tools = findAllSeedTools(st.seeds)
    if #tools == 0 then return false, "no_seed_tool" end

    local lastErr = "plant_fail"
    for i = 1, #tools do
        local tool = tools[((seedToolRotate + i - 2) % #tools) + 1]
        equipTool(tool)
        local ok, err = plantAtPosition(pos, tool)
        if ok then
            seedToolRotate = ((seedToolRotate + i - 2) % #tools) + 1
            return true
        end
        lastErr = err or lastErr
        if _isAvatarBlockedError(err) then
            _markSeedToolSkipped(tool, 90)
            if os.clock() - randomWarnAt > 8 then
                randomWarnAt = os.clock()
                warn("[GAG2-AP] seed mutation butuh avatar khusus — pilih seed biasa (mis. Grape) atau equip avatar yang diminta")
            end
        else
            break
        end
    end
    return false, lastErr
end

local function _snapToPlantSurface(plot, pos)
    if not plot or not pos then return pos end
    local surfaces = collectPlotSurfaces(plot)
    if #surfaces == 0 then return pos end

    local params = RaycastParams.new()
    params.FilterType = Enum.RaycastFilterType.Include
    params.FilterDescendantsInstances = surfaces

    local hit = workspace:Raycast(
        pos + Vector3.new(0, 25, 0),
        Vector3.new(0, -50, 0),
        params
    )
    if hit and hit.Instance:IsDescendantOf(plot) then
        return hit.Position
    end
    return pos
end

local function randomPlantAreaPart(plot)
    local parts = {}
    for _, inst in ipairs(collectPlotSurfaces(plot)) do
        if inst:IsA("BasePart") then
            parts[#parts + 1] = inst
        end
    end
    if #parts == 0 then return nil end
    return parts[math.random(1, #parts)]
end

local function randomPointOnPart(part)
    local size = part.Size
    local cf = part.CFrame
    local margin = RANDOM_PART_MARGIN
    local rx = (math.random() - 0.5) * size.X * margin
    local rz = (math.random() - 0.5) * size.Z * margin
    return (cf * CFrame.new(rx, size.Y * 0.5, rz)).Position
end

local function tryRandomPlant(st)
    local plot = getPlayerPlot()
    if not plot then
        if os.clock() - randomWarnAt > 8 then
            randomWarnAt = os.clock()
            warn("[GAG2-AP] plot tidak ditemukan (PlotId?)")
        end
        return false
    end

    if next(st.seeds) and _countSeedTools(st.seeds) == 0 then
        return false
    end

    local surfaces = collectPlotSurfaces(plot)
    if #surfaces == 0 then
        if os.clock() - randomWarnAt > 8 then
            randomWarnAt = os.clock()
            warn("[GAG2-AP] area tanam tidak ditemukan di plot")
        end
        return false
    end

    for _ = 1, RANDOM_MAX_TRY do
        local part = randomPlantAreaPart(plot)
        if part then
            local pos = randomPointOnPart(part)
            pos = _snapToPlantSurface(plot, pos)
            local ok = tryPlantAt(pos, st, { minDist = RANDOM_MIN_PLANT_DIST })
            if ok then return true end
        end
    end

    if os.clock() - randomWarnAt > 8 then
        randomWarnAt = os.clock()
        local nPlants = _countPlantsOnPlot(plot)
        warn(("[GAG2-AP] tidak ada spot kosong (%d tanaman di plot, jarak min %.2f)"):format(
            nPlants, RANDOM_MIN_PLANT_DIST))
    end
    return false
end

local function _resetManualGrid()
    manualGridSlot = 1
end

-- Spiral dengan jarak antar slot ~MANUAL_SLOT_SPACING (skip titik yang sudah ada tanaman)
local function _offsetForGridSlot(slot)
    if slot <= 1 then
        return Vector3.zero
    end
    local idx = slot - 2
    local golden = 2.399963229728653
    local r = MANUAL_SLOT_SPACING * math.sqrt(idx + 1)
    local angle = idx * golden
    return Vector3.new(math.cos(angle) * r, 0, math.sin(angle) * r)
end

local function _isManualGridExhausted()
    return manualGridSlot > MANUAL_GRID_MAX
end

local function _tryPlantGridAt(center, st)
    if not center then return false end

    local plot = getPlayerPlot()
    if not plot then return false end

    local tried = 0
    while manualGridSlot <= MANUAL_GRID_MAX and tried < MANUAL_MAX_TRY_PER_TICK do
        tried += 1
        local slot = manualGridSlot
        local pos = _snapToPlantSurface(plot, center + _offsetForGridSlot(slot))

        if isBlockedPlantSpot(pos, nil, plot) then
            manualGridSlot = slot + 1
        else
            local ok = tryPlantAt(pos, st)
            if ok then
                manualGridSlot = slot + 1
                return true
            end
            manualGridSlot = slot + 1
        end
    end

    return false
end

local function _resolveManualAnchor(st)
    local positions = st.positions
    if type(positions) ~= "table" or #positions == 0 then return nil end

    if st.autoManual then
        return vecFromSaved(positions[manualPosIndex])
    end

    if st.selectedPosition then
        for _, entry in ipairs(positions) do
            if tostring(entry.id) == tostring(st.selectedPosition) then
                return vecFromSaved(entry)
            end
        end
    end

    return vecFromSaved(positions[1])
end

local manualWarnAt = 0

local function tryManualPlant(st)
    st = st or getPlantState()
    local positions = st.positions
    if type(positions) ~= "table" or #positions == 0 then
        if os.clock() - manualWarnAt > 5 then
            manualWarnAt = os.clock()
            warn("[GAG2] Manual plant: simpan posisi dulu (berdiri di tile → Save Position ON)")
        end
        return false
    end

    if next(st.seeds) and _countSeedTools(st.seeds) == 0 then
        return false
    end

    local plot = getPlayerPlot()
    if not plot then return false end

    local anchor = _resolveManualAnchor(st)
    if not anchor then return false end

    if st.autoManual then
        if _isManualGridExhausted() then
            _resetManualGrid()
            manualPosIndex += 1
            if manualPosIndex > #positions then manualPosIndex = 1 end
            anchor = _resolveManualAnchor(st)
            if not anchor then return false end
        end
        return _tryPlantGridAt(anchor, st)
    end

    return _tryPlantGridAt(anchor, st)
end

local function plantTick(st)
    if not _canPlantMore() then return false end
    st = st or getPlantState()
    if st.mode == "manual" then
        return tryManualPlant(st)
    end
    return tryRandomPlant(st)
end

local function mainLoop(myId)
    _log("loop start", myId)
    while running and loopId == myId do
        local st = getPlantState()
        if st.enabled then
            local done, reason = _isPlantSessionDone(st)
            if done then
                _autoStopPlantSession(st, reason)
            else
                plantTick(st)
                local doneAfter, reasonAfter = _isPlantSessionDone(st)
                if doneAfter then
                    _autoStopPlantSession(st, reasonAfter)
                else
                    _notifySeedStatsChanged()
                end
            end
        end
        task.wait(st.delay)
    end
    _log("loop end", myId)
end

----------------------------------------------------------------
-- save position (klik di PlantArea plot sendiri)
----------------------------------------------------------------
local _bindSaveListener
local _disableSaveMode

local function _isMouseOverBlockingUI()
    local ui = G.__GROWAGARDEN2_UI
    if not ui then return false end

    local loc = UserInputService:GetMouseLocation()
    local inset = GuiService:GetGuiInset()
    local x, y = loc.X, loc.Y - inset.Y

    local function hitsRoot(root)
        if not root or not root.Parent then return false end
        for _, obj in ipairs(GuiService:GetGuiObjectsAtPosition(x, y)) do
            if obj == root or obj:IsDescendantOf(root) then
                return true
            end
        end
        return false
    end

    if hitsRoot(ui.mainFrame) then return true end

    local sg = ui._sg
    if sg then
        for _, desc in ipairs(sg:GetDescendants()) do
            if desc.Name == "NodeHubDropdownOverlay" or desc.Name == "NodeHubModeOverlay" then
                if hitsRoot(desc) then return true end
            end
        end
    end

    return false
end

local function _isTargetOnPlot(target, plot)
    if not target or not plot then return false end
    return target:IsDescendantOf(plot)
end

local function _resolveSaveHit(plot, preferStanding)
    if preferStanding then
        local stand = _getStandingPlotPosition(plot)
        if stand then return stand end
    end

    local cam = workspace.CurrentCamera
    if cam then
        local loc = UserInputService:GetMouseLocation()
        local ray = cam:ViewportPointToRay(loc.X, loc.Y)
        local hit = raycastPlantArea(ray.Origin, ray.Direction * 5000, plot)
        if hit and _isTargetOnPlot(hit.Instance, plot) then
            return hit.Position
        end
    end

    local mouse = LP:GetMouse()
    if mouse and mouse.Target and mouse.Hit and _isTargetOnPlot(mouse.Target, plot) then
        return mouse.Hit.Position
    end

    if not preferStanding then
        return _getStandingPlotPosition(plot)
    end

    return nil
end

local function _commitSavePosition(pos)
    if not pos then return false end

    local MAIN = rawget(_G, "MAIN") or G.MAIN
    if type(MAIN) ~= "table" then return false end

    MAIN.auto = MAIN.auto or {}
    MAIN.auto.plant = MAIN.auto.plant or {}
    local positions = type(MAIN.auto.plant.positions) == "table" and MAIN.auto.plant.positions or {}

    local id = ("pos_%d"):format(math.floor(os.clock() * 1000))
    positions[#positions + 1] = {
        id = id,
        x = pos.X,
        y = pos.Y,
        z = pos.Z,
    }
    MAIN.auto.plant.positions = positions
    MAIN.auto.plant.selectedPosition = id
    G.MAIN = MAIN
    _G.MAIN = MAIN

    G.AUTO_PLANT_SELECTED_POSITION = id
    _G.AUTO_PLANT_SELECTED_POSITION = id

    _notifyPositionsChanged()
    _resetManualGrid()
    print(("[GAG2] Posisi tanam tersimpan (#%d)"):format(#positions))
    _log("saved pos", id, pos)

    _disableSaveMode()
    return true
end

_disableSaveMode = function()
    saveModeActive = false
    G.AUTO_PLANT_SAVE_POSITION = false
    _G.AUTO_PLANT_SAVE_POSITION = false
    _writeMainPlant({ savePosition = false })
    saveEnableAt = 0

    if type(G.__GAG2_ON_PLANT_SAVE_MODE_CHANGED) == "function" then
        pcall(G.__GAG2_ON_PLANT_SAVE_MODE_CHANGED, false)
    end

    local api = G.__GAG2_PLANT_SAVE_TOGGLE_API
    if type(api) == "table" and type(api.setOff) == "function" then
        pcall(api.setOff, true)
    end
end

local function trySavePositionFromMouse(force)
    if not saveModeActive and not getPlantState().savePosition then return false end
    if not force and os.clock() < saveEnableAt then return false end
    if not force and os.clock() - lastClickAt < 0.15 then return false end
    lastClickAt = os.clock()

    local plot = getPlayerPlot()
    if not plot then
        warn("[GAG2] Save gagal: plot tidak ditemukan")
        return false
    end

    local pos = _resolveSaveHit(plot, force == true)
    if not pos then
        if not force and _isMouseOverBlockingUI() then
            return false
        end
        warn("[GAG2] Save gagal: berdiri di tile plot, lalu tekan Save Position")
        return false
    end

    return _commitSavePosition(pos)
end

_bindSaveListener = function()
    if saveInputConn then return end

    saveInputConn = UserInputService.InputEnded:Connect(function(input)
        if input.UserInputType ~= Enum.UserInputType.MouseButton1
            and input.UserInputType ~= Enum.UserInputType.Touch then
            return
        end
        task.defer(trySavePositionFromMouse)
    end)

    UserInputService.InputBegan:Connect(function(input)
        if input.UserInputType ~= Enum.UserInputType.MouseButton1
            and input.UserInputType ~= Enum.UserInputType.Touch then
            return
        end
        task.delay(0.05, trySavePositionFromMouse)
    end)
end

local function _scheduleSaveListener()
    saveEnableAt = os.clock() + 0.15
    _bindSaveListener()
end

----------------------------------------------------------------
-- public API
----------------------------------------------------------------
function M.SetEnabled(on)
    on = (on == true)
    local wasRunning = running

    G.AUTO_PLANT_ENABLED = on
    _G.AUTO_PLANT_ENABLED = on
    _writeMainPlant({ enabled = on })

    if on then
        if not wasRunning then
            _resetSessionSeedStats()
        end
        if not running then
            running = true
            loopId += 1
            local myId = loopId
            task.spawn(function() mainLoop(myId) end)
        end
    else
        running = false
        _notifySeedStatsChanged()
    end
end

M.setEnabled = M.SetEnabled
function M.Start() return M.SetEnabled(true) end
M.start = M.Start
function M.Stop() return M.SetEnabled(false) end
M.stop = M.Stop

function M.SetSavePosition(on)
    on = (on == true)
    if not on then
        saveModeActive = false
        G.AUTO_PLANT_SAVE_POSITION = false
        _G.AUTO_PLANT_SAVE_POSITION = false
        _writeMainPlant({ savePosition = false })
        saveEnableAt = 0
        return
    end

    saveModeActive = true
    G.AUTO_PLANT_SAVE_POSITION = true
    _G.AUTO_PLANT_SAVE_POSITION = true
    _writeMainPlant({ savePosition = true })

    local ui = G.__GROWAGARDEN2_UI
    if ui and type(ui.CloseDropdownOverlays) == "function" then
        pcall(ui.CloseDropdownOverlays, ui)
    end

    task.defer(function()
        M.SaveStandingPosition()
    end)
end

M.setSavePosition = M.SetSavePosition

function M.SetAutoManual(on)
    on = (on == true)
    G.AUTO_PLANT_AUTO_MANUAL = on
    _G.AUTO_PLANT_AUTO_MANUAL = on
    _writeMainPlant({ autoManual = on })
end

M.setAutoManual = M.SetAutoManual

function M.SetPlantTotal(a, b)
    local n = tonumber(b)
    if n == nil then n = tonumber(a) end
    if n == nil then return end
    if n < 0 then n = 0 end
    n = math.floor(n)
    G.AUTO_PLANT_TOTAL = n
    _G.AUTO_PLANT_TOTAL = n
    sessionUserLimit = n
    if not running then
        sessionPlanted = 0
    end
    _writeMainPlant({ plantTotal = n })
    _notifySeedStatsChanged()
end

M.setPlantTotal = M.SetPlantTotal

function M.SetMode(mode)
    mode = tostring(mode or "random"):lower()
    if mode ~= "manual" then mode = "random" end
    G.AUTO_PLANT_MODE = mode
    _G.AUTO_PLANT_MODE = mode
    _writeMainPlant({ mode = mode })
end

M.setMode = M.SetMode

function M.SetSelectedPosition(id)
    id = _normalizePositionId(id)
    G.AUTO_PLANT_SELECTED_POSITION = id
    _G.AUTO_PLANT_SELECTED_POSITION = id
    _writeMainPlant({ selectedPosition = id })
    _resetManualGrid()
end

M.setSelectedPosition = M.SetSelectedPosition

function M.SyncFromState()
    local st = getPlantState()
    saveModeActive = false
    if st.savePosition then
        G.AUTO_PLANT_SAVE_POSITION = false
        _G.AUTO_PLANT_SAVE_POSITION = false
        _writeMainPlant({ savePosition = false })
    end
    M.SetEnabled(st.enabled)
end

M.syncFromState = M.SyncFromState

function M.GetPlayerPlot()
    return getPlayerPlot()
end

M.getPlayerPlot = M.GetPlayerPlot

function M.GetState()
    return getPlantState()
end

M.getState = M.GetState

function M.CountSeedTools(selectedSeeds)
    if selectedSeeds == nil then
        return _countInventorySeeds(getPlantState().seeds)
    end
    if type(selectedSeeds) == "table" then
        return _countInventorySeeds(_normalizeSet(selectedSeeds))
    end
    return 0
end

M.countSeedTools = M.CountSeedTools

function M.CountEquippedSeedTools(selectedSeeds)
    if selectedSeeds == nil then
        return _countSeedTools(getPlantState().seeds)
    end
    if type(selectedSeeds) == "table" then
        return _countSeedTools(_normalizeSet(selectedSeeds))
    end
    return 0
end

M.countEquippedSeedTools = M.CountEquippedSeedTools

function M.BuildOwnedSeedItems()
    local cached = G.__GAG2_PLANT_SEED_LIST_CACHE or rawget(_G, "__GAG2_PLANT_SEED_LIST_CACHE")
    if type(cached) == "table" and #cached > 0 then
        return cached
    end
    local plv = _getPlantListView()
    if plv and type(plv.buildPlantSeedItems) == "function" then
        local ok, items = pcall(plv.buildPlantSeedItems, plv)
        if ok and type(items) == "table" and #items > 0 then return items end
    end
    return {}
end

M.buildOwnedSeedItems = M.BuildOwnedSeedItems

function M.GetSeedStats()
    local ok, stats = pcall(function()
        local st = getPlantState()
        local totalInventory = _countInventorySeeds({})
        local remaining = totalInventory
        if next(st.seeds) then
            remaining = _countInventorySeeds(st.seeds)
        end
        local startTotal = sessionStartTotal
        if startTotal <= 0 then
            startTotal = next(st.seeds) and remaining or totalInventory
        end
        local target = sessionUserLimit
        if target <= 0 then
            target = startTotal
        end
        return {
            remaining = remaining,
            totalInventory = totalInventory,
            startTotal = startTotal,
            planted = sessionPlanted,
            total = startTotal,
            plantTotal = sessionUserLimit,
            target = target,
            equippedTools = _countSeedTools(st.seeds),
        }
    end)
    if ok and type(stats) == "table" then
        return stats
    end
    return {
        remaining = 0,
        totalInventory = 0,
        startTotal = 0,
        planted = sessionPlanted,
        total = 0,
        plantTotal = sessionUserLimit,
        target = 0,
        equippedTools = 0,
    }
end

M.getSeedStats = M.GetSeedStats

function M.SaveStandingPosition()
    saveModeActive = true
    G.AUTO_PLANT_SAVE_POSITION = true
    _G.AUTO_PLANT_SAVE_POSITION = true
    saveEnableAt = 0

    local plot = getPlayerPlot()
    if not plot then
        warn("[GAG2] Save gagal: plot tidak ditemukan")
        _disableSaveMode()
        return false
    end

    local pos = _getStandingPlotPosition(plot)
    if not pos then
        warn("[GAG2] Save gagal: berdiri di tile plot dulu, lalu tekan Save Position")
        _disableSaveMode()
        return false
    end

    return _commitSavePosition(pos)
end

M.saveStandingPosition = M.SaveStandingPosition

function M.SavePositionNow()
    saveModeActive = true
    saveEnableAt = 0
    return trySavePositionFromMouse(true) == true
end

M.savePositionNow = M.SavePositionNow

function M.DeletePosition(id)
    id = tostring(id or "")
    if id == "" then return false end

    local MAIN = rawget(_G, "MAIN") or G.MAIN
    if type(MAIN) ~= "table" then return false end

    MAIN.auto = MAIN.auto or {}
    MAIN.auto.plant = MAIN.auto.plant or {}
    local positions = type(MAIN.auto.plant.positions) == "table" and MAIN.auto.plant.positions or {}

    local removed = false
    for i = #positions, 1, -1 do
        local entry = positions[i]
        if type(entry) == "table" and tostring(entry.id) == id then
            table.remove(positions, i)
            removed = true
        end
    end
    if not removed then return false end

    MAIN.auto.plant.positions = positions
    if tostring(MAIN.auto.plant.selectedPosition) == id then
        local nextId = positions[1] and positions[1].id or nil
        MAIN.auto.plant.selectedPosition = nextId and tostring(nextId) or nil
        G.AUTO_PLANT_SELECTED_POSITION = MAIN.auto.plant.selectedPosition
        _G.AUTO_PLANT_SELECTED_POSITION = MAIN.auto.plant.selectedPosition
    end

    if manualPosIndex > #positions then
        manualPosIndex = math.max(1, #positions)
    end
    _resetManualGrid()

    G.MAIN = MAIN
    _G.MAIN = MAIN
    _notifyPositionsChanged()
    return true
end

M.deletePosition = M.DeletePosition

----------------------------------------------------------------
G.AutoPlant = M
G.AutoPlantModule = M
_G.AutoPlant = M
_G.AutoPlantModule = M

_bindSaveListener()

return M
 end,                      required = false },
    { key = "AutoTrowel",              name = "Auto Trowel",             factory = function() -- AutoTrowel.lua — Grow A Garden 2
-- Move plant: Networking.Trowel.MovePlant:Fire(plantName, position, rotationDeg)

local Players           = game:GetService("Players")
local ReplicatedStorage = game:GetService("ReplicatedStorage")
local UserInputService  = game:GetService("UserInputService")

local LP = Players.LocalPlayer
local G  = (getgenv and getgenv()) or _G
local M  = {}

local Networking = require(ReplicatedStorage.SharedModules.Networking)
local MovePlant  = Networking.Trowel and Networking.Trowel.MovePlant

local Gardens = workspace:WaitForChild("Gardens")

local LOOP_MIN_SEC      = 0.5
local MOVE_COOLDOWN     = 0.35
local PLOT_CACHE_SEC    = 2
local POSITION_RADIUS   = 3

local running           = false
local loopId            = 0
local lastMoveAt        = 0
local cachedPlot        = nil
local cachedPlotAt      = 0
local saveInputConn     = nil
local saveModeActive    = false
local saveEnableAt      = 0
local lastClickAt       = 0
local sessionMovedCount     = 0
local lastSessionMovedCount = 0
local stallCount            = 0
local lastFinishReason      = nil

local EQUIP_WAIT        = 0.6
local MOVE_VERIFY_WAIT  = 0.45
local STALL_LIMIT       = 12

local function _dbg()
    return G.AUTO_TROWEL_DEBUG == true or _G.AUTO_TROWEL_DEBUG == true
end

local function _log(...)
    if not _dbg() then return end
    print("[GAG2-ATrw]", ...)
end

local function _normalizePositionId(v)
    if v == nil then return nil end
    if type(v) == "table" then v = v.id or v.key end
    v = tostring(v)
    if v == "" or v:sub(1, 6) == "table:" then return nil end
    return v
end

local function _writeMain(patch)
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    if type(MAIN) ~= "table" then return end
    MAIN.auto = MAIN.auto or {}
    MAIN.auto.trowel = MAIN.auto.trowel or {}
    for k, v in pairs(patch) do
        if k ~= "enabled" then
            MAIN.auto.trowel[k] = v
        end
    end
    MAIN.auto.trowel.enabled = false
    G.MAIN = MAIN
    _G.MAIN = MAIN
end

local function _notifyPositionsChanged()
    if type(G.__GAG2_ON_TROWEL_POSITIONS_CHANGED) == "function" then
        pcall(G.__GAG2_ON_TROWEL_POSITIONS_CHANGED)
    end
end

local function _notifyStatsChanged()
    if type(G.__GAG2_ON_TROWEL_STATS_CHANGED) == "function" then
        pcall(G.__GAG2_ON_TROWEL_STATS_CHANGED)
    end
end

local function _finishRun(reason)
    lastFinishReason = reason
    lastSessionMovedCount = sessionMovedCount
    sessionMovedCount = 0
    stallCount = 0
    running = false
    G.AUTO_TROWEL_ENABLED = false
    _G.AUTO_TROWEL_ENABLED = false
    _writeMain({ enabled = false })
    _disableSaveMode()

    local api = G.__GAG2_TROWEL_ENABLE_API or rawget(_G, "__GAG2_TROWEL_ENABLE_API")
    if type(api) == "table" and type(api.setOff) == "function" then
        pcall(api.setOff, true)
    elseif type(api) == "table" and type(api.set) == "function" then
        pcall(api.set, false, true)
    end

    if type(G.__GAG2_ON_TROWEL_AUTO_FINISHED) == "function" then
        pcall(G.__GAG2_ON_TROWEL_AUTO_FINISHED, reason)
    end

    _notifyStatsChanged()
end

----------------------------------------------------------------
-- Plant type key (same idea as Auto Shovel)
----------------------------------------------------------------
local function _mutationNamesFallback()
    local PLV = G.PlantListView or rawget(_G, "PlantListView")
    if type(PLV) == "table" and type(PLV.listMutationNames) == "function" then
        local ok, list = pcall(PLV.listMutationNames, PLV)
        if ok and type(list) == "table" and #list > 0 then return list end
    end
    return { "Gold", "Rainbow" }
end

function M.GetPlantDisplayName(plant)
    if not plant then return "Unknown" end
    local name = plant:GetAttribute("SeedName")
        or plant:GetAttribute("ConfigPathName")
        or plant:GetAttribute("CorePartName")
        or plant:GetAttribute("FruitType")
        or plant:GetAttribute("ItemName")
        or plant.Name
    name = tostring(name or ""):gsub("^%s+", ""):gsub("%s+$", "")
    if name == "" then name = plant.Name or "Unknown" end
    return name
end

function M.GetPlantMutation(plant)
    if not plant then return nil end
    local mut = plant:GetAttribute("Mutation")
    if type(mut) == "string" then
        mut = mut:gsub("^%s+", ""):gsub("%s+$", "")
        if mut ~= "" and mut:lower() ~= "none" and mut:lower() ~= "normal" then
            return mut
        end
    end
    for _, name in ipairs(_mutationNamesFallback()) do
        if plant:GetAttribute(name) == true then
            return name
        end
    end
    return nil
end

function M.GetPlantTypeKey(plant)
    local name = M.GetPlantDisplayName(plant)
    local mut = M.GetPlantMutation(plant)
    if mut then
        return mut .. " " .. name
    end
    return name
end

local function _plantMatchesTypeKey(plant, typeKey)
    if not plant or not typeKey or typeKey == "" then return false end
    if M.GetPlantTypeKey(plant) == typeKey then return true end
    if tostring(plant.Name) == typeKey then return true end
    return false
end

local function getTrowelState()
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    local st = MAIN and MAIN.auto and MAIN.auto.trowel
    st = type(st) == "table" and st or {}

    local delay = tonumber(st.delay)
    if delay == nil then
        delay = tonumber(G.AUTO_TROWEL_DELAY or rawget(_G, "AUTO_TROWEL_DELAY")) or 1
    end
    if delay < LOOP_MIN_SEC then delay = LOOP_MIN_SEC end

    local positions = type(st.positions) == "table" and st.positions or {}
    local selectedPosition = _normalizePositionId(st.selectedPosition)
    if selectedPosition == nil then
        selectedPosition = _normalizePositionId(G.AUTO_TROWEL_SELECTED_POSITION)
    end

    local selectedPlant = st.selectedPlant
    if selectedPlant == nil or selectedPlant == "" then
        selectedPlant = G.AUTO_TROWEL_SELECTED_PLANT or rawget(_G, "AUTO_TROWEL_SELECTED_PLANT")
    end
    if type(selectedPlant) == "table" then
        selectedPlant = selectedPlant.key or selectedPlant.name or selectedPlant.id
    end
    if selectedPlant ~= nil then selectedPlant = tostring(selectedPlant) end
    if selectedPlant == ""
        or selectedPlant == "_none"
        or (selectedPlant and selectedPlant:sub(1, 6) == "table:") then
        selectedPlant = nil
    end

    local moveTotal = tonumber(st.moveTotal)
    if moveTotal == nil then
        moveTotal = tonumber(G.AUTO_TROWEL_MOVE_TOTAL or rawget(_G, "AUTO_TROWEL_MOVE_TOTAL")) or 0
    end
    if moveTotal < 0 then moveTotal = 0 end
    moveTotal = math.floor(moveTotal)

    local rotation = tonumber(st.rotation)
    if rotation == nil then
        rotation = tonumber(G.AUTO_TROWEL_ROTATION or rawget(_G, "AUTO_TROWEL_ROTATION")) or 0
    end
    rotation = rotation % 360

    local enabled = (G.AUTO_TROWEL_ENABLED == true)
        or (rawget(_G, "AUTO_TROWEL_ENABLED") == true)

    local savePosition = (G.AUTO_TROWEL_SAVE_POSITION == true)
        or (rawget(_G, "AUTO_TROWEL_SAVE_POSITION") == true)
        or (st.savePosition == true)

    return {
        enabled          = enabled,
        selectedPlant    = selectedPlant,
        positions        = positions,
        selectedPosition = selectedPosition,
        savePosition     = savePosition,
        delay            = delay,
        rotation         = rotation,
        moveTotal        = moveTotal,
    }
end

local function _plotOwnedByLocal(plot)
    if not plot then return false end
    local uid, name = LP.UserId, LP.Name
    local function match(v)
        if v == nil then return false end
        return v == uid or v == name or tostring(v) == tostring(uid) or tostring(v) == name
    end
    if match(plot:GetAttribute("OwnerId")) then return true end
    if match(plot:GetAttribute("Owner")) then return true end
    if match(plot:GetAttribute("OwnerUserId")) then return true end
    if match(plot:GetAttribute("UserId")) then return true end
    return false
end

local function getPlayerPlot()
    local now = os.clock()
    if cachedPlot and cachedPlot.Parent and (now - cachedPlotAt) <= PLOT_CACHE_SEC then
        return cachedPlot
    end
    if not Gardens or not Gardens.Parent then
        cachedPlot = nil
        cachedPlotAt = now
        return nil
    end
    local plotId = LP:GetAttribute("PlotId")
    if plotId ~= nil then
        local plot = Gardens:FindFirstChild("Plot" .. tostring(plotId))
        if plot then
            cachedPlot = plot
            cachedPlotAt = now
            return plot
        end
    end
    for _, plot in ipairs(Gardens:GetChildren()) do
        if _plotOwnedByLocal(plot) then
            cachedPlot = plot
            cachedPlotAt = now
            return plot
        end
    end
    cachedPlot = nil
    cachedPlotAt = now
    return nil
end

local function getPlantsFolder(plot)
    plot = plot or getPlayerPlot()
    return plot and plot:FindFirstChild("Plants") or nil
end

local function vecFromSaved(entry)
    if type(entry) ~= "table" then return nil end
    local x, y, z = tonumber(entry.x), tonumber(entry.y), tonumber(entry.z)
    if x and y and z then return Vector3.new(x, y, z) end
    return nil
end

local function resolveTargetPosition(st)
    st = st or getTrowelState()
    local positions = st.positions
    if type(positions) ~= "table" or #positions == 0 then return nil end
    if st.selectedPosition then
        for _, entry in ipairs(positions) do
            if type(entry) == "table" and tostring(entry.id) == tostring(st.selectedPosition) then
                return vecFromSaved(entry)
            end
        end
    end
    return vecFromSaved(positions[1])
end

local function getPlantPivot(plant)
    if not plant then return nil end
    local ok, pivot = pcall(function() return plant:GetPivot() end)
    if ok and typeof(pivot) == "CFrame" then
        return pivot.Position
    end
    local pp = plant.PrimaryPart or plant:FindFirstChildWhichIsA("BasePart", true)
    return pp and pp.Position or nil
end

local function horizontalDistance(a, b)
    local dx = a.X - b.X
    local dz = a.Z - b.Z
    return math.sqrt(dx * dx + dz * dz)
end

function M.BuildGardenPlantItems()
    local AS = G.AutoShovel or G.AutoShovelModule
    if type(AS) == "table" and type(AS.BuildGardenPlantItems) == "function" then
        local ok, items = pcall(AS.BuildGardenPlantItems, AS)
        if ok and type(items) == "table" then return items end
    end

    local items = {}
    local folder = getPlantsFolder()
    if not folder then
        return { { key = "_none", name = "(No plants in garden)" } }
    end

    local groups = {}
    for _, plant in ipairs(folder:GetChildren()) do
        if plant:IsA("Model") then
            local typeKey = M.GetPlantTypeKey(plant)
            local g = groups[typeKey]
            if not g then
                g = { key = typeKey, name = typeKey, count = 0 }
                groups[typeKey] = g
            end
            g.count = g.count + 1
        end
    end

    for _, g in pairs(groups) do
        items[#items + 1] = {
            key = g.key,
            name = string.format("%s x %d", g.name, g.count),
            count = g.count,
        }
    end

    table.sort(items, function(a, b)
        return tostring(a.name) < tostring(b.name)
    end)

    if #items == 0 then
        items[1] = { key = "_none", name = "(No plants in garden)" }
    end
    return items
end

M.buildGardenPlantItems = M.BuildGardenPlantItems

function M.CountOutsideRadius(typeKey, targetPos, radius)
    radius = tonumber(radius) or POSITION_RADIUS
    local folder = getPlantsFolder()
    if not folder or not typeKey or not targetPos then return 0 end
    local n = 0
    for _, plant in ipairs(folder:GetChildren()) do
        if plant:IsA("Model") and _plantMatchesTypeKey(plant, typeKey) then
            local pos = getPlantPivot(plant)
            if pos and horizontalDistance(pos, targetPos) > radius then
                n += 1
            end
        end
    end
    return n
end

function M.GetSessionMovedCount()
    if running then return sessionMovedCount end
    return lastSessionMovedCount
end

function M.IsRunning()
    return running
end

local function scanMoveCandidates(st, targetPos)
    local folder = getPlantsFolder()
    if not folder or not st.selectedPlant or not targetPos then return {} end

    local out = {}
    for _, plant in ipairs(folder:GetChildren()) do
        if plant:IsA("Model") and _plantMatchesTypeKey(plant, st.selectedPlant) then
            local pos = getPlantPivot(plant)
            if pos and horizontalDistance(pos, targetPos) > POSITION_RADIUS then
                out[#out + 1] = {
                    plant = plant,
                    fireName = tostring(plant.Name),
                    dist = horizontalDistance(pos, targetPos),
                }
            end
        end
    end

    table.sort(out, function(a, b)
        return a.dist > b.dist
    end)
    return out
end

local function _isTrowelTool(tool)
    if not tool or not tool:IsA("Tool") then return false end
    if tool:GetAttribute("Trowel") then return true end
    if tool:GetAttribute("Shovel") then return false end
    return tool.Name:lower():find("trowel", 1, true) ~= nil
end

local function _getEquippedTrowel()
    local char = LP and LP.Character
    if not char then return nil end
    for _, ch in ipairs(char:GetChildren()) do
        if ch:IsA("Tool") and _isTrowelTool(ch) then
            return ch
        end
    end
    return nil
end

local function _findTrowelTool()
    local equipped = _getEquippedTrowel()
    if equipped then return equipped end

    local bp = LP and LP:FindFirstChild("Backpack")
    if not bp then return nil end
    for _, tool in ipairs(bp:GetChildren()) do
        if _isTrowelTool(tool) then
            return tool
        end
    end
    return nil
end

local function _equipTrowel()
    if _getEquippedTrowel() then return true end

    local tool = _findTrowelTool()
    if not tool then return false end

    local char = LP and LP.Character
    local hum = char and char:FindFirstChildOfClass("Humanoid")
    if not hum then return false end

    pcall(function() hum:EquipTool(tool) end)

    local deadline = os.clock() + EQUIP_WAIT
    while os.clock() < deadline do
        if _getEquippedTrowel() then return true end
        task.wait(0.03)
    end
    return _getEquippedTrowel() ~= nil
end

local function _plantNearTarget(plant, targetPos)
    local pos = getPlantPivot(plant)
    return pos and horizontalDistance(pos, targetPos) <= POSITION_RADIUS
end

local function _moveSucceeded(plant, targetPos, beforePos)
    if not plant or not plant.Parent then return true end
    if _plantNearTarget(plant, targetPos) then return true end
    if not beforePos then return false end
    local afterPos = getPlantPivot(plant)
    if not afterPos then return false end
    return horizontalDistance(afterPos, targetPos) < horizontalDistance(beforePos, targetPos) - 0.5
end

local function _getStandingPlotPosition(plot)
    local char = LP.Character
    local hrp = char and char:FindFirstChild("HumanoidRootPart")
    if not hrp or not plot then return nil end
    if not plot:IsDescendantOf(workspace) then return nil end
    local pos = hrp.Position
    local ref = plot:FindFirstChild("PlotSizeReference")
    if ref and ref:IsA("BasePart") then
        local localPos = ref.CFrame:PointToObjectSpace(pos)
        local half = ref.Size / 2
        if math.abs(localPos.X) <= half.X and math.abs(localPos.Z) <= half.Z then
            return Vector3.new(pos.X, hrp.Position.Y - 2.5, pos.Z)
        end
    end
    return Vector3.new(pos.X, hrp.Position.Y - 2.5, pos.Z)
end

local function _disableSaveMode()
    saveModeActive = false
    G.AUTO_TROWEL_SAVE_POSITION = false
    _G.AUTO_TROWEL_SAVE_POSITION = false
    _writeMain({ savePosition = false })
    saveEnableAt = 0
    if type(G.__GAG2_ON_TROWEL_SAVE_MODE_CHANGED) == "function" then
        pcall(G.__GAG2_ON_TROWEL_SAVE_MODE_CHANGED, false)
    end
    local api = G.__GAG2_TROWEL_SAVE_TOGGLE_API
    if type(api) == "table" and type(api.setOff) == "function" then
        pcall(api.setOff, true)
    end
end

local function _commitSavePosition(pos)
    if not pos then return false end
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    if type(MAIN) ~= "table" then return false end

    MAIN.auto = MAIN.auto or {}
    MAIN.auto.trowel = MAIN.auto.trowel or {}
    local positions = type(MAIN.auto.trowel.positions) == "table" and MAIN.auto.trowel.positions or {}

    local id = ("tpos_%d"):format(math.floor(os.clock() * 1000))
    positions[#positions + 1] = {
        id = id,
        x = pos.X,
        y = pos.Y,
        z = pos.Z,
    }
    MAIN.auto.trowel.positions = positions
    MAIN.auto.trowel.selectedPosition = id
    G.MAIN = MAIN
    _G.MAIN = MAIN

    G.AUTO_TROWEL_SELECTED_POSITION = id
    _G.AUTO_TROWEL_SELECTED_POSITION = id

    _notifyPositionsChanged()
    print(("[GAG2] Trowel position saved (#%d)"):format(#positions))
    _disableSaveMode()
    return true
end

local function trySavePositionFromStanding()
    if not saveModeActive and not getTrowelState().savePosition then return false end
    if os.clock() < saveEnableAt then return false end
    if os.clock() - lastClickAt < 0.15 then return false end
    lastClickAt = os.clock()

    local plot = getPlayerPlot()
    if not plot then
        warn("[GAG2] Save trowel failed: plot not found")
        return false
    end
    local pos = _getStandingPlotPosition(plot)
    if not pos then
        warn("[GAG2] Save trowel failed: stand on plot tile first")
        return false
    end
    return _commitSavePosition(pos)
end

local function _bindSaveListener()
    if saveInputConn then return end
    saveInputConn = UserInputService.InputEnded:Connect(function(input)
        if not saveModeActive then return end
        if input.UserInputType ~= Enum.UserInputType.MouseButton1
            and input.UserInputType ~= Enum.UserInputType.Touch then
            return
        end
        trySavePositionFromStanding()
    end)
end

local function tryMoveOnce(st)
    st = st or getTrowelState()
    if not MovePlant or not MovePlant.Fire then
        warn("[GAG2-ATrw] Networking.Trowel.MovePlant not found")
        return false, "no_remote"
    end
    if not st.selectedPlant then return false, "no_plant" end

    local targetPos = resolveTargetPosition(st)
    if not targetPos then return false, "no_position" end

    if st.moveTotal > 0 and sessionMovedCount >= st.moveTotal then
        _finishRun("total_reached")
        return false, "total_reached"
    end

    local candidates = scanMoveCandidates(st, targetPos)
    if #candidates == 0 then
        _finishRun("all_in_range")
        return false, "all_in_range"
    end

    if os.clock() - lastMoveAt < MOVE_COOLDOWN then return false, "cooldown" end

    if not _equipTrowel() then
        stallCount += 1
        if stallCount >= STALL_LIMIT then
            warn("[GAG2-ATrw] Auto Trowel stopped: equip Trowel in backpack first")
            _finishRun("no_trowel")
        end
        return false, "no_trowel"
    end

    local pick = candidates[1]
    local plant = pick.plant
    local beforePos = getPlantPivot(plant)
    lastMoveAt = os.clock()

    local ok, err = pcall(function()
        MovePlant:Fire(pick.fireName, targetPos, st.rotation or 0)
    end)
    if not ok then
        warn("[GAG2-ATrw] MovePlant error:", tostring(err))
        stallCount += 1
        if stallCount >= STALL_LIMIT then
            _finishRun("fire_error")
        end
        return false, "fire_error"
    end

    task.wait(MOVE_VERIFY_WAIT)

    if not _moveSucceeded(plant, targetPos, beforePos) then
        stallCount += 1
        _log("move_not_verified", pick.fireName, stallCount)
        if stallCount >= STALL_LIMIT then
            warn("[GAG2-ATrw] Auto Trowel stopped: plant did not move (equip Trowel?)")
            _finishRun("stalled")
        end
        return false, "move_failed"
    end

    stallCount = 0
    sessionMovedCount += 1
    _notifyStatsChanged()
    _log("moved", pick.fireName, targetPos, st.rotation, sessionMovedCount)

    if st.moveTotal > 0 and sessionMovedCount >= st.moveTotal then
        _finishRun("total_reached")
    end

    return true
end

local function mainLoop(myId)
    while running and loopId == myId do
        local st = getTrowelState()
        if st.enabled then
            pcall(tryMoveOnce, st)
        end
        task.wait(st.delay)
    end
end

function M.SetEnabled(on)
    on = (on == true)
    G.AUTO_TROWEL_ENABLED = on
    _G.AUTO_TROWEL_ENABLED = on
    _writeMain({ enabled = on })

    if on then
        sessionMovedCount = 0
        lastSessionMovedCount = 0
        stallCount = 0
        lastFinishReason = nil
        _notifyStatsChanged()
        if not running then
            running = true
            loopId += 1
            local myId = loopId
            task.spawn(function() mainLoop(myId) end)
        end
    else
        running = false
        sessionMovedCount = 0
        stallCount = 0
        _notifyStatsChanged()
        _disableSaveMode()
    end
end

function M.GetLastFinishReason()
    return lastFinishReason
end

function M.HasEquippedTrowel()
    return _getEquippedTrowel() ~= nil
end

function M.SetSelectedPlant(typeKey)
    if typeKey == nil or typeKey == "" or typeKey == "_none" then
        G.AUTO_TROWEL_SELECTED_PLANT = nil
        _G.AUTO_TROWEL_SELECTED_PLANT = nil
        _writeMain({ selectedPlant = nil })
        return
    end
    typeKey = tostring(typeKey)
    G.AUTO_TROWEL_SELECTED_PLANT = typeKey
    _G.AUTO_TROWEL_SELECTED_PLANT = typeKey
    _writeMain({ selectedPlant = typeKey })
end

function M.SetSelectedPosition(id)
    id = _normalizePositionId(id)
    G.AUTO_TROWEL_SELECTED_POSITION = id
    _G.AUTO_TROWEL_SELECTED_POSITION = id
    _writeMain({ selectedPosition = id })
end

function M.SetMoveTotal(n)
    n = math.floor(tonumber(n) or 0)
    if n < 0 then n = 0 end
    G.AUTO_TROWEL_MOVE_TOTAL = n
    _G.AUTO_TROWEL_MOVE_TOTAL = n
    _writeMain({ moveTotal = n })
end

function M.SetSavePosition(on)
    on = (on == true)
    if not on then
        saveModeActive = false
        _disableSaveMode()
        return
    end
    saveModeActive = true
    saveEnableAt = os.clock() + 0.2
    G.AUTO_TROWEL_SAVE_POSITION = true
    _G.AUTO_TROWEL_SAVE_POSITION = true
    _writeMain({ savePosition = true })
    _bindSaveListener()
end

function M.SaveStandingPosition()
    saveModeActive = true
    saveEnableAt = 0
    return trySavePositionFromStanding()
end

function M.SyncFromState()
    local st = getTrowelState()
    M.SetMoveTotal(st.moveTotal)
