local lastFailReason = ""

local function _statusMessage(reason)
    reason = tostring(reason or "")
    if reason == "" or reason == "garden_full" then return STATUS_TEXT.idle or "Idle" end
    return STATUS_TEXT[reason] or reason
end

local function _publishStatus(reason, detail)
    lastFailReason = tostring(reason or "")
    if lastFailReason == "garden_full" then
        return
    end
    local msg = _statusMessage(lastFailReason)
    if detail ~= nil and detail ~= "" then
        msg = msg .. " (" .. tostring(detail) .. ")"
    end
    G.__GAG2_SPRINKLER_STATUS = msg
    _G.__GAG2_SPRINKLER_STATUS = msg
end

local function _dbg()
    return G.AUTO_SPRINKLER_DEBUG == true or _G.AUTO_SPRINKLER_DEBUG == true
end

local function _log(...)
    if not _dbg() then return end
    print("[GAG2-ASpr]", ...)
end

local function _fail(reason, ...)
    _publishStatus(reason)
    if _dbg() then
        if select("#", ...) > 0 then
            warn("[GAG2-ASpr]", reason, ...)
        else
            warn("[GAG2-ASpr]", reason)
        end
    end
    return false, reason
end

local function _writeMain(patch)
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    if type(MAIN) ~= "table" then return end
    MAIN.auto = MAIN.auto or {}
    MAIN.auto.sprinkler = MAIN.auto.sprinkler or {}
    for k, v in pairs(patch) do
        MAIN.auto.sprinkler[k] = v
    end
    G.MAIN = MAIN
    _G.MAIN = MAIN
end

local function _normalizeSet(src)
    if type(src) ~= "table" then return {} end
    local out = {}
    for i = 1, #src do
        local v = src[i]
        if v ~= nil and tostring(v) ~= "" then
            out[tostring(v)] = true
        end
    end
    if next(out) then return out end
    for k, v in pairs(src) do
        if v == true or v == 1 or v == "true" then
            out[tostring(k)] = true
        end
    end
    return out
end

local function _canon(s)
    s = tostring(s or ""):lower():gsub("[^%w]+", "")
    return s
end

local function _sprinklerTypeMatch(a, b)
    if a == nil or b == nil then return false end
    if tostring(a) == tostring(b) then return true end
    return _canon(a) == _canon(b)
end

local function _isSameSprinklerType(a, b)
    return a ~= nil and b ~= nil and _sprinklerTypeMatch(a, b)
end

local function _getSLV()
    return G.SprinklerListView or rawget(_G, "SprinklerListView")
end

local function _getShovel()
    return G.AutoShovel or G.AutoShovelModule or rawget(_G, "AutoShovel")
end

local function getSprinklerState()
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    local st = MAIN and MAIN.auto and MAIN.auto.sprinkler
    st = type(st) == "table" and st or {}

    local sprinklers = G.AUTO_SPRINKLER_SELECTED
        or rawget(_G, "AUTO_SPRINKLER_SELECTED")
        or _normalizeSet(st.sprinklers)

    local plants = G.AUTO_SPRINKLER_PLANTS_SELECTED
        or rawget(_G, "AUTO_SPRINKLER_PLANTS_SELECTED")
        or _normalizeSet(st.plants)

    local delay = tonumber(st.delay)
    if delay == nil then
        delay = tonumber(G.AUTO_SPRINKLER_DELAY or rawget(_G, "AUTO_SPRINKLER_DELAY")) or 2
    end
    if delay < LOOP_MIN_SEC then delay = LOOP_MIN_SEC end

    local settleDelay = tonumber(st.settleDelay)
    if settleDelay == nil then
        settleDelay = tonumber(G.AUTO_SPRINKLER_SETTLE_DELAY or rawget(_G, "AUTO_SPRINKLER_SETTLE_DELAY")) or 0
    end
    if settleDelay < 0 then settleDelay = 0 end

    local minFruitHarvest = tonumber(st.minFruitHarvest)
    if minFruitHarvest == nil then
        minFruitHarvest = tonumber(G.AUTO_SPRINKLER_MIN_FRUIT_HARVEST or rawget(_G, "AUTO_SPRINKLER_MIN_FRUIT_HARVEST")) or 0
    end
    minFruitHarvest = math.floor(minFruitHarvest)
    if minFruitHarvest < 0 then minFruitHarvest = 0 end

    local maxFruitHarvest = tonumber(st.maxFruitHarvest)
    if maxFruitHarvest == nil then
        maxFruitHarvest = tonumber(G.AUTO_SPRINKLER_MAX_FRUIT_HARVEST or rawget(_G, "AUTO_SPRINKLER_MAX_FRUIT_HARVEST")) or 0
    end
    maxFruitHarvest = math.floor(maxFruitHarvest)
    if maxFruitHarvest < 0 then maxFruitHarvest = 0 end
    if maxFruitHarvest > 0 and minFruitHarvest > 0 and minFruitHarvest >= maxFruitHarvest then
        minFruitHarvest = math.max(0, maxFruitHarvest - 1)
    end

    local mode = tostring(st.mode or G.AUTO_SPRINKLER_MODE or "random"):lower()
    if mode ~= "near_plant" then mode = "random" end

    local enabled = (G.AUTO_SPRINKLER_ENABLED == true)
        or (rawget(_G, "AUTO_SPRINKLER_ENABLED") == true)
        or (st.enabled == true)

    return {
        enabled         = enabled,
        sprinklers      = _normalizeSet(sprinklers),
        plants          = _normalizeSet(plants),
        mode            = mode,
        delay           = delay,
        settleDelay     = settleDelay,
        minFruitHarvest = minFruitHarvest,
        maxFruitHarvest = maxFruitHarvest,
    }
end

local function invalidateSprinklerCache()
    tickCache.existing = nil
    tickCache.existingAt = 0
    randomGrids = {}
end

local function invalidatePlantScanCache()
    tickCache.targets = nil
    tickCache.targetsKey = nil
    tickCache.targetsAt = 0
    tickCache.areas = nil
    tickCache.areasAt = 0
    tickCache.rayParams = nil
    tickCache.rayOriginY = nil
    plantListCache.at = 0
    plantListCache.key = ""
    plantListCache.items = nil
end

local function invalidatePlacementCaches()
    invalidateSprinklerCache()
end

local function invalidateAllCaches()
    invalidateSprinklerCache()
    invalidatePlantScanCache()
end

local function _plantsFolderCount(plot)
    if not plot then return 0 end
    local folder = plot:FindFirstChild("Plants")
    return folder and #folder:GetChildren() or 0
end

local function computeSettleSec(plot, st)
    local user = tonumber(st and st.settleDelay)
    if user ~= nil and user > 0 then
        return math.clamp(user, 0.15, 5)
    end
    local n = _plantsFolderCount(plot)
    if n >= 500 then return 1.2
    elseif n >= 300 then return 1.0
    elseif n >= 200 then return 0.8
    elseif n >= 100 then return 0.55
    end
    return 0.35
end

local function getHarvestReadyCount(forGate)
    local AC = G.AutoCollectFruit or G.CollectFruitModule or rawget(_G, "AutoCollectFruit")
    if type(AC) ~= "table" then return 0 end
    if forGate and type(AC.CountHarvestForGate) == "function" then
        local ok, n = pcall(AC.CountHarvestForGate, AC)
        if ok and type(n) == "number" then return math.max(0, math.floor(n)) end
    end
    if type(AC.PeekHarvestCount) == "function" then
        local ok, n = pcall(AC.PeekHarvestCount, AC)
        if ok and type(n) == "number" then return math.max(0, math.floor(n)) end
    end
    if type(AC.CountFiltered) == "function" then
        local ok, n = pcall(AC.CountFiltered, AC)
        if ok and type(n) == "number" then return math.max(0, math.floor(n)) end
    end
    return 0
end

local function checkFruitHarvestGate(st)
    local maxF = math.floor(tonumber(st and st.maxFruitHarvest) or 0)
    local minF = math.floor(tonumber(st and st.minFruitHarvest) or 0)
    if maxF <= 0 then
        fruitGatePaused = false
        return true
    end

    local count = getHarvestReadyCount(true)

    if count >= maxF then
        fruitGatePaused = true
        return false, "fruit_max", count
    end

    if fruitGatePaused then
        local resumeBelow = (minF > 0) and minF or maxF
        if count >= resumeBelow then
            return false, "fruit_wait", count
        end
    end

    fruitGatePaused = false
    return true, nil, count
end

local function _resetCollectGate()
    local AC = G.AutoCollectFruit or G.CollectFruitModule or rawget(_G, "AutoCollectFruit")
    if type(AC) == "table" and type(AC.ResetGrowAssistGate) == "function" then
        pcall(AC.ResetGrowAssistGate, AC)
    end
    collectGatePaused = false
end

local function checkCollectIdleGate()
    local AC = G.AutoCollectFruit or G.CollectFruitModule or rawget(_G, "AutoCollectFruit")
    if type(AC) ~= "table" or type(AC.CheckGrowAssistGate) ~= "function" then
        collectGatePaused = false
        return true
    end

    local ok, reason, inN, outN = AC.CheckGrowAssistGate(AC)
    if not ok then
        collectGatePaused = true
        return false, reason or "collect_idle", ("skip=" .. tostring(outN or 0))
    end

    collectGatePaused = false
    if reason == "collect_wait" then
        return true, reason, inN
    end
    return true
end

local collectPlantAreas

local function getCachedPlantAreas(plot, forceRefresh)
    if not plot then return {} end
    local now = os.clock()
    if not forceRefresh
        and tickCache.plot == plot
        and type(tickCache.areas) == "table" then
        local age = now - (tickCache.areasAt or 0)
        local ttl = (#tickCache.areas > 0) and PLANT_AREA_CACHE_SEC or EMPTY_AREA_CACHE_SEC
        if age <= ttl then
            return tickCache.areas
        end
    end
    if type(collectPlantAreas) ~= "function" then
        return {}
    end
    local areas = collectPlantAreas(plot)
    tickCache.plot = plot
    tickCache.areas = areas
    tickCache.areasAt = now
    tickCache.rayParams = nil
    tickCache.rayOriginY = nil
    return areas
end

local function getCachedRaycast(plot)
    local areas = getCachedPlantAreas(plot)
    if #areas == 0 then
        return nil, areas, 250
    end
    if tickCache.plot == plot and tickCache.rayParams then
        return tickCache.rayParams, areas, tickCache.rayOriginY or 250
    end
    local originY = 250
    for _, part in ipairs(areas) do
        if part:IsA("BasePart") then
            originY = math.max(originY, part.Position.Y + 80)
        end
    end
    local params = RaycastParams.new()
    params.FilterType = Enum.RaycastFilterType.Include
    params.FilterDescendantsInstances = areas
    tickCache.plot = plot
    tickCache.rayParams = params
    tickCache.rayOriginY = originY
    return params, areas, originY
end

local function snapToPlantAreaCached(plot, pos)
    if not plot or not pos then return nil end
    local params, _, originY = getCachedRaycast(plot)
    if not params then return nil end
    local hit = workspace:Raycast(
        Vector3.new(pos.X, originY, pos.Z),
        Vector3.new(0, -600, 0),
        params
    )
    if hit then
        local inst = hit.Instance
        if inst:IsDescendantOf(plot) then
            return hit.Position
        end
        local _, areas = getCachedRaycast(plot)
        for _, part in ipairs(areas) do
            if inst == part or inst:IsDescendantOf(part) or part:IsDescendantOf(inst) then
                return hit.Position
            end
        end
    end
    return nil
end

