function M.SetEnabled(on)
    on = (on == true)
    G.AUTO_SPRINKLER_ENABLED = on
    _G.AUTO_SPRINKLER_ENABLED = on
    _writeMain({ enabled = on })

    if on then
        sessionPlaced = 0
        invalidateAllCaches()
        resetActiveSprinklerType()
        _resetCollectGate()
        _publishStatus("idle")
        task.spawn(warmInitialScan)
        if not running then
            running = true
            loopId += 1
            local myId = loopId
            task.spawn(function() mainLoop(myId) end)
        end
    else
        running = false
        loopId += 1
        fruitGatePaused = false
        collectGatePaused = false
        _resetCollectGate()
        unequipSprinklerTool(nil)
        resetActiveSprinklerType()
        _publishStatus("idle")
    end
end

