    if txt == "" then return 0, "above" end
    local n = tonumber(txt)
    if not n then return 0, "above" end
    if n < 0 then return math.abs(n), "below" end
    return n, "above"
end

local function parseScaledNumber(txt)
    txt = tostring(txt or ""):gsub("%s+", ""):gsub(",", "")
    if txt == "" then return nil end
    local sign = 1
    if txt:sub(1, 1) == "-" then
        sign = -1
        txt = txt:sub(2)
    end
    local last = txt:sub(-1):upper()
    local mult = 1
    if last == "K" then
        mult = 1000
        txt = txt:sub(1, -2)
    elseif last == "M" then
        mult = 1000000
        txt = txt:sub(1, -2)
    elseif last == "B" then
        mult = 1000000000
        txt = txt:sub(1, -2)
    end
    local n = tonumber(txt)
    if not n then return nil end
    return n * mult * sign
end

local function parsePriceRule(txt)
    local n = parseScaledNumber(txt)
    if not n then return 0, "above" end
    if n < 0 then return math.floor(math.abs(n)), "below" end
    return math.floor(n), "above"
end

local function kgInputText(st)
