    },
}

local function getProfile(ctx)
    local kind = tostring(type(ctx) == "table" and ctx.rulesKind or "collect")
    return PROFILES[kind] or PROFILES.collect
end

local function getRulesState(ctx)
    if type(ctx.RULES_STATE) == "table" then return ctx.RULES_STATE end
    if type(ctx.AC_STATE) == "table" then return ctx.AC_STATE end
    if type(ctx.SF_STATE) == "table" then return ctx.SF_STATE end
    if type(ctx.AS_STATE) == "table" then return ctx.AS_STATE end
    return {}
end

local function setGlobal(name, value)
    G[name] = value
    _G[name] = value
end

local ROW_H = 26
local ROW_PAD = 4
local VISIBLE_ROWS = 6
local LIST_PAD_TOP = 8
local LIST_PAD_BOT = 8

local function parseKgRule(txt)
    txt = tostring(txt or ""):gsub("%s+", "")
    if txt == "" then return 0, "above" end
    local n = tonumber(txt)
    if not n then return 0, "above" end
    if n < 0 then return math.abs(n), "below" end
    return n, "above"
end

local function parseScaledNumber(txt)
    txt = tostring(txt or ""):lower():gsub("%s+", ""):gsub(",", "")
    if txt == "" then return nil end
    local sign = 1
    if txt:sub(1, 1) == "-" then
        sign = -1
        txt = txt:sub(2)
    end
    local suffixes = {
        { "juta", 1000000 }, { "jt", 1000000 },
        { "ribu", 1000 }, { "rb", 1000 },
        { "b", 1000000000 }, { "m", 1000000 }, { "k", 1000 },
    }
    for _, pair in ipairs(suffixes) do
        local suf, mult = pair[1], pair[2]
        if #txt > #suf and txt:sub(-#suf) == suf then
            local n = tonumber(txt:sub(1, -#suf - 1))
            if n then return n * mult * sign end
        end
    end
    local n = tonumber(txt)
    if n then return n * sign end
    return nil
end

local function parsePriceRule(txt)
    local n = parseScaledNumber(txt)
    if not n then return 0, "above" end
    if n < 0 then return math.floor(math.abs(n)), "below" end
    return math.floor(n), "above"
end

local function newRuleId(prefix)
    prefix = tostring(prefix or "cr")
    return prefix .. tostring(math.floor(os.clock() * 1000)) .. "_" .. tostring(math.random(1000, 9999))
end

local function mkCorner(p, r)
    local c = Instance.new("UICorner")
    c.CornerRadius = UDim.new(0, r or 6)
    c.Parent = p
end

local function mkStroke(p, col, th, tr)
    local s = Instance.new("UIStroke")
    s.Color = col or Color3.fromRGB(40, 40, 40)
    s.Thickness = th or 1
    s.Transparency = tr or 0.5
    s.Parent = p
end

local function mkPad(p, l, r, t, b)
    local pad = Instance.new("UIPadding")
    pad.PaddingTop = UDim.new(0, t or 4)
    pad.PaddingBottom = UDim.new(0, b or 4)
    pad.PaddingLeft = UDim.new(0, l or 4)
    pad.PaddingRight = UDim.new(0, r or 4)
    pad.Parent = p
end

local function norm(s)
    s = tostring(s or ""):lower()
    s = s:gsub("%s+", " "):gsub("^%s+", ""):gsub("%s+$", "")
    return s
end

local function setToArray(src)
    if type(src) ~= "table" then return {} end
    local out = {}
    for i = 1, #src do
        local v = src[i]
        if v ~= nil and tostring(v) ~= "" then
            out[#out + 1] = tostring(v)
        end
    end
    if #out > 0 then
        table.sort(out)
        return out
    end
    for k, v in pairs(src) do
        if v == true or v == 1 or v == "true" then
            out[#out + 1] = tostring(k)
        end
    end
    table.sort(out)
    return out
end

local function ruleKgFields(rule)
    rule = type(rule) == "table" and rule or {}
    local kg = tonumber(rule.kg)
    local mode = tostring(rule.kgMode or "above")
    if (kg == nil or kg <= 0) and type(rule.kgRule) == "string" and rule.kgRule:gsub("%s+", "") ~= "" then
        kg, mode = parseKgRule(rule.kgRule)
    end
    return kg or 0, mode
end

local function rulePriceFields(rule)
    rule = type(rule) == "table" and rule or {}
    local price = tonumber(rule.minPrice)
    local mode = tostring(rule.minPriceMode or "above")
    if (price == nil or price <= 0) and type(rule.priceRule) == "string" and rule.priceRule:gsub("%s+", "") ~= "" then
        price, mode = parsePriceRule(rule.priceRule)
    end
    return price or 0, mode
end

local function sanitizeRuleForPersist(rule)
    if type(rule) ~= "table" then return rule end
    local kg, kgMode = ruleKgFields(rule)
    local minPrice, minPriceMode = rulePriceFields(rule)
    local kgRule = type(rule.kgRule) == "string" and rule.kgRule:gsub("%s+", "") or ""
    if kgRule == "" then
        kgRule = (kg > 0 and ((kgMode == "below") and ("-" .. tostring(kg)) or tostring(kg))) or "0"
    end
    local priceRule = type(rule.priceRule) == "string" and rule.priceRule:gsub("%s+", "") or ""
    if priceRule == "" then
        priceRule = (minPrice > 0 and ((minPriceMode == "below") and ("-" .. tostring(minPrice)) or tostring(minPrice))) or "0"
    end
    return {
        id = tostring(rule.id or ""),
        enabled = rule.enabled ~= false,
        fruits = setToArray(rule.fruits),
        mutations = setToArray(rule.mutations),
        kg = kg,
        kgMode = kgMode,
        kgRule = kgRule,
        minPrice = minPrice,
        minPriceMode = minPriceMode,
        priceRule = priceRule,
        requireMut = rule.requireMut == true,
    }
end

local function sanitizeRulesPayload(rules, order)
    rules = type(rules) == "table" and rules or {}
    order = type(order) == "table" and order or {}
    local byId = {}
    for _, raw in ipairs(rules) do
        if type(raw) == "table" then
            local rule = sanitizeRuleForPersist(raw)
            if rule.id == "" then
                rule.id = newRuleId("r")
            end
            byId[rule.id] = rule
        end
    end
    for id, raw in pairs(rules) do
        if type(raw) == "table" and type(id) ~= "number" then
            local rule = sanitizeRuleForPersist(raw)
            rule.id = tostring(rule.id ~= "" and rule.id or id)
            byId[rule.id] = rule
        end
    end
    local out, seen = {}, {}
    for _, id in ipairs(order) do
        id = tostring(id or "")
        local rule = byId[id]
        if rule and not seen[id] then
            seen[id] = true
            out[#out + 1] = rule
        end
    end
    for id, rule in pairs(byId) do
        if not seen[id] then
            out[#out + 1] = rule
        end
    end
    local nextOrder = {}
    for _, rule in ipairs(out) do
        nextOrder[#nextOrder + 1] = rule.id
    end
    return out, nextOrder
end

local function formatKgShort(kg, mode)
    kg = tonumber(kg) or 0
    mode = tostring(mode or "above")
    if kg <= 0 then return "any kg" end
    if mode == "below" then return "<" .. tostring(kg) .. "kg" end
    return ">=" .. tostring(kg) .. "kg"
end

local function formatPriceShort(price, mode)
    price = tonumber(price) or 0
    mode = tostring(mode or "above")
    if price <= 0 then return "any price" end
    if mode == "below" then return "<" .. tostring(price) end
    return ">=" .. tostring(price)
end

local function summarizeFruitShort(rule)
    local fruits = setToArray(rule and rule.fruits)
    if #fruits == 0 then
        return "All Fruit"
    end
    if #fruits == 1 then
        return tostring(fruits[1])
    end
    if #fruits == 2 then
        return tostring(fruits[1]) .. ", " .. tostring(fruits[2])
    end
    return tostring(#fruits) .. " fruits"
end

local COLOR3_PARTS = {
    fruit = Color3.fromRGB(255, 224, 138),
    sep = Color3.fromRGB(90, 90, 90),
    kg = Color3.fromRGB(110, 207, 255),
    price = Color3.fromRGB(125, 218, 138),
}

local function buildSummaryParts(rule)
    if type(rule) ~= "table" then
        return { { text = "(invalid)", color = Color3.fromRGB(200, 200, 200) } }
    end
    local kg, kgMode = ruleKgFields(rule)
    local minPrice, minPriceMode = rulePriceFields(rule)
    return {
        { text = summarizeFruitShort(rule), color = COLOR3_PARTS.fruit },
        { text = " · ", color = COLOR3_PARTS.sep },
        { text = formatKgShort(kg, kgMode), color = COLOR3_PARTS.kg },
        { text = " · ", color = COLOR3_PARTS.sep },
        { text = formatPriceShort(minPrice, minPriceMode), color = COLOR3_PARTS.price },
    }
end

local function mountColoredSummary(parent, rule)
    local row = Instance.new("Frame")
    row.Name = "SummaryRow"
    row.BackgroundTransparency = 1
    row.AutomaticSize = Enum.AutomaticSize.X
    row.Size = UDim2.new(0, 0, 1, 0)
    row.Parent = parent

    local layout = Instance.new("UIListLayout")
    layout.FillDirection = Enum.FillDirection.Horizontal
    layout.SortOrder = Enum.SortOrder.LayoutOrder
    layout.VerticalAlignment = Enum.VerticalAlignment.Center
    layout.Parent = row

    for i, part in ipairs(buildSummaryParts(rule)) do
        local lbl = Instance.new("TextLabel")
        lbl.Name = "Part" .. i
        lbl.LayoutOrder = i
        lbl.BackgroundTransparency = 1
        lbl.AutomaticSize = Enum.AutomaticSize.X
        lbl.Size = UDim2.new(0, 0, 1, 0)
        lbl.Font = Enum.Font.Gotham
        lbl.TextSize = 11
        lbl.TextXAlignment = Enum.TextXAlignment.Left
        lbl.TextYAlignment = Enum.TextYAlignment.Center
        lbl.TextColor3 = part.color
        lbl.Text = part.text
        lbl.Parent = row
    end
end

local function getMutationBadge(rule)
    local muts = setToArray(rule and rule.mutations)
    if #muts > 0 then
        return {
            text = tostring(#muts),
            clickable = true,
            muts = muts,
        }
    end
    return {
        text = "any",
        clickable = false,
        muts = {},
    }
end

local function summarizeRulePlain(rule)
    if type(rule) ~= "table" then return "(invalid)" end
    local kg, kgMode = ruleKgFields(rule)
    local minPrice, minPriceMode = rulePriceFields(rule)
    return summarizeFruitShort(rule)
        .. " · " .. formatKgShort(kg, kgMode)
        .. " · " .. formatPriceShort(minPrice, minPriceMode)
end

local function resolvePopupRoot(ui)
    if type(ui) == "table" then
        return ui.right or ui.mainFrame or ui._sg
    end
    return nil
end

local function closeMutationPopup(ui, popupName)
    popupName = tostring(popupName or "GAG2CollectMutPopup")
    local root = resolvePopupRoot(ui)
    if not root then return end
    for _, desc in ipairs(root:GetDescendants()) do
        if desc.Name == popupName then
            pcall(function() desc:Destroy() end)
        end
    end
end

local function showMutationPopup(ui, muts, ruleLabel, popupName)
    muts = type(muts) == "table" and muts or {}
    if #muts == 0 then return end

    popupName = tostring(popupName or "GAG2CollectMutPopup")
    closeMutationPopup(ui, popupName)

    local parentFrame = resolvePopupRoot(ui)
    if not parentFrame then return end

    if type(ui.CloseDropdownOverlays) == "function" then
        pcall(ui.CloseDropdownOverlays, ui)
    end

    local BASE_Z = 110

    local overlay = Instance.new("TextButton")
    overlay.Name = popupName
    overlay.Size = UDim2.new(1, 0, 1, 0)
    overlay.BackgroundColor3 = Color3.fromRGB(0, 0, 0)
    overlay.BackgroundTransparency = 0.3
    overlay.Text = ""
    overlay.AutoButtonColor = false
    overlay.Active = true
    overlay.ZIndex = BASE_Z
    overlay.Parent = parentFrame

    local panel = Instance.new("Frame")
    panel.Name = "Panel"
    panel.Size = UDim2.new(0.9, 0, 0, 0)
    panel.AutomaticSize = Enum.AutomaticSize.Y
    panel.Position = UDim2.new(0.5, 0, 0.45, 0)
    panel.AnchorPoint = Vector2.new(0.5, 0.5)
    panel.BackgroundColor3 = Color3.fromRGB(20, 20, 24)
    panel.BorderSizePixel = 0
    panel.Active = true
    panel.ZIndex = BASE_Z + 1
    panel.Parent = overlay
    mkCorner(panel, 10)
    mkStroke(panel, Color3.fromRGB(255, 217, 0), 1, 0.45)

    local panelPad = Instance.new("UIPadding")
    panelPad.PaddingTop = UDim.new(0, 10)
    panelPad.PaddingBottom = UDim.new(0, 10)
    panelPad.PaddingLeft = UDim.new(0, 12)
    panelPad.PaddingRight = UDim.new(0, 12)
    panelPad.Parent = panel

    local panelLayout = Instance.new("UIListLayout")
    panelLayout.Padding = UDim.new(0, 6)
    panelLayout.SortOrder = Enum.SortOrder.LayoutOrder
    panelLayout.Parent = panel

    local titleLbl = Instance.new("TextLabel")
    titleLbl.LayoutOrder = 1
    titleLbl.BackgroundTransparency = 1
    titleLbl.Size = UDim2.new(1, 0, 0, 18)
    titleLbl.Font = Enum.Font.GothamBold
    titleLbl.TextSize = 12
    titleLbl.TextXAlignment = Enum.TextXAlignment.Left
    titleLbl.TextColor3 = Color3.fromRGB(255, 217, 0)
    titleLbl.ZIndex = BASE_Z + 2
    titleLbl.Text = "Mutations (" .. #muts .. ")"
    if ruleLabel and ruleLabel ~= "" then
        titleLbl.Text = titleLbl.Text .. " — " .. tostring(ruleLabel)
    end
    titleLbl.Parent = panel

    local maxVisible = 8
    local lineH = 20
    local scrollH = (#muts * lineH) + math.max(0, #muts - 1) * 2
    if scrollH > (maxVisible * lineH) + ((maxVisible - 1) * 2) then
        scrollH = (maxVisible * lineH) + ((maxVisible - 1) * 2)
    end

    local scroll = Instance.new("ScrollingFrame")
    scroll.LayoutOrder = 2
    scroll.BackgroundColor3 = Color3.fromRGB(12, 12, 16)
    scroll.BorderSizePixel = 0
    scroll.Size = UDim2.new(1, 0, 0, scrollH)
    scroll.CanvasSize = UDim2.new(0, 0, 0, 0)
    scroll.AutomaticCanvasSize = Enum.AutomaticSize.Y
    scroll.ScrollBarThickness = 3
    scroll.ScrollingDirection = Enum.ScrollingDirection.Y
    scroll.Active = true
    scroll.ZIndex = BASE_Z + 2
    scroll.Parent = panel
    mkCorner(scroll, 4)

    local scrollLayout = Instance.new("UIListLayout")
    scrollLayout.Padding = UDim.new(0, 2)
    scrollLayout.SortOrder = Enum.SortOrder.LayoutOrder
    scrollLayout.Parent = scroll

    local scrollPad = Instance.new("UIPadding")
    scrollPad.PaddingTop = UDim.new(0, 4)
    scrollPad.PaddingBottom = UDim.new(0, 4)
    scrollPad.PaddingLeft = UDim.new(0, 8)
    scrollPad.PaddingRight = UDim.new(0, 8)
    scrollPad.Parent = scroll

    for i, m in ipairs(muts) do
        local row = Instance.new("TextLabel")
        row.LayoutOrder = i
        row.BackgroundTransparency = 1
        row.Size = UDim2.new(1, 0, 0, lineH)
        row.Font = Enum.Font.Gotham
        row.TextSize = 11
        row.TextXAlignment = Enum.TextXAlignment.Left
        row.TextColor3 = Color3.fromRGB(210, 185, 255)
        row.Text = tostring(i) .. ". " .. tostring(m)
        row.TextTruncate = Enum.TextTruncate.AtEnd
        row.ZIndex = BASE_Z + 3
        row.Parent = scroll
    end

    local hint = Instance.new("TextLabel")
    hint.LayoutOrder = 3
    hint.BackgroundTransparency = 1
    hint.Size = UDim2.new(1, 0, 0, 14)
    hint.Font = Enum.Font.Gotham
    hint.TextSize = 10
    hint.TextColor3 = Color3.fromRGB(120, 120, 120)
    hint.Text = "Tap luar untuk tutup"
    hint.ZIndex = BASE_Z + 2
    hint.Parent = panel

    overlay.MouseButton1Click:Connect(function()
        closeMutationPopup(ui, popupName)
    end)
end

local function ruleSearchBlob(rule)
    local parts = { summarizeRulePlain(rule) }
    for _, m in ipairs(setToArray(rule and rule.mutations)) do
        parts[#parts + 1] = tostring(m)
    end
    if rule.requireMut == true then
        parts[#parts + 1] = "requiremut"
    end
    return norm(table.concat(parts, " "))
end

local function resolveRulesList(modState)
    modState = type(modState) == "table" and modState or {}
    local rawRules = modState.rules
    local order = modState.rulesOrder
    local ac = G.AutoCollect or G.AutoCollectFruit or rawget(_G, "AutoCollect")
    if type(ac) == "table" and type(ac.NormalizeRulesList) == "function" then
        local ok, list = pcall(ac.NormalizeRulesList, rawRules, order)
        if ok and type(list) == "table" then return list end
    end
    local out = {}
    if type(rawRules) == "table" then
        for _, r in ipairs(rawRules) do
            if type(r) == "table" then out[#out + 1] = r end
        end
    end
    return out
end

local function nextLayoutOrder(body)
    local maxOrder = 0
    for _, ch in ipairs(body:GetChildren()) do
        if ch:IsA("GuiObject") and ch.LayoutOrder > maxOrder then
            maxOrder = ch.LayoutOrder
        end
    end
    return maxOrder + 1
end

local function resolveModState(ctx, profile)
    if type(ctx) == "table" and type(ctx.getAuto) == "function" then
        local ok, live = pcall(ctx.getAuto, profile.patchKey)
        if ok and type(live) == "table" then
            live.filterMode = "rules"
            live.rules = type(live.rules) == "table" and live.rules or {}
            live.rulesOrder = type(live.rulesOrder) == "table" and live.rulesOrder or {}
            return live
        end
    end
    local st = getRulesState(ctx)
    st.filterMode = "rules"
    st.rules = type(st.rules) == "table" and st.rules or {}
    st.rulesOrder = type(st.rulesOrder) == "table" and st.rulesOrder or {}
    return st
end

local function getGlobalStores()
    G.__GAG2_RULES_UI_STORES = type(G.__GAG2_RULES_UI_STORES) == "table" and G.__GAG2_RULES_UI_STORES or {}
    return G.__GAG2_RULES_UI_STORES
end

local function bindStoreCtx(store, ctx)
    store._ctx = ctx
    store._externalSync = ctx.syncAutoCollectModule or ctx.syncAutoSellModule
        or ctx.syncAutoShovelFruitModule or ctx.syncRulesModule
end

local function refreshStoreModState(store)
    local ctx = store._ctx
    if type(ctx) == "table" and store.profile then
        store.MOD_STATE = resolveModState(ctx, store.profile)
    end
end

local function syncCtxRulesState(store)
    local st = store.MOD_STATE
    if type(st) ~= "table" then return end
    local ctx = store._ctx
    if type(ctx) ~= "table" then return end
    for _, key in ipairs({ "RULES_STATE", "AC_STATE", "SF_STATE", "AS_STATE" }) do
        local ref = ctx[key]
        if type(ref) == "table" and ref ~= st then
            ref.rules = st.rules
            ref.rulesOrder = st.rulesOrder
            ref.filterMode = "rules"
        end
    end
end

local function ensureStore(ctx)
    if type(ctx) ~= "table" then return nil end
    local profile = getProfile(ctx)
    local storeKey = profile.storeKey
    local stores = getGlobalStores()
    local store = stores[storeKey]

    if type(store) == "table" then
        bindStoreCtx(store, ctx)
        refreshStoreModState(store)
        ctx[storeKey] = store
        return store
    end

    store = {
        profile = profile,
        MOD_STATE = resolveModState(ctx, profile),
        bulk = {
            fruits = {},
            mutations = {},
            kgRule = "0",
            priceRule = "0",
        },
        refreshSavedList = nil,
        savedListBuilt = false,
        listBody = nil,
        bulkBuilt = false,
        bulkBody = nil,
        flushRegistered = false,
        _applyBusy = false,
    }
    bindStoreCtx(store, ctx)

    function store.persistRules(syncModule)
        local c = store._ctx
        local profile = store.profile
        if type(c) ~= "table" then return end
        syncModule = syncModule or store._externalSync
        local st = store.MOD_STATE
        local cleanRules, cleanOrder = sanitizeRulesPayload(st.rules, st.rulesOrder)
        st.rules = cleanRules
        st.rulesOrder = cleanOrder
        local payload = {
            filterMode = "rules",
            rules = cleanRules,
            rulesOrder = cleanOrder,
        }
        if type(c.patchAutoOnly) == "function" then
            c.patchAutoOnly(profile.patchKey, payload)
        elseif type(c.patchAuto) == "function" then
            c.patchAuto(profile.patchKey, payload)
            syncModule = nil
        end
        refreshStoreModState(store)
        syncCtxRulesState(store)
        if type(syncModule) == "function" then
            pcall(syncModule)
        end
    end

    function store.pushGlobals()
        refreshStoreModState(store)
        local st = store.MOD_STATE
        local profile = store.profile
        setGlobal(profile.gFilterMode, "rules")
        setGlobal(profile.gRules, st.rules)
        setGlobal(profile.gRulesOrder, st.rulesOrder)
    end

    function store.syncRulesModule()
        store.pushGlobals()
        if type(store._externalSync) == "function" then
            pcall(store._externalSync)
        end
    end

    stores[storeKey] = store
    ctx[storeKey] = store
    return store
end

function M.RegisterSavedList(ctx)
    if type(ctx) ~= "table" or type(ctx.ui) ~= "table" then return end
    local body = ctx.body
    if not body then return end
    local store = ensureStore(ctx)
    if store.savedListBuilt and store.listBody == body then
        refreshStoreModState(store)
        if store.refreshSavedList then pcall(store.refreshSavedList) end
        return
    end
    store.savedListBuilt = true
    store.listBody = body

    local MOD_STATE = store.MOD_STATE
    local persistRules = store.persistRules
    local syncRulesModule = store.syncRulesModule
    local profile = store.profile
    local ui = ctx.ui

    local function currentRules()
        return resolveRulesList(store.MOD_STATE)
    end

    local function deleteRule(ruleId)
        ruleId = tostring(ruleId or "")
        if ruleId == "" then return end
        refreshStoreModState(store)
        local st = store.MOD_STATE
        local nextRules, nextOrder = {}, {}
        for _, rule in ipairs(resolveRulesList(st)) do
            if tostring(rule.id or "") ~= ruleId then
                local clean = sanitizeRuleForPersist(rule)
                nextRules[#nextRules + 1] = clean
                nextOrder[#nextOrder + 1] = clean.id
            end
        end
        st.rules = nextRules
        st.rulesOrder = nextOrder
        local ok, err = pcall(function()
            store.persistRules(syncRulesModule)
        end)
        if not ok then
            warn("[GAG2-Rules] deleteRule persist error:", tostring(err))
        end
        if store.refreshSavedList then pcall(store.refreshSavedList) end
    end

    local listRow = Instance.new("Frame")
    listRow.Name = "RowCollectRulesList"
    listRow.BackgroundTransparency = 1
    listRow.Size = UDim2.new(1, 0, 0, 0)
    listRow.AutomaticSize = Enum.AutomaticSize.Y
    listRow.LayoutOrder = nextLayoutOrder(body)
    listRow.Parent = body

    local rowLayout = Instance.new("UIListLayout")
    rowLayout.Parent = listRow
    rowLayout.FillDirection = Enum.FillDirection.Vertical
    rowLayout.SortOrder = Enum.SortOrder.LayoutOrder
    rowLayout.Padding = UDim.new(0, 8)

    local titleLbl = Instance.new("TextLabel")
    titleLbl.Name = "SavedListTitle"
    titleLbl.Parent = listRow
    titleLbl.BackgroundTransparency = 1
    titleLbl.Size = UDim2.new(1, 0, 0, 18)
    titleLbl.LayoutOrder = 1
    titleLbl.Font = Enum.Font.Gotham
    titleLbl.TextSize = 12
    titleLbl.TextXAlignment = Enum.TextXAlignment.Left
    titleLbl.TextColor3 = Color3.fromRGB(180, 180, 180)
    titleLbl.Text = "Saved Rules"

    local searchWrap = Instance.new("Frame")
    searchWrap.Name = "SearchWrap"
    searchWrap.Parent = listRow
    searchWrap.BackgroundColor3 = Color3.fromRGB(22, 22, 22)
    searchWrap.BorderSizePixel = 0
    searchWrap.Size = UDim2.new(1, 0, 0, 26)
    searchWrap.LayoutOrder = 2
    mkCorner(searchWrap, 4)
    mkStroke(searchWrap, Color3.fromRGB(40, 40, 40), 1, 0.5)
    mkPad(searchWrap, 6, 6, 0, 0)

    local searchBox = Instance.new("TextBox")
    searchBox.Name = "Search"
    searchBox.Parent = searchWrap
    searchBox.BackgroundTransparency = 1
    searchBox.Size = UDim2.new(1, 0, 1, 0)
    searchBox.Font = Enum.Font.Gotham
    searchBox.TextSize = 12
    searchBox.TextColor3 = Color3.fromRGB(235, 235, 235)
    searchBox.TextXAlignment = Enum.TextXAlignment.Center
    searchBox.ClearTextOnFocus = false
    searchBox.Text = ""

    local searchHint = Instance.new("TextLabel")
    searchHint.Name = "Hint"
    searchHint.Parent = searchWrap
    searchHint.BackgroundTransparency = 1
    searchHint.Size = UDim2.new(1, 0, 1, 0)
    searchHint.Font = Enum.Font.Gotham
    searchHint.TextSize = 12
    searchHint.TextColor3 = Color3.fromRGB(150, 150, 150)
    searchHint.TextXAlignment = Enum.TextXAlignment.Center
    searchHint.Text = "Search rules..."
    searchHint.ZIndex = searchBox.ZIndex + 1

    local function updateSearchHint()
        local txt = tostring(searchBox.Text or ""):gsub("%s+", "")
        searchHint.Visible = (txt == "") and (not searchBox:IsFocused())
    end
    updateSearchHint()
    searchBox.Focused:Connect(updateSearchHint)
    searchBox.FocusLost:Connect(function()
        updateSearchHint()
        if store.refreshSavedList then store.refreshSavedList() end
    end)

    local function calcListHeight(count)
        local rows = math.min(count or 0, VISIBLE_ROWS)
        if rows <= 0 then rows = 1 end
        return (rows * ROW_H) + ((rows - 1) * ROW_PAD) + LIST_PAD_TOP + LIST_PAD_BOT
    end

    local listScroll = Instance.new("ScrollingFrame")
    listScroll.Name = "SavedRulesList"
    listScroll.Parent = listRow
    listScroll.BackgroundColor3 = Color3.fromRGB(15, 15, 15)
    listScroll.BorderSizePixel = 0
    listScroll.LayoutOrder = 3
    listScroll.Size = UDim2.new(1, 0, 0, calcListHeight(0))
    listScroll.CanvasSize = UDim2.new(0, 0, 0, 0)
    listScroll.ScrollBarThickness = 4
    listScroll.ScrollBarImageTransparency = 0.2
    listScroll.ScrollingDirection = Enum.ScrollingDirection.Y
    listScroll.AutomaticCanvasSize = Enum.AutomaticSize.Y
    listScroll.ClipsDescendants = true
    mkCorner(listScroll, 6)
    mkStroke(listScroll, Color3.fromRGB(40, 40, 40), 1, 0.5)
    mkPad(listScroll, 4, 4, LIST_PAD_TOP, LIST_PAD_BOT)

    local listLayout = Instance.new("UIListLayout")
    listLayout.FillDirection = Enum.FillDirection.Vertical
    listLayout.SortOrder = Enum.SortOrder.LayoutOrder
    listLayout.Padding = UDim.new(0, ROW_PAD)
    listLayout.Parent = listScroll

    local function clearListRows()
        for _, ch in ipairs(listScroll:GetChildren()) do
            if ch:IsA("Frame") and ch.Name:sub(1, 5) == "Item_" then
                ch:Destroy()
            end
            if ch:IsA("TextLabel") and ch.Name == "EmptyHint" then
                ch:Destroy()
            end
        end
    end

    local function buildListRow(index, rule)
        local ruleId = tostring(rule.id or ("#" .. index))
        local summaryPlain = summarizeRulePlain(rule)
        local mutBadge = getMutationBadge(rule)

        local idxW = 20
        local mutW = mutBadge.clickable and 34 or 30
        local delW = 22
        local gap = 4

        local item = Instance.new("Frame")
        item.Name = "Item_" .. ruleId
        item.BackgroundColor3 = Color3.fromRGB(22, 22, 22)
        item.Size = UDim2.new(1, 0, 0, ROW_H)
        item.LayoutOrder = index
        item.Parent = listScroll
        mkCorner(item, 4)

        local ip = Instance.new("UIPadding")
        ip.PaddingLeft = UDim.new(0, 6)
        ip.PaddingRight = UDim.new(0, 4)
        ip.Parent = item

        local idxLbl = Instance.new("TextLabel")
        idxLbl.BackgroundTransparency = 1
        idxLbl.Position = UDim2.new(0, 0, 0, 0)
        idxLbl.Size = UDim2.new(0, idxW, 1, 0)
        idxLbl.Font = Enum.Font.GothamBold
        idxLbl.TextSize = 11
        idxLbl.TextXAlignment = Enum.TextXAlignment.Left
        idxLbl.TextYAlignment = Enum.TextYAlignment.Center
        idxLbl.TextColor3 = Color3.fromRGB(255, 217, 0)
        idxLbl.Text = tostring(index) .. "."
        idxLbl.Parent = item

        local rightW = delW + gap + mutW + gap

        local summaryWrap = Instance.new("Frame")
        summaryWrap.Name = "SummaryWrap"
        summaryWrap.BackgroundTransparency = 1
        summaryWrap.Position = UDim2.new(0, idxW + gap, 0, 0)
        summaryWrap.Size = UDim2.new(1, -rightW - idxW - gap, 1, 0)
        summaryWrap.ClipsDescendants = true
        summaryWrap.Parent = item
        mountColoredSummary(summaryWrap, rule)

        if mutBadge.clickable then
            local mutBtn = Instance.new("TextButton")
            mutBtn.Name = "BtnMutCount"
            mutBtn.Parent = item
            mutBtn.BackgroundColor3 = Color3.fromRGB(52, 36, 78)
            mutBtn.Size = UDim2.new(0, mutW, 0, ROW_H - 8)
            mutBtn.Position = UDim2.new(1, -(delW + gap + mutW), 0.5, 0)
            mutBtn.AnchorPoint = Vector2.new(0, 0.5)
            mutBtn.AutoButtonColor = true
            mutBtn.Font = Enum.Font.GothamBold
            mutBtn.TextSize = 10
            mutBtn.TextColor3 = Color3.fromRGB(220, 175, 255)
            mutBtn.Text = "×" .. mutBadge.text
            mutBtn.BorderSizePixel = 0
            mkCorner(mutBtn, 5)
            mkStroke(mutBtn, Color3.fromRGB(160, 110, 220), 1, 0.25)

            mutBtn.MouseButton1Click:Connect(function()
                showMutationPopup(ui, mutBadge.muts, summaryPlain, profile.popupName)
            end)
        else
            local mutPill = Instance.new("Frame")
            mutPill.Name = "MutAny"
            mutPill.Parent = item
            mutPill.BackgroundColor3 = Color3.fromRGB(38, 38, 42)
            mutPill.Size = UDim2.new(0, mutW, 0, ROW_H - 8)
            mutPill.Position = UDim2.new(1, -(delW + gap + mutW), 0.5, 0)
            mutPill.AnchorPoint = Vector2.new(0, 0.5)
            mkCorner(mutPill, 5)
            mkStroke(mutPill, Color3.fromRGB(60, 60, 65), 1, 0.5)

            local mutLbl = Instance.new("TextLabel")
            mutLbl.BackgroundTransparency = 1
            mutLbl.Size = UDim2.new(1, 0, 1, 0)
            mutLbl.Font = Enum.Font.Gotham
            mutLbl.TextSize = 9
            mutLbl.TextXAlignment = Enum.TextXAlignment.Center
            mutLbl.TextYAlignment = Enum.TextYAlignment.Center
            mutLbl.TextColor3 = Color3.fromRGB(145, 145, 152)
            mutLbl.Text = "Any"
            mutLbl.Parent = mutPill
        end

        local del = Instance.new("TextButton")
        del.Name = "BtnDelete"
        del.Parent = item
        del.BackgroundColor3 = Color3.fromRGB(160, 40, 40)
        del.Size = UDim2.new(0, delW, 0, delW - 2)
        del.Position = UDim2.new(1, -delW, 0.5, 0)
        del.AnchorPoint = Vector2.new(0, 0.5)
        del.AutoButtonColor = true
        del.Font = Enum.Font.GothamBold
        del.TextSize = 14
        del.TextColor3 = Color3.fromRGB(255, 255, 255)
        del.Text = "-"
        del.BorderSizePixel = 0
        mkCorner(del, 4)
        mkStroke(del, Color3.fromRGB(40, 40, 40), 1, 0.6)

        del.MouseButton1Click:Connect(function()
            deleteRule(ruleId)
        end)
    end

    store.refreshSavedList = function()
        clearListRows()
        local q = norm(searchBox.Text or "")
        local allRules = currentRules()
        local shown = {}
        for i, rule in ipairs(allRules) do
            if q == "" or ruleSearchBlob(rule):find(q, 1, true) then
                shown[#shown + 1] = { index = i, rule = rule }
            end
        end

        listScroll.Size = UDim2.new(1, 0, 0, calcListHeight(#shown))

        if #shown == 0 then
            local empty = Instance.new("TextLabel")
            empty.Name = "EmptyHint"
            empty.BackgroundTransparency = 1
            empty.Size = UDim2.new(1, 0, 0, ROW_H)
            empty.Font = Enum.Font.Gotham
            empty.TextSize = 11
            empty.TextColor3 = Color3.fromRGB(140, 140, 140)
            empty.Text = (#allRules == 0)
                and "Belum ada rule — isi bulk lalu APPLY."
                or "Tidak ada rule cocok search."
            empty.Parent = listScroll
            return
        end

        for i, entry in ipairs(shown) do
            buildListRow(i, entry.rule)
        end
    end

    local searchDebounce = 0
    searchBox:GetPropertyChangedSignal("Text"):Connect(function()
        searchDebounce += 1
        local token = searchDebounce
        task.delay(0.15, function()
            if token ~= searchDebounce then return end
            updateSearchHint()
            if store.refreshSavedList then store.refreshSavedList() end
        end)
    end)

    store.refreshSavedList()
end

function M.RegisterBulk(ctx)
    if type(ctx) ~= "table" or type(ctx.ui) ~= "table" then return end
    local body = ctx.body
    if not body then return end
    local store = ensureStore(ctx)
    if store.bulkBuilt and store.bulkBody == body then
        refreshStoreModState(store)
        return
    end
    store.bulkBuilt = true
    store.bulkBody = body

    local ui = ctx.ui
    local MOD_STATE = store.MOD_STATE
    local bulk = store.bulk
    local persistRules = store.persistRules
    local syncRulesModule = store.syncRulesModule
    local profile = store.profile
    local cleanSelectedMap = ctx.cleanSelectedMap
    local mapToArray = ctx.mapToArray
    local PlantListView = ctx.PlantListView or G.PlantListView
    local registerFlush = ctx.registerFlush

    local fruitDropdownApi
    local mutDropdownApi
    local setKgInput
    local setPriceInput

    local function resetBulkUi()
        bulk.fruits = {}
        bulk.mutations = {}
        bulk.kgRule = "0"
        bulk.priceRule = "0"
        if type(fruitDropdownApi) == "table" and type(fruitDropdownApi.setSelected) == "function" then
            pcall(fruitDropdownApi.setSelected, {})
        end
        if type(mutDropdownApi) == "table" and type(mutDropdownApi.setSelected) == "function" then
            pcall(mutDropdownApi.setSelected, {})
        end
        if type(setKgInput) == "function" then pcall(setKgInput, "0") end
        if type(setPriceInput) == "function" then pcall(setPriceInput, "0") end
    end

    local function addRuleFromBulk()
        refreshStoreModState(store)
        local kg, kgMode = parseKgRule(bulk.kgRule)
        local minPrice, minPriceMode = parsePriceRule(bulk.priceRule)
        local fruits = mapToArray(cleanSelectedMap(bulk.fruits))
        local mutations = mapToArray(cleanSelectedMap(bulk.mutations))
        local rule = sanitizeRuleForPersist({
            id = newRuleId(profile.ruleIdPrefix),
            enabled = true,
            fruits = fruits,
            mutations = mutations,
            kg = kg,
            kgMode = kgMode,
            kgRule = bulk.kgRule,
            minPrice = minPrice,
            minPriceMode = minPriceMode,
            priceRule = bulk.priceRule,
            requireMut = false,
        })
        local st = store.MOD_STATE
        local nextRules = {}
        for _, r in ipairs(resolveRulesList(st)) do
            nextRules[#nextRules + 1] = sanitizeRuleForPersist(r)
        end
        nextRules[#nextRules + 1] = rule
        st.rules = nextRules
        st.rulesOrder = {}
        for _, r in ipairs(nextRules) do
            st.rulesOrder[#st.rulesOrder + 1] = r.id
        end
        local ok, err = pcall(function()
            store.persistRules(syncRulesModule)
        end)
        if not ok then
            warn("[GAG2-Rules] addRule persist error:", tostring(err))
        end
        if store.refreshSavedList then pcall(store.refreshSavedList) end
    end

    local function applyBulk()
        if store._applyBusy then return end
        store._applyBusy = true
        local ok, err = pcall(function()
            addRuleFromBulk()
            resetBulkUi()
        end)
        store._applyBusy = false
        if not ok then
            warn("[GAG2-Rules] applyBulk error:", tostring(err))
        end
    end

    _, fruitDropdownApi = ui:CreateRowDropdown(body, {
        label = "Rule Fruit",
        placeholder = "All Fruit...",
        mode = "multi",
        getItems = function()
            if PlantListView and type(PlantListView.buildFruitItems) == "function" then
                return PlantListView.buildFruitItems() or {}
            end
            return {}
        end,
        initial = bulk.fruits,
        onChanged = function(_, selectedMap)
            bulk.fruits = cleanSelectedMap(selectedMap)
        end,
    })

    _, mutDropdownApi = ui:CreateRowDropdown(body, {
        label = "Rule Mutation",
        placeholder = "All Mutation...",
        mode = "multi",
        deferItemLoad = true,
        getItems = function()
            if PlantListView and type(PlantListView.listFruitMutations) == "function" then
                return PlantListView.listFruitMutations() or {}
            end
            return {}
        end,
        initial = bulk.mutations,
        onChanged = function(_, selectedMap)
            bulk.mutations = cleanSelectedMap(selectedMap)
        end,
    })

    _, setKgInput = ui:CreateRowInput(body, "Rule KG (- below / + above)", bulk.kgRule, function(txt)
        bulk.kgRule = tostring(txt or "0")
    end, false)

    _, setPriceInput = ui:CreateRowInput(body, "Rule Price (- below / + above)", bulk.priceRule, function(txt)
        bulk.priceRule = tostring(txt or "0")
    end, false)

    if ui.CreateRowButton then
        ui:CreateRowButton(body, "APPLY → Add Rule", applyBulk)
    else
        ui:CreateRowToggle(body, "APPLY → Add Rule", false, function(isOn)
            if not isOn then return end
            applyBulk()
        end, nil, nil, 0.25)
    end

    if not store.flushRegistered and type(registerFlush) == "function" then
        store.flushRegistered = true
        registerFlush(profile.flushKey, function()
            store.pushGlobals()
            if store.refreshSavedList then store.refreshSavedList() end
        end)
    end
end

function M.Register(ctx)
    M.RegisterSavedList(ctx)
    M.RegisterBulk(ctx)
end

G.SectionAutoCollectRules = M
_G.SectionAutoCollectRules = M
G.SectionAutoFruitRules = M
_G.SectionAutoFruitRules = M

return M
 end,    required = false },
    { key = "SectionAutoBuyPet",       name = "Section Auto Buy Pet",    factory = function() -- section_auto_buy_pet.lua — UI Auto Buy Pet (target list: pet + variant + size)
-- Dipanggil dari tabs_auto.lua (tab Auto → Buy)

local RS = game:GetService("ReplicatedStorage")
local G = (getgenv and getgenv()) or _G
local M = {}

local function getFriendStealList()
    local mod = G.FriendStealList or rawget(_G, "FriendStealList")
    return type(mod) == "table" and mod or nil
end

local _typeItemsCache = nil
local _sizeItemsCache = nil
local DEFAULT_MAX_STEAL = 2
local MAX_STEAL_ROW_LABEL = "Max Steal (counted per steal, NOT price)"
local DEFAULT_MAX_STEAL_PRICE = 100000000
local STEAL_PRICE_MIN = 25000000
local STEAL_PRICE_MAX = 500000000
local STEAL_PRICE_STEP = 25000000

function M.normalizeMaxStealPrice(raw)
    local n = math.floor(tonumber(raw) or DEFAULT_MAX_STEAL_PRICE)
    n = math.floor((n + STEAL_PRICE_STEP / 2) / STEAL_PRICE_STEP) * STEAL_PRICE_STEP
    if n < STEAL_PRICE_MIN then n = STEAL_PRICE_MIN end
    if n > STEAL_PRICE_MAX then n = STEAL_PRICE_MAX end
    return n
end

function M.buildMaxStealPriceItems()
    local out = {}
    for n = STEAL_PRICE_MIN, STEAL_PRICE_MAX, STEAL_PRICE_STEP do
        out[#out + 1] = {
            key = tostring(n),
            name = string.format("%.0fM", n / 1000000),
            order = n,
        }
    end
    return out
end

local function normKey(s)
    return tostring(s or ""):lower():gsub("[%s_%-]+", "")
end

local function cleanMap(map)
    local out = {}
    if type(map) ~= "table" then return out end
    for k, v in pairs(map) do
        if v == true or v == 1 or v == "true" then
            local key = tostring(k)
            if key ~= "" and key ~= "_none" then
                out[key] = true
            end
        end
    end
    return out
end

local function mapFromList(list)
    local out = {}
    if type(list) ~= "table" then return out end
    if list[1] ~= nil then
        for _, v in ipairs(list) do
            local key = tostring(v or "")
            if key ~= "" then out[key] = true end
        end
        return out
    end
    return cleanMap(list)
end

local function mapToArray(map)
    local arr = {}
    for k, v in pairs(map or {}) do
        if v == true then arr[#arr + 1] = tostring(k) end
    end
    table.sort(arr)
    return arr
end

local function parseSteal(raw)
    if raw == true or raw == 1 or raw == "true" or raw == "1" then return true end
    if raw == false or raw == 0 or raw == "false" or raw == "0" then return false end
    return nil
end

local function parseMaxSteal(raw)
    local n = tonumber(raw)
    if not n or n < 1 then return nil end
    return math.floor(n + 0.499)
end

local function parseEnabled(raw)
    if raw == true or raw == 1 or raw == "true" or raw == "1" then return true end
    return false
end

function M.normalizeTarget(raw)
    if type(raw) ~= "table" then return nil end
    local pet = tostring(raw.pet or raw.name or raw.key or "")
    pet = pet:gsub("^%s+", ""):gsub("%s+$", "")
    if pet == "" then return nil end
    return {
        pet = pet,
        enabled = parseEnabled(raw.enabled),
        types = mapFromList(raw.types),
        sizes = mapFromList(raw.sizes),
        steal = parseSteal(raw.steal),
        max_steal = parseMaxSteal(raw.max_steal or raw.max_steal_mult),
    }
end

function M.normalizeTargets(list)
    local out = {}
    if type(list) ~= "table" then return out end
    local seen = {}
    for _, raw in ipairs(list) do
        local t = M.normalizeTarget(raw)
        if t and not seen[normKey(t.pet)] then
            seen[normKey(t.pet)] = true
            out[#out + 1] = t
        end
    end
    return out
end

function M.migrateFromSelected(selectedMap)
    local out = {}
    selectedMap = cleanMap(selectedMap)
    local keys = mapToArray(selectedMap)
    for _, pet in ipairs(keys) do
        out[#out + 1] = { pet = pet, enabled = false, types = {}, sizes = {}, steal = false }
    end
    return out
end

function M.anyTargetEnabled(targets)
    for _, t in ipairs(M.normalizeTargets(targets)) do
        if t.enabled == true then return true end
    end
    return false
end

function M.countEnabledTargets(targets)
    local n = 0
    for _, t in ipairs(M.normalizeTargets(targets)) do
        if t.enabled == true then n += 1 end
    end
    return n
end

function M.getEnabledTargets(targets)
    local out = {}
    for _, t in ipairs(M.normalizeTargets(targets)) do
        if t.enabled == true then out[#out + 1] = t end
    end
    return out
end

function M.targetsToSelected(targets)
    local out = {}
    for _, t in ipairs(M.normalizeTargets(targets)) do
        if t.enabled == true then
            out[t.pet] = true
        end
    end
    return out
end

function M.serializeTargets(targets)
    local out = {}
    for _, t in ipairs(M.normalizeTargets(targets)) do
        local row = {
            pet = t.pet,
            types = mapToArray(t.types),
            sizes = mapToArray(t.sizes),
        }
        if t.enabled == true then
            row.enabled = true
        end
        if t.steal == true or t.steal == false then
            row.steal = t.steal
        end
        if t.max_steal then
            row.max_steal = t.max_steal
        end
        out[#out + 1] = row
    end
    return out
end

function M.deserializeTargets(list)
    if type(list) ~= "table" then return {} end
    local out = {}
    for _, raw in ipairs(list) do
        local t = M.normalizeTarget(raw)
        if t then
            out[#out + 1] = t
        end
    end
    return out
end

local function labelFromMap(map, fallback)
    local arr = mapToArray(map)
    if #arr == 0 then return fallback or "Any" end
    if #arr == 1 then return arr[1] end
    if #arr <= 3 then return table.concat(arr, ", ") end
    return arr[1] .. " +" .. (#arr - 1)
end

function M.formatTargetSummary(t)
    t = M.normalizeTarget(t)
    if not t then return "" end
    local onLbl = t.enabled == true and " · ON" or " · OFF"
    local stealLbl = ""
    if t.steal == true then
        stealLbl = " · steal"
    elseif t.steal == false then
        stealLbl = " · buy only"
    end
    if t.max_steal then
        stealLbl = stealLbl .. string.format(" · max %d steals (not price)", t.max_steal)
    end
    return t.pet .. onLbl .. " · " .. labelFromMap(t.types, "Any") .. " · " .. labelFromMap(t.sizes, "Any") .. stealLbl
end

function M.formatTargetsSummary(targets, maxLines)
    targets = M.normalizeTargets(targets)
    maxLines = tonumber(maxLines) or 4
    if #targets == 0 then
        return "No targets — tap Add Pet"
    end
    local lines = {}
    for i, t in ipairs(targets) do
        if i <= maxLines then
            lines[#lines + 1] = "• " .. M.formatTargetSummary(t)
        end
    end
    if #targets > maxLines then
        lines[#lines + 1] = "• +" .. (#targets - maxLines) .. " more"
    end
    return table.concat(lines, "\n")
end

local function enumItems(mod, fallback)
    local out = {}
    if type(mod) == "table" then
        local keys = {}
        for name, val in pairs(mod) do
            if type(name) == "string" and type(val) == "number" and not name:match("^Get") then
                keys[#keys + 1] = name
            end
        end
        table.sort(keys)
        for _, name in ipairs(keys) do
            out[#out + 1] = { key = name, name = name }
        end
    end
    if #out == 0 and type(fallback) == "table" then
        for _, name in ipairs(fallback) do
            out[#out + 1] = { key = name, name = name }
        end
    end
    return out
end

function M.buildPetTypeItems()
    if _typeItemsCache then return _typeItemsCache end

    local mod
    pcall(function()
        local sd = RS:FindFirstChild("SharedData")
        local inst = sd and sd:FindFirstChild("PetTypes")
        if inst and inst:IsA("ModuleScript") then
            mod = require(inst)
        end
    end)

    local out = { { key = "Normal", name = "Normal" } }
    local seen = { [normKey("Normal")] = true }

    if type(mod) == "table" then
        local keys = {}
        for name, val in pairs(mod) do
            if type(name) == "string" and type(val) == "string"
                and not name:match("^Get") and name ~= "BOOST_MULTIPLIER" then
                keys[#keys + 1] = name
            end
        end
        table.sort(keys)
        for _, name in ipairs(keys) do
            local ck = normKey(name)
            if not seen[ck] then
                seen[ck] = true
                local display = name
                if type(mod.GetDisplayText) == "function" then
                    local ok, txt = pcall(mod.GetDisplayText, name)
                    if ok and type(txt) == "string" and txt ~= "" then
                        display = txt
                    end
                end
                out[#out + 1] = { key = name, name = display }
            end
        end
    end

    if not seen[normKey("Rainbow")] then
        out[#out + 1] = { key = "Rainbow", name = "RAINBOW" }
    end

    _typeItemsCache = out
    return _typeItemsCache
end

function M.resolvePetTypeRaw(raw)
    if raw == nil or raw == "" then return "Normal" end
    local petTypes
    pcall(function()
        local sd = RS:FindFirstChild("SharedData")
        local inst = sd and sd:FindFirstChild("PetTypes")
        if inst and inst:IsA("ModuleScript") then
            petTypes = require(inst)
        end
    end)
    if type(raw) == "number" then
        if type(petTypes) == "table" then
            for name, val in pairs(petTypes) do
                if type(name) == "string" and val == raw then
                    return name
                end
            end
        end
        return tostring(raw)
    end
    if type(raw) == "string" then
        local trimmed = raw:gsub("^%s+", ""):gsub("%s+$", "")
        if trimmed == "" then return "Normal" end
        if type(petTypes) == "table" then
            if type(petTypes.IsValid) == "function" then
                local ok, valid = pcall(petTypes.IsValid, trimmed)
                if ok and valid then return trimmed end
            end
            for name, val in pairs(petTypes) do
                if type(name) == "string" and type(val) == "string" and val == trimmed then
                    return name
                end
            end
        end
        if normKey(trimmed) == "rainbow" then return "Rainbow" end
        return trimmed
    end
    return "Normal"
end

function M.resolvePetSizeRaw(raw)
    if raw == nil or raw == "" then return "Normal" end
    local petSizes
    pcall(function()
        local sd = RS:FindFirstChild("SharedData")
        local inst = sd and sd:FindFirstChild("PetSizes")
        if inst and inst:IsA("ModuleScript") then
            petSizes = require(inst)
        end
    end)
    if type(raw) == "number" then
        if type(petSizes) == "table" then
            for name, val in pairs(petSizes) do
                if type(name) == "string" and val == raw then
                    return name
                end
            end
        end
        return tostring(raw)
    end
    if type(raw) == "string" then
        local trimmed = raw:gsub("^%s+", ""):gsub("%s+$", "")
        if trimmed == "" then return "Normal" end
        if type(petSizes) == "table" then
            if type(petSizes.IsValid) == "function" then
                local ok, valid = pcall(petSizes.IsValid, trimmed)
                if ok and valid then return trimmed end
            end
            for name, val in pairs(petSizes) do
                if type(name) == "string" and type(val) == "string" and val == trimmed then
                    return name
                end
            end
        end
        local lower = normKey(trimmed)
        if lower == "big" then return "Big" end
        if lower == "huge" then return "Huge" end
        if lower == "normal" then return "Normal" end
        return trimmed
    end
    return "Normal"
end

function M.typeMatchesRule(refType, allowedMap)
    if type(allowedMap) ~= "table" or not next(allowedMap) then return true end
    refType = M.resolvePetTypeRaw(refType)
    local canonRef = normKey(refType)
    if canonRef == "" then canonRef = "normal" end

    for k, on in pairs(allowedMap) do
        if on == true then
            local want = normKey(k)
            if want == "normal" then
                if canonRef == "normal" then return true end
            elseif want == "rainbow" then
                if canonRef == "rainbow" then return true end
            elseif want == canonRef then
                return true
            end
        end
    end
    return false
end

function M.sizeMatchesRule(refSize, allowedMap)
    if type(allowedMap) ~= "table" or not next(allowedMap) then return true end
    refSize = M.resolvePetSizeRaw(refSize)
    local canonRef = normKey(refSize or "Normal")
    if canonRef == "" then canonRef = "normal" end
    for k, on in pairs(allowedMap) do
        if on == true and normKey(k) == canonRef then return true end
    end
    return false
end

-- Variant vs size: kalau keduanya diisi = salah satu cukup (OR). Cuma satu filter = filter itu saja.
function M.variantSizeMatchesRule(typeRaw, sizeRaw, ruleTypes, ruleSizes)
    local hasTypes = type(ruleTypes) == "table" and next(ruleTypes)
    local hasSizes = type(ruleSizes) == "table" and next(ruleSizes)
    if not hasTypes and not hasSizes then return true end

    local typeOk = (not hasTypes) or M.typeMatchesRule(typeRaw, ruleTypes)
    local sizeOk = (not hasSizes) or M.sizeMatchesRule(sizeRaw, ruleSizes)

    if hasTypes and hasSizes then
        return typeOk or sizeOk
    end
    return typeOk and sizeOk
end

function M.buildPetSizeItems()
    if _sizeItemsCache then return _sizeItemsCache end
    local mod
    pcall(function()
        local sd = RS:FindFirstChild("SharedData")
        local inst = sd and sd:FindFirstChild("PetSizes")
        if inst and inst:IsA("ModuleScript") then
            mod = require(inst)
        end
    end)
    _sizeItemsCache = enumItems(mod, { "Normal", "Big", "Huge" })
    return _sizeItemsCache
end

function M.Register(ctx)
    if type(ctx) ~= "table" or type(ctx.ui) ~= "table" then return end

    local ui = ctx.ui
    local getStore = ctx.getStore
    local patchStore = ctx.patchStore
    local readEnabled = ctx.readEnabled
    local applyRuntime = ctx.applyRuntime
    local registerFlush = ctx.registerFlush
    local PetListView = ctx.PetListView or G.PetListView or rawget(_G, "PetListView")

    if type(getStore) ~= "function" or type(patchStore) ~= "function" then
        warn("[GAG2] SectionAutoBuyPet: missing getStore/patchStore")
        return
    end

    local store = getStore()
    store.targets = M.normalizeTargets(store.targets)
    if #store.targets == 0 and type(store.selected) == "table" and next(store.selected) then
        store.targets = M.migrateFromSelected(store.selected)
    end
    if store.enabled == true and store._legacyGlobalMigrated ~= true then
        for _, t in ipairs(store.targets) do
            if t.enabled ~= true then
                t.enabled = true
            end
        end
        store._legacyGlobalMigrated = true
        store.enabled = false
    end
    store.max_steal_price = M.normalizeMaxStealPrice(store.max_steal_price)

    local targets = store.targets
    local rowApis = {}
    local rowUi = {}

    local function syncTargetsRef(nextTargets)
        targets = nextTargets
        store.targets = targets
    end

    local function resolvePetIcon(petKey)
        if PetListView and type(PetListView.getPetIcon) == "function" then
            return PetListView.getPetIcon(petKey)
        end
        return nil
    end

    local function attachPetIcon(parent, petKey, size, xOffset)
        local icon = resolvePetIcon(petKey)
        if not icon or icon == "" then return nil end
        size = size or 18
        xOffset = xOffset or 0
        local img = Instance.new("ImageLabel")
        img.Name = "PetIcon"
        img.BackgroundTransparency = 1
        img.Size = UDim2.new(0, size, 0, size)
        img.Position = UDim2.new(0, xOffset, 0.5, -math.floor(size / 2))
        img.Image = icon
        img.ScaleType = Enum.ScaleType.Fit
        img.ZIndex = (parent.ZIndex or 1) + 1
        img.Parent = parent
        return img
    end

    local function anyTargetEnabled()
        return M.anyTargetEnabled(targets)
    end

    local function commitTargets(syncRuntime)
        local normalized = M.normalizeTargets(targets)
        syncTargetsRef(normalized)
        store.selected = M.targetsToSelected(store.targets)
        local runtimeOn = anyTargetEnabled()
        patchStore({
            enabled = runtimeOn,
            targets = M.serializeTargets(store.targets),
            selected = store.selected,
        }, function()
            if syncRuntime ~= false and type(applyRuntime) == "function" then
                applyRuntime(runtimeOn)
            end
        end)
    end

    local bodyPet = ui:CreateSection("Auto Buy Pet", false)

    local listWrap = Instance.new("Frame")
    listWrap.Name = "BuyPetTargetList"
    listWrap.BackgroundTransparency = 1
    listWrap.Size = UDim2.new(1, 0, 0, 0)
    listWrap.AutomaticSize = Enum.AutomaticSize.Y
    listWrap.LayoutOrder = 4
    listWrap.Parent = bodyPet

    local listLayout = Instance.new("UIListLayout")
    listLayout.FillDirection = Enum.FillDirection.Vertical
    listLayout.SortOrder = Enum.SortOrder.LayoutOrder
    listLayout.Padding = UDim.new(0, 6)
    listLayout.Parent = listWrap

    local scroll = Instance.new("Frame")
    scroll.Name = "TargetScroll"
    scroll.BackgroundColor3 = Color3.fromRGB(12, 12, 12)
    scroll.BackgroundTransparency = 0.15
    scroll.BorderSizePixel = 0
    scroll.Size = UDim2.new(1, 0, 0, 0)
    scroll.AutomaticSize = Enum.AutomaticSize.Y
    scroll.LayoutOrder = 1
    scroll.Parent = listWrap

    local scrollCorner = Instance.new("UICorner")
    scrollCorner.CornerRadius = UDim.new(0, 6)
    scrollCorner.Parent = scroll

    local scrollStroke = Instance.new("UIStroke")
    scrollStroke.Color = Color3.fromRGB(40, 40, 40)
    scrollStroke.Transparency = 0.5
    scrollStroke.Parent = scroll

    local scrollPad = Instance.new("UIPadding")
    scrollPad.PaddingTop = UDim.new(0, 4)
