function M.GetLists()
    local PlantListView = G.PlantListView
    local ShopListView = G.ShopListView
    local seeds, gears, props = {}, {}, {}

    if type(PlantListView) == "table" and type(PlantListView.buildSeedItems) == "function" then
        seeds = PlantListView.buildSeedItems() or {}
    end
    if type(ShopListView) == "table" then
        if type(ShopListView.buildGearItems) == "function" then
            gears = ShopListView.buildGearItems() or {}
        end
        if type(ShopListView.buildPropsItems) == "function" then
            props = ShopListView.buildPropsItems() or {}
        end
    end

    return seeds, gears, props
end

function M.GetSeedStock(itemName)
    if not itemName then return 0 end
    return _getLiveStockCount("seed", tostring(itemName)) or 0
end

function M.GetAllSeedStocks()
    local stocks, ok = _collectLiveStocks("seed")
    return stocks, ok
end

function M.GetStock(catKey, itemName)
    catKey = tostring(catKey or "seed"):lower()
    if itemName then
        return _getLiveStockCount(catKey, tostring(itemName)) or 0
    end
    local stocks = select(1, _collectLiveStocks(catKey))
    return stocks
end

function M.GetRemotePath(catKey)
    catKey = tostring(catKey or "seed"):lower()
    local _, path = _ensureRemote(catKey)
    return path
end

function M.GetDiagnostics()
    local seedRemote, seedPath = _ensureRemote("seed")
    local gearRemote, gearPath = _ensureRemote("gear")
    local propsRemote, propsPath = _ensureRemote("props")
    local stocks, hasStock = _collectLiveStocks("seed")

    local sampleStock = {}
    if type(stocks) == "table" then
        local n = 0
        for name, count in pairs(stocks) do
            n += 1
            sampleStock[name] = count
            if n >= 5 then break end
        end
    end

    return {
        moduleLoaded = true,
        remotes = {
            seed  = { ok = seedRemote ~= nil,  path = seedPath },
            gear  = { ok = gearRemote ~= nil,  path = gearPath },
            props = { ok = propsRemote ~= nil, path = propsPath },
        },
        stockValues = {
            seedShop = hasStock,
            sample = sampleStock,
            blueberry = _getLiveStockCount("seed", "Blueberry") or 0,
        },
        poll = {
            afterBuySec = AFTER_BUY_SEC,
            stockPollSec = STOCK_POLL_SEC,
            noMoneyPollSec = _noMoneyPollSec(),
            noStockPollSec = _noStockPollSec(),
        },
        money = {
            sheckles = _getMoney(),
            skipCheck = _skipMoneyCheck(),
            pausedItems = (function()
                local n = 0
                for _, untilAt in pairs(_brokeItems) do
                    if type(untilAt) == "number" and os.clock() < untilAt then
                        n += 1
                    end
                end
                return n
            end)(),
        },
        state = getBuyState(),
        hint = (not seedRemote) and "Networking.SeedShop.PurchaseSeed tidak ditemukan — reload script"
            or "Uang kurang → pause "
                .. tostring(_noMoneyPollSec()) .. "s; restock watcher + fallback scan"
    }
end

function M.SyncFromGlobals()
    local st = getBuyState()
    G.AUTO_BUY_SEED_ENABLED = st.seedEnabled
    G.AUTO_BUY_GEAR_ENABLED = st.gearEnabled
    G.AUTO_BUY_PROPS_ENABLED = st.propsEnabled
    _G.AUTO_BUY_SEED_ENABLED = st.seedEnabled
    _G.AUTO_BUY_GEAR_ENABLED = st.gearEnabled
    _G.AUTO_BUY_PROPS_ENABLED = st.propsEnabled

    G.BUY_SEED_SELECTED = st.seedSelected
    G.BUY_GEAR_SELECTED = st.gearSelected
    G.BUY_PROPS_SELECTED = st.propsSelected
    _G.BUY_SEED_SELECTED = st.seedSelected
    _G.BUY_GEAR_SELECTED = st.gearSelected
    _G.BUY_PROPS_SELECTED = st.propsSelected
end

M.syncFromGlobals = M.SyncFromGlobals

function M.SetEnabled(cat, on)
    cat = tostring(cat or ""):lower()
    on = (on == true)

    if cat == "seed" or cat == "seeds" then
        G.AUTO_BUY_SEED_ENABLED = on
        _G.AUTO_BUY_SEED_ENABLED = on
        _writeMainBuy({ seed = { enabled = on, items = _setToArray(getBuyState().seedSelected) } })
    elseif cat == "gear" or cat == "gears" then
        G.AUTO_BUY_GEAR_ENABLED = on
        _G.AUTO_BUY_GEAR_ENABLED = on
        _writeMainBuy({ gear = { enabled = on, items = _setToArray(getBuyState().gearSelected) } })
    elseif cat == "props" or cat == "prop" then
        G.AUTO_BUY_PROPS_ENABLED = on
        _G.AUTO_BUY_PROPS_ENABLED = on
        _writeMainBuy({ props = { enabled = on, items = _setToArray(getBuyState().propsSelected) } })
    end

    if on then
        M.Start()
    else
        local st = getBuyState()
        if not st.seedEnabled and not st.gearEnabled and not st.propsEnabled then
            M.Stop()
        end
    end
end

function M.SetSelected(cat, map)
    cat = tostring(cat or ""):lower()
    map = _normalizeSet(map)

    if cat == "seed" or cat == "seeds" then
        G.BUY_SEED_SELECTED = map
        _G.BUY_SEED_SELECTED = map
        _writeMainBuy({ seed = { enabled = getBuyState().seedEnabled, items = _setToArray(map) } })
    elseif cat == "gear" or cat == "gears" then
        G.BUY_GEAR_SELECTED = map
        _G.BUY_GEAR_SELECTED = map
        _writeMainBuy({ gear = { enabled = getBuyState().gearEnabled, items = _setToArray(map) } })
    elseif cat == "props" or cat == "prop" then
        G.BUY_PROPS_SELECTED = map
        _G.BUY_PROPS_SELECTED = map
        _writeMainBuy({ props = { enabled = getBuyState().propsEnabled, items = _setToArray(map) } })
    end
    _watchSig = ""
end

function M.Start()
    _clearBroke()
    if not running then
        running = true
        loopId += 1
        local myId = loopId
        task.spawn(function() buyLoop(myId) end)
    end
end

M.start = M.Start

function M.Stop()
    running = false
    _clearWatchers()
    _clearMoneyWatch()
end

M.stop = M.Stop

function M.IsRunning()
    return running == true
end

function M.SyncFromState()
    M.SyncFromGlobals()
    local st = getBuyState()
    if st.seedEnabled or st.gearEnabled or st.propsEnabled then
        M.Start()
    else
        M.Stop()
    end
end

M.syncFromState = M.SyncFromState

function M.ClearBroke()
    _clearBroke()
end

function M.BuyOnce()
    return buyTick(getBuyState())
end

M.buyOnce = M.BuyOnce

G.AutoBuyModule = M
G.AutoBuy = M
_G.AutoBuyModule = M
_G.AutoBuy = M

pcall(function() M.SyncFromState() end)

return M
 end,                        required = false },
    { key = "Webhook",                 name = "Webhook",                 factory = function() -- Webhook.lua v2 — POST panel ke webhook.php (Discord embed)
-- Payload: event + player + petName + rarity + price + panel (tanpa fields/embed/blob)

local HttpService = game:GetService("HttpService")
local Players = game:GetService("Players")
local LP = Players.LocalPlayer
local G = (getgenv and getgenv()) or _G
local M = {}

M.VERSION = "2.4"

local function isNormalTrait(value)
    value = tostring(value or ""):lower():gsub("^%s+", ""):gsub("%s+$", "")
    return value == "" or value == "normal"
end

function M.formatPetDisplayName(baseName, petType, petSize)
    baseName = tostring(baseName or "")
    local extras = {}
    if not isNormalTrait(petType) then
        extras[#extras + 1] = tostring(petType)
    end
    if not isNormalTrait(petSize) then
        extras[#extras + 1] = tostring(petSize)
    end
    if #extras == 0 then
        return baseName
    end
    return baseName .. " ( " .. table.concat(extras, " , ") .. " )"
end

local API_URL = "https://golas.co.id/grow_a_garden25353466689966/webhook.php"

local function apiUrl()
    local u = G.WEBHOOK_API_URL or _G.WEBHOOK_API_URL
    if type(u) == "string" and u ~= "" then
        return u
    end
    return API_URL
end

local function getRequest()
    return (syn and syn.request)
        or (http and http.request)
        or http_request
        or (fluxus and fluxus.request)
        or request
end

local function httpPost(url, data)
    local req = getRequest()
    if not req then
        return false, "no_http"
    end

    local headers = { ["Content-Type"] = "application/json" }
    local key = G.WEBHOOK_API_KEY or _G.WEBHOOK_API_KEY
    if type(key) == "string" and key ~= "" then
        headers["X-API-Key"] = key
    end

    local body = HttpService:JSONEncode(data)
    local ok, res = pcall(function()
        return req({
            Url = url,
            Method = "POST",
            Headers = headers,
            Body = body,
        })
    end)
    if not ok then
        return false, tostring(res)
    end

    local code = res.StatusCode or res.status or 0
    local text = res.Body or res.body or ""
    if code < 200 or code >= 300 then
        return false, ("HTTP %d: %s"):format(code, text:sub(1, 200))
    end

    if text == "" then
        return true, { ok = true }
    end
    local okJson, parsed = pcall(function()
        return HttpService:JSONDecode(text)
    end)
    if okJson and type(parsed) == "table" then
        return true, parsed
    end
    return true, { ok = true }
end

local function maskName(name)
    name = tostring(name or "")
    local len = #name
    if len == 0 then return "***" end
    if len <= 2 then return name:sub(1, 1) .. "*" end
    local half = math.max(1, math.floor(len / 2))
    return name:sub(1, half) .. string.rep("*", len - half)
end

local function buildPanel(player, basePetName, rarity, price, petType, petSize)
    local priceText = "-"
    local n = tonumber(price)
    if n and n > 0 then
        priceText = tostring(math.floor(n))
    end
    local lines = {
        "**Profile**",
        "| Username : " .. maskName(player),
        "",
        "**Pet Details**",
        "| Pet : " .. tostring(basePetName),
    }
    if not isNormalTrait(petType) then
        lines[#lines + 1] = "| Variant : " .. tostring(petType)
    end
    if not isNormalTrait(petSize) then
        lines[#lines + 1] = "| Size : " .. tostring(petSize)
    end
    lines[#lines + 1] = "| Rarity : " .. tostring(rarity)
    lines[#lines + 1] = "| Price : " .. priceText
    return table.concat(lines, "\n")
end

local function isBad(s)
    s = tostring(s or "")
    return s == "" or s == "Unknown"
end

function M.Send(data)
    if type(data) ~= "table" then
        return false, "bad_args"
    end
    return httpPost(apiUrl(), data)
end

--- Kirim notifikasi pet buy. Arg: { player, petName, petKey, petType, petSize, rarity, price }
function M.SendPetBuy(info)
    if type(info) ~= "table" then
        return false, "bad_args"
    end

    local player = tostring(info.player or LP.Name)
    local petKey = tostring(info.petKey or info.pet or "")
    local basePetName = tostring(info.petName or info.pet or "")
    local petType = info.petType or info.pet_type
    local petSize = info.petSize or info.pet_size
    local petName = M.formatPetDisplayName(basePetName, petType, petSize)
    local rarity = tostring(info.rarity or info.Rarity or info.r or "")
    local price = math.floor(tonumber(info.price) or 0)

    if isBad(basePetName) and isBad(petName) then
        return false, "no_pet"
    end
    if isBad(rarity) then
        return false, "no_rarity"
    end

    local panel = buildPanel(player, basePetName, rarity, price, petType, petSize)

    return M.Send({
        event = "PET_BUY",
        player = player,
        petName = petName,
        petKey = (petKey ~= "" and petKey) or basePetName,
        petType = isNormalTrait(petType) and nil or tostring(petType),
        petSize = isNormalTrait(petSize) and nil or tostring(petSize),
        pt = isNormalTrait(petType) and nil or tostring(petType),
        ps = isNormalTrait(petSize) and nil or tostring(petSize),
        rarity = rarity,
        price = price,
        panel = panel,
        luaVer = M.VERSION,
    })
end

function M.LoadFromUrl(url)
    url = url or G.WEBHOOK_MODULE_URL or _G.WEBHOOK_MODULE_URL
    if type(url) ~= "string" or url == "" then
        return false, "no_url"
    end
    if not url:find("^https?://", 1) then
        url = "https://" .. url
    end

    local req = getRequest()
    local body
    if req then
        local res = req({ Url = url, Method = "GET" })
        body = res and (res.Body or res.body)
    else
        body = game:HttpGet(url)
    end
    if type(body) ~= "string" or body == "" or body:sub(1, 1) == "<" then
        return false, "not_lua"
    end

    body = body:gsub("^%EF%BB%BF", "")
    local fn, err
    if load then
        fn, err = load(body, "webhook", "t", getgenv() or _G)
    end
    if type(fn) ~= "function" and loadstring then
        fn, err = loadstring(body, "webhook")
    end
    if type(fn) ~= "function" then
        return false, err or "compile_fail"
    end

    local ok, mod = pcall(fn)
    if not ok or type(mod) ~= "table" then
        return false, mod or "run_fail"
    end

    G.Webhook = mod
    G.WebhookModule = mod
    _G.Webhook = mod
    _G.WebhookModule = mod
    return true, mod
end

G.Webhook = M
G.WebhookModule = M
_G.Webhook = M
_G.WebhookModule = M

return M
 end,                       required = false },
    { key = "AutoBuyPet",              name = "Auto Buy Pet",            factory = function() -- AutoBuyPet.lua — Grow A Garden 2
-- Simple: pause Auto Tele → garden → TP bawah pet (Y-7) → WildPetTame:Fire → sukses → garden → resume Auto Tele
-- Tanpa BuyPrompt. Webhook setelah pet sampai garden (hilang dari WildPetRef).

local Players           = game:GetService("Players")
local ReplicatedStorage = game:GetService("ReplicatedStorage")

local LP = Players.LocalPlayer
local G  = (getgenv and getgenv()) or _G
local M  = {}

local WildPetTame, WildPetTameResult

local function _ensureNetworking()
    if WildPetTame and WildPetTameResult then return true end
    local ok, net = pcall(function()
        return require(ReplicatedStorage:WaitForChild("SharedModules", 10):WaitForChild("Networking", 10))
    end)
    if ok and type(net) == "table" and type(net.Pets) == "table" then
        WildPetTame = net.Pets.WildPetTame
        WildPetTameResult = net.Pets.WildPetTameResult
    end
    return WildPetTame ~= nil
end

local SCAN_SEC        = 0.2
local UNDER_Y         = -7
local BUY_RANGE       = 11
local FIRE_SEC        = 0.12
local STEAL_FIRE_SEC  = 0.05
local STICK_SEC       = 0.05
local BUY_GAP         = 0.5
local GARDEN_TP_OFFSET = Vector3.new(0, 3, 0)
local GARDEN_WAIT     = 0.2

local running         = false
local loopId          = 0
local wildFolder      = nil
local boundFolder     = nil
local childConn       = nil
local mapConn         = nil
local activeSelected  = {}
local buyBusy         = false
local lastBuyEndAt    = 0
local teleWasOn       = false
local telePaused      = false
local refLastPrice    = {}
local refBasePrice    = {}
local freshWildLearned = {}
local WILD_FRESH_SHOP_MULT = 3
local stealSuccessByPet = {}
local DEFAULT_MAX_STEAL = 2
local DEFAULT_MAX_PRICE_MULT = 5
local DEFAULT_MAX_STEAL_PRICE = 100000000
local STEAL_PRICE_MIN = 25000000
local STEAL_PRICE_MAX = 500000000
local STEAL_PRICE_STEP = 25000000
local lastWebhookTame = nil
local webhookSentKeys = {}
local webhookPending = {}
local WEBHOOK_GARDEN_WAIT_SEC = 90
local WEBHOOK_GARDEN_POLL_SEC = 0.15
local PetDataCache    = nil
local PetTypesCache   = nil
local PetSizesCache   = nil

local stats = { attempts = 0, fired = 0, ok = 0, fail = 0 }

local DEBUG_FIRE_EVERY = 10
local debugOn = false

----------------------------------------------------------------
-- debug
----------------------------------------------------------------
local function _truthyDebug(v)
    return v == true or v == 1 or v == "true" or v == "1" or v == "on" or v == "ON"
end

local function _syncDebugFlag(on)
    on = (on == true)
    debugOn = on
    G.AUTO_BUY_PET_DEBUG = on
    _G.AUTO_BUY_PET_DEBUG = on
    local ge = (getgenv and getgenv()) or nil
    if type(ge) == "table" then
        ge.AUTO_BUY_PET_DEBUG = on
    end
    local s = _getStore and _getStore() or nil
    if type(s) == "table" then
        s.debug = on
        G.__GAG2_BUY_PET = s
        _G.__GAG2_BUY_PET = s
    end
end

local function _restoreDebug()
    local ge = (getgenv and getgenv()) or nil
    local on = _truthyDebug(G.AUTO_BUY_PET_DEBUG)
        or _truthyDebug(rawget(_G, "AUTO_BUY_PET_DEBUG"))
        or (type(ge) == "table" and _truthyDebug(ge.AUTO_BUY_PET_DEBUG))
    if not on then
        local s = _getStore and _getStore() or nil
        if type(s) == "table" then
            on = _truthyDebug(s.debug)
        end
    end
    if on then
        _syncDebugFlag(true)
    end
end

local function _dbg()
    if debugOn then return true end
    if _truthyDebug(G.AUTO_BUY_PET_DEBUG) then return true end
    if _truthyDebug(rawget(_G, "AUTO_BUY_PET_DEBUG")) then return true end
    local ge = (getgenv and getgenv()) or nil
    if type(ge) == "table" and _truthyDebug(ge.AUTO_BUY_PET_DEBUG) then return true end
    local s = _getStore and _getStore() or nil
    return type(s) == "table" and s.debug == true
end

local function _log(...)
    if _dbg() then print("[GAG2-BuyPet]", ...) end
end

----------------------------------------------------------------
-- Store / settings
----------------------------------------------------------------
local function _normalizeSet(src)
    if type(src) ~= "table" then return {} end
    local out = {}
    for i = 1, #src do
        local v = src[i]
        if v ~= nil and tostring(v) ~= "" then out[tostring(v)] = true end
    end
    if next(out) then return out end
    for k, v in pairs(src) do
        if v == true or v == 1 or v == "true" then out[tostring(k)] = true end
    end
    return out
end

local function _setToArray(map)
    local out = {}
    if type(map) ~= "table" then return out end
    for k, v in pairs(map) do
        if v == true then out[#out + 1] = tostring(k) end
    end
    table.sort(out)
    return out
end

local function _hasAnySelected(map)
    if type(map) ~= "table" then return false end
    for _, v in pairs(map) do
        if v == true then return true end
    end
    return false
end

local function _getStore()
    local s = G.__GAG2_BUY_PET or rawget(_G, "__GAG2_BUY_PET")
    return type(s) == "table" and s or nil
end

local function _ensureStore()
    local s = _getStore()
    if type(s) == "table" then return s end
    s = { enabled = false, auto_tame = false, max_steal_price = DEFAULT_MAX_STEAL_PRICE, selected = {} }
    G.__GAG2_BUY_PET = s
    _G.__GAG2_BUY_PET = s
    return s
end

local function _patchStore(patch)
    if type(patch) ~= "table" then return end
    local s = _ensureStore()
    if patch.enabled ~= nil then s.enabled = patch.enabled == true end
    if patch.auto_tame ~= nil then s.auto_tame = patch.auto_tame == true end
    if patch.max_steal_price ~= nil then
        s.max_steal_price = _clampMaxStealPrice(patch.max_steal_price)
    end
    if patch.selected ~= nil then s.selected = _normalizeSet(patch.selected) end
    if patch.debug ~= nil then s.debug = _truthyDebug(patch.debug) end
    G.__GAG2_BUY_PET = s
    _G.__GAG2_BUY_PET = s
end

local function _readMainPet()
    local MAIN = G.MAIN or rawget(_G, "MAIN")
    if type(MAIN) == "table" and type(MAIN.auto) == "table"
        and type(MAIN.auto.buy) == "table" and type(MAIN.auto.buy.pet) == "table" then
        return MAIN.auto.buy.pet
    end
    return nil
end

local function _normalizeTargetRules(raw)
    if type(raw) ~= "table" or #raw <= 0 then return nil end
    local SectionBuyPet = G.SectionAutoBuyPet or rawget(_G, "SectionAutoBuyPet")
    if type(SectionBuyPet) == "table" and type(SectionBuyPet.normalizeTargets) == "function" then
        return SectionBuyPet.normalizeTargets(raw)
    end
    return raw
end

local function _selectedFromEnabledTargets()
    local s = _getStore()
    local raw = type(s) == "table" and s.targets or nil
    if type(raw) ~= "table" or #raw <= 0 then
        raw = G.BUY_PET_TARGETS or rawget(_G, "BUY_PET_TARGETS")
    end
    if type(raw) ~= "table" or #raw <= 0 then
        local pet = _readMainPet()
        raw = pet and pet.targets
    end
    if type(raw) ~= "table" or #raw <= 0 then return nil end

    local rules = _normalizeTargetRules(raw)
    if not rules then return nil end
    local out = {}
    for _, rule in ipairs(rules) do
        if type(rule) == "table" and rule.enabled == true and rule.pet then
            out[tostring(rule.pet)] = true
        end
    end
    return out
end

local function _selected()
    local fromTargets = _selectedFromEnabledTargets()
    if fromTargets ~= nil then
        return fromTargets
    end

    local s = _getStore()
    if type(s) == "table" and type(s.selected) == "table" and next(s.selected) then
        return _normalizeSet(s.selected)
    end
    local pet = _readMainPet()
    if pet and type(pet.items) == "table" and next(pet.items) then
        return _normalizeSet(pet.items)
    end
    local map = G.BUY_PET_SELECTED or rawget(_G, "BUY_PET_SELECTED")
    if type(map) == "table" and next(map) then return _normalizeSet(map) end
    local legacy = rawget(_G, "GAG2_PET_LIST")
    if type(legacy) == "table" and #legacy > 0 then return _normalizeSet(legacy) end
    return {}
end

local function _getActiveSelected()
    activeSelected = _selected()
    return activeSelected
end

-- Fresh-buy price cap: base × mult. No UI/save — constant lives here only.
local function _getMaxPriceMult()
    return DEFAULT_MAX_PRICE_MULT
end

local function _clampMaxStealPrice(n)
    n = math.floor(tonumber(n) or DEFAULT_MAX_STEAL_PRICE)
    n = math.floor((n + STEAL_PRICE_STEP / 2) / STEAL_PRICE_STEP) * STEAL_PRICE_STEP
    if n < STEAL_PRICE_MIN then n = STEAL_PRICE_MIN end
    if n > STEAL_PRICE_MAX then n = STEAL_PRICE_MAX end
    return n
end

local function _getMaxStealPrice()
    local s = _getStore()
    if type(s) == "table" then
        local n = tonumber(s.max_steal_price)
        if n and n > 0 then return _clampMaxStealPrice(n) end
    end
    local n = tonumber(G.AUTO_BUY_PET_MAX_STEAL_PRICE) or tonumber(rawget(_G, "AUTO_BUY_PET_MAX_STEAL_PRICE"))
    if n and n > 0 then return _clampMaxStealPrice(n) end
    local pet = _readMainPet()
    n = pet and tonumber(pet.max_steal_price)
    if n and n > 0 then return _clampMaxStealPrice(n) end
    return DEFAULT_MAX_STEAL_PRICE
end

local function _withinMaxStealPrice(ref)
    local price = tonumber(ref and ref:GetAttribute("Price")) or 0
    if price <= 0 then return true end
    return price <= _getMaxStealPrice()
end

local function _isModuleCall(first)
    return type(first) == "table" and type(first.Start) == "function"
end

local function _boolArg(a, b)
    if _isModuleCall(a) then return b == true end
    return a == true
end

local function _secondArg(a, b)
    if _isModuleCall(a) then return b end
    return a
end

----------------------------------------------------------------
-- Auto Tele: stop sebelum follow pet, start lagi setelah beli
----------------------------------------------------------------
local function _getAutoTeleMod()
    return G.AutoTele or rawget(_G, "AutoTele")
end

local function _teleIsOn()
    local mod = _getAutoTeleMod()
    if type(mod) == "table" and type(mod.IsEnabled) == "function" then
        return mod.IsEnabled() == true
    end
    local s = rawget(_G, "__GAG2_AUTO_TELE") or G.__GAG2_AUTO_TELE
    if type(s) == "table" then return s.enabled == true end
    return G.AUTO_TELE_ENABLED == true or rawget(_G, "AUTO_TELE_ENABLED") == true
end

local function _teleWasRunning()
    local mod = _getAutoTeleMod()
    if type(mod) == "table" and type(mod.IsRunning) == "function" then
        return mod.IsRunning() == true
    end
    return false
end

local function _setBuyBusy(on)
    buyBusy = (on == true)
    G.__GAG2_AUTO_BUY_PET_BUSY = buyBusy
    _G.__GAG2_AUTO_BUY_PET_BUSY = buyBusy
end

local function _teleStopForBuy()
    teleWasOn = _teleIsOn() and _teleWasRunning()
    if not teleWasOn then
        telePaused = false
        _log("tele pause skip (auto tele off)")
        return
    end
    telePaused = true
    G.__GAG2_AUTO_TELE_SUPPRESS = true
    _G.__GAG2_AUTO_TELE_SUPPRESS = true
    _log("tele paused for buy/tame")
    local mod = _getAutoTeleMod()
    if type(mod) == "table" and type(mod.Stop) == "function" then
        pcall(mod.Stop, mod)
    end
end

local function _teleResumeNow()
    if not teleWasOn then
        telePaused = false
        return
    end
    telePaused = false
    teleWasOn = false
    G.__GAG2_AUTO_TELE_SUPPRESS = false
    _G.__GAG2_AUTO_TELE_SUPPRESS = false
    _log("tele resumed")
    local mod = _getAutoTeleMod()
    if type(mod) == "table" and type(mod.IsEnabled) == "function" and mod.IsEnabled() then
        if type(mod.Start) == "function" then pcall(mod.Start, mod) end
    end
end

local function _teleKeepPaused()
    if not teleWasOn then return end
    telePaused = true
    G.__GAG2_AUTO_TELE_SUPPRESS = true
    _G.__GAG2_AUTO_TELE_SUPPRESS = true
end

----------------------------------------------------------------
-- Character / pet ref
----------------------------------------------------------------
local function _getHRP()
    local ch = LP.Character
    if not ch then return nil end
    local hrp = ch:FindFirstChild("HumanoidRootPart")
    return hrp and hrp:IsA("BasePart") and hrp or nil
end

local function _canonPet(s)
    return tostring(s or ""):lower():gsub("[%s_%-]+", "")
end

local function _getSkipStealFriends()
    local s = _getStore()
    if type(s) == "table" and type(s.skip_steal_friends) == "table" then
        return s.skip_steal_friends
    end
    local pet = _readMainPet()
    if pet and type(pet.skip_steal_friends) == "table" then
        return pet.skip_steal_friends
    end
    return {}
end

local function _shouldSkipStealOwner(ownerUserId)
    ownerUserId = tonumber(ownerUserId)
    if not ownerUserId or ownerUserId <= 0 then return false end
    local list = _getSkipStealFriends()
    if type(list) ~= "table" or #list <= 0 then return false end
    local FSL = G.FriendStealList or rawget(_G, "FriendStealList")
    if type(FSL) == "table" and type(FSL.isSkipOwner) == "function" then
        return FSL.isSkipOwner(ownerUserId, list) == true
    end
    for _, row in ipairs(list) do
        if type(row) == "table" and tonumber(row.userId) == ownerUserId then
            return true
        end
    end
    return false
end

local function _getOwnerUserId(ref)
    if not ref then return nil end
    local v = ref:GetAttribute("OwnerUserId")
    if v ~= nil then
        local n = tonumber(v)
        if n and n ~= 0 then
            return n
        end
    end
    return nil
end

local function _refKey(ref) return ref and tostring(ref.Name) or "" end

local function _getWildRefFolder()
    if wildFolder and wildFolder.Parent then return wildFolder end
    local map = workspace:FindFirstChild("Map")
    if not map then return nil end
    local ref = map:FindFirstChild("WildPetRef")
    if ref and ref:IsA("Folder") then wildFolder = ref end
    return wildFolder
end

local function _isWildPetRef(ref)
    if not ref or not ref.Parent then return false end
    local folder = _getWildRefFolder()
    return folder ~= nil and ref.Parent == folder
end

local function _getTargetPos(ref)
    local suffix = _refKey(ref)
    local spawns = workspace:FindFirstChild("Map") and workspace.Map:FindFirstChild("WildPetSpawns")
    if spawns and suffix ~= "" then
        for _, m in ipairs(spawns:GetChildren()) do
            if m:IsA("Model") and m.Name:sub(-#suffix) == suffix then
                local p = m.PrimaryPart or m:FindFirstChildWhichIsA("BasePart")
                if p then return p.Position end
            end
        end
    end
    return ref.Position
end

local function _tpUnder(ref)
    local h = _getHRP()
    if not h then return end
    local target = _getTargetPos(ref)
    local under = Vector3.new(target.X, target.Y + UNDER_Y, target.Z)
    pcall(function()
        local ch = LP.Character
        local cf = CFrame.new(under, target)
        if ch and ch.PrimaryPart then ch:PivotTo(cf)
        else h.CFrame = cf end
    end)
end

local function _inBuyRange(ref)
    local h = _getHRP()
    if not h or not ref then return false end
    local target = _getTargetPos(ref)
    return (h.Position - target).Magnitude <= BUY_RANGE
end

local function _matchPlotOwner(v)
    if v == nil or not LP then return false end
    return v == LP.UserId or v == LP.Name
        or tostring(v) == tostring(LP.UserId) or tostring(v) == LP.Name
end

local function _getPlayerPlot()
    local gardens = workspace:FindFirstChild("Gardens")
    if not gardens or not LP then return nil end

    local plotId = LP:GetAttribute("PlotId")
    local idStr = plotId ~= nil and tostring(plotId) or nil

    if idStr then
        for _, name in ipairs({ "Plot" .. idStr, idStr, "Plot_" .. idStr }) do
            local plot = gardens:FindFirstChild(name)
            if plot then return plot end
        end
    end

    for _, plot in ipairs(gardens:GetChildren()) do
        if _matchPlotOwner(plot:GetAttribute("OwnerId"))
            or _matchPlotOwner(plot:GetAttribute("Owner"))
            or _matchPlotOwner(plot:GetAttribute("OwnerUserId"))
            or _matchPlotOwner(plot:GetAttribute("UserId")) then
            return plot
        end
    end

    local myPlot = LP:GetAttribute("Plot") or LP:GetAttribute("PlotName")
        or LP:GetAttribute("GardenPlot") or LP:GetAttribute("PlotId")
    if myPlot then
        for _, name in ipairs({ tostring(myPlot), "Plot" .. tostring(myPlot), "Plot_" .. tostring(myPlot) }) do
            local plot = gardens:FindFirstChild(name)
            if plot then return plot end
        end
    end

    return nil
end

local function _getGardenCFrame()
    local mod = _getAutoTeleMod()
    if type(mod) == "table" then
        local cf = nil
        if type(mod.ResolveTargetCFrame) == "function" then
            cf = mod.ResolveTargetCFrame()
        elseif type(mod.GetGardenCenterCFrame) == "function" then
            cf = mod.GetGardenCenterCFrame()
        end
        if typeof(cf) == "CFrame" then return cf end
    end

    local plot = _getPlayerPlot()
    if not plot then return nil end

    local spawn = plot:FindFirstChild("Spawn", true) or plot:FindFirstChild("SpawnLocation", true)
    if spawn and spawn:IsA("BasePart") then
        return spawn.CFrame + GARDEN_TP_OFFSET
    end

    if plot:IsA("Model") then
        local ok, cf = pcall(function() return plot:GetPivot() end)
        if ok and typeof(cf) == "CFrame" then
            return cf + GARDEN_TP_OFFSET
        end
    end

    return nil
end

local function _tpToGarden()
    local cf = _getGardenCFrame()
    if typeof(cf) ~= "CFrame" then return false end
    local h = _getHRP()
    local ch = LP.Character
    if not h or not ch then return false end
    local ok = pcall(function()
        if ch.PrimaryPart then ch:PivotTo(cf) else h.CFrame = cf end
    end)
    if ok then task.wait(GARDEN_WAIT) end
    return ok
end

local function _getSheckles()
    local v = tonumber(LP:GetAttribute("Sheckles"))
    if v then return v end
    local ls = LP:FindFirstChild("leaderstats")
    if ls then
        for _, n in ipairs({ "Sheckles", "Money", "Cash", "Coins" }) do
            local o = ls:FindFirstChild(n)
            if o and (o:IsA("IntValue") or o:IsA("NumberValue")) then return tonumber(o.Value) end
        end
    end
    return nil
end

local function _getPetTypes()
    if PetTypesCache then return PetTypesCache end
    local sd = ReplicatedStorage:FindFirstChild("SharedData")
    local pt = sd and sd:FindFirstChild("PetTypes")
    if pt and pt:IsA("ModuleScript") then
        local ok, mod = pcall(require, pt)
        if ok and type(mod) == "table" then PetTypesCache = mod end
    end
    return PetTypesCache
end

local function _resolvePetType(raw)
    local SectionBuyPet = G.SectionAutoBuyPet or rawget(_G, "SectionAutoBuyPet")
    if type(SectionBuyPet) == "table" and type(SectionBuyPet.resolvePetTypeRaw) == "function" then
        return SectionBuyPet.resolvePetTypeRaw(raw)
    end
    if raw == nil or raw == "" then return "Normal" end
    if type(raw) == "string" and raw ~= "" then return raw end
    if type(raw) == "number" then
        local petTypes = _getPetTypes()
        if petTypes then
            for name, val in pairs(petTypes) do
                if val == raw then return name end
            end
        end
    end
    return "Normal"
end

local function _getPetSizes()
    if PetSizesCache then return PetSizesCache end
    local sd = ReplicatedStorage:FindFirstChild("SharedData")
    local ps = sd and sd:FindFirstChild("PetSizes")
    if ps and ps:IsA("ModuleScript") then
        local ok, mod = pcall(require, ps)
        if ok and type(mod) == "table" then PetSizesCache = mod end
    end
    return PetSizesCache
end

local function _resolvePetSize(raw)
    local SectionBuyPet = G.SectionAutoBuyPet or rawget(_G, "SectionAutoBuyPet")
    if type(SectionBuyPet) == "table" and type(SectionBuyPet.resolvePetSizeRaw) == "function" then
        return SectionBuyPet.resolvePetSizeRaw(raw)
    end
    if raw == nil then return "Normal" end
    if type(raw) == "string" and raw ~= "" then return raw end
    if type(raw) == "number" then
        local petSizes = _getPetSizes()
        if petSizes then
            for name, val in pairs(petSizes) do
                if val == raw then return name end
            end
        end
    end
    return tostring(raw)
end

local function _getRefPetType(ref)
    if not ref then return "Normal" end
    return _resolvePetType(ref:GetAttribute("PetType"))
end

local function _getRefPetSize(ref)
    if not ref then return "Normal" end
    return _resolvePetSize(ref:GetAttribute("PetSize"))
end

local function _getPetName(ref)
    if not ref then return nil end
    local n = ref:GetAttribute("PetName")
    if type(n) == "string" and n ~= "" then return n end
    local petType = ref:GetAttribute("PetType")
    if petType ~= nil then
        local resolved = _resolvePetType(petType)
        if type(resolved) == "string" and resolved ~= "" then return resolved end
    end
    for _, attr in ipairs({ "Species", "Pet", "PetId", "Name" }) do
        local v = ref:GetAttribute(attr)
        if type(v) == "string" and v ~= "" then return v end
    end
    return nil
end

local function _getPetData()
    if PetDataCache then return PetDataCache end
    local sd = ReplicatedStorage:FindFirstChild("SharedData")
    local pd = sd and sd:FindFirstChild("PetData")
    if pd and pd:IsA("ModuleScript") then
        local ok, mod = pcall(require, pd)
        if ok and type(mod) == "table" then PetDataCache = mod end
    end
    return PetDataCache
end

local function _getPetCatalogEntry(petName)
    petName = tostring(petName or "")
    if petName == "" then return nil, nil end
    local data = _getPetData()
    if not data then return nil, nil end
    local cfg = data[petName]
    if type(cfg) == "table" then return cfg, petName end
    for key, entry in pairs(data) do
        if type(entry) == "table" then
            if entry.DisplayName == petName then return entry, key end
            if type(data.GetSpeciesDisplayName) == "function" then
                local ok, dn = pcall(data.GetSpeciesDisplayName, key)
                if ok and dn == petName then return entry, key end
            end
        end
    end
    return nil, nil
end

local function _getCatalogBasePrice(petName)
    if not petName then return 0 end
    local data = _getPetData()
    if not data then return 0 end
    local entry = data[petName]
    if type(entry) == "table" then
        local p = tonumber(entry.WildPrice or entry.TamePrice or entry.TameBasePrice
            or entry.BasePrice or entry.PurchasePrice or entry.Price)
        if p and p > 0 then return p end
    end
    return 0
end

local function _getCatalogWildFreshPrice(petName)
    if not petName then return 0 end
    local entry = select(1, _getPetCatalogEntry(petName))
    if not entry then return 0 end
    local wild = tonumber(entry.WildPrice or entry.TamePrice or entry.TameBasePrice)
    if wild and wild > 0 then return wild end
    local shop = tonumber(entry.BasePrice or entry.PurchasePrice or entry.Price)
    if shop and shop > 0 then return math.floor(shop * WILD_FRESH_SHOP_MULT + 0.5) end
    return 0
end

local function _freshPriceKey(petName, petType, petSize)
    local pet = _canonPet(petName)
    if pet == "" then return "" end
    return pet .. "|" .. _canonPet(petType or "normal") .. "|" .. _canonPet(petSize or "normal")
end

local function _isStealRef(ref)
    local owner = _getOwnerUserId(ref)
    return owner ~= nil and owner ~= LP.UserId
end

local function _observeFreshFromRef(ref)
    if not ref or _isStealRef(ref) then return end
    local price = tonumber(ref:GetAttribute("Price")) or 0
    if price <= 0 then return end
    local petName = _getPetName(ref)
    if not petName then return end
    local key = _freshPriceKey(petName, _getRefPetType(ref), _getRefPetSize(ref))
    local petKey = "@" .. _canonPet(petName)
    freshWildLearned[key] = price
    freshWildLearned[petKey] = price
end

-- Dipakai untuk fresh buy (max price mult), boleh learn dari pet gratis di server.
local function _getWildFreshPrice(ref)
    local petName = _getPetName(ref)
    if not petName then return 0 end
    local key = _freshPriceKey(petName, _getRefPetType(ref), _getRefPetSize(ref))
    local petKey = "@" .. _canonPet(petName)

    local learned = freshWildLearned[key] or freshWildLearned[petKey]
    if type(learned) == "number" and learned > 0 then
        return learned
    end

    return _getCatalogWildFreshPrice(petName)
end

local function _refreshFreshLearned(folder)
    if not folder then return end
    for _, ref in ipairs(folder:GetChildren()) do
        if ref:IsA("BasePart") then
            _observeFreshFromRef(ref)
        end
    end
end

local function _getPetDisplayName(petKey)
    petKey = tostring(petKey or "")
    if petKey == "" then return nil end
    local entry = select(1, _getPetCatalogEntry(petKey))
    if entry and type(entry.DisplayName) == "string" and entry.DisplayName ~= "" then
        return entry.DisplayName
    end
    local data = _getPetData()
    if data and type(data.GetSpeciesDisplayName) == "function" then
        local ok, dn = pcall(data.GetSpeciesDisplayName, petKey)
        if ok and type(dn) == "string" and dn ~= "" then return dn end
    end
    return petKey
end

local function _getPetListView()
    return G.PetListView or rawget(_G, "PetListView")
end

local _STATIC_RARITY_RANK = {
    common = 1,
    uncommon = 2,
    rare = 3,
    legendary = 4,
    mythic = 5,
    super = 6,
}

local function _normRarityKey(s)
    return tostring(s or ""):lower():gsub("%s+", "")
end

local function _getRarityRank(rarity)
    rarity = tostring(rarity or "")
    if rarity == "" then return 0 end
    local plv = _getPetListView()
    if type(plv) == "table" and type(plv.getRarityRank) == "function" then
        local function callRank(name)
            local ok, rank = pcall(plv.getRarityRank, plv, name)
            if not ok then ok, rank = pcall(plv.getRarityRank, name) end
            if ok and type(rank) == "number" and rank > 0 then return rank end
            return 0
        end
        local rank = callRank(rarity)
        if rank > 0 then return rank end
    end
    return _STATIC_RARITY_RANK[_normRarityKey(rarity)] or 0
end

local function _getRareRankThreshold()
    return _STATIC_RARITY_RANK.rare or 3
end

local function _isRarityAboveRare(rarity)
    local rank = _getRarityRank(rarity)
    return rank > _getRareRankThreshold()
end

local function _resolvePetRarity(ref, petKey, petName)
    if ref then
        local attr = ref:GetAttribute("Rarity")
        if attr ~= nil and tostring(attr) ~= "" and tostring(attr) ~= "Unknown" then
            return tostring(attr)
        end
    end
    local data = _getPetData()
    if data and petKey ~= "" then
        local entry = data[petKey]
        if type(entry) == "table" and entry.Rarity then return tostring(entry.Rarity) end
    end
    return nil
end

local function _isOwned(ref)
    return _getOwnerUserId(ref) == LP.UserId
end

local function _canBuyRef(ref)
    -- Sama seperti BuyPrompt di game: enabled saat OwnerUserId ~= LocalPlayer
    return _getOwnerUserId(ref) ~= LP.UserId
end

local function _getBasePrice(ref)
    local key = _refKey(ref)
    if key ~= "" and refBasePrice[key] then return refBasePrice[key] end
    local fresh = _getWildFreshPrice(ref)
    if fresh > 0 then
        if key ~= "" then refBasePrice[key] = fresh end
        return fresh
    end
    local catalog = _getCatalogBasePrice(_getPetName(ref))
    local price = tonumber(ref:GetAttribute("Price")) or 0
    local base = (catalog > 0) and catalog or price
    if base <= 0 then base = price end
    if key ~= "" then refBasePrice[key] = base end
    return base
end

local function _getMaxStealForRule(rule)
    if type(rule) ~= "table" then return DEFAULT_MAX_STEAL end
    local n = tonumber(rule.max_steal or rule.max_steal_mult)
    if n and n >= 1 then return math.floor(n + 0.499) end
    return DEFAULT_MAX_STEAL
end

local function _ruleStealKey(rule)
    if type(rule) ~= "table" then return "" end
    return _canonPet(rule.pet or "")
end

local function _getStealSuccessCount(rule)
    local key = _ruleStealKey(rule)
    if key == "" then return 0 end
    return stealSuccessByPet[key] or 0
end

local function _recordStealSuccess(rule)
    local key = _ruleStealKey(rule)
    if key == "" then return end
    stealSuccessByPet[key] = _getStealSuccessCount(rule) + 1
    _log("steal success", key, stealSuccessByPet[key], "/", _getMaxStealForRule(rule))
end

local function _stealAllowedForRule(rule)
    if type(rule) ~= "table" then return false end
    return rule.steal == true
end

-- Max steal quota = jumlah steal sukses per pet rule; harga dicek terpisah via max_steal_price.
local function _withinStealQuota(ref, rule)
    if not _isStealRef(ref) then return true end
    if not _stealAllowedForRule(rule) then return true end
    return _getStealSuccessCount(rule) < _getMaxStealForRule(rule)
end

local function _withinMaxFreshPrice(ref)
    if _isStealRef(ref) then return true end
    local base = _getBasePrice(ref)
    local price = tonumber(ref:GetAttribute("Price")) or 0
    if base <= 0 or price <= 0 then return true end
    return (price / base) <= _getMaxPriceMult() + 0.001
end

local function _passesTargetLimits(ref, rule)
    if _isStealRef(ref) then
        if not _withinStealQuota(ref, rule) then return false end
        return _withinMaxStealPrice(ref)
    end
    return _withinMaxFreshPrice(ref)
end

local function _withinMaxPrice(ref, rule)
    return _passesTargetLimits(ref, rule)
end

local function _getPriceMult(ref)
    local base = _getBasePrice(ref)
    local price = tonumber(ref:GetAttribute("Price")) or 0
    if base <= 0 or price <= 0 then return 1 end
    return price / base
end

local function _canAfford(ref)
    local price = tonumber(ref:GetAttribute("Price")) or 0
    if price <= 0 then return true end
    local money = _getSheckles()
    return type(money) ~= "number" or money >= price
end

local function _matchesFilter(ref, selected)
    local petKey = _getPetName(ref)
    if not petKey or not _hasAnySelected(selected) then return false end

    if selected[petKey] == true then return true end

    local display = _getPetDisplayName(petKey)
    if display and selected[display] == true then return true end

    local _, catalogKey = _getPetCatalogEntry(petKey)
    if catalogKey and selected[catalogKey] == true then return true end

    local canonRef = _canonPet(petKey)
    local canonDisp = display and _canonPet(display) or ""
    for k, v in pairs(selected) do
        if v == true then
            local ck = _canonPet(k)
            if ck ~= "" and (ck == canonRef or ck == canonDisp) then
                return true
            end
        end
    end

    return false
end

local function _getSectionBuyPet()
    return G.SectionAutoBuyPet or rawget(_G, "SectionAutoBuyPet")
end

local function _loadTargetRules()
    local SectionBuyPet = _getSectionBuyPet()
    local s = _getStore()
    if type(s) == "table" and type(s.targets) == "table" and #s.targets > 0 then
        if SectionBuyPet and type(SectionBuyPet.normalizeTargets) == "function" then
            return SectionBuyPet.normalizeTargets(s.targets)
        end
        if SectionBuyPet and type(SectionBuyPet.deserializeTargets) == "function" then
            return SectionBuyPet.deserializeTargets(s.targets)
        end
        return s.targets
    end

    local raw = G.BUY_PET_TARGETS or rawget(_G, "BUY_PET_TARGETS")
    if type(raw) == "table" and #raw > 0 then
        if SectionBuyPet and type(SectionBuyPet.deserializeTargets) == "function" then
            return SectionBuyPet.deserializeTargets(raw)
        end
        return raw
    end

    local pet = _readMainPet()
    if pet and type(pet.targets) == "table" and #pet.targets > 0 then
        if SectionBuyPet and type(SectionBuyPet.deserializeTargets) == "function" then
            return SectionBuyPet.deserializeTargets(pet.targets)
        end
        return pet.targets
    end

    return {}
end

local function _anyRuleEnabled(rules)
    rules = rules or _loadTargetRules()
    for _, rule in ipairs(rules) do
        if type(rule) == "table" and rule.enabled == true then return true end
    end
    return false
end

local function _enabled()
    local rules = _loadTargetRules()
    if #rules > 0 then
        return _anyRuleEnabled(rules)
    end
    local s = _getStore()
    if type(s) == "table" and s.enabled == true then return true end
    if G.AUTO_BUY_PET_ENABLED == true or rawget(_G, "AUTO_BUY_PET_ENABLED") == true then return true end
    local pet = _readMainPet()
    return type(pet) == "table" and pet.enabled == true
end

local function _autoTameEnabled()
    local rules = _loadTargetRules()
    for _, rule in ipairs(rules) do
        if type(rule) == "table" and rule.enabled == true and rule.steal == true then
            return true
        end
    end
    return false
end

local function getState()
    return {
        enabled  = _enabled(),
        autoTame = _autoTameEnabled(),
        selected = _getActiveSelected(),
    }
end

local function _hasConfiguredTargets()
    return _anyRuleEnabled()
end

local function _hasActiveBuyConfig(selected)
    if _hasConfiguredTargets() then return true end
    return _hasAnySelected(selected)
end

local function _mapMatchesRef(refValue, allowedMap)
    if type(allowedMap) ~= "table" or not next(allowedMap) then return true end
    local canonRef = _canonPet(refValue or "Normal")
    for k, v in pairs(allowedMap) do
        if v == true and _canonPet(k) == canonRef then return true end
    end
    return false
end

local function _petNameMatchesRule(rulePet, refPetKey)
    if not rulePet or not refPetKey then return false end
    if _canonPet(rulePet) == _canonPet(refPetKey) then return true end

    local display = _getPetDisplayName(refPetKey)
    if display and _canonPet(rulePet) == _canonPet(display) then return true end

    local _, catalogKey = _getPetCatalogEntry(refPetKey)
    if catalogKey and _canonPet(rulePet) == _canonPet(catalogKey) then return true end

    local _, ruleCatalogKey = _getPetCatalogEntry(rulePet)
    if ruleCatalogKey and _canonPet(ruleCatalogKey) == _canonPet(refPetKey) then return true end

    return false
end

local function _typeMatchesRef(ref, allowedMap)
    local SectionBuyPet = _getSectionBuyPet()
    if type(SectionBuyPet) == "table" and type(SectionBuyPet.typeMatchesRule) == "function" then
        local raw = ref and ref:GetAttribute("PetType")
        return SectionBuyPet.typeMatchesRule(raw, allowedMap)
    end
    return _mapMatchesRef(_getRefPetType(ref), allowedMap)
end

local function _matchTargetRule(ref, rule)
    if type(rule) ~= "table" then return false end
    if rule.enabled ~= true then return false end
    local petKey = _getPetName(ref)
    if not petKey then return false end
    if not _petNameMatchesRule(rule.pet, petKey) then return false end
    local SectionBuyPet = _getSectionBuyPet()
    if type(SectionBuyPet) == "table" and type(SectionBuyPet.variantSizeMatchesRule) == "function" then
        if not SectionBuyPet.variantSizeMatchesRule(
            ref and ref:GetAttribute("PetType"),
            _getRefPetSize(ref),
            rule.types,
            rule.sizes
        ) then
            return false
        end
    else
        if not _typeMatchesRef(ref, rule.types) then return false end
        if not _mapMatchesRef(_getRefPetSize(ref), rule.sizes) then return false end
    end
    return true
end

local function _anyStealEnabled()
    local rules = _loadTargetRules()
    for _, rule in ipairs(rules) do
        if rule.enabled == true and _stealAllowedForRule(rule) then return true end
    end
    return false
end

local function _getRefMatchRule(ref)
    local rules = _loadTargetRules()
    if #rules > 0 then
        for _, rule in ipairs(rules) do
            if rule.enabled == true and _matchTargetRule(ref, rule) then return rule end
        end
        return nil
    end

    local selected = _getActiveSelected()
    if not next(selected) then return nil end
    if _matchesFilter(ref, selected) then
        return { enabled = true, steal = nil }
    end
    return nil
end

local function _refMatchesConfig(ref, selected)
    return _getRefMatchRule(ref) ~= nil
end

local function _canTarget(ref, selected)
    if not ref or not ref.Parent or not _enabled() then return false end
    if not _canBuyRef(ref) then return false end

    local rule = _getRefMatchRule(ref)
    if not rule then return false end
    if not _getPetName(ref) then return false end
    if not _canAfford(ref) then return false end
    if not _passesTargetLimits(ref, rule) then return false end

    local owner = _getOwnerUserId(ref)
    if owner ~= nil and owner ~= LP.UserId then
        if not _stealAllowedForRule(rule) then return false end
        if _shouldSkipStealOwner(owner) then return false end
    end
    return true
end

local function _getTargetBlockReason(ref, selected)
    if not ref or not ref.Parent then return "no_ref" end
    if not _enabled() then return "disabled" end
    if not _canBuyRef(ref) then return "owned_by_you" end

    local rule = _getRefMatchRule(ref)
    if not rule then return "not_selected" end
    if not _getPetName(ref) then return "no_pet_name" end
    if not _canAfford(ref) then return "cant_afford" end

    local owner = _getOwnerUserId(ref)
    if owner ~= nil and owner ~= LP.UserId then
        if not _stealAllowedForRule(rule) then return "steal_disabled" end
        if _shouldSkipStealOwner(owner) then return "skip_steal_friend" end
        local done = _getStealSuccessCount(rule)
        local maxSteal = _getMaxStealForRule(rule)
        if done >= maxSteal then
            return string.format("steal_quota_%d/%d", done, maxSteal)
        end
        if not _withinMaxStealPrice(ref) then
            return "steal_price_over_max"
        end
        return nil
    end

    if not _withinMaxFreshPrice(ref) then return "price_over_max" end
    return nil
end

local function _refMode(ref, rule)
    if not ref then return "?" end
    local owner = _getOwnerUserId(ref)
    if owner ~= nil and owner ~= LP.UserId then
        rule = rule or _getRefMatchRule(ref)
        local done = rule and _getStealSuccessCount(rule) or 0
        local maxSteal = rule and _getMaxStealForRule(rule) or DEFAULT_MAX_STEAL
        return string.format("STEAL %d/%d", done, maxSteal)
    end
    if owner == nil then return "BUY" end
    return "OTHER"
end

local function _refSummary(ref)
    if not ref then return "nil" end
    return string.format(
        "%s mode=%s price=%s mult=%.2fx owner=%s",
        tostring(_getPetName(ref) or ref.Name),
        _refMode(ref),
        tostring(ref:GetAttribute("Price") or 0),
        _getPriceMult(ref),
        tostring(_getOwnerUserId(ref))
    )
end

local function _sessionStopReason(ref, selected, bought)
    if bought then return "owned_ok" end
    if not ref or not ref.Parent then return "ref_gone" end
    if not running or not _enabled() then return "disabled" end
    local rule = _getRefMatchRule(ref)
    if not _passesTargetLimits(ref, rule) then
        if _isStealRef(ref) then
            if not _withinStealQuota(ref, rule) then
                local done = _getStealSuccessCount(rule)
                local maxSteal = _getMaxStealForRule(rule)
                return string.format("steal_quota_%d/%d", done, maxSteal)
            end
            if not _withinMaxStealPrice(ref) then
                return "steal_price_over_max"
            end
            return "steal_blocked"
        end
        return "price_over_max"
    end
    if not _canBuyRef(ref) then return "cant_buy_ref" end
    return _getTargetBlockReason(ref, selected) or "target_invalid"
end

----------------------------------------------------------------
-- Webhook
----------------------------------------------------------------
local function _webhookDisplayPrice(ref, attrPrice)
    attrPrice = math.floor(tonumber(attrPrice) or 0)
    if attrPrice <= 0 then return 0 end
    local owner = ref and _getOwnerUserId(ref)
    if not ref or (owner ~= nil and owner ~= LP.UserId) then return attrPrice end
    local tameBase = _getCatalogBasePrice(_getPetName(ref))
    if tameBase > 0 and attrPrice >= tameBase * 2 - 1 and attrPrice <= tameBase * 2 + 1 then
        return tameBase
    end
    local owner = tonumber(ref:GetAttribute("OwnerUserId"))
    if (not owner or owner == 0) and attrPrice % 2 == 0 then
        return math.floor(attrPrice / 2)
    end
    return attrPrice
end

local function _readRefForWebhook(ref)
    if not ref then return nil end
    local petKey = _getPetName(ref)
    if not petKey then return nil end
    local petName = _getPetDisplayName(petKey) or petKey
    local key = _refKey(ref)
    local price = tonumber(ref:GetAttribute("Price")) or refLastPrice[key] or 0
    return {
        petKey = petKey,
        petName = petName,
        petType = _getRefPetType(ref),
        petSize = _getRefPetSize(ref),
        rarity = _resolvePetRarity(ref, petKey, petName) or "",
        price = _webhookDisplayPrice(ref, price),
        refKey = key,
        at = os.clock(),
    }
end

local function _rememberWebhookTame(ref)
    lastWebhookTame = _readRefForWebhook(ref)
end

local WEBHOOK_NOTABLE_TRAITS = {
    rainbow = true,
    big = true,
    huge = true,
}

local function _canonTraitKey(v)
    return tostring(v or ""):lower():gsub("[%s_%-]+", "")
end

local function _isWebhookNotableTrait(v)
    local k = _canonTraitKey(v)
    return k ~= "" and k ~= "normal" and WEBHOOK_NOTABLE_TRAITS[k] == true
end

local function _hasNotablePetTraits(info, ref)
    local petType = type(info) == "table" and info.petType or nil
    local petSize = type(info) == "table" and info.petSize or nil
    if ref then
        petType = petType or _getRefPetType(ref)
        petSize = petSize or _getRefPetSize(ref)
    end
    return _isWebhookNotableTrait(petType) or _isWebhookNotableTrait(petSize)
end

local function _shouldSendPetBuyWebhook(rarity, info, ref)
    rarity = tostring(rarity or "")
    if rarity == "" then return false end
    if _isRarityAboveRare(rarity) then return true end
    return _hasNotablePetTraits(info, ref)
end

local function _sendPetBuyWebhook(info, key, ref)
    key = key or (type(info) == "table" and info.refKey) or ""
    if key ~= "" and webhookSentKeys[key] then return end
    if type(info) ~= "table" then return end

    if ref and ref.Parent then
        local fresh = _readRefForWebhook(ref)
        if fresh then info = fresh end
    end

    local petName = info.petName or _getPetDisplayName(info.petKey)
    local rarity = tostring(info.rarity or _resolvePetRarity(nil, info.petKey, petName) or "")
    if not _shouldSendPetBuyWebhook(rarity, info, nil) then return end

    if key ~= "" then webhookSentKeys[key] = true end

    task.spawn(function()
        local wh = G.WebhookModule or G.Webhook or _G.WebhookModule or _G.Webhook
        if type(wh) ~= "table" or type(wh.SendPetBuy) ~= "function" then return end
        pcall(wh.SendPetBuy, {
            player = LP.Name,
            petName = petName,
            petKey = info.petKey or info.petName,
            petType = info.petType,
            petSize = info.petSize,
            rarity = rarity,
            price = tonumber(info.price) or 0,
        })
    end)
end

-- Tunggu pet hilang dari WildPetRef (= sampai garden). Batal jika di-steal balik.
local function _queuePetBuyWebhook(ref)
    if not ref then return end
    local key = _refKey(ref)
    if key == "" or webhookSentKeys[key] or webhookPending[key] then return end

    local info = lastWebhookTame
    local fresh = _readRefForWebhook(ref)
    if fresh then info = fresh end
    if not info then return end

    local petName = info.petName or _getPetDisplayName(info.petKey)
    local rarity = _resolvePetRarity(ref, info.petKey, petName) or info.rarity or ""
    if not _shouldSendPetBuyWebhook(rarity, info, ref) then
        lastWebhookTame = nil
        return
    end

    lastWebhookTame = nil
    webhookPending[key] = { info = info, ref = ref }

    task.spawn(function()
        local deadline = os.clock() + WEBHOOK_GARDEN_WAIT_SEC
        while os.clock() < deadline do
            local pend = webhookPending[key]
            if not pend then return end

            local r = pend.ref
            if r and r.Parent and _isWildPetRef(r) then
                local owner = _getOwnerUserId(r)
                if owner ~= nil and owner ~= LP.UserId then
                    webhookPending[key] = nil
                    _log("webhook cancel", key, "stolen_before_garden")
                    return
                end
            else
                webhookPending[key] = nil
                _sendPetBuyWebhook(pend.info, key, pend.ref)
                _log("webhook sent", key, "at_garden")
                return
            end

            task.wait(WEBHOOK_GARDEN_POLL_SEC)
        end

        webhookPending[key] = nil
        _log("webhook cancel", key, "garden_timeout")
    end)
end

local function _markFireAttempt(ref)
    local key = _refKey(ref)
    if key ~= "" then
        refLastPrice[key] = _webhookDisplayPrice(ref, ref:GetAttribute("Price"))
    end
    pcall(_rememberWebhookTame, ref)
end

----------------------------------------------------------------
-- Fire remote
----------------------------------------------------------------
local function _fireTameRemote(ref)
    if not ref or not _ensureNetworking() or not WildPetTame then return false end
    return pcall(function()
        if type(WildPetTame.Fire) == "function" then
            WildPetTame:Fire(ref)
        else
            WildPetTame:InvokeServer(ref)
        end
    end)
end

local function _fireInterval(ref)
    local owner = ref and _getOwnerUserId(ref)
    if owner ~= nil and owner ~= LP.UserId then
        return STEAL_FIRE_SEC
    end
    return FIRE_SEC
end

----------------------------------------------------------------
-- Core: follow bawah pet → fire sampai beli
----------------------------------------------------------------
local function _pickBest(folder, selected)
    _refreshFreshLearned(folder)
    local best, bestScore, bestD = nil, -math.huge, math.huge
    local h = _getHRP()
    if not h then return nil end
    for _, ref in ipairs(folder:GetChildren()) do
        if ref:IsA("BasePart") and _canTarget(ref, selected) then
            local owner = _getOwnerUserId(ref)
            local score = (owner ~= nil and owner ~= LP.UserId) and 1000 or 0
            local d = (_getTargetPos(ref) - h.Position).Magnitude
            if not best or score > bestScore or (score == bestScore and d < bestD) then
                best, bestScore, bestD = ref, score, d
            end
        end
    end
    return best
end

local function _hasMoreTargets(folder, selected)
    return folder and _pickBest(folder, selected) ~= nil
end

local function _followBuyUntilDone(ref, selected)
    if not _canTarget(ref, selected) or not _getHRP() then
        _log("session skip (not targetable)", ref and _refSummary(ref) or "nil")
        return false
    end

    stats.attempts += 1
    _setBuyBusy(true)
    _teleStopForBuy()

    local rule = _getRefMatchRule(ref)
    local wasStealSession = _isStealRef(ref)
    local mode = _refMode(ref, rule)
    local sessionFired = 0
    local sessionLimit = wasStealSession
        and string.format("stealQuota=%d/%d", _getStealSuccessCount(rule), _getMaxStealForRule(rule))
        or string.format("maxFreshMult=%.2fx", _getMaxPriceMult())
    _log("SESSION start", mode, _refSummary(ref), "|", sessionLimit)

    -- Sebelum ke pet: garden dulu
    _tpToGarden()
    _log("tp garden ok")

    local lastFire = 0
    local bought = false

    while running and _enabled() and ref.Parent and _canBuyRef(ref) do
        if not _canTarget(ref, selected) then
            _log("loop break: target invalid", _getTargetBlockReason(ref, selected))
            break
        end
        if not _passesTargetLimits(ref, rule) then
            if _isStealRef(ref) then
                _log("loop break: steal_quota_full",
                    string.format("%d/%d", _getStealSuccessCount(rule), _getMaxStealForRule(rule)))
            else
                _log("loop break: price_over_max",
                    string.format("%.2fx > %.2fx", _getPriceMult(ref), _getMaxPriceMult()))
            end
            break
        end

        _tpUnder(ref)

        local now = os.clock()
        if now - lastFire >= _fireInterval(ref) then
            if _fireTameRemote(ref) then
                lastFire = now
                stats.fired += 1
                sessionFired += 1
                _markFireAttempt(ref)
                if sessionFired == 1 or sessionFired % DEBUG_FIRE_EVERY == 0 then
                    _log("fire", sessionFired, "total=", stats.fired, mode, _refSummary(ref))
                end
            end
        end

        if _isOwned(ref) then
            bought = true
            break
        end

        task.wait(STICK_SEC)
    end

    if _isOwned(ref) then bought = true end

    local stopReason = _sessionStopReason(ref, selected, bought)
    if bought then
        stats.ok += 1
        if wasStealSession and rule then
            _recordStealSuccess(rule)
        end
        pcall(_queuePetBuyWebhook, ref)
        _tpToGarden()
        _teleResumeNow()
        _log("SESSION OK", mode, "fires=", sessionFired, "reason=", stopReason, _refSummary(ref))
    else
        stats.fail += 1
        if _hasMoreTargets(_getWildRefFolder(), selected) then
            _teleKeepPaused()
            _log("SESSION FAIL", mode, "fires=", sessionFired, "reason=", stopReason, "tele=keep_paused")
        else
            _teleResumeNow()
            _log("SESSION FAIL", mode, "fires=", sessionFired, "reason=", stopReason, "tele=resume")
        end
    end

    _setBuyBusy(false)
    lastBuyEndAt = os.clock()
    return bought
end

----------------------------------------------------------------
-- Scan / watchers
----------------------------------------------------------------
local function _bindFolder(folder)
    if not folder or boundFolder == folder then return end
    if childConn then childConn:Disconnect(); childConn = nil end
    boundFolder = folder
    childConn = folder.ChildAdded:Connect(function(ref)
        if running and _enabled() and not buyBusy and ref:IsA("BasePart") then
            task.defer(function()
                local sel = _getActiveSelected()
                if running and not buyBusy and ref.Parent and _canTarget(ref, sel) then
                    _log("spawn target", _refSummary(ref))
                    _followBuyUntilDone(ref, sel)
                end
            end)
        end
    end)
end

local function _ensureWatchers()
    local map = workspace:FindFirstChild("Map")
    if map and not mapConn then
        mapConn = map.ChildAdded:Connect(function(child)
            if child.Name == "WildPetRef" and child:IsA("Folder") then
                wildFolder = child
                _bindFolder(child)
            end
        end)
    end
    local folder = _getWildRefFolder()
    if folder then _bindFolder(folder) end
    return folder
end

local function _scanFolder(folder, selected)
    if not folder or buyBusy or not _enabled() then return 0 end
    if os.clock() - lastBuyEndAt < BUY_GAP then return 0 end
    if not _hasActiveBuyConfig(selected) then return 0 end

    local target = _pickBest(folder, selected)
    if not target then return 0 end

    if _dbg() then _log("scan pick", _refSummary(target)) end
    return _followBuyUntilDone(target, selected) and 1 or 0
end

local function _mainLoop(myId)
    task.wait()
    local sel = _getActiveSelected()
    while running and loopId == myId do
        if _enabled() then
            local folder = _ensureWatchers()
            if folder then
                pcall(_scanFolder, folder, sel)
                sel = _getActiveSelected()
            end
            task.wait(SCAN_SEC)
        else
            task.wait(0.5)
        end
    end
end

pcall(function()
    if not _ensureNetworking() or not WildPetTameResult then return end
    WildPetTameResult.OnClientEvent:Connect(function(ref, uid)
        if not ref or uid ~= LP.UserId then return end
        pcall(_rememberWebhookTame, ref)
        if _isOwned(ref) then
            pcall(_queuePetBuyWebhook, ref)
        end
    end)
end)

----------------------------------------------------------------
-- Module API
----------------------------------------------------------------
function M.Start()
    if not _enabled() then running = false; return end
    activeSelected = _selected()
    _ensureWatchers()
    running = true
    loopId += 1
    local myId = loopId
    task.spawn(function() pcall(_mainLoop, myId) end)
    task.defer(function()
        if running and loopId == myId and _enabled() then
            local folder = _getWildRefFolder()
            if folder then pcall(_scanFolder, folder, _getActiveSelected()) end
        end
    end)
end
M.start = M.Start

function M.Stop()
    running = false
    _setBuyBusy(false)
    _teleResumeNow()
    if childConn then childConn:Disconnect(); childConn = nil end
    table.clear(stealSuccessByPet)
    table.clear(webhookPending)
end
M.stop = M.Stop

function M.IsRunning() return running end

function M.TameOnce()
    if not _enabled() then return 0 end
    local folder = _ensureWatchers()
    return folder and _scanFolder(folder, _getActiveSelected()) or 0
end
M.tameOnce = M.TameOnce

function M.SetEnabled(a, b)
