    _G.AUTO_BUY_PET_ENABLED = on
    if on then M.Start() else M.Stop() end
end
M.setEnabled = M.SetEnabled

function M.ApplyRuntime(a, b)
    local on = (a == nil and b == nil) and _enabled() or _boolArg(a, b)
    M.SetEnabled(on)
    return on
end
M.applyRuntime = M.ApplyRuntime

function M.EnsureRunning()
    if not _enabled() then M.Stop(); return false end
    if not running then M.Start() end
    return running
end
M.ensureRunning = M.EnsureRunning

function M.SetAutoTame(a, b)
    local on = _boolArg(a, b)
    _patchStore({ auto_tame = on })
    G.AUTO_TAME_PET_ENABLED = on
    _G.AUTO_TAME_PET_ENABLED = on
    if on and _enabled() and running then
        task.defer(function()
            if _anyStealEnabled() and _enabled() and running then
                M.TameOnce()
            end
        end)
    end
end
M.setAutoTame = M.SetAutoTame

function M.GetMaxPriceMult()
