end
M.getMaxPriceMult = M.GetMaxPriceMult

function M.SetMaxStealPrice(a, b)
    local n = _clampMaxStealPrice(_secondArg(a, b))
    _patchStore({ max_steal_price = n })
    G.AUTO_BUY_PET_MAX_STEAL_PRICE = n
    _G.AUTO_BUY_PET_MAX_STEAL_PRICE = n
end
M.setMaxStealPrice = M.SetMaxStealPrice
M.GetMaxStealPrice = function() return _getMaxStealPrice() end

function M.SetSelected(a, b)
    local map = _secondArg(a, b)
    if type(map) ~= "table" then return end
    map = _normalizeSet(map)
    activeSelected = map
    _patchStore({ selected = map })
    G.BUY_PET_SELECTED = map
    _G.BUY_PET_SELECTED = map
    if next(map) then
        G.GAG2_PET_LIST = _setToArray(map)
        _G.GAG2_PET_LIST = G.GAG2_PET_LIST
    end
end
M.setSelected = M.SetSelected

function M.SyncFromGlobals()
    local on = _enabled()
    G.AUTO_BUY_PET_ENABLED = on
    _G.AUTO_BUY_PET_ENABLED = on
    G.AUTO_TAME_PET_ENABLED = _autoTameEnabled()
    _G.AUTO_TAME_PET_ENABLED = G.AUTO_TAME_PET_ENABLED
    G.AUTO_BUY_PET_MAX_PRICE_MULT = _getMaxPriceMult()
    _G.AUTO_BUY_PET_MAX_PRICE_MULT = G.AUTO_BUY_PET_MAX_PRICE_MULT
    local sel = _selected()
    if next(sel) then M.SetSelected(sel) end
    if on then M.Start() else M.Stop() end
end
M.syncFromGlobals = M.SyncFromGlobals
M.SyncFromState = M.SyncFromGlobals
M.syncFromState = M.SyncFromGlobals

function M.GetState()
    local st = getState()
    return {
        enabled = st.enabled,
        autoTame = st.autoTame,
        selected = st.selected,
        selectedList = _setToArray(st.selected),
    }
