M.getState = M.GetState

local function _buildDiagnostics()
    _ensureNetworking()

    local folder = _getWildRefFolder()
    local st = getState()
    local selected = st.selected
    local allRefs = {}
    local summary = {
        totalRefs = 0,
        targetable = 0,
        matched = 0,
        steal = 0,
        fresh = 0,
        inRange = 0,
        blockReasons = {},
    }
    local bestTarget = nil

    if folder then
        _refreshFreshLearned(folder)
        for _, ref in ipairs(folder:GetChildren()) do
            if ref:IsA("BasePart") and _getPetName(ref) then
                local owner = _getOwnerUserId(ref)
                local matched = _refMatchesConfig(ref, selected)
                local targetable = _canTarget(ref, selected)
                local steal = owner ~= nil and owner ~= LP.UserId
                local fresh = owner == nil
                local inRange = _inBuyRange(ref)
                local blockReason = targetable and nil or _getTargetBlockReason(ref, selected)
                local priceMult = _getPriceMult(ref)
                local rule = _getRefMatchRule(ref)
                local stealDone = rule and _getStealSuccessCount(rule) or 0
                local maxStealQuota = rule and _getMaxStealForRule(rule) or DEFAULT_MAX_STEAL

                summary.totalRefs += 1
                if matched then summary.matched += 1 end
                if targetable then summary.targetable += 1 end
                if steal then summary.steal += 1 end
                if fresh then summary.fresh += 1 end
                if inRange then summary.inRange += 1 end
                if blockReason then
                    summary.blockReasons[blockReason] = (summary.blockReasons[blockReason] or 0) + 1
                end

                if targetable and (not bestTarget or (steal and not bestTarget.steal)) then
                    bestTarget = {
                        name = ref.Name,
                        petName = _getPetName(ref),
                        steal = steal,
                        fresh = fresh,
                    }
                end

                allRefs[#allRefs + 1] = {
                    name = ref.Name,
                    petName = _getPetName(ref),
                    price = tonumber(ref:GetAttribute("Price")) or 0,
                    owner = owner,
                    tameable = ref:GetAttribute("Tameable"),
                    matched = matched,
                    targetable = targetable,
                    blockReason = blockReason,
                    steal = steal,
                    fresh = fresh,
                    inRange = inRange,
                    stealDone = stealDone,
                    maxStealQuota = maxStealQuota,
                    priceMult = priceMult,
                    priceMultText = string.format("%.2fx", priceMult),
                    canAfford = _canAfford(ref),
                    withinLimits = _passesTargetLimits(ref, rule),
                }
            end
        end
    end

    return {
        ok = summary.targetable > 0,
        enabled = st.enabled,
        autoTame = st.autoTame,
        running = running,
        buyBusy = buyBusy,
        teleWasOn = teleWasOn,
        networkingReady = WildPetTame ~= nil,
        sheckles = _getSheckles(),
        maxPriceMult = _getMaxPriceMult(),
        stealQuota = stealSuccessByPet,
        selected = _setToArray(selected),
        wildFolder = folder and folder:GetFullName() or nil,
        stats = {
            attempts = stats.attempts,
            fired = stats.fired,
            ok = stats.ok,
            fail = stats.fail,
        },
        summary = summary,
        bestTarget = bestTarget,
        allRefs = allRefs,
    }
end

function M.SetDebug(a, b)
    local on
    if type(a) == "table" and type(a.SetDebug) == "function" then
        on = _truthyDebug(b)
    else
        on = _truthyDebug(a)
    end
    _syncDebugFlag(on)
    if on then
        print("[GAG2-BuyPet] Debug ON — log alur BUY/STEAL per session (SetDebug(false) untuk off)")
    else
        print("[GAG2-BuyPet] Debug OFF")
    end
    return on
end
M.setDebug = M.SetDebug
M.IsDebug = function() return _dbg() end
M.isDebug = M.IsDebug

function M.GetDiagnostics()
