end
M.getDiagnostics = M.GetDiagnostics

function M.DumpDiagnostics(verbose)
    local d = _buildDiagnostics()
    local s = d.summary or {}
    local br = s.blockReasons or {}
    local brParts = {}
    for k, v in pairs(br) do
        brParts[#brParts + 1] = k .. "=" .. tostring(v)
    end
    table.sort(brParts)

    print("[GAG2-BuyPet] ========== AUTO BUY PET DUMP ==========")
    print("[GAG2-BuyPet] enabled:", d.enabled, "| autoTame:", d.autoTame, "| running:", d.running, "| buyBusy:", d.buyBusy)
    print("[GAG2-BuyPet] network:", d.networkingReady, "| sheckles:", d.sheckles, "| maxMult:", d.maxPriceMult)
    print("[GAG2-BuyPet] wildFolder:", d.wildFolder or "nil")
    print("[GAG2-BuyPet] selected:", table.concat(d.selected or {}, ", "))
    print("[GAG2-BuyPet] refs:", s.totalRefs or 0,
        "| matched:", s.matched or 0,
        "| targetable:", s.targetable or 0,
        "| steal:", s.steal or 0,
        "| fresh:", s.fresh or 0,
        "| inRange:", s.inRange or 0)
    print("[GAG2-BuyPet] block:", table.concat(brParts, ", "))
    print("[GAG2-BuyPet] stats: attempts=", d.stats.attempts,
        "fired=", d.stats.fired,
        "ok=", d.stats.ok,
        "fail=", d.stats.fail)
    if d.bestTarget then
        print("[GAG2-BuyPet] bestTarget:", d.bestTarget.petName,
            d.bestTarget.steal and "(steal)" or (d.bestTarget.fresh and "(fresh)" or ""))
    end

    if verbose == true and type(d.allRefs) == "table" and #d.allRefs > 0 then
        print("[GAG2-BuyPet] ---- refs detail ----")
        print("#  | pet            | price    | mult  | mode         | quota | match | OK? | block")
        for i, r in ipairs(d.allRefs) do
            if i <= 60 then
                local mode
                if r.steal then
                    mode = string.format("STEAL %d/%d", tonumber(r.stealDone) or 0, tonumber(r.maxStealQuota) or 0)
                elseif r.fresh then
                    mode = "BUY"
                else
                    mode = "OTHER"
                end
                print(string.format(
                    "%3d| %-14s | %8s | %5s | %-12s | %3s | %-5s | %-3s | %s",
                    i,
                    tostring(r.petName or "?"):sub(1, 14),
                    tostring(r.price or 0),
                    tostring(r.priceMultText or "-"),
                    mode,
                    r.steal and string.format("%d/%d", tonumber(r.stealDone) or 0, tonumber(r.maxStealQuota) or 0) or "-",
                    r.matched and "YES" or "no",
                    r.targetable and "YES" or "no",
                    tostring(r.blockReason or "OK")
                ))
            end
        end
        if #d.allRefs > 60 then
            print(string.format("[GAG2-BuyPet] ... +%d more refs", #d.allRefs - 60))
        end
    end

    print("[GAG2-BuyPet] debug:", _dbg(), "| cmd: _G.__GAG2_BUY_PET_CHECK()")
    print("[GAG2-BuyPet] =======================================")
    return d
end
M.dumpDiagnostics = M.DumpDiagnostics

function M.CheckFilter()
    return M.DumpDiagnostics(true)
end
M.checkFilter = M.CheckFilter

function M.PrintDiagnostics()
    return M.DumpDiagnostics(true)
end
M.printDiagnostics = M.PrintDiagnostics
M.runDiagnostics = M.DumpDiagnostics

G.AutoBuyPet = M
G.AutoBuyPetModule = M
_G.AutoBuyPet = M
_G.AutoBuyPetModule = M

G.__GAG2_BUY_PET_CHECK = function()
    if type(M.CheckFilter) == "function" then
        return M.CheckFilter()
    end
    return M.DumpDiagnostics(true)
end
_G.__GAG2_BUY_PET_CHECK = G.__GAG2_BUY_PET_CHECK

task.defer(function()
    _setBuyBusy(false)
    _ensureNetworking()
    _restoreDebug()
    if _enabled() then M.EnsureRunning() end
end)

return M
 end,                     required = false },
    { key = "AutoBuyAuction",          name = "Auto Buy Auction",        factory = function() -- AutoBuyAuction.lua — auto beli item di Auction Stand (Networking.Auctioneer)

local Players           = game:GetService("Players")
local ReplicatedStorage = game:GetService("ReplicatedStorage")
local RunService        = game:GetService("RunService")

local LP = Players.LocalPlayer
local G  = (getgenv and getgenv()) or _G
local M  = {}

local LOOP_SEC           = 1.0
local PURCHASE_GAP_SEC   = 0.35
local SNAPSHOT_EVERY_SEC = 8.0

local GEAR_CATEGORIES = {
    Gear = true, Gears = true,
    Sprinklers = true, Rakes = true, WateringCans = true,
    Trowels = true, Shovels = true, Tools = true,
}

local SLOT_CATEGORIES = {
    seed     = { Seeds = true },
    seedpack = { SeedPacks = true },
    egg      = { Eggs = true },
}

local Networking, Auctioneer, PurchaseLot, RequestSnapshot
local AuctionFlags = nil

local running     = false
local loopId      = 0
local netReady    = false
local snapshot    = nil
local stockMap    = {}
local purchaseAt  = {}
local cooldownUntil = {}
local lastSnapshotAt = 0
local lastPurchaseAt = 0
local eventConns  = {}

local stats = {
    lastStatus = "Ready",
    lastError  = nil,
    lastBuy    = nil,
    buys       = 0,
}

local function _dbg()
    return G.AUTO_BUY_AUCTION_DEBUG == true or rawget(_G, "AUTO_BUY_AUCTION_DEBUG") == true
end

local function _log(...)
    if _dbg() then print("[GAG2-ABA]", ...) end
end

local function _setStatus(msg)
    stats.lastStatus = tostring(msg or "Ready")
    G.AUTO_BUY_AUCTION_STATUS = stats.lastStatus
    rawset(_G, "AUTO_BUY_AUCTION_STATUS", stats.lastStatus)
end

local function _stripSelectSuffix(s)
    s = tostring(s or "")
    s = s:gsub("%s+%+%d+$", "")  -- "Super Sprinkler +1" -> "Super Sprinkler"
    s = s:gsub("%s+x%s+[%d%.]+[kKmMbB]?$", "")
    return s
end

local function _normKey(s)
    return _stripSelectSuffix(s):lower():gsub("[%s_%-%.'']+", "")
end

local function _lotIdKey(lotId)
    return tostring(lotId or "")
end

local function _normalizeLot(lot)
    if typeof(lot) ~= "table" then return nil end
    local lotId = lot.lotId or lot.id or lot.Id
    if lotId == nil or tostring(lotId) == "" then return nil end
    lot.lotId = tostring(lotId)
    return lot
end

local function _collectLots(rawLots)
    local lots = {}
    if typeof(rawLots) ~= "table" then return lots end

    local function push(lot)
        lot = _normalizeLot(lot)
        if lot then lots[#lots + 1] = lot end
    end

    if #rawLots > 0 then
        for _, lot in ipairs(rawLots) do push(lot) end
    else
        for _, lot in pairs(rawLots) do push(lot) end
    end
    return lots
end

local function _connectRemoteEvent(remote, handler)
    if not remote then return false end
    local signal = remote.OnClientEvent
    if signal and type(signal.Connect) == "function" then
        eventConns[#eventConns + 1] = signal:Connect(handler)
        return true
    end
    if typeof(remote) == "Instance" and remote:IsA("RemoteEvent") then
        eventConns[#eventConns + 1] = remote.OnClientEvent:Connect(handler)
        return true
    end
    return false
end

local function _normalizeSet(src)
    if type(src) ~= "table" then return {} end
    local out = {}
    for i = 1, #src do
        local v = src[i]
        if v ~= nil and tostring(v) ~= "" then out[tostring(v)] = true end
    end
    if next(out) then return out end
    for k, v in pairs(src) do
        if v == true or v == 1 or v == "true" then out[tostring(k)] = true end
    end
    return out
end

local function _hasAnySelected(map)
    if type(map) ~= "table" then return false end
    for _, v in pairs(map) do
        if v == true then return true end
    end
    return false
end

local function _parseMoneyValue(raw)
    if type(raw) == "number" then return raw end
    local s = tostring(raw or ""):gsub(",", "")
    local n = tonumber(s)
    if n then return n end
    local num, suf = s:match("^([%d%.]+)([kKmMbB])?$")
    n = tonumber(num)
    if not n then return nil end
    suf = tostring(suf or ""):upper()
    if suf == "K" then return n * 1000 end
    if suf == "M" then return n * 1000000 end
    if suf == "B" then return n * 1000000000 end
    return n
end

local function _getMoney()
    local ls = LP:FindFirstChild("leaderstats")
    if ls then
        for _, n in ipairs({ "Sheckles", "Money", "Cash", "Coins" }) do
            local o = ls:FindFirstChild(n)
            if o and (o:IsA("IntValue") or o:IsA("NumberValue")) then
                local v = _parseMoneyValue(o.Value)
                if v ~= nil then return v end
            end
        end
    end
    local attr = LP:GetAttribute("Sheckles")
    if attr ~= nil then
        return _parseMoneyValue(attr)
    end
    return nil
end

local function _getServerTime()
    local ok, t = pcall(function()
        return workspace:GetServerTimeNow()
    end)
    return ok and t or os.time()
end

local function _ensureNet()
    if netReady and PurchaseLot then return true end
    local ok, net = pcall(function()
        return require(ReplicatedStorage:WaitForChild("SharedModules"):WaitForChild("Networking"))
    end)
    if not ok or type(net) ~= "table" or type(net.Auctioneer) ~= "table" then
        stats.lastError = "Networking.Auctioneer missing"
        return false
    end
    Networking = net
    PurchaseLot = net.Auctioneer.PurchaseLot
    RequestSnapshot = net.Auctioneer.RequestSnapshot
    if not PurchaseLot or type(PurchaseLot.Fire) ~= "function" then
        stats.lastError = "PurchaseLot missing"
        return false
    end
    if not Auctioneer then
        pcall(function()
            Auctioneer = require(ReplicatedStorage.SharedModules.Auctioneer)
        end)
    end
    if not AuctionFlags then
        pcall(function()
            local sm = ReplicatedStorage.SharedModules
            local flags = sm:FindFirstChild("Flags")
            local inst = flags and flags:FindFirstChild("AuctioneerFlags") or sm:FindFirstChild("AuctioneerFlags")
            if inst then AuctionFlags = require(inst) end
        end)
    end
    netReady = true
    stats.lastError = nil
    return true
end

local function _parseSnapshot(raw)
    if typeof(raw) ~= "table" then return false end
    local lots = {}
    local manifest = raw.manifest
    if typeof(manifest) == "table" and typeof(manifest.lots) == "table" then
        lots = _collectLots(manifest.lots)
    elseif typeof(raw.lots) == "table" then
        lots = _collectLots(raw.lots)
    end
    snapshot = {
        lots = lots,
        stock = typeof(raw.stock) == "table" and raw.stock or {},
    }
    stockMap = snapshot.stock
    lastSnapshotAt = os.clock()
    _log("snapshot parsed", #lots, "lots")
    return #lots > 0
end

local function _requestSnapshot()
    if not _ensureNet() or not RequestSnapshot then return false end
    local raw
    local ok, err = pcall(function()
        if type(RequestSnapshot.InvokeServer) == "function" then
            raw = RequestSnapshot:InvokeServer()
        end
        if typeof(raw) ~= "table" and type(RequestSnapshot.Fire) == "function" then
            raw = RequestSnapshot:Fire()
        end
    end)
    if not ok then
        stats.lastError = tostring(err)
        _log("RequestSnapshot error", err)
        return false
    end
    if typeof(raw) == "table" then
        return _parseSnapshot(raw)
    end
    stats.lastError = "RequestSnapshot returned " .. typeof(raw)
    return false
end

local function _readCfg()
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    local buy = MAIN and MAIN.auto and MAIN.auto.buy
    local a = type(buy) == "table" and buy.auction or nil
    a = type(a) == "table" and a or {}

    local enabled = (G.AUTO_BUY_AUCTION_ENABLED == true)
        or (rawget(_G, "AUTO_BUY_AUCTION_ENABLED") == true)
        or (a.enabled == true)

    local maxPrice = G.AUTO_BUY_AUCTION_MAX_PRICE
    if maxPrice == nil then maxPrice = rawget(_G, "AUTO_BUY_AUCTION_MAX_PRICE") end
    if maxPrice == nil then maxPrice = a.max_price end
    maxPrice = math.max(0, math.floor(tonumber(maxPrice) or 0))

    return {
        enabled   = enabled,
        max_price = maxPrice,
        seed      = _normalizeSet(G.BUY_AUCTION_SEED_SELECTED or rawget(_G, "BUY_AUCTION_SEED_SELECTED") or (a.seed and a.seed.items)),
        gear      = _normalizeSet(G.BUY_AUCTION_GEAR_SELECTED or rawget(_G, "BUY_AUCTION_GEAR_SELECTED") or (a.gear and a.gear.items)),
        seedpack  = _normalizeSet(G.BUY_AUCTION_SEEDPACK_SELECTED or rawget(_G, "BUY_AUCTION_SEEDPACK_SELECTED") or (a.seedpack and a.seedpack.items)),
        egg       = _normalizeSet(G.BUY_AUCTION_EGG_SELECTED or rawget(_G, "BUY_AUCTION_EGG_SELECTED") or (a.egg and a.egg.items)),
    }
end

local function _lotSlot(category)
    category = tostring(category or "")
    if SLOT_CATEGORIES.seed[category] then return "seed" end
    if SLOT_CATEGORIES.seedpack[category] then return "seedpack" end
    if SLOT_CATEGORIES.egg[category] then return "egg" end
    if GEAR_CATEGORIES[category] then return "gear" end
    return "gear"
end

local function _matchesSelected(selected, ...)
    if not _hasAnySelected(selected) then return false end
    for i = 1, select("#", ...) do
        local name = tostring(select(i, ...) or "")
        if name ~= "" then
            if selected[name] == true then return true end
            local plain = _stripSelectSuffix(name)
            if plain ~= name and selected[plain] == true then return true end
            local nk = _normKey(name)
            for k, v in pairs(selected) do
                if v == true and _normKey(k) == nk then return true end
            end
        end
    end
    return false
end

local function _lotDisplayName(lot)
    if Auctioneer and type(Auctioneer.DisplayName) == "function" then
        local ok, name = pcall(Auctioneer.DisplayName, lot)
        if ok and typeof(name) == "string" and name ~= "" then return name end
    end
    return tostring(lot.item or "")
end

local function _lotSelected(lot, cfg)
    local slot = _lotSlot(lot.category)
    local selected = cfg[slot]
    if not _hasAnySelected(selected) then return false end
    local display = _lotDisplayName(lot)
    return _matchesSelected(selected, lot.item, display)
end

local function _stockLeft(lot)
    local id = _lotIdKey(lot.lotId)
    return stockMap[id] or stockMap[lot.lotId]
end

local function _lotAvailable(lot, serverTime)
    if (lot.expiresAt or 0) <= serverTime then return false, "expired" end
    local stockLeft = _stockLeft(lot)
    if lot.stockQuantity ~= nil and stockLeft ~= nil and stockLeft <= 0 then
        return false, "sold_out"
    end
    if Auctioneer and type(Auctioneer.IsActive) == "function" then
        local ok, active = pcall(Auctioneer.IsActive, lot, serverTime, stockLeft)
        if ok and active == false then return false, "inactive" end
    end
    return true
end

local function _lotPrice(lot, serverTime)
    if Auctioneer and type(Auctioneer.CurrentPrice) == "function" then
        local ok, price = pcall(Auctioneer.CurrentPrice, lot, serverTime)
        if ok and type(price) == "number" and price == price then
            return math.floor(price)
        end
    end
    return nil
end

local function _priceOk(price, maxPrice)
    if type(price) ~= "number" or price < 0 then return false end
    if maxPrice <= 0 then return true end
    return price <= maxPrice
end

local function _canPurchaseNow(lotId)
    local now = os.clock()
    if now < (cooldownUntil[lotId] or 0) then return false end
    local debounce = 0.25
    if AuctionFlags and AuctionFlags.PurchaseDebounceSeconds and type(AuctionFlags.PurchaseDebounceSeconds.Get) == "function" then
        local ok, v = pcall(AuctionFlags.PurchaseDebounceSeconds.Get, AuctionFlags.PurchaseDebounceSeconds)
        if ok and type(v) == "number" then debounce = v end
    end
    if now - (purchaseAt[lotId] or 0) < debounce then return false end
    if now - lastPurchaseAt < PURCHASE_GAP_SEC then return false end
    return true
end

local function _tryBuyLot(lot, price, cfg)
    if not _canPurchaseNow(lot.lotId) then return false, "debounce" end
    local money = _getMoney()
    if type(money) == "number" and money < price then
        return false, "no_money"
    end
    local ok, err = pcall(function()
        PurchaseLot:Fire(lot.lotId, price)
    end)
    if not ok then
        stats.lastError = tostring(err)
        return false, "fire_fail"
    end
    local now = os.clock()
    purchaseAt[lot.lotId] = now
    lastPurchaseAt = now
    local cd = 0
    if AuctionFlags and AuctionFlags.PurchaseCooldownSeconds and type(AuctionFlags.PurchaseCooldownSeconds.Get) == "function" then
        local okCd, v = pcall(AuctionFlags.PurchaseCooldownSeconds.Get, AuctionFlags.PurchaseCooldownSeconds)
        if okCd and type(v) == "number" and v > 0 then cd = v end
    end
    if cd > 0 then cooldownUntil[lot.lotId] = now + cd end
    stats.buys += 1
    stats.lastBuy = {
        lotId = lot.lotId,
        item = lot.item,
        category = lot.category,
        price = price,
        at = os.time(),
    }
    _setStatus(string.format("Beli %s @ %s", tostring(lot.item), tostring(price)))
    _log("buy", lot.lotId, lot.item, price)
    return true
end

local function _tick()
    local cfg = _readCfg()
    if not cfg.enabled then
        _setStatus("Off")
        return LOOP_SEC
    end
    if not _hasAnySelected(cfg.seed) and not _hasAnySelected(cfg.gear)
        and not _hasAnySelected(cfg.seedpack) and not _hasAnySelected(cfg.egg) then
        _setStatus("Pilih item di dropdown")
        return LOOP_SEC
    end
    if not _ensureNet() then
        _setStatus("Auction remote belum ready")
        return LOOP_SEC * 2
    end
    if #eventConns == 0 then
        _hookEvents()
    end
    local needSnap = not snapshot or #snapshot.lots == 0
        or (os.clock() - lastSnapshotAt) > SNAPSHOT_EVERY_SEC
    if needSnap then
        _requestSnapshot()
    end
    if not snapshot or #snapshot.lots == 0 then
        _setStatus(stats.lastError and ("Menunggu data: " .. stats.lastError) or "Menunggu auction data...")
        return LOOP_SEC
    end

    local serverTime = _getServerTime()
    for _, lot in ipairs(snapshot.lots) do
        if _lotSelected(lot, cfg) then
            local okAvail = _lotAvailable(lot, serverTime)
            if okAvail then
                local price = _lotPrice(lot, serverTime)
                if price and _priceOk(price, cfg.max_price) then
                    local bought, reason = _tryBuyLot(lot, price, cfg)
                    if bought then return LOOP_SEC end
                    if reason == "no_money" then
                        _setStatus("Uang tidak cukup")
                        return LOOP_SEC * 3
                    end
                elseif price and cfg.max_price > 0 then
                    _setStatus(string.format("Menunggu harga <= %s (%s)", cfg.max_price, lot.item))
                end
            end
        end
    end

    _setStatus("Scan auction...")
    return LOOP_SEC
end

local function _hookEvents()
    if #eventConns > 0 or not _ensureNet() then return end
    local ae = Networking.Auctioneer
    local function onSnap(payload)
        if typeof(payload) == "table" then
            _parseSnapshot(payload)
            _log("Snapshot event", snapshot and #snapshot.lots or 0, "lots")
        end
    end
    local function onStock(payload)
        if typeof(payload) == "table" and typeof(payload.stock) == "table" then
            stockMap = payload.stock
            if snapshot then snapshot.stock = stockMap end
        end
    end
    local function onResult(lotId, success)
        lotId = _lotIdKey(lotId)
        if success == false then
            cooldownUntil[lotId] = nil
            purchaseAt[lotId] = nil
        end
    end
    _connectRemoteEvent(ae.Snapshot, onSnap)
    _connectRemoteEvent(ae.StockUpdate, onStock)
    _connectRemoteEvent(ae.PurchaseResult, onResult)
end

local function _unhookEvents()
    for _, c in ipairs(eventConns) do
        pcall(function() c:Disconnect() end)
    end
    table.clear(eventConns)
end

function M.Start()
    if running then return end
    running = true
    loopId += 1
    local myId = loopId
    _hookEvents()
    task.spawn(function()
        _requestSnapshot()
        while running and loopId == myId do
            local waitSec = LOOP_SEC
            local ok, ret = pcall(_tick)
            if ok and type(ret) == "number" then waitSec = ret end
            task.wait(waitSec)
        end
    end)
end

function M.Stop()
    running = false
    loopId += 1
    _unhookEvents()
    _setStatus("Off")
end

function M.EnsureRunning()
    local cfg = _readCfg()
    if cfg.enabled then M.Start() else M.Stop() end
end

function M.SyncFromState()
    M.EnsureRunning()
end

function M.SyncFromGlobals()
    M.EnsureRunning()
end

function M.GetStats()
    return stats
end

function M.RefreshSnapshot()
    return _requestSnapshot()
end

return M
 end,               required = false },
    { key = "SectionAutoBuyAuction",   name = "Section Auto Buy Auction", factory = function() -- section_auto_buy_auction.lua — UI Auto Buy Auction (tab Auto → Buy)

local G = (getgenv and getgenv()) or _G
local M = {}

local function cleanMap(map)
    local out = {}
    if type(map) ~= "table" then return out end
    for k, v in pairs(map) do
        if v == true or v == 1 or v == "true" then
            local key = tostring(k)
            if key ~= "" then out[key] = true end
        end
    end
    return out
end

local function mapToArray(map)
    local arr = {}
    for k, v in pairs(map or {}) do
        if v == true then arr[#arr + 1] = tostring(k) end
    end
    table.sort(arr)
    return arr
end

local function normalizeMaxPrice(raw)
    return math.max(0, math.floor(tonumber(raw) or 0))
end

function M.Register(ctx)
    if type(ctx) ~= "table" or type(ctx.ui) ~= "table" then return end

    local ui = ctx.ui
    local getAuto = ctx.getAuto
    local patchAuto = ctx.patchAuto
    local patchAutoOnly = ctx.patchAutoOnly
    local registerFlush = ctx.registerFlush
    local cleanSelectedMap = ctx.cleanSelectedMap or cleanMap
    local arrayToMap = ctx.arrayToMap
    local mapToArrayFn = ctx.mapToArray or mapToArray

    local PlantListView = ctx.PlantListView or G.PlantListView
    local ShopListView = ctx.ShopListView or G.ShopListView

    if type(getAuto) ~= "function" or type(patchAuto) ~= "function" then
        warn("[GAG2] SectionAutoBuyAuction: missing getAuto/patchAuto")
        return
    end

    local BUY = getAuto("buy")
    BUY.auction = type(BUY.auction) == "table" and BUY.auction or {}
    local A = BUY.auction

    A.enabled = (A.enabled == true)
    A.max_price = normalizeMaxPrice(A.max_price)
    A.seed = type(A.seed) == "table" and A.seed or { items = {} }
    A.gear = type(A.gear) == "table" and A.gear or { items = {} }
    A.seedpack = type(A.seedpack) == "table" and A.seedpack or { items = {} }
    A.egg = type(A.egg) == "table" and A.egg or { items = {} }
    A.seed.items = type(A.seed.items) == "table" and A.seed.items or {}
    A.gear.items = type(A.gear.items) == "table" and A.gear.items or {}
    A.seedpack.items = type(A.seedpack.items) == "table" and A.seedpack.items or {}
    A.egg.items = type(A.egg.items) == "table" and A.egg.items or {}

    local SEL_SEED = cleanSelectedMap(arrayToMap and arrayToMap(A.seed.items) or cleanMap(A.seed.items))
    local SEL_GEAR = cleanSelectedMap(arrayToMap and arrayToMap(A.gear.items) or cleanMap(A.gear.items))
    local SEL_SEEDPACK = cleanSelectedMap(arrayToMap and arrayToMap(A.seedpack.items) or cleanMap(A.seedpack.items))
    local SEL_EGG = cleanSelectedMap(arrayToMap and arrayToMap(A.egg.items) or cleanMap(A.egg.items))

    local function getModule()
        return G.AutoBuyAuctionModule or G.AutoBuyAuction or rawget(_G, "AutoBuyAuctionModule") or rawget(_G, "AutoBuyAuction")
    end

    local function writeGlobals()
        local enableApi = G.__GAG2_BUY_AUCTION_ENABLE_API or rawget(_G, "__GAG2_BUY_AUCTION_ENABLE_API")
        if type(enableApi) == "table" and type(enableApi.get) == "function" then
            A.enabled = (enableApi.get() == true)
        end

        A.max_price = normalizeMaxPrice(A.max_price)
        A.seed.items = mapToArrayFn(SEL_SEED)
        A.gear.items = mapToArrayFn(SEL_GEAR)
        A.seedpack.items = mapToArrayFn(SEL_SEEDPACK)
        A.egg.items = mapToArrayFn(SEL_EGG)

        G.AUTO_BUY_AUCTION_ENABLED = A.enabled
        _G.AUTO_BUY_AUCTION_ENABLED = A.enabled
        G.AUTO_BUY_AUCTION_MAX_PRICE = A.max_price
        _G.AUTO_BUY_AUCTION_MAX_PRICE = A.max_price
        G.BUY_AUCTION_SEED_SELECTED = SEL_SEED
        _G.BUY_AUCTION_SEED_SELECTED = SEL_SEED
        G.BUY_AUCTION_GEAR_SELECTED = SEL_GEAR
        _G.BUY_AUCTION_GEAR_SELECTED = SEL_GEAR
        G.BUY_AUCTION_SEEDPACK_SELECTED = SEL_SEEDPACK
        _G.BUY_AUCTION_SEEDPACK_SELECTED = SEL_SEEDPACK
        G.BUY_AUCTION_EGG_SELECTED = SEL_EGG
        _G.BUY_AUCTION_EGG_SELECTED = SEL_EGG

        if type(patchAutoOnly) == "function" then
            patchAutoOnly("buy", {
                auction = {
                    enabled = A.enabled,
                    max_price = A.max_price,
                    seed = { items = A.seed.items },
                    gear = { items = A.gear.items },
                    seedpack = { items = A.seedpack.items },
                    egg = { items = A.egg.items },
                },
            })
        end
    end

    local function applyRuntime()
        writeGlobals()
        local mod = getModule()
        if type(mod) ~= "table" then return end
        if A.enabled then
            if type(mod.Start) == "function" then pcall(mod.Start, mod)
            elseif type(mod.start) == "function" then pcall(mod.start, mod) end
        else
            if type(mod.Stop) == "function" then pcall(mod.Stop, mod)
            elseif type(mod.stop) == "function" then pcall(mod.stop, mod) end
        end
    end

    if type(registerFlush) == "function" then
        registerFlush("buy_auction", function()
            writeGlobals()
        end)
    end

    G.__GAG2_SYNC_AUTO_BUY_AUCTION = applyRuntime
    _G.__GAG2_SYNC_AUTO_BUY_AUCTION = applyRuntime

    local body = ui:CreateSection("Auto Buy Auction", false)

    ui:CreateRowDropdown(body, {
        label       = "Select Seed",
        placeholder = "Select Options",
        mode        = "multi",
        getItems = function()
            if PlantListView and type(PlantListView.buildSeedItems) == "function" then
                return PlantListView.buildSeedItems() or {}
            end
            return {}
        end,
        initial = SEL_SEED,
        onChanged = function(_, selectedMap)
            SEL_SEED = cleanSelectedMap(selectedMap)
            patchAuto("buy", { auction = { seed = { items = mapToArrayFn(SEL_SEED) } } }, applyRuntime)
        end,
    })

    ui:CreateRowDropdown(body, {
        label       = "Select Gear",
        placeholder = "Select Options",
        mode        = "multi",
        getItems = function()
            if ShopListView and type(ShopListView.buildGearItems) == "function" then
                return ShopListView.buildGearItems() or {}
            end
            return {}
        end,
        initial = SEL_GEAR,
        onChanged = function(_, selectedMap)
            SEL_GEAR = cleanSelectedMap(selectedMap)
            patchAuto("buy", { auction = { gear = { items = mapToArrayFn(SEL_GEAR) } } }, applyRuntime)
        end,
    })

    ui:CreateRowDropdown(body, {
        label       = "Select Seed Pack",
        placeholder = "Select Options",
        mode        = "multi",
        getItems = function()
            if ShopListView and type(ShopListView.buildSeedPackItems) == "function" then
                return ShopListView.buildSeedPackItems() or {}
            end
            return {}
        end,
        initial = SEL_SEEDPACK,
        onChanged = function(_, selectedMap)
            SEL_SEEDPACK = cleanSelectedMap(selectedMap)
            patchAuto("buy", { auction = { seedpack = { items = mapToArrayFn(SEL_SEEDPACK) } } }, applyRuntime)
        end,
    })

    ui:CreateRowDropdown(body, {
        label       = "Select Egg",
        placeholder = "Select Options",
        mode        = "multi",
        getItems = function()
            if ShopListView and type(ShopListView.buildEggItems) == "function" then
                return ShopListView.buildEggItems() or {}
            end
            return {}
        end,
        initial = SEL_EGG,
        onChanged = function(_, selectedMap)
            SEL_EGG = cleanSelectedMap(selectedMap)
            patchAuto("buy", { auction = { egg = { items = mapToArrayFn(SEL_EGG) } } }, applyRuntime)
        end,
    })

    ui:CreateRowInput(body, "Max Price (0 = any price)", tostring(A.max_price or 0), function(txt)
        A.max_price = normalizeMaxPrice(txt)
        patchAuto("buy", { auction = { max_price = A.max_price } }, applyRuntime)
    end)

    local _, _, enableApi = ui:CreateRowToggle(body, "Enable Auto Buy Auction", A.enabled, function(isOn)
        A.enabled = (isOn == true)
        patchAuto("buy", { auction = { enabled = A.enabled } }, applyRuntime)
    end)
    G.__GAG2_BUY_AUCTION_ENABLE_API = enableApi
    _G.__GAG2_BUY_AUCTION_ENABLE_API = enableApi

    ui:CreateRowLabel(body, "Max Price 0 = beli harga berapapun. >0 = max sheckles per item.", nil, nil, "muted")

    applyRuntime()
end

return M
 end,   required = false },
    { key = "AutoGiftPrice",           name = "Auto Gift Price",         factory = function() -- AutoGiftPrice.lua — harvest price combo search (subset of AutoGift)

local M = {}

function M.create(deps)
    deps = type(deps) == "table" and deps or {}
    local clampBatch = deps.clampBatch or function(n) return math.max(1, math.floor(tonumber(n) or 1)) end
    local maxBatch = tonumber(deps.maxBatch) or 10000
    local formatSellPrice = deps.formatSellPrice or tostring
    local isHarvested = deps.isHarvestedFruitsCategory or function() return false end
    local entrySellPrice = deps.entrySellPrice or function() return 0 end

    local PRICE_SUBSET_MAX_ITEMS = 200

    local function itemPrice(item)
        return math.floor(tonumber(item and item.SellPrice) or 0)
    end

    local function itemKey(item)
        return tostring(item and item.ItemKey or "")
    end

    local function poolFromCandidates(candidates)
        local pool = {}
        for _, item in ipairs(candidates) do
            local cat = item.Category
            if not isHarvested(cat) then
                continue
            end
            local price = math.floor(tonumber(item.SellPrice) or 0)
            if price <= 0 then
                price = entrySellPrice(cat, item.ItemKey, item.Entry)
                item.SellPrice = price
            end
            if price > 0 then
                pool[#pool + 1] = item
            end
        end
        return pool
    end

    local function formatBreakdown(pick)
        if type(pick) ~= "table" or #pick == 0 then return "" end
        local map = {}
        for _, item in ipairs(pick) do
            local p = math.floor(tonumber(item.SellPrice) or 0)
            if p > 0 then
                map[p] = (map[p] or 0) + 1
            end
        end
        local keys = {}
        for p in pairs(map) do
            keys[#keys + 1] = p
        end
        table.sort(keys)
        local parts = {}
        for _, p in ipairs(keys) do
            local c = map[p]
            if c > 1 then
                parts[#parts + 1] = tostring(c) .. "x" .. formatSellPrice(p)
            else
                parts[#parts + 1] = formatSellPrice(p)
            end
        end
        return table.concat(parts, "+")
    end

    local function filterPricePool(pool, maxSum)
        local items = {}
        for _, item in ipairs(pool) do
            local p = itemPrice(item)
            if p > 0 and p <= maxSum then
                items[#items + 1] = item
            end
        end
        return items
    end

    local function sortPriceItems(items, descending)
        table.sort(items, function(a, b)
            if descending then
                return itemPrice(a) > itemPrice(b)
            end
            return itemPrice(a) < itemPrice(b)
        end)
        return items
    end

    local function findMaxComboUnder(pool, maxSum, maxItems)
        maxSum = math.max(1, math.floor(tonumber(maxSum) or 0))
        maxItems = math.max(1, math.min(clampBatch(maxItems or maxBatch), #pool))
        local items = sortPriceItems(filterPricePool(pool, maxSum), true)
        local combo = {}
        local sum = 0
        for _, item in ipairs(items) do
            if #combo >= maxItems then
                break
            end
            local p = itemPrice(item)
            if sum + p <= maxSum then
                combo[#combo + 1] = item
                sum += p
            end
        end
        if #combo > 0 then
            return combo, sum
        end
        return nil, 0
    end

    local function tryBuildPriceCombo(items, minSum, maxSum, maxItems, descending)
        minSum = math.max(1, math.floor(tonumber(minSum) or 0))
        maxSum = math.max(minSum, math.floor(tonumber(maxSum) or 0))
        maxItems = math.max(1, math.min(clampBatch(maxItems or maxBatch), #items))
        if #items == 0 then
            return nil, 0
        end

        local order = sortPriceItems(items, descending == true)
        local combo = {}
        local usedKeys = {}
        local sum = 0

        local function tryAddFromList(list)
            for _, item in ipairs(list) do
                if sum >= minSum then
                    return
                end
                if #combo >= maxItems then
                    return
                end
                local key = itemKey(item)
                if key == "" or usedKeys[key] then
                    continue
                end
                local p = itemPrice(item)
                if p <= 0 or sum + p > maxSum then
                    continue
                end
                combo[#combo + 1] = item
                usedKeys[key] = true
                sum += p
            end
        end

        tryAddFromList(order)
        if sum < minSum then
            return nil, 0
        end

        local trimPasses = math.max(12, #order * 2)
        while trimPasses > 0 do
            if sum >= minSum and sum <= maxSum then
                return combo, sum
            end
            if sum <= maxSum and sum < minSum then
                tryAddFromList(sortPriceItems(order, false))
                if sum >= minSum and sum <= maxSum then
                    return combo, sum
                end
                return nil, 0
            end
            if sum <= maxSum then
                return nil, 0
            end

            trimPasses -= 1
            local removeIdx, removePrice = 1, 0
            for i, item in ipairs(combo) do
                local p = itemPrice(item)
                if p > removePrice then
                    removeIdx = i
                    removePrice = p
                end
            end
            local removed = table.remove(combo, removeIdx)
            usedKeys[itemKey(removed)] = nil
            sum -= removePrice

            for _, item in ipairs(sortPriceItems(order, false)) do
                if sum >= minSum and sum <= maxSum then
                    break
                end
                if #combo >= maxItems then
                    break
                end
                local key = itemKey(item)
                if key == "" or usedKeys[key] then
                    continue
                end
                local p = itemPrice(item)
                if p <= 0 or sum + p > maxSum then
                    continue
                end
                combo[#combo + 1] = item
                usedKeys[key] = true
                sum += p
            end
        end

        if sum >= minSum and sum <= maxSum then
            return combo, sum
        end
        return nil, 0
    end

    local function findPriceSubset(pool, minSum, maxSum, maxItems)
        minSum = math.max(1, math.floor(tonumber(minSum) or 0))
        maxSum = math.max(minSum, math.floor(tonumber(maxSum) or 0))
        maxItems = math.max(1, math.min(clampBatch(maxItems or maxBatch), #pool))
        if minSum > maxSum or #pool == 0 then
            return nil, 0
        end

        local items = filterPricePool(pool, maxSum)
        if #items == 0 then
            return nil, 0
        end
        if #items > PRICE_SUBSET_MAX_ITEMS then
            items = sortPriceItems(items, true)
            local trimmed = {}
            for i = 1, PRICE_SUBSET_MAX_ITEMS do
                trimmed[i] = items[i]
            end
            items = trimmed
        end

        local pick, total = tryBuildPriceCombo(items, minSum, maxSum, maxItems, true)
        if pick then
            return pick, total
        end
        pick, total = tryBuildPriceCombo(items, minSum, maxSum, maxItems, false)
        if pick then
            return pick, total
        end
        return nil, 0
    end

    local function pickToBatch(pick, total)
        if type(pick) ~= "table" or #pick == 0 then
            return nil, 0
        end
        local batch = {}
        for _, item in ipairs(pick) do
            batch[#batch + 1] = {
                Category = item.Category,
                ItemKey = item.ItemKey,
                Count = 1,
                SellPrice = itemPrice(item),
            }
        end
        return batch, total
    end

    local function buildMultiBatchPricePlan(candidates, targetMin, targetMax, maxItems)
        targetMin = math.max(1, math.floor(tonumber(targetMin) or 0))
        targetMax = math.max(targetMin, math.floor(tonumber(targetMax) or 0))
        maxItems = math.max(1, clampBatch(maxItems or 20))

        local pool = poolFromCandidates(candidates)
        if #pool == 0 then
            return nil, 0, #pool, 0
        end

        local sent = 0
        local allPick = {}
        local usedKeys = {}
        local batchCount = 0
        local maxRounds = math.ceil(#pool / math.max(1, maxItems)) + 2

        while sent < targetMin and batchCount < maxRounds do
            local remainMin = targetMin - sent
            local remainMax = targetMax - sent
            local available = {}
            for _, item in ipairs(pool) do
                local key = itemKey(item)
                if key ~= "" and not usedKeys[key] then
                    available[#available + 1] = item
                end
            end
            if #available == 0 then
                break
            end

            local pick, total = findPriceSubset(available, remainMin, remainMax, maxItems)
            if not pick then
                pick, total = findMaxComboUnder(available, remainMax, maxItems)
            end
            if not pick or #pick == 0 or total <= 0 then
                break
            end

            batchCount += 1
            for _, item in ipairs(pick) do
                allPick[#allPick + 1] = item
                usedKeys[itemKey(item)] = true
            end
            sent += total
            if sent >= targetMin and sent <= targetMax then
                break
            end
        end

        if sent >= targetMin and sent <= targetMax then
            return allPick, sent, #pool, batchCount
        end
        return nil, sent, #pool, batchCount
    end

    local function planPriceBatch(candidates, minSum, maxSum, maxItems, usedKeys)
        local pool = poolFromCandidates(candidates)
        if type(usedKeys) == "table" then
            local filtered = {}
            for _, item in ipairs(pool) do
                local key = itemKey(item)
                if key ~= "" and not usedKeys[key] then
                    filtered[#filtered + 1] = item
                end
            end
            pool = filtered
        end
        local pick, total = findPriceSubset(pool, minSum, maxSum, maxItems)
        if not pick then
            pick, total = findMaxComboUnder(pool, maxSum, maxItems)
        end
        if not pick then
            return nil, 0, pool
        end
        local batch, batchTotal = pickToBatch(pick, total)
        return batch, batchTotal, pool
    end

    local function pricePlanSummary(pick, total, minSum, maxSum, poolSize, batchCount)
        if type(pick) ~= "table" or #pick == 0 then
            return "Tidak ada kombinasi "
                .. formatSellPrice(minSum) .. "–" .. formatSellPrice(maxSum)
                .. " (" .. tostring(poolSize or 0) .. " buah dicek)"
        end
        local batchNote = ""
        if type(batchCount) == "number" and batchCount > 1 then
            batchNote = " / " .. tostring(batchCount) .. " batch"
        end
        return string.format(
            "Plan: %d buah %s (range %s–%s%s) [%s]",
            #pick,
            formatSellPrice(total),
            formatSellPrice(minSum),
            formatSellPrice(maxSum),
            batchNote,
            formatBreakdown(pick)
        )
    end

    return {
        poolFromCandidates = poolFromCandidates,
        formatBreakdown = formatBreakdown,
        buildMultiBatchPricePlan = buildMultiBatchPricePlan,
        planPriceBatch = planPriceBatch,
        pricePlanSummary = pricePlanSummary,
    }
end

return M
 end,                  required = false },
    { key = "GiftMailHistory",         name = "Gift Mail History",       factory = function() -- GiftMailHistory.lua — log gift mail sends to file + side panel UI

local HttpService = game:GetService("HttpService")
local Players = game:GetService("Players")
local UserInputService = game:GetService("UserInputService")
local LP = Players.LocalPlayer

local G = (getgenv and getgenv()) or _G
local M = {}

local SAVE_DIR = "growagarden2"
local FILE_VERSION = 1
local DEFAULT_RETAIN_DAYS = 7
local MAX_ENTRIES = 500
local RENDER_PAGE_SIZE = 50
local SCROLL_LOAD_THRESHOLD = 72

local CAN_FS = (typeof(writefile) == "function" and typeof(readfile) == "function"
    and typeof(isfile) == "function" and typeof(makefolder) == "function")

local COLOR_PANEL = Color3.fromRGB(10, 10, 10)
local COLOR_PANEL_ALT = Color3.fromRGB(15, 15, 15)
local COLOR_CARD = Color3.fromRGB(12, 12, 12)
local COLOR_CARD_HEAD = Color3.fromRGB(16, 16, 16)
local COLOR_YELLOW = Color3.fromRGB(255, 211, 0)
local COLOR_WHITE = Color3.fromRGB(255, 255, 255)
local COLOR_GRAY = Color3.fromRGB(180, 180, 180)
local COLOR_DIM = Color3.fromRGB(105, 105, 105)
local COLOR_STROKE = Color3.fromRGB(60, 60, 60)
local COLOR_SEARCH = Color3.fromRGB(18, 18, 18)
local COLOR_OK = Color3.fromRGB(95, 220, 130)
local COLOR_FAIL = Color3.fromRGB(235, 95, 95)

local RADIUS = 18
local RADIUS_CARD = 10
local UI_VER = 18

local CAT_ICONS = {
    HarvestedFruits = "🍎",
    Pets = "🐾",
    Seeds = "🌱",
}

local retainDays = DEFAULT_RETAIN_DAYS
local entries = {}
local searchQuery = ""
local panelVisible = false
local uiBuilt = false
local hubMode = false
local gui = nil
local panelRoot = nil
local listFrame = nil
local listScroll = nil
local countLabel = nil
local searchBox = nil
local filteredIndices = {}
local filteredMatchCount = 0
local renderedCount = 0
local scrollLoading = false
local scrollConn = nil

local _findPanelInstance, _rebindUiRefs, _setPanelVisible, _buildUi

local function _safeName(s)
    s = tostring(s or "player")
    s = s:gsub("[^%w%-_.]", "_"):gsub("_+", "_")
    return s:sub(1, 48)
end

local function _historyFile()
    return SAVE_DIR .. "/" .. _safeName(LP and LP.Name or "player") .. "_gift_mail_history.json"
end

local function _ensureFolder()
    if not CAN_FS then return false end
    if typeof(isfolder) == "function" and not isfolder(SAVE_DIR) then
        pcall(makefolder, SAVE_DIR)
    end
    return typeof(isfolder) == "function" and isfolder(SAVE_DIR)
end

local function _jsonEncode(t)
    local ok, s = pcall(function() return HttpService:JSONEncode(t) end)
    return ok and s or nil
end

local function _jsonDecode(s)
    local ok, t = pcall(function() return HttpService:JSONDecode(s) end)
    return ok and type(t) == "table" and t or nil
end

local function _clampRetainDays(n)
    n = math.floor(tonumber(n) or DEFAULT_RETAIN_DAYS)
    if n < 1 then n = 1 end
    if n > 90 then n = 90 end
    return n
end

local function _dayKey(ts)
    return os.date("%Y-%m-%d", ts or os.time())
end

local function _prune(list)
    list = type(list) == "table" and list or {}
    local cutoff = os.time() - retainDays * 86400
    local out = {}
    for _, e in ipairs(list) do
        if type(e) == "table" then
            local ts = math.floor(tonumber(e.ts) or 0)
            if ts <= 0 or ts >= cutoff then
                out[#out + 1] = e
            end
        end
    end
    if #out > MAX_ENTRIES then
        local start = #out - MAX_ENTRIES + 1
        local trimmed = {}
        for i = start, #out do
            trimmed[#trimmed + 1] = out[i]
        end
        out = trimmed
    end
    return out
end

local function _saveFile()
    if not CAN_FS or not _ensureFolder() then return false end
    entries = _prune(entries)
    local payload = {
        version = FILE_VERSION,
        retain_days = retainDays,
        entries = entries,
    }
    local json = _jsonEncode(payload)
    if not json then return false end
    local ok = pcall(writefile, _historyFile(), json)
    return ok == true
end

local function _loadFile()
    entries = {}
    if not CAN_FS then return entries end
    local path = _historyFile()
    if not isfile(path) then return entries end
    local ok, text = pcall(readfile, path)
    if not ok or type(text) ~= "string" or text == "" then return entries end
    local data = _jsonDecode(text)
    if not data then return entries end
    retainDays = _clampRetainDays(data.retain_days or retainDays)
    local raw = type(data.entries) == "table" and data.entries or {}
    local list = {}
    if #raw > 0 then
        list = raw
    else
        for _, v in pairs(raw) do
            if type(v) == "table" then
                list[#list + 1] = v
            end
        end
        table.sort(list, function(a, b)
            return (tonumber(a.ts) or 0) > (tonumber(b.ts) or 0)
        end)
    end
    entries = _prune(list)
    return entries
end

local function _findScrollFrame(content)
    if not content then return nil end
    local viewport = content:FindFirstChild("ListViewport")
    if viewport then
        return viewport:FindFirstChild("Scroll")
    end
    return content:FindFirstChild("Scroll")
end

local function _panelUiReady(root)
    if not root or not root.Parent then return false end
    if root:GetAttribute("UiVer") ~= UI_VER then return false end
    local content = root:FindFirstChild("Content")
    if not content then return false end
    local scroll = _findScrollFrame(content)
    local list = scroll and scroll:FindFirstChild("List")
    return scroll ~= nil and list ~= nil
end

local function _clearListCards()
    if not listFrame then return end
    for _, ch in ipairs(listFrame:GetChildren()) do
        if ch:IsA("Frame") or ch:IsA("TextLabel") then
            ch:Destroy()
        end
    end
end

local function _entryIndicesNewestFirst()
    local idx = {}
    for i = 1, #entries do
        if type(entries[i]) == "table" then
            idx[#idx + 1] = i
        end
    end
    if #idx == 0 then
        for k, e in pairs(entries) do
            if type(k) == "number" and type(e) == "table" then
                idx[#idx + 1] = k
            end
        end
        table.sort(idx)
    end
    table.sort(idx, function(a, b)
        local ta = math.floor(tonumber(entries[a] and entries[a].ts) or 0)
        local tb = math.floor(tonumber(entries[b] and entries[b].ts) or 0)
        if ta ~= tb then return ta > tb end
        return a > b
    end)
    return idx
end

local CAT_LABELS = {
    HarvestedFruits = "Harvested Fruits",
    Pets = "Pets",
    Seeds = "Seeds",
}
local CAT_ORDER = { HarvestedFruits = 1, Pets = 2, Seeds = 3 }

local function _catTheme(_cat)
    return {
        bg = COLOR_PANEL_ALT,
        head = Color3.fromRGB(18, 18, 18),
        accent = COLOR_WHITE,
        price = COLOR_YELLOW,
    }
end

local function _round(inst, r)
    local c = Instance.new("UICorner")
    if type(r) == "number" and r >= 100 then
        c.CornerRadius = UDim.new(1, 0)
    else
        c.CornerRadius = UDim.new(0, r or RADIUS)
    end
    c.Parent = inst
    return c
end

local function _softStroke(inst, color, t, tr)
    local s = Instance.new("UIStroke")
    s.Color = color or COLOR_STROKE
    s.Thickness = t or 1
    s.Transparency = tr or 0.55
    s.ApplyStrokeMode = Enum.ApplyStrokeMode.Border
    pcall(function()
        s.LineJoinMode = Enum.LineJoinMode.Round
    end)
    s.Parent = inst
    return s
end

local function _insetBorder(parent, opts)
    opts = type(opts) == "table" and opts or {}
    local radius = opts.radius or RADIUS
    local border = opts.border or COLOR_YELLOW
    local fill = opts.fill or COLOR_PANEL
    local inset = opts.inset or 1

    local shell = Instance.new("Frame")
    shell.Name = opts.name or "BorderShell"
    shell.BackgroundColor3 = border
    shell.BorderSizePixel = 0
    shell.Size = opts.size or UDim2.new(1, 0, 0, 0)
    shell.Parent = parent
    _round(shell, radius)

    local inner = Instance.new("Frame")
    inner.Name = opts.innerName or "BorderInner"
    inner.BackgroundColor3 = fill
    inner.BorderSizePixel = 0
    inner.ClipsDescendants = opts.clip == true
    if opts.clip == true then
        shell.ClipsDescendants = true
    end
    inner.Position = UDim2.new(0, inset, 0, inset)
    inner.Parent = shell
    _round(inner, math.max(radius - inset, 4))

    if opts.autoY == true then
        inner.Size = UDim2.new(1, -(inset * 2), 0, 0)
        inner.AutomaticSize = Enum.AutomaticSize.Y
        local function syncShell()
            local h = inner.AbsoluteSize.Y
            shell.Size = UDim2.new(1, 0, 0, math.max(h + (inset * 2), inset * 2))
        end
        inner:GetPropertyChangedSignal("AbsoluteSize"):Connect(syncShell)
        task.defer(syncShell)
    else
        inner.Size = UDim2.new(1, -(inset * 2), 1, -(inset * 2))
    end

    return shell, inner
end

local function _formatPrice(n)
    n = math.floor(tonumber(n) or 0)
    if n <= 0 then return "" end
    if n >= 1000000000 then return string.format("%.2fB", n / 1000000000) end
    if n >= 1000000 then return string.format("%.2fM", n / 1000000) end
    if n >= 1000 then return string.format("%.1fK", n / 1000) end
    return tostring(n)
end

local function _harvestTotalFromSummary(summary)
    local total = 0
    if type(summary) ~= "table" then return 0 end
    for _, row in ipairs(summary) do
        if row.cat == "HarvestedFruits" then
            total += math.max(0, math.floor(tonumber(row.price) or 0))
        end
    end
    return total
end

local function _resolveHarvestTotal(storedTotal, summary)
    local fromSummary = _harvestTotalFromSummary(summary)
    if fromSummary > 0 then
        return fromSummary
    end
    return math.max(0, math.floor(tonumber(storedTotal) or 0))
end

local function _catLabel(cat)
    cat = tostring(cat or "")
    if CAT_LABELS[cat] then return CAT_LABELS[cat] end
    return cat:gsub("(%l)(%u)", "%1 %2")
end

local function _catSortKey(cat)
    return CAT_ORDER[tostring(cat or "")] or 100
end

local function _isUuidLike(s)
    s = tostring(s or "")
    if #s < 12 then return false end
    return s:match("^[%x%-]+$") ~= nil
end

local function _fallbackTypeName(cat)
    cat = tostring(cat or "")
    if cat == "Pets" then return "Pet" end
    if cat == "HarvestedFruits" then return "Fruit" end
    if cat == "Seeds" then return "Seed" end
    return _catLabel(cat)
end

local function _displayItemName(name, cat)
    name = tostring(name or ""):gsub("^%s+", ""):gsub("%s+$", "")
    if name == "" or name == "?" then return nil end
    if _isUuidLike(name) then return nil end
    local catL = _catLabel(tostring(cat or ""))
    if name == catL or name == cat or name:lower() == catL:lower() then
        return nil
    end
    return name
end

local function _sanitizeDisplayName(name, cat)
    name = tostring(name or ""):gsub("^%s+", ""):gsub("%s+$", "")
    if name == "" or name == "?" or _isUuidLike(name) then
        return _fallbackTypeName(cat)
    end
    local dn = _displayItemName(name, cat)
    if dn then return dn end
    return _fallbackTypeName(cat)
end

local function _normalizeSummaryRow(row)
    if type(row) ~= "table" then return nil end
    local cat = tostring(row.cat or row.Category or "")
    local count = math.max(1, math.floor(tonumber(row.count or row.Count) or 1))
    local price = math.max(0, math.floor(tonumber(row.price or row.Price) or 0))
    if price <= 0 then
        local unit = math.max(0, math.floor(tonumber(row.UnitPrice or row.unitPrice) or 0))
        if unit > 0 then
            price = unit * count
        end
    end
    return {
        cat = cat,
        name = _sanitizeDisplayName(row.name or row.Name, cat),
        count = count,
        price = price,
    }
end

local function _getEntrySummary(e)
    if type(e.summary) == "table" and #e.summary > 0 then
        local out = {}
        for _, row in ipairs(e.summary) do
            local r = _normalizeSummaryRow(row)
            if r then out[#out + 1] = r end
        end
        return out
    end
    if type(e.summary) == "table" then
        local out = {}
        for _, row in pairs(e.summary) do
            if type(row) == "table" then
                local r = _normalizeSummaryRow(row)
                if r then out[#out + 1] = r end
            end
        end
        if #out > 0 then return out end
    end
    local items = type(e.items) == "table" and e.items or {}
    if #items == 0 then return {} end
    local groups, order = {}, {}
    for _, row in ipairs(items) do
        if type(row) == "table" then
            local cat = tostring(row.Category or "")
            local rawName = tostring(row.Name or row.ItemKey or row.ItemName or "?")
            local name = _sanitizeDisplayName(rawName, cat)
            local gkey = cat .. "\0" .. name
            if not groups[gkey] then
                groups[gkey] = { cat = cat, name = name, count = 0, price = 0 }
                order[#order + 1] = gkey
            end
            local g = groups[gkey]
            local cnt = math.max(1, math.floor(tonumber(row.Count) or 1))
            g.count += cnt
            local linePrice = math.floor(tonumber(row.Price or row.price) or 0)
            if linePrice <= 0 then
                local unit = math.floor(tonumber(row.UnitPrice or row.unitPrice) or 0)
                if unit > 0 then
                    linePrice = unit * cnt
                end
            end
            if linePrice > 0 then
                g.price += linePrice
            end
        end
    end
    local out = {}
    for _, gkey in ipairs(order) do
        out[#out + 1] = groups[gkey]
    end
    return out
end

local function _summarizeSummary(summary)
    if type(summary) ~= "table" or #summary == 0 then return "—" end
    local parts = {}
    for _, row in ipairs(summary) do
        local s = string.format("%s x%d", _sanitizeDisplayName(row.name, row.cat), row.count)
        if row.price and row.price > 0 then
            s = s .. " " .. _formatPrice(row.price)
        end
        parts[#parts + 1] = s
    end
    local text = table.concat(parts, ", ")
    if #text > 120 then text = text:sub(1, 117) .. "..." end
    return text
end

local function _summarizeItems(items)
    if type(items) ~= "table" or #items == 0 then return "—" end
    return _summarizeSummary(_getEntrySummary({ items = items }))
end

local function _entrySearchText(e)
    local summary = _getEntrySummary(e)
    local chunks = {
        tostring(e.recipient_username or ""),
        tostring(e.recipient_display or ""),
        tostring(e.recipient_user_id or ""),
        tostring(e.profile or ""),
        tostring(e.note or ""),
        tostring(e.message or ""),
        tostring(e.day or ""),
        _summarizeSummary(summary),
    }
    for _, row in ipairs(summary) do
        chunks[#chunks + 1] = row.cat
        chunks[#chunks + 1] = row.name
    end
    return table.concat(chunks, " "):lower()
end

local function _matchesSearch(e)
    local q = tostring(searchQuery or ""):lower():gsub("^%s+", ""):gsub("%s+$", "")
    if q == "" then return true end
    local ok, hit = pcall(function()
        return _entrySearchText(e):find(q, 1, true) ~= nil
    end)
    return ok and hit == true
end

local function _colorHex(c)
    return string.format("#%02X%02X%02X",
        math.floor((c.R or 0) * 255 + 0.5),
        math.floor((c.G or 0) * 255 + 0.5),
        math.floor((c.B or 0) * 255 + 0.5))
end

local function _richEscape(s)
    s = tostring(s or "")
    s = s:gsub("&", "&amp;"):gsub("<", "&lt;"):gsub(">", "&gt;")
    return s
end

local function _catIcon(cat)
    return CAT_ICONS[tostring(cat or "")] or "📦"
end

local function _makeLabel(parent, props)
    local lbl = Instance.new("TextLabel")
    lbl.BackgroundTransparency = 1
    lbl.Font = props.font or Enum.Font.Gotham
    lbl.TextSize = props.size or 12
    lbl.TextColor3 = props.color or COLOR_WHITE
    lbl.TextXAlignment = props.x or Enum.TextXAlignment.Left
    lbl.TextYAlignment = props.y or Enum.TextYAlignment.Top
    lbl.TextWrapped = props.wrap == true
    lbl.Text = props.text or ""
    lbl.Size = props.Size or UDim2.new(1, 0, 0, 16)
    lbl.Position = props.Position or UDim2.new()
    if props.rich == true then
        pcall(function() lbl.RichText = true end)
    end
    if props.truncate then
        lbl.TextTruncate = props.truncate
    end
    lbl.Parent = parent
    return lbl
end

local function _catSectionSubtitle(rows, harvestTotal, catKey)
    local names, total = {}, 0
    for _, item in ipairs(rows) do
        total += math.floor(tonumber(item.count) or 1)
        local n = _sanitizeDisplayName(item.name, catKey)
        if n and #names < 3 then
            names[#names + 1] = string.format("%s x%d", n, item.count)
        end
    end
    if #names > 0 then
        local s = table.concat(names, ", ")
        if #names < #rows then s = s .. "..." end
        if harvestTotal and harvestTotal > 0 then
            s = s .. "  ·  " .. _formatPrice(harvestTotal)
        end
        return s
    end
    if harvestTotal and harvestTotal > 0 then
        return string.format("%d item  ·  %s", total, _formatPrice(harvestTotal))
    end
    return string.format("%d item", total)
end

local function _compactEntryPreview(summary, harvestTotal)
    if type(summary) ~= "table" or #summary == 0 then return "—" end
    local byCat, order = {}, {}
    for _, row in ipairs(summary) do
        local cat = row.cat
        if not byCat[cat] then
            byCat[cat] = { count = 0, price = 0, names = {} }
            order[#order + 1] = cat
        end
        local g = byCat[cat]
        g.count += row.count
        g.price += row.price or 0
        local n = _sanitizeDisplayName(row.name, cat)
        if n then
            g.names[n] = (g.names[n] or 0) + row.count
        end
    end
    table.sort(order, function(a, b)
        local ka, kb = _catSortKey(a), _catSortKey(b)
        if ka ~= kb then return ka < kb end
        return tostring(a) < tostring(b)
    end)

    local parts = {}
    for _, cat in ipairs(order) do
        local g = byCat[cat]
        local nameCount = 0
        for _ in pairs(g.names) do nameCount += 1 end
        if nameCount == 1 then
            for n, c in pairs(g.names) do
                parts[#parts + 1] = string.format("%s x%d", n, c)
            end
        elseif cat == "HarvestedFruits" then
            local extra = g.price > 0 and (" · " .. _formatPrice(g.price)) or ""
            parts[#parts + 1] = string.format("%d fruit%s%s", g.count, g.count > 1 and "s" or "", extra)
        else
            parts[#parts + 1] = string.format("%s x%d", _fallbackTypeName(cat), g.count)
        end
    end
    if harvestTotal and harvestTotal > 0 and not byCat.HarvestedFruits then
        parts[#parts + 1] = _formatPrice(harvestTotal)
    end
    return table.concat(parts, " · ")
end

local function _chipWidth(text)
    text = tostring(text or "")
    return math.max(34, #text * 7 + 14)
end

local function _makeChip(parent, text, bg, fg, w)
    text = tostring(text or "")
    local h = 16
    local chip = Instance.new("Frame")
    chip.BackgroundColor3 = bg
    chip.BorderSizePixel = 0
    chip.Size = UDim2.new(0, w or _chipWidth(text), 0, h)
    chip.Parent = parent
    _round(chip, 100)
    _makeLabel(chip, {
        text = text,
        size = 8,
        color = fg,
        font = Enum.Font.GothamBold,
        x = Enum.TextXAlignment.Center,
        y = Enum.TextYAlignment.Center,
        Size = UDim2.new(1, 0, 1, 0),
    })
    return chip
end

local function _profileChipStyle(profile)
    profile = tostring(profile or "once"):upper()
    if profile == "LOOP" then
        return Color3.fromRGB(42, 36, 0), COLOR_YELLOW
    end
    if profile == "NORMAL" then
        return Color3.fromRGB(0, 36, 48), Color3.fromRGB(120, 210, 255)
    end
    return Color3.fromRGB(28, 28, 28), COLOR_GRAY
end

local function _buildItemRow(parent, name, count, linePrice, theme, catKey)
    theme = theme or _catTheme()
    catKey = tostring(catKey or "")
    local row = Instance.new("Frame")
    row.BackgroundTransparency = 1
    row.BorderSizePixel = 0
    row.Size = UDim2.new(1, 0, 0, 16)
    row.Parent = parent

    _makeLabel(row, {
        text = _catIcon(catKey) .. " " .. name,
        size = 10,
        color = COLOR_WHITE,
        font = Enum.Font.GothamMedium,
        y = Enum.TextYAlignment.Center,
        x = Enum.TextXAlignment.Left,
        Size = UDim2.new(0.56, 0, 1, 0),
    })
    _makeLabel(row, {
        text = "×" .. tostring(count),
        size = 9,
        color = COLOR_GRAY,
        font = Enum.Font.GothamBold,
        y = Enum.TextYAlignment.Center,
        x = Enum.TextXAlignment.Center,
        Size = UDim2.new(0.14, 0, 1, 0),
        Position = UDim2.new(0.56, 0, 0, 0),
    })
    local priceText = (linePrice and linePrice > 0) and _formatPrice(linePrice) or ""
    if priceText ~= "" then
        _makeLabel(row, {
            text = string.format(
                '<u><font color="%s"><b>%s</b></font></u>',
                _colorHex(theme.price or COLOR_YELLOW),
                priceText
            ),
            size = 9,
            color = theme.price or COLOR_YELLOW,
            font = Enum.Font.GothamBold,
            rich = true,
            y = Enum.TextYAlignment.Center,
            x = Enum.TextXAlignment.Right,
            Size = UDim2.new(0.3, 0, 1, 0),
            Position = UDim2.new(0.7, 0, 0, 0),
        })
    end
end

local function _buildCategoryBlock(parent, catKey, rows, harvestTotal)
    local theme = _catTheme(catKey)
    local icon = _catIcon(catKey)
    local label = _catLabel(catKey)

    _makeLabel(parent, {
        text = string.format(
            '%s <b><u><font color="%s">%s</font></u></b>',
            icon,
            _colorHex(COLOR_YELLOW),
            label
        ),
        font = Enum.Font.GothamMedium,
        size = 10,
        color = COLOR_YELLOW,
        rich = true,
        Size = UDim2.new(1, 0, 0, 14),
    })

    for _, item in ipairs(rows) do
        local price = math.floor(tonumber(item.price) or 0)
        local dn = _sanitizeDisplayName(item.name, catKey)
        _buildItemRow(parent, dn, math.floor(tonumber(item.count) or 1), price, theme, catKey)
    end

    if harvestTotal and harvestTotal > 0 then
        local foot = Instance.new("Frame")
        foot.BackgroundTransparency = 1
        foot.BorderSizePixel = 0
        foot.Size = UDim2.new(1, 0, 0, 16)
        foot.Parent = parent
        _makeLabel(foot, {
            text = "💰 Total harvest",
            size = 9,
            color = COLOR_DIM,
            font = Enum.Font.GothamMedium,
            y = Enum.TextYAlignment.Center,
            x = Enum.TextXAlignment.Left,
            Size = UDim2.new(0.6, 0, 1, 0),
        })
        _makeLabel(foot, {
            text = string.format(
                '<u><font color="%s"><b>%s</b></font></u>',
                _colorHex(COLOR_YELLOW),
                _formatPrice(harvestTotal)
            ),
            size = 10,
            color = COLOR_YELLOW,
            font = Enum.Font.GothamBold,
            rich = true,
            y = Enum.TextYAlignment.Center,
            x = Enum.TextXAlignment.Right,
            Size = UDim2.new(0.4, 0, 1, 0),
            Position = UDim2.new(0.6, 0, 0, 0),
        })
    end
end

local function _buildCard(parent, e, defaultExpanded)
    local ok = e.success == true
    local user = tostring(e.recipient_username or ""):gsub("^%s+", ""):gsub("%s+$", ""):gsub("^@", "")
    local disp = tostring(e.recipient_display or ""):gsub("^%s+", ""):gsub("%s+$", "")
    local who = disp
    if who == "" then who = user end
    if who == "" then
        local uid = math.floor(tonumber(e.recipient_user_id) or 0)
        who = uid > 0 and ("UserId " .. tostring(uid)) or "(no target)"
    elseif user ~= "" and user:lower() ~= who:lower() then
        who = who .. " @" .. user
    end

    local ts = math.floor(tonumber(e.ts) or os.time())
    local itemN = math.floor(tonumber(e.item_count) or 0)
    local sendN = math.floor(tonumber(e.send_batch) or 0)
    local profile = tostring(e.profile or "once"):upper()
    local summary = _getEntrySummary(e)
    local harvestTotal = _resolveHarvestTotal(e.harvest_total_price, summary)
    local preview = _compactEntryPreview(summary, harvestTotal)
    if #preview > 80 then preview = preview:sub(1, 77) .. "..." end

    local cardOpen = defaultExpanded == true
    local statusColor = ok and COLOR_OK or COLOR_FAIL
    local yHex = _colorHex(COLOR_YELLOW)
    local gHex = _colorHex(COLOR_GRAY)

    local card, cardInner = _insetBorder(parent, {
        name = "Entry_" .. tostring(e.id or "x"),
        radius = RADIUS_CARD,
        border = COLOR_YELLOW,
        fill = COLOR_CARD,
        autoY = true,
        inset = 1,
        clip = true,
    })

    local cardLayout = Instance.new("UIListLayout")
    cardLayout.SortOrder = Enum.SortOrder.LayoutOrder
    cardLayout.Padding = UDim.new(0, 0)
    cardLayout.Parent = cardInner

    local head = Instance.new("TextButton")
    head.Name = "CardHead"
    head.AutoButtonColor = false
    head.BackgroundColor3 = COLOR_CARD_HEAD
    head.BorderSizePixel = 0
    head.ClipsDescendants = true
    head.Size = UDim2.new(1, 0, 0, 0)
    head.AutomaticSize = Enum.AutomaticSize.Y
    head.Text = ""
    head.Parent = cardInner
    _round(head, math.max(RADIUS_CARD - 1, 4))

    local function syncCardShell()
        local h = cardInner.AbsoluteSize.Y
        card.Size = UDim2.new(1, 0, 0, math.max(h + 2, 2))
    end

    local headPad = Instance.new("UIPadding")
    headPad.PaddingLeft = UDim.new(0, 6)
    headPad.PaddingRight = UDim.new(0, 6)
    headPad.PaddingTop = UDim.new(0, 5)
    headPad.PaddingBottom = UDim.new(0, 5)
    headPad.Parent = head

    local headLayout = Instance.new("UIListLayout")
    headLayout.SortOrder = Enum.SortOrder.LayoutOrder
    headLayout.Padding = UDim.new(0, 2)
    headLayout.Parent = head

    local topRow = Instance.new("Frame")
    topRow.BackgroundTransparency = 1
    topRow.Size = UDim2.new(1, 0, 0, 18)
    topRow.Parent = head

    local topLayout = Instance.new("UIListLayout")
    topLayout.FillDirection = Enum.FillDirection.Horizontal
    topLayout.SortOrder = Enum.SortOrder.LayoutOrder
    topLayout.VerticalAlignment = Enum.VerticalAlignment.Center
    topLayout.Padding = UDim.new(0, 4)
    topLayout.Parent = topRow

    local statusLbl = _makeLabel(topRow, {
        text = ok and "✓" or "✗",
        font = Enum.Font.GothamBold,
        size = 12,
        color = statusColor,
        x = Enum.TextXAlignment.Center,
        y = Enum.TextYAlignment.Center,
        Size = UDim2.new(0, 14, 0, 16),
    })
    statusLbl.LayoutOrder = 1

    local nameLbl = _makeLabel(topRow, {
        text = string.format(
            '<b><font color="%s">👤 %s</font></b>',
            _colorHex(ok and COLOR_WHITE or COLOR_DIM),
            _richEscape(who)
        ),
        font = Enum.Font.GothamBold,
        size = 11,
        color = ok and COLOR_WHITE or COLOR_DIM,
        rich = true,
        Size = UDim2.new(1, -82, 0, 16),
    })
    nameLbl.LayoutOrder = 2
    nameLbl.TextTruncate = Enum.TextTruncate.AtEnd

    local chipBg, chipFg = _profileChipStyle(profile)
    local badge = _makeChip(topRow, profile, chipBg, chipFg)
    badge.LayoutOrder = 3

    local arrow = _makeLabel(topRow, {
        text = cardOpen and "▼" or "▶",
        size = 9,
        color = COLOR_YELLOW,
        font = Enum.Font.GothamBold,
        x = Enum.TextXAlignment.Center,
        y = Enum.TextYAlignment.Center,
        Size = UDim2.new(0, 12, 0, 14),
    })
    arrow.LayoutOrder = 4

    local meta = string.format(
        '<font color="%s">🕒 %s</font> · <b>📦 %d item</b> · <font color="%s"><u>#%d</u></font>',
        gHex,
        os.date("%d/%m/%Y %H:%M", ts),
        itemN,
        yHex,
        sendN > 0 and sendN or 1
    )
    _makeLabel(head, {
        text = meta,
        color = COLOR_DIM,
        size = 9,
        rich = true,
        Size = UDim2.new(1, 0, 0, 13),
    })

    local previewLbl
    if preview ~= "—" then
        previewLbl = _makeLabel(head, {
            text = string.format('<font color="%s"><i>📋 %s</i></font>', gHex, _richEscape(preview)),
            color = COLOR_GRAY,
            size = 9,
            rich = true,
            wrap = true,
            Size = UDim2.new(1, 0, 0, 0),
        })
        previewLbl.AutomaticSize = Enum.AutomaticSize.Y
        previewLbl.Visible = not cardOpen
    end

    local body = Instance.new("Frame")
    body.Name = "CardBody"
    body.BackgroundTransparency = 1
    body.BorderSizePixel = 0
    body.Size = UDim2.new(1, 0, 0, 0)
    body.AutomaticSize = Enum.AutomaticSize.Y
    body.Visible = cardOpen
    body.Parent = cardInner

    local bodyPad = Instance.new("UIPadding")
    bodyPad.PaddingTop = UDim.new(0, 2)
    bodyPad.PaddingBottom = UDim.new(0, 6)
    bodyPad.PaddingLeft = UDim.new(0, 6)
    bodyPad.PaddingRight = UDim.new(0, 6)
    bodyPad.Parent = body

    local bodyLayout = Instance.new("UIListLayout")
    bodyLayout.SortOrder = Enum.SortOrder.LayoutOrder
    bodyLayout.Padding = UDim.new(0, 2)
    bodyLayout.Parent = body

    if #summary == 0 then
        _makeLabel(body, {
            text = "—",
            color = COLOR_GRAY,
            size = 11,
            Size = UDim2.new(1, 0, 0, 14),
        })
    else
        local byCat, catOrder = {}, {}
        for _, row in ipairs(summary) do
            local cat = row.cat
            if not byCat[cat] then
                byCat[cat] = {}
                catOrder[#catOrder + 1] = cat
            end
            byCat[cat][#byCat[cat] + 1] = row
        end
        table.sort(catOrder, function(a, b)
            local ka, kb = _catSortKey(a), _catSortKey(b)
            if ka ~= kb then return ka < kb end
            return tostring(a) < tostring(b)
        end)

        for _, cat in ipairs(catOrder) do
            local sectionTotal = nil
            if cat == "HarvestedFruits" and harvestTotal > 0 then
                sectionTotal = harvestTotal
            end
            _buildCategoryBlock(body, cat, byCat[cat], sectionTotal)
        end
    end

    local msg = tostring(e.message or "")
    if msg ~= "" then
        _makeLabel(body, {
            text = string.format('<font color="%s"><i>💬 %s</i></font>', gHex, _richEscape(msg)),
            color = COLOR_DIM,
            size = 9,
            rich = true,
            wrap = true,
            Size = UDim2.new(1, 0, 0, 0),
        }).AutomaticSize = Enum.AutomaticSize.Y
    end

    if not cardOpen then
        body.AutomaticSize = Enum.AutomaticSize.None
        body.Size = UDim2.new(1, 0, 0, 0)
    end

    head.MouseButton1Click:Connect(function()
        cardOpen = not cardOpen
        if cardOpen then
            body.AutomaticSize = Enum.AutomaticSize.Y
            body.Size = UDim2.new(1, 0, 0, 0)
            body.Visible = true
        else
            body.Visible = false
            body.AutomaticSize = Enum.AutomaticSize.None
            body.Size = UDim2.new(1, 0, 0, 0)
        end
        arrow.Text = cardOpen and "▼" or "▶"
        if previewLbl then previewLbl.Visible = not cardOpen end
        syncCardShell()
        task.defer(syncCardShell)
    end)
end

local function _entryCount()
    local n = #entries
    if n > 0 then return n end
    local c = 0
    for k, e in pairs(entries) do
        if type(k) == "number" and type(e) == "table" then
            c = c + 1
        end
    end
    return c
end

local function _ensureListScrollRef()
    if listScroll and listScroll.Parent then return listScroll end
    local root = panelRoot
    if not root or not root.Parent then
        if type(_findPanelInstance) == "function" then
            root = select(1, _findPanelInstance())
        end
    end
    if not root then return nil end
    local content = root:FindFirstChild("Content")
    listScroll = _findScrollFrame(content)
    return listScroll
end

local function _buildFilteredIndices()
    local order = _entryIndicesNewestFirst()
    local out = {}
    for _, i in ipairs(order) do
        local e = entries[i]
        if type(e) == "table" and _matchesSearch(e) then
            out[#out + 1] = i
        end
    end
    return out
end

local function _updateCountLabel()
    if not countLabel then return end
    local total = _entryCount()
    local q = tostring(searchQuery or ""):gsub("^%s+", ""):gsub("%s+$", "")
    countLabel.RichText = true
    if q ~= "" then
        countLabel.Text = string.format(
            '<font color="%s">📋</font> <b><font color="%s">%d</font></b><font color="%s"> / %d matches</font> <font color="%s">(%d total)</font>',
            _colorHex(COLOR_DIM),
            _colorHex(COLOR_YELLOW),
            renderedCount,
            _colorHex(COLOR_DIM),
            filteredMatchCount,
            _colorHex(COLOR_DIM),
            total
        )
    else
        countLabel.Text = string.format(
            '<font color="%s">📋</font> <b><font color="%s">%d</font></b><font color="%s"> / %d entries</font>',
            _colorHex(COLOR_DIM),
            _colorHex(COLOR_YELLOW),
            renderedCount,
            _colorHex(COLOR_DIM),
            filteredMatchCount
        )
    end
end

local function _appendHistoryCards(maxCount)
    if not listFrame or not listFrame.Parent then return 0 end
    maxCount = math.max(1, math.floor(tonumber(maxCount) or RENDER_PAGE_SIZE))
    local remain = filteredMatchCount - renderedCount
    if remain <= 0 then return 0 end

    local added = 0
    local batch = math.min(maxCount, remain)
    for j = 1, batch do
        local filterIdx = renderedCount + j
        local entryIdx = filteredIndices[filterIdx]
        local e = entries[entryIdx]
        if type(e) == "table" then
            local expand = (renderedCount == 0 and j == 1)
            local ok = pcall(_buildCard, listFrame, e, expand)
            if ok then
                added += 1
            end
        end
    end
    renderedCount += added
    _updateCountLabel()
    return added
end

local function _ensureHistoryFillViewport()
    if not listScroll or not listScroll.Parent then return end
    if renderedCount >= filteredMatchCount then return end
    local canvas = listScroll.AbsoluteCanvasSize.Y
    local view = listScroll.AbsoluteWindowSize.Y
    if view <= 0 then return end
    if canvas <= view + SCROLL_LOAD_THRESHOLD then
        if _appendHistoryCards(RENDER_PAGE_SIZE) > 0 then
            task.defer(_ensureHistoryFillViewport)
        end
    end
end

local function _tryLoadMoreHistoryCards()
    if scrollLoading then return end
    if renderedCount >= filteredMatchCount then return end
    if not listScroll or not listScroll.Parent then return end

    local pos = listScroll.CanvasPosition.Y
    local view = listScroll.AbsoluteWindowSize.Y
    local canvas = listScroll.AbsoluteCanvasSize.Y
    if view <= 0 or canvas <= 0 then return end
    if pos + view < canvas - SCROLL_LOAD_THRESHOLD then return end

    scrollLoading = true
    task.defer(function()
        _appendHistoryCards(RENDER_PAGE_SIZE)
        scrollLoading = false
        _ensureHistoryFillViewport()
    end)
end

local function _bindScrollLoadMore()
    if scrollConn then
        scrollConn:Disconnect()
        scrollConn = nil
    end
    if not listScroll or not listScroll.Parent then return end
    scrollConn = listScroll:GetPropertyChangedSignal("CanvasPosition"):Connect(function()
        _tryLoadMoreHistoryCards()
    end)
end

local function _refreshList()
    if not listFrame or not listFrame.Parent then
        if type(_rebindUiRefs) == "function" then
            pcall(_rebindUiRefs)
        end
    end
    if not listFrame or not listFrame.Parent then
        if type(_buildUi) == "function" then
            pcall(_buildUi)
        end
        if type(_rebindUiRefs) == "function" then
            pcall(_rebindUiRefs)
        end
    end
    if not listFrame or not listFrame.Parent then return end

    _ensureListScrollRef()
    _bindScrollLoadMore()
    filteredIndices = _buildFilteredIndices()
    filteredMatchCount = #filteredIndices
    renderedCount = 0
    scrollLoading = false
    _clearListCards()

    if listScroll then
        listScroll.CanvasPosition = Vector2.new(0, 0)
    end

    if filteredMatchCount == 0 then
        _updateCountLabel()
        _makeLabel(listFrame, {
            text = (_entryCount() == 0)
                and string.format('<font color="%s"><i>📭 Belum ada gift mail tercatat.</i></font>', _colorHex(COLOR_GRAY))
                or string.format('<font color="%s"><i>🔍 Tidak ada hasil search.</i></font>', _colorHex(COLOR_GRAY)),
            color = COLOR_GRAY,
            rich = true,
            x = Enum.TextXAlignment.Center,
            Size = UDim2.new(1, 0, 0, 40),
        })
        return
    end

    _appendHistoryCards(RENDER_PAGE_SIZE)
    task.defer(_ensureHistoryFillViewport)
end

local PANEL_W = 250
local PANEL_H = 420
local PANEL_PAD = 12
local CONTENT_PAD_L = 4
local SCROLL_W_OFF = 6
local CONTENT_W_OFF = CONTENT_PAD_L + SCROLL_W_OFF
local LIST_PAD_L = 0
local LIST_PAD_R = 2
local LIST_TOP_PAD = 0
local SEARCH_TOP = 40
local SEARCH_H = 26
local SEARCH_LIST_GAP = 2
local LIST_VIEWPORT_TOP = SEARCH_TOP + SEARCH_H + SEARCH_LIST_GAP
local LIST_VIEWPORT_BOTTOM = 10

local function _savePanelPos(frame)
    if not frame then return end
    local ap = frame.AnchorPoint
    local pos = frame.Position
    local saved = {
        ax = ap.X, ay = ap.Y,
        xs = pos.X.Scale, xo = pos.X.Offset,
        ys = pos.Y.Scale, yo = pos.Y.Offset,
    }
    G.__GAG2_GIFT_HISTORY_PANEL_POS = saved
    _G.__GAG2_GIFT_HISTORY_PANEL_POS = saved
end

local function _loadPanelPos(frame)
    if not frame then return end
    local saved = G.__GAG2_GIFT_HISTORY_PANEL_POS or _G.__GAG2_GIFT_HISTORY_PANEL_POS
    if type(saved) ~= "table" then return end
    frame.AnchorPoint = Vector2.new(tonumber(saved.ax) or 0.5, tonumber(saved.ay) or 0.5)
    frame.Position = UDim2.new(
        tonumber(saved.xs) or 0.5, tonumber(saved.xo) or 0,
        tonumber(saved.ys) or 0.5, tonumber(saved.yo) or 0
    )
end

local function _makePanelDraggable(frame, dragHandle)
    if not frame or not dragHandle then return end
    if frame:GetAttribute("DragReady") == true then return end
    frame:SetAttribute("DragReady", true)
    dragHandle.Active = true

    local dragging = false
    local dragStart
    local startPos

    dragHandle.InputBegan:Connect(function(input)
        if input.UserInputType == Enum.UserInputType.MouseButton1
            or input.UserInputType == Enum.UserInputType.Touch then
            dragging = true
            dragStart = input.Position
            startPos = frame.Position
        end
    end)

    local function stopDrag(input)
        if input.UserInputType ~= Enum.UserInputType.MouseButton1
            and input.UserInputType ~= Enum.UserInputType.Touch then
            return
        end
        if dragging then
            _savePanelPos(frame)
        end
        dragging = false
        dragStart = nil
        startPos = nil
    end

    dragHandle.InputEnded:Connect(stopDrag)
    UserInputService.InputEnded:Connect(stopDrag)

    UserInputService.InputChanged:Connect(function(input)
        if not dragging or not dragStart or not startPos then return end
        if input.UserInputType ~= Enum.UserInputType.MouseMovement
            and input.UserInputType ~= Enum.UserInputType.Touch then
            return
        end
        local delta = input.Position - dragStart
        frame.Position = UDim2.new(
            startPos.X.Scale, startPos.X.Offset + delta.X,
            startPos.Y.Scale, startPos.Y.Offset + delta.Y
        )
    end)
end

local function _ensurePanelDrag(root)
    if not root or root:GetAttribute("DragReady") == true then return end
    local content = root:FindFirstChild("Content")
    local header = content and content:FindFirstChild("Header")
    if header then
        _makePanelDraggable(root, header)
    end
end

local function _playerGui()
    if not LP then return nil end
    return LP:FindFirstChild("PlayerGui") or LP:WaitForChild("PlayerGui", 10)
end

local function _destroyExistingPanels()
    local pg = _playerGui()
    if not pg then return end
    local sg = pg:FindFirstChild("GAG2_GiftMailHistory")
    if sg then
        pcall(function() sg:Destroy() end)
    end
    panelRoot = nil
    gui = nil
    uiBuilt = false
    listFrame = nil
    countLabel = nil
    searchBox = nil
    G.__GAG2_GIFT_HISTORY_PANEL = nil
    G.__GAG2_GIFT_HISTORY_GUI = nil
    _G.__GAG2_GIFT_HISTORY_PANEL = nil
    _G.__GAG2_GIFT_HISTORY_GUI = nil
end

local function _bindGlobals()
    G.__GAG2_GIFT_HISTORY_GUI = gui
    G.__GAG2_GIFT_HISTORY_PANEL = panelRoot
    _G.__GAG2_GIFT_HISTORY_GUI = gui
    _G.__GAG2_GIFT_HISTORY_PANEL = panelRoot
end

_findPanelInstance = function()
    if panelRoot and panelRoot.Parent then
        return panelRoot, gui
    end
    local cached = G.__GAG2_GIFT_HISTORY_PANEL or rawget(_G, "__GAG2_GIFT_HISTORY_PANEL")
    local cachedGui = G.__GAG2_GIFT_HISTORY_GUI or rawget(_G, "__GAG2_GIFT_HISTORY_GUI")
    if typeof(cached) == "Instance" and cached.Parent then
        panelRoot = cached
        if typeof(cachedGui) == "Instance" then
            gui = cachedGui
        end
        if type(_rebindUiRefs) == "function" then
            _rebindUiRefs()
        end
        return panelRoot, gui
    end
    local pg = _playerGui()
    if not pg then return nil, nil end
    local sg = pg:FindFirstChild("GAG2_GiftMailHistory")
    if sg then
        gui = sg
        local panel = sg:FindFirstChild("GiftMailHistoryPanel", true)
        if panel then
            panelRoot = panel
            _bindGlobals()
            if type(_rebindUiRefs) == "function" then
                _rebindUiRefs()
            end
            return panelRoot, gui
        end
    end
    return nil, nil
end

_rebindUiRefs = function()
    local root = panelRoot
    if (not root or not root.Parent) then
        if type(_findPanelInstance) == "function" then
            _findPanelInstance()
        end
        root = panelRoot
    end
    if not root then return false end

    local content = root:FindFirstChild("Content")
    local scroll = _findScrollFrame(content) or root:FindFirstChild("Scroll")
    listScroll = scroll
    listFrame = scroll and scroll:FindFirstChild("List") or nil

    local header = (content and content:FindFirstChild("Header")) or root:FindFirstChild("Header")
    if header then
        countLabel = header:FindFirstChild("CountLabel")
    end

    local searchWrap = (content and content:FindFirstChild("SearchWrap")) or root:FindFirstChild("SearchWrap")
    if searchWrap then
        local searchBg = searchWrap:FindFirstChild("SearchBg")
        local searchInner = searchBg and searchBg:FindFirstChild("SearchInner") or nil
        searchBox = searchInner and searchInner:FindFirstChild("Search") or nil
    end

    _bindScrollLoadMore()
    return listFrame ~= nil
end

_setPanelVisible = function(on)
    panelVisible = on == true
    local panel, sg = nil, nil
    if type(_findPanelInstance) == "function" then
        panel, sg = _findPanelInstance()
    end
    if panel then
        panel.Visible = panelVisible
    end
    if sg then
        sg.Enabled = panelVisible
    end
    if panelVisible then
        if _entryCount() == 0 then
            _loadFile()
        end
        _refreshList()
    end
end

