function M.SetPanelVisible(onOrSelf, maybeOn)
    local on = onOrSelf
    if type(onOrSelf) == "table" then
        on = maybeOn
    end
    panelVisible = on == true
    local okFind = false
    if type(_findPanelInstance) == "function" then
        okFind = _findPanelInstance() ~= nil
    end
    if not okFind and type(_buildUi) == "function" then
        pcall(_buildUi)
    end
    if type(_setPanelVisible) == "function" then
        pcall(_setPanelVisible, panelVisible)
    end
    if panelVisible and type(_findPanelInstance) == "function" and not _findPanelInstance() then
        task.spawn(function()
            for _ = 1, 60 do
                task.wait(0.1)
                if type(_findPanelInstance) == "function" and _findPanelInstance() then break end
                if type(_buildUi) == "function" then
                    pcall(_buildUi)
                end
            end
            if type(_setPanelVisible) == "function" then
                pcall(_setPanelVisible, panelVisible)
            end
        end)
    end
end

