local function _normalizeSet(src)
    if type(src) ~= "table" then return {} end
    local out = {}
    for i = 1, #src do
        local v = src[i]
        if v ~= nil and tostring(v) ~= "" then out[tostring(v)] = true end
    end
    if next(out) then return out end
    for k, v in pairs(src) do
        if v == true or v == 1 or v == "true" then out[tostring(k)] = true end
    end
    return out
end

local function _mapToArray(map)
    local arr = {}
    if type(map) ~= "table" then return arr end
    for k, v in pairs(map) do
        if v == true then arr[#arr + 1] = tostring(k) end
    end
    table.sort(arr)
    return arr
end

local function _clampBatch(n)
    n = math.floor(tonumber(n) or MAX_BATCH)
    if n < 1 then n = 1 end
    if n > MAX_BATCH then n = MAX_BATCH end
    return n
end

local function _formatCount(n)
    n = tonumber(n) or 0
    if n >= 1000000 then
        return string.format("%.1fM", n / 1000000)
    end
    if n >= 1000 then
        return string.format("%.1fk", n / 1000)
    end
    return tostring(math.floor(n))
end

local function _parseScaledPriceNumber(txt)
    txt = tostring(txt or ""):lower():gsub("%s+", ""):gsub(",", "")
    if txt == "" then return nil end
    local sign = 1
    if txt:sub(1, 1) == "-" then
        sign = -1
        txt = txt:sub(2)
    end
    local suffixes = {
        { "juta", 1000000 }, { "jt", 1000000 },
        { "ribu", 1000 }, { "rb", 1000 },
        { "b", 1000000000 }, { "m", 1000000 }, { "k", 1000 },
    }
    for _, pair in ipairs(suffixes) do
        local suf, mult = pair[1], pair[2]
        if #txt > #suf and txt:sub(-#suf) == suf then
            local n = tonumber(txt:sub(1, -#suf - 1))
            if n then return math.floor(n * mult * sign) end
        end
    end
    local n = tonumber(txt)
    if n then return math.floor(n * sign) end
    return nil
end

function M.ParseSendTotalPrice(a, b)
    local raw = b
    if type(a) == "string" or type(a) == "number" then raw = a end
    if type(raw) == "number" then
        return math.max(0, math.floor(raw))
    end
    local parsed = _parseScaledPriceNumber(raw)
    if parsed == nil then return 0 end
    if parsed < 0 then parsed = 0 end
    return parsed
end

function M.FormatSendTotalPrice(a, b)
    local n = b
    if type(a) == "number" then n = a end
    n = math.floor(tonumber(n) or 0)
    if n <= 0 then return "0" end
    if n >= 1000000000 then return string.format("%.2fB", n / 1000000000) end
    if n >= 1000000 then return string.format("%.2fM", n / 1000000) end
    if n >= 1000 then return string.format("%.1fK", n / 1000) end
    return tostring(n)
end

local function _normalizeSendTotalInput(n)
    if type(n) == "string" then
        return M.ParseSendTotalPrice(n)
    end
    n = math.floor(tonumber(n) or 0)
    if n < 0 then n = 0 end
    return n
end

local function _formatSellPrice(n)
    return M.FormatSendTotalPrice(n)
end

local function _clampSendTotalGoal(n)
    n = _normalizeSendTotalInput(n)
    if n < 1 then n = 1 end
    return n
end

local function _normalizeCategoryMode(v)
    v = tostring(v or "single"):lower()
    if v == "multi" then return "multi" end
    return "single"
end

local function _normalizeSendListMode(v)
    v = tostring(v or "loop"):lower():gsub("%s+", "")
    if v == "sendtotal" or v == "send_total" or v == "total" then return "send_total" end
    return "loop"
end

local function _normalizeHarvestPriceCalcMode(v)
    return (tostring(v or "base"):lower() == "stock") and "stock" or "base"
end

local function _harvestPriceThresholdPct()
    local pct = math.floor(tonumber(cfg.harvest_price_threshold_pct) or 10)
    if pct < 0 then pct = 0 end
    if pct > 100 then pct = 100 end
    return pct
end

local function _harvestPriceCalcMode()
    return _normalizeHarvestPriceCalcMode(cfg.harvest_price_calc_mode)
end

local function _priceRangeForRemain(remain)
    remain = math.max(0, math.floor(tonumber(remain) or 0))
    if remain <= 0 then return 0, 0 end
    local pct = _harvestPriceThresholdPct()
    local maxPrice = math.floor(remain * (1 + pct / 100) + 0.5)
    return remain, maxPrice
end

local function _normalizeOnceSendMode(v)
    return (tostring(v or "total"):lower() == "price") and "price" or "total"
end

local function _normalizeAfterSendMode(v)
    v = tostring(v or "keep"):lower()
    if v == "reset" then return "reset" end
    return "keep"
end

local function _clampDelay(n)
    n = tonumber(n) or MAILBOX_SEND_COOLDOWN_SEC
    if n < MAILBOX_SEND_COOLDOWN_SEC then n = MAILBOX_SEND_COOLDOWN_SEC end
    if n > 120 then n = 120 end
    return n
end

local function _sendInterval()
    return math.max(_clampDelay(cfg.delay_sec), MAILBOX_SEND_COOLDOWN_SEC)
end

local function _parseCooldownSeconds(text)
    text = tostring(text or ""):lower()
    local n = text:match("wait%s+(%d+)%s*s")
    if n then return tonumber(n) end
    n = text:match("wait%s+(%d+)")
    if n then return tonumber(n) end
    if text:find("wait", 1, true) then
        n = text:match("(%d+)%s*s")
        if n then return tonumber(n) end
    end
    return nil
end

local function _noteServerCooldownFromMessage(msg)
    local sec = _parseCooldownSeconds(msg)
    if not sec or sec <= 0 then return end
    sec = math.max(sec, MAILBOX_SEND_COOLDOWN_SEC)
    local untilAt = os.clock() + sec + 0.35
    if untilAt > serverSendBlockedUntil then
        serverSendBlockedUntil = untilAt
    end
end

local function _effectiveSendCooldownRemain()
    local interval = _sendInterval()
    local sinceLast = interval - (os.clock() - lastSendAt)
    local serverRemain = math.max(0, serverSendBlockedUntil - os.clock())
    return math.max(sinceLast, serverRemain, 0)
end

local _setStatus
local _statusProfileKey

local function _waitNoItemsRetry()
    task.wait(NO_ITEMS_RETRY_SEC)
end

local function _isCooldownReason(reason, statusText)
    reason = tostring(reason or ""):lower()
    local status = tostring(statusText or stats.lastStatus or ""):lower()
    if reason == "cooldown" then return true end
    if reason:find("cooldown", 1, true) then return true end
    if status:find("cooldown", 1, true) then return true end
    if reason:find("before sending", 1, true) or status:find("before sending", 1, true) then
        return true
    end
    if reason:find("wait", 1, true) and reason:find("gift", 1, true) then return true end
    if status:find("wait", 1, true) and status:find("gift", 1, true) then return true end
    if _parseCooldownSeconds(reason) or _parseCooldownSeconds(status) then return true end
    return false
end

local function _cleanUsername(s)
    s = tostring(s or ""):gsub("^%s+", ""):gsub("%s+$", "")
    s = s:gsub("^@", "")
    return s
end

local function _dbg()
    return debugOn or G.AUTO_GIFT_DEBUG == true or _G.AUTO_GIFT_DEBUG == true
end

local function _log(...)
    if _dbg() then print("[GAG2-Gift]", ...) end
end

local function _refreshGiftStatusUi(profile)
    if profile == "once" then
        local onceFn = G.__GAG2_REFRESH_GIFT_ONCE_STATUS or rawget(_G, "__GAG2_REFRESH_GIFT_ONCE_STATUS")
        if type(onceFn) == "function" then
            pcall(onceFn)
        end
        return
    end
    if profile == "loop" then
        local loopFn = G.__GAG2_REFRESH_GIFT_LOOP_STATUS or rawget(_G, "__GAG2_REFRESH_GIFT_LOOP_STATUS")
        if type(loopFn) == "function" then
            pcall(loopFn)
        end
        return
    end
    local onceFn = G.__GAG2_REFRESH_GIFT_ONCE_STATUS or rawget(_G, "__GAG2_REFRESH_GIFT_ONCE_STATUS")
    if type(onceFn) == "function" then
        pcall(onceFn)
    end
    local loopFn = G.__GAG2_REFRESH_GIFT_LOOP_STATUS or rawget(_G, "__GAG2_REFRESH_GIFT_LOOP_STATUS")
    if type(loopFn) == "function" then
        pcall(loopFn)
    end
end

local function _statusProfileKey(profile)
    if profile == "once" or profile == "loop" then
        return profile
    end
    if sendJobRunning then
        return "once"
    end
    if autoSendRunning and cfg.auto_send == true then
        return "loop"
    end
    if _normalizeSendListMode(cfg.send_list_mode) == "send_total" then
        return "once"
    end
    return lastStatusProfile or "loop"
end

_statusProfileKey = _statusProfileKey

local function _formatPriceSendProgress(sentUnits, sentPrice, targetMin, targetMax, batchNum)
    local parts = {
        tostring(sentUnits or 0) .. " buah",
        _formatSellPrice(sentPrice or 0),
        _formatSellPrice(targetMin or 0) .. "–" .. _formatSellPrice(targetMax or 0),
    }
    local msg = "Progress: " .. table.concat(parts, " | ")
    if type(batchNum) == "number" and batchNum > 0 then
        msg = msg .. " (batch " .. tostring(batchNum) .. ")"
    end
    return msg
end

local function _setStatus(msg, err, profile)
    local text = tostring(msg or "")
    profile = _statusProfileKey(profile)
    stats.lastError = err
    if profile == "once" or profile == "loop" then
        lastStatusProfile = profile
        if profile == "once" then
            stats.lastStatusOnce = text
            G.AUTO_GIFT_ONCE_STATUS = text
            _G.AUTO_GIFT_ONCE_STATUS = text
        else
            stats.lastStatusLoop = text
            G.AUTO_GIFT_LOOP_STATUS = text
            _G.AUTO_GIFT_LOOP_STATUS = text
        end
        stats.lastStatus = text
        G.AUTO_GIFT_STATUS = text
        _G.AUTO_GIFT_STATUS = text
        _refreshGiftStatusUi(profile)
    else
        stats.lastStatus = text
    end
    if _dbg() and err ~= nil then
        _log("status err:", err)
    end
end

_setStatus = _setStatus

local function _waitSendCooldownWithStatus(profile)
    profile = profile or _statusProfileKey()
    while true do
        local remain = _effectiveSendCooldownRemain()
        if remain <= 0.01 then
            break
        end
        _setStatus("Cooldown kirim berikutnya: " .. tostring(math.ceil(remain)) .. "s...", nil, profile)
        task.wait(math.min(remain, 0.4))
    end
end

local function _waitForNextSend(profile)
    _waitSendCooldownWithStatus(profile)
end

local function _waitSendCooldown(profile)
    _waitSendCooldownWithStatus(profile)
end

local function _canonicalCategory(cat)
    if cat == nil then return "" end
    local key = tostring(cat)
    if key == "" then return "" end
    return SAVE_CATEGORY_ALIASES[key] or key
end

local function _categoryLabel(key)
    key = tostring(key or "")
    if key == "" then return key end
    return key:gsub("(%l)(%u)", "%1 %2")
end

local function _findCatalogModule()
    if catalogModuleInst and catalogModuleInst.Parent then
        return catalogModuleInst
    end
    local function pick(inst)
        if inst and inst:IsA("ModuleScript") and inst.Name == "MailboxItemCatalog" then
            catalogModuleInst = inst
            return inst
        end
        return nil
    end
    local function tryKnownPaths(root)
        if not root then return nil end
        local controllers = root:FindFirstChild("Controllers")
        local mailboxCtrl = controllers and controllers:FindFirstChild("MailboxController")
        local m = mailboxCtrl and pick(mailboxCtrl:FindFirstChild("MailboxItemCatalog"))
        if m then return m end
        m = pick(root:FindFirstChild("MailboxItemCatalog", true))
        if m then return m end
        return nil
    end
    local function waitMailboxCatalog(root, waitSec)
        if not root then return nil end
        local ok, inst = pcall(function()
            local controllers = root:WaitForChild("Controllers", waitSec)
            local mailboxCtrl = controllers:WaitForChild("MailboxController", waitSec)
            return mailboxCtrl:WaitForChild("MailboxItemCatalog", waitSec)
        end)
        if ok then
            return pick(inst)
        end
        return nil
    end

    -- StarterPlayerScripts (source template — available before PlayerScripts clone)
    local sps = StarterPlayer:FindFirstChild("StarterPlayerScripts")
    if sps then
        local m = tryKnownPaths(sps)
        if m then return m end
    end

    local ps = LP:FindFirstChild("PlayerScripts")
    if not ps then
        local ok, child = pcall(function()
            return LP:WaitForChild("PlayerScripts", 8)
        end)
        if ok then ps = child end
    end
    if ps then
        local m = tryKnownPaths(ps)
        if m then return m end
        m = waitMailboxCatalog(ps, 6)
        if m then return m end
    end

    if not sps then
        local ok, child = pcall(function()
            return StarterPlayer:WaitForChild("StarterPlayerScripts", 6)
        end)
        if ok then sps = child end
    end
    if sps then
        local m = waitMailboxCatalog(sps, 6)
        if m then return m end
    end
    local pg = LP:FindFirstChild("PlayerGui")
    if pg then
        local m = pick(pg:FindFirstChild("MailboxItemCatalog", true))
        if m then return m end
    end
    local cm = ReplicatedStorage:FindFirstChild("ClientModules")
    if cm then
        local m = pick(cm:FindFirstChild("MailboxItemCatalog", true))
        if m then return m end
    end
    local shared = ReplicatedStorage:FindFirstChild("SharedModules")
    if shared then
        local m = pick(shared:FindFirstChild("MailboxItemCatalog", true))
        if m then return m end
    end
    return pick(ReplicatedStorage:FindFirstChild("MailboxItemCatalog", true))
end

local function _invokeCatalog(methodName, ...)
    if not MailboxCatalog then return false, nil end
    local fn = MailboxCatalog[methodName]
    if type(fn) ~= "function" then return false, nil end
    local a1, a2, a3, a4 = ...
    local ok, res = pcall(fn, a1, a2, a3, a4)
    if ok then return true, res end
    ok, res = pcall(fn, MailboxCatalog, a1, a2, a3, a4)
    if ok then return true, res end
    return false, nil
end

local function _normalizeCategoryList(cats)
    if type(cats) ~= "table" then return {} end
    if #cats > 0 then
        local out = {}
        for _, key in ipairs(cats) do
            if type(key) == "string" and key ~= "" then
                out[#out + 1] = key
            end
        end
        return out
    end
    local out = {}
    for key, val in pairs(cats) do
        if type(val) == "string" and val ~= "" then
            out[#out + 1] = val
        elseif type(key) == "string" and key ~= "" and (val == true or val == 1) then
            out[#out + 1] = key
        end
    end
    table.sort(out)
    return out
end

local function _catalogIsGiftable(cat)
    if not MailboxCatalog then return false end
    cat = tostring(cat or "")
    for _, key in ipairs(_normalizeCategoryList(MailboxCatalog.Categories)) do
        if key == cat then return true end
    end
    local ok, res = _invokeCatalog("IsGiftable", cat)
    return ok and res == true
end

local function _ensureMailboxCatalog(force)
    if force then
        MailboxCatalog = nil
        catalogLoadedFromGame = false
        catalogModuleInst = nil
    end
    if MailboxCatalog and catalogLoadedFromGame then
        return true
    end
    local modScript = _findCatalogModule()
    if modScript then
        local ok, mod = pcall(require, modScript)
        if ok and type(mod) == "table" and type(mod.Categories) == "table" then
            MailboxCatalog = mod
            catalogLoadedFromGame = true
            return true
        end
    end
    return false
end

local function _catalogCategories()
    if not _ensureMailboxCatalog() then return {} end
    return _normalizeCategoryList(MailboxCatalog.Categories)
end

local function _remoteCallable(remote)
    if remote == nil then return false end
    if type(remote) == "table" then
        return type(remote.Fire) == "function" or type(remote.Invoke) == "function"
    end
    if typeof(remote) == "Instance" then
        return remote:IsA("RemoteFunction") or remote:IsA("RemoteEvent")
    end
    return false
end

local function _callNetworkingRemote(remote, ...)
    if not _remoteCallable(remote) then
        return false, "no_remote"
    end
    local args = table.pack(...)

    local function invoke()
        if type(remote) == "table" then
            if type(remote.Fire) == "function" then
                if args.n > 0 then
                    return remote:Fire(table.unpack(args, 1, args.n))
                end
                return remote:Fire()
            end
            if type(remote.Invoke) == "function" then
                if args.n > 0 then
                    return remote:Invoke(table.unpack(args, 1, args.n))
                end
                return remote:Invoke()
            end
        end
        if typeof(remote) == "Instance" then
            if remote:IsA("RemoteFunction") then
                if args.n > 0 then
                    return remote:InvokeServer(table.unpack(args, 1, args.n))
                end
                return remote:InvokeServer()
            end
            if remote:IsA("RemoteEvent") then
                if args.n > 0 then
                    remote:FireServer(table.unpack(args, 1, args.n))
                else
                    remote:FireServer()
                end
                return nil
            end
        end
        error("networking remote not callable")
    end

    local results = table.pack(pcall(invoke))
    if not results[1] then
        return false, results[2]
    end
    return true, results[2], results[3], results[4], results[5]
end

local function _clearNetworkingCache()
    Networking = nil
    MailboxSendBatch = nil
    MailboxLookup = nil
    MailboxList = nil
    MailboxClaim = nil
    MailboxOpenInbox = nil
    MailboxUpdated = nil
    BackpackGetLayout = nil
    BackpackPromoteFruit = nil
end

local function _ensureNetworking()
    if Networking and _remoteCallable(MailboxSendBatch) then return true end
    local ok, net = pcall(function()
        return require(ReplicatedStorage:WaitForChild("SharedModules"):WaitForChild("Networking"))
    end)
    if ok and type(net) == "table" then
        Networking = net
        if net.Mailbox then
            MailboxSendBatch = net.Mailbox.SendBatch
            MailboxLookup = net.Mailbox.LookupPlayer
            MailboxList = net.Mailbox.List
            MailboxClaim = net.Mailbox.Claim
            MailboxOpenInbox = net.Mailbox.OpenInbox
            MailboxUpdated = net.Mailbox.Updated
        end
        if type(net.Backpack) == "table" then
            BackpackGetLayout = net.Backpack.GetLayout
            BackpackPromoteFruit = net.Backpack.PromoteFruit
        end
    end
    return _remoteCallable(MailboxSendBatch)
end

local function _ensureGiftingNetworking()
    if not _ensureNetworking() then return false end
    if type(Networking) ~= "table" or type(Networking.Gifting) ~= "table" then
        return false
    end
    GiftingPrompted = Networking.Gifting.Prompted
    GiftingResponse = Networking.Gifting.Response
    GiftingFakeFriendRequest = Networking.Gifting.FakeFriendRequest
    GiftingFakeFriendRequestResponse = Networking.Gifting.FakeFriendRequestResponse
    return GiftingPrompted ~= nil
        and GiftingPrompted.OnClientEvent ~= nil
        and _remoteCallable(GiftingResponse)
end

local function _ensureFakeFriendNetworking()
    if not _ensureGiftingNetworking() then return false end
    return GiftingFakeFriendRequest ~= nil
        and GiftingFakeFriendRequest.OnClientEvent ~= nil
        and _remoteCallable(GiftingFakeFriendRequestResponse)
end

local function _hideGiftingUi()
    local pg = LP:FindFirstChild("PlayerGui")
    if not pg then return end
    local gifting = pg:FindFirstChild("Gifting")
    if gifting then
        gifting.Enabled = false
    end
end

local function _dismissFakeFriendRequestUi(otherPlayer)
    local pg = LP:FindFirstChild("PlayerGui")
    if not pg then return end
    local frGui = pg:FindFirstChild("FriendRequest")
    if not frGui then return end
    frGui.Enabled = false
    local frame = frGui:FindFirstChild("Frame")
    if not frame then return end
    if otherPlayer then
        local clone = frame:FindFirstChild("FriendRequest_" .. tostring(otherPlayer.UserId))
        if clone then clone:Destroy() end
    end
    for _, ch in ipairs(frame:GetChildren()) do
        if ch.Name:match("^FriendRequest_") then
            ch:Destroy()
        end
    end
end

local function _declineFakeFriendRequest(otherPlayer)
    if typeof(otherPlayer) ~= "Instance" or not otherPlayer:IsA("Player") then return end
    if not otherPlayer.Parent then return end
    if not _ensureFakeFriendNetworking() then return end
    pcall(_callNetworkingRemote, GiftingFakeFriendRequestResponse, otherPlayer, false)
    _dismissFakeFriendRequestUi(otherPlayer)
end

local function _onFakeFriendRequest(otherPlayer)
    if cfg.suppress_fake_friend_request == false then return end
    _declineFakeFriendRequest(otherPlayer)
end

local function _bindFriendRequestUiGuard()
    if friendRequestUiConn then return true end
    local pg = LP:FindFirstChild("PlayerGui")
    if not pg then return false end
    local frGui = pg:FindFirstChild("FriendRequest")
    if not frGui then return false end
    local frame = frGui:FindFirstChild("Frame")
    if not frame then return false end

    friendRequestUiConn = frame.ChildAdded:Connect(function(ch)
        if cfg.suppress_fake_friend_request == false then return end
        if not ch.Name:match("^FriendRequest_") then return end
        task.defer(function()
            if ch.Parent then ch:Destroy() end
            frGui.Enabled = false
            local otherId = ch.Name:match("^FriendRequest_(%d+)$")
            if otherId then
                local other = Players:GetPlayerByUserId(tonumber(otherId) or 0)
                if other then
                    pcall(_declineFakeFriendRequest, other)
                end
            end
        end)
    end)
    return true
end

local function _bindFakeFriendSuppress()
    if fakeFriendConn then
        pcall(function() fakeFriendConn:Disconnect() end)
        fakeFriendConn = nil
    end
    if cfg.suppress_fake_friend_request == false then return false end
    if not _ensureFakeFriendNetworking() then return false end
    fakeFriendConn = GiftingFakeFriendRequest.OnClientEvent:Connect(_onFakeFriendRequest)
    _bindFriendRequestUiGuard()
    return true
end

local function _onNormalGiftPrompted(senderPlayer, _itemName)
    if cfg.auto_accept_gift ~= true then return end
    if typeof(senderPlayer) ~= "Instance" or not senderPlayer:IsA("Player") then return end
    if not senderPlayer.Parent then return end
    if not _ensureGiftingNetworking() then return end

    task.defer(function()
        if cfg.auto_accept_gift ~= true then return end
        if not senderPlayer.Parent then return end
        local ok = _callNetworkingRemote(GiftingResponse, senderPlayer, true)
        if ok then
            stats.acceptedNormalGifts = (stats.acceptedNormalGifts or 0) + 1
            _hideGiftingUi()
            _setStatus("Accepted gift from " .. tostring(senderPlayer.Name))
            _log("accepted normal gift from", senderPlayer.Name, _itemName)
        else
            _log("accept normal gift failed from", senderPlayer.Name)
        end
    end)
end

local function _bindNormalGiftAccept()
    if acceptGiftConn then
        pcall(function() acceptGiftConn:Disconnect() end)
        acceptGiftConn = nil
    end
    if not _ensureGiftingNetworking() then return false end
    acceptGiftConn = GiftingPrompted.OnClientEvent:Connect(_onNormalGiftPrompted)
    return true
end

local function _applyInboxData(data)
    if type(data) ~= "table" then
        table.clear(inboxGifts)
        return
    end

    local box = data.Mailbox
    if type(box) ~= "table" then
        if data.PendingInvites == nil and data.Badge == nil then
            box = data
        else
            return
        end
    end

    table.clear(inboxGifts)
    for giftId, payload in pairs(box) do
        local key = tostring(giftId)
        if key ~= "" and type(payload) == "table" then
            inboxGifts[key] = payload
        end
    end
end

local function _refreshInboxFromServer()
    if not _mailboxUsable() then return false end

    for _ = 1, 4 do
        if not _ensureNetworking() or not _remoteCallable(MailboxOpenInbox) then
            _clearNetworkingCache()
            task.wait(0.25)
            continue
        end

        local ok, data = _callNetworkingRemote(MailboxOpenInbox)
        if ok and type(data) == "table" then
            _applyInboxData(data)
            return true
        end
        break
    end
    return false
end

local function _trackMailboxInbox()
    if inboxConn then return end
    if not _ensureNetworking() then return end

    if MailboxUpdated and MailboxUpdated.OnClientEvent then
        inboxConn = MailboxUpdated.OnClientEvent:Connect(function(data)
            pcall(_applyInboxData, data)
        end)
    end

    task.spawn(function()
        task.wait(2)
        pcall(_refreshInboxFromServer)
    end)
end

local function _ensurePlayerState()
    if PlayerStateClient then return true end
    local function tryRequire(modInst)
        if not modInst then return false end
        local ok, mod = pcall(require, modInst)
        if ok and type(mod) == "table" then
            PlayerStateClient = mod
            return true
        end
        return false
    end
    local cm = ReplicatedStorage:FindFirstChild("ClientModules")
    if cm and tryRequire(cm:FindFirstChild("PlayerStateClient")) then return true end
    local ok = pcall(function()
        return tryRequire(ReplicatedStorage:WaitForChild("ClientModules", 15):WaitForChild("PlayerStateClient"))
    end)
    return ok and PlayerStateClient ~= nil
end

local function _getInventory(waitSec)
    waitSec = tonumber(waitSec) or 0
    if not _ensurePlayerState() then return nil end
    if type(PlayerStateClient.GetLocalReplica) ~= "function" then return nil end
    local replica = PlayerStateClient:GetLocalReplica()
    local deadline = os.clock() + waitSec
    while not replica and os.clock() < deadline do
        task.wait(0.1)
        replica = PlayerStateClient:GetLocalReplica()
    end
    if not replica or type(replica.Data) ~= "table" then return nil end
    local inv = replica.Data.Inventory
    return type(inv) == "table" and inv or nil
end

local function _entryUniqueId(entry, itemKey)
    if type(entry) == "table" then
        local id = entry.Id or entry.UUID or entry.PetId or entry.InstanceId
            or entry.Guid or entry.UniqueId or entry.PetUUID
        if id ~= nil and tostring(id) ~= "" then
            return tostring(id)
        end
    end
    if itemKey ~= nil and tostring(itemKey) ~= "" then
        return tostring(itemKey)
    end
    return nil
end

local function _isUniqueInventoryEntry(entry, itemKey)
    if type(entry) ~= "table" then return false end
    if _entryUniqueId(entry, itemKey) ~= nil then return true end
    return entry.Type ~= nil or entry.PetName ~= nil or entry.PetType ~= nil
        or entry.Name ~= nil or entry.DisplayName ~= nil
end

local function _bagHasEntries(bag)
    if type(bag) ~= "table" then return false end
    local nested = bag.List or bag.Items
    if type(nested) == "table" and #nested > 0 then return true end
    for itemKey in pairs(bag) do
        local keyStr = tostring(itemKey)
        if keyStr:sub(1, 1) ~= "_" then
            return true
        end
    end
    return false
end

local function _eachBagEntry(bag, fn)
    if type(bag) ~= "table" or type(fn) ~= "function" then return end
    local nested = bag.List or bag.Items
    if type(nested) == "table" and (bag.List ~= nil or bag.Items ~= nil) and #nested > 0 then
        for idx, entry in ipairs(nested) do
            fn(_entryUniqueId(entry, idx) or tostring(idx), entry)
        end
        return
    end
    for itemKey, entry in pairs(bag) do
        local keyStr = tostring(itemKey)
        if keyStr:sub(1, 1) == "_" then
            continue
        end
        fn(itemKey, entry)
    end
end

local function _normalizeFruitGroupKey(name)
    return tostring(name or ""):lower():gsub("[%s_%-%.'']+", "")
end

local _isHarvestedFruitsCategory, _resolveHarvestFruitItemKey, _fruitBaseTypeName, _entrySellPrice
local _buildMultiBatchPricePlan, _prepareHarvestBatch, _dedupeInventoryItems, _getInventoryBag
local _batchSendLimit, _categorySendLimit, _isCountBasedCategory, _ensureCfgCategoryTables, _rebuildCategoryDefs
local _planPriceBatch, _pricePoolFromCandidates, _pricePlanSummary, _formatPriceBreakdown, _ensureFsvFresh
local _isHarvestEntryFavorited
do
local FRUIT_ID_FIELDS = { "Id", "id", "UUID", "Uuid", "FruitId", "fruitId" }
local FRUIT_NAME_FIELDS = { "FruitName", "Fruit", "Name", "name", "fruitName", "PlantName" }
local FRUIT_WEIGHT_FIELDS = { "Weight", "weight", "Kg", "kg" }
local FRUIT_MUTATION_FIELDS = { "Mutation", "mutation" }
local HARVESTED_FRUITS_CAT = "HarvestedFruits"

_isHarvestedFruitsCategory = function(cat)
    return _canonicalCategory(cat) == HARVESTED_FRUITS_CAT
end

local function _getFruitSellValueModule()
    local fsv = G.FruitSellValue or rawget(_G, "FruitSellValue")
    if type(fsv) == "table" then return fsv end
    return nil
end

local function _pickFruitField(entry, fields)
    if type(entry) ~= "table" then return nil end
    for _, f in ipairs(fields) do
        local v = entry[f]
        if v ~= nil and tostring(v) ~= "" then return v end
    end
    return nil
end

local function _stackEntryCount(entry)
    if type(entry) == "number" then return entry end
    if type(entry) ~= "table" then
        return tonumber(entry)
    end
    return tonumber(entry.Count or entry.Amount or entry.Quantity or entry.Stack or entry.Qty)
end

local function _isStackInventoryEntry(entry, itemKey)
    if type(entry) == "table" then
        if _isUniqueInventoryEntry(entry, itemKey) then return false end
        local n = _stackEntryCount(entry)
        return type(n) == "number" and n > 0
    end
    local n = tonumber(entry)
    return type(n) == "number" and n > 0
end

local function _bagIsStackedCounts(bag)
    if type(bag) ~= "table" then return false end
    local stackCount, uniqueCount = 0, 0
    _eachBagEntry(bag, function(itemKey, entry)
        if _isUniqueInventoryEntry(entry, itemKey) then
            uniqueCount += 1
        elseif _isStackInventoryEntry(entry, itemKey) then
            stackCount += 1
        end
    end)
    return stackCount > 0 and uniqueCount == 0
end

_dedupeInventoryItems = function(items)
    local out = {}
    local byNorm = {}
    for _, it in ipairs(type(items) == "table" and items or {}) do
        local rawKey = tostring(it.key or it.name or "")
        if rawKey == "" then
            out[#out + 1] = it
            continue
        end
        local baseName = rawKey:gsub("%s*x%s+.+$", "")
        local norm = _normalizeFruitGroupKey(baseName)
        if norm == "" then
            norm = _normalizeFruitGroupKey(rawKey)
        end
        local prev = byNorm[norm]
        if prev then
            prev.count = math.max(tonumber(prev.count) or 0, tonumber(it.count) or 0)
            prev.key = baseName ~= "" and baseName or rawKey
            prev.name = prev.key .. " x " .. _formatCount(prev.count)
            prev.right = _formatCount(prev.count)
        else
            local key = baseName ~= "" and baseName or rawKey
            local copy = {
                key = key,
                name = it.name or (key .. " x " .. _formatCount(it.count)),
                right = it.right,
                count = it.count,
            }
            if copy.name == key then
                copy.name = key .. " x " .. _formatCount(copy.count)
            end
            byNorm[norm] = copy
            out[#out + 1] = copy
        end
    end
    table.sort(out, function(a, b)
        return tostring(a.key) < tostring(b.key)
    end)
    return out
end

local function _looksLikeLayoutFruitEntry(entry)
    if type(entry) ~= "table" then return false end
    if entry.SeedTool ~= nil or entry.Pet ~= nil then return false end
    if entry.PottedPlant == true then return false end
    if tostring(entry.MainCategory or "") == "Seed" then return false end
    local id = _pickFruitField(entry, FRUIT_ID_FIELDS)
    if type(id) == "string" and id ~= "" and #id >= 8 then return true end
    local name = _pickFruitField(entry, FRUIT_NAME_FIELDS)
    if name ~= nil and tostring(name) ~= "" then return true end
    if entry.HarvestedFruit == true or entry.FruitProxy == true then return true end
    return false
end

local function _collectLayoutFruitEntries(layout, out, depth, seen)
    if depth > 12 or type(layout) ~= "table" then return end
    if seen[layout] then return end
    seen[layout] = true
    if _looksLikeLayoutFruitEntry(layout) then
        out[#out + 1] = layout
        return
    end
    for _, value in pairs(layout) do
        if type(value) == "table" then
            if _looksLikeLayoutFruitEntry(value) then
                out[#out + 1] = value
            else
                _collectLayoutFruitEntries(value, out, depth + 1, seen)
            end
        end
    end
end

local function _layoutFruitToMailEntry(raw)
    if not _looksLikeLayoutFruitEntry(raw) then return nil end
    local id = tostring(_pickFruitField(raw, FRUIT_ID_FIELDS) or "")
    if not _isLikelyFruitInstanceId(id) then return nil end
    return {
        Id = id,
        FruitName = _pickFruitField(raw, FRUIT_NAME_FIELDS),
        Mutation = _pickFruitField(raw, FRUIT_MUTATION_FIELDS),
        Weight = tonumber(_pickFruitField(raw, FRUIT_WEIGHT_FIELDS)),
        SizeMultiplier = raw.SizeMultiplier or raw.SizeMulti,
        IsFavorite = raw.IsFavorite,
        Favorite = raw.Favorite,
        Favorited = raw.Favorited,
        isFavorite = raw.isFavorite,
        d = raw.d,
    }
end

local function _instLooksLikeHarvestedFruit(inst)
    if not inst or type(inst.GetAttribute) ~= "function" then return false end
    if inst:GetAttribute("SeedTool") ~= nil then return false end
    if inst:GetAttribute("Pet") ~= nil then return false end
    if inst:GetAttribute("PottedPlant") == true then return false end
    if tostring(inst:GetAttribute("MainCategory") or "") == "Seed" then return false end
    local fruitName = inst:GetAttribute("FruitName") or inst:GetAttribute("Fruit")
    if fruitName ~= nil and tostring(fruitName) ~= "" then return true end
    if inst:GetAttribute("FruitProxy") == true then return true end
    local hf = inst:GetAttribute("HarvestedFruit")
    if hf == true then return true end
    if type(hf) == "string" and hf ~= "" then return true end
    return false
end

local function _isLikelyFruitInstanceId(id)
    id = tostring(id or "")
    if id == "" then return false end
    if id:find("%s") then return false end
    if #id < 8 then return false end
    if id:match("^[%a'%-]+$") and not id:match("[%d_]") then
        return false
    end
    return true
end

_resolveHarvestFruitItemKey = function(itemKey, entry)
    if type(entry) == "table" then
        local fromEntry = _pickFruitField(entry, FRUIT_ID_FIELDS)
        if fromEntry ~= nil and _isLikelyFruitInstanceId(fromEntry) then
            return tostring(fromEntry)
        end
    end
    local keyStr = tostring(itemKey or "")
    if _isLikelyFruitInstanceId(keyStr) then
        return keyStr
    end
    return nil
end

local function _bagHasOnlyDisplayNameKeys(bag)
    if type(bag) ~= "table" then return false end
    local sawNameKey = false
    local sawIdKey = false
    _eachBagEntry(bag, function(itemKey, entry)
        if _resolveHarvestFruitItemKey(itemKey, entry) then
            sawIdKey = true
        else
            sawNameKey = true
        end
    end)
    return sawNameKey and not sawIdKey
end

local function _findToolByFruitId(id)
    id = tostring(id or "")
    if id == "" then return nil end
    local found = nil
    local function scan(container)
        if not container or found then return end
        for _, inst in ipairs(container:GetDescendants()) do
            if inst:IsA("Tool") or _instLooksLikeHarvestedFruit(inst) then
                if tostring(inst:GetAttribute("Id") or inst:GetAttribute("UUID") or "") == id then
                    found = inst
                    return
                end
            end
        end
    end
    scan(LP:FindFirstChild("Backpack") or LP:FindFirstChildOfClass("Backpack"))
    scan(LP.Character)
    return found
end

local function _fruitDisplayName(raw)
    local name = tostring(raw or ""):gsub("^%s+", ""):gsub("%s+$", "")
    if name == "" then return nil end
    if name:match("^[%x%-]+$") and #name >= 12 then return nil end
    if _isLikelyFruitInstanceId(name) then return nil end
    return name
end

_fruitBaseTypeName = function(entry, itemKey)
    if type(entry) == "table" then
        local name = _fruitDisplayName(
            entry.FruitName or entry.Fruit or entry.PlantName or entry.Name or entry.DisplayName
        )
        if name then return name end
    end

    local id = _resolveHarvestFruitItemKey(itemKey, entry)
    if id and type(_getBackpackFruitBag) == "function" then
        local bag = _getBackpackFruitBag(false)
        local cached = type(bag) == "table" and bag[id] or nil
        if type(cached) == "table" then
            local name = _fruitDisplayName(
                cached.FruitName or cached.Fruit or cached.PlantName or cached.Name or cached.DisplayName
            )
            if name then return name end
        end
    end

    if id then
        local inst = _findToolByFruitId(id)
        if inst then
            local name = _fruitDisplayName(
                inst:GetAttribute("FruitName") or inst:GetAttribute("Fruit") or inst.Name
            )
            if name then return name end
        end
    end

    local key = tostring(itemKey or ""):gsub("%s*%[.-%]", ""):gsub("%s+$", "")
    local name = _fruitDisplayName(key)
    if name then return name end
    return "Fruit"
end

local function _resolvePriceMulti(entry, inst)
    local fsv = _getFruitSellValueModule()
    if inst and fsv and type(fsv.resolveMulti) == "function" then
        local ok, m = pcall(fsv.resolveMulti, inst)
        if ok and type(m) == "number" and m > 0 then return m end
    end
    if type(entry) == "table" then
        local sm = tonumber(entry.SizeMultiplier or entry.SizeMulti)
        if sm and sm > 0 then return sm end
        local w = tonumber(entry.Weight or entry.weight)
        if w and w > 0 then return w end
    end
    if inst then
        local w = tonumber(inst:GetAttribute("Weight"))
        if w and w > 0 then return w end
    end
    return 0
end

local _fsvRefreshedAt = 0
local _pricePlanEpoch = 0
local _pricePlanPreviewCache = nil

local function _invalidatePricePlanPreview()
    _pricePlanPreviewCache = nil
end

_ensureFsvFresh = function(force)
    local fsv = _getFruitSellValueModule()
    if not fsv or type(fsv.refresh) ~= "function" then
        return fsv
    end
    local now = os.clock()
    if force or (now - _fsvRefreshedAt) > 1 then
        pcall(fsv.refresh, true)
        _fsvRefreshedAt = now
    end
    return fsv
end

_entrySellPrice = function(category, itemKey, entry)
    if not _isHarvestedFruitsCategory(category) then return 0 end
    local fsv = _ensureFsvFresh(false)
    if not fsv then return 0 end

    local espMode = _harvestPriceCalcMode()
    local inst = nil
    local id = _resolveHarvestFruitItemKey(itemKey, entry)
    if id then inst = _findToolByFruitId(id) end

    local name = _fruitBaseTypeName(entry, itemKey)
    local multi = _resolvePriceMulti(entry, inst)
    local mut = type(entry) == "table" and (entry.Mutation or entry.mutation) or nil
    if (mut == nil or mut == "") and inst and type(inst.GetAttribute) == "function" then
        mut = inst:GetAttribute("Mutation")
    end
    local decay = type(entry) == "table" and entry.DecayAlpha or nil
    if decay == nil and inst and type(inst.GetAttribute) == "function" then
        decay = inst:GetAttribute("DecayAlpha")
    end

    local bidPrice = 0
    if inst then
        if type(fsv.resolveBidPrice) == "function" then
            local okBid, b = pcall(fsv.resolveBidPrice, inst)
            if okBid and type(b) == "number" and b > 0 then bidPrice = b end
        elseif type(inst.GetAttribute) == "function" then
            bidPrice = tonumber(inst:GetAttribute("BidPrice")) or 0
        end
    end
    if type(fsv.getBackpackEspPrice) == "function" and multi > 0 and name ~= "" then
        local ok, p = pcall(fsv.getBackpackEspPrice, name, multi, mut, decay, espMode, id or "", bidPrice)
        if ok and type(p) == "number" and p > 0 then
            return math.floor(p + 0.5)
        end
    end
    if type(fsv.getBackpackPrice) == "function" then
        local ok, p = pcall(fsv.getBackpackPrice, name, multi, mut, id, decay)
        if ok and type(p) == "number" and p > 0 then
            return math.floor(p + 0.5)
        end
    end
    if type(fsv.calculate) == "function" and multi > 0 and name ~= "" then
        local ok, p = pcall(fsv.calculate, name, multi, mut, LP, decay)
        if ok and type(p) == "number" and p > 0 then
            return math.floor(p + 0.5)
        end
    end
    return 0
end

local _giftPriceApi = nil
local function _giftPrice()
    if _giftPriceApi then
        return _giftPriceApi
    end
    local factory = G.AutoGiftPriceModule or G.AutoGiftPrice
        or rawget(_G, "AutoGiftPriceModule") or rawget(_G, "AutoGiftPrice")
    if type(factory) == "table" and type(factory.create) == "function" then
        _giftPriceApi = factory.create({
            clampBatch = _clampBatch,
            maxBatch = MAX_BATCH,
            formatSellPrice = _formatSellPrice,
            isHarvestedFruitsCategory = _isHarvestedFruitsCategory,
            entrySellPrice = _entrySellPrice,
        })
    end
    return _giftPriceApi
end

_pricePoolFromCandidates = function(candidates)
    local px = _giftPrice()
    if not px then return {} end
    return px.poolFromCandidates(candidates)
end

_formatPriceBreakdown = function(pick)
    local px = _giftPrice()
    if not px then return "" end
    return px.formatBreakdown(pick)
end

_buildMultiBatchPricePlan = function(candidates, targetMin, targetMax, maxItems)
    local px = _giftPrice()
    if not px then return nil, 0, 0, 0 end
    return px.buildMultiBatchPricePlan(candidates, targetMin, targetMax, maxItems)
end

_planPriceBatch = function(candidates, minSum, maxSum, maxItems, usedKeys)
    local px = _giftPrice()
    if not px then return nil, 0, {} end
    return px.planPriceBatch(candidates, minSum, maxSum, maxItems, usedKeys)
end

_pricePlanSummary = function(pick, total, minSum, maxSum, poolSize, batchCount)
    local px = _giftPrice()
    if not px then
        return "Price module belum load — re-execute hub"
    end
    return px.pricePlanSummary(pick, total, minSum, maxSum, poolSize, batchCount)
end

local function _promoteHarvestFruitForMail(id)
    id = tostring(id or "")
    if id == "" or not _isLikelyFruitInstanceId(id) then return false end
    if _findToolByFruitId(id) then return true end
    if not _ensureNetworking() or not _remoteCallable(BackpackPromoteFruit) then
        return false
    end
    local ok = _callNetworkingRemote(BackpackPromoteFruit, id)
    if not ok then return false end
    M.InvalidateHarvestFruitCache()
    for _ = 1, 12 do
        task.wait(0.08)
        if _findToolByFruitId(id) then return true end
    end
    return true
end

_prepareHarvestBatch = function(batch)
    if type(batch) ~= "table" or #batch == 0 then return batch end
    local out = {}
    for _, item in ipairs(batch) do
        if _isHarvestedFruitsCategory(item.Category) then
            local id = _resolveHarvestFruitItemKey(item.ItemKey, nil)
            if id then
                _promoteHarvestFruitForMail(id)
                out[#out + 1] = {
                    Category = item.Category,
                    ItemKey = id,
                    Count = item.Count or 1,
                }
            end
        else
            out[#out + 1] = item
        end
    end
    return out
end

local function _instanceFruitToMailEntry(inst)
    if not _instLooksLikeHarvestedFruit(inst) then return nil end
    local id = inst:GetAttribute("Id") or inst:GetAttribute("UUID") or inst:GetAttribute("FruitId")
    id = tostring(id or "")
    if not _isLikelyFruitInstanceId(id) then return nil end
    return {
        Id = id,
        FruitName = inst:GetAttribute("FruitName") or inst:GetAttribute("Fruit") or inst.Name,
        Mutation = inst:GetAttribute("Mutation"),
        Weight = tonumber(inst:GetAttribute("Weight")),
        SizeMultiplier = inst:GetAttribute("SizeMultiplier") or inst:GetAttribute("SizeMulti"),
        IsFavorite = inst:GetAttribute("IsFavorite"),
        Favorite = inst:GetAttribute("Favorite"),
        Favorited = inst:GetAttribute("Favorited"),
        isFavorite = inst:GetAttribute("isFavorite"),
        d = inst:GetAttribute("d"),
    }
end

local function _mergeFavFields(dst, src)
    if type(dst) ~= "table" or type(src) ~= "table" then return dst end
    for _, key in ipairs({ "IsFavorite", "Favorite", "Favorited", "isFavorite", "d" }) do
        if src[key] ~= nil then dst[key] = src[key] end
    end
    return dst
end

local function _mergeHarvestedFruitBag(dst, src)
    dst = type(dst) == "table" and dst or {}
    if type(src) ~= "table" then return dst end
    for itemKey, entry in pairs(src) do
        local keyStr = tostring(itemKey)
        if keyStr:sub(1, 1) ~= "_" and dst[itemKey] == nil then
            dst[itemKey] = entry
        end
    end
    return dst
end

_getBackpackFruitBag = function(forceRefresh)
    local now = os.clock()
    if not forceRefresh and harvestFruitBagCache and (now - harvestFruitBagCacheAt) < HARVEST_FRUIT_BAG_CACHE_SEC then
        return harvestFruitBagCache
    end

    local bag = {}
    local byId = {}

    local function addEntry(entry)
        if type(entry) ~= "table" then return end
        local id = tostring(entry.Id or _pickFruitField(entry, FRUIT_ID_FIELDS) or "")
        if not _isLikelyFruitInstanceId(id) then return end
        entry.Id = id
        if byId[id] then
            _mergeFavFields(bag[id], entry)
            return
        end
        byId[id] = true
        bag[id] = entry
    end

    if _ensureNetworking() and _remoteCallable(BackpackGetLayout) then
        local ok, layout = _callNetworkingRemote(BackpackGetLayout)
        if ok and type(layout) == "table" then
            local raw = {}
            _collectLayoutFruitEntries(layout, raw, 0, {})
            for _, layoutEntry in ipairs(raw) do
                addEntry(_layoutFruitToMailEntry(layoutEntry))
            end
        end
    end

    local function scanContainer(container)
        if not container then return end
        for _, inst in ipairs(container:GetDescendants()) do
            if inst:IsA("Tool") or _instLooksLikeHarvestedFruit(inst) then
                addEntry(_instanceFruitToMailEntry(inst))
            end
        end
    end

    scanContainer(LP:FindFirstChild("Backpack") or LP:FindFirstChildOfClass("Backpack"))
    scanContainer(LP.Character)

    harvestFruitBagCache = bag
    harvestFruitBagCacheAt = now
    return bag
end

function M.InvalidateHarvestFruitCache()
    harvestFruitBagCache = nil
    harvestFruitBagCacheAt = 0
    harvestFavCache = nil
    _pricePlanEpoch += 1
    _invalidatePricePlanPreview()
end

local function _truthyFavFlag(val)
    return val == true or val == 1 or val == "true" or val == "1"
end

local function _rawEntryFavorited(entry, depth)
    depth = math.floor(tonumber(depth) or 0)
    if depth > 5 or type(entry) ~= "table" then return false end
    if _truthyFavFlag(entry.IsFavorite) or _truthyFavFlag(entry.Favorite)
        or _truthyFavFlag(entry.Favorited) or _truthyFavFlag(entry.isFavorite)
        or _truthyFavFlag(entry.d) then
        return true
    end
    for _, key in ipairs({ "Attributes", "Data", "Fruit", "Entry", "Item" }) do
        local nested = entry[key]
        if type(nested) == "table" and _rawEntryFavorited(nested, depth + 1) then
            return true
        end
    end
    return false
end

local function _instanceFavorited(inst)
    if not inst or typeof(inst) ~= "Instance" or type(inst.GetAttribute) ~= "function" then
        return false
    end
    return _truthyFavFlag(inst:GetAttribute("IsFavorite"))
        or _truthyFavFlag(inst:GetAttribute("Favorite"))
        or _truthyFavFlag(inst:GetAttribute("Favorited"))
        or _truthyFavFlag(inst:GetAttribute("isFavorite"))
        or _truthyFavFlag(inst:GetAttribute("d"))
end

local function _getAutoFavModule()
    return G.AutoFav or G.AutoFavModule or rawget(_G, "AutoFav") or rawget(_G, "AutoFavModule")
end

local function _getNormalGiftModule()
    return G.NormalGift or G.NormalGiftModule or rawget(_G, "NormalGift") or rawget(_G, "NormalGiftModule")
end

_isHarvestEntryFavorited = function(itemKey, entry)
    local uuid = _resolveHarvestFruitItemKey(itemKey, entry)
    if not uuid or uuid == "" then return false end

    if type(harvestFavCache) ~= "table" then
        harvestFavCache = {}
    elseif harvestFavCache[uuid] ~= nil then
        return harvestFavCache[uuid] == true
    end

    local function cacheResult(yes)
        harvestFavCache[uuid] = yes == true
        return yes == true
    end

    local ng = _getNormalGiftModule()
    if type(ng) == "table" and type(ng.IsHarvestFavorited) == "function" then
        local ok, yes = pcall(ng.IsHarvestFavorited, ng, {
            uuid = uuid,
            raw = type(entry) == "table" and entry or nil,
            giftType = "HarvestedFruits",
        })
        if ok and yes == true then
            return cacheResult(true)
        end
    end

    local bagEntry = type(entry) == "table" and entry or nil
    if not bagEntry and type(_getBackpackFruitBag) == "function" then
        local bag = _getBackpackFruitBag(false)
        if type(bag) == "table" then
            bagEntry = bag[uuid]
        end
    end

    if _rawEntryFavorited(bagEntry, 0) then
        return cacheResult(true)
    end

    local inst = _findToolByFruitId(uuid)
    if inst and _instanceFavorited(inst) then
        return cacheResult(true)
    end

    local af = _getAutoFavModule()
    if type(af) == "table" and type(af.IsFruitIdFavorited) == "function" then
        local ok, yes = pcall(af.IsFruitIdFavorited, af, uuid, inst)
        if ok and yes == true then
            return cacheResult(true)
        end
    end

    return cacheResult(false)
end

function M.IsHarvestFavorited(itemKey, entry)
    if type(itemKey) == "table" then
        local row = itemKey
        return _isHarvestEntryFavorited(row.ItemKey or row.uuid or row.id, row.Entry or row.raw or row)
    end
    return _isHarvestEntryFavorited(itemKey, entry)
end

local function _getHarvestedFruitBag(inv)
    local invBag = nil
    if type(inv) == "table" then
        invBag = inv[HARVESTED_FRUITS_CAT] or inv.Fruits or inv.Fruit
    end
    local bpBag = _getBackpackFruitBag(false)
    local invHas = type(invBag) == "table" and _bagHasEntries(invBag)
    local bpHas = type(bpBag) == "table" and _bagHasEntries(bpBag)

    if invHas and _bagHasOnlyDisplayNameKeys(invBag) then
        bpBag = _getBackpackFruitBag(true)
        bpHas = type(bpBag) == "table" and _bagHasEntries(bpBag)
    end

    if bpHas then
        return bpBag
    end
    if invHas and not _bagHasOnlyDisplayNameKeys(invBag) then
        return invBag
    end
    return {}
end

_getInventoryBag = function(inv, category)
    category = _canonicalCategory(category)
    if category == "" then return nil, category end
    if _isHarvestedFruitsCategory(category) then
        return _getHarvestedFruitBag(inv), category
    end
    if type(inv) ~= "table" then return nil, category end
    local fallbacks = CATEGORY_BAG_FALLBACKS[category]
    if type(fallbacks) == "table" then
        local emptyBag = nil
        for _, key in ipairs(fallbacks) do
            local bag = inv[key]
            if type(bag) == "table" then
                if _bagHasEntries(bag) then return bag, category end
                if not emptyBag then emptyBag = bag end
            end
        end
        if emptyBag then return emptyBag, category end
    end
    local bag = inv[category]
    if type(bag) == "table" then return bag, category end
    local alt = SAVE_CATEGORY_ALIASES[category]
    if alt and type(inv[alt]) == "table" then return inv[alt], category end
    for legacy, canon in pairs(SAVE_CATEGORY_ALIASES) do
        if canon == category and type(inv[legacy]) == "table" then
            return inv[legacy], category
        end
    end
    local lower = category:lower()
    for key, bag in pairs(inv) do
        if type(bag) == "table" and tostring(key):lower() == lower then
            return bag, category
        end
    end
    return nil, category
end

local function _isUniqueEntryCategory(cat, bag)
    if type(bag) ~= "table" then return false end
    if _bagIsStackedCounts(bag) then return false end
    local hasUnique, hasStack = false, false
    _eachBagEntry(bag, function(itemKey, entry)
        if _isUniqueInventoryEntry(entry, itemKey) then
            hasUnique = true
        elseif _isStackInventoryEntry(entry, itemKey) then
            hasStack = true
        end
    end)
    if hasStack and not hasUnique then return false end
    return hasUnique
end

_isCountBasedCategory = function(cat, inv)
    cat = _canonicalCategory(cat)
    if cat == "" then return true end
    if _isHarvestedFruitsCategory(cat) then return false end
    inv = inv or _getInventory()
    local bag = inv and _getInventoryBag(inv, cat)
    return not _isUniqueEntryCategory(cat, bag)
end

_batchSendLimit = function(candidates, totalRemaining)
    local limit = _clampBatch(cfg.max_per_batch)
    if totalRemaining ~= nil then
        local remain = math.max(0, math.floor(tonumber(totalRemaining) or 0))
        if remain > 0 then
            limit = math.min(limit, remain)
        end
    end
    return limit
end

_categorySendLimit = function(cat)
    local limit = _clampBatch(cfg.max_per_batch)
    if not _isCountBasedCategory(cat, _getInventory(0)) then
        limit = math.min(limit, MAILBOX_UNIQUE_PER_SEND)
    end
    return limit
end

_rebuildCategoryDefs = function()
    if not _ensureMailboxCatalog() then
        return
    end
    local defs = {}
    local inv = nil
    local okInv, invResult = pcall(_getInventory, 2)
    if okInv then inv = invResult end
    for _, key in ipairs(_catalogCategories()) do
        if _catalogIsGiftable(key) then
            local bag = inv and _getInventoryBag(inv, key)
            defs[#defs + 1] = {
                key = key,
                label = _categoryLabel(key),
                countBased = key ~= HARVESTED_FRUITS_CAT and not _isUniqueEntryCategory(key, bag),
            }
        end
    end
    CATEGORY_DEFS = defs
end

local function _defaultSendTotals()
    local totals = {}
    for _, def in ipairs(CATEGORY_DEFS) do
        totals[def.key] = MAX_BATCH
    end
    return totals
end

_ensureCfgCategoryTables = function()
    cfg.categories = type(cfg.categories) == "table" and cfg.categories or {}
    cfg.selected = type(cfg.selected) == "table" and cfg.selected or {}
    cfg.send_totals = type(cfg.send_totals) == "table" and cfg.send_totals or {}
    for _, def in ipairs(CATEGORY_DEFS) do
        local key = def.key
        if cfg.categories[key] == nil then
            cfg.categories[key] = false
        end
        if type(cfg.selected[key]) ~= "table" then
            cfg.selected[key] = {}
        end
        if cfg.send_totals[key] == nil then
            cfg.send_totals[key] = MAX_BATCH
        end
    end
end
end

local _petBaseTypeName, _findInventoryPetEntry
do
    local function _petTypeName(entry, itemKey)
        if type(entry) == "table" then
            return tostring(entry.Type or entry.PetType or entry.PetName or entry.Name or entry.DisplayName or itemKey)
        end
        return tostring(itemKey)
    end

    local function _petDisplayName(raw)
        local name = tostring(raw or ""):gsub("^%s+", ""):gsub("%s+$", "")
        if name == "" then return nil end
        if name:match("^[%x%-]+$") and #name >= 12 then return nil end
        return name
    end

    local function _instLooksLikePet(inst)
        if not inst or type(inst.GetAttribute) ~= "function" then return false end
        if inst:GetAttribute("Pet") ~= nil then return true end
        if inst:GetAttribute("PetName") or inst:GetAttribute("PetType") then return true end
        if inst:GetAttribute("PottedPlant") == true then return false end
        if inst:GetAttribute("FruitName") or inst:GetAttribute("Fruit") then return false end
        return false
    end

    local function _findToolByPetId(id)
        id = tostring(id or "")
        if id == "" then return nil end
        local found = nil
        local function scan(container)
            if not container or found then return end
            for _, inst in ipairs(container:GetDescendants()) do
                if inst:IsA("Tool") or _instLooksLikePet(inst) then
                    local pid = tostring(
                        inst:GetAttribute("Id") or inst:GetAttribute("UUID")
                            or inst:GetAttribute("PetId") or inst:GetAttribute("InstanceId") or ""
                    )
                    if pid == id then
                        found = inst
                        return
                    end
                end
            end
        end
        scan(LP:FindFirstChild("Backpack") or LP:FindFirstChildOfClass("Backpack"))
        scan(LP.Character)
        return found
    end

    local function _entryHasPetName(entry, itemKey)
        if type(entry) ~= "table" then return false end
        local name = _petTypeName(entry, itemKey)
        if name == "" or name == tostring(itemKey) then return false end
        if name:match("^[%x%-]+$") and #name >= 12 then return false end
        return true
    end

    _findInventoryPetEntry = function(category, itemKey, hintEntry)
        if _entryHasPetName(hintEntry, itemKey) then
            return hintEntry
        end
        category = _canonicalCategory(category)
        if not PET_LIKE_CATEGORIES[category] then return hintEntry end
        local inv = _getInventory(0)
        if not inv then return hintEntry end
        local bag = _getInventoryBag(inv, category)
        if type(bag) ~= "table" then return hintEntry end
        local idWanted = tostring(itemKey or "")
        if idWanted == "" then return hintEntry end
        local found = nil
        _eachBagEntry(bag, function(key, entry)
            if found then return end
            local uid = _entryUniqueId(entry, key)
            if uid and tostring(uid) == idWanted then
                found = entry
            elseif tostring(key) == idWanted then
                found = entry
            end
        end)
        return found or hintEntry
    end

    _petBaseTypeName = function(entry, itemKey, category)
        category = _canonicalCategory(category or "Pets")
        entry = _findInventoryPetEntry(category, itemKey, entry)

        if _ensureMailboxCatalog() then
            local ok, name = _invokeCatalog("Resolve", category, itemKey, entry)
            if ok and name ~= nil then
                name = _petDisplayName(name)
                if name then return name end
            end
        end

        if type(entry) == "table" then
            local name = _petDisplayName(
                entry.PetName or entry.PetType or entry.Type or entry.Name or entry.DisplayName
            )
            if name then return name end
        end

        local id = _entryUniqueId(entry, itemKey) or tostring(itemKey or "")
        if id ~= "" then
            local inst = _findToolByPetId(id)
            if inst then
                local name = _petDisplayName(
                    inst:GetAttribute("PetName") or inst:GetAttribute("PetType")
                        or inst:GetAttribute("Pet") or inst.Name
                )
                if name then return name end
            end
        end

        local keyName = _petDisplayName(itemKey)
        if keyName then return keyName end
        return "Pet"
    end
end

local function _resolveDisplayName(category, itemKey, entry)
    if PET_LIKE_CATEGORIES[_canonicalCategory(category)] then
        return _petBaseTypeName(entry, itemKey, category)
    end
    if _ensureMailboxCatalog() then
        local ok, name = _invokeCatalog("Resolve", category, itemKey, entry)
        if ok and name ~= nil and tostring(name) ~= "" then
            return tostring(name)
        end
    end
    return tostring(itemKey)
end

local function _groupDisplayName(category, itemKey, entry)
    if _isHarvestedFruitsCategory(category) then
        return _fruitBaseTypeName(entry, itemKey)
    end
    if PET_LIKE_CATEGORIES[_canonicalCategory(category)] then
        return _petBaseTypeName(entry, itemKey, category)
    end
    return _resolveDisplayName(category, itemKey, entry)
end

local function _mailboxUsable()
    local ok, flags = pcall(function()
        return require(ReplicatedStorage.SharedModules.Flags.MailboxFlags)
    end)
    if ok and type(flags) == "table" and flags.OpenEnabled then
        if type(flags.OpenEnabled.Get) == "function" then
            local okGet, enabled = pcall(flags.OpenEnabled.Get, flags.OpenEnabled)
            if okGet then
                return enabled == true
            end
        elseif type(flags.OpenEnabled) == "function" then
            local okCall, enabled = pcall(flags.OpenEnabled)
            if okCall then
                return enabled == true
            end
        end
    end
    return true
end

local function _isModuleMethodCall(first)
    return type(first) == "table" and type(first.BuildInventoryItems) == "function"
end

local function _categoryArg(first, second)
    if type(second) == "string" then return second end
    if type(first) == "string" then return first end
    return tostring(second or first or "")
end

local function _boolArg(first, second)
    if _isModuleMethodCall(first) then
        return second == true
    end
    return first == true
end

local function _configArg(first, second)
    if _isModuleMethodCall(first) then
        return second
    end
    return first
end

local function _strArg(first, second)
    if type(second) == "string" then return second end
    if type(first) == "string" then return first end
    return tostring(second or first or "")
end

function M.GetInventory(_self)
    return _getInventory(5)
end

function M.GetPlayerStatePath()
    return "ReplicatedStorage.ClientModules.PlayerStateClient -> GetLocalReplica().Data.Inventory"
end

function M.GetCatalogPath()
    if catalogModuleInst and catalogModuleInst.Parent then
        return catalogModuleInst:GetFullName()
    end
    return "StarterPlayer.StarterPlayerScripts.Controllers.MailboxController.MailboxItemCatalog"
end

function M.ReloadCatalog(a, b)
    local force = _boolArg(a, b)
    _ensureMailboxCatalog(force)
    _rebuildCategoryDefs()
    _ensureCfgCategoryTables()
    if not catalogLoadedFromGame then
        _setStatus("MailboxItemCatalog not loaded")
    elseif #CATEGORY_DEFS == 0 then
        _setStatus("Mailbox categories empty")
    end
end

function M.IsCatalogLoaded(_self)
    return catalogLoadedFromGame == true and #CATEGORY_DEFS > 0
end

function M.ListInventoryKeys(_self)
    local inv = _getInventory(5)
    if not inv then return {} end
    local keys = {}
    for key, bag in pairs(inv) do
        if type(bag) == "table" then
            keys[#keys + 1] = tostring(key)
        end
    end
    table.sort(keys)
    return keys
end

local function _categoryEnabled(key)
    key = _canonicalCategory(key)
    if cfg.categories[key] == true then return true end
    for legacy, canon in pairs(SAVE_CATEGORY_ALIASES) do
        if canon == key and cfg.categories[legacy] == true then return true end
    end
    return false
end

local function _categorySelected(key)
    key = _canonicalCategory(key)
    local sel = cfg.selected[key]
    if type(sel) ~= "table" then sel = {} end
    local out = _normalizeSet(sel)
    for legacy, canon in pairs(SAVE_CATEGORY_ALIASES) do
        if canon == key then
            local leg = cfg.selected[legacy]
            if type(leg) == "table" then
                for k, v in pairs(_normalizeSet(leg)) do
                    if v == true then out[k] = true end
                end
            end
        end
    end
    return out
end

local function _enabledCategoryKeys()
    local out = {}
    for _, def in ipairs(CATEGORY_DEFS) do
        if _categoryEnabled(def.key) then
            out[#out + 1] = def.key
        end
    end
    return out
end

local function _onceUsesPriceMode()
    if _normalizeSendListMode(cfg.send_list_mode) ~= "send_total" then
        return false
    end
    if _normalizeOnceSendMode(cfg.once_send_mode) ~= "price" then
        return false
    end
    for _, cat in ipairs(_enabledCategoryKeys()) do
        if _isHarvestedFruitsCategory(cat) then
            return true
        end
    end
    return false
end

local function _onceSendUnitTarget()
    for _, cat in ipairs(_enabledCategoryKeys()) do
        local t = cfg.send_totals and cfg.send_totals[cat]
        if t ~= nil then
            return _clampSendTotalGoal(t)
        end
    end
    return _clampSendTotalGoal(20)
end

local function _matchesSelected(category, name, selectedMap, itemKey, entry)
    if not next(selectedMap) then return false end
    if itemKey ~= nil and selectedMap[tostring(itemKey)] == true then return true end
    local uid = _entryUniqueId(entry, itemKey)
    if uid and selectedMap[uid] == true then return true end
    name = tostring(name or "")
    if name ~= "" and selectedMap[name] == true then return true end
    local norm = name:lower():gsub("[%s_%-]+", "")
    for k, v in pairs(selectedMap) do
        if v == true and tostring(k):lower():gsub("[%s_%-]+", "") == norm then
            return true
        end
    end
    if entry ~= nil and _ensureMailboxCatalog() then
        local ok, resolved = _invokeCatalog("Resolve", category, itemKey, entry)
        if ok and resolved ~= nil and selectedMap[tostring(resolved)] == true then
            return true
        end
    end
    if PET_LIKE_CATEGORIES[_canonicalCategory(category)] and name ~= "" then
        for k, v in pairs(selectedMap) do
            if v == true then
                local base = tostring(k):gsub("%s*#%w+$", ""):gsub("%s*x%s+.+$", "")
                if base:lower():gsub("[%s_%-]+", "") == norm then
                    return true
                end
            end
        end
    end
    if _isHarvestedFruitsCategory(category) and name ~= "" then
        local normName = _normalizeFruitGroupKey(name)
        for k, v in pairs(selectedMap) do
            if v == true then
                local base = tostring(k):gsub("%s*x%s+.+$", "")
                if _normalizeFruitGroupKey(base) == normName then
                    return true
                end
            end
        end
    end
    return false
end

local function _loopSendAllWhenUnselected()
    return _normalizeSendListMode(cfg.send_list_mode) == "loop"
end

local function _includeGiftEntry(sendCat, displayName, selectedMap, itemKey, entry, harvestCat)
    if next(selectedMap) then
        return _matchesSelected(sendCat, displayName, selectedMap, itemKey, entry)
    end
    if harvestCat or _loopSendAllWhenUnselected() then
        return true
    end
    return false
end

local function _fruitTypeName(entry, itemKey)
    return _fruitBaseTypeName(entry, itemKey)
end

local function _isEquippedItemLegacy(itemKey, entry)
    if cfg.skip_equipped ~= true then return false end
    if type(entry) == "table" then
        local id = entry.Id or entry.UUID or entry.PetId or entry.InstanceId
            or entry.Guid or entry.UniqueId or entry.PetUUID
        if id ~= nil and equippedPets[tostring(id)] then return true end
        if entry.Equipped == true then return true end
    end
    if itemKey ~= nil and equippedPets[tostring(itemKey)] then return true end
    return false
end

local function _entryCount(entry)
    if type(entry) == "number" then return entry end
    local n = tonumber(entry)
    if type(n) == "number" then return n end
    if type(entry) == "table" then
        return tonumber(entry.Count or entry.Amount or entry.Quantity or entry.Stack or entry.Qty)
    end
    return nil
end

local function _isOwnedEntry(category, itemKey, entry)
    if type(entry) == "table" then
        if _isUniqueInventoryEntry(entry, itemKey) then
            return true
        end
        local n = _entryCount(entry)
        return type(n) == "number" and n > 0
    end
    local n = tonumber(entry)
    return type(n) == "number" and n > 0
end

local function _isGiftableEntry(category, itemKey, entry)
    category = _canonicalCategory(category)
    if type(entry) == "table" then
        if _isUniqueInventoryEntry(entry, itemKey) then
            if _isEquippedItemLegacy(itemKey, entry) then return false end
            return true
        end
        local n = _entryCount(entry)
        return type(n) == "number" and n > 0
    end
    local n = tonumber(entry)
    return type(n) == "number" and n > 0
end

local function _selectedMapForUi(category)
    local sel = _categorySelected(category)
    if next(sel) then return sel end
    local store = G.__GAG2_AUTO_GIFT or _G.__GAG2_AUTO_GIFT
    if type(store) == "table" and type(store.selected) == "table" then
        local cat = _canonicalCategory(category)
        local raw = store.selected[cat]
        if type(raw) == "table" then
            local out = _normalizeSet(raw)
            if next(out) then return out end
        end
        for legacy, canon in pairs(SAVE_CATEGORY_ALIASES) do
            if canon == cat and type(store.selected[legacy]) == "table" then
                local out = _normalizeSet(store.selected[legacy])
                if next(out) then return out end
            end
        end
    end
    return sel
end

local function _appendSelectedZeroItems(items, category)
    items = type(items) == "table" and items or {}
    local selectedMap = _selectedMapForUi(category)
    if not next(selectedMap) then return items end

    local have = {}
    local haveNorm = {}
    for _, it in ipairs(items) do
        local k = tostring(it.key)
        have[k] = true
        local base = k:gsub("%s*x%s+.+$", "")
        haveNorm[_normalizeFruitGroupKey(base)] = true
    end
    for selKey, on in pairs(selectedMap) do
        if on == true then
            local sk = tostring(selKey)
            local norm = _normalizeFruitGroupKey(sk:gsub("%s*x%s+.+$", ""))
            if not have[sk] and not haveNorm[norm] then
                items[#items + 1] = {
                    key = sk,
                    name = sk .. " x 0",
                    right = "0",
                    count = 0,
                }
            end
        end
    end
    table.sort(items, function(a, b) return a.name < b.name end)
    return items
end

local function _buildInventoryItems(category)
    category = _canonicalCategory(tostring(category or ""))
    if category == "" then return {} end

    local inv = _getInventory(10)
    if not inv and not _isHarvestedFruitsCategory(category) then
        return _appendSelectedZeroItems({}, category)
    end

    local bag, sendCat = _getInventoryBag(inv, category)
    if type(bag) ~= "table" then return _appendSelectedZeroItems({}, category) end
    sendCat = sendCat or category

    _ensureMailboxCatalog()
    if not _catalogIsGiftable(category) and not next(bag) then
        return _appendSelectedZeroItems({}, category)
    end

    local items = {}
    local countBased = _isCountBasedCategory(sendCat, inv)

    if countBased then
        _eachBagEntry(bag, function(itemKey, count)
            if type(count) == "table" then
                if _isUniqueInventoryEntry(count, itemKey) then
                    if _isOwnedEntry(sendCat, itemKey, count) then
                        local typeName = _resolveDisplayName(sendCat, itemKey, count)
                        items[#items + 1] = {
                            key = typeName,
                            name = typeName .. " x 1",
                            right = "1",
                            count = 1,
                        }
                    end
                    return
                end
                count = _entryCount(count) or 0
            else
                count = tonumber(count) or 0
            end
            if _isOwnedEntry(sendCat, itemKey, count) then
                local key = tostring(itemKey)
                local displayName = _resolveDisplayName(sendCat, itemKey, type(count) == "table" and count or nil)
                items[#items + 1] = {
                    key = key,
                    name = displayName .. " x " .. _formatCount(count),
                    right = _formatCount(count),
                    count = count,
                }
            end
        end)
        table.sort(items, function(a, b) return a.key < b.key end)
        return _appendSelectedZeroItems(items, category)
    end

    local grouped = {}
    _eachBagEntry(bag, function(itemKey, entry)
        if _isOwnedEntry(sendCat, itemKey, entry) then
            if _isHarvestedFruitsCategory(sendCat) and _isHarvestEntryFavorited(itemKey, entry) then
                return
            end
            local typeName = _groupDisplayName(sendCat, itemKey, entry)
            local groupKey = _normalizeFruitGroupKey(typeName)
            local slot = grouped[groupKey]
            if not slot then
                slot = { name = typeName, count = 0 }
                grouped[groupKey] = slot
            end
            if type(entry) == "number" or (tonumber(entry) and type(entry) ~= "table") then
                local n = math.floor(tonumber(entry) or 0)
                if n > 0 then
                    slot.count += n
                else
                    slot.count += 1
                end
            else
                slot.count += 1
            end
        end
    end)

    for _, slot in pairs(grouped) do
        items[#items + 1] = {
            key = slot.name,
            name = slot.name .. " x " .. _formatCount(slot.count),
            right = _formatCount(slot.count),
            count = slot.count,
        }
    end
    table.sort(items, function(a, b) return a.name < b.name end)
    return _appendSelectedZeroItems(_dedupeInventoryItems(items), category)
end

function M.BuildInventoryItems(a, b)
    return _buildInventoryItems(_categoryArg(a, b))
end

function M.PeekCategory(a, b)
    local category = _canonicalCategory(_categoryArg(a, b))
    _ensureMailboxCatalog()
    local inv = _getInventory(5)
    local bag, sendCat = _getInventoryBag(inv, category)
    print("[AutoGift] peek", category, "bag=", type(bag), "countBased=", inv and _isCountBasedCategory(sendCat, inv))
    if type(bag) == "table" then
        local n = 0
        _eachBagEntry(bag, function(k, e)
            n += 1
            if n <= 5 then
                print("  raw", k, type(e), "giftable=", _isGiftableEntry(sendCat, k, e),
                    "name=", _resolveDisplayName(sendCat, k, e))
            end
        end)
        print("  entries=", n, "ui items=", #_buildInventoryItems(category))
    end
end

M.PackCategory = M.PeekCategory

function M.DebugCategory(a, b)
    local category = _canonicalCategory(_categoryArg(a, b))
    if category == "" then
        warn("[AutoGift] DebugCategory: pass a category name, e.g. DebugCategory(ag, \"Pets\")")
        return
    end
    _ensureMailboxCatalog(true)
    local inv = _getInventory(10)
    local bag, sendCat = _getInventoryBag(inv, category)
    sendCat = sendCat or category
    local lines = {
        "[AutoGift] DebugCategory " .. category,
        "  catalogLoaded=" .. tostring(catalogLoadedFromGame),
        "  giftable=" .. tostring(_catalogIsGiftable(category)),
        "  inventory=" .. tostring(inv ~= nil),
        "  bag=" .. tostring(type(bag)),
        "  bagEntries=" .. tostring(bag and _bagHasEntries(bag)),
        "  countBased=" .. tostring(inv and _isCountBasedCategory(sendCat, inv)),
        "  uiItems=" .. tostring(#_buildInventoryItems(category)),
    }
    if type(bag) == "table" then
        local n = 0
        _eachBagEntry(bag, function(k, e)
            n += 1
            if n <= 8 then
                lines[#lines + 1] = "  [" .. n .. "] " .. tostring(k) .. " type=" .. type(e)
                    .. " owned=" .. tostring(_isOwnedEntry(sendCat, k, e))
                    .. " sendable=" .. tostring(_isGiftableEntry(sendCat, k, e))
                    .. " name=" .. tostring(_resolveDisplayName(sendCat, k, e))
            end
        end)
        lines[#lines + 1] = "  rawCount=" .. tostring(n)
    end
    local out = table.concat(lines, "\n")
    print(out)
    return out
end

function M.DebugHarvestSend(a, b)
    local category = _canonicalCategory(_categoryArg(a, b))
    if category == "" then category = "HarvestedFruits" end
    if not _isHarvestedFruitsCategory(category) then
        warn("[AutoGift] DebugHarvestSend: use HarvestedFruits category")
        return nil
    end

    M.InvalidateHarvestFruitCache()
    _ensureMailboxCatalog()

    local lines = { "[AutoGift] DebugHarvestSend " .. category }
    lines[#lines + 1] = "  --- UI list (key = pilih di dropdown, name = tampilan) ---"
    for _, it in ipairs(_buildInventoryItems(category)) do
        lines[#lines + 1] = ("  UI  key=%s  name=%s"):format(
            tostring(it.key or ""),
            tostring(it.name or "")
        )
    end

    lines[#lines + 1] = "  --- Send candidates (ItemKey = yang dikirim ke server) ---"
    local candidates = _collectCandidates()
    local harvestN = 0
    for _, item in ipairs(candidates) do
        if _isHarvestedFruitsCategory(item.Category) then
            harvestN += 1
            if harvestN <= 12 then
                lines[#lines + 1] = ("  SEND  ItemKey=%s  Count=%s"):format(
                    tostring(item.ItemKey or ""),
                    tostring(item.Count or 1)
                )
            end
        end
    end
    lines[#lines + 1] = "  harvestCandidates=" .. tostring(harvestN)
        .. " totalCandidates=" .. tostring(#candidates)
    lines[#lines + 1] = "  mailboxUniquePerSend=" .. tostring(MAILBOX_UNIQUE_PER_SEND)
        .. " (harvested fruits kirim per batch, bukan 100 sekaligus)"

    local out = table.concat(lines, "\n")
    print(out)
    return {
        category = category,
        uiItems = _buildInventoryItems(category),
        candidates = candidates,
        harvestCount = harvestN,
    }
end

M.debugHarvestSend = M.DebugHarvestSend

local function _collectCandidatesForCategory(inv, category, selectedMap, allowUnselected)
    local out = {}
    local cat = _canonicalCategory(tostring(category or ""))
    if cat == "" then return out end

    selectedMap = type(selectedMap) == "table" and selectedMap or {}
    local bag, sendCat = _getInventoryBag(inv, cat)
    local harvestCat = _isHarvestedFruitsCategory(sendCat)
    if not harvestCat and not next(selectedMap) and not allowUnselected then
        return out
    end
    if type(bag) ~= "table" then return out end

    if _isCountBasedCategory(sendCat, inv) then
        _eachBagEntry(bag, function(itemKey, count)
            if type(count) == "table" then
                count = _entryCount(count) or 0
            else
                count = tonumber(count) or 0
            end
            local displayName = _resolveDisplayName(sendCat, itemKey, nil)
            if _isGiftableEntry(sendCat, itemKey, count)
                and _includeGiftEntry(sendCat, displayName, selectedMap, itemKey, nil, harvestCat) then
                out[#out + 1] = {
                    Category = sendCat,
                    ItemKey = tostring(itemKey),
                    Count = count,
                    SortKey = tostring(itemKey),
                    Entry = nil,
                    SellPrice = 0,
                }
            end
        end)
    else
        _eachBagEntry(bag, function(itemKey, entry)
            if _isGiftableEntry(sendCat, itemKey, entry) then
                if harvestCat and _isHarvestEntryFavorited(itemKey, entry) then
                    return
                end
                local typeName = _groupDisplayName(sendCat, itemKey, entry)
                if _includeGiftEntry(sendCat, typeName, selectedMap, itemKey, entry, harvestCat) then
                    local mailKey = harvestCat
                        and _resolveHarvestFruitItemKey(itemKey, entry)
                        or tostring(itemKey)
                    if mailKey then
                        local sellPrice = harvestCat and _entrySellPrice(sendCat, itemKey, entry) or 0
                        out[#out + 1] = {
                            Category = sendCat,
                            ItemKey = mailKey,
                            Count = 1,
                            SortKey = typeName .. ":" .. mailKey,
                            Entry = type(entry) == "table" and entry or nil,
                            SellPrice = sellPrice,
                        }
                    end
                end
            end
        end)
    end

    table.sort(out, function(a, b)
        return tostring(a.SortKey) < tostring(b.SortKey)
    end)
    return out
end

function M.CollectCategoryCandidates(a, b, c)
    local category = a
    local selectedMap = b
    if type(a) == "table" and type(b) == "string" then
        category = b
        selectedMap = c
    end
    if type(_ensureFsvFresh) == "function" then
        _ensureFsvFresh(true)
    end
    return _collectCandidatesForCategory(
        _getInventory(0),
        category,
        selectedMap,
        _loopSendAllWhenUnselected()
    )
end

function M.GetHarvestFruitBag(_self, forceRefresh)
    return _getBackpackFruitBag(forceRefresh == true)
end

local function _collectCandidates()
    if type(_ensureFsvFresh) == "function" then
        _ensureFsvFresh(true)
    end
    local inv = _getInventory(0)

    local out = {}
    for _, def in ipairs(CATEGORY_DEFS) do
        local cat = def.key
        if _categoryEnabled(cat) then
            local selectedMap = _categorySelected(cat)
            local harvestCat = _isHarvestedFruitsCategory(cat)
            if not harvestCat and not next(selectedMap) and not _loopSendAllWhenUnselected() then
                continue
            end
            local chunk = _collectCandidatesForCategory(
                inv,
                cat,
                selectedMap,
                _loopSendAllWhenUnselected()
            )
            for _, row in ipairs(chunk) do
                out[#out + 1] = row
            end
        end
    end

    table.sort(out, function(a, b)
        return tostring(a.SortKey) < tostring(b.SortKey)
    end)
    return out
end

local function _sumCandidateUnits(candidates)
    local n = 0
    for _, item in ipairs(candidates) do
        n += math.max(0, math.floor(tonumber(item.Count) or 1))
    end
    return n
end

local function _sumCandidatePrice(candidates)
    local total = 0
    for _, item in ipairs(candidates) do
        local price = math.floor(tonumber(item.SellPrice) or 0)
        if price <= 0 and not _isCountBasedCategory(item.Category, _getInventory(0)) then
            price = _entrySellPrice(item.Category, item.ItemKey, item.Entry)
            item.SellPrice = price
        end
        if price > 0 then
            total += price
        end
    end
    return total
end

function M.CountSendableUnits(_self)
    return _sumCandidateUnits(_collectCandidates())
end

function M.CountSendablePrice(_self)
    return _sumCandidatePrice(_collectCandidates())
end

function M.CheckSendTotalAvailability(_self, target, priceMode)
    target = math.floor(tonumber(target) or 0)
    if target < 1 then
        return true
    end
    if priceMode == nil then
        priceMode = _onceUsesPriceMode()
    else
        priceMode = priceMode == true
    end
    M.InvalidateHarvestFruitCache()
    local candidates = _collectCandidates()
    if priceMode then
        local available = _sumCandidatePrice(candidates)
        if available < 1 then
            return false, "Tidak ada item giftable di inventory untuk category terpilih"
        end
        if available < target then
            return false, "Value kurang: punya "
                .. _formatSellPrice(available)
                .. ", butuh "
                .. _formatSellPrice(target)
        end
    else
        local available = _sumCandidateUnits(candidates)
        if available < 1 then
            return false, "Tidak ada item giftable di inventory untuk category terpilih"
        end
        if available < target then
            return false, "Item kurang: punya "
                .. tostring(available)
                .. ", butuh "
                .. tostring(target)
        end
    end
    return true
end

function M.PreviewHarvestPricePlan(_self)
    if not _onceUsesPriceMode() then
        return {
            ok = false,
            text = "Mode count — bukan price search",
        }
    end
    local cacheKey = string.format(
        "mb|%d|%s|%s|%s",
        _pricePlanEpoch,
        tostring(cfg.send_total or 0),
        tostring(cfg.harvest_price_threshold_pct or 0),
        tostring(cfg.harvest_price_calc_mode or "base")
    )
    if type(_pricePlanPreviewCache) == "table" and _pricePlanPreviewCache.key == cacheKey then
        return _pricePlanPreviewCache.val
    end

    local target = _clampSendTotalGoal(cfg.send_total)
    local minSum, maxSum = _priceRangeForRemain(target)
    local candidates = _collectCandidates()
    local batchLimit = math.min(MAILBOX_UNIQUE_PER_SEND, _batchSendLimit(candidates, nil))
    local pick, total, poolSize, batchCount = _buildMultiBatchPricePlan(
        candidates,
        minSum,
        maxSum,
        batchLimit
    )
    local result
    if not pick or #pick == 0 then
        local text = _pricePlanSummary(nil, total or 0, minSum, maxSum, poolSize or 0, batchCount)
        result = {
            ok = false,
            minTotal = minSum,
            maxTotal = maxSum,
            poolSize = poolSize or 0,
            text = text,
        }
    else
        local text = _pricePlanSummary(pick, total, minSum, maxSum, poolSize, batchCount)
        result = {
            ok = true,
            minTotal = minSum,
            maxTotal = maxSum,
            total = total,
            count = #pick,
            poolSize = poolSize,
            batchCount = batchCount,
            breakdown = _formatPriceBreakdown(pick),
            text = text,
        }
    end
    _pricePlanPreviewCache = { key = cacheKey, val = result }
    return result
end

local function _buildBatch(candidates, maxItems, totalRemaining)
    maxItems = _clampBatch(maxItems)
    if totalRemaining ~= nil then
        totalRemaining = math.max(0, math.floor(tonumber(totalRemaining) or 0))
        maxItems = math.min(maxItems, totalRemaining)
    end
    if maxItems <= 0 then return {}, 0 end

    local batch = {}
    local used = 0
    local catUsed = {}
    local unitsLeft = totalRemaining
    local inv = _getInventory(0)

    for _, item in ipairs(candidates) do
        if #batch >= MAILBOX_UNIQUE_PER_SEND then
            break
        end

        local cat = item.Category
        local countBased = _isCountBasedCategory(cat, inv)
        if countBased and used >= maxItems then
            break
        end

        local catLimit = _categorySendLimit(cat)
        local cu = catUsed[cat] or 0
        if cu >= catLimit then
            continue
        end

        local count = tonumber(item.Count) or 1
        if countBased then
            local room = math.min(maxItems - used, catLimit - cu)
            if unitsLeft ~= nil then
                room = math.min(room, unitsLeft)
            end
            count = math.min(count, room)
            if count > 0 then
                batch[#batch + 1] = {
                    Category = item.Category,
                    ItemKey = item.ItemKey,
                    Count = count,
                    Entry = item.Entry,
                }
                used += count
                catUsed[cat] = cu + count
                if unitsLeft ~= nil then
                    unitsLeft -= count
                end
            end
        elseif unitsLeft == nil or unitsLeft > 0 then
            batch[#batch + 1] = {
                Category = item.Category,
                ItemKey = item.ItemKey,
                Count = 1,
                Entry = item.Entry,
            }
            used += 1
            catUsed[cat] = cu + 1
            if unitsLeft ~= nil then
                unitsLeft -= 1
            end
        end
    end

    return batch, used
end

local _resetSendJobHistory, _flushSendJobHistory, _commitGiftHistory
do
    local function _accumulateSendJobHistory(batchSnap, totalSnap, sendBatchNum, histMsg)
        local acc = sendJobHistoryAcc
        if type(acc) ~= "table" then return end
        for _, row in ipairs(batchSnap) do
            if type(row) == "table" then
                acc.rows[#acc.rows + 1] = {
                    Category = row.Category,
                    Name = row.Name,
                    Count = row.Count,
                    UnitPrice = row.UnitPrice,
                }
                if _isHarvestedFruitsCategory(row.Category) then
                    local cnt = math.max(1, math.floor(tonumber(row.Count) or 1))
                    local unit = math.max(0, math.floor(tonumber(row.UnitPrice) or 0))
                    if unit > 0 then
                        acc.totalHarvestPrice = (acc.totalHarvestPrice or 0) + (unit * cnt)
                    end
                end
            end
        end
        acc.totalUnits += math.max(0, math.floor(tonumber(totalSnap) or 0))
        local bn = math.max(1, math.floor(tonumber(sendBatchNum) or 1))
        if bn > acc.batchCount then
            acc.batchCount = bn
        end
        if histMsg and tostring(histMsg) ~= "" then
            acc.lastMsg = tostring(histMsg)
        end
    end

    local function _writeGiftHistoryRecord(batchSnap, totalSnap, sendBatchNum, histMsg, harvestTotalHint)
        if type(batchSnap) ~= "table" or #batchSnap == 0 then return end
        local hist = G.GiftMailHistoryModule or G.GiftMailHistory
            or rawget(_G, "GiftMailHistoryModule") or rawget(_G, "GiftMailHistory")
        if type(hist) ~= "table" then return end

        totalSnap = math.max(0, math.floor(tonumber(totalSnap) or 0))
        sendBatchNum = math.max(1, math.floor(tonumber(sendBatchNum) or 1))
        histMsg = tostring(histMsg or "")

        local harvestTotalPrice = math.max(0, math.floor(tonumber(harvestTotalHint) or 0))
        if harvestTotalPrice <= 0 then
            for _, row in ipairs(batchSnap) do
                if type(row) == "table" and _isHarvestedFruitsCategory(row.Category) then
                    local cnt = math.max(1, math.floor(tonumber(row.Count) or 1))
                    local unit = math.max(0, math.floor(tonumber(row.UnitPrice) or 0))
                    if unit > 0 then
                        harvestTotalPrice += unit * cnt
                    end
                end
            end
        end

        local opts = {
            total = totalSnap,
            success = true,
            msg = histMsg,
            sendBatchNum = sendBatchNum,
            cfg = cfg,
            auto_send = cfg.auto_send,
            harvest_total_price = harvestTotalPrice > 0 and harvestTotalPrice or nil,
        }

        if type(hist.RecordSendBatch) == "function" then
            pcall(hist.RecordSendBatch, batchSnap, opts)
            return
        end
        if type(hist.Record) ~= "function" then return end

        local uid = math.floor(tonumber(cfg.recipient_user_id) or 0)
        local user = tostring(cfg.recipient_username or "")
        local disp = tostring(cfg.recipient_display or "")
        if uid <= 0 then
            local s = G.__GAG2_AUTO_GIFT or rawget(_G, "__GAG2_AUTO_GIFT")
            local p = (type(s) == "table" and type(s.once) == "table") and s.once or s
            if type(p) == "table" then
                uid = math.floor(tonumber(p.recipient_user_id) or 0)
                if user == "" then user = tostring(p.recipient_username or "") end
                if disp == "" then disp = tostring(p.recipient_display or "") end
            end
        end

        pcall(hist.Record, {
            ts = os.time(),
            profile = (cfg.auto_send == true) and "loop" or "once",
            success = true,
            recipient_user_id = uid,
            recipient_username = user,
            recipient_display = disp,
            item_count = totalSnap,
            send_batch = sendBatchNum,
            batch_rows = #batchSnap,
            note = tostring(cfg.note or ""),
            message = histMsg,
            items = batchSnap,
        })
    end

    _resetSendJobHistory = function()
        sendJobHistoryAcc = {
            rows = {},
            totalUnits = 0,
            totalHarvestPrice = 0,
            batchCount = 0,
            lastMsg = "",
        }
    end

    _flushSendJobHistory = function()
        local acc = sendJobHistoryAcc
        sendJobHistoryAcc = nil
        if type(acc) ~= "table" or #acc.rows == 0 then return end
        local msg = acc.lastMsg
        if msg == "" then
            msg = "Gift sent! (" .. tostring(acc.totalUnits) .. " item)"
        end
        _writeGiftHistoryRecord(
            acc.rows,
            acc.totalUnits,
            acc.batchCount,
            msg,
            acc.totalHarvestPrice
        )
    end

    _commitGiftHistory = function(batchSnap, totalSnap, sendBatchNum, histMsg)
        if sendJobRunning and type(sendJobHistoryAcc) == "table" then
            _accumulateSendJobHistory(batchSnap, totalSnap, sendBatchNum, histMsg)
            return
        end
        _writeGiftHistoryRecord(batchSnap, totalSnap, sendBatchNum, histMsg)
    end
end

local function _fireSendBatch(batch, total, sendBatchNum)
    if #batch == 0 or total <= 0 then
        return false, "empty_batch"
    end

    local batchSnap = {}
    for _, row in ipairs(batch) do
        if type(row) == "table" then
            local cat = tostring(row.Category or "")
            local ikey = tostring(row.ItemKey or row.ItemName or "")
            local src = type(row.Entry) == "table" and row.Entry or row
            if _isHarvestedFruitsCategory(cat) then
                local fid = _resolveHarvestFruitItemKey(ikey, src)
                if fid and type(_getBackpackFruitBag) == "function" then
                    local bag = _getBackpackFruitBag(false)
                    if type(bag) == "table" and type(bag[fid]) == "table" then
                        src = bag[fid]
                        ikey = fid
                    end
                end
            elseif PET_LIKE_CATEGORIES[_canonicalCategory(cat)] then
                src = _findInventoryPetEntry(cat, ikey, src)
            end
            local dname = _groupDisplayName(cat, ikey, src)
            if dname:match("^[%x%-]+$") and #dname >= 12 then
                if _isHarvestedFruitsCategory(cat) then
                    dname = _fruitBaseTypeName(src, ikey)
                elseif PET_LIKE_CATEGORIES[_canonicalCategory(cat)] then
                    dname = _petBaseTypeName(src, ikey, cat)
                end
                if dname:match("^[%x%-]+$") and #dname >= 12 then
                    dname = (PET_LIKE_CATEGORIES[_canonicalCategory(cat)] and "Pet")
                        or (cat == "Seeds" and "Seed")
                        or (_isHarvestedFruitsCategory(cat) and "Fruit") or cat
                end
            end
            local unitPrice = 0
            if _isHarvestedFruitsCategory(cat) then
                unitPrice = math.floor(tonumber(_entrySellPrice(cat, ikey, src)) or 0)
            end
            batchSnap[#batchSnap + 1] = {
                Category = cat,
                Name = dname,
                Count = math.max(1, math.floor(tonumber(row.Count) or 1)),
                UnitPrice = unitPrice,
            }
        end
    end
    local totalSnap = math.max(0, math.floor(tonumber(total) or 0))

    local note = tostring(cfg.note or "")
    if #note > 100 then note = note:sub(1, 100) end

    if _effectiveSendCooldownRemain() > 0 then
        return false, "cooldown"
    end

    local sendBatch = {}
    for _, row in ipairs(batch) do
        if type(row) == "table" then
            sendBatch[#sendBatch + 1] = {
                Category = row.Category,
                ItemKey = row.ItemKey,
                Count = row.Count,
            }
        end
    end

    local ok, success, msg = _callNetworkingRemote(MailboxSendBatch, cfg.recipient_user_id, sendBatch, note)

    if not ok then
        local errMsg = tostring(success)
        stats.lastSendError = errMsg
        G.AUTO_GIFT_LAST_SEND_ERROR = errMsg
        _G.AUTO_GIFT_LAST_SEND_ERROR = errMsg
        warn("[GAG2-Gift] SendBatch error:", errMsg)
        _log("SendBatch throw:", errMsg, "batchRows=", #sendBatch, "total=", totalSnap)
        _setStatus("Send error: " .. errMsg, errMsg)
        if _isCooldownReason(errMsg, errMsg) then
            _noteServerCooldownFromMessage(errMsg)
            return false, "cooldown"
        end
        return false, "send_error"
    end

    if success == true then
        lastSendAt = os.clock()
        stats.lastSendAt = lastSendAt
        stats.sentBatches += 1
        stats.sentItems += totalSnap
        M.InvalidateHarvestFruitCache()
        local text = (msg and tostring(msg) ~= "") and tostring(msg) or ("Gift sent! (" .. tostring(totalSnap) .. " item)")
        _setStatus(text)
        if type(_commitGiftHistory) == "function" then
            pcall(_commitGiftHistory, batchSnap, totalSnap, sendBatchNum, text)
        end
        return true, batch
    end

    local failMsg = tostring(msg ~= "" and msg or "Could not send gift")
    stats.lastSendError = failMsg
    G.AUTO_GIFT_LAST_SEND_ERROR = failMsg
    _G.AUTO_GIFT_LAST_SEND_ERROR = failMsg
    warn("[GAG2-Gift] SendBatch rejected:", failMsg)
    _log("SendBatch rejected:", failMsg, "batchRows=", #sendBatch, "total=", totalSnap)
    _setStatus(failMsg, failMsg)
    if _isCooldownReason(failMsg, failMsg) then
        _noteServerCooldownFromMessage(failMsg)
        return false, "cooldown"
    end
    return false, msg
end

function M.LookupRecipient(a, b)
    local username = _cleanUsername(_strArg(a, b))
    if username == "" then
        cfg.recipient_user_id = 0
        cfg.recipient_display = ""
        _setStatus("Enter recipient username")
        return false, "empty_username"
    end

    local now = os.clock()
    if now - lastLookupAt < LOOKUP_COOLDOWN then
        return cfg.recipient_user_id > 0, cfg.recipient_user_id
    end
    lastLookupAt = now

    if not _ensureNetworking() or not _remoteCallable(MailboxLookup) then
        _setStatus("Mailbox remote not ready")
        return false, "no_remote"
    end

    local ok, userId, displayName = _callNetworkingRemote(MailboxLookup, username)
    if not ok then
        _setStatus("Lookup failed")
        return false, "lookup_error"
    end

    userId = tonumber(userId) or 0
    if userId <= 0 or userId == LP.UserId then
        cfg.recipient_user_id = 0
        cfg.recipient_display = ""
        _setStatus("User not found: " .. username)
        return false, "not_found"
    end

    cfg.recipient_username = username
    cfg.recipient_user_id = userId
    cfg.recipient_display = tostring(displayName ~= "" and displayName or username)
    _setStatus("Recipient OK: " .. cfg.recipient_display .. " (" .. tostring(userId) .. ")")
    return true, userId
end

function M._notifySendJobDone(completedOk, reason)
    if type(_flushSendJobHistory) == "function" then
        pcall(_flushSendJobHistory)
    end
    if cfg.after_send_mode == "reset" and completedOk then
        local resetKey = (_normalizeSendListMode(cfg.send_list_mode) == "loop")
            and "__GAG2_RESET_GIFT_LOOP" or "__GAG2_RESET_GIFT_ONCE"
        local fn = G[resetKey] or rawget(_G, resetKey)
        if type(fn) ~= "function" then
            fn = G.__GAG2_RESET_GIFT_MAILBOX or rawget(_G, "__GAG2_RESET_GIFT_MAILBOX")
        end
        if type(fn) == "function" then
            pcall(fn)
        end
    end
    local keepToggle = (completedOk ~= true) and _isCooldownReason(reason, stats.lastStatus)
    local doneFn = G.__GAG2_GIFT_SEND_JOB_DONE or _G.__GAG2_GIFT_SEND_JOB_DONE
    if type(doneFn) == "function" then
        pcall(doneFn, completedOk == true, keepToggle)
    end
end

local function _loopWaitingStatusMessage()
    local enabled = _enabledCategoryKeys()
    if #enabled == 0 then
        return "Auto send: menunggu item (belum ada category)"
    end
    M.InvalidateHarvestFruitCache()
    local candidates = _collectCandidates()
    local byCat = {}
    for _, item in ipairs(candidates) do
        local cat = tostring(item.Category or "")
        byCat[cat] = (byCat[cat] or 0) + math.max(1, math.floor(tonumber(item.Count) or 1))
    end
    local activeParts = {}
    local emptyParts = {}
    for _, cat in ipairs(enabled) do
        local n = byCat[cat] or 0
        local label = _categoryLabel(cat)
        if n > 0 then
            activeParts[#activeParts + 1] = label .. " " .. tostring(n)
        else
            emptyParts[#emptyParts + 1] = label
        end
    end
    if #activeParts > 0 then
        return "Auto send: lanjut " .. table.concat(activeParts, ", ")
    end
    if #emptyParts > 0 then
        return "Auto send: menunggu item (" .. table.concat(emptyParts, ", ") .. " habis)"
    end
    return "Auto send: menunggu item..."
end

function M.SendOnceInternal()
    if cfg.recipient_user_id <= 0 then
        local ok = M.LookupRecipient(cfg.recipient_username)
        if not ok then return false, "no_recipient" end
    end
    if not _mailboxUsable() then
        _setStatus("Mailbox disabled on server")
        return false, "mailbox_disabled"
    end
    if not _ensureNetworking() or not MailboxSendBatch then
        _setStatus("SendBatch remote not ready")
        return false, "no_remote"
    end

    if _effectiveSendCooldownRemain() > 0 then
        return false, "cooldown"
    end

    M.InvalidateHarvestFruitCache()
    local candidates = _collectCandidates()
    if #candidates == 0 then
        local enabled = _enabledCategoryKeys()
        local hasSelection = false
        for _, cat in ipairs(enabled) do
            if next(_categorySelected(cat)) then
                hasSelection = true
                break
            end
        end
        if not hasSelection and not _loopSendAllWhenUnselected() then
            _setStatus("Pilih item di list (kosong = tidak kirim)")
            return false, "no_selection"
        end
        local cats = enabled
        local hint = (#cats > 0) and table.concat(cats, ", ") or "none"
        _setStatus("No items to send (" .. hint .. ") — check category & inventory")
        return false, "no_items"
    end

    local batch, total = _buildBatch(candidates, _batchSendLimit(candidates, nil), nil)
    batch = _prepareHarvestBatch(batch)
    if #batch == 0 then
        return false, "empty_batch"
    end
    total = 0
    for _, item in ipairs(batch) do
        total += math.max(1, math.floor(tonumber(item.Count) or 1))
    end

    return _fireSendBatch(batch, total, 1)
end

function M.SendOnce(_self)
    local ok, res = M.SendOnceInternal()
    if not ok and res == "cooldown" then
        _setStatus("Send cooldown...")
    elseif not ok and res == "no_items" then
        _setStatus("No giftable items")
    end
    return ok, res
end

function M.SetStatus(_self, msg, profile)
    _setStatus(tostring(msg or ""), nil, profile)
end

function M.GetProfileStatus(_self, profileKey)
    profileKey = (tostring(profileKey or ""):lower() == "loop") and "loop" or "once"
    if profileKey == "loop" then
        return stats.lastStatusLoop or "Ready"
    end
    return stats.lastStatusOnce or "Ready"
end

function M.ValidateSendOnceJob(_self)
    if cfg.recipient_user_id <= 0 then
        if tostring(cfg.recipient_username or "") == "" then
            _setStatus("Pilih target dulu")
            return false, "Pilih target dulu"
        end
        local ok = M.LookupRecipient(cfg.recipient_username)
        if not ok then
            _setStatus("Target tidak ditemukan / lookup gagal")
            return false, "Target tidak ditemukan / lookup gagal"
        end
    end
    if not _mailboxUsable() then
        _setStatus("Mailbox disabled on server")
        return false, "Mailbox disabled on server"
    end
    if not _ensureNetworking() or not MailboxSendBatch then
        _setStatus("SendBatch remote not ready")
        return false, "SendBatch remote not ready"
    end
    local priceMode = _onceUsesPriceMode()
    local target = priceMode and _clampSendTotalGoal(cfg.send_total) or _onceSendUnitTarget()
    if target < 1 then
        local msg = priceMode and "Send total price minimal 1" or "Send total minimal 1"
        _setStatus(msg)
        return false, msg
    end
    local enabled = _enabledCategoryKeys()
    if #enabled == 0 then
        _setStatus("Pilih category dulu — belum ada category aktif")
        return false, "Pilih category dulu — belum ada category aktif"
    end
    local hasSelection = false
    local emptyCats = {}
    for _, cat in ipairs(enabled) do
        if _isHarvestedFruitsCategory(cat) and _onceUsesPriceMode() then
            hasSelection = true
        elseif next(_categorySelected(cat)) then
            hasSelection = true
        else
            emptyCats[#emptyCats + 1] = cat
        end
    end
    if not hasSelection then
        local detail = (#emptyCats > 0) and (" (" .. table.concat(emptyCats, ", ") .. ")") or ""
        local msg = "Pilih item di list — belum ada item terpilih" .. detail
        _setStatus(msg)
        return false, msg
    end
    local candidates = _collectCandidates()
    if priceMode then
        local fruitCount = 0
        for _, item in ipairs(candidates) do
            if _isHarvestedFruitsCategory(item.Category) then
                fruitCount += 1
            end
        end
        local available = _sumCandidatePrice(candidates)
        if available < 1 then
            if fruitCount < 1 then
                local onlyHarvest = true
                for _, cat in ipairs(enabled) do
                    if not _isHarvestedFruitsCategory(cat) then
                        onlyHarvest = false
                        break
                    end
                end
                if onlyHarvest then
                    local msg = "Tidak ada Harvested Fruits di inventory — panen buah dulu"
                    _setStatus(msg)
                    return false, msg
                end
                local msg = "Tidak ada item giftable di inventory untuk category terpilih"
                _setStatus(msg)
                return false, msg
            end
            if not _getFruitSellValueModule() then
                local msg = "FruitSellValue belum load — re-execute hub / upload FruitSellValue.lua"
                _setStatus(msg)
                return false, msg
            end
            local msg = "Ada " .. tostring(fruitCount) .. " buah tapi total value 0 — cek FruitSellValue"
            _setStatus(msg)
            return false, msg
        end
        if available < target then
            local msg = "Value kurang: punya " .. _formatSellPrice(available)
                .. ", butuh " .. _formatSellPrice(target)
            _setStatus(msg)
            return false, msg
        end
        local minSum, maxSum = _priceRangeForRemain(target)
        local batchLimit = math.min(MAILBOX_UNIQUE_PER_SEND, _batchSendLimit(candidates, nil))
        local planPick, _, poolSize = _buildMultiBatchPricePlan(
            candidates,
            minSum,
            maxSum,
            batchLimit
        )
        if not planPick or #planPick == 0 then
            local msg = _pricePlanSummary(nil, 0, minSum, maxSum, poolSize or 0)
            _setStatus(msg)
            return false, msg
        end
    else
        local okAvail, errAvail = M.CheckSendTotalAvailability(M, target, false)
        if not okAvail then
            _setStatus(tostring(errAvail or "Item kurang"))
            return false, errAvail
        end
    end
    return true
end

function M.IsSendJobRunning(_self)
    return sendJobRunning == true
end

function M.GetSendCooldownRemain(_self)
    return _effectiveSendCooldownRemain()
end

function M.StopSendJob(_self)
    sendJobRunning = false
    if type(_flushSendJobHistory) == "function" then
        pcall(_flushSendJobHistory)
    end
end

function M.StopAutoSend(_self)
    autoSendRunning = false
end

function M.IsAutoSendRunning(_self)
    return autoSendRunning == true
end

function M.StartAutoSend(_self)
    if autoSendRunning then return false end
    autoSendRunning = true
    autoSendLoopId += 1
    local myId = autoSendLoopId
    task.spawn(function()
        task.wait(0.25)
        while autoSendRunning and autoSendLoopId == myId do
            if cfg.auto_send ~= true or _normalizeSendListMode(cfg.send_list_mode) ~= "loop" then
                task.wait(0.5)
                continue
            end
            if sendJobRunning then
                task.wait(0.2)
                continue
            end

            local ok, reason = M.SendOnceInternal()
            if ok then
                _waitForNextSend()
            elseif reason == "no_items" or reason == "empty_batch" then
                _setStatus(_loopWaitingStatusMessage(), nil, "loop")
                _waitNoItemsRetry()
            elseif reason == "cooldown" then
                _waitSendCooldown("loop")
            elseif reason == "no_recipient" then
                _setStatus("Auto send: set target username", nil, "loop")
                task.wait(2)
            elseif reason == "mailbox_disabled" or reason == "no_remote" then
                task.wait(2)
            else
                _waitNoItemsRetry()
            end
        end
    end)
    return true
end

function M.ApplyAutoSendRuntime(a, b)
    local on = _boolArg(a, b)
    cfg.auto_send = on
    M.StopAutoSend()
    if on and _normalizeSendListMode(cfg.send_list_mode) == "loop" then
        M.StartAutoSend()
        _setStatus("Auto send ON — looping selected list", nil, "loop")
    elseif not on then
        _setStatus("Auto send OFF", nil, "loop")
    end
    return on
end

do
local function sendJobLoop(myId)
    task.wait(0.05)
    local mode = _normalizeSendListMode(cfg.send_list_mode)

    if mode == "send_total" then
        local okValidate, validateErr = M.ValidateSendOnceJob(M)
        if not okValidate then
            _setStatus(tostring(validateErr or "Validasi gagal"))
            sendJobRunning = false
            M._notifySendJobDone(false)
            return
        end

        if _onceUsesPriceMode() then
            local target = _clampSendTotalGoal(cfg.send_total)
            cfg.send_total = target
            local targetMin, targetMax = _priceRangeForRemain(target)

            local sentPrice = 0
            local sentUnits = 0
            local batchNum = 0
            local noItemsRetries = 0

            local planCandidates = _collectCandidates()
            local batchLimitPlan = math.min(MAILBOX_UNIQUE_PER_SEND, _batchSendLimit(planCandidates, nil))
            local planPick, planTotal, _, planBatchCount = _buildMultiBatchPricePlan(
                planCandidates,
                targetMin,
                targetMax,
                batchLimitPlan
            )
            if planPick and #planPick > 0 then
                local batchNote = (type(planBatchCount) == "number" and planBatchCount > 1)
                    and (" / " .. tostring(planBatchCount) .. " batch")
                    or ""
                _setStatus(
                    "Mulai kirim: "
                        .. tostring(#planPick)
                        .. " buah "
                        .. _formatSellPrice(planTotal)
                        .. batchNote
                        .. " (target "
                        .. _formatSellPrice(targetMin)
                        .. "–"
                        .. _formatSellPrice(targetMax)
                        .. ")"
                )
            end

            while sendJobRunning and sendJobId == myId and sentPrice < targetMin do
                if _effectiveSendCooldownRemain() > 0 then
                    _waitSendCooldown()
                    if not sendJobRunning or sendJobId ~= myId then
                        if type(_flushSendJobHistory) == "function" then
                            pcall(_flushSendJobHistory)
                        end
                        return
                    end
                end

                local candidates = _collectCandidates()
                if #candidates == 0 then
                    noItemsRetries += 1
                    if noItemsRetries < 3 then
                        _waitNoItemsRetry()
                        continue
                    end
                    _setStatus("Tidak ada item dengan value yang bisa dikirim")
                    sendJobRunning = false
                    M._notifySendJobDone(false)
                    return
                end
                noItemsRetries = 0

                local remainMin = math.max(1, targetMin - sentPrice)
                local remainMax = math.max(remainMin, targetMax - sentPrice)
                local batchLimit = math.min(MAILBOX_UNIQUE_PER_SEND, _batchSendLimit(candidates, nil))
                local batch, batchPrice
                if type(_planPriceBatch) == "function" then
                    batch, batchPrice = _planPriceBatch(
                        candidates,
                        remainMin,
                        remainMax,
                        batchLimit
                    )
                end
                if not batch then
                    batch = {}
                    batchPrice = 0
                end
                batch = (type(_prepareHarvestBatch) == "function") and _prepareHarvestBatch(batch) or batch
                if #batch == 0 or batchPrice <= 0 then
                    local pool = _pricePoolFromCandidates(candidates)
                    local msg = _pricePlanSummary(nil, 0, remainMin, remainMax, #pool)
                    _setStatus(msg)
                    sendJobRunning = false
                    M._notifySendJobDone(false)
                    return
                end
                local batchUnits = #batch
                batchNum += 1
                _setStatus(
                    "Batch "
                        .. tostring(batchNum)
                        .. ": kirim "
                        .. tostring(batchUnits)
                        .. " buah ("
                        .. _formatSellPrice(batchPrice)
                        .. ")..."
                )

                local ok, reason = _fireSendBatch(batch, batchUnits, batchNum)
                if ok then
                    sentPrice += batchPrice
                    sentUnits += batchUnits
                    _setStatus(_formatPriceSendProgress(sentUnits, sentPrice, targetMin, targetMax, batchNum))
                    if sentPrice >= targetMin and sentPrice <= targetMax then
                        break
                    end
                    _waitForNextSend()
                elseif _isCooldownReason(reason, stats.lastStatus) then
                    _waitSendCooldown()
                    continue
                else
                    local errText = tostring(reason or stats.lastStatus or "Kirim gagal")
                    if errText == "" or errText == "send_error" then
                        errText = tostring(stats.lastStatus or "Kirim gagal (server/network)")
                    end
                    _setStatus("Kirim gagal: " .. errText)
                    sendJobRunning = false
                    M._notifySendJobDone(false, reason)
                    return
                end
            end

            if sentPrice >= targetMin and sentPrice <= targetMax then
                _setStatus(
                    "Selesai: "
                        .. tostring(sentUnits)
                        .. " buah | "
                        .. _formatSellPrice(sentPrice)
                        .. " (range "
                        .. _formatSellPrice(targetMin)
                        .. "–"
                        .. _formatSellPrice(targetMax)
                        .. ")"
                )
                sendJobRunning = false
                M._notifySendJobDone(true)
            else
                _setStatus(
                    "Berhenti: "
                        .. tostring(sentUnits)
                        .. " buah | "
                        .. _formatSellPrice(sentPrice)
                        .. " / target "
                        .. _formatSellPrice(targetMin)
                        .. "–"
                        .. _formatSellPrice(targetMax)
                )
                sendJobRunning = false
                M._notifySendJobDone(false)
            end
            return
        end

        local target = _onceSendUnitTarget()
        local sentUnits = 0
        local noItemsRetries = 0
        local sendBatchNum = 0
        while sendJobRunning and sendJobId == myId and sentUnits < target do
            if _effectiveSendCooldownRemain() > 0 then
                _waitSendCooldown()
                if not sendJobRunning or sendJobId ~= myId then
                    if type(_flushSendJobHistory) == "function" then
                        pcall(_flushSendJobHistory)
                    end
                    return
                end
            end

            M.InvalidateHarvestFruitCache()
            local candidates = _collectCandidates()
            if #candidates == 0 then
                noItemsRetries += 1
                if noItemsRetries < 3 then
                    _waitNoItemsRetry()
                    continue
                end
                _setStatus("Tidak ada item yang bisa dikirim")
                sendJobRunning = false
                M._notifySendJobDone(false)
                return
            end
            noItemsRetries = 0

            local remainUnits = target - sentUnits
            local batch, batchUnits = _buildBatch(
                candidates,
                _batchSendLimit(candidates, remainUnits),
                remainUnits
            )
            batch = _prepareHarvestBatch(batch)
            if #batch == 0 or batchUnits <= 0 then
                _setStatus("Batch kosong — tidak ada item yang bisa dikirim")
                sendJobRunning = false
                M._notifySendJobDone(false)
                return
            end

            sendBatchNum += 1
            local ok, reason = _fireSendBatch(batch, batchUnits, sendBatchNum)
            if ok then
                sentUnits += batchUnits
                _setStatus("Mengirim " .. tostring(sentUnits) .. "/" .. tostring(target))
                if sentUnits >= target then
                    break
                end
                _waitForNextSend()
            elseif _isCooldownReason(reason, stats.lastStatus) then
                _waitSendCooldown()
                continue
            else
                local errText = tostring(reason or stats.lastStatus or "Kirim gagal")
                if errText == "" or errText == "send_error" then
                    errText = tostring(stats.lastStatus or "Kirim gagal (server/network)")
                end
                _setStatus("Kirim gagal: " .. errText)
                sendJobRunning = false
                M._notifySendJobDone(false, reason)
                return
            end
        end

        if sentUnits >= target then
            _setStatus("Selesai: kirim " .. tostring(sentUnits) .. " item")
            sendJobRunning = false
            M._notifySendJobDone(true)
        else
            _setStatus("Berhenti: " .. tostring(sentUnits) .. "/" .. tostring(target))
            sendJobRunning = false
            M._notifySendJobDone(false)
        end
        return
    end

    while sendJobRunning and sendJobId == myId do
        local ok, reason = M.SendOnceInternal()
        if not ok then
            if reason == "no_items" or reason == "empty_batch" then
                _setStatus(_loopWaitingStatusMessage(), nil, "loop")
                _waitNoItemsRetry()
            elseif reason == "cooldown" then
                _waitSendCooldown("loop")
            elseif reason == "no_recipient" then
                _setStatus("Pilih target / lookup gagal")
                _waitForNextSend()
            elseif reason == "mailbox_disabled" then
                _setStatus("Mailbox disabled on server")
                _waitForNextSend()
            elseif reason == "no_remote" then
                _setStatus("SendBatch remote not ready")
                _waitForNextSend()
            else
                _log("loop skip:", reason)
                _waitNoItemsRetry()
            end
        else
            _waitForNextSend()
        end
    end
end

function M.StartSendJob(_self)
    if sendJobRunning then
        return false, "already_running"
    end
    if _normalizeSendListMode(cfg.send_list_mode) == "send_total" then
        local okValidate, validateErr = M.ValidateSendOnceJob(M)
        if not okValidate then
            _setStatus(tostring(validateErr or "Validasi gagal"))
            return false, validateErr
        end
    end
    sendJobRunning = true
    sendJobId += 1
    if type(_resetSendJobHistory) == "function" then
        _resetSendJobHistory()
    end
    local myId = sendJobId
    task.spawn(function()
        sendJobLoop(myId)
    end)
    return true
end
end

do
local function _collectInboxGiftIds()
    if not _mailboxUsable() then return {} end
    pcall(_refreshInboxFromServer)

    local ids = {}
    for giftId in pairs(inboxGifts) do
        local key = tostring(giftId)
        if key ~= "" then
            ids[#ids + 1] = key
        end
    end

    if #ids == 0 and _remoteCallable(MailboxList) then
        local ok, data = _callNetworkingRemote(MailboxList)
        if ok and type(data) == "table" then
            if type(data.Inbox) == "table" then
                _applyInboxData({ Mailbox = data.Inbox })
            else
                _applyInboxData(data)
            end
            for giftId in pairs(inboxGifts) do
                ids[#ids + 1] = tostring(giftId)
            end
        end
    end

    table.sort(ids)
    return ids
end

function M.ClaimOnce()
    if not cfg.auto_claim_mail then
        return false, "disabled"
    end
    if not _mailboxUsable() then
        _setStatus("Mailbox disabled — cannot claim")
        return false, "mailbox_disabled"
    end
    if not _ensureNetworking() or not _remoteCallable(MailboxClaim) then
        _setStatus("Mailbox.Claim remote not ready")
        return false, "no_remote"
    end

    local now = os.clock()
    if now - lastClaimAt < MIN_CLAIM_SEC then
        return false, "cooldown"
    end

    local giftIds = _collectInboxGiftIds()
    if #giftIds == 0 then
        return false, "no_gifts"
    end

    local claimed = 0
    for _, giftId in ipairs(giftIds) do
        if pendingClaims[giftId] then
            continue
        end
        pendingClaims[giftId] = true
        local ok, success, msg = _callNetworkingRemote(MailboxClaim, giftId)
        pendingClaims[giftId] = nil
        lastClaimAt = os.clock()

        if ok and success == true then
            claimed += 1
            stats.claimedGifts += 1
            inboxGifts[giftId] = nil
        elseif ok and success ~= true then
            _setStatus(tostring(msg ~= "" and msg or "Could not claim gift"))
        end
        if #giftIds > 1 then
            task.wait(0.08)
        end
    end

    if claimed > 0 then
        _setStatus("Claimed " .. tostring(claimed) .. " gift(s)")
        return true, claimed
    end
    return false, "claim_failed"
end

local function _claimLoop(myId)
    task.wait(0.25)
    while claimRunning and claimLoopId == myId do
        if cfg.auto_claim_mail then
            local ok, res = pcall(M.ClaimOnce)
            if not ok then
                _log("claim error:", res)
            elseif res == "no_gifts" then
                pcall(_refreshInboxFromServer)
            end
            task.wait(CLAIM_LOOP_SEC)
        else
            task.wait(0.5)
        end
    end
end

function M.DebugClaim(_self)
    pcall(_refreshInboxFromServer)
    local ids = _collectInboxGiftIds()
    local report = {
        auto_claim_mail = cfg.auto_claim_mail,
        claimRunning = claimRunning,
        mailboxUsable = _mailboxUsable(),
        claimRemote = _remoteCallable(MailboxClaim),
        inboxCount = #ids,
        giftIds = ids,
    }
    print("[GAG2-Gift] DebugClaim inbox=" .. tostring(#ids)
        .. " auto=" .. tostring(cfg.auto_claim_mail)
        .. " loop=" .. tostring(claimRunning))
    for i = 1, math.min(5, #ids) do
        print("  giftId:", ids[i])
    end
    return report
end

M.debugClaim = M.DebugClaim

function M.StartClaim()
    claimRunning = true
    claimLoopId += 1
    stats.claimRunning = true
    local myId = claimLoopId
    task.spawn(function()
        _claimLoop(myId)
    end)
end

function M.StopClaim()
    claimRunning = false
    stats.claimRunning = false
end
end

function M.ApplyConfig(a, b)
    local nextCfg = _configArg(a, b)
    if type(nextCfg) ~= "table" then return end
    if nextCfg.enabled ~= nil then cfg.enabled = (nextCfg.enabled == true) end
    if nextCfg.auto_send ~= nil then cfg.auto_send = (nextCfg.auto_send == true) end
    if nextCfg.auto_claim_mail ~= nil then cfg.auto_claim_mail = (nextCfg.auto_claim_mail == true) end
    if nextCfg.auto_accept_gift ~= nil then cfg.auto_accept_gift = (nextCfg.auto_accept_gift == true) end
    if nextCfg.suppress_fake_friend_request ~= nil then
        cfg.suppress_fake_friend_request = (nextCfg.suppress_fake_friend_request == true)
    end
    if nextCfg.recipient_username ~= nil then cfg.recipient_username = _cleanUsername(nextCfg.recipient_username) end
    if nextCfg.recipient_user_id ~= nil then cfg.recipient_user_id = tonumber(nextCfg.recipient_user_id) or 0 end
    if nextCfg.recipient_display ~= nil then cfg.recipient_display = tostring(nextCfg.recipient_display or "") end
    if nextCfg.skip_equipped ~= nil then cfg.skip_equipped = (nextCfg.skip_equipped == true) end
    if nextCfg.max_per_batch ~= nil then
        cfg.max_per_batch = _clampBatch(nextCfg.max_per_batch)
        if cfg.max_per_batch == 20 then
            cfg.max_per_batch = MAX_BATCH
        end
    end
    if nextCfg.note ~= nil then cfg.note = tostring(nextCfg.note or "") end
    if nextCfg.delay_sec ~= nil then cfg.delay_sec = _clampDelay(nextCfg.delay_sec) end
    if nextCfg.category_mode ~= nil then cfg.category_mode = _normalizeCategoryMode(nextCfg.category_mode) end
    if nextCfg.send_list_mode ~= nil then cfg.send_list_mode = _normalizeSendListMode(nextCfg.send_list_mode) end
    if nextCfg.send_total ~= nil then cfg.send_total = _normalizeSendTotalInput(nextCfg.send_total) end
    if nextCfg.after_send_mode ~= nil then cfg.after_send_mode = _normalizeAfterSendMode(nextCfg.after_send_mode) end
    if nextCfg.harvest_price_threshold_pct ~= nil then
        local pct = math.floor(tonumber(nextCfg.harvest_price_threshold_pct) or 10)
        if pct < 0 then pct = 0 end
        if pct > 100 then pct = 100 end
        cfg.harvest_price_threshold_pct = pct
    end
    if nextCfg.harvest_price_calc_mode ~= nil then
        cfg.harvest_price_calc_mode = _normalizeHarvestPriceCalcMode(nextCfg.harvest_price_calc_mode)
    end
    if nextCfg.once_send_mode ~= nil then
        cfg.once_send_mode = _normalizeOnceSendMode(nextCfg.once_send_mode)
    end

    if type(nextCfg.categories) == "table" then
        cfg.categories = {}
        for _, def in ipairs(CATEGORY_DEFS) do
            local key = def.key
            local legacy = nil
            for old, new in pairs(SAVE_CATEGORY_ALIASES) do
                if new == key then legacy = old break end
            end
            local on = (nextCfg.categories[key] == true)
            if not on and legacy and nextCfg.categories[legacy] == true then
                on = true
            end
            cfg.categories[key] = on
        end
    end
    if type(nextCfg.selected) == "table" then
        cfg.selected = type(cfg.selected) == "table" and cfg.selected or {}
        for _, def in ipairs(CATEGORY_DEFS) do
            local key = def.key
            local src = nextCfg.selected[key]
            if src == nil then
                for old, new in pairs(SAVE_CATEGORY_ALIASES) do
                    if new == key and nextCfg.selected[old] ~= nil then
                        src = nextCfg.selected[old]
                        break
                    end
                end
            end
            cfg.selected[key] = _normalizeSet(src)
        end
        for key, src in pairs(nextCfg.selected) do
            if type(key) == "string" and cfg.selected[key] == nil then
                cfg.selected[key] = _normalizeSet(src)
            end
        end
    end
    if type(nextCfg.send_totals) == "table" then
        cfg.send_totals = cfg.send_totals or {}
        for _, def in ipairs(CATEGORY_DEFS) do
            if nextCfg.send_totals[def.key] ~= nil then
                cfg.send_totals[def.key] = _clampSendTotalGoal(nextCfg.send_totals[def.key])
            end
        end
    end
    _ensureCfgCategoryTables()
    if cfg.auto_send == true and _normalizeSendListMode(cfg.send_list_mode) == "loop" then
        if not autoSendRunning then
            M.StartAutoSend()
        end
    elseif autoSendRunning then
        M.StopAutoSend()
    end
end

function M.GetConfig(_self)
    local categories = {}
    local selected = {}
    for _, def in ipairs(CATEGORY_DEFS) do
        categories[def.key] = (cfg.categories[def.key] == true)
        selected[def.key] = _normalizeSet(cfg.selected[def.key])
    end
    return {
        enabled = cfg.enabled,
        auto_send = cfg.auto_send,
        auto_claim_mail = cfg.auto_claim_mail,
        auto_accept_gift = cfg.auto_accept_gift,
        recipient_username = cfg.recipient_username,
        recipient_user_id = cfg.recipient_user_id,
        recipient_display = cfg.recipient_display,
        categories = categories,
        selected = selected,
        skip_equipped = cfg.skip_equipped,
        max_per_batch = cfg.max_per_batch,
        note = cfg.note,
        delay_sec = cfg.delay_sec,
        send_totals = type(cfg.send_totals) == "table" and cfg.send_totals or {},
        category_mode = cfg.category_mode,
        send_list_mode = cfg.send_list_mode,
        send_total = cfg.send_total,
        after_send_mode = cfg.after_send_mode,
    }
end

function M.GetCategoryDefs(_self)
    return CATEGORY_DEFS
end

function M.GetCategoryKeys(_self)
    local keys = {}
    for _, def in ipairs(CATEGORY_DEFS) do
        keys[#keys + 1] = def.key
    end
    return keys
end

function M.GetStats(_self)
    local inboxN = 0
    for _ in pairs(inboxGifts) do inboxN += 1 end
    return {
        lastStatus = stats.lastStatus,
        lastStatusOnce = stats.lastStatusOnce,
        lastStatusLoop = stats.lastStatusLoop,
        lastError = stats.lastError,
        lastSendError = stats.lastSendError,
        sentBatches = stats.sentBatches,
        sentItems = stats.sentItems,
        lastSendAt = stats.lastSendAt,
        claimedGifts = stats.claimedGifts,
        running = running,
        claimRunning = claimRunning,
        inboxGifts = inboxN,
        autoClaimMail = cfg.auto_claim_mail,
        autoAcceptGift = cfg.auto_accept_gift,
        acceptedNormalGifts = stats.acceptedNormalGifts or 0,
        sendCooldownRemain = _effectiveSendCooldownRemain(),
    }
end

function M.SetDebug(on)
    debugOn = (on == true)
    G.AUTO_GIFT_DEBUG = debugOn
    _G.AUTO_GIFT_DEBUG = debugOn
    if debugOn then
        print("[GAG2-Gift] Debug ON — log kirim & error")
    end
    return debugOn
end

M.setDebug = M.SetDebug

function M.DebugWhyNot(_self)
    local report = {
        ok = true,
        reasons = {},
        sendable = 0,
        enabledCategories = _enabledCategoryKeys(),
        recipient_user_id = cfg.recipient_user_id,
        recipient_username = cfg.recipient_username,
        catalogLoaded = catalogLoadedFromGame,
        categoryCount = #CATEGORY_DEFS,
        mailboxUsable = _mailboxUsable(),
        networkingReady = _ensureNetworking() and MailboxSendBatch ~= nil,
        sendJobRunning = sendJobRunning,
        lastStatus = stats.lastStatus,
    }

    local function fail(code, msg)
        report.ok = false
        report.reasons[#report.reasons + 1] = code
        if msg then report.reasons[#report.reasons] = code .. ": " .. msg end
    end

    if not catalogLoadedFromGame or #CATEGORY_DEFS == 0 then
        fail("catalog_not_loaded", "ReloadCatalog / re-execute hub")
    end
    if cfg.recipient_user_id <= 0 then
        fail("no_recipient", cfg.recipient_username ~= "" and cfg.recipient_username or "pilih Target")
    end
    if not report.mailboxUsable then
        fail("mailbox_disabled", "MailboxFlags.OpenEnabled = false")
    end
    if not report.networkingReady then
        fail("no_send_remote", "Networking.Mailbox.SendBatch")
    end
    if #report.enabledCategories == 0 then
        fail("no_category", "Category dropdown — pilih Seeds/Fruits/etc")
    end

    report.sendable = M.CountSendableUnits(M)
    if report.sendable <= 0 then
        local cat = report.enabledCategories[1] or ""
        fail("no_sendable_items", cat .. " kosong atau filter item terlalu ketat")
    end

    local lines = { "========== Auto Gift DebugWhyNot ==========" }
    lines[#lines + 1] = "ok: " .. tostring(report.ok)
    lines[#lines + 1] = "sendable: " .. tostring(report.sendable)
    lines[#lines + 1] = "target: " .. tostring(cfg.recipient_display)
        .. " @" .. tostring(cfg.recipient_username) .. " uid=" .. tostring(cfg.recipient_user_id)
    lines[#lines + 1] = "categories: " .. table.concat(report.enabledCategories, ", ")
    lines[#lines + 1] = "catalog: " .. tostring(report.catalogLoaded) .. " defs=" .. tostring(report.categoryCount)
    lines[#lines + 1] = "mailbox: " .. tostring(report.mailboxUsable) .. " remote: " .. tostring(report.networkingReady)
    lines[#lines + 1] = "sendJob: " .. tostring(report.sendJobRunning) .. " status: " .. tostring(report.lastStatus)
    if #report.reasons > 0 then
        lines[#lines + 1] = "reasons:"
        for _, r in ipairs(report.reasons) do
            lines[#lines + 1] = "  - " .. r
        end
    end
    lines[#lines + 1] = "==========================================="
    local out = table.concat(lines, "\n")
    print(out)
    return report
end

M.debugWhyNot = M.DebugWhyNot

function M.PrintDiagnostics()
    local store = G.__GAG2_AUTO_GIFT or _G.__GAG2_AUTO_GIFT
    local mainGift = nil
    if type(G.MAIN) == "table" and type(G.MAIN.auto) == "table" then
        mainGift = G.MAIN.auto.gift
    end

    print("========== GAG2 Auto Gift ==========")
    print("target:", cfg.recipient_display, "(@" .. cfg.recipient_username .. ")", "uid:", cfg.recipient_user_id)
    print("inventory path:", M.GetPlayerStatePath())
    print("status:", stats.lastStatus, "| sent batches:", stats.sentBatches, "| sent items:", stats.sentItems)

    if type(store) == "table" then
        print("-- store __GAG2_AUTO_GIFT --")
        print("  enabled:", store.enabled, "| auto_send:", store.auto_send)
        print("  target:", store.recipient_username, "uid:", store.recipient_user_id)
        if type(store.categories) == "table" then
            for _, def in ipairs(CATEGORY_DEFS) do
                print("  cat " .. def.key .. ":", store.categories[def.key])
            end
        end
        if type(store.selected) == "table" then
            for _, def in ipairs(CATEGORY_DEFS) do
                local sel = store.selected[def.key]
                local n = 0
                if type(sel) == "table" then
                    for _, v in pairs(sel) do
                        if v == true then n += 1 end
                    end
                end
                print("  sel " .. def.key .. ":", n)
            end
        end
        if type(store.send_totals) == "table" then
            for _, def in ipairs(CATEGORY_DEFS) do
                print("  send total " .. def.key .. ":", store.send_totals[def.key])
            end
        end
    else
        print("store: MISSING")
    end

    if type(mainGift) == "table" then
        print("-- MAIN.auto.gift --")
        print("  enabled:", mainGift.enabled, "| auto_send:", mainGift.auto_send)
        print("  target:", mainGift.recipient_username, "uid:", mainGift.recipient_user_id)
    else
        print("MAIN.auto.gift: MISSING")
    end

    if cfg.recipient_user_id <= 0 then
        print("hint: Select a target first (Target dropdown)")
    end
    print("auto claim mail:", cfg.auto_claim_mail, "| claimed gifts:", stats.claimedGifts)
    print("sendable units:", M.CountSendableUnits(M), "| send job:", sendJobRunning)
    print("enabled categories:", table.concat(_enabledCategoryKeys(), ", "))
    print("hint: SetDebug(true) | DebugWhyNot() | DebugCategory(ag, \"Seeds\")")

    local inv = _getInventory()
    if inv then
        for _, def in ipairs(CATEGORY_DEFS) do
            local cat = def.key
            local bag = _getInventoryBag(inv, cat)
            local n = 0
            if type(bag) == "table" then
                if _isCountBasedCategory(cat, inv) then
                    for itemKey, count in pairs(bag) do
                        if type(count) == "table" then
                            count = _entryCount(count) or 0
                        else
                            count = tonumber(count) or 0
                        end
                        if _isGiftableEntry(cat, itemKey, count) then
                            n += 1
                        end
                    end
                else
                    for itemKey, entry in pairs(bag) do
                        if _isGiftableEntry(cat, itemKey, entry) then
                            n += 1
                        end
                    end
                end
            end
            print("inventory giftable " .. cat .. ":", n)
        end
    else
        print("inventory: MISSING (PlayerStateClient not ready)")
    end
end

M.printDiagnostics = M.PrintDiagnostics

function M.ApplyClaimRuntime(a, b)
    local on = _boolArg(a, b)
    cfg.auto_claim_mail = on
    M.StopClaim()
    if on then
        M.StartClaim()
        _setStatus("Auto claim mail ON")
    else
        _setStatus("Auto claim mail OFF")
    end
    return on
end

function M.StopAcceptGift()
    if acceptGiftConn then
        pcall(function() acceptGiftConn:Disconnect() end)
        acceptGiftConn = nil
    end
end

function M.StopFakeFriendSuppress()
    if fakeFriendConn then
        pcall(function() fakeFriendConn:Disconnect() end)
        fakeFriendConn = nil
    end
    if friendRequestUiConn then
        pcall(function() friendRequestUiConn:Disconnect() end)
        friendRequestUiConn = nil
    end
end

function M.StartFakeFriendSuppress()
    M.StopFakeFriendSuppress()
    if cfg.suppress_fake_friend_request == false then return false end
    if _bindFakeFriendSuppress() then
        return true
    end
    task.spawn(function()
        for _ = 1, 30 do
            if cfg.suppress_fake_friend_request == false then return end
            if _bindFakeFriendSuppress() then return end
            task.wait(1)
        end
    end)
    return false
end

function M.ApplyFakeFriendSuppressRuntime(a, b)
    local on = _boolArg(a, b)
    cfg.suppress_fake_friend_request = on
    M.StopFakeFriendSuppress()
    if on then
        M.StartFakeFriendSuppress()
    end
    return on
end

function M.StartAcceptGift()
    M.StopAcceptGift()
    if _bindNormalGiftAccept() then
        return true
    end
    task.spawn(function()
        for _ = 1, 30 do
            if cfg.auto_accept_gift ~= true then return end
            if _bindNormalGiftAccept() then return end
            task.wait(1)
        end
        if cfg.auto_accept_gift == true then
            _setStatus("Gifting remote not ready")
        end
    end)
    return false
end

function M.ApplyAcceptGiftRuntime(a, b)
    local on = _boolArg(a, b)
    cfg.auto_accept_gift = on
    M.StopAcceptGift()
    if on then
        M.StartAcceptGift()
        if _ensureGiftingNetworking() then
            _setStatus("Auto accept normal gift ON")
        else
            _setStatus("Auto accept ON — waiting for gifting remote")
        end
    else
        _setStatus("Auto accept normal gift OFF")
    end
    return on
end

function M.Start()
    running = false
end

function M.Stop()
    running = false
    M.StopAutoSend()
    M.StopSendJob()
    M.StopAcceptGift()
    M.StopFakeFriendSuppress()
end

function M.ApplyRuntime(_on)
    M.StopSendJob()
    return false
end

function M.SyncFromGlobals()
    local syncFn = G.__GAG2_SYNC_AUTO_GIFT or rawget(_G, "__GAG2_SYNC_AUTO_GIFT")
    if type(syncFn) == "function" then
        pcall(syncFn)
    else
        local store = G.__GAG2_AUTO_GIFT or _G.__GAG2_AUTO_GIFT
        local fromStore = G.__GAG2_GIFT_CONFIG_FROM_STORE or rawget(_G, "__GAG2_GIFT_CONFIG_FROM_STORE")
        if type(fromStore) == "function" and type(store) == "table" then
            local profile = (store.auto_send == true) and "loop" or "once"
            local ok, cfgOut = pcall(fromStore, store, profile)
            if ok and type(cfgOut) == "table" then
                M.ApplyConfig(cfgOut)
            end
        end
    end
    M.StopSendJob()
    M.ApplyClaimRuntime(cfg.auto_claim_mail == true)
    M.ApplyAcceptGiftRuntime(cfg.auto_accept_gift == true)
    M.ApplyFakeFriendSuppressRuntime(cfg.suppress_fake_friend_request ~= false)
    if cfg.auto_send == true and _normalizeSendListMode(cfg.send_list_mode) == "loop" then
        M.ApplyAutoSendRuntime(true)
    else
        M.StopAutoSend()
    end
end

function M.EnsureRunning()
end

do
local function _trackEquippedPets()
    if not _ensureNetworking() or not Networking.Pets then return end
    for _, conn in ipairs(petEquipConn) do
        pcall(function() conn:Disconnect() end)
    end
    table.clear(petEquipConn)
    table.clear(equippedPets)

    local function mark(id, on)
        id = tostring(id or "")
        if id ~= "" then
            if on then equippedPets[id] = true else equippedPets[id] = nil end
        end
    end

    if Networking.Pets.PetEquipped and Networking.Pets.PetEquipped.OnClientEvent then
        petEquipConn[#petEquipConn + 1] = Networking.Pets.PetEquipped.OnClientEvent:Connect(function(id)
            mark(id, true)
        end)
    end
    if Networking.Pets.PetUnequipped and Networking.Pets.PetUnequipped.OnClientEvent then
        petEquipConn[#petEquipConn + 1] = Networking.Pets.PetUnequipped.OnClientEvent:Connect(function(id)
            mark(id, false)
        end)
    end
    if Networking.Pets.GetEquippedPets then
        task.spawn(function()
            local ok, list = pcall(function()
                return Networking.Pets.GetEquippedPets:Fire()
            end)
            if ok and type(list) == "table" then
                for _, pet in ipairs(list) do
                    if type(pet) == "table" then
                        mark(pet.Id or pet.UUID or pet.PetId, true)
                    elseif pet ~= nil then
                        mark(pet, true)
                    end
                end
            end
        end)
    end
end

task.defer(function()
    for _ = 1, 12 do
        M.ReloadCatalog(true)
        if catalogLoadedFromGame and #CATEGORY_DEFS > 0 then break end
        task.wait(0.25)
    end
    _ensureNetworking()
    _trackEquippedPets()
    _trackMailboxInbox()
    if catalogLoadedFromGame and #CATEGORY_DEFS > 0 then
        _setStatus("Ready")
    elseif catalogLoadedFromGame then
        _setStatus("Mailbox categories empty")
    else
        _setStatus("MailboxItemCatalog not loaded")
    end
end)
end

G.AutoGift = M
G.AutoGiftModule = M
_G.AutoGift = M
_G.AutoGiftModule = M

return M
 end,                       required = false },
    { key = "NormalGift",              name = "Normal Gift",             factory = function() -- NormalGift.lua — Grow A Garden 2
-- Nearby player gifts via Networking.Gifting.Send (not mailbox).

local Players           = game:GetService("Players")
local ReplicatedStorage = game:GetService("ReplicatedStorage")

local LP = Players.LocalPlayer
local G  = (getgenv and getgenv()) or _G
local M  = {}

local MAX_SEND_DISTANCE = 5000
local SEND_GAP_SEC         = 35
local SEND_VERIFY_WAIT_SEC = 0.5
local SEND_FAV_REJECT_SEC  = 2.5
local SEND_UUID_MAX_TRIES = 6
local TP_STAND_DIST     = 6
local TP_Y_OFFSET       = 3
local AFTER_TP_SEC      = 0.1

local GIFT_ATTR_MAP = nil
local GIFT_ATTR_ORDER = nil

local Networking = nil
local GiftingSend = nil
local BackpackGetLayout = nil
local sendBusy = false
local sendJobCancel = false
local sendJobHistoryAcc = nil
local sendJobFavCache = nil

local virtualFruitCache = nil
local virtualFruitCacheAt = 0
local VIRTUAL_FRUIT_CACHE_SEC = 15

local sendCandidatesCache = nil
local sendCandidatesCacheAt = 0
local SEND_CANDIDATES_CACHE_SEC = 12

local harvestPriceByUuid = {}
local sendJobFsvPrimed = false
local toolByUuidCache = nil


local uiItemsCache = {}
local uiItemsCacheAt = {}
local UI_ITEMS_CACHE_SEC = 6
local HARVEST_UI_ITEMS_CACHE_SEC = 20

local cfg = {
    target_user_id  = 0,
    target_name     = "",
    category        = "Seeds",
    selected        = {},
    selectedByCat   = {},
    send_total      = 1,
    send_mode       = "total",
    harvest_price_threshold_pct = 10,
    harvest_price_calc_mode = "base",
    teleport_to_target = true,
}

local stats = {
    lastStatus = "Ready",
    lastError  = nil,
    sentCount  = 0,
}

local H = {}

function H._setStatus(msg, err)
    stats.lastStatus = tostring(msg or "")
    stats.lastError = err
    G.NORMAL_GIFT_STATUS = stats.lastStatus
    _G.NORMAL_GIFT_STATUS = stats.lastStatus
end

function H._normalizeSet(src)
    if type(src) ~= "table" then return {} end
    local out = {}
    for i = 1, #src do
        local v = src[i]
        if v ~= nil and tostring(v) ~= "" then out[tostring(v)] = true end
    end
    if next(out) then return out end
    for k, v in pairs(src) do
        if v == true or v == 1 or v == "true" then out[tostring(k)] = true end
    end
    return out
end

function H._canonicalCategory(cat)
    cat = tostring(cat or "")
    local norm = cat:lower():gsub("[%s_]+", "")
    if norm == "harvestedfruit" or norm == "harvestedfruits" or norm == "harvestedfruid" then
        return "HarvestedFruits"
    end
    return cat
end

function H._isHarvestedFruitsCategory(cat)
    return H._canonicalCategory(cat) == "HarvestedFruits"
end

function H._harvestUiKey(uuid)
    uuid = tostring(uuid or "")
    if uuid == "" then return "" end
    return "hf_" .. uuid:gsub("[^%w]", "")
end

function H._registerHarvestKeyMap(uiKey, uuid)
    uiKey = tostring(uiKey or "")
    uuid = tostring(uuid or "")
    if uiKey == "" or uuid == "" then return uiKey end
    local map = G.__GAG2_NORMAL_GIFT_HF_KEYS or {}
    map[uiKey] = uuid
    map[uuid] = uuid
    G.__GAG2_NORMAL_GIFT_HF_KEYS = map
    _G.__GAG2_NORMAL_GIFT_HF_KEYS = map
    return uiKey
end

function H._resolveHarvestSelectionKey(key)
    key = tostring(key or "")
    if key == "" then return key end
    local map = G.__GAG2_NORMAL_GIFT_HF_KEYS or rawget(_G, "__GAG2_NORMAL_GIFT_HF_KEYS")
    if type(map) == "table" and map[key] then
        return tostring(map[key])
    end
    return key
end

function H._expandSelectedMapForHarvest(selectedMap)
    if type(selectedMap) ~= "table" then return selectedMap end
    local out = {}
    for k, v in pairs(selectedMap) do
        if v == true then
            out[k] = true
            local resolved = H._resolveHarvestSelectionKey(k)
            if resolved ~= "" and resolved ~= k then
                out[resolved] = true
            end
        end
    end
    return out
end

function H._normalizeFruitGroupKey(name)
    return tostring(name or ""):lower():gsub("[%s_%-%.'']+", "")
end

function H._normalizeSendMode(v)
    return (tostring(v or "total"):lower() == "price") and "price" or "total"
end

function H._normalizeHarvestPriceCalcMode(v)
    return (tostring(v or "base"):lower() == "stock") and "stock" or "base"
end

function H._usesPriceMode(catKey)
    catKey = H._canonicalCategory(catKey or cfg.category)
    return H._isHarvestedFruitsCategory(catKey) and H._normalizeSendMode(cfg.send_mode) == "price"
end

function H._harvestPriceThresholdPct()
    local pct = math.floor(tonumber(cfg.harvest_price_threshold_pct) or 10)
    if pct < 0 then pct = 0 end
    if pct > 100 then pct = 100 end
    return pct
end

function H._harvestPriceCalcMode()
    return H._normalizeHarvestPriceCalcMode(cfg.harvest_price_calc_mode)
end

function H._priceRangeForRemain(remain)
    remain = math.max(0, math.floor(tonumber(remain) or 0))
    if remain <= 0 then return 0, 0 end
    local pct = H._harvestPriceThresholdPct()
    local maxPrice = math.floor(remain * (1 + pct / 100) + 0.5)
    return remain, maxPrice
end

function H._parseSendTotalPrice(raw)
    local ag = G.AutoGiftModule or G.AutoGift or rawget(_G, "AutoGiftModule") or rawget(_G, "AutoGift")
    if type(ag) == "table" and type(ag.ParseSendTotalPrice) == "function" then
        local ok, n = pcall(ag.ParseSendTotalPrice, ag, raw)
        if ok and type(n) == "number" then return math.max(0, math.floor(n)) end
    end
    if type(raw) == "number" then return math.max(0, math.floor(raw)) end
    local txt = tostring(raw or ""):lower():gsub("%s+", "")
    if txt == "" then return 0 end
    local sign = 1
    if txt:sub(1, 1) == "-" then sign = -1 txt = txt:sub(2) end
    local suffixes = {
        { "juta", 1000000 }, { "jt", 1000000 },
        { "ribu", 1000 }, { "rb", 1000 },
        { "b", 1000000000 }, { "m", 1000000 }, { "k", 1000 },
    }
    for _, pair in ipairs(suffixes) do
        local suf, mult = pair[1], pair[2]
        if #txt > #suf and txt:sub(-#suf) == suf then
            local n = tonumber(txt:sub(1, -#suf - 1))
            if n then return math.max(0, math.floor(n * mult * sign)) end
        end
    end
    local n = tonumber(txt)
    if n then return math.max(0, math.floor(n * sign)) end
    return 0
end

function H._clampSendTotalGoal(n, priceMode)
    if priceMode == true then
        n = H._parseSendTotalPrice(n)
        if n < 1 then n = 1 end
        return n
    end
    n = math.floor(tonumber(n) or 1)
    if n < 1 then n = 1 end
    return n
end

function H._harvestGroupLabel(inst, info)
    if inst and type(inst.GetAttribute) == "function" then
        local fruitName = inst:GetAttribute("FruitName") or inst:GetAttribute("Fruit")
        if fruitName and tostring(fruitName) ~= "" then
            return tostring(fruitName):gsub("%s*%[.-%]", ""):gsub("%s+$", "")
        end
        local name = tostring(inst.Name or "Fruit"):gsub("%s*%[.-%]", ""):gsub("%s+$", "")
        return name
    end
    if info then
        if type(info.raw) == "table" then
            local rawName = info.raw.FruitName or info.raw.Fruit or info.raw.PlantName or info.raw.Name
            if rawName and tostring(rawName) ~= "" then
                return tostring(rawName):gsub("%s*%[.-%]", ""):gsub("%s+$", "")
            end
        end
        local k = tostring(info.name or info.key or "Fruit")
        return k:gsub("%s*%[.-%]", ""):gsub("%s+$", "")
    end
    return "Fruit"
end

function H._canonicalGiftType(giftType)
    if H._isHarvestedFruitsCategory(giftType) then
        return "HarvestedFruits"
    end
    return tostring(giftType or "")
end

local GIFT_ATTR_KNOWN = {
    Crate = "Crates",
    Gnome = "Gnomes",
    Mushroom = "Mushrooms",
    Sprinkler = "Sprinklers",
    WateringCan = "WateringCans",
    HarvestedFruit = "HarvestedFruits",
    SeedTool = "Seeds",
}

function H._mergeGiftAttrMap(map, order)
    map = type(map) == "table" and map or {}
    order = type(order) == "table" and order or {}
    local seen = {}
    for _, k in ipairs(order) do
        seen[k] = true
    end
    for attr, giftType in pairs(GIFT_ATTR_KNOWN) do
        if map[attr] == nil then
            map[attr] = giftType
            if not seen[attr] then
                order[#order + 1] = attr
                seen[attr] = true
            end
        end
    end
    table.sort(order)
    map.HarvestedFruit = GIFT_ATTR_KNOWN.HarvestedFruit or "HarvestedFruits"
    return map, order
end

function H._scoreGiftAttrMap(t)
    local n = 0
    local hasHF = false
    if type(t) ~= "table" then return 0, false end
    for k, v in pairs(t) do
        if type(k) == "string" and type(v) == "string" then
            n += 1
            if k == "HarvestedFruit" then hasHF = true end
        end
    end
    return n, hasHF
end

function H._tableLooksLikeGiftAttrMap(t)
    if type(t) ~= "table" then return false end
    local seedTool = rawget(t, "SeedTool")
    if type(seedTool) == "string" and seedTool == "Seeds" then
        return true
    end
    local crate = rawget(t, "Crate")
    if type(crate) == "string" and crate == "Crates" then
        return true
    end
    return false
end

function H._cloneGiftAttrMap(src)
    local map, order = {}, {}
    local ok = pcall(function()
        for k, v in pairs(src) do
            if type(k) == "string" and type(v) == "string" then
                map[k] = v
                order[#order + 1] = k
            end
        end
    end)
    if not ok or not next(map) then return nil, nil end
    table.sort(order)
    return map, order
end

function H._extractMapFromFunction(fn)
    if type(fn) ~= "function" or type(debug) ~= "table" or type(debug.getupvalue) ~= "function" then
        return nil
    end
    local best = nil
    local bestScore = 0
    for i = 1, 40 do
        local ok, _, val = pcall(debug.getupvalue, fn, i)
        if not ok or val == nil then break end
        if type(val) == "table" then
            local ok2, isMap = pcall(_tableLooksLikeGiftAttrMap, val)
            if ok2 and isMap then
                local n, hasHF = H._scoreGiftAttrMap(val)
                local score = n + (hasHF and 100 or 0)
                if score > bestScore then
                    best = val
                    bestScore = score
                end
            end
        end
    end
    return best
end

function H._waitForControllersStarted(maxSec)
    maxSec = tonumber(maxSec) or 15
    local deadline = os.clock() + maxSec
    while os.clock() < deadline do
        if LP:HasTag("ControllersStarted") then return true end
        task.wait(0.25)
    end
    return LP:HasTag("ControllersStarted")
end

function H._findGiftAttrMapInGc()
    if type(getgc) ~= "function" then return nil end
    local ok, objects = pcall(getgc, true)
    if not ok or type(objects) ~= "table" then return nil end
    local best = nil
    local bestScore = 0
    for _, obj in ipairs(objects) do
        if type(obj) == "table" then
            local ok2, isMap = pcall(_tableLooksLikeGiftAttrMap, obj)
            if ok2 and isMap then
                local n, hasHF = H._scoreGiftAttrMap(obj)
                local score = n + (hasHF and 100 or 0)
                if score > bestScore then
                    best = obj
                    bestScore = score
                end
            end
        end
    end
    return best
end

function H._getGiftingControllerScript()
    local ps = LP:FindFirstChild("PlayerScripts")
    if ps then
        local controllers = ps:FindFirstChild("Controllers")
        if controllers then
            local inst = controllers:FindFirstChild("GiftingController")
            if inst then return inst end
        end
    end
    local sps = game:GetService("StarterPlayer"):FindFirstChild("StarterPlayerScripts")
    if sps then
        local controllers = sps:FindFirstChild("Controllers")
        if controllers then
            return controllers:FindFirstChild("GiftingController")
        end
    end
    return nil
end

function H._extractGiftAttrMapFromController(maxWaitSec)
    if type(debug) ~= "table" or type(debug.getupvalue) ~= "function" then
        return nil
    end

    maxWaitSec = tonumber(maxWaitSec) or 0
    if maxWaitSec > 0 then
        H._waitForControllersStarted(maxWaitSec)
    elseif not LP:HasTag("ControllersStarted") then
        return nil
    end

    local inst = H._getGiftingControllerScript()
    if not inst then return nil end

    local ok, mod = pcall(require, inst)
    if not ok or type(mod) ~= "table" then return nil end

    local fromEquip = H._extractMapFromFunction(mod._updateEquippedTool)
    if fromEquip then return fromEquip end

    for _, fn in pairs(mod) do
        local found = H._extractMapFromFunction(fn)
        if found then return found end
    end

    return nil
end

function H._loadGiftAttrMapFromGame(maxWaitSec)
    local fromController = H._extractGiftAttrMapFromController(maxWaitSec)
    if fromController then return fromController end
    return H._findGiftAttrMapInGc()
end

function H._ensureGiftAttrMap(maxWaitSec)
    if GIFT_ATTR_MAP and next(GIFT_ATTR_MAP) then
        if not GIFT_ATTR_MAP.HarvestedFruit then
            GIFT_ATTR_MAP, GIFT_ATTR_ORDER = H._mergeGiftAttrMap(GIFT_ATTR_MAP, GIFT_ATTR_ORDER)
            G.__GAG2_GIFTING_ATTR_MAP = GIFT_ATTR_MAP
        end
        return GIFT_ATTR_MAP
    end

    local cached = G.__GAG2_GIFTING_ATTR_MAP
    if type(cached) == "table" then
        local ok, isMap = pcall(_tableLooksLikeGiftAttrMap, cached)
        if ok and isMap then
            local map, order = H._cloneGiftAttrMap(cached)
            if map then
                map, order = H._mergeGiftAttrMap(map, order)
                GIFT_ATTR_MAP, GIFT_ATTR_ORDER = map, order
                G.__GAG2_GIFTING_ATTR_MAP = GIFT_ATTR_MAP
                return GIFT_ATTR_MAP
            end
        end
    end

    local fromGame = H._loadGiftAttrMapFromGame(maxWaitSec)
    if fromGame then
        local map, order = H._cloneGiftAttrMap(fromGame)
        if map then
            map, order = H._mergeGiftAttrMap(map, order)
            GIFT_ATTR_MAP, GIFT_ATTR_ORDER = map, order
            G.__GAG2_GIFTING_ATTR_MAP = GIFT_ATTR_MAP
            return GIFT_ATTR_MAP
        end
    end

    local map, order = H._mergeGiftAttrMap({}, {})
    if next(map) then
        GIFT_ATTR_MAP, GIFT_ATTR_ORDER = map, order
        G.__GAG2_GIFTING_ATTR_MAP = GIFT_ATTR_MAP
        return GIFT_ATTR_MAP
    end

    return nil
end

function H._categoryDef(key)
    key = H._canonicalCategory(key)
    if key == "" then key = "Seeds" end
    return { key = key, giftType = key }
end

function H._remoteCallable(remote)
    if remote == nil then return false end
    if type(remote) == "table" then
        return type(remote.Fire) == "function" or type(remote.Invoke) == "function"
    end
    if typeof(remote) == "Instance" then
        return remote:IsA("RemoteFunction") or remote:IsA("RemoteEvent")
    end
    return false
end

function H._callNetworkingRemote(remote, ...)
    if not H._remoteCallable(remote) then return false, "no_remote" end
    local args = table.pack(...)
    local function invoke()
        if type(remote) == "table" then
            if type(remote.Fire) == "function" then
                if args.n > 0 then return remote:Fire(table.unpack(args, 1, args.n)) end
                return remote:Fire()
            end
            if type(remote.Invoke) == "function" then
                if args.n > 0 then return remote:Invoke(table.unpack(args, 1, args.n)) end
                return remote:Invoke()
            end
        elseif typeof(remote) == "Instance" then
            if remote:IsA("RemoteFunction") then
                if args.n > 0 then return remote:InvokeServer(table.unpack(args, 1, args.n)) end
                return remote:InvokeServer()
            end
            if remote:IsA("RemoteEvent") then
                if args.n > 0 then remote:FireServer(table.unpack(args, 1, args.n))
                else remote:FireServer() end
                return nil
            end
        end
        error("networking remote not callable")
    end
    local results = table.pack(pcall(invoke))
    if not results[1] then return false, results[2] end
    return true, results[2], results[3], results[4]
end

function H._ensureNetworking()
    if Networking and H._remoteCallable(GiftingSend) then return true end
    local ok, net = pcall(function()
        return require(ReplicatedStorage:WaitForChild("SharedModules"):WaitForChild("Networking"))
    end)
    if ok and type(net) == "table" then
        Networking = net
        if type(net.Gifting) == "table" then
            GiftingSend = net.Gifting.Send
        end
        if type(net.Backpack) == "table" then
            BackpackGetLayout = net.Backpack.GetLayout
        end
    end
    return H._remoteCallable(GiftingSend)
end

function H._ensureBackpackNetworking()
    if not H._ensureNetworking() then return false end
    return H._remoteCallable(BackpackGetLayout)
end

local FRUIT_ID_FIELDS = { "Id", "id", "UUID", "Uuid", "FruitId", "fruitId", "c" }
local FRUIT_NAME_FIELDS = { "FruitName", "Fruit", "Name", "name", "fruitName" }
local FRUIT_WEIGHT_FIELDS = { "Weight", "weight", "Kg", "kg" }
local FRUIT_MUTATION_FIELDS = { "Mutation", "mutation" }

function H._pickFruitField(entry, fields)
    if type(entry) ~= "table" then return nil end
    for _, f in ipairs(fields) do
        local v = entry[f]
        if v ~= nil and tostring(v) ~= "" then return v end
    end
    return nil
end

function H._isLikelyFruitInstanceId(id)
    id = tostring(id or "")
    if id == "" then return false end
    if id:find("%s") then return false end
    if #id < 8 then return false end
    if id:match("^[%a'%-]+$") and not id:match("[%d_]") then
        return false
    end
    return true
end

function H._getAutoGiftModule()
    return G.AutoGiftModule or G.AutoGift or rawget(_G, "AutoGiftModule") or rawget(_G, "AutoGift")
end

function H._looksLikeLayoutFruitEntry(entry)
    if type(entry) ~= "table" then return false end
    if entry.SeedTool ~= nil or entry.Pet ~= nil then return false end
    if entry.PottedPlant == true then return false end
    if tostring(entry.MainCategory or "") == "Seed" then return false end

    local id = H._pickFruitField(entry, FRUIT_ID_FIELDS)
    if type(id) == "string" and id ~= "" and #id >= 8 then return true end

    local name = H._pickFruitField(entry, FRUIT_NAME_FIELDS)
    if name ~= nil and tostring(name) ~= "" then return true end

    if entry.HarvestedFruit == true then return true end
    if entry.FruitProxy == true then return true end

    return false
end

function H._virtualFruitLabel(entry)
    local fruitName = tostring(H._pickFruitField(entry, FRUIT_NAME_FIELDS) or "Fruit")
    local weight = tonumber(H._pickFruitField(entry, FRUIT_WEIGHT_FIELDS))
    local name = fruitName
    if weight and weight > 0 then
        name = name .. string.format(" [%.2fkg]", weight)
    end
    local mutation = H._pickFruitField(entry, FRUIT_MUTATION_FIELDS)
    if mutation ~= nil and tostring(mutation) ~= "" then
        name = name .. " " .. tostring(mutation)
    end
    return name
end

function H._buildVirtualFruitInfo(entry)
    if not H._looksLikeLayoutFruitEntry(entry) then return nil end
    local uuid = tostring(H._pickFruitField(entry, FRUIT_ID_FIELDS) or "")
    if not H._isLikelyFruitInstanceId(uuid) then return nil end
    return {
        attr = "HarvestedFruit",
        key = H._virtualFruitLabel(entry),
        name = tostring(H._pickFruitField(entry, FRUIT_NAME_FIELDS) or "Fruit"),
        uuid = uuid,
        giftType = "HarvestedFruits",
        source = "layout",
        raw = entry,
    }
end

function H._collectLayoutFruitEntries(layout, out, depth, seen)
    if depth > 12 or type(layout) ~= "table" then return end
    if seen[layout] then return end
    seen[layout] = true

    if H._looksLikeLayoutFruitEntry(layout) then
        out[#out + 1] = layout
        return
    end

    for key, value in pairs(layout) do
        if type(value) == "table" then
            if H._looksLikeLayoutFruitEntry(value) then
                out[#out + 1] = value
            else
                H._collectLayoutFruitEntries(value, out, depth + 1, seen)
            end
        end
    end
end

function H._mergeFruitInfoLists(primary, secondary)
    local merged = {}
    local byId = {}
    for _, list in ipairs({ primary, secondary }) do
        for _, info in ipairs(list or {}) do
            local uuid = tostring(info.uuid or "")
            if uuid ~= "" and not byId[uuid] then
                byId[uuid] = true
                merged[#merged + 1] = info
            end
        end
    end
    table.sort(merged, function(a, b) return tostring(a.key) < tostring(b.key) end)
    return merged
end

function H._parseBackpackLayoutFruits(layout)
    if type(layout) ~= "table" then return {} end
    local raw = {}
    H._collectLayoutFruitEntries(layout, raw, 0, {})
    local fruits = {}
    local byId = {}
    for _, entry in ipairs(raw) do
        local info = H._buildVirtualFruitInfo(entry)
        if info and not byId[info.uuid] then
            byId[info.uuid] = true
            fruits[#fruits + 1] = info
        end
    end
    table.sort(fruits, function(a, b) return a.key < b.key end)
    return fruits
end

function H._formatCount(n)
    n = tonumber(n) or 0
    if n >= 1000000 then return string.format("%.1fM", n / 1000000) end
    if n >= 1000 then return string.format("%.1fk", n / 1000) end
    return tostring(math.floor(n))
end

function H._getFruitSellValue()
    local fsv = G.FruitSellValue or rawget(_G, "FruitSellValue")
    if type(fsv) == "table" and type(fsv.fromFruit) == "function" then
        return fsv
    end
    return nil
end

function H._formatSellPrice(n)
    n = tonumber(n) or 0
    if n <= 0 then return "" end
    if n >= 1000000 then return string.format("%.2fM", n / 1000000) end
    if n >= 1000 then return string.format("%.1fk", n / 1000) end
    return tostring(math.floor(n))
end

function H._harvestSellPrice(inst)
    if not inst then return 0 end
    local fsv = H._getFruitSellValue()
    if not fsv then return 0 end
    local ok, price = pcall(fsv.fromFruit, inst, LP)
    if ok and type(price) == "number" then return price end
    return 0
end

function H._toolStackCount(tool)
    if not tool then return 1 end
    local n = tonumber(tool:GetAttribute("Count") or tool:GetAttribute("Amount")
        or tool:GetAttribute("Stack") or tool:GetAttribute("Qty"))
    if n and n > 0 then return math.floor(n) end
    return 1
end

function H._iterInventoryContainers()
    local out = {}
    local seen = {}

    local function add(c)
        if c and not seen[c] then
            seen[c] = true
            out[#out + 1] = c
        end
    end

    local bp = LP:FindFirstChild("Backpack") or LP:FindFirstChildOfClass("Backpack")
    if not bp then
        pcall(function() bp = LP:WaitForChild("Backpack", 2) end)
    end
    add(bp)
    add(LP.Character)

    for _, ch in ipairs(LP:GetChildren()) do
        if ch:IsA("Folder") or ch:IsA("Model") or ch:IsA("Backpack") then
            local n = ch.Name:lower()
            if n:find("backpack") or n:find("ransel") or n:find("tas") or n:find("inventory") then
                add(ch)
            elseif ch ~= bp and ch ~= LP.Character
                and ch.Name ~= "PlayerScripts" and ch.Name ~= "PlayerGui" then
                add(ch)
            end
        end
    end

    return out
end

function H._giftInstanceCanonical(inst)
    if not inst then return nil end
    local cur = inst
    while cur and cur ~= game do
        if cur:IsA("Tool") then return cur end
        if cur == LP then break end
        cur = cur.Parent
    end
    return inst
end

function H._instFruitUuid(inst)
    if not inst or type(inst.GetAttribute) ~= "function" then return "" end
    return tostring(inst:GetAttribute("Id") or inst:GetAttribute("id")
        or inst:GetAttribute("UUID") or inst:GetAttribute("Uuid")
        or inst:GetAttribute("FruitId") or inst:GetAttribute("fruitId")
        or inst:GetAttribute("c") or "")
end

function H._instLooksLikeHarvestedFruit(inst)
    if not inst or type(inst.GetAttribute) ~= "function" then return false end
    if inst:GetAttribute("SeedTool") ~= nil then return false end
    if inst:GetAttribute("Pet") ~= nil then return false end
    if inst:GetAttribute("PottedPlant") == true then return false end
    if tostring(inst:GetAttribute("MainCategory") or "") == "Seed" then return false end

    local fruitName = inst:GetAttribute("FruitName") or inst:GetAttribute("Fruit")
    if fruitName ~= nil and tostring(fruitName) ~= "" then
        return true
    end

    if inst:GetAttribute("FruitProxy") == true then return true end

    local hf = inst:GetAttribute("HarvestedFruit")
    if hf == true then return true end
    if type(hf) == "string" and hf ~= "" then return true end

    if inst:GetAttribute("Id") and (inst:GetAttribute("Weight") or inst:GetAttribute("SizeMultiplier")) then
        return true
    end

    return false
end

function H._foreachGiftInstance(callback)
    if type(callback) ~= "function" then return end
    local seen = {}
    local function visit(inst)
        if not inst or seen[inst] then return end
        local canonical = H._giftInstanceCanonical(inst)
        if canonical ~= inst then return end
        if inst:IsA("Tool") or H._instLooksLikeHarvestedFruit(inst) then
            seen[inst] = true
            callback(inst)
        end
    end
    for _, container in ipairs(H._iterInventoryContainers()) do
        visit(container)
        for _, inst in ipairs(container:GetDescendants()) do
            visit(inst)
        end
    end
end

function H._getVirtualFruits(forceRefresh, allowRemote)
    allowRemote = (allowRemote ~= false)
    local now = os.clock()
    if not forceRefresh and virtualFruitCache and (now - virtualFruitCacheAt) < VIRTUAL_FRUIT_CACHE_SEC then
        return virtualFruitCache
    end

    local layoutFruits = {}
    local cachedLayout = G.__GAG2_NORMAL_GIFT_BACKPACK_LAYOUT or rawget(_G, "__GAG2_NORMAL_GIFT_BACKPACK_LAYOUT")
    if type(cachedLayout) == "table" then
        layoutFruits = H._parseBackpackLayoutFruits(cachedLayout)
    end

    if allowRemote and (#layoutFruits == 0 or forceRefresh) and H._ensureBackpackNetworking() then
        local ok, layout = H._callNetworkingRemote(BackpackGetLayout)
        if ok and type(layout) == "table" then
            G.__GAG2_NORMAL_GIFT_BACKPACK_LAYOUT = layout
            _G.__GAG2_NORMAL_GIFT_BACKPACK_LAYOUT = layout
            layoutFruits = H._parseBackpackLayoutFruits(layout)
        end
    end

    if #layoutFruits > 0 then
        virtualFruitCache = layoutFruits
    else
        virtualFruitCache = H._mergeFruitInfoLists(layoutFruits, H._collectInstanceFruitInfos())
    end
    virtualFruitCacheAt = now
    return virtualFruitCache
end

function H._hasHarvestGiftSources()
    local cachedLayout = G.__GAG2_NORMAL_GIFT_BACKPACK_LAYOUT or rawget(_G, "__GAG2_NORMAL_GIFT_BACKPACK_LAYOUT")
    if type(cachedLayout) == "table" and #H._parseBackpackLayoutFruits(cachedLayout) > 0 then
        return true
    end
    if virtualFruitCache and #virtualFruitCache > 0 then return true end
    if #H._collectInstanceFruitInfos() > 0 then return true end
    local virtual = H._getVirtualFruits(false, false)
    return type(virtual) == "table" and #virtual > 0
end

function H._invalidateUiItemsCache(catKey)
    if catKey ~= nil and catKey ~= "" then
        catKey = H._canonicalCategory(tostring(catKey))
        uiItemsCache[catKey] = nil
        uiItemsCacheAt[catKey] = nil
        return
    end
    uiItemsCache = {}
    uiItemsCacheAt = {}
end

function H._invalidateVirtualFruitCache()
    virtualFruitCache = nil
    virtualFruitCacheAt = 0
    H._invalidateUiItemsCache()
end

function H._invalidateSendCandidatesCache()
    sendCandidatesCache = nil
    sendCandidatesCacheAt = 0
end

function H._invalidateHarvestCaches()
    harvestPriceByUuid = {}
    sendJobFsvPrimed = false
    toolByUuidCache = nil
    H._invalidateVirtualFruitCache()
    H._invalidateSendCandidatesCache()
    local ag = H._getAutoGiftModule()
    if type(ag) == "table" and type(ag.InvalidateHarvestFruitCache) == "function" then
        pcall(ag.InvalidateHarvestFruitCache, ag)
    end
end

local harvestPrefetchBusy = false

function H._refreshNormalGiftItemDropdown()
    local dd = G.__GAG2_NORMAL_GIFT_ITEM_DD or rawget(_G, "__GAG2_NORMAL_GIFT_ITEM_DD")
    if type(dd) == "table" and type(dd.refreshItems) == "function" then
        pcall(dd.refreshItems, dd)
    end
end

function H._foreachGiftTool(callback)
    H._foreachGiftInstance(function(inst)
        if inst:IsA("Tool") then callback(inst) end
    end)
end

function H._attrMatchesGift(attr, attrVal)
    if attrVal == nil then return false end
    if attr == "HarvestedFruit" then
        if attrVal == true then return true end
        if type(attrVal) == "string" and attrVal ~= "" then return true end
        return false
    end
    if type(attrVal) == "boolean" then
        return attrVal == true
    end
    return true
end

function H._harvestedFruitLabel(inst)
    local instName = tostring(inst.Name or "")
    if instName:find("%[.-%]") then
        local fruitName = inst:GetAttribute("FruitName") or inst:GetAttribute("Fruit")
        if fruitName and instName:find(tostring(fruitName), 1, true) then
            return instName
        end
    end
    local fruitName = inst:GetAttribute("FruitName") or inst:GetAttribute("Fruit")
    local name = tostring(fruitName or inst.Name or "Fruit")
    local weight = tonumber(inst:GetAttribute("Weight"))
    if weight and weight > 0 then
        name = name .. string.format(" [%.2fkg]", weight)
    end
    local mutation = inst:GetAttribute("Mutation")
    if mutation ~= nil and tostring(mutation) ~= "" then
        return name .. " " .. tostring(mutation)
    end
    return name
end

function H._toolLooksLikeHarvestedFruit(inst)
    return H._instLooksLikeHarvestedFruit(inst)
end

function H._buildHarvestedFruitInfo(inst, giftType)
    if not H._instLooksLikeHarvestedFruit(inst) then return nil end

    local uuid = H._instFruitUuid(inst)
    if not H._isLikelyFruitInstanceId(uuid) then
        uuid = ""
    end
    if uuid == "" then
        local harvestedFlag = inst:GetAttribute("HarvestedFruit")
        if type(harvestedFlag) == "string" and H._isLikelyFruitInstanceId(harvestedFlag) then
            uuid = harvestedFlag
        end
    end
    if uuid == "" then
        uuid = tostring(inst.Name)
    end

    return {
        attr = "HarvestedFruit",
        key = H._harvestedFruitLabel(inst),
        name = inst.Name,
        uuid = tostring(uuid),
        giftType = "HarvestedFruits",
    }
end

function H._buildGiftInfoFromAttr(tool, attr, giftType, attrVal)
    if attr == "HarvestedFruit" or giftType == "HarvestedFruits" then
        return H._buildHarvestedFruitInfo(tool, giftType)
    end

    local uuid = tool:GetAttribute("Id")
    if type(uuid) ~= "string" or uuid == "" then
        if type(attrVal) == "string" and attrVal ~= "" then
            uuid = attrVal
        else
            uuid = tool.Name
        end
    end
    local key = type(attrVal) == "string" and attrVal or tostring(attrVal)
    return {
        attr = attr,
        key = key,
        name = tool.Name,
        uuid = tostring(uuid),
        giftType = giftType,
    }
end

function H._toolGiftInfo(inst)
    if not inst or type(inst.GetAttribute) ~= "function" then return nil end

    if H._instLooksLikeHarvestedFruit(inst) then
        return H._buildHarvestedFruitInfo(inst, "HarvestedFruits")
    end

    local map = H._ensureGiftAttrMap()
    if not map then return nil end

    if not inst:IsA("Tool") then return nil end

    for _, attr in ipairs(GIFT_ATTR_ORDER or {}) do
        local giftType = map[attr]
        local attrVal = inst:GetAttribute(attr)
        if giftType and H._attrMatchesGift(attr, attrVal) then
            local info = H._buildGiftInfoFromAttr(inst, attr, giftType, attrVal)
            if info then return info end
        end
    end

    for attr, giftType in pairs(map) do
        local attrVal = inst:GetAttribute(attr)
        if H._attrMatchesGift(attr, attrVal) then
            local info = H._buildGiftInfoFromAttr(inst, attr, giftType, attrVal)
            if info then return info end
        end
    end

    return nil
end

function H._collectInstanceFruitInfos()
    local out = {}
    local byId = {}
    H._foreachGiftInstance(function(inst)
        if not H._instLooksLikeHarvestedFruit(inst) then return end
        local info = H._buildHarvestedFruitInfo(inst, "HarvestedFruits")
        if not info then return end
        local uuid = tostring(info.uuid or "")
        if uuid ~= "" and not byId[uuid] then
            byId[uuid] = true
            out[#out + 1] = {
                attr = info.attr,
                key = info.key,
                name = info.name,
                uuid = uuid,
                giftType = "HarvestedFruits",
                source = "instance",
                inst = inst,
            }
        end
    end)
    return out
end

function H._toolDisplayName(tool)
    if not tool then return "Item" end
    if H._instLooksLikeHarvestedFruit(tool) then
        return H._harvestedFruitLabel(tool)
    end
    local seedTool = tool:GetAttribute("SeedTool")
    if seedTool then
        local name = tostring(seedTool)
        local lower = string.lower(name)
        if not (string.sub(lower, -5) == " seed" or lower == "seed") then
            name = name .. " Seed"
        end
        return name
    end
    local fruitName = tool:GetAttribute("FruitName") or tool:GetAttribute("Fruit")
    if fruitName then
        local name = tostring(fruitName)
        local mutation = tool:GetAttribute("Mutation")
        if mutation and mutation ~= "" then
            return name .. " " .. tostring(mutation)
        end
        return name
    end
    local info = H._toolGiftInfo(tool)
    if info then return tostring(info.key) end
    return tool.Name
end

function H._stripCountSuffix(name)
    return tostring(name or ""):gsub("%s+x%s+[%d%.]+[kKmMbB]?$", "")
end

function H._harvestFruitTypeName(inst)
    if not inst or type(inst.GetAttribute) ~= "function" then return "Fruit" end
    local fruitName = inst:GetAttribute("FruitName") or inst:GetAttribute("Fruit")
    if fruitName and tostring(fruitName) ~= "" then
        return tostring(fruitName)
    end
    local raw = tostring(inst.Name or "Fruit")
    return raw:gsub("%s*%[.-%]", ""):gsub("%s+$", "")
end

function H._giftTypeLabel(inst, info, catKey)
    catKey = H._canonicalCategory(catKey or (info and info.giftType) or "")
    if H._isHarvestedFruitsCategory(catKey) then
        if inst then return H._harvestFruitTypeName(inst) end
        if info and info.inst then return H._harvestFruitTypeName(info.inst) end
        local k = tostring(info and (info.key or info.name) or "Fruit")
        return k:gsub("%s*%[.-%]", ""):gsub("%s+$", "")
    end
    if inst then
        return H._stripCountSuffix(H._toolDisplayName(inst))
    end
    return H._stripCountSuffix(tostring(info and (info.key or info.name) or "Item"))
end

function H._giftTypeKey(inst, info, catKey)
    return H._giftTypeLabel(inst, info, catKey)
end

function H._hasSelection(selectedMap)
    if type(selectedMap) ~= "table" then return false end
    for _, v in pairs(selectedMap) do
        if v == true then return true end
    end
    return false
end

function H._matchesHarvestGroupSelection(inst, info, selectedMap)
    if not H._hasSelection(selectedMap) then return false end
    local norm = H._normalizeFruitGroupKey(H._harvestGroupLabel(inst, info))
    if norm == "" then return false end
    for k, v in pairs(selectedMap) do
        if v == true then
            local base = tostring(k):gsub("%s*x%s+.+$", "")
            if base:sub(1, 5) == "hgrp_" then
                if base == ("hgrp_" .. norm) then
                    return true
                end
            elseif H._normalizeFruitGroupKey(base) == norm then
                return true
            end
        end
    end
    return false
end

function H._itemUiKey(inst, info, catKey)
    catKey = H._canonicalCategory(catKey or (info and info.giftType) or "")
    local uuid = tostring(info and info.uuid or "")
    if H._isHarvestedFruitsCategory(catKey) and uuid ~= "" then
        return H._registerHarvestKeyMap(H._harvestUiKey(uuid), uuid)
    end
    if uuid ~= "" then return uuid end
    return tostring(info and info.key or (inst and inst.Name) or "")
end

function H._itemUiName(inst, info, catKey)
    catKey = H._canonicalCategory(catKey or (info and info.giftType) or "")
    if H._isHarvestedFruitsCategory(catKey) then
        if inst then return H._harvestFruitTypeName(inst) end
        local name = tostring(info and (info.name or info.key) or "Fruit")
        return name:gsub("%s*%[.-%]", ""):gsub("%s+$", "")
    end
    local name = H._stripCountSuffix(inst and H._toolDisplayName(inst) or tostring(info and info.key or "Item"))
    if inst and inst:IsA("Tool") then
        local cnt = H._toolStackCount(inst)
        if cnt > 1 then
            name = name .. " x " .. H._formatCount(cnt)
        end
    end
    return name
end

function H._eachHarvestGiftInfo(callback)
    if type(callback) ~= "function" then return end
    local seen = {}
    local virtual = H._getVirtualFruits(false, false)
    for _, info in ipairs(virtual) do
        local uuid = tostring(info.uuid or "")
        if uuid ~= "" and not seen[uuid] then
            seen[uuid] = true
            callback(nil, info, uuid)
        end
    end
    if #virtual >= 1 then return end
    for _, info in ipairs(H._collectInstanceFruitInfos()) do
        local uuid = tostring(info.uuid or "")
        if uuid ~= "" and not seen[uuid] then
            seen[uuid] = true
            callback(info.inst, info, uuid)
        end
    end
end

function H._matchesToolSelection(inst, info, selectedMap)
    if not info then return false end
    local catKey = H._canonicalGiftType(info.giftType)
    if H._isHarvestedFruitsCategory(catKey) and not H._hasSelection(selectedMap) then
        return true
    end
    if not H._hasSelection(selectedMap) then return false end
    if H._isHarvestedFruitsCategory(catKey) then
        if H._matchesHarvestGroupSelection(inst, info, selectedMap) then
            return true
        end
        selectedMap = H._expandSelectedMapForHarvest(selectedMap)
    end

    local keys = {
        H._itemUiKey(inst, info, catKey),
        tostring(info.uuid or ""),
    }
    if H._isHarvestedFruitsCategory(catKey) then
        keys[#keys + 1] = H._harvestUiKey(info.uuid)
        keys[#keys + 1] = H._resolveHarvestSelectionKey(H._harvestUiKey(info.uuid))
    end
    keys[#keys + 1] = tostring(info.key or "")

    for _, k in ipairs(keys) do
        if k ~= "" and selectedMap[k] == true then
            return true
        end
    end
    return false
end

function H._buildHarvestUiItemsFallback()
    local grouped = {}
    H._eachHarvestGiftInfo(function(inst, info, uuid)
        local label = H._harvestGroupLabel(inst, info)
        local gkey = H._normalizeFruitGroupKey(label)
        if gkey == "" then return end
        local slot = grouped[gkey]
        if not slot then
            slot = { name = label, count = 0 }
            grouped[gkey] = slot
        end
        slot.count += 1
        H._registerHarvestKeyMap(label, uuid)
        H._registerHarvestKeyMap(slot.name, uuid)
    end)

    local items = {}
    local seen = {}
    for _, slot in pairs(grouped) do
        local uiKey = slot.name
        if uiKey == "" then uiKey = "Fruit" end
        if not seen[uiKey] then
            seen[uiKey] = true
            items[#items + 1] = {
                key = uiKey,
                name = slot.name .. " x " .. H._formatCount(slot.count),
                giftType = "HarvestedFruits",
                count = slot.count,
                groupName = slot.name,
            }
        end
    end
    table.sort(items, function(a, b) return a.name < b.name end)
    return items
end

function H._buildHarvestUiItems()
    local ag = H._getAutoGiftModule()
    if type(ag) == "table" and type(ag.BuildInventoryItems) == "function" then
        local ok, rawItems = pcall(function()
            return ag:BuildInventoryItems("HarvestedFruits")
        end)
        if ok and type(rawItems) == "table" and #rawItems > 0 then
            local out = {}
            local seen = {}
            for _, it in ipairs(rawItems) do
                if type(it) == "table" then
                    local key = tostring(it.key or "")
                    if key == "" then
                        key = tostring(it.name or ""):gsub("%s*x%s+.+$", ""):gsub("%s+$", "")
                    end
                    if key ~= "" and not seen[key] then
                        seen[key] = true
                        local count = math.max(0, math.floor(tonumber(it.count) or 0))
                        local name = tostring(it.name or "")
                        if name == "" then
                            name = key .. " x " .. H._formatCount(math.max(count, 1))
                        end
                        out[#out + 1] = {
                            key = key,
                            name = name,
                            giftType = "HarvestedFruits",
                            count = count,
                            groupName = key,
                        }
                    end
                end
            end
            table.sort(out, function(a, b) return a.name < b.name end)
            if #out > 0 then
                return out
            end
        end
    end
    return H._buildHarvestUiItemsFallback()
end

function H._toolsAsUiItems(catKey)
    catKey = H._canonicalCategory(tostring(catKey or ""))
    if catKey == "" then catKey = "Seeds" end

    local now = os.clock()
    local cachedAt = uiItemsCacheAt[catKey] or 0
    local cacheSec = H._isHarvestedFruitsCategory(catKey) and HARVEST_UI_ITEMS_CACHE_SEC or UI_ITEMS_CACHE_SEC
    if uiItemsCache[catKey] and (now - cachedAt) < cacheSec then
        return uiItemsCache[catKey]
    end

    if H._isHarvestedFruitsCategory(catKey) then
        local items = H._buildHarvestUiItems()
        uiItemsCache[catKey] = items
        uiItemsCacheAt[catKey] = now
        return items
    end

    if not H._ensureGiftAttrMap() then return {} end

    local items = {}
    local seen = {}
    H._foreachGiftInstance(function(inst)
        if not inst.Parent then return end
        local info = H._toolGiftInfo(inst)
        if not info or H._canonicalGiftType(info.giftType) ~= catKey then return end
        local uiKey = H._itemUiKey(inst, info, catKey)
        if uiKey == "" or seen[uiKey] then return end
        seen[uiKey] = true
        items[#items + 1] = {
            key = uiKey,
            name = H._itemUiName(inst, info, catKey),
            uuid = info.uuid,
            giftType = catKey,
        }
    end)

    table.sort(items, function(a, b) return a.name < b.name end)
    uiItemsCache[catKey] = items
    uiItemsCacheAt[catKey] = now
    return items
end

function M.GetCategoryDefs()
    local mapReady = H._ensureGiftAttrMap()

    local seen = {}
    local withTools = {}
    if mapReady then
        H._foreachGiftInstance(function(inst)
            local info = H._toolGiftInfo(inst)
            if info then
                local gt = H._canonicalGiftType(info.giftType)
                if gt ~= "" and not seen[gt] then
                    seen[gt] = true
                    withTools[#withTools + 1] = gt
                end
            end
        end)
    end
    if not seen.HarvestedFruits and H._hasHarvestGiftSources() then
        withTools[#withTools + 1] = "HarvestedFruits"
    end
    if #withTools == 0 then
        return {}
    end
    table.sort(withTools)

    local out = {}
    for _, giftType in ipairs(withTools) do
        out[#out + 1] = {
            key = giftType,
            label = giftType,
            giftType = giftType,
        }
    end

    return out
end

function M.GetItemsForCategory(a, b)
    local catKey = a
    if type(a) == "table" and type(b) == "string" then
        catKey = b
    end
    catKey = H._canonicalCategory(tostring(catKey or cfg.category or ""))
    if catKey == "" then catKey = "Seeds" end
    H._ensureGiftAttrMap()
    if H._isHarvestedFruitsCategory(catKey) then
        local items = H._toolsAsUiItems(catKey)
        if #items == 0 then
            M.PrefetchHarvestSources()
        end
        return items
    end
    return H._toolsAsUiItems(catKey)
end

function M.PrefetchHarvestSources()
    if harvestPrefetchBusy then return end
    harvestPrefetchBusy = true
    task.spawn(function()
        pcall(function()
            local ag = H._getAutoGiftModule()
            if type(ag) == "table" and type(ag.GetHarvestFruitBag) == "function" then
                pcall(ag.GetHarvestFruitBag, ag, false)
            end
            H._getVirtualFruits(true, true)
            H._invalidateUiItemsCache("HarvestedFruits")
        end)
        harvestPrefetchBusy = false
        H._refreshNormalGiftItemDropdown()
    end)
end

function M.InvalidateItemCache()
    H._invalidateHarvestCaches()
end

function M.ListServerPlayers()
    local out = {}
    for _, p in ipairs(Players:GetPlayers()) do
        if p ~= LP then
            out[#out + 1] = {
                key = tostring(p.UserId),
                name = p.DisplayName .. " (@" .. p.Name .. ")",
                userId = p.UserId,
                player = p,
            }
        end
    end
    table.sort(out, function(a, b) return a.name < b.name end)
    return out
end

function H._selectedMapForCategory(catKey)
    catKey = H._canonicalCategory(tostring(catKey or cfg.category or ""))
    if type(cfg.selectedByCat) == "table" and type(cfg.selectedByCat[catKey]) == "table" then
        return H._normalizeSet(cfg.selectedByCat[catKey])
    end
    if H._canonicalCategory(cfg.category) == catKey then
        return H._normalizeSet(cfg.selected)
    end
    return {}
end

function H._resolveCategoryFromUi()
    local dd = G.__GAG2_NORMAL_GIFT_CAT_DD or rawget(_G, "__GAG2_NORMAL_GIFT_CAT_DD")
    if type(dd) == "table" and type(dd.getSelected) == "function" then
        local ok, sel = pcall(dd.getSelected, dd)
        if not ok then ok, sel = pcall(dd.getSelected) end
        if ok and sel ~= nil and tostring(sel) ~= "" then
            return H._canonicalCategory(sel)
        end
    end
    local store = G.__GAG2_NORMAL_GIFT or _G.__GAG2_NORMAL_GIFT
    if type(store) == "table" and store.category ~= nil and tostring(store.category) ~= "" then
        return H._canonicalCategory(store.category)
    end
    return H._canonicalCategory(cfg.category)
end

function H._resolveSelectedFromUi(catKey)
    catKey = H._canonicalCategory(tostring(catKey or cfg.category or ""))
    local dd = G.__GAG2_NORMAL_GIFT_ITEM_DD or rawget(_G, "__GAG2_NORMAL_GIFT_ITEM_DD")
    if type(dd) == "table" and type(dd.getSelected) == "function" then
        local ok, sel = pcall(dd.getSelected, dd)
        if not ok then ok, sel = pcall(dd.getSelected) end
        if ok and type(sel) == "table" then
            return H._normalizeSet(sel)
        end
        if ok and sel ~= nil and tostring(sel) ~= "" then
            return { [tostring(sel)] = true }
        end
    end
    return H._selectedMapForCategory(catKey)
end

function H._normalizeSelectedForSend(catKey, selectedMap)
    selectedMap = H._normalizeSet(selectedMap)
    if not next(selectedMap) then return selectedMap end
    if H._isHarvestedFruitsCategory(catKey) then
        return H._expandSelectedMapForHarvest(selectedMap)
    end
    return selectedMap
end

function H._selectedMapForSend(catKey)
    catKey = H._canonicalCategory(tostring(catKey or cfg.category or ""))
    if catKey == "" then catKey = "Seeds" end
    local fromCat = type(cfg.selectedByCat) == "table" and cfg.selectedByCat[catKey] or nil
    local fromCfg = H._normalizeSet(fromCat or cfg.selected)
    if H._hasSelection(fromCfg) then
        return H._normalizeSelectedForSend(catKey, fromCfg)
    end
    return H._normalizeSelectedForSend(catKey, H._resolveSelectedFromUi(catKey))
end

function H._syncCfgFromUi()
    local catKey = H._resolveCategoryFromUi()
    if catKey ~= "" then
        cfg.category = catKey
    end
    local selectedMap = H._resolveSelectedFromUi(catKey)
    cfg.selected = selectedMap
    cfg.selectedByCat = type(cfg.selectedByCat) == "table" and cfg.selectedByCat or {}
    if catKey ~= "" then
        cfg.selectedByCat[catKey] = selectedMap
    end
end

function H._resolvePlayerFromKey(key)
    key = tostring(key or ""):gsub("^%s+", ""):gsub("%s+$", "")
    if key == "" then return nil end

    local uid = math.floor(tonumber(key) or 0)
    if uid > 0 then
        local p = Players:GetPlayerByUserId(uid)
        if p and p ~= LP then return p end
    end

    local lower = key:lower():gsub("^@", "")
    for _, p in ipairs(Players:GetPlayers()) do
        if p ~= LP then
            local label = p.DisplayName .. " (@" .. p.Name .. ")"
            if p.Name:lower() == lower
                or p.DisplayName:lower() == lower
                or label:lower() == lower
                or label:lower():find(lower, 1, true)
                or lower:find(p.Name:lower(), 1, true) then
                return p
            end
        end
    end

    for _, item in ipairs(M.ListServerPlayers()) do
        if tostring(item.key or "") == key then
            local pid = math.floor(tonumber(item.userId or item.key) or 0)
            if pid > 0 then
                local p = Players:GetPlayerByUserId(pid)
                if p then return p end
            end
        end
        local itemName = tostring(item.name or ""):lower()
        if itemName == lower or itemName:find(lower, 1, true) then
            local pid = math.floor(tonumber(item.userId or item.key) or 0)
            if pid > 0 then
                local p = Players:GetPlayerByUserId(pid)
                if p then return p end
            end
        end
    end

    return nil
end

function H._syncTargetCfgFromPlayer(p)
    if not p then return false end
    cfg.target_user_id = p.UserId
    cfg.target_name = p.Name
    return true
end

function H._resolveTarget()
    local uid = math.floor(tonumber(cfg.target_user_id) or 0)
    if uid > 0 then
        local p = Players:GetPlayerByUserId(uid)
        if p then return p end
    end

    local p = H._resolvePlayerFromKey(cfg.target_name)
    if p then
        H._syncTargetCfgFromPlayer(p)
        return p
    end

    local store = G.__GAG2_NORMAL_GIFT or _G.__GAG2_NORMAL_GIFT
    if type(store) == "table" then
        uid = math.floor(tonumber(store.target_user_id) or 0)
        if uid > 0 then
            p = Players:GetPlayerByUserId(uid)
            if p then
                H._syncTargetCfgFromPlayer(p)
                return p
            end
        end
        p = H._resolvePlayerFromKey(store.target_name)
        if p then
            H._syncTargetCfgFromPlayer(p)
            return p
        end
    end

    local dd = G.__GAG2_NORMAL_GIFT_PLAYER_DD or rawget(_G, "__GAG2_NORMAL_GIFT_PLAYER_DD")
    if type(dd) == "table" and type(dd.getSelected) == "function" then
        local ok, sel = pcall(dd.getSelected, dd)
        if not ok then ok, sel = pcall(dd.getSelected) end
        if ok and sel ~= nil and tostring(sel) ~= "" then
            p = H._resolvePlayerFromKey(sel)
            if p then
                H._syncTargetCfgFromPlayer(p)
                return p
            end
        end
    end

    return nil
end

function H._distanceToPlayer(target)
    local char = LP.Character
    local tchar = target and target.Character
    if not char or not tchar then return math.huge end
    local hrp = char:FindFirstChild("HumanoidRootPart")
    local thrp = tchar:FindFirstChild("HumanoidRootPart")
    if not hrp or not thrp then return math.huge end
    return (hrp.Position - thrp.Position).Magnitude
end

function H._teleport(cf)
    if typeof(cf) ~= "CFrame" then return false end
    local char = LP.Character
    local hrp = char and char:FindFirstChild("HumanoidRootPart")
    if not char or not hrp then return false end
    local ok = pcall(function()
        if char.PrimaryPart then
            char:PivotTo(cf)
        else
            hrp.CFrame = cf
        end
    end)
    if ok then task.wait(AFTER_TP_SEC) end
    return ok
end

function H._teleportNearTarget(target)
    local tchar = target and target.Character
    local thrp = tchar and tchar:FindFirstChild("HumanoidRootPart")
    if not thrp then return false end

    local char = LP.Character
    local hrp = char and char:FindFirstChild("HumanoidRootPart")
    if not hrp then return false end

    local toUs = hrp.Position - thrp.Position
    local dir = toUs.Magnitude > 1 and toUs.Unit or -thrp.CFrame.LookVector
    local flat = Vector3.new(dir.X, 0, dir.Z)
    if flat.Magnitude < 0.05 then
        flat = Vector3.new(0, 0, -1)
    else
        flat = flat.Unit
    end

    local standDist = math.min(TP_STAND_DIST, math.max(3, MAX_SEND_DISTANCE - 1))
    local pos = thrp.Position + flat * standDist + Vector3.new(0, TP_Y_OFFSET, 0)
    local cf = CFrame.new(pos, thrp.Position)
    return H._teleport(cf)
end

function H._ensureNearTarget(target)
    if H._distanceToPlayer(target) <= MAX_SEND_DISTANCE then
        return true
    end
    if cfg.teleport_to_target ~= true then
        return false, "too_far"
    end
    if not H._teleportNearTarget(target) then
        return false, "tp_fail"
    end
    return H._distanceToPlayer(target) <= MAX_SEND_DISTANCE + 2
end

function M.TeleportToTarget(targetOrKey)
    local target = targetOrKey
    if typeof(targetOrKey) ~= "Instance" or not targetOrKey:IsA("Player") then
        target = H._resolveTarget()
    end
    if not target then
        H._setStatus("Select a player in this server")
        return false, "no_target"
    end
    if H._teleportNearTarget(target) then
        H._setStatus(string.format("Teleported near %s", target.Name))
        return true
    end
    H._setStatus("Teleport failed")
    return false, "tp_fail"
end

function H._rebuildToolByUuidCache()
    if type(toolByUuidCache) == "table" then return end
    toolByUuidCache = {}
    H._foreachGiftInstance(function(inst)
        if not inst.Parent then return end
        local uuid = H._instFruitUuid(inst)
        if uuid == "" or toolByUuidCache[uuid] then return end
        if inst:IsA("Tool") then
            toolByUuidCache[uuid] = inst
            return
        end
        if H._instLooksLikeHarvestedFruit(inst) then
            toolByUuidCache[uuid] = inst
            return
        end
        local cur = inst
        while cur and cur ~= LP and cur ~= game do
            if cur:IsA("Tool") then
                toolByUuidCache[uuid] = cur
                return
            end
            cur = cur.Parent
        end
    end)
end

function H._findToolByFruitId(id)
    id = tostring(id or "")
    if id == "" then return nil end
    H._rebuildToolByUuidCache()
    local tool = toolByUuidCache[id]
    if tool and tool.Parent then return tool end
    local found = nil
    H._foreachGiftInstance(function(inst)
        if found or not inst.Parent then return end
        if H._instFruitUuid(inst) == id then
            found = inst
        end
    end)
    if found and found.Parent then
        toolByUuidCache[id] = found
        return found
    end
    return nil
end

function H._getAutoFavModule()
    return G.AutoFav or G.AutoFavModule or rawget(_G, "AutoFav") or rawget(_G, "AutoFavModule")
end

function H._truthyFavFlag(val)
    return val == true or val == 1 or val == "true" or val == "1"
end

function H._rawEntryFavorited(entry, depth)
    depth = math.floor(tonumber(depth) or 0)
    if depth > 5 or type(entry) ~= "table" then return false end
    if H._truthyFavFlag(entry.IsFavorite) or H._truthyFavFlag(entry.Favorite)
        or H._truthyFavFlag(entry.Favorited) or H._truthyFavFlag(entry.isFavorite)
        or H._truthyFavFlag(entry.d) then
        return true
    end
    for _, key in ipairs({ "Attributes", "Data", "Fruit", "Entry", "Item" }) do
        local nested = entry[key]
        if type(nested) == "table" and H._rawEntryFavorited(nested, depth + 1) then
            return true
        end
    end
    return false
end

function H._instanceFavorited(inst)
    if not inst or typeof(inst) ~= "Instance" or type(inst.GetAttribute) ~= "function" then
        return false
    end
    return H._truthyFavFlag(inst:GetAttribute("IsFavorite"))
        or H._truthyFavFlag(inst:GetAttribute("Favorite"))
        or H._truthyFavFlag(inst:GetAttribute("Favorited"))
        or H._truthyFavFlag(inst:GetAttribute("isFavorite"))
        or H._truthyFavFlag(inst:GetAttribute("d"))
end

function H._isHarvestUuidFavoritedFast(uuid, entry, instHint)
    uuid = tostring(uuid or "")
    if uuid ~= "" and type(sendJobFavCache) == "table" and sendJobFavCache[uuid] == true then
        return true
    end
    if H._rawEntryFavorited(entry, 0) then
        if uuid ~= "" and type(sendJobFavCache) == "table" then sendJobFavCache[uuid] = true end
        return true
    end
    local hint = instHint
    if (not hint or not hint.Parent) and uuid ~= "" then
        hint = H._findToolByFruitId(uuid)
    end
    if hint and H._instanceFavorited(hint) then
        if uuid ~= "" and type(sendJobFavCache) == "table" then sendJobFavCache[uuid] = true end
        return true
    end
    local af = H._getAutoFavModule()
    if type(af) == "table" and uuid ~= "" then
        if type(af.IsFruitIdFavorited) == "function" then
            local ok, yes = pcall(af.IsFruitIdFavorited, af, uuid, hint)
            if ok and yes == true then
                if type(sendJobFavCache) == "table" then sendJobFavCache[uuid] = true end
                return true
            end
        elseif hint and type(af.IsFruitFavorited) == "function" then
            local ok, yes = pcall(af.IsFruitFavorited, af, hint)
            if ok and yes == true then
                if type(sendJobFavCache) == "table" then sendJobFavCache[uuid] = true end
                return true
            end
        end
    end
    return false
end

function H._isHarvestItemFavorited(item)
    if not item then return false end

    local uuid = tostring(item.uuid or "")
    local entry = type(item.raw) == "table" and item.raw or nil
    if not entry and type(item.info) == "table" and type(item.info.raw) == "table" then
        entry = item.info.raw
    end

    local instHint = nil
    if item.tool and typeof(item.tool) == "Instance" and item.tool.Parent then
        instHint = item.tool
    elseif item.inst and typeof(item.inst) == "Instance" and item.inst.Parent then
        instHint = item.inst
    end

    if H._isHarvestUuidFavoritedFast(uuid, entry, instHint) then return true end

    if uuid ~= "" and type(sendJobFavCache) == "table" then
        sendJobFavCache[uuid] = false
    end
    return false
end

function H._isSendableHarvestCandidate(item)
    if not item then return false end
    return not H._isHarvestItemFavorited(item)
end

function H._resolveSendTool(inst, info)
    if inst and inst:IsA("Tool") and inst.Parent then return inst end
    if inst and inst.Parent then
        local cur = inst.Parent
        while cur and cur ~= LP and cur ~= game do
            if cur:IsA("Tool") and cur.Parent then return cur end
            cur = cur.Parent
        end
    end
    if info and info.uuid then
        return H._findToolByFruitId(info.uuid)
    end
    return nil
end

local _fsvRefreshedAt = 0
local _giftPriceApi = nil

function H._ensureFsvFresh(force)
    local fsv = H._getFruitSellValue()
    if not fsv or type(fsv.refresh) ~= "function" then
        return fsv
    end
    local now = os.clock()
    if force or (now - _fsvRefreshedAt) > 1 then
        pcall(fsv.refresh, true)
        _fsvRefreshedAt = now
    end
    return fsv
end

function H._fruitBaseTypeName(entry, itemKey)
    if type(entry) == "table" then
        local name = H._pickFruitField(entry, FRUIT_NAME_FIELDS)
        if name ~= nil and tostring(name) ~= "" then
            return tostring(name)
        end
    end
    return tostring(itemKey or ""):gsub("%s*%[.-%]", ""):gsub("%s+$", "")
end

function H._resolvePriceMulti(entry, inst)
    if inst and type(inst.GetAttribute) == "function" then
        local ok, m = pcall(function()
            local fsv = H._getFruitSellValue()
            if fsv and type(fsv.resolveMulti) == "function" then
                return fsv.resolveMulti(inst)
            end
            return tonumber(inst:GetAttribute("Weight"))
        end)
        if ok and type(m) == "number" and m > 0 then return m end
    end
    if type(entry) == "table" then
        local sm = tonumber(entry.SizeMultiplier or entry.SizeMulti)
        if sm and sm > 0 then return sm end
        local w = tonumber(entry.Weight or entry.weight)
        if w and w > 0 then return w end
    end
    if inst and type(inst.GetAttribute) == "function" then
        local w = tonumber(inst:GetAttribute("Weight"))
        if w and w > 0 then return w end
    end
    return 0
end

function H._entrySellPrice(category, itemKey, entry, inst)
    if not H._isHarvestedFruitsCategory(category) then return 0 end
    local fsv = H._ensureFsvFresh(false)
    if not fsv then return 0 end

    local espMode = H._harvestPriceCalcMode()
    inst = inst or nil
    if not inst and type(entry) == "table" and entry.inst then
        inst = entry.inst
    end

    local name = H._fruitBaseTypeName(entry, itemKey)
    local multi = H._resolvePriceMulti(entry, inst)
    local mut = type(entry) == "table" and (entry.Mutation or entry.mutation) or nil
    if (mut == nil or mut == "") and inst and type(inst.GetAttribute) == "function" then
        mut = inst:GetAttribute("Mutation")
    end
    local decay = type(entry) == "table" and entry.DecayAlpha or nil
    if decay == nil and inst and type(inst.GetAttribute) == "function" then
        decay = inst:GetAttribute("DecayAlpha")
    end
    local id = tostring(itemKey or "")

    local bidPrice = 0
    if inst then
        if type(fsv.resolveBidPrice) == "function" then
            local okBid, b = pcall(fsv.resolveBidPrice, inst)
            if okBid and type(b) == "number" and b > 0 then bidPrice = b end
        elseif type(inst.GetAttribute) == "function" then
            bidPrice = tonumber(inst:GetAttribute("BidPrice")) or 0
        end
    end
    if type(fsv.getBackpackEspPrice) == "function" and multi > 0 and name ~= "" then
        local ok, p = pcall(fsv.getBackpackEspPrice, name, multi, mut, decay, espMode, id, bidPrice)
        if ok and type(p) == "number" and p > 0 then
            return math.floor(p + 0.5)
        end
    end
    if type(fsv.getBackpackPrice) == "function" then
        local ok, p = pcall(fsv.getBackpackPrice, name, multi, mut, id, decay)
        if ok and type(p) == "number" and p > 0 then
            return math.floor(p + 0.5)
        end
    end
    if inst then
        local p = H._harvestSellPrice(inst)
        if p > 0 then return math.floor(p + 0.5) end
    end
    if type(fsv.calculate) == "function" and multi > 0 and name ~= "" then
        local ok, p = pcall(fsv.calculate, name, multi, mut, LP, decay)
        if ok and type(p) == "number" and p > 0 then
            return math.floor(p + 0.5)
        end
    end
    return 0
end

function H._giftPrice()
    if _giftPriceApi then return _giftPriceApi end
    local factory = G.AutoGiftPriceModule or G.AutoGiftPrice
        or rawget(_G, "AutoGiftPriceModule") or rawget(_G, "AutoGiftPrice")
    if type(factory) == "table" and type(factory.create) == "function" then
        _giftPriceApi = factory.create({
            clampBatch = function(n) return math.max(1, math.floor(tonumber(n) or 1)) end,
            maxBatch = 10000,
            formatSellPrice = _formatSellPrice,
            isHarvestedFruitsCategory = _isHarvestedFruitsCategory,
            entrySellPrice = _entrySellPrice,
        })
    end
    return _giftPriceApi
end

function H._candidateHarvestPrice(item)
    if not item then return 0 end
    local inst = item.inst
    if (not inst or not inst.Parent) and item.tool and item.tool.Parent then
        inst = item.tool
    end
    local entry = type(item.raw) == "table" and item.raw or nil
    if not entry and type(item.info) == "table" and type(item.info.raw) == "table" then
        entry = item.info.raw
    end
    if not entry and inst then
        entry = {
            FruitName = inst:GetAttribute("FruitName") or inst:GetAttribute("Fruit"),
            Mutation = inst:GetAttribute("Mutation"),
            Weight = inst:GetAttribute("Weight"),
            Id = item.uuid,
        }
    end
    return H._entrySellPrice("HarvestedFruits", item.uuid, entry, inst)
end

function H._cachedHarvestPrice(item)
    if not item then return 0 end
    local uuid = tostring(item.uuid or "")
    if uuid ~= "" then
        local cached = harvestPriceByUuid[uuid]
        if cached ~= nil then
            return cached
        end
    end
    local price = math.max(0, math.floor(H._candidateHarvestPrice(item)))
    if uuid ~= "" then
        harvestPriceByUuid[uuid] = price
    end
    return price
end

function H._primeHarvestPriceEngine()
    if sendJobFsvPrimed then return end
    sendJobFsvPrimed = true
    pcall(function() H._ensureFsvFresh(true) end)
end

function H._sumCandidatePrice(candidates)
    local total = 0
    for _, item in ipairs(candidates) do
        total += math.floor(tonumber(item.SellPrice) or 0)
    end
    return total
end

function H._planPricePickOne(candidates, minSum, maxSum)
    candidates = type(candidates) == "table" and candidates or {}
    minSum = math.max(1, math.floor(tonumber(minSum) or 0))
    maxSum = math.max(minSum, math.floor(tonumber(maxSum) or 0))
    if #candidates == 0 then return nil, 0 end

    local px = H._giftPrice()
    if px and type(px.planPriceBatch) == "function" then
        local batch, price = px.planPriceBatch(candidates, minSum, maxSum, 1)
        if type(batch) == "table" and #batch > 0 then
            price = math.floor(tonumber(price or batch[1].SellPrice) or 0)
            if price > 0 and price <= maxSum then
                local key = tostring(batch[1].ItemKey or "")
                for _, c in ipairs(candidates) do
                    if tostring(c.ItemKey or "") == key then
                        return c, price
                    end
                end
            end
        end
    end

    local bestInRange, bestInRangePrice = nil, 0
    local bestUnder, bestUnderPrice = nil, 0
    for _, c in ipairs(candidates) do
        local p = math.floor(tonumber(c.SellPrice) or 0)
        if p <= 0 then continue end
        if p >= minSum and p <= maxSum and p > bestInRangePrice then
            bestInRange, bestInRangePrice = c, p
        end
        if p <= maxSum and p > bestUnderPrice then
            bestUnder, bestUnderPrice = c, p
        end
    end
    if bestInRange then return bestInRange, bestInRangePrice end
    if bestUnder then return bestUnder, bestUnderPrice end
    return nil, 0
end

function H._buildHarvestPresenceSet()
    local set = {}
    H._foreachGiftInstance(function(inst)
        if not inst.Parent then return end
        if not H._instLooksLikeHarvestedFruit(inst) then return end
        local id = tostring(inst:GetAttribute("Id") or inst:GetAttribute("UUID") or "")
        if id ~= "" then set[id] = true end
    end)
    local ag = H._getAutoGiftModule()
    if type(ag) == "table" and type(ag.GetHarvestFruitBag) == "function" then
        local ok, bag = pcall(function()
            return ag:GetHarvestFruitBag(true)
        end)
        if ok and type(bag) == "table" then
            for uuid in pairs(bag) do
                uuid = tostring(uuid or "")
                if uuid ~= "" then set[uuid] = true end
            end
        end
    end
    return set
end

function H._harvestUuidPresent(uuid, presenceSet)
    uuid = tostring(uuid or "")
    if uuid == "" then return false end
    if type(presenceSet) == "table" and presenceSet[uuid] then return true end
    return H._inventoryHasHarvestUuid(uuid)
end

function H._syncSendTotalFromUi()
    local priceMode = H._usesPriceMode()
    local totalFn = G.__GAG2_NORMAL_GIFT_SEND_TOTAL or rawget(_G, "__GAG2_NORMAL_GIFT_SEND_TOTAL")
    if type(totalFn) == "function" then
        local ok, n = pcall(totalFn)
        if ok then
            cfg.send_total = H._clampSendTotalGoal(n, priceMode)
        end
    end
    local store = G.__GAG2_NORMAL_GIFT or _G.__GAG2_NORMAL_GIFT
    if type(store) == "table" and tonumber(store.send_total) then
        cfg.send_total = H._clampSendTotalGoal(store.send_total, priceMode)
    end
end

function H._sortCandidates(candidates)
    table.sort(candidates, function(a, b)
        local ak = tostring(a.key or a.name or a.uuid or "")
        local bk = tostring(b.key or b.name or b.uuid or "")
        if ak ~= bk then return ak < bk end
        return tostring(a.uuid or "") < tostring(b.uuid or "")
    end)
    return candidates
end

function H._candidateUnitCount(item)
    if not item then return 0 end
    local tool = item.tool
    if (not tool or not tool.Parent) and item.inst and item.inst:IsA("Tool") and item.inst.Parent then
        tool = item.inst
    end
    if tool and tool.Parent then
        return H._toolStackCount(tool)
    end
    if item.virtual or H._isHarvestedFruitsCategory(item.giftType) then
        return 1
    end
    if item.inst and item.inst.Parent then
        return 1
    end
    return 0
end

function H._pickCandidate(candidates, index, skipUuids)
    candidates = H._sortCandidates(candidates)
    if #candidates == 0 then return nil end
    skipUuids = type(skipUuids) == "table" and skipUuids or {}
    for offset = 0, #candidates - 1 do
        local item = candidates[((index + offset - 1) % #candidates) + 1]
        local uuid = tostring(item.uuid or "")
        if uuid == "" or not skipUuids[uuid] then
            local sendable = not H._isHarvestedFruitsCategory(item.giftType)
                or H._isSendableHarvestCandidate(item)
            if sendable and H._candidateUnitCount(item) > 0 then
                return item
            end
        end
    end
    return nil
end

function H._resolveSendTarget(targetSnap)
    if type(targetSnap) ~= "table" then return nil end
    local uid = math.floor(tonumber(targetSnap.userId) or 0)
    if uid <= 0 then return nil end
    local p = Players:GetPlayerByUserId(uid)
    if p and p.Parent then return p end
    return nil
end

function H._resetNormalGiftHistoryAcc()
    sendJobFavCache = {}
    sendJobHistoryAcc = {
        rows = {},
        totalUnits = 0,
        totalSentPrice = 0,
        lastMsg = "",
    }
end

function H._historyRowName(item, catKey)
    catKey = H._canonicalCategory(catKey or (item and item.giftType) or "")
    if not item then return "Item" end
    if H._isHarvestedFruitsCategory(catKey) then
        return H._harvestGroupLabel(item.inst, {
            name = item.name,
            key = item.key,
            raw = item.raw,
        })
    end
    return H._stripCountSuffix(tostring(item.name or item.key or "Item"))
end

function H._accumulateNormalGiftHistoryRow(item, catKey, unitPrice, count)
    if type(sendJobHistoryAcc) ~= "table" then return end
    count = math.max(1, math.floor(tonumber(count) or 1))
    catKey = H._canonicalCategory(catKey or (item and item.giftType) or "Seeds")
    local name = H._historyRowName(item, catKey)
    unitPrice = math.max(0, math.floor(tonumber(unitPrice) or 0))
    local linePrice = unitPrice * count
    for _, row in ipairs(sendJobHistoryAcc.rows) do
        if tostring(row.Category or "") == catKey and tostring(row.Name or "") == name then
            row.Count = math.max(1, math.floor(tonumber(row.Count) or 1)) + count
            row.Price = math.floor(tonumber(row.Price) or 0) + linePrice
            if unitPrice > 0 then
                row.UnitPrice = unitPrice
            end
            sendJobHistoryAcc.totalUnits += count
            sendJobHistoryAcc.totalSentPrice += linePrice
            return
        end
    end
    sendJobHistoryAcc.rows[#sendJobHistoryAcc.rows + 1] = {
        Category = catKey,
        Name = name,
        Count = count,
        UnitPrice = unitPrice,
        Price = linePrice,
    }
    sendJobHistoryAcc.totalUnits += count
    sendJobHistoryAcc.totalSentPrice += linePrice
end

function H._flushNormalGiftHistory(targetSnap, message)
    local acc = sendJobHistoryAcc
    sendJobHistoryAcc = nil
    if type(acc) ~= "table" or #acc.rows == 0 then return end

    local hist = G.GiftMailHistoryModule or G.GiftMailHistory
        or rawget(_G, "GiftMailHistoryModule") or rawget(_G, "GiftMailHistory")
    if type(hist) ~= "table" then return end

    message = tostring(message or acc.lastMsg or "")
    if message == "" then
        message = string.format(
            "Normal gift (%d item) → @%s",
            acc.totalUnits,
            tostring(targetSnap and targetSnap.name or "?")
        )
    end

    local uid = math.floor(tonumber(targetSnap and targetSnap.userId) or 0)
    local user = tostring(targetSnap and targetSnap.name or "")
    local disp = tostring(targetSnap and targetSnap.displayName or "")

    if type(hist.RecordSendBatch) == "function" then
        pcall(hist.RecordSendBatch, acc.rows, {
            total = acc.totalUnits,
            success = true,
            msg = message,
            sendBatchNum = 1,
            profile = "normal",
            harvest_total_price = math.floor(tonumber(acc.totalSentPrice) or 0),
            cfg = {
                recipient_user_id = uid,
                recipient_username = user,
                recipient_display = disp,
            },
        })
        return
    end

    if type(hist.Record) == "function" then
        pcall(hist.Record, {
            ts = os.time(),
            profile = "normal",
            success = true,
            recipient_user_id = uid,
            recipient_username = user,
            recipient_display = disp,
            item_count = acc.totalUnits,
            send_batch = 1,
            batch_rows = #acc.rows,
            message = message,
            items = acc.rows,
        })
    end
end

function H._sendTrackingKey(item)
    if not item then return "" end
    local uuid = tostring(item.uuid or "")
    if uuid ~= "" then return uuid end
    return tostring(item.key or item.name or "")
end

function H._inventoryHasHarvestUuid(uuid, forceFresh)
    uuid = tostring(uuid or "")
    if uuid == "" then return false end
    local ag = H._getAutoGiftModule()
    if type(ag) == "table" and type(ag.GetHarvestFruitBag) == "function" then
        local ok, bag = pcall(function()
            return ag:GetHarvestFruitBag(forceFresh == true)
        end)
        if ok and type(bag) == "table" and bag[uuid] ~= nil then
            return true
        end
    end
    if H._findToolByFruitId(uuid) then return true end
    return false
end

function H._harvestLikelyGoneAfterSend(sendUuid, tool)
    sendUuid = tostring(sendUuid or "")
    H._invalidateHarvestCaches()
    if tool then
        if not tool.Parent then return true end
        local bp = LP:FindFirstChild("Backpack")
        if tool.Parent ~= LP.Character and (not bp or tool.Parent ~= bp) then
            return true
        end
    end
    if sendUuid == "" then return false end
    if H._findToolByFruitId(sendUuid) then return false end
    if not H._inventoryHasHarvestUuid(sendUuid, true) then return true end
    for _, info in ipairs(H._collectInstanceFruitInfos()) do
        if tostring(info.uuid or "") == sendUuid then
            return false
        end
    end
    return true
end

function H._inventoryHasUniqueItem(item)
    if not item then return false end
    local uuid = tostring(item.uuid or "")
    local tool = item.tool or item.inst
    if tool and tool.Parent then
        if uuid ~= "" then
            local ti = H._toolGiftInfo(tool)
            if ti and tostring(ti.uuid or "") == uuid then
                return true
            end
        end
        return true
    end
    if uuid == "" then return false end
    local found = false
    H._foreachGiftInstance(function(inst)
        if found or not inst.Parent then return end
        local ti = H._toolGiftInfo(inst)
        if ti and tostring(ti.uuid or "") == uuid then
            found = true
        end
    end)
    return found
end

function H._currentStackCountForItem(item)
    if not item then return 0 end
    local tool = item.tool
    if (not tool or not tool.Parent) and item.inst and item.inst:IsA("Tool") and item.inst.Parent then
        tool = item.inst
    end
    if tool and tool.Parent then
        return H._toolStackCount(tool)
    end
    return H._candidateUnitCount(item)
end

function H._harvestItemPrice(item)
    local price = math.max(0, math.floor(tonumber(item and item._agSellPrice) or 0))
    if price > 0 then return price end
    return H._cachedHarvestPrice(item)
end

function H._buildHarvestUuidCache(candidates, goal, priceMode)
    candidates = H._sortCandidates(type(candidates) == "table" and candidates or {})
    local cache = {}
    local totalPrice = 0
    local seen = {}
    if priceMode == true then
        for _, item in ipairs(candidates) do
            local uuid = tostring(item.uuid or "")
            if uuid ~= "" and not seen[uuid] then
                seen[uuid] = true
                local price = H._harvestItemPrice(item)
                if price > 0 then
                    cache[#cache + 1] = { uuid = uuid, item = item, price = price }
                    totalPrice += price
                end
            end
        end
        return cache, #cache, totalPrice
    end
    goal = math.max(1, math.floor(tonumber(goal) or 1))
    for _, item in ipairs(candidates) do
        if #cache >= goal then break end
        local uuid = tostring(item.uuid or "")
        if uuid ~= "" and not seen[uuid] then
            seen[uuid] = true
            cache[#cache + 1] = {
                uuid = uuid,
                item = item,
                price = 0,
            }
        end
    end
    return cache, #cache, 0
end

function H._harvestPricePoolFromCache(cache, skipUuids)
    local out = {}
    skipUuids = type(skipUuids) == "table" and skipUuids or {}
    for _, entry in ipairs(cache or {}) do
        local uuid = tostring(entry.uuid or "")
        if uuid ~= "" and not skipUuids[uuid] and H._inventoryHasHarvestUuid(uuid) then
            local ngItem = entry.item
            if ngItem then
                out[#out + 1] = {
                    Category = "HarvestedFruits",
                    ItemKey = uuid,
                    SellPrice = math.floor(tonumber(entry.price) or 0),
                    _ngItem = entry.item,
                }
            end
        end
    end
    return out
end

function H._pickHarvestCacheEntry(cache, skipUuids, startIndex)
    cache = type(cache) == "table" and cache or {}
    skipUuids = type(skipUuids) == "table" and skipUuids or {}
    if #cache == 0 then return nil end
    startIndex = math.max(1, math.floor(tonumber(startIndex) or 1))
    for offset = 0, #cache - 1 do
        local entry = cache[((startIndex + offset - 1) % #cache) + 1]
        local uuid = tostring(entry.uuid or "")
        if uuid ~= "" and not skipUuids[uuid] and H._inventoryHasHarvestUuid(uuid) then
            local ngItem = entry.item
            if not ngItem or H._isSendableHarvestCandidate(ngItem) then
                return entry
            end
        end
    end
    return nil
end

function H._estimateCandidateUnits(candidates)
    local total = 0
    for _, item in ipairs(type(candidates) == "table" and candidates or {}) do
        total += H._candidateUnitCount(item)
    end
    return total
end

function H._isGiftRemovedNow(item, sendUuid, tool, countBefore)
    sendUuid = tostring(sendUuid or "")
    local catKey = H._canonicalCategory(item and item.giftType or "")

    if H._isHarvestedFruitsCategory(catKey) and sendUuid ~= "" then
        return not H._inventoryHasHarvestUuid(sendUuid, true)
    end

    countBefore = math.max(1, math.floor(tonumber(countBefore) or 1))
    local nowCount = H._currentStackCountForItem(item)
    if nowCount > 0 and nowCount < countBefore then
        return true
    end
    if tool and not tool.Parent then
        return true
    end
    if tool and tool.Parent and H._toolStackCount(tool) < countBefore then
        return true
    end
    if countBefore == 1 and item and not H._inventoryHasUniqueItem(item) then
        return true
    end
    return false
end

-- Poll max SEND_GAP_SEC: sukses segera saat UUID/stack berkurang; skip cepat jika fav ditolak game.
function H._awaitGiftConfirmation(item, sendUuid, tool, countBefore)
    local deadline = os.clock() + SEND_GAP_SEC
    local quickRejectAt = os.clock() + SEND_FAV_REJECT_SEC
    local isHarvest = H._isHarvestedFruitsCategory(item and item.giftType or "")
    sendUuid = tostring(sendUuid or "")

    while os.clock() < deadline do
        if sendJobCancel then
            return false, "cancelled"
        end
        task.wait(SEND_VERIFY_WAIT_SEC)
        H._invalidateHarvestCaches()

        if H._isGiftRemovedNow(item, sendUuid, tool, countBefore) then
            return true, "confirmed"
        end

        if isHarvest and sendUuid ~= "" then
            if H._isHarvestItemFavorited(item) then
                return false, "favorited"
            end
            if os.clock() >= quickRejectAt and H._inventoryHasHarvestUuid(sendUuid, true) then
                pcall(function() H._getVirtualFruits(true, true) end)
                if H._isHarvestItemFavorited(item) then
                    return false, "favorited"
                end
            end
        end
    end

    return false, "not_removed"
end

function H._giftUuidStillOwned(sendUuid, item, tool, countBefore)
    sendUuid = tostring(sendUuid or "")
    local catKey = H._canonicalCategory(item and item.giftType or "")

    if H._isHarvestedFruitsCategory(catKey) and sendUuid ~= "" then
        if H._findToolByFruitId(sendUuid) then return true end
        local ag = H._getAutoGiftModule()
        if type(ag) == "table" and type(ag.GetHarvestFruitBag) == "function" then
            local ok, bag = pcall(function()
                return ag:GetHarvestFruitBag(true)
            end)
            if ok and type(bag) == "table" and bag[sendUuid] ~= nil then
                return true
            end
        end
        for _, info in ipairs(H._collectInstanceFruitInfos()) do
            if tostring(info.uuid or "") == sendUuid then
                return true
            end
        end
        return false
    end

    if tool and tool.Parent then
        local before = math.max(1, math.floor(tonumber(countBefore) or 1))
        if before > 1 then
            return H._toolStackCount(tool) >= before
        end
        return true
    end

    if sendUuid == "" then return false end

    local found = false
    H._foreachGiftInstance(function(inst)
        if found or not inst.Parent then return end
        if H._instLooksLikeHarvestedFruit(inst) then
            if H._instFruitUuid(inst) == sendUuid then
                found = true
            end
            return
        end
        local ti = H._toolGiftInfo(inst)
        if ti and tostring(ti.uuid or "") == sendUuid then
            found = true
        end
    end)
    return found
end

function H._sendOneGift(target, item)
    if not item then return false, "no_item" end

    if H._isHarvestedFruitsCategory(item.giftType) then
        if H._isHarvestItemFavorited(item) then
            return false, "favorited"
        end
    end

    local sendType = item.giftType
    local sendUuid = tostring(item.uuid or "")
    local tool = item.tool
    if (not tool or not tool.Parent) and item.inst and item.inst:IsA("Tool") and item.inst.Parent then
        tool = item.inst
    end
    if (not tool or not tool.Parent) and sendUuid ~= "" then
        tool = H._findToolByFruitId(sendUuid)
    end
    if not tool or not tool.Parent then
        tool = H._resolveSendTool(item.inst, item)
    end

    local info = tool and H._toolGiftInfo(tool) or nil
    if info then
        sendType = info.giftType or sendType
        if sendUuid == "" then
            sendUuid = tostring(info.uuid or info.key or "")
        end
    end

    if sendUuid == "" then
        return false, "no_uuid"
    end

    local countBefore = tool and tool.Parent and H._toolStackCount(tool) or H._currentStackCountForItem(item)
    countBefore = math.max(1, math.floor(tonumber(countBefore) or 1))

    local fired = H._callNetworkingRemote(GiftingSend, target.UserId, sendType, sendUuid)
    if not fired then
        return false, "remote_fail"
    end

    local ok, reason = H._awaitGiftConfirmation(item, sendUuid, tool, countBefore)
    if ok then
        H._invalidateHarvestCaches()
        return true, "confirmed"
    end
    return false, reason or "not_removed"
end

function M.StopSend(_self)
    sendJobCancel = true
    if sendBusy then
        H._setStatus("Stopping send...")
        task.delay(1.5, function()
            if sendBusy and sendJobCancel then
                sendBusy = false
                sendJobCancel = false
                H._setStatus("Send stopped")
            end
        end)
    end
end

function M.IsSendBusy(_self)
    return sendBusy == true
end

function H._agRowToSendItem(row, catKey)
    local uuid = tostring(row.ItemKey or "")
    if uuid == "" then return nil end
    local entry = type(row.Entry) == "table" and row.Entry or nil
    return {
        inst = nil,
        virtual = true,
        tool = nil,
        giftType = catKey,
        uuid = uuid,
        key = uuid,
        name = H._fruitBaseTypeName(entry, uuid),
        raw = entry,
        _agSellPrice = math.floor(tonumber(row.SellPrice) or 0),
    }
end

function H._collectHarvestViaAutoGift(catKey, selectedMap)
    local ag = H._getAutoGiftModule()
    if type(ag) ~= "table" or type(ag.CollectCategoryCandidates) ~= "function" then
        return nil, false
    end
    local ok, rows = pcall(function()
        return ag:CollectCategoryCandidates(catKey, selectedMap)
    end)
    if not ok or type(rows) ~= "table" then return nil, false end
    local candidates = {}
    for _, row in ipairs(rows) do
        local item = H._agRowToSendItem(row, catKey)
        if item and H._isSendableHarvestCandidate(item) then
            candidates[#candidates + 1] = item
        end
    end
    return candidates, true
end

function H._collectPriceCandidatesViaAutoGift(catKey, selectedMap)
    local rows, viaAg = H._collectHarvestViaAutoGift(catKey, selectedMap)
    if not viaAg then return nil end
    local out = {}
    for _, ngItem in ipairs(rows) do
        if not H._isSendableHarvestCandidate(ngItem) then continue end
        local price = math.floor(tonumber(ngItem._agSellPrice) or 0)
        if price <= 0 then
            price = H._candidateHarvestPrice(ngItem)
        end
        if price > 0 then
            out[#out + 1] = {
                Category = catKey,
                ItemKey = tostring(ngItem.uuid or ""),
                SellPrice = price,
                _ngItem = ngItem,
            }
        end
    end
    return out
end

function H._collectSendCandidates(catKey, selectedMap, allowRemote)
    catKey = H._canonicalCategory(tostring(catKey or cfg.category or "Seeds"))
    if catKey == "" then catKey = "Seeds" end
    selectedMap = H._normalizeSelectedForSend(catKey, selectedMap)
    local candidates = {}

    if H._isHarvestedFruitsCategory(catKey) then
        local agCandidates, viaAg = H._collectHarvestViaAutoGift(catKey, selectedMap)
        if viaAg and #agCandidates > 0 then
            return agCandidates
        end

        H._getVirtualFruits(allowRemote == true, allowRemote == true)
        local seenUuid = {}
        H._eachHarvestGiftInfo(function(inst, info, uuid)
            if seenUuid[uuid] then return end
            if not H._matchesToolSelection(inst, info, selectedMap) then return end
            local entry = type(info) == "table" and info.raw or nil
            if not H._isSendableHarvestCandidate({
                inst = inst,
                uuid = uuid,
                raw = entry,
                giftType = "HarvestedFruits",
            }) then return end
            seenUuid[uuid] = true
            candidates[#candidates + 1] = {
                inst = inst,
                virtual = inst == nil,
                tool = nil,
                giftType = "HarvestedFruits",
                uuid = uuid,
                key = H._itemUiKey(inst, info, catKey),
                name = H._itemUiName(inst, info, catKey),
                raw = entry,
            }
        end)
        return candidates
    end

    H._foreachGiftInstance(function(inst)
        if inst.Parent then
            local info = H._toolGiftInfo(inst)
            if info and H._canonicalGiftType(info.giftType) == catKey
                and H._matchesToolSelection(inst, info, selectedMap) then
                local candidate = {
                    inst = inst,
                    virtual = false,
                    tool = H._resolveSendTool(inst, info),
                    giftType = H._canonicalGiftType(info.giftType),
                    uuid = info.uuid,
                    key = H._itemUiKey(inst, info, catKey),
                    name = H._itemUiName(inst, info, catKey),
                }
                candidates[#candidates + 1] = candidate
            end
        end
    end)

    return candidates
end

function H._collectSendCandidatesCached(catKey, selectedMap, allowRemote, forceRefresh)
    if forceRefresh then
        H._invalidateSendCandidatesCache()
    end
    local now = os.clock()
    if not forceRefresh and sendCandidatesCache and (now - sendCandidatesCacheAt) < SEND_CANDIDATES_CACHE_SEC then
        return sendCandidatesCache
    end
    local candidates = H._collectSendCandidates(catKey, selectedMap, allowRemote)
    sendCandidatesCache = candidates
    sendCandidatesCacheAt = now
    return candidates
end

function H._collectPriceCandidates(catKey, selectedMap)
    if H._isHarvestedFruitsCategory(catKey) then
        local viaAg = H._collectPriceCandidatesViaAutoGift(catKey, selectedMap)
        if viaAg ~= nil then return viaAg end
    end
    local out = {}
    for _, item in ipairs(H._collectSendCandidates(catKey, selectedMap)) do
        if not H._isSendableHarvestCandidate(item) then continue end
        local price = H._candidateHarvestPrice(item)
        if price > 0 then
            out[#out + 1] = {
                Category = "HarvestedFruits",
                ItemKey = tostring(item.uuid or ""),
                SellPrice = price,
                _ngItem = item,
            }
        end
    end
    return out
end

function H._estimateSendableHarvestPrice(catKey, selectedMap)
    local total = 0
    local units = 0
    for _, item in ipairs(H._collectSendCandidates(catKey, selectedMap, true)) do
        if H._isSendableHarvestCandidate(item) then
            local price = math.max(0, math.floor(H._candidateHarvestPrice(item)))
            if price > 0 then
                total += price
                units += 1
            end
        end
    end
    return total, units
end

function H._estimateSendableUnits(catKey, selectedMap)
    local candidates = H._sortCandidates(H._collectSendCandidates(catKey, selectedMap))
    local total = 0
    local count = 0
    for _, item in ipairs(candidates) do
        if H._isHarvestedFruitsCategory(catKey) and not H._isSendableHarvestCandidate(item) then
            continue
        end
        count += 1
        total += H._candidateUnitCount(item)
    end
    return total, count
end

function H._looksLikeConfigPatch(t)
    if type(t) ~= "table" then return false end
    return t.target_user_id ~= nil
        or t.target_name ~= nil
        or t.category ~= nil
        or t.selected ~= nil
        or t.selectedByCat ~= nil
        or t.send_total ~= nil
        or t.send_mode ~= nil
        or t.harvest_price_threshold_pct ~= nil
        or t.harvest_price_calc_mode ~= nil
        or t.teleport_to_target ~= nil
end

function M.SendNow(a, b)
    if sendBusy then
        H._setStatus("Send already running")
        return false, "busy"
    end
    sendBusy = true
    sendJobCancel = false

    local patch = (H._looksLikeConfigPatch(a) and b == nil) and a or nil

    task.spawn(function()
        local catKey = "Seeds"
        local selectedMap = {}
        local targetSnap = {
            userId = 0,
            name = "",
            displayName = "",
        }

        local sent = 0
        local sentPrice = 0
        local failStreak = 0
        local skipUuids = {}
        local uuidTries = {}
        local abortReason = nil
        local finalMessage = ""
        local harvestCache = nil
        local harvestCacheUnits = 0
        local harvestCachePrice = 0
        local isHarvest = false

        local function finishJob()
            sendBusy = false
            sendJobCancel = false
            sendJobFavCache = nil
            sendJobFsvPrimed = false
            toolByUuidCache = nil

            if finalMessage ~= "" and type(sendJobHistoryAcc) == "table" then
                sendJobHistoryAcc.lastMsg = finalMessage
            end
            H._flushNormalGiftHistory(targetSnap, finalMessage)

            local done = G.__GAG2_NORMAL_GIFT_SEND_DONE or rawget(_G, "__GAG2_NORMAL_GIFT_SEND_DONE")
            if type(done) == "function" then
                pcall(done, sent > 0)
            end

            local itemDd = G.__GAG2_NORMAL_GIFT_ITEM_DD or rawget(_G, "__GAG2_NORMAL_GIFT_ITEM_DD")
            if type(itemDd) == "table" and type(itemDd.refreshItems) == "function" then
                pcall(itemDd.refreshItems, itemDd)
            end
        end

        local function abortEarly(msg)
            finalMessage = tostring(msg or "Send failed")
            H._setStatus(finalMessage)
            finishJob()
        end

        local okPrep, prepErr = pcall(function()
            if sendJobCancel then
                abortEarly("Send stopped")
                return
            end

            H._setStatus("Preparing send...")

            if patch then
                M.ApplyConfig(patch)
            else
                M.SyncFromGlobals()
            end
            H._syncSendTotalFromUi()

            if not H._ensureNetworking() then
                abortEarly("Gifting remote not ready")
                return
            end

            if not H._ensureGiftAttrMap() then
                abortEarly("GiftingController map not ready — wait/rejoin")
                return
            end

            local target = H._resolveTarget()
            if not target then
                abortEarly("Select a player in this server")
                return
            end

            targetSnap = {
                userId = target.UserId,
                name = target.Name,
                displayName = target.DisplayName,
            }

            local dist = H._distanceToPlayer(target)
            if cfg.teleport_to_target == true then
                if dist > MAX_SEND_DISTANCE then
                    H._setStatus(string.format("Teleporting near %s...", target.Name))
                    if not H._teleportNearTarget(target) then
                        abortEarly("Teleport to target failed")
                        return
                    end
                end
            elseif dist > MAX_SEND_DISTANCE then
                abortEarly(string.format(
                    "Too far (%.0f studs) — enable teleport to target",
                    dist
                ))
                return
            end

            if sendJobCancel then
                abortEarly("Send stopped")
                return
            end

            catKey = H._canonicalCategory(tostring(cfg.category or ""))
            if catKey == "" then
                catKey = H._resolveCategoryFromUi()
            end
            if catKey == "" then catKey = "Seeds" end
            cfg.category = catKey
            cfg.selectedByCat = type(cfg.selectedByCat) == "table" and cfg.selectedByCat or {}
            if H._hasSelection(cfg.selected) then
                cfg.selectedByCat[catKey] = H._normalizeSet(cfg.selected)
            elseif type(cfg.selectedByCat[catKey]) == "table" then
                cfg.selected = H._normalizeSet(cfg.selectedByCat[catKey])
            end
            selectedMap = H._selectedMapForSend(catKey)
            if not H._hasSelection(selectedMap) and not H._isHarvestedFruitsCategory(catKey) then
                abortEarly("Select at least 1 item in list")
                return
            end

            sendJobCancel = false
            H._resetNormalGiftHistoryAcc()
            H._setStatus(string.format("Near %s — preparing...", targetSnap.name))
        end)

        if not okPrep then
            abortEarly("Send error: " .. tostring(prepErr))
            return
        end
        if sendBusy == false then
            return
        end

        isHarvest = H._isHarvestedFruitsCategory(catKey)

        H._syncSendTotalFromUi()
        local priceMode = H._usesPriceMode(catKey)
        local goal = H._clampSendTotalGoal(cfg.send_total, priceMode)

        local function ensureNearTargetPlayer(targetPlayer)
            if not targetPlayer then return false, "player_left" end
            local near, err = H._ensureNearTarget(targetPlayer)
            if near == true then return true end
            if err == "too_far" then
                H._setStatus(string.format(
                    "Too far (%.0f studs) — enable teleport to target",
                    H._distanceToPlayer(targetPlayer)
                ))
            elseif err == "tp_fail" then
                H._setStatus("Teleport to target failed")
            end
            return false, err or "too_far"
        end

        local function noteUuidTry(uuid)
            uuid = tostring(uuid or "")
            if uuid == "" then return 0 end
            uuidTries[uuid] = (uuidTries[uuid] or 0) + 1
            return uuidTries[uuid]
        end

        local function recordConfirmedSend(item, unitPrice)
            unitPrice = math.max(0, math.floor(tonumber(unitPrice) or 0))
            if unitPrice <= 0 and item and H._isHarvestedFruitsCategory(item.giftType) then
                unitPrice = math.max(0, math.floor(tonumber(item._plannedSendPrice) or 0))
                if unitPrice <= 0 then
                    unitPrice = math.max(0, math.floor(H._candidateHarvestPrice(item)))
                end
            end
            sent += 1
            if unitPrice > 0 then
                sentPrice += unitPrice
            end
            stats.sentCount += 1
            failStreak = 0
            local uuid = tostring(item and item.uuid or "")
            if uuid ~= "" and H._isHarvestedFruitsCategory(item.giftType) then
                skipUuids[uuid] = true
            end
            H._accumulateNormalGiftHistoryRow(item, catKey, unitPrice, 1)
            return true
        end

        local function handleSendFailure(reason, item)
            local uuid = tostring(item and item.uuid or "")
            local harvestItem = H._isHarvestedFruitsCategory(item and item.giftType or catKey)
            if reason == "no_uuid" or reason == "favorited" then
                if harvestItem and uuid ~= "" then
                    skipUuids[uuid] = true
                    if reason == "favorited" then
                        local af = H._getAutoFavModule()
                        if type(af) == "table" and type(af.MarkFruitIdFavorited) == "function" then
                            pcall(af.MarkFruitIdFavorited, af, uuid)
                        end
                    end
                end
                if reason == "favorited" then
                    H._setStatus(string.format(
                        "Skip favorited (%d/%d)...",
                        math.floor(tonumber(sent) or 0),
                        math.floor(tonumber(goal) or tonumber(cfg.send_total) or 1)
                    ))
                elseif reason ~= "favorited" then
                    failStreak += 1
                end
                return
            end
            if reason == "not_removed" or reason == "remote_fail" then
                if harvestItem and H._isHarvestItemFavorited(item) then
                    skipUuids[uuid] = true
                    local af = H._getAutoFavModule()
                    if type(af) == "table" and type(af.MarkFruitIdFavorited) == "function" then
                        pcall(af.MarkFruitIdFavorited, af, uuid)
                    end
                    H._setStatus(string.format(
                        "Skip favorited (%d/%d)...",
                        math.floor(tonumber(sent) or 0),
                        math.floor(tonumber(goal) or tonumber(cfg.send_total) or 1)
                    ))
                    return
                end
                if harvestItem then
                    local tries = noteUuidTry(uuid)
                    if uuid ~= "" and tries >= SEND_UUID_MAX_TRIES then
                        skipUuids[uuid] = true
                    end
                end
                if reason == "not_removed" then
                    H._setStatus(string.format(
                        "Not removed (%ds) — retry kirim...",
                        SEND_GAP_SEC
                    ))
                end
                failStreak += 1
                return
            end
            failStreak += 1
        end

        local function trySendItem(targetPlayer, item, unitPrice)
            unitPrice = math.max(0, math.floor(tonumber(unitPrice) or 0))
            local near, nearErr = ensureNearTargetPlayer(targetPlayer)
            if not near then
                if nearErr == "player_left" then
                    abortReason = "player_left"
                end
                return false, nearErr or "too_far"
            end
            local ok, reason = H._sendOneGift(targetPlayer, item)
            if ok then
                recordConfirmedSend(item, unitPrice)
                if isHarvest then
                    local sendUuid = tostring(item and item.uuid or "")
                    if sendUuid ~= "" then
                        harvestPriceByUuid[sendUuid] = nil
                    end
                    toolByUuidCache = nil
                    H._invalidateSendCandidatesCache()
                end
                return true, "confirmed"
            end
            handleSendFailure(reason, item)
            return false, reason
        end

        sendJobFavCache = {}
        sendJobFsvPrimed = false
        toolByUuidCache = nil
        if isHarvest then
            local ag = H._getAutoGiftModule()
            if type(ag) == "table" and type(ag.GetHarvestFruitBag) == "function" then
                pcall(ag.GetHarvestFruitBag, ag, false)
            end
        end
        H._setStatus(string.format("Near %s — scan harvest...", targetSnap.name))
        local layoutReady = type(G.__GAG2_NORMAL_GIFT_BACKPACK_LAYOUT) == "table"
            or (virtualFruitCache and #virtualFruitCache > 0)
        local sendCandidates = H._collectSendCandidatesCached(catKey, selectedMap, not layoutReady, not layoutReady)
        if #sendCandidates == 0 then
            sendCandidates = H._collectSendCandidatesCached(catKey, selectedMap, true, true)
        end
        if #sendCandidates == 0 then
            if isHarvest then
                abortEarly("No sendable harvest — buah favorited tidak bisa di-gift")
            else
                abortEarly("No matching giftable items for selected category")
            end
            return
        end
        sendCandidatesCache = sendCandidates
        sendCandidatesCacheAt = os.clock()

        if isHarvest then
            harvestCache, harvestCacheUnits, harvestCachePrice = H._buildHarvestUuidCache(
                sendCandidates, goal, priceMode
            )
            if priceMode then
                if harvestCachePrice < 1 then
                    if not H._getFruitSellValue() then
                        abortEarly("FruitSellValue belum load — re-execute hub")
                        return
                    end
                    abortEarly("No sendable harvest items with value for selection")
                    return
                end
                local targetMin = select(1, H._priceRangeForRemain(goal))
                if harvestCachePrice < targetMin then
                    abortEarly(string.format(
                        "Value kurang: punya %s, butuh %s",
                        H._formatSellPrice(harvestCachePrice),
                        H._formatSellPrice(targetMin)
                    ))
                    return
                end
            else
                if harvestCacheUnits < 1 then
                    abortEarly("No sendable harvest UUID for selection")
                    return
                end
                if goal > harvestCacheUnits then
                    abortEarly(string.format(
                        "Item kurang: punya %d, butuh %d",
                        harvestCacheUnits,
                        goal
                    ))
                    return
                end
            end
        else
            local availUnits = H._estimateCandidateUnits(sendCandidates)
            if availUnits < 1 then
                abortEarly("No sendable units for selected items")
                return
            end
            if not priceMode and goal > availUnits then
                abortEarly(string.format(
                    "Item kurang: punya %d, butuh %d",
                    availUnits,
                    goal
                ))
                return
            end
        end

        if priceMode then
            local targetMin = select(1, H._priceRangeForRemain(goal))
            H._setStatus(string.format(
                "Sending 0/%s to %s... (queue %d uuid)",
                H._formatSellPrice(targetMin),
                targetSnap.name,
                harvestCacheUnits
            ))
        else
            H._setStatus(string.format(
                "Sending 0/%d to %s... (ready %d)",
                goal,
                targetSnap.name,
                isHarvest and harvestCacheUnits or H._estimateCandidateUnits(sendCandidates)
            ))
        end

        local okLoop, loopErr = pcall(function()
            if priceMode then
                local targetMin, targetMax = H._priceRangeForRemain(goal)
                while not sendJobCancel do
                    if sentPrice >= targetMin then break end

                    local targetPlayer = H._resolveSendTarget(targetSnap)
                    if not targetPlayer then
                        abortReason = "player_left"
                        break
                    end

                    local filtered = H._harvestPricePoolFromCache(harvestCache, skipUuids)
                    if #filtered == 0 then
                        failStreak += 1
                        if failStreak >= 6 then break end
                        H._setStatus(string.format(
                            "Waiting harvest... (%s/%s)",
                            H._formatSellPrice(sentPrice),
                            H._formatSellPrice(targetMin)
                        ))
                        task.wait(0.35)
                    else
                        local remainMin = math.max(1, targetMin - sentPrice)
                        local remainMax = math.max(remainMin, targetMax - sentPrice)
                        local pickRow, unitPrice = H._planPricePickOne(filtered, remainMin, remainMax)
                        if not pickRow or (unitPrice or 0) <= 0 then
                            failStreak += 1
                            H._setStatus(string.format(
                                "No price match (%s–%s) — %d buah",
                                H._formatSellPrice(remainMin),
                                H._formatSellPrice(remainMax),
                                #filtered
                            ))
                            if failStreak >= 6 then break end
                            task.wait(0.35)
                        else
                            unitPrice = math.floor(tonumber(unitPrice) or 0)
                            local item = pickRow._ngItem
                            if not item then
                                failStreak += 1
                                H._setStatus("Pick item missing — retry...")
                                if failStreak >= 6 then break end
                                task.wait(0.2)
                            else
                                if sentPrice + unitPrice > targetMax then
                                    local uuid = tostring(item.uuid or pickRow.ItemKey or "")
                                    if uuid ~= "" then skipUuids[uuid] = true end
                                    failStreak += 1
                                    H._setStatus(string.format(
                                        "Skip %s (> max %s) — cari buah lebih kecil",
                                        H._formatSellPrice(unitPrice),
                                        H._formatSellPrice(targetMax)
                                    ))
                                    if failStreak >= 6 then break end
                                    task.wait(1)
                                else
                                    item._plannedSendPrice = unitPrice
                                    H._setStatus(string.format(
                                        "Sending %s/%s to %s...",
                                        H._formatSellPrice(sentPrice + unitPrice),
                                        H._formatSellPrice(targetMin),
                                        targetPlayer.Name
                                    ))
                                    trySendItem(targetPlayer, item, unitPrice)
                                    if sentPrice >= targetMin then break end
                                end
                            end
                        end
                    end
                end
            elseif isHarvest then
                local pickIndex = 1
                while not sendJobCancel do
                    if sent >= goal then break end

                    local targetPlayer = H._resolveSendTarget(targetSnap)
                    if not targetPlayer then
                        abortReason = "player_left"
                        break
                    end

                    local entry = H._pickHarvestCacheEntry(harvestCache, skipUuids, pickIndex)
                    if not entry or not entry.item then
                        failStreak += 1
                        if failStreak >= 6 then break end
                        H._setStatus(string.format("Waiting harvest... (%d/%d)", sent, goal))
                        task.wait(0.35)
                    else
                        pickIndex += 1
                        local unitPrice = math.max(0, math.floor(tonumber(entry.price) or 0))
                        if unitPrice <= 0 and entry.item then
                            unitPrice = H._harvestItemPrice(entry.item)
                            entry.price = unitPrice
                        end
                        if entry.item then entry.item._plannedSendPrice = unitPrice end
                        H._setStatus(string.format(
                            "Sending %d/%d to %s...",
                            sent + 1,
                            goal,
                            targetPlayer.Name
                        ))
                        trySendItem(targetPlayer, entry.item, unitPrice)
                    end
                end
            else
                while not sendJobCancel do
                    if sent >= goal then break end

                    local targetPlayer = H._resolveSendTarget(targetSnap)
                    if not targetPlayer then
                        abortReason = "player_left"
                        break
                    end

                    H._invalidateSendCandidatesCache()
                    local liveCandidates = H._collectSendCandidates(catKey, selectedMap, false)
                    local item = H._pickCandidate(liveCandidates, sent + 1, skipUuids)
                    if not item or H._candidateUnitCount(item) < 1 then
                        failStreak += 1
                        if failStreak >= 6 then break end
                        H._setStatus(string.format("Waiting items... (%d/%d)", sent, goal))
                        task.wait(0.35)
                    else
                        H._setStatus(string.format(
                            "Sending %d/%d to %s...",
                            sent + 1,
                            goal,
                            targetPlayer.Name
                        ))
                        trySendItem(targetPlayer, item, 0)
                    end
                end
            end
        end)

        if not okLoop then
            finalMessage = "Send error: " .. tostring(loopErr)
            H._setStatus(finalMessage)
        elseif priceMode then
            local targetMin = select(1, H._priceRangeForRemain(goal))
            if abortReason == "player_left" then
                if sent > 0 then
                    finalMessage = string.format(
                        "Partial (%d buah, %s) — player left → @%s",
                        sent,
                        H._formatSellPrice(sentPrice),
                        targetSnap.name
                    )
                    H._setStatus(finalMessage)
                else
                    finalMessage = "Send stopped — player left server"
                    H._setStatus(finalMessage)
                end
            elseif sentPrice >= targetMin and sent > 0 then
                finalMessage = string.format(
                    "Gift completed (%d buah, %s) → %s",
                    sent,
                    H._formatSellPrice(sentPrice),
                    targetSnap.name
                )
                H._setStatus(finalMessage)
            elseif sent > 0 then
                finalMessage = string.format(
                    "Partial (%d buah, %s) — out of items → @%s",
                    sent,
                    H._formatSellPrice(sentPrice),
                    targetSnap.name
                )
                H._setStatus(finalMessage)
            elseif sent == 0 then
                if failStreak >= 6 then
                    finalMessage = "Send failed — harvest plan stuck (cek fruit layout & selection)"
                else
                    finalMessage = "Send failed — item not confirmed removed"
                end
                H._setStatus(finalMessage)
            end
        elseif abortReason == "player_left" then
            if sent > 0 then
                finalMessage = string.format(
                    "Partial (%d/%d) — player left → @%s",
                    sent,
                    goal,
                    targetSnap.name
                )
                H._setStatus(finalMessage)
            else
                finalMessage = "Send stopped — player left server"
                H._setStatus(finalMessage)
            end
        elseif sent >= goal then
            if isHarvest and sentPrice > 0 then
                finalMessage = string.format(
                    "Gift completed (%d buah, %s) → %s",
                    sent,
                    H._formatSellPrice(sentPrice),
                    targetSnap.name
                )
            else
                finalMessage = string.format("Gift completed (%d/%d) → %s", sent, goal, targetSnap.name)
            end
            H._setStatus(finalMessage)
        elseif sent > 0 then
            finalMessage = string.format(
                "Partial (%d/%d) — out of items → @%s",
                sent,
                goal,
                targetSnap.name
            )
            H._setStatus(finalMessage)
        elseif isHarvest then
            local histUnits = type(sendJobHistoryAcc) == "table"
                and math.floor(tonumber(sendJobHistoryAcc.totalUnits) or 0) or 0
            if histUnits > 0 then
                finalMessage = string.format(
                    "Gift completed (%d/%d) → %s",
                    histUnits,
                    goal,
                    targetSnap.name
                )
                H._setStatus(finalMessage)
            else
                finalMessage = "Send failed — item not confirmed removed (cek fruit layout)"
                H._setStatus(finalMessage)
            end
        else
            finalMessage = "Send failed — item not confirmed removed"
            H._setStatus(finalMessage)
        end

        finishJob()
    end)

    return true, "started"
end

function M.ApplyConfig(nextCfg)
    if not H._looksLikeConfigPatch(nextCfg) then return end
    if nextCfg.target_user_id ~= nil then
        cfg.target_user_id = math.floor(tonumber(nextCfg.target_user_id) or 0)
    end
    if nextCfg.target_name ~= nil then
        cfg.target_name = tostring(nextCfg.target_name or "")
    end
    if nextCfg.category ~= nil and tostring(nextCfg.category) ~= "" then
        cfg.category = H._canonicalCategory(nextCfg.category)
    end
    if type(nextCfg.selectedByCat) == "table" then
        cfg.selectedByCat = {}
        for cat, sel in pairs(nextCfg.selectedByCat) do
            local ck = H._canonicalCategory(cat)
            if ck ~= "" then
                cfg.selectedByCat[ck] = H._normalizeSet(sel)
            end
        end
    end
    if type(nextCfg.selected) == "table" then
        local cur = H._canonicalCategory(nextCfg.category or cfg.category)
        cfg.selected = H._normalizeSet(nextCfg.selected)
        cfg.selectedByCat = type(cfg.selectedByCat) == "table" and cfg.selectedByCat or {}
        if cur ~= "" then
            cfg.selectedByCat[cur] = cfg.selected
        end
    elseif cfg.category ~= "" and type(cfg.selectedByCat) == "table" then
        local cur = H._canonicalCategory(cfg.category)
        if type(cfg.selectedByCat[cur]) == "table" then
            cfg.selected = H._normalizeSet(cfg.selectedByCat[cur])
        end
    end
    if nextCfg.send_total ~= nil then
        cfg.send_total = H._clampSendTotalGoal(nextCfg.send_total, H._usesPriceMode(nextCfg.category or cfg.category))
    end
    if nextCfg.send_mode ~= nil then
        cfg.send_mode = H._normalizeSendMode(nextCfg.send_mode)
    end
    if nextCfg.harvest_price_threshold_pct ~= nil then
        local pct = math.floor(tonumber(nextCfg.harvest_price_threshold_pct) or 10)
        if pct < 0 then pct = 0 end
        if pct > 100 then pct = 100 end
        cfg.harvest_price_threshold_pct = pct
    end
    if nextCfg.harvest_price_calc_mode ~= nil then
        cfg.harvest_price_calc_mode = H._normalizeHarvestPriceCalcMode(nextCfg.harvest_price_calc_mode)
    end
    if nextCfg.teleport_to_target ~= nil then
        cfg.teleport_to_target = (nextCfg.teleport_to_target == true)
    end
    G.__GAG2_NORMAL_GIFT = M.GetConfig()
    _G.__GAG2_NORMAL_GIFT = G.__GAG2_NORMAL_GIFT
end

function M.GetConfig()
    local catKey = H._canonicalCategory(cfg.category)
    return {
        target_user_id = cfg.target_user_id,
        target_name = cfg.target_name,
        category = catKey,
        selected = H._normalizeSet(cfg.selected),
        selectedByCat = type(cfg.selectedByCat) == "table" and cfg.selectedByCat or {},
        send_total = cfg.send_total,
        send_mode = H._normalizeSendMode(cfg.send_mode),
        harvest_price_threshold_pct = H._harvestPriceThresholdPct(),
        harvest_price_calc_mode = H._harvestPriceCalcMode(),
        teleport_to_target = cfg.teleport_to_target == true,
    }
end

function M.ParseSendTotalPrice(a, b)
    local raw = b
    if type(a) == "string" or type(a) == "number" then raw = a end
    return H._parseSendTotalPrice(raw)
end

function M.FormatSendTotalPrice(a, b)
    local n = b
    if type(a) == "number" then n = a end
    n = math.floor(tonumber(n) or 0)
    if n <= 0 then return "0" end
    if n >= 1000000000 then return string.format("%.2fB", n / 1000000000) end
    if n >= 1000000 then return string.format("%.2fM", n / 1000000) end
    if n >= 1000 then return string.format("%.1fK", n / 1000) end
    return tostring(n)
end

function M.EstimateSendableHarvestPrice(a, b, c)
    local catKey = a
    local selectedMap = b
    if type(a) == "table" and type(b) == "string" then
        catKey = b
        selectedMap = c
    end
    catKey = H._canonicalCategory(tostring(catKey or cfg.category or "HarvestedFruits"))
    if type(selectedMap) ~= "table" then
        selectedMap = H._selectedMapForCategory(catKey)
    end
    return H._estimateSendableHarvestPrice(catKey, selectedMap)
end

function M.EstimateSendableUnits(a, b, c)
    local catKey = a
    local selectedMap = b
    if type(a) == "table" and type(b) == "string" then
        catKey = b
        selectedMap = c
    end
    catKey = H._canonicalCategory(tostring(catKey or cfg.category or "HarvestedFruits"))
    if type(selectedMap) ~= "table" then
        selectedMap = H._selectedMapForCategory(catKey)
    end
    return H._estimateSendableUnits(catKey, selectedMap)
end

function M.CheckSendTotalAvailability(a, b)
    local patch = (H._looksLikeConfigPatch(a) and b == nil) and a or nil
    if patch then
        M.ApplyConfig(patch)
    else
        M.SyncFromGlobals()
    end

    local function failCheck(msg)
        msg = tostring(msg or "Item kurang")
        H._setStatus(msg)
        return false, msg
    end

    local catKey = H._canonicalCategory(tostring(cfg.category or ""))
    if catKey == "" then catKey = "Seeds" end
    local selectedMap = H._selectedMapForSend(catKey)
    local priceMode = H._usesPriceMode(catKey)
    local goal = H._clampSendTotalGoal(cfg.send_total, priceMode)
    if goal < 1 then return true end

    local sendCandidates = H._collectSendCandidatesCached(catKey, selectedMap, false, false)
    if #sendCandidates == 0 then
        if H._isHarvestedFruitsCategory(catKey) then
            return failCheck("No sendable harvest — buah favorited / tidak ada buah")
        end
        return failCheck("Tidak ada item giftable di inventory untuk category terpilih")
    end

    local isHarvest = H._isHarvestedFruitsCategory(catKey)
    if priceMode then
        local _, _, availablePrice = H._buildHarvestUuidCache(sendCandidates, goal, true)
        if availablePrice < 1 then
            if not H._getFruitSellValue() then
                return failCheck("FruitSellValue belum load — re-execute hub")
            end
            return failCheck("No sendable harvest items with value for selection")
        end
        local targetMin = select(1, H._priceRangeForRemain(goal))
        if availablePrice < targetMin then
            return failCheck(string.format(
                "Value kurang: punya %s, butuh %s",
                H._formatSellPrice(availablePrice),
                H._formatSellPrice(targetMin)
            ))
        end
    else
        local available
        if isHarvest then
            _, available = H._buildHarvestUuidCache(sendCandidates, goal, false)
        else
            available = H._estimateCandidateUnits(sendCandidates)
        end
        available = math.floor(tonumber(available) or 0)
        if available < 1 then
            return failCheck("Tidak ada item giftable di inventory untuk category terpilih")
        end
        if available < goal then
            return failCheck(string.format("Item kurang: punya %d, butuh %d", available, goal))
        end
    end
    return true
end

function M.GetStats()
    return {
        lastStatus = stats.lastStatus,
        lastError = stats.lastError,
        sentCount = stats.sentCount,
        busy = sendBusy,
    }
end

function M.IsHarvestFavorited(uuidOrItem)
    if type(uuidOrItem) == "table" then
        return H._isHarvestItemFavorited(uuidOrItem) == true
    end
    return H._isHarvestItemFavorited({
        uuid = tostring(uuidOrItem or ""),
        giftType = "HarvestedFruits",
    }) == true
end

function H._listToolAttributeLines(tool)
    local lines = {}
    pcall(function()
        for name, val in pairs(tool:GetAttributes()) do
            lines[#lines + 1] = tostring(name) .. "=" .. tostring(val)
        end
    end)
    table.sort(lines)
    return lines
end

function M.PrintDebug(catKey)
    catKey = H._canonicalCategory(tostring(catKey or cfg.category or "Seeds"))
    if catKey == "" then catKey = "Seeds" end

    local lines = {}
    local function line(msg)
        msg = tostring(msg or "")
        lines[#lines + 1] = msg
        print("[NormalGift] " .. msg)
    end

    line("=== NormalGift Debug ===")
    line("category=" .. catKey)
    line("ControllersStarted=" .. tostring(LP:HasTag("ControllersStarted")))

    local map = H._ensureGiftAttrMap(5)
    if map then
        line("gift attr map: loaded")
        for _, attr in ipairs(GIFT_ATTR_ORDER or {}) do
            line("  " .. attr .. " -> " .. tostring(map[attr]))
        end
    else
        line("gift attr map: NOT loaded (wait/rejoin)")
    end

    local toolCount = 0
    local instCount = 0
    local giftableCount = 0
    H._foreachGiftInstance(function(inst)
        instCount += 1
        if inst:IsA("Tool") then toolCount += 1 end
        local parentName = inst.Parent and inst.Parent.Name or "?"
        local attrText = table.concat(H._listToolAttributeLines(inst), ", ")
        local info = H._toolGiftInfo(inst)
        if info then
            giftableCount += 1
