                "INST #%d parent=%s class=%s name=%s NOT giftable attrs=[%s]",
                instCount, parentName, inst.ClassName, inst.Name, attrText
            ))
        end
    end)
    line("instances=" .. instCount .. " tools=" .. toolCount .. " giftable=" .. giftableCount)

    local items = H._toolsAsUiItems(catKey)
    line("UI items for " .. catKey .. ": " .. #items)
    for i = 1, math.min(#items, 25) do
        local it = items[i]
        line("  item[" .. i .. "] key=" .. tostring(it.key) .. " name=" .. tostring(it.name))
    end

    local sel = H._selectedMapForCategory(catKey)
    local selCount = 0
    for _, v in pairs(sel) do
        if v == true then selCount += 1 end
    end
    line("selected count=" .. selCount)
    line("=== end debug ===")

    return table.concat(lines, "\n")
end

local PlayerStateClient = nil

function H._ensurePlayerState()
    if PlayerStateClient then return true end
    local function tryRequire(modInst)
        if not modInst then return false end
        local ok, mod = pcall(require, modInst)
        if ok and type(mod) == "table" then
            PlayerStateClient = mod
            return true
        end
        return false
    end
    local cm = ReplicatedStorage:FindFirstChild("ClientModules")
    if cm and tryRequire(cm:FindFirstChild("PlayerStateClient")) then return true end
    local ok = pcall(function()
        return tryRequire(ReplicatedStorage:WaitForChild("ClientModules", 5):WaitForChild("PlayerStateClient"))
    end)
    return ok and PlayerStateClient ~= nil
end

function H._getPlayerStateInventory(waitSec)
    waitSec = tonumber(waitSec) or 2
    if not H._ensurePlayerState() then return nil end
    if type(PlayerStateClient.GetLocalReplica) ~= "function" then return nil end
    local replica = PlayerStateClient:GetLocalReplica()
    local deadline = os.clock() + waitSec
    while not replica and os.clock() < deadline do
        task.wait(0.1)
        replica = PlayerStateClient:GetLocalReplica()
    end
    if not replica or type(replica.Data) ~= "table" then return nil end
    local inv = replica.Data.Inventory
    return type(inv) == "table" and inv or nil
end

function H._countBagEntries(bag)
    if type(bag) ~= "table" then return 0 end
    local nested = bag.List or bag.Items
    if type(nested) == "table" and #nested > 0 then return #nested end
    local n = 0
    for k, v in pairs(bag) do
        if tostring(k):sub(1, 1) ~= "_" then
            n += 1
        end
    end
    return n
end

function H._summarizeBagEntry(entry, itemKey)
    itemKey = tostring(itemKey or "")
    if type(entry) == "table" then
        local parts = {}
        for _, field in ipairs({ "Id", "UUID", "Name", "DisplayName", "Type", "Count", "Amount", "Qty" }) do
            local val = entry[field]
            if val ~= nil and tostring(val) ~= "" then
                parts[#parts + 1] = field .. "=" .. tostring(val)
            end
        end
        if #parts > 0 then return table.concat(parts, ", ") end
        return "table"
    end
    return "count=" .. tostring(entry)
end

function M.PrintInventoryDebug()
    local lines = {}
    local function line(msg)
        msg = tostring(msg or "")
        lines[#lines + 1] = msg
        print("[NormalGift-Inv] " .. msg)
    end

    line("=== Inventory Debug (Normal Gift vs PlayerState) ===")
    line("Normal Gift source = Tool di Backpack/Character (BUKAN inventory virtual)")
    line("ControllersStarted=" .. tostring(LP:HasTag("ControllersStarted")))

    local map = H._ensureGiftAttrMap(5)
    if map then
        line("gift attr map: loaded")
        for _, attr in ipairs(GIFT_ATTR_ORDER or {}) do
            line("  " .. attr .. " -> " .. tostring(map[attr]))
        end
    else
        line("gift attr map: NOT loaded")
    end

    line("")
    line("--- A) GIFT INSTANCES (Backpack/Character/player folders) ---")
    local instCount = 0
    local toolCount = 0
    local giftableByType = {}
    H._foreachGiftInstance(function(inst)
        instCount += 1
        if inst:IsA("Tool") then toolCount += 1 end
        local parentName = inst.Parent and inst.Parent.Name or "?"
        local attrText = table.concat(H._listToolAttributeLines(inst), ", ")
        local info = H._toolGiftInfo(inst)
        if info then
            giftableByType[info.giftType] = (giftableByType[info.giftType] or 0) + 1
            line(string.format(
                "INST parent=%s class=%s name=%s giftType=%s key=%s uuid=%s attrs=[%s]",
                parentName, inst.ClassName, inst.Name, info.giftType, info.key, info.uuid, attrText
            ))
        else
            line(string.format(
                "INST parent=%s class=%s name=%s NOT giftable attrs=[%s]",
                parentName, inst.ClassName, inst.Name, attrText
            ))
        end
    end)
    line("instances total=" .. instCount .. " tools=" .. toolCount)
    line("player FruitCount=" .. tostring(LP:GetAttribute("FruitCount"))
        .. " MaxFruitCapacity=" .. tostring(LP:GetAttribute("MaxFruitCapacity")))
    line("Backpack.GetLayout fruits=" .. #H._getVirtualFruits(true))
    local cats = M.GetCategoryDefs()
    line("giftable categories from tools=" .. #cats)
    for _, def in ipairs(cats) do
        line("  cat " .. def.key .. " tools=" .. tostring(giftableByType[def.key] or 0))
    end

    line("")
    line("--- B) PLAYERSTATE INVENTORY (virtual, untuk Gift Mail) ---")
    local inv = H._getPlayerStateInventory(3)
    if not inv then
        line("PlayerState inventory: NOT available")
    else
        local bagKeys = {}
        for key in pairs(inv) do
            if type(inv[key]) == "table" then
                bagKeys[#bagKeys + 1] = tostring(key)
            end
        end
        table.sort(bagKeys)
        line("inventory bags=" .. #bagKeys)
        for _, bagKey in ipairs(bagKeys) do
            local bag = inv[bagKey]
            local entryCount = H._countBagEntries(bag)
            line("  bag[" .. bagKey .. "] entries=" .. entryCount)
            local shown = 0
            if type(bag) == "table" then
                local nested = bag.List or bag.Items
                if type(nested) == "table" and #nested > 0 then
                    for idx, entry in ipairs(nested) do
                        shown += 1
                        if shown <= 8 then
                            line("    [" .. idx .. "] " .. H._summarizeBagEntry(entry, idx))
                        end
                    end
                else
                    for itemKey, entry in pairs(bag) do
                        if tostring(itemKey):sub(1, 1) ~= "_" then
                            shown += 1
                            if shown <= 8 then
                                line("    [" .. tostring(itemKey) .. "] " .. H._summarizeBagEntry(entry, itemKey))
                            end
                        end
                    end
                end
                if shown > 8 then
                    line("    ... +" .. (shown - 8) .. " more")
                end
            end
        end
    end

    line("")
    line("--- C) UI preview per category ---")
    for _, def in ipairs(cats) do
        local items = H._toolsAsUiItems(def.key)
        line("  " .. def.key .. " uiItems=" .. #items)
    end
    line("=== end inventory debug ===")

    return table.concat(lines, "\n")
end

function H._harvestRejectReason(inst)
    if not inst or type(inst.GetAttribute) ~= "function" then return "invalid instance" end
    if inst:GetAttribute("SeedTool") ~= nil then return "has SeedTool (seed pack)" end
    if inst:GetAttribute("Pet") ~= nil then return "has Pet attribute" end
    if inst:GetAttribute("PottedPlant") == true then return "PottedPlant=true" end
    if tostring(inst:GetAttribute("MainCategory") or "") == "Seed" then return "MainCategory=Seed" end

    local hf = inst:GetAttribute("HarvestedFruit")
    local fruitName = inst:GetAttribute("FruitName") or inst:GetAttribute("Fruit")
    local parts = {
        "class=" .. inst.ClassName,
        "FruitName=" .. tostring(fruitName),
        "FruitProxy=" .. tostring(inst:GetAttribute("FruitProxy")),
        "Id=" .. tostring(inst:GetAttribute("Id")),
        "HarvestedFruit=" .. tostring(hf),
        "Mutation=" .. tostring(inst:GetAttribute("Mutation")),
        "SizeMultiplier=" .. tostring(inst:GetAttribute("SizeMultiplier")),
    }
    return "bukan harvest fruit (perlu FruitName/FruitProxy/HarvestedFruit) | " .. table.concat(parts, " ")
end

function M.PrintHarvestDebug()
    local lines = {}
    local function line(msg)
        msg = tostring(msg or "")
        lines[#lines + 1] = msg
        print("[NormalGift-Harvest] " .. msg)
    end

    line("=== HarvestedFruit Debug ===")
    line("Sumber: Backpack.GetLayout (virtual fruit layout)")
    line("Kirim: Gifting.Send(userId, type, uuid) — langsung dari layout UUID")
    line("Gifting.Send = (userId, giftType, uuid) per Networking decompile")

    local map = H._ensureGiftAttrMap(5)
    if map then
        line("map HarvestedFruit -> " .. tostring(map.HarvestedFruit or "MISSING"))
    else
        line("gift map NOT loaded")
    end

    line("Backpack API ready=" .. tostring(H._ensureBackpackNetworking()))
    line("player FruitCount=" .. tostring(LP:GetAttribute("FruitCount"))
        .. " MaxFruitCapacity=" .. tostring(LP:GetAttribute("MaxFruitCapacity")))

    local virtualFruits = H._getVirtualFruits(true)
    local layoutOnly = 0
    local instanceOnly = 0
    for _, info in ipairs(virtualFruits) do
        if info.source == "layout" then layoutOnly += 1
        elseif info.source == "instance" then instanceOnly += 1 end
    end
    line("Backpack.GetLayout fruits=" .. #virtualFruits
        .. " (layout=" .. layoutOnly .. " instance=" .. instanceOnly .. ")")
    if #virtualFruits == 0 and H._ensureBackpackNetworking() then
        local layout = G.__GAG2_NORMAL_GIFT_BACKPACK_LAYOUT or rawget(_G, "__GAG2_NORMAL_GIFT_BACKPACK_LAYOUT")
        if type(layout) == "table" then
            local keys = {}
            for k in pairs(layout) do keys[#keys + 1] = tostring(k) end
            table.sort(keys)
            line("layout top-level keys: " .. table.concat(keys, ", "))
        end
    end
    for i = 1, math.min(#virtualFruits, 12) do
        local info = virtualFruits[i]
        local fav = false
        if type(info) == "table" then
            local probe = {
                uuid = info.uuid,
                raw = info.raw,
                giftType = "HarvestedFruits",
            }
            fav = H._isHarvestItemFavorited(probe)
        end
        line(string.format(
            "LAYOUT #%d uuid=%s key=%s hasTool=%s fav=%s",
            i, tostring(info.uuid), tostring(info.key),
            tostring(H._findToolByFruitId(info.uuid) ~= nil),
            tostring(fav)
        ))
    end

    local fruitLike = 0
    local giftable = 0
    local withTool = 0
    H._foreachGiftInstance(function(inst)
        local parentName = inst.Parent and inst.Parent.Name or "?"
        local attrs = table.concat(H._listToolAttributeLines(inst), ", ")
        if H._instLooksLikeHarvestedFruit(inst) then
            fruitLike += 1
            local info = H._toolGiftInfo(inst)
            local sendTool = info and H._resolveSendTool(inst, info)
            if sendTool then withTool += 1 end
            if info and info.giftType == "HarvestedFruits" then
                giftable += 1
                line(string.format(
                    "OK parent=%s class=%s name=%s key=%s uuid=%s hasTool=%s attrs=[%s]",
                    parentName, inst.ClassName, inst.Name, info.key, info.uuid,
                    tostring(sendTool ~= nil), attrs
                ))
            else
                line(string.format(
                    "FRUIT-LIKE but not giftable parent=%s class=%s name=%s attrs=[%s]",
                    parentName, inst.ClassName, inst.Name, attrs
                ))
            end
        end
    end)

    line("fruit-like instances=" .. fruitLike .. " giftable HarvestedFruits=" .. giftable
        .. " with sendable Tool=" .. withTool)
    line("category HarvestedFruits uiItems=" .. #H._toolsAsUiItems("HarvestedFruits"))

    if fruitLike == 0 and #virtualFruits == 0 then
        line("")
        line("Tidak ada buah di Backpack.GetLayout maupun Tool client.")
        line("Harvest/collect buah dulu, lalu debug lagi.")
        line("")
        line("Sample non-fruit instances (max 5):")
        local shown = 0
        H._foreachGiftInstance(function(inst)
            if shown >= 5 then return end
            if not H._instLooksLikeHarvestedFruit(inst) then
                shown += 1
                local parentName = inst.Parent and inst.Parent.Name or "?"
                line("  " .. parentName .. "/" .. inst.Name .. " (" .. inst.ClassName .. ") | " .. H._harvestRejectReason(inst))
            end
        end)
    elseif withTool == 0 and #virtualFruits > 0 then
        line("")
        line("Buah ada di layout — Normal Gift kirim langsung via Gifting.Send(uuid).")
    end

    local inv = H._getPlayerStateInventory(2)
    if inv then
        line("")
        line("PlayerState bags dengan 'fruit' di nama:")
        local found = false
        for key, bag in pairs(inv) do
            if type(bag) == "table" and tostring(key):lower():find("fruit", 1, true) then
                found = true
                line("  bag[" .. tostring(key) .. "] entries=" .. H._countBagEntries(bag))
            end
        end
        if not found then
            line("  (tidak ada — harvest fruit memang bukan virtual bag)")
        end
    end

    line("=== end harvest debug ===")
    return table.concat(lines, "\n")
end

function M.SyncFromGlobals()
    local uiReady = G.__GAG2_NORMAL_GIFT_UI_READY == true
        or rawget(_G, "__GAG2_NORMAL_GIFT_UI_READY") == true

    if uiReady then
        if not sendBusy then
            H._syncCfgFromUi()
            local store = G.__GAG2_NORMAL_GIFT or _G.__GAG2_NORMAL_GIFT
            if type(store) == "table" then
                if store.target_user_id ~= nil or store.target_name ~= nil then
                    M.ApplyConfig({
                        target_user_id = store.target_user_id,
                        target_name = store.target_name,
                        category = store.category,
                        selected = store.selected,
                        send_total = store.send_total,
                        teleport_to_target = store.teleport_to_target,
                    })
                end
            end
        end
        return
    end

    local store = G.__GAG2_NORMAL_GIFT or _G.__GAG2_NORMAL_GIFT
    if type(store) == "table" then
        M.ApplyConfig(store)
    end
    local main = G.MAIN or rawget(_G, "MAIN")
    if type(main) == "table" and type(main.auto) == "table" and type(main.auto.normalGift) == "table" then
        local ngMain = main.auto.normalGift
        local patch = {
            target_user_id = ngMain.target_user_id,
            target_name = ngMain.target_name,
            category = ngMain.category,
            send_total = ngMain.send_total,
            teleport_to_target = ngMain.teleport_to_target,
        }
        if type(ngMain.selectedByCat) == "table" then
            patch.selectedByCat = ngMain.selectedByCat
        end
        if type(ngMain.selected) == "table" then
            patch.selected = ngMain.selected
        end
        M.ApplyConfig(patch)
    end
end

G.NormalGift = M
G.NormalGiftModule = M
G.NormalGiftDebug = M.PrintDebug
G.NormalGiftInventoryDebug = M.PrintInventoryDebug
G.NormalGiftHarvestDebug = M.PrintHarvestDebug
_G.NormalGift = M
_G.NormalGiftModule = M
_G.NormalGiftDebug = M.PrintDebug
_G.NormalGiftInventoryDebug = M.PrintInventoryDebug
_G.NormalGiftHarvestDebug = M.PrintHarvestDebug

task.spawn(function()
    for _ = 1, 12 do
        if H._ensureNetworking() then break end
        task.wait(0.25)
    end
    if H._ensureBackpackNetworking() then
        pcall(function()
            local ag = H._getAutoGiftModule()
            if type(ag) == "table" and type(ag.GetHarvestFruitBag) == "function" then
                pcall(ag.GetHarvestFruitBag, ag, false)
            end
            H._getVirtualFruits(true, true)
        end)
    end
end)

task.defer(function()
    H._waitForControllersStarted(8)
    for _ = 1, 16 do
        if H._ensureGiftAttrMap(0) then break end
        task.wait(0.25)
    end
    if virtualFruitCache == nil and H._ensureBackpackNetworking() then
        M.PrefetchHarvestSources()
    end
    M.SyncFromGlobals()
    if stats.lastStatus == "Ready" then
        H._setStatus("Ready")
    end
    H._refreshNormalGiftItemDropdown()
    local refresh = G.__GAG2_NORMAL_GIFT_CAT_DD or rawget(_G, "__GAG2_NORMAL_GIFT_CAT_DD")
    if type(refresh) == "table" and type(refresh.refreshItems) == "function" then
        pcall(refresh.refreshItems, refresh)
    end
end)

return M
 end,                     required = false },
    { key = "AutoShovel",              name = "Auto Shovel",             factory = function() -- AutoShovel.lua - Grow A Garden 2
-- Equip shovel -> Networking.Shovel.UseShovel:Fire(plantId, fruitId, shovelType, tool)

local Players           = game:GetService("Players")
local ReplicatedStorage = game:GetService("ReplicatedStorage")
local RunService        = game:GetService("RunService")

local LP = Players.LocalPlayer
local G  = (getgenv and getgenv()) or _G
local M  = {}

local UseShovel     = nil
local remotesReady  = false
local LOOP_SEC      = 0.72
local SHOVEL_CD     = 0.68

local running       = false
local loopId        = 0
local shovelBusy    = false
local lastShovelAt  = 0
local plantsConn    = nil
local plotConn      = nil

local stats = {
    attempts = 0,
    ok = 0,
    skipped = {},
    lastError = nil,
    lastPlantId = nil,
    lastSkip = nil,
}

local function _dbg()
    return G.AUTO_SHOVEL_DEBUG == true or _G.AUTO_SHOVEL_DEBUG == true
end

local function _log(...)
    if not _dbg() then return end
    print("[GAG2-AS]", ...)
end

local function _enabled()
    local store = G.__GAG2_SHOVEL or rawget(_G, "__GAG2_SHOVEL")
    if type(store) == "table" and store.enabled == true then return true end
    return G.AUTO_SHOVEL_ENABLED == true or rawget(_G, "AUTO_SHOVEL_ENABLED") == true
end

local function _selectedMap()
    local map = G.AUTO_SHOVEL_PLANTS_SELECTED or rawget(_G, "AUTO_SHOVEL_PLANTS_SELECTED")
    if type(map) == "table" then
        if map._none then map._none = nil end
        return map
    end
    local store = G.__GAG2_SHOVEL or rawget(_G, "__GAG2_SHOVEL")
    if type(store) == "table" and type(store.plants) == "table" then
        map = {}
        for _, id in ipairs(store.plants) do
            if id ~= nil and tostring(id) ~= "" and tostring(id) ~= "_none" then
                map[tostring(id)] = true
            end
        end
        return map
    end
    return {}
end

local function _selectedCount()
    local n = 0
    for k, v in pairs(_selectedMap()) do
        if v == true and k ~= "_none" then n = n + 1 end
    end
    return n
end

local function _canRun()
    return _enabled() and _selectedCount() >= 1
end

function M.GetSelectedCount()
    return _selectedCount()
end
M.getSelectedCount = M.GetSelectedCount

function M.HasSelection()
    return _selectedCount() >= 1
end
M.hasSelection = M.HasSelection

function M.CanRun()
    return _canRun()
end
M.canRun = M.CanRun

local function _initRemotes()
    if remotesReady then return end
    remotesReady = true
    local ok, Networking = pcall(function()
        return require(ReplicatedStorage.SharedModules.Networking)
    end)
    if not ok or type(Networking) ~= "table" then
        stats.lastError = "Networking require gagal"
        return
    end
    local ShovelNet = Networking.Shovel
    if type(ShovelNet) == "table" and type(ShovelNet.UseShovel) == "table"
        and type(ShovelNet.UseShovel.Fire) == "function" then
        UseShovel = ShovelNet.UseShovel
    end
    if not UseShovel then
        stats.lastError = "UseShovel MISSING"
        warn("[GAG2-AS] UseShovel remote tidak ditemukan")
    end
end

local function _getPlot()
    local plotId = LP and LP:GetAttribute("PlotId")
    if not plotId then return nil end
    local gardens = workspace:FindFirstChild("Gardens")
    if not gardens then return nil end
    return gardens:FindFirstChild("Plot" .. tostring(plotId))
end

local function _getPlantsFolder()
    local plot = _getPlot()
    return plot and plot:FindFirstChild("Plants") or nil
end

function M.GetPlantDisplayName(plant)
    if not plant then return "?" end
    return plant:GetAttribute("SeedName")
        or plant:GetAttribute("ConfigPathName")
        or plant:GetAttribute("CorePartName")
        or plant:GetAttribute("FruitType")
        or plant:GetAttribute("ItemName")
        or plant.Name
end
M.getPlantDisplayName = M.GetPlantDisplayName

local function _mutationNamesFallback()
    local PLV = G.PlantListView or rawget(_G, "PlantListView")
    if type(PLV) == "table" and type(PLV.listMutationNames) == "function" then
        local ok, list = pcall(PLV.listMutationNames, PLV)
        if ok and type(list) == "table" and #list > 0 then return list end
    end
    return { "Gold", "Rainbow" }
end

-- Dex: plant punya attribute string "Mutation" = "Gold" / "Rainbow" / ...
function M.GetPlantMutation(plant)
    if not plant then return nil end
    local mut = plant:GetAttribute("Mutation")
    if type(mut) == "string" then
        mut = mut:gsub("^%s+", ""):gsub("%s+$", "")
        if mut ~= "" and mut:lower() ~= "none" and mut:lower() ~= "normal" then
            return mut
        end
    end
    for _, name in ipairs(_mutationNamesFallback()) do
        if plant:GetAttribute(name) == true then
            return name
        end
    end
    return nil
end
M.getPlantMutation = M.GetPlantMutation

function M.GetPlantTypeKey(plant)
    local name = M.GetPlantDisplayName(plant)
    name = tostring(name or ""):gsub("^%s+", ""):gsub("%s+$", "")
    if name == "" then name = plant and plant.Name or "Unknown" end
    local mut = M.GetPlantMutation(plant)
    if mut then
        return mut .. " " .. name
    end
    return name
end
M.getPlantTypeKey = M.GetPlantTypeKey

local function _plantMatchesSelection(plant, sel)
    if not plant or type(sel) ~= "table" then return false end
    local typeKey = M.GetPlantTypeKey(plant)
    if sel[typeKey] then return true end
    -- backward compat: save lama pakai instance Name
    if sel[plant.Name] then return true end
    return false
end

function M.BuildGardenPlantItems()
    local items = {}
    local folder = _getPlantsFolder()
    if not folder then return items end

    local groups = {}
    for _, plant in ipairs(folder:GetChildren()) do
        local typeKey = M.GetPlantTypeKey(plant)
        local g = groups[typeKey]
        if not g then
            g = { key = typeKey, name = typeKey, count = 0 }
            groups[typeKey] = g
        end
        g.count = g.count + 1
    end

    for _, g in pairs(groups) do
        items[#items + 1] = {
            key = g.key,
            name = string.format("%s x %d", g.name, g.count),
            count = g.count,
        }
    end

    table.sort(items, function(a, b)
        return tostring(a.name) < tostring(b.name)
    end)
    return items
end
M.buildGardenPlantItems = M.BuildGardenPlantItems

function M.GetActiveTypeKeys()
    local out = {}
    for _, item in ipairs(M.BuildGardenPlantItems()) do
        local k = item and item.key
        if k and k ~= "" and k ~= "_none" then
            out[tostring(k)] = true
        end
    end
    return out
end
M.getActiveTypeKeys = M.GetActiveTypeKeys

-- Buang tipe dari selection kalau sudah tidak ada di garden
function M.PruneSelectionToGarden(sel)
    sel = type(sel) == "table" and sel or _selectedMap()
    local active = M.GetActiveTypeKeys()
    local out = {}
    local removed = {}
    for k, v in pairs(sel) do
        if v == true and k ~= "_none" then
            if active[k] then
                out[k] = true
            else
                removed[#removed + 1] = k
            end
        end
    end
    return out, #removed > 0, removed
end
M.pruneSelectionToGarden = M.PruneSelectionToGarden

local function _notifyPlantsChanged()
    local fn = G.__GAG2_ON_SHOVEL_PLANTS_CHANGED or rawget(_G, "__GAG2_ON_SHOVEL_PLANTS_CHANGED")
    if type(fn) == "function" then
        pcall(fn)
    end
end

local function _unbindPlantsWatch()
    if plantsConn then plantsConn:Disconnect() plantsConn = nil end
    if plotConn then plotConn:Disconnect() plotConn = nil end
end

local function _bindPlantsWatch(folder)
    _unbindPlantsWatch()
    if not folder then return end
    plantsConn = folder.ChildAdded:Connect(function()
        task.defer(_notifyPlantsChanged)
    end)
    folder.ChildRemoved:Connect(function()
        task.defer(_notifyPlantsChanged)
    end)
    local plot = folder.Parent
    if plot then
        plotConn = plot.ChildAdded:Connect(function(ch)
            if ch.Name == "Plants" then
                _bindPlantsWatch(ch)
                _notifyPlantsChanged()
            end
        end)
    end
end

local function _getEquippedShovel()
    local char = LP and LP.Character
    if not char then return nil end
    for _, ch in ipairs(char:GetChildren()) do
        if ch:IsA("Tool") and ch:GetAttribute("Shovel") then
            return ch
        end
    end
    return nil
end

local function _equipShovel()
    if _getEquippedShovel() then return true end
    local char = LP and LP.Character
    local hum = char and char:FindFirstChildOfClass("Humanoid")
    local bp = LP and LP:FindFirstChild("Backpack")
    if not hum or not bp then return false end
    for _, tool in ipairs(bp:GetChildren()) do
        if tool:IsA("Tool") and tool:GetAttribute("Shovel") then
            local ok = pcall(function() hum:EquipTool(tool) end)
            if ok and _getEquippedShovel() then return true end
        end
    end
    return false
end

local function _shovelPlantInst(plant)
    _initRemotes()
    if not UseShovel or not plant or not plant.Parent then return false, "no_plant" end

    if os.clock() - lastShovelAt < SHOVEL_CD then
        return false, "cooldown"
    end

    if not _equipShovel() then
        stats.lastError = "shovel_not_equipped"
        return false, "no_tool"
    end

    local tool = _getEquippedShovel()
    if not tool then return false, "no_tool" end

    local shovelType = tool:GetAttribute("Shovel")
    if shovelType == nil then return false, "no_shovel_attr" end

    local plantId = plant.Name
    local ok, err = pcall(function()
        UseShovel:Fire(plantId, "", shovelType, tool)
    end)
    lastShovelAt = os.clock()
    stats.attempts = stats.attempts + 1
    stats.lastPlantId = plantId

    if ok then
        stats.ok = stats.ok + 1
        _log("UseShovel", plantId, M.GetPlantTypeKey(plant))
        return true, plantId
    end

    stats.lastError = tostring(err)
    return false, "fire_fail"
end

local function _tick()
    if not _canRun() then return end
    if shovelBusy then return end

    local folder = _getPlantsFolder()
    if not folder then return end

    local sel = _selectedMap()
    shovelBusy = true
    pcall(function()
        for _, plant in ipairs(folder:GetChildren()) do
            if _plantMatchesSelection(plant, sel) then
                local ok = _shovelPlantInst(plant)
                if ok then break end
                task.wait(0.05)
            end
        end
    end)
    shovelBusy = false
end

local function shovelLoop(myId)
    _initRemotes()
    _bindPlantsWatch(_getPlantsFolder())
    _log("loop start")

    while running and loopId == myId do
        local ok, err = pcall(_tick)
        if not ok then
            stats.lastError = tostring(err)
            warn("[GAG2-AS] loop error:", err)
        end
        if _canRun() then
            RunService.Heartbeat:Wait()
            task.wait(LOOP_SEC)
        elseif _enabled() then
            task.wait(0.5)
        else
            task.wait(0.5)
        end
    end
    _unbindPlantsWatch()
    _log("loop stop")
end

function M.Start()
    _initRemotes()
    if running then return end
    running = true
    loopId = loopId + 1
    local myId = loopId
    task.spawn(function() shovelLoop(myId) end)
end
M.start = M.Start

function M.Stop()
    running = false
    _unbindPlantsWatch()
end
M.stop = M.Stop

function M.IsRunning()
    return running == true
end

function M.SetEnabled(on)
    on = (on == true)
    if type(G.__GAG2_SHOVEL) ~= "table" then G.__GAG2_SHOVEL = {} end
    G.__GAG2_SHOVEL.enabled = on
    _G.__GAG2_SHOVEL = G.__GAG2_SHOVEL
    G.AUTO_SHOVEL_ENABLED = on
    _G.AUTO_SHOVEL_ENABLED = on
    if on then
        M.ApplyRuntime(true)
    else
        M.Stop()
    end
    return on
end
M.setEnabled = M.SetEnabled

function M.ApplyRuntime(on)
    if on == true and not M.HasSelection() then
        M.Stop()
        stats.lastSkip = "no_selection"
        return false
    end
    if on then M.Start() else M.Stop() end
    return on == true
end
M.applyRuntime = M.ApplyRuntime

function M.SyncFromGlobals()
    M.SetEnabled(_enabled())
end
M.syncFromGlobals = M.SyncFromGlobals
M.SyncFromState = M.SyncFromGlobals
M.syncFromState = M.SyncFromGlobals

function M.ShovelOnce()
    if not _canRun() then return 0 end
    local n = 0
    local sel = _selectedMap()
    local folder = _getPlantsFolder()
    if not folder then return 0 end
    for _, plant in ipairs(folder:GetChildren()) do
        if _plantMatchesSelection(plant, sel) then
            local ok = _shovelPlantInst(plant)
            if ok then n = n + 1 break end
        end
    end
    return n
end
M.shovelOnce = M.ShovelOnce

function M.GetDiagnostics()
    _initRemotes()
    local folder = _getPlantsFolder()
    local active = M.BuildGardenPlantItems()
    local sel = _selectedMap()
    local selCount = 0
    for _ in pairs(sel) do selCount = selCount + 1 end
    return {
        enabled = _enabled(),
        running = running,
        remote = UseShovel ~= nil,
        plantsFolder = folder and folder:GetFullName() or nil,
        plantCount = #active,
        selectedCount = selCount,
        hasSelection = selCount >= 1,
        canRun = _canRun(),
        hasShovel = _getEquippedShovel() ~= nil,
        stats = stats,
    }
end
M.getDiagnostics = M.GetDiagnostics

function M.PrintDiagnostics()
    if _enabled() and not running then M.Start() end
    local d = M.GetDiagnostics()
    print("========== GAG2 Auto Shovel ==========")
    print("enabled:", d.enabled, "| running:", d.running)
    print("remote UseShovel:", d.remote and "OK" or "MISSING")
    print("types:", d.plantCount, "| selected:", d.selectedCount, "| canRun:", d.canRun)
    print("folder:", d.plantsFolder or "MISSING (PlotId?)")
    print("shovel equipped:", d.hasShovel)
    print("stats ok=", stats.ok, " attempts=", stats.attempts)
    if stats.lastError then print("lastError:", stats.lastError) end
    local sel = _selectedMap()
    for _, item in ipairs(M.BuildGardenPlantItems()) do
        local mark = sel[item.key] and "[x]" or "[ ]"
        print(" ", mark, item.name)
    end
    print("======================================")
    return d
end
M.printDiagnostics = M.PrintDiagnostics

G.AutoShovel = M
G.AutoShovelModule = M
_G.AutoShovel = M
_G.AutoShovelModule = M

return M
 end,                     required = false },
    { key = "AutoShovelFruit",         name = "Auto Shovel Fruit",       factory = function() -- AutoShovelFruit.lua — shovel fruit di garden by filter rules (UseShovel remote)

local Players           = game:GetService("Players")
