function M.Register(ctx)
    if type(ctx) ~= "table" or type(ctx.ui) ~= "table" then return end

    local ui = ctx.ui
    local getAuto = ctx.getAuto
    local patchAuto = ctx.patchAuto
    local patchAutoOnly = ctx.patchAutoOnly
    local registerFlush = ctx.registerFlush
    local toggleApiGet = ctx.toggleApiGet

    local SF_STATE = getAuto("shovelFruit")
    SF_STATE.enabled = (SF_STATE.enabled == true)
    do
        local d = tonumber(SF_STATE.delay)
        if d == nil then d = 0.72 end
        if d < 0 then d = 0 end
        if d > 5 then d = 5 end
        SF_STATE.delay = d
    end
    SF_STATE.rules = type(SF_STATE.rules) == "table" and SF_STATE.rules or {}
    SF_STATE.rulesOrder = type(SF_STATE.rulesOrder) == "table" and SF_STATE.rulesOrder or {}
    SF_STATE.filterMode = "rules"

    local function sfLive()
        if type(getAuto) == "function" then
            local ok, st = pcall(getAuto, "shovelFruit")
            if ok and type(st) == "table" then return st end
        end
        return SF_STATE
    end

    local function delayDisplay()
        local n = tonumber(sfLive().delay)
        return (n ~= nil) and n or 0.72
    end

    local function readDelayFromUi()
        local fn = G.__GAG2_SHOVEL_FRUIT_DELAY_API or rawget(_G, "__GAG2_SHOVEL_FRUIT_DELAY_API")
        if type(fn) == "function" then
            local ok, v = pcall(fn)
            if ok and v ~= nil then
                local n = tonumber(v)
                if n ~= nil then
                    if n < 0 then n = 0 end
                    if n > 5 then n = 5 end
                    return n
                end
            end
        end
        return delayDisplay()
    end

    local function snapshot()
        local st = sfLive()
        local on = toggleApiGet and toggleApiGet("__GAG2_SHOVEL_FRUIT_ENABLE_API")
        return {
            enabled = on ~= nil and on or (st.enabled == true),
            delay = readDelayFromUi(),
            filterMode = "rules",
            rules = st.rules,
            rulesOrder = st.rulesOrder,
        }
    end

    registerFlush("shovelFruit", function()
        patchAutoOnly("shovelFruit", snapshot())
    end)

    G.AUTO_SHOVEL_FRUIT_ENABLED = SF_STATE.enabled
    _G.AUTO_SHOVEL_FRUIT_ENABLED = SF_STATE.enabled
    G.AUTO_SHOVEL_FRUIT_DELAY = SF_STATE.delay
    _G.AUTO_SHOVEL_FRUIT_DELAY = SF_STATE.delay
    G.AUTO_SHOVEL_FRUIT_FILTER_MODE = "rules"
    _G.AUTO_SHOVEL_FRUIT_FILTER_MODE = "rules"
    G.AUTO_SHOVEL_FRUIT_RULES = SF_STATE.rules
    _G.AUTO_SHOVEL_FRUIT_RULES = SF_STATE.rules
    G.AUTO_SHOVEL_FRUIT_RULES_ORDER = SF_STATE.rulesOrder
    _G.AUTO_SHOVEL_FRUIT_RULES_ORDER = SF_STATE.rulesOrder

    local function syncAutoShovelFruitModule()
        local st = sfLive()
        G.AUTO_SHOVEL_FRUIT_ENABLED = (st.enabled == true)
        _G.AUTO_SHOVEL_FRUIT_ENABLED = G.AUTO_SHOVEL_FRUIT_ENABLED
        G.AUTO_SHOVEL_FRUIT_DELAY = delayDisplay()
        _G.AUTO_SHOVEL_FRUIT_DELAY = G.AUTO_SHOVEL_FRUIT_DELAY
        G.AUTO_SHOVEL_FRUIT_FILTER_MODE = "rules"
        _G.AUTO_SHOVEL_FRUIT_FILTER_MODE = "rules"
        G.AUTO_SHOVEL_FRUIT_RULES = st.rules
        _G.AUTO_SHOVEL_FRUIT_RULES = st.rules
        G.AUTO_SHOVEL_FRUIT_RULES_ORDER = st.rulesOrder
        _G.AUTO_SHOVEL_FRUIT_RULES_ORDER = st.rulesOrder

        local mod = G.AutoShovelFruit or G.AutoShovelFruitModule or rawget(_G, "AutoShovelFruit")
        if type(mod) ~= "table" then return end
        local function __call(fn, ...)
            if type(mod[fn]) == "function" then pcall(mod[fn], ...) end
        end
        __call("SetDelay", G.AUTO_SHOVEL_FRUIT_DELAY)
        __call("setDelay", G.AUTO_SHOVEL_FRUIT_DELAY)
        __call("SetFilterMode", "rules")
        __call("setFilterMode", "rules")
        __call("SetRules", G.AUTO_SHOVEL_FRUIT_RULES, G.AUTO_SHOVEL_FRUIT_RULES_ORDER)
        __call("setRules", G.AUTO_SHOVEL_FRUIT_RULES, G.AUTO_SHOVEL_FRUIT_RULES_ORDER)
        if G.AUTO_SHOVEL_FRUIT_ENABLED then
            __call("EnsureRunning")
            __call("ensureRunning")
        else
            __call("Stop")
            __call("stop")
        end
    end

    G.__GAG2_SYNC_AUTO_SHOVEL_FRUIT = syncAutoShovelFruitModule
    _G.__GAG2_SYNC_AUTO_SHOVEL_FRUIT = syncAutoShovelFruitModule

    local function getBreakdown()
        local mod = G.AutoShovelFruit or G.AutoShovelFruitModule or rawget(_G, "AutoShovelFruit")
        if type(mod) == "table" and type(mod.PeekHarvestBreakdown) == "function" then
            local ok, br = pcall(mod.PeekHarvestBreakdown, mod)
            if ok and type(br) == "table" then
                return {
                    inFilter = math.max(0, math.floor(tonumber(br.inFilter) or 0)),
                    outFilter = math.max(0, math.floor(tonumber(br.outFilter) or 0)),
                    scanning = br.scanning == true,
                }
            end
        end
        return { inFilter = 0, outFilter = 0, scanning = false }
    end

    local body = ui:CreateSection("Auto Shovel Fruit", false)

    local _, statusInFilter = ui:CreateRowLabel(body, "Match filter: ...", nil, nil, "muted")
    local _, statusOutFilter = ui:CreateRowLabel(body, "Skipped: ...", nil, nil, "muted")

    local function refreshStatus()
        local br = getBreakdown()
        local mod = G.AutoShovelFruit or G.AutoShovelFruitModule
        local st
        if type(mod) == "table" and type(mod.GetStats) == "function" then
            local ok, s = pcall(mod.GetStats, mod)
            if ok and type(s) == "table" then st = s end
        end
        local runHint = "OFF"
        if st then
            if st.enabled ~= true then
                runHint = "OFF"
            elseif st.remoteReady ~= true then
                runHint = "no remote"
            elseif st.running == true then
                runHint = "running"
            else
                runHint = "paused"
            end
        end
        if statusInFilter and statusInFilter.Parent then
            local hint = runHint
            if br.scanning == true then
                hint = "updating..."
            end
            statusInFilter.Text = ("Match filter: %d  (%s)"):format(br.inFilter or 0, hint)
        end
        if statusOutFilter and statusOutFilter.Parent then
            statusOutFilter.Text = ("Skipped: %d"):format(br.outFilter or 0)
        end
    end

    task.defer(function() pcall(refreshStatus) end)
    task.spawn(function()
        while body and body.Parent do
            local waitSec = 5
            local br = getBreakdown()
            if br.scanning == true then waitSec = 2 end
            task.wait(waitSec)
            pcall(refreshStatus)
        end
    end)

    local rulesCtx = {
        rulesKind = "shovel_fruit",
        RULES_STATE = SF_STATE,
        SF_STATE = SF_STATE,
        body = body,
        ui = ui,
        getAuto = getAuto,
        patchAuto = patchAuto,
        patchAutoOnly = patchAutoOnly,
        registerFlush = registerFlush,
        cleanSelectedMap = ctx.cleanSelectedMap,
        mapToArray = ctx.mapToArray,
        arrayToMap = ctx.arrayToMap,
        PlantListView = ctx.PlantListView or G.PlantListView,
        syncAutoShovelFruitModule = syncAutoShovelFruitModule,
    }

    do
        local SectionRules = G.SectionAutoCollectRules or rawget(_G, "SectionAutoCollectRules")
        if type(SectionRules) == "table" and type(SectionRules.RegisterSavedList) == "function" then
            pcall(SectionRules.RegisterSavedList, rulesCtx)
        end
    end
    do
        local SectionRules = G.SectionAutoCollectRules or rawget(_G, "SectionAutoCollectRules")
        if type(SectionRules) == "table" and type(SectionRules.RegisterBulk) == "function" then
            pcall(SectionRules.RegisterBulk, rulesCtx)
        end
    end

    local _, delayFn = ui:CreateRowInput(
        body,
        "Shovel Delay (sec)",
        tostring(delayDisplay()),
        function(txt)
            local n = tonumber(txt)
            if n == nil then return end
            if n < 0 then n = 0 end
            if n > 5 then n = 5 end
            SF_STATE.delay = n
            sfLive().delay = n
            G.AUTO_SHOVEL_FRUIT_DELAY = n
            _G.AUTO_SHOVEL_FRUIT_DELAY = n
            patchAuto("shovelFruit", { delay = n }, syncAutoShovelFruitModule)
        end,
        false
    )
    G.__GAG2_SHOVEL_FRUIT_DELAY_API = delayFn
    _G.__GAG2_SHOVEL_FRUIT_DELAY_API = delayFn

    local _, _, enableApi = ui:CreateRowToggle(
        body,
        "Enable Auto Shovel Fruit",
        (SF_STATE.enabled == true),
        function(isOn)
            SF_STATE.enabled = (isOn == true)
            sfLive().enabled = (isOn == true)
            patchAuto("shovelFruit", { enabled = isOn == true }, syncAutoShovelFruitModule)
        end
    )
    G.__GAG2_SHOVEL_FRUIT_ENABLE_API = enableApi
    _G.__GAG2_SHOVEL_FRUIT_ENABLE_API = enableApi

    syncAutoShovelFruitModule()
end

G.SectionAutoShovelFruit = M
_G.SectionAutoShovelFruit = M

return M
 end,   required = false },
    { key = "AutoTele",                name = "Auto Tele",               factory = function() -- AutoTele.lua — Grow A Garden 2
-- Runtime: persistent loop (same pattern as AutoClaimSeed)

local Players           = game:GetService("Players")
local CollectionService = game:GetService("CollectionService")

local LP = Players.LocalPlayer
local G  = (getgenv and getgenv()) or _G
local M  = {}

local MIN_DELAY      = 1
local DEFAULT_DELAY  = 10
local TP_OFFSET      = Vector3.new(0, 3, 0)
local SPAWN_SPAM_INTERVAL   = 1.0
local SPAWN_SPAM_MAX        = 60
local CENTER_RADIUS         = 6   -- jarak datar (XZ) ke center
local SPAWN_RADIUS          = 6   -- jarak datar (XZ) ke titik TP spawn (bukan 10 — terlalu longgar)
local GARDEN_NEAR_RADIUS    = 55
local SPAWN_TO_CENTER_DELAY = 2
local TP_SETTLE_SEC         = 0.2
local SPAWN_STAND_OFFSET    = 3   -- stud di atas permukaan part Spawn
local SPAWN_FORWARD_STUDS   = 20   -- setelah TP spawn, maju lagi sejauh ini (mode Garden Spawn)
local SPAWN_FORWARD_RADIUS  = 4   -- radius verifikasi titik maju (lebih ketat dari SPAWN_RADIUS)

local running        = false
local loopId         = 0
local tickBusy       = false
local pendingCenter  = false -- spawn gateway selesai, center belum (lanjut loop berikutnya)
local cachedPlot     = nil
local cachedGardenCf = nil

local function _truthy(v)
    return (v == true) or (v == 1) or (v == "true") or (v == "1")
end

local function _store()
    local s = rawget(_G, "__GAG2_AUTO_TELE")
    if type(s) ~= "table" then
        s = G.__GAG2_AUTO_TELE
    end
    if type(s) ~= "table" then
        local ge = (getgenv and getgenv()) or nil
        if type(ge) == "table" and type(ge.__GAG2_AUTO_TELE) == "table" then
            s = ge.__GAG2_AUTO_TELE
        end
    end
    return type(s) == "table" and s or nil
end

local function _enabled()
    local store = _store()
    if type(store) == "table" then
        return store.enabled == true
    end

    if G.AUTO_TELE_ENABLED == false or rawget(_G, "AUTO_TELE_ENABLED") == false then
        return false
    end

    local MAIN = G.MAIN or rawget(_G, "MAIN")
    if type(MAIN) == "table" and type(MAIN.auto) == "table"
        and type(MAIN.auto.autoTele) == "table" then
        return MAIN.auto.autoTele.enabled == true
    end

    return G.AUTO_TELE_ENABLED == true or rawget(_G, "AUTO_TELE_ENABLED") == true
end

local function _writeEnabled(on)
    on = (on == true)
    local store = _store()
    if type(store) ~= "table" then
        store = { enabled = on, delay = DEFAULT_DELAY, selectedLocation = "center" }
        G.__GAG2_AUTO_TELE = store
    end
    store.enabled = on
    G.__GAG2_AUTO_TELE = store
    _G.__GAG2_AUTO_TELE = store
    G.AUTO_TELE_ENABLED = on
    _G.AUTO_TELE_ENABLED = on

    local MAIN = G.MAIN or rawget(_G, "MAIN")
    if type(MAIN) == "table" then
        MAIN.auto = MAIN.auto or {}
        MAIN.auto.autoTele = MAIN.auto.autoTele or {}
        MAIN.auto.autoTele.enabled = on
        G.MAIN = MAIN
        _G.MAIN = MAIN
    end
    return on
end

local function _cfg()
    local s = _store()
    local delay = nil
    local loc = "center"

    if type(s) == "table" then
        delay = tonumber(s.delay)
        loc = tostring(s.selectedLocation or "center")
    end

    if not delay or delay <= 0 then
        local MAIN = G.MAIN or rawget(_G, "MAIN")
        if type(MAIN) == "table" and type(MAIN.auto) == "table"
            and type(MAIN.auto.autoTele) == "table" then
            delay = tonumber(MAIN.auto.autoTele.delay)
            if MAIN.auto.autoTele.selectedLocation then
                loc = tostring(MAIN.auto.autoTele.selectedLocation)
            end
        end
    end

    if not delay or delay <= 0 then delay = DEFAULT_DELAY end
    if delay < MIN_DELAY then delay = MIN_DELAY end
    if loc ~= "spawn" then loc = "center" end

    if type(s) == "table" then
        s.delay = delay
        s.selectedLocation = loc
        G.__GAG2_AUTO_TELE = s
        _G.__GAG2_AUTO_TELE = s
    end

    return {
        enabled = _enabled(),
        delay = delay,
        selectedLocation = loc,
    }
end

local function _hrp()
    local char = LP and LP.Character
    return char and char:FindFirstChild("HumanoidRootPart") or nil
end

local function _matchOwner(v)
    if v == nil or not LP then return false end
    return v == LP.UserId or v == LP.Name
        or tostring(v) == tostring(LP.UserId) or tostring(v) == LP.Name
end

local function _plotOwnedByLocal(plot)
    if not plot then return false end
    if _matchOwner(plot:GetAttribute("OwnerId")) then return true end
    if _matchOwner(plot:GetAttribute("Owner")) then return true end
    if _matchOwner(plot:GetAttribute("OwnerUserId")) then return true end
    if _matchOwner(plot:GetAttribute("UserId")) then return true end

    for _, child in ipairs(plot:GetChildren()) do
        if child:IsA("ValueBase") then
            local n = child.Name:lower()
            if n:find("owner") or n:find("userid") or n:find("player") then
                if _matchOwner(child.Value) then return true end
            end
        end
    end

    local myPlot = LP:GetAttribute("Plot") or LP:GetAttribute("PlotName")
        or LP:GetAttribute("GardenPlot") or LP:GetAttribute("PlotId")
    if myPlot and plot.Name == tostring(myPlot) then return true end
    if myPlot and plot.Name == ("Plot" .. tostring(myPlot)) then return true end

    return false
end

function M.GetPlayerPlot()
    local gardens = workspace:FindFirstChild("Gardens")
    if not gardens or not LP then return nil end

    local plotId = LP:GetAttribute("PlotId")
    local idStr = plotId ~= nil and tostring(plotId) or nil

    if cachedPlot and cachedPlot.Parent then
        if idStr then
            for _, name in ipairs({ "Plot" .. idStr, idStr, "Plot_" .. idStr }) do
                local expected = gardens:FindFirstChild(name)
                if expected and cachedPlot == expected then
                    return cachedPlot
                end
            end
        elseif _plotOwnedByLocal(cachedPlot) then
            return cachedPlot
        end
        cachedPlot = nil
        cachedGardenCf = nil
    end

    if idStr then
        for _, name in ipairs({ "Plot" .. idStr, idStr, "Plot_" .. idStr }) do
            local plot = gardens:FindFirstChild(name)
            if plot then
                cachedPlot = plot
                return plot
            end
        end
    end

    for _, plot in ipairs(gardens:GetChildren()) do
        if _plotOwnedByLocal(plot) then
            cachedPlot = plot
            return plot
        end
    end

    local hrp = _hrp()
    if hrp then
        local params = RaycastParams.new()
        params.FilterType = Enum.RaycastFilterType.Include
        params.FilterDescendantsInstances = { gardens }
        local hit = workspace:Raycast(hrp.Position + Vector3.new(0, 6, 0), Vector3.new(0, -40, 0), params)
        if hit then
            for _, plot in ipairs(gardens:GetChildren()) do
                if hit.Instance:IsDescendantOf(plot) and _plotOwnedByLocal(plot) then
                    cachedPlot = plot
                    return plot
                end
            end
        end
    end

    return nil
end

local function _collectPlotSurfaces(plot)
    local list, seen = {}, {}
    local function add(inst)
        if inst and not seen[inst] then
            seen[inst] = true
            list[#list + 1] = inst
        end
    end
    for _, inst in ipairs(CollectionService:GetTagged("PlantArea")) do
        if inst:IsDescendantOf(plot) then add(inst) end
    end
    if #list > 0 then return list end
    for _, desc in ipairs(plot:GetDescendants()) do
        if desc:IsA("BasePart") then
            local n = desc.Name:lower()
            if n:find("soil") or n:find("dirt") or n:find("ground")
                or n:find("farm") or n:find("plot") or n:find("grass") then
                add(desc)
            end
        end
    end
    if #list > 0 then return list end
    for _, desc in ipairs(plot:GetDescendants()) do
        if desc:IsA("BasePart") and desc.CanQuery ~= false then
            add(desc)
        end
    end
    return list
end

local function _findPlotSpawnPart(plot)
    if not plot then return nil end
    for _, name in ipairs({ "Spawn", "SpawnLocation", "GardenSpawn", "PlotSpawn" }) do
        local inst = plot:FindFirstChild(name)
        if inst and inst:IsA("BasePart") then return inst end
    end
    for _, desc in ipairs(plot:GetDescendants()) do
        if desc:IsA("BasePart") and (desc.Name == "Spawn" or desc.Name == "SpawnLocation") then
            return desc
        end
    end
    return nil
end

-- CFrame berdiri di atas part Spawn (ikut rotasi part, XZ = tepat di spawn).
local function _spawnStandCFrame(part)
    if not part or not part:IsA("BasePart") then return nil end
    return part.CFrame * CFrame.new(0, part.Size.Y * 0.5 + SPAWN_STAND_OFFSET, 0)
end

-- Titik akhir mode Garden Spawn: maju dari spawn mengikuti arah hadap part.
local function _spawnForwardCFrame(spawnCf)
    if typeof(spawnCf) ~= "CFrame" then return nil end
    return spawnCf * CFrame.new(0, 0, -SPAWN_FORWARD_STUDS)
end

function M.GetGardenPlotCFrame(plot)
    plot = plot or M.GetPlayerPlot()
    if not plot then return nil end

    local spawn = _findPlotSpawnPart(plot)
    if spawn then
        return _spawnStandCFrame(spawn)
    end

    if plot:IsA("Model") then
        local ok, cf = pcall(function() return plot:GetPivot() end)
        if ok and typeof(cf) == "CFrame" then
            return cf + TP_OFFSET
        end
    end

    return nil
end

function M.GetGardenCenterCFrame(plot)
    plot = plot or M.GetPlayerPlot()

    if plot then
        local areas = _collectPlotSurfaces(plot)
        if #areas > 0 then
            local sx, sy, sz, n = 0, 0, 0, 0
            for _, part in ipairs(areas) do
                if part:IsA("BasePart") then
                    local p = part.Position
                    sx = sx + p.X
                    sy = sy + p.Y + part.Size.Y * 0.5
                    sz = sz + p.Z
                    n = n + 1
                end
            end
            if n > 0 then
                cachedGardenCf = CFrame.new(sx / n, sy / n, sz / n) + TP_OFFSET
                return cachedGardenCf
            end
        end

        if plot:IsA("Model") then
            local okBB, cf, size = pcall(function() return plot:GetBoundingBox() end)
            if okBB and typeof(cf) == "CFrame" and typeof(size) == "Vector3" then
                cachedGardenCf = cf + Vector3.new(0, size.Y * 0.5, 0) + TP_OFFSET
                return cachedGardenCf
            end
            local ok, cf = pcall(function() return plot:GetPivot() end)
            if ok and typeof(cf) == "CFrame" then
                cachedGardenCf = cf + TP_OFFSET
                return cachedGardenCf
            end
        end

        local plotCf = M.GetGardenPlotCFrame(plot)
        if plotCf then
            cachedGardenCf = plotCf
            return cachedGardenCf
        end
    end

    return cachedGardenCf
end

function M.GetGardenSpawnCFrame(plot)
    plot = plot or M.GetPlayerPlot()
    if plot then
        local spawn = _findPlotSpawnPart(plot)
        if spawn then
            return _spawnStandCFrame(spawn)
        end
    end
    return M.GetGardenCenterCFrame(plot)
end

-- Spawn plot: part + CFrame tujuan TP.
local function _getPlotSpawnTarget(plot)
    plot = plot or M.GetPlayerPlot()
    if not plot then return nil, nil end
    local spawnPart = _findPlotSpawnPart(plot)
    if spawnPart then
        return spawnPart, _spawnStandCFrame(spawnPart)
    end
    local cf = M.GetGardenPlotCFrame(plot)
    return nil, cf
end

local function _flatDist(a, b)
    if not a or not b then return nil end
    local dx, dz = a.X - b.X, a.Z - b.Z
    return math.sqrt(dx * dx + dz * dz)
end

-- Verifikasi posisi: jarak DATAR (XZ) saja — abaikan Y (player di tanah, target +3 stud).
local function _flatWithinRadius(hrpPos, anchorPos, radius)
    if not hrpPos or not anchorPos then return false end
    return (_flatDist(hrpPos, anchorPos) or 999) <= (tonumber(radius) or SPAWN_RADIUS)
end

local function _spawnAnchorPos(_spawnPart, spawnCf)
    -- Verifikasi ke titik TP yang sama (bukan part.Position center yang bisa beda visual).
    if spawnCf then return spawnCf.Position end
    return nil
end

local function _atSpawn(hrpPos, spawnPart, spawnCf)
    local anchor = _spawnAnchorPos(spawnPart, spawnCf)
    return _flatWithinRadius(hrpPos, anchor, SPAWN_RADIUS)
end

local function _atSpawnForward(hrpPos, spawnCf)
    local forwardCf = _spawnForwardCFrame(spawnCf)
    if not forwardCf then return false end
    return _flatWithinRadius(hrpPos, forwardCf.Position, SPAWN_FORWARD_RADIUS)
end

local function _atCenter(hrpPos, centerCf)
    if not centerCf then return false end
    return _flatWithinRadius(hrpPos, centerCf.Position, CENTER_RADIUS)
end

local function _delayUnlessStopped(sec, myId)
    sec = tonumber(sec) or 0
    if sec <= 0 then return end
    local deadline = os.clock() + sec
    while running and loopId == myId and os.clock() < deadline do
        task.wait(0.05)
    end
end

local function _buyPetBusy()
    return G.__GAG2_AUTO_BUY_PET_BUSY == true
        or rawget(_G, "__GAG2_AUTO_BUY_PET_BUSY") == true
end

local function _claimSeedBusy()
    return G.__GAG2_AUTO_CLAIM_SEED_BUSY == true
        or rawget(_G, "__GAG2_AUTO_CLAIM_SEED_BUSY") == true
end

local function _suppressed()
    if _buyPetBusy() then return true end
    if _claimSeedBusy() then return true end
    return G.__GAG2_AUTO_TELE_SUPPRESS == true
        or rawget(_G, "__GAG2_AUTO_TELE_SUPPRESS") == true
end

local function _teleport(cf)
    if typeof(cf) ~= "CFrame" then return false end
    local char = LP and LP.Character
    local hrp = _hrp()
    if not char or not hrp then return false end

    local ok = pcall(function()
        if char.PrimaryPart then
            char:PivotTo(cf)
        else
            hrp.CFrame = cf
        end
    end)
    if ok then return true end

    ok = pcall(function()
        hrp.CFrame = cf
    end)
    return ok
end

-- Spam TP tiap 1s sampai jarak datar ke anchor <= radius.
local function _ensureAtAnchor(targetCf, anchorPos, myId, radius, maxAttempts)
    if typeof(targetCf) ~= "CFrame" or not anchorPos then return false end
    maxAttempts = tonumber(maxAttempts) or SPAWN_SPAM_MAX
    local attempts = 0

    while running and loopId == myId and _enabled() and not _suppressed() do
        local hrp = _hrp()
        if not hrp then return false end
        if _flatWithinRadius(hrp.Position, anchorPos, radius) then
            return true
        end

        _teleport(targetCf)
        attempts += 1
        task.wait(TP_SETTLE_SEC)
        hrp = _hrp()
        if hrp and _flatWithinRadius(hrp.Position, anchorPos, radius) then
            return true
        end
        if attempts >= maxAttempts then
            return hrp ~= nil and _flatWithinRadius(hrp.Position, anchorPos, radius)
        end

        task.wait(math.max(0, SPAWN_SPAM_INTERVAL - TP_SETTLE_SEC))
    end

    return false
end

function M.ResolveTargetCFrame()
    local cfg = _cfg()

    if cfg.selectedLocation == "spawn" then
        local cf = M.GetGardenSpawnCFrame()
        if cf then return _spawnForwardCFrame(cf) or cf end
        return cachedGardenCf
    end

    local cf = M.GetGardenCenterCFrame()
    if cf then return cf end
    return cachedGardenCf
end

function M.ClearSuppress()
    G.__GAG2_AUTO_TELE_SUPPRESS = false
    _G.__GAG2_AUTO_TELE_SUPPRESS = false
end
M.clearSuppress = M.ClearSuppress

local function _goToCenter(myId, plot, spawnCf)
    local hrp = _hrp()
    if not hrp then return false end

    local centerCf = M.GetGardenCenterCFrame(plot) or spawnCf
    if not centerCf then return false end
    if _atCenter(hrp.Position, centerCf) then
        pendingCenter = false
        return true
    end

    local ok = _ensureAtAnchor(centerCf, centerCf.Position, myId, CENTER_RADIUS, SPAWN_SPAM_MAX)
    if ok then
        pendingCenter = false
    end
    return ok
end

-- Setiap loop (belum di center): spawn dulu → delay 2s (jika baru TP spawn) → center.
local function _tickCenterMode(myId, plot, spawnPart, spawnCf)
    local hrp = _hrp()
    if not hrp then return false end

    local centerCf = M.GetGardenCenterCFrame(plot) or spawnCf
    if _atCenter(hrp.Position, centerCf) then
        pendingCenter = false
        return false
    end

    if pendingCenter then
        return _goToCenter(myId, plot, spawnCf)
    end

    local anchor = _spawnAnchorPos(spawnPart, spawnCf)
    local wasAtSpawn = _atSpawn(hrp.Position, spawnPart, spawnCf)

    if not wasAtSpawn then
        if not _ensureAtAnchor(spawnCf, anchor, myId, SPAWN_RADIUS, SPAWN_SPAM_MAX) then
            return false
        end
        pendingCenter = true
        _delayUnlessStopped(SPAWN_TO_CENTER_DELAY, myId)
        if not running or loopId ~= myId then
            return false
        end
    end

    return _goToCenter(myId, plot, spawnCf)
end

local function _tick(myId)
    myId = myId or loopId
    if tickBusy then return false end
    if not _enabled() or _suppressed() then return false end

    tickBusy = true
    local ok, result = pcall(function()
        local hrp = _hrp()
        if not hrp then return false end

        local cfg = _cfg()
        local plot = M.GetPlayerPlot()
        if not plot then return false end

        local spawnPart, spawnCf = _getPlotSpawnTarget(plot)
        if not spawnCf then return false end

        if cfg.selectedLocation == "spawn" then
            local forwardCf = _spawnForwardCFrame(spawnCf)
            if not forwardCf then return false end

            if _atSpawnForward(hrp.Position, spawnCf) then
                return false
            end

            if not _atSpawn(hrp.Position, spawnPart, spawnCf) then
                local anchor = _spawnAnchorPos(spawnPart, spawnCf)
                if not _ensureAtAnchor(spawnCf, anchor, myId, SPAWN_RADIUS, SPAWN_SPAM_MAX) then
                    return false
                end
            end

            return _ensureAtAnchor(
                forwardCf,
                forwardCf.Position,
                myId,
                SPAWN_FORWARD_RADIUS,
                SPAWN_SPAM_MAX
            )
        end

        return _tickCenterMode(myId, plot, spawnPart, spawnCf)
    end)

    tickBusy = false
    if ok then return result == true end
    return false
end

local function _loop(myId)
    if G.__GAG2_TELE_SKIP_FIRST_TICK == true or rawget(_G, "__GAG2_TELE_SKIP_FIRST_TICK") == true then
        task.wait(0.5)
    end
    while running and loopId == myId do
        local ok = pcall(function()
            if _enabled() and not _suppressed() then
                _tick(myId)
                task.wait(math.max(MIN_DELAY, _cfg().delay))
            else
                task.wait(0.5)
            end
        end)
        if not ok then
            task.wait(0.5)
        end
    end
end

function M.EnsureRunning()
    if not _enabled() then return end
    if not running then
        M.Start()
    end
end

function M.GetDelay()
    return _cfg().delay
end
M.getDelay = M.GetDelay

function M.SetDelay(sec)
    local d = tonumber(sec)
    if not d or d <= 0 then d = DEFAULT_DELAY end
    if d < MIN_DELAY then d = MIN_DELAY end

    local store = _store()
    if type(store) ~= "table" then
        store = { enabled = _enabled(), delay = d, selectedLocation = "center" }
    else
        store.delay = d
    end
    G.__GAG2_AUTO_TELE = store
    _G.__GAG2_AUTO_TELE = store

    local MAIN = G.MAIN or rawget(_G, "MAIN")
    if type(MAIN) == "table" then
        MAIN.auto = MAIN.auto or {}
        MAIN.auto.autoTele = MAIN.auto.autoTele or {}
        MAIN.auto.autoTele.delay = d
        G.MAIN = MAIN
        _G.MAIN = MAIN
    end
    return d
end
M.setDelay = M.SetDelay

function M.InvalidateCache()
    cachedPlot = nil
    cachedGardenCf = nil
end
M.invalidateCache = M.InvalidateCache

function M.Start()
    if not _enabled() then return end
    if running then return end
    running = true
    loopId = loopId + 1
    local myId = loopId
    task.spawn(_loop, myId)
end
M.start = M.Start

function M.Stop()
    running = false
    loopId = loopId + 1
    pendingCenter = false
end
M.stop = M.Stop

function M.IsRunning()
    return running == true
end

function M.IsEnabled()
    return _enabled()
end
M.isEnabled = M.IsEnabled

function M.ApplyRuntime(on)
    if on == nil then on = _enabled() end
    on = _truthy(on)
    _writeEnabled(on)
    if on then
        M.ClearSuppress()
        if running then M.Stop() end
        M.Start()
    else
        M.Stop()
        M.ClearSuppress()
    end
    return on
end
M.applyRuntime = M.ApplyRuntime

function M.SetEnabled(on)
    return M.ApplyRuntime(on)
end
M.setEnabled = M.SetEnabled

function M.TeleportNow()
    if _suppressed() then return false end
    return _tick()
end

function M.SyncFromState()
    M.EnsureRunning()
end

M.SyncFromGlobals = M.SyncFromState

-- watchdog: hanya hidupkan loop kalau mati (tidak bypass delay UI)
task.defer(function()
    while true do
        task.wait(1.5)
        if _enabled() and not running and not _suppressed() and not _buyPetBusy() and not _claimSeedBusy() then
            M.Start()
        end
    end
end)

G.AutoTele = M
G.AutoTeleModule = M
_G.AutoTele = M
_G.AutoTeleModule = M

if LP then
    pcall(function()
        LP:GetAttributeChangedSignal("PlotId"):Connect(function()
            cachedPlot = nil
            cachedGardenCf = nil
        end)
    end)
end

task.defer(function()
    if _enabled() then
        M.EnsureRunning()
    end
end)

return M
 end,                       required = false },
    { key = "AutoClaimSeed",           name = "Auto Claim Seed",         factory = function() -- AutoClaimSeed.lua - Grow A Garden 2
-- Alur: stop Auto Tele -> stick TP bawah seed (Y-7, 0.05s) -> follow claim sampai sukses
--       -> seed lain masih ada? lanjut : resume Auto Tele
-- Type spawn: hook game SpawnSeedPackController.SpawnClient + scan attribute/asset Seeds

local Players           = game:GetService("Players")
local ReplicatedStorage = game:GetService("ReplicatedStorage")
local RunService        = game:GetService("RunService")

local LP = Players.LocalPlayer
local G  = (getgenv and getgenv()) or _G
local M  = {}

local ClickPack       = nil
local SeedPackFX      = nil
local remotesReady    = false
local remotePath      = nil
local loopAliveId     = 0

local SCAN_SEC        = 0
local CLAIM_COOLDOWN  = 0.05
local ATTR_WAIT_SEC   = 0.18
local ATTR_POLL_SEC   = 0.005

local UNDER_Y         = -7
local STICK_SEC       = 0.05
local FOLLOW_FIRE_SEC = 0.12
local MAX_FOLLOW_SEC  = 90
local TP_STAND_DIST   = 2
local CLAIM_RANGE     = 18
local PREFIRE_MAX_DIST = 99999
local TP_OFFSET       = Vector3.new(0, 3, 0)
local AFTER_TP_SEC    = 0.05
local VERIFY_WAIT     = 0.2
local VERIFY_WAIT_FAST = 0.08
local CLAIM_COMPLETE_WAIT = 14
local CLAIM_VERDICT_WAIT  = 0.75
local CLAIM_POLL_SEC      = 0.04
local OPEN_UI_WAIT    = 0.18
local OPEN_UI_POLL    = 0.008
local OPEN_PROMPT_FIND_WAIT = 0.05
local OPEN_PROMPT_RETRY_SEC = 0.14
local OPEN_PROMPT_RETRIES   = 4
local VERIFY_POLL     = 0.004
local CLICK_NEAR_DIST = 50
local BURST_FIRE_GAP  = 0
local LOST_CLAIM_COOLDOWN = 2.5

local running       = false
local loopId        = 0
local claimBusy     = false
local spawnFolder   = nil
local childConn     = nil
local attrConns     = {}
local mapConn       = nil
local fxConn        = nil
local claimedConn   = nil
local claimCooldown = {}
local savedGardenCf = nil
local lastScanInfo  = { count = 0, ready = 0, at = 0 }
local lastFxAt      = 0
local lastFxPos     = nil
local lastClaimedAt = 0
local lastClaimedId = nil
local lastClaimedByUs = false
local claimAttemptStartedAt = 0
local inFlightClaims = {}
local seedPackEffectMod = nil
local teleWasOn = false
local telePaused = false
local spawnCtrl = nil
local spawnCtrlHooked = false
local seedBoolAttrOrder = nil
local gameValidatedSpawns = {}
local seedsFolderWired = false
local SPAWN_CTRL_NAME = "SpawnSeedPackController"
-- Urutan bool seed di SpawnClient game (decompile) — hanya anchor; sisanya dari Assets.Seeds
local GAME_BOOL_SEED_PRIORITY = { "RainbowSeed", "GoldSeed", "MegaSeed" }

local stats = {
    attempts = 0,
    fired = 0,
    remoteOk = 0,
    teleports = 0,
    clickOk = 0,
    prefire = 0,
    skipped = {},
    lastResult = nil,
    lastSkip = nil,
    lastError = nil,
    lastClaimId = nil,
    lastMethod = nil,
    falseOk = 0,
    lastMs = nil,
}

local function _skip(reason)
    stats.lastSkip = reason
    stats.skipped[reason] = (stats.skipped[reason] or 0) + 1
end

local function _getLP()
    local lp = LP or Players.LocalPlayer
    if lp then LP = lp end
    return lp
end

local function _isLocalPlayerClaim(id)
    local lp = _getLP()
    if not lp or id == nil then return false end
    local s = tostring(id)
    if s == lp.Name then return true end
    if s == tostring(lp.UserId) then return true end
    local n = tonumber(s)
    return n ~= nil and n == lp.UserId
end

local function _getHRP()
    local lp = _getLP()
    if not lp then return nil end
    local char = lp.Character
    if not char then return nil end
    local hrp = char:FindFirstChild("HumanoidRootPart")
    if hrp and hrp:IsA("BasePart") then return hrp end
    return nil
end

local function _enabled()
    local MAIN = G.MAIN or rawget(_G, "MAIN")
    if type(MAIN) == "table" and type(MAIN.auto) == "table"
        and type(MAIN.auto.claimSeed) == "table" then
        return MAIN.auto.claimSeed.enabled == true
    end
    local store = G.__GAG2_CLAIM_SEED or rawget(_G, "__GAG2_CLAIM_SEED")
    if type(store) == "table" then
        return store.enabled == true
    end
    return G.AUTO_CLAIM_SEED_ENABLED == true or rawget(_G, "AUTO_CLAIM_SEED_ENABLED") == true
end

local function _writeEnabled(on)
    on = (on == true)
    if type(G.__GAG2_CLAIM_SEED) ~= "table" then G.__GAG2_CLAIM_SEED = {} end
    G.__GAG2_CLAIM_SEED.enabled = on
    _G.__GAG2_CLAIM_SEED = G.__GAG2_CLAIM_SEED
    G.AUTO_CLAIM_SEED_ENABLED = on
    _G.AUTO_CLAIM_SEED_ENABLED = on
    local MAIN = G.MAIN or rawget(_G, "MAIN")
    if type(MAIN) == "table" then
        MAIN.auto = MAIN.auto or {}
        MAIN.auto.claimSeed = MAIN.auto.claimSeed or {}
        MAIN.auto.claimSeed.enabled = on
        G.MAIN = MAIN
        _G.MAIN = MAIN
    end
    return on
end

local function _dbg(...)
    if G.AUTO_CLAIM_SEED_DEBUG ~= true and rawget(_G, "AUTO_CLAIM_SEED_DEBUG") ~= true then
        return
    end
    warn("[GAG2-ClaimSeed]", ...)
end

local function _dbgSkip(reason, extra)
    _skip(reason)
    if extra ~= nil then
        _dbg("skip:", reason, extra)
    else
        _dbg("skip:", reason)
    end
end

local function _findRemote(net, names)
    if type(net) ~= "table" then return nil end
    for _, name in ipairs(names) do
        local r = net[name]
        if r then
            if type(r.Fire) == "function" or type(r.FireServer) == "function"
                or type(r.InvokeServer) == "function" then
                return r, name
            end
        end
    end
    return nil
end

local function _initRemotes()
    if ClickPack then return true end

    local ok, Networking = pcall(function()
        return require(ReplicatedStorage:WaitForChild("SharedModules", 10):WaitForChild("Networking", 10))
    end)
    if not ok or type(Networking) ~= "table" then
        stats.lastError = "Networking require gagal"
        remotesReady = false
        return false
    end

    local SeedNet = Networking.SeedPack or Networking.Seedpack or Networking.SeedPacks
    ClickPack, remotePath = _findRemote(SeedNet, { "ClickPack", "ClickSeedPack", "Click" })
    if not ClickPack then
        ClickPack, remotePath = _findRemote(Networking, { "ClickSeedPack", "ClickPack" })
        if ClickPack then remotePath = "Networking." .. tostring(remotePath) end
    else
        remotePath = "Networking.SeedPack." .. tostring(remotePath)
    end

    local SpawnNet = Networking.SeedPackSpawn or Networking.SeedpackSpawn
    if type(SpawnNet) == "table" then
        SeedPackFX = SpawnNet.FX
        if not claimedConn and SpawnNet.Claimed and SpawnNet.Claimed.OnClientEvent then
            claimedConn = SpawnNet.Claimed.OnClientEvent:Connect(function(id, seedName)
                lastClaimedAt = os.clock()
                lastClaimedId = id ~= nil and tostring(id) or nil
                lastClaimedByUs = _isLocalPlayerClaim(id)
            end)
        end
    end

    remotesReady = ClickPack ~= nil
    if not ClickPack then
        stats.lastError = "ClickPack MISSING"
    end
    return remotesReady
end

local function _getMap()
    return workspace:FindFirstChild("Map")
end

local function _getSpawnFolder()
    if spawnFolder and spawnFolder.Parent then return spawnFolder end
    local map = _getMap()
    if not map then return nil end
    spawnFolder = map:FindFirstChild("SeedPackSpawnServerLocations")
        or map:WaitForChild("SeedPackSpawnServerLocations", 2)
    return spawnFolder
end

local function _truthy(v)
    return v == true or v == 1 or v == "true" or v == "1"
end

local function _getSpawnAttr(inst, name)
    if not inst then return nil end
    local v = inst:GetAttribute(name)
    if v ~= nil then return v end
    return nil
end

local function _getAssetsSeedsFolder()
    local assets = ReplicatedStorage:FindFirstChild("Assets")
    return assets and assets:FindFirstChild("Seeds")
end

local function _refreshSeedBoolAttrOrder()
    local out = {}
    local seen = {}
    for _, attr in ipairs(GAME_BOOL_SEED_PRIORITY) do
        out[#out + 1] = attr
        seen[attr] = true
    end
    local seeds = _getAssetsSeedsFolder()
    if seeds then
        for _, ch in ipairs(seeds:GetChildren()) do
            local attr = ch.Name .. "Seed"
            if not seen[attr] then
                seen[attr] = true
                out[#out + 1] = attr
            end
        end
    end
    seedBoolAttrOrder = out
    if not seedsFolderWired and seeds then
        seedsFolderWired = true
        seeds.ChildAdded:Connect(function()
            _refreshSeedBoolAttrOrder()
        end)
    end
    return out
end

local function _getSeedBoolAttrOrder()
    if not seedBoolAttrOrder then
        _refreshSeedBoolAttrOrder()
    end
    return seedBoolAttrOrder
end

local function _getWatchAttrNames(inst)
    local names = { "SeedPack" }
    local seen = { SeedPack = true }
    for _, attr in ipairs(_getSeedBoolAttrOrder()) do
        if not seen[attr] then
            seen[attr] = true
            names[#names + 1] = attr
        end
    end
    if inst then
        for name in pairs(inst:GetAttributes()) do
            if not seen[name] and name ~= "SeedPack" and name:sub(-4) == "Seed" then
                seen[name] = true
                names[#names + 1] = name
            end
        end
    end
    return names
end

local function _boolSeedActive(inst, attr)
    return inst and inst:GetAttribute(attr) == true
end

local function _resolveSpawnInfo(inst, packHint)
    if not inst then return "unknown", "Normal" end
    local cached = gameValidatedSpawns[inst]
    if type(cached) == "table" and cached.label then
        return cached.label, cached.packName or "Normal"
    end

    local pack = inst:GetAttribute("SeedPack")
    if type(pack) ~= "string" then pack = packHint end
    if type(pack) ~= "string" then pack = nil end

    for _, attr in ipairs(_getSeedBoolAttrOrder()) do
        if _boolSeedActive(inst, attr) then
            local base = attr:gsub("Seed$", "")
            return base .. " Seed", base
        end
    end
    for name, val in pairs(inst:GetAttributes()) do
        if name ~= "SeedPack" and name:sub(-4) == "Seed" and val == true then
            local base = name:gsub("Seed$", "")
            return base .. " Seed", base
        end
    end
    if type(pack) == "string" and pack ~= "" then return pack, pack end
    return inst.Name or "unknown", "Normal"
end

local function _spawnHasAttrs(inst)
    if not inst or not inst.Parent then return false end
    if gameValidatedSpawns[inst] then return true end
    local packName = inst:GetAttribute("SeedPack")
    if type(packName) == "string" and packName ~= "" then return true end
    for _, attr in ipairs(_getSeedBoolAttrOrder()) do
        if _boolSeedActive(inst, attr) then return true end
    end
    for name, val in pairs(inst:GetAttributes()) do
        if name ~= "SeedPack" and name:sub(-4) == "Seed" and val == true then
            return true
        end
    end
    return false
end

local function _waitSpawnReady(inst)
    if not inst or not inst.Parent then return false end
    if _spawnHasAttrs(inst) then return true end
    local deadline = os.clock() + ATTR_WAIT_SEC
    while inst.Parent and os.clock() < deadline do
        if _spawnHasAttrs(inst) then return true end
        local woke = false
        for _, attr in ipairs(_getWatchAttrNames(inst)) do
            local ok = pcall(function()
                inst:GetAttributeChangedSignal(attr):Wait()
            end)
            if ok then woke = true break end
        end
        if not woke then task.wait(ATTR_POLL_SEC) end
    end
    return _spawnHasAttrs(inst)
end

local function _partCFrame(inst)
    if not inst then return nil end
    if inst:IsA("BasePart") then return inst.CFrame end
    if inst:IsA("Model") then
        local ok, cf = pcall(function() return inst:GetPivot() end)
        if ok and typeof(cf) == "CFrame" then return cf end
        local part = inst:FindFirstChildWhichIsA("BasePart", true)
        if part then return part.CFrame end
    end
    return nil
end

local function _spawnPosition(inst)
    local cf = _partCFrame(inst)
    return cf and cf.Position or nil
end

local function _childWorldPos(obj)
    if not obj then return nil end
    if obj:IsA("BasePart") then return obj.Position end
    if obj:IsA("Model") then
        local pp = obj.PrimaryPart or obj:FindFirstChildWhichIsA("BasePart", true)
        if pp then return pp.Position end
    end
    return nil
end

local function _partWorldPos(inst)
    if not inst then return nil end
    local pos = _spawnPosition(inst)
    if pos then return pos end
    return _childWorldPos(inst)
end

local function _spawnLabel(inst)
    return select(1, _resolveSpawnInfo(inst))
end

local function _findSpawnSeedPackControllerModule()
    local lp = _getLP()
    local roots = {}
    if lp then
        local scripts = lp:FindFirstChild("PlayerScripts")
        local controllers = scripts and scripts:FindFirstChild("Controllers")
        if controllers then roots[#roots + 1] = controllers end
    end
    local starter = game:GetService("StarterPlayer")
    local starterScripts = starter and starter:FindFirstChild("StarterPlayerScripts")
    local starterControllers = starterScripts and starterScripts:FindFirstChild("Controllers")
    if starterControllers then roots[#roots + 1] = starterControllers end

    for _, controllers in ipairs(roots) do
        local modInst = controllers:FindFirstChild(SPAWN_CTRL_NAME)
        if modInst then return modInst end
    end
    return nil
end

local function _getSpawnSeedPackController()
    if spawnCtrl == false then return nil end
    if type(spawnCtrl) == "table" then return spawnCtrl end

    local modInst = _findSpawnSeedPackControllerModule()
    if not modInst then
        return nil
    end
    local ok, result = pcall(require, modInst)
    if ok and type(result) == "table" then
        spawnCtrl = result
        return spawnCtrl
    end
    spawnCtrl = false
    return nil
end

local function _trackGameValidatedSpawn(serverPart, packHint)
    if not serverPart then return end
    local label, packName = _resolveSpawnInfo(serverPart, packHint)
    gameValidatedSpawns[serverPart] = {
        label = label,
        packName = packName,
        at = os.clock(),
    }
    pcall(function()
        serverPart.Destroying:Connect(function()
            gameValidatedSpawns[serverPart] = nil
        end)
    end)
end

local function _onGameSpawnClient(serverPart, packHint)
    if not serverPart or not serverPart.Parent then return end
    _trackGameValidatedSpawn(serverPart, packHint)
    if not _enabled() or not _spawnHasAttrs(serverPart) then return end
    task.defer(function()
        if not serverPart.Parent or not _enabled() then return end
        _prefireRemote(serverPart, "spawn_client")
        _queueClaimSession("spawn_client")
    end)
end

local function _hookSpawnSeedPackController()
    if spawnCtrlHooked then return true end
    _refreshSeedBoolAttrOrder()

    local ctrl = _getSpawnSeedPackController()
    if not ctrl or type(ctrl.SpawnClient) ~= "function" then
        return false
    end
    if ctrl.__GAG2_ClaimSeedSpawnHook then
        spawnCtrlHooked = true
        return true
    end

    local origSpawnClient = ctrl.SpawnClient
    ctrl.SpawnClient = function(self, serverPart, packHint, ...)
        local ret = origSpawnClient(self, serverPart, packHint, ...)
        pcall(_onGameSpawnClient, serverPart, packHint)
        return ret
    end
    ctrl.__GAG2_ClaimSeedSpawnHook = true
    spawnCtrlHooked = true
    _dbg("SpawnSeedPackController hooked")
    return true
end

local function _ensureSpawnSeedPackController()
    if _hookSpawnSeedPackController() then return true end
    task.spawn(function()
        for _ = 1, 45 do
            if _hookSpawnSeedPackController() then return end
            task.wait(1)
        end
    end)
    return false
end

local function _folderSpawnRoot(inst)
    local folder = _getSpawnFolder()
    if not folder or not inst then return inst end
    local node = inst
    while node and node.Parent and node.Parent ~= folder do
        node = node.Parent
    end
    if node and node.Parent == folder then return node end
    return inst
end

local function _globalSpawnIndex(inst)
    local folder = _getSpawnFolder()
    if not folder then return nil end
    local root = _folderSpawnRoot(inst)
    for i, ch in ipairs(folder:GetChildren()) do
        if ch == root then return tostring(i) end
    end
    return nil
end

local function _findClientSpawnNear(inst)
    local pos = _spawnPosition(inst)
    if not pos then return nil end
    local map = _getMap()
    local client = map and map:FindFirstChild("SeedPackSpawnClient")
    if not client then return nil end
    local best, bestD = nil, 10
    for _, ch in ipairs(client:GetChildren()) do
        local p = _childWorldPos(ch)
        if p then
            local d = (p - pos).Magnitude
            if d < bestD then
                best = ch
                bestD = d
            end
        end
    end
    return best
end

local function _getClaimIds(inst)
    local out = {}
    local seen = {}
    local function add(v)
        if v == nil then return end
        v = tostring(v)
        if v == "" or seen[v] then return end
        if v == "Part" or v == "Model" then return end
        seen[v] = true
        out[#out + 1] = v
    end

    -- Slot index di SeedPackSpawnServerLocations (paling umum di GAG2)
    add(_globalSpawnIndex(inst))

    add(_getSpawnAttr(inst, "SpawnId"))
    add(_getSpawnAttr(inst, "Id"))
    add(_getSpawnAttr(inst, "UUID"))
    add(_getSpawnAttr(inst, "Slot"))
    add(_getSpawnAttr(inst, "SlotId"))
    add(_getSpawnAttr(inst, "Index"))

    if inst and inst.Parent then
        for i, ch in ipairs(inst.Parent:GetChildren()) do
            if ch == inst then add(tostring(i)) break end
        end
    end

    if inst and inst.Name ~= "Part" and inst.Name ~= "Model" then
        add(inst.Name)
    end

    return out
end

local function _primaryClaimId(inst)
    local ids = _getClaimIds(inst)
    return ids[1]
end

local function _distToSpawn(inst)
    local hrp = _getHRP()
    local pos = _spawnPosition(inst)
    if not hrp or not pos then return nil end
    return (hrp.Position - pos).Magnitude
end

local function _spawnTrackKey(inst)
    if not inst then return nil end
    local id = _getSpawnAttr(inst, "SpawnId") or _getSpawnAttr(inst, "Id")
        or _getSpawnAttr(inst, "UUID") or _getSpawnAttr(inst, "SlotId")
    if id ~= nil then return "id:" .. tostring(id) end
    local gidx = _globalSpawnIndex(inst)
    if gidx then return "slot:" .. gidx end
    local pos = _spawnPosition(inst)
    if pos then
        return string.format("p:%.1f,%.1f,%.1f", pos.X, pos.Y, pos.Z)
    end
    return tostring(inst)
end

local function _claimedDuringAttempt()
    return lastClaimedAt >= claimAttemptStartedAt - 0.02
end

local function _weWonClaim()
    return lastClaimedByUs and _claimedDuringAttempt()
end

local function _otherWonClaim()
    return not lastClaimedByUs and _claimedDuringAttempt()
end

local function _claimLock(inst)
    local key = _spawnTrackKey(inst)
    if not key or inFlightClaims[key] then return false, key end
    inFlightClaims[key] = true
    return true, key
end

local function _claimUnlock(key)
    if key then inFlightClaims[key] = nil end
end

local function _shouldPrefire(dist)
    return dist == nil or dist <= PREFIRE_MAX_DIST
end

local function _getGardenCFrame()
    local lp = _getLP()
    if not lp then return nil end

    local plotId = lp:GetAttribute("PlotId")
    local gardens = workspace:FindFirstChild("Gardens")
    if gardens and plotId ~= nil then
        for _, name in ipairs({ "Plot" .. tostring(plotId), tostring(plotId), "Plot_" .. tostring(plotId) }) do
            local plot = gardens:FindFirstChild(name)
            if plot then
                local spawn = plot:FindFirstChild("SpawnPoint", true)
                    or plot:FindFirstChild("Spawn", true)
                    or plot:FindFirstChild("SpawnLocation", true)
                if spawn and spawn:IsA("BasePart") then
                    return spawn.CFrame + TP_OFFSET
                end
                if plot:IsA("Model") then
                    local ok, cf = pcall(function() return plot:GetPivot() end)
                    if ok and typeof(cf) == "CFrame" then return cf + TP_OFFSET end
                end
            end
        end
    end

    if not gardens then return nil end
    for _, plot in ipairs(gardens:GetChildren()) do
        local owner = plot:GetAttribute("Owner") or plot:GetAttribute("OwnerId") or plot:GetAttribute("OwnerUserId")
        if owner ~= nil and (tostring(owner) == lp.Name or tonumber(owner) == lp.UserId) then
            local spawn = plot:FindFirstChild("SpawnPoint", true)
                or plot:FindFirstChild("Spawn", true)
                or plot:FindFirstChild("SpawnLocation", true)
            if spawn and spawn:IsA("BasePart") then return spawn.CFrame + TP_OFFSET end
            if plot:IsA("Model") then
                local ok, cf = pcall(function() return plot:GetPivot() end)
                if ok and typeof(cf) == "CFrame" then return cf + TP_OFFSET end
            end
        end
    end
    return nil
end

local function _teleport(cf)
    if typeof(cf) ~= "CFrame" then return false end
    local lp = _getLP()
    local char = lp and lp.Character
    local hrp = _getHRP()
    if not char or not hrp then return false end
    local ok = pcall(function()
        if char.PrimaryPart then char:PivotTo(cf) else hrp.CFrame = cf end
    end)
    if ok then stats.teleports = stats.teleports + 1 end
    return ok
end

----------------------------------------------------------------
-- Auto Tele: stop dulu, resume kalau tidak ada seed lagi
----------------------------------------------------------------
local function _getAutoTeleMod()
    return G.AutoTele or rawget(_G, "AutoTele")
end

local function _teleIsOn()
    local mod = _getAutoTeleMod()
    if type(mod) == "table" and type(mod.IsEnabled) == "function" then
        return mod.IsEnabled() == true
    end
    local s = rawget(_G, "__GAG2_AUTO_TELE") or G.__GAG2_AUTO_TELE
    if type(s) == "table" then return s.enabled == true end
    return G.AUTO_TELE_ENABLED == true or rawget(_G, "AUTO_TELE_ENABLED") == true
end

local function _teleWasRunning()
    local mod = _getAutoTeleMod()
    if type(mod) == "table" and type(mod.IsRunning) == "function" then
        return mod.IsRunning() == true
    end
    return false
end

local function _teleStopForClaim()
    teleWasOn = _teleIsOn() and _teleWasRunning()
    telePaused = true
    G.__GAG2_AUTO_TELE_SUPPRESS = true
    _G.__GAG2_AUTO_TELE_SUPPRESS = true
    local mod = _getAutoTeleMod()
    if type(mod) == "table" and type(mod.Stop) == "function" then
        pcall(mod.Stop, mod)
    end
end

local function _teleKeepPaused()
    telePaused = true
    G.__GAG2_AUTO_TELE_SUPPRESS = true
    _G.__GAG2_AUTO_TELE_SUPPRESS = true
    local mod = _getAutoTeleMod()
    if type(mod) == "table" and type(mod.IsRunning) == "function"
        and mod.IsRunning() and type(mod.Stop) == "function" then
        pcall(mod.Stop, mod)
    end
end

local function _tpUnderSeed(inst)
    local pos = _partWorldPos(inst)
    if not pos then return false end
    local under = Vector3.new(pos.X, pos.Y + UNDER_Y, pos.Z)
    return _teleport(CFrame.new(under, pos))
end

local function _stickUnderSeed(inst)
    _teleKeepPaused()
    return _tpUnderSeed(inst)
end

local function _waitClaimVerdict(maxWait, inst)
    maxWait = tonumber(maxWait) or 0.1
    local deadline = os.clock() + maxWait
    while os.clock() < deadline do
        if inst then _stickUnderSeed(inst) end
        if _weWonClaim() then return true, "claimed_event" end
        if _otherWonClaim() then return false, "lost_to_other" end
        task.wait(VERIFY_POLL)
    end
    if _weWonClaim() then return true, "claimed_event" end
    if _otherWonClaim() then return false, "lost_to_other" end
    return nil, nil
end

local function _teleResumeNow()
    telePaused = false
    if not teleWasOn then
        G.__GAG2_AUTO_TELE_SUPPRESS = false
        _G.__GAG2_AUTO_TELE_SUPPRESS = false
        return
    end
    teleWasOn = false
    G.__GAG2_AUTO_TELE_SUPPRESS = false
    _G.__GAG2_AUTO_TELE_SUPPRESS = false
    local mod = _getAutoTeleMod()
    if type(mod) == "table" and type(mod.IsEnabled) == "function" and mod.IsEnabled() then
        if type(mod.Start) == "function" then pcall(mod.Start, mod) end
    end
end

local function _standCFrame(inst)
    local cf = _partCFrame(inst)
    if not cf then return nil end
    local seedPos = cf.Position
    local standPos = seedPos
    if TP_STAND_DIST > 0.05 then
        local hrp = _getHRP()
        local flat = Vector3.new(0, 0, -1)
        if hrp then
            flat = seedPos - hrp.Position
            flat = Vector3.new(flat.X, 0, flat.Z)
        end
        if flat.Magnitude < 0.05 then
            flat = Vector3.new(0, 0, -1)
        else
            flat = flat.Unit
        end
        standPos = seedPos - flat * TP_STAND_DIST
    end
    standPos = standPos + Vector3.new(0, TP_OFFSET.Y, 0)
    return CFrame.new(standPos, seedPos)
end

local function _canClaim(inst)
    local untilAt = claimCooldown[inst]
    return not (untilAt and os.clock() < untilAt)
end

local function _markClaimed(inst, sec)
    claimCooldown[inst] = os.clock() + (tonumber(sec) or CLAIM_COOLDOWN)
end

local function _getClickFn()
    if type(fireclickdetector) == "function" then return fireclickdetector end
    if type(rawget(_G, "fireclickdetector")) == "function" then return rawget(_G, "fireclickdetector") end
    return nil
end

local function _getPromptFn()
    if type(fireproximityprompt) == "function" then return fireproximityprompt end
    if type(rawget(_G, "fireproximityprompt")) == "function" then return rawget(_G, "fireproximityprompt") end
    return nil
end

local function _getSeedPackEffect()
    if seedPackEffectMod == false then return nil end
    if seedPackEffectMod then return seedPackEffectMod end
    local lp = _getLP()
    local controllers = lp and lp:FindFirstChild("PlayerScripts")
    controllers = controllers and controllers:FindFirstChild("Controllers")
    if not controllers then seedPackEffectMod = false return nil end

    local tryPaths = {
        { "SeedPackController", "SeedPackEffect" },
        { "SeedPackController", "SeedPackOpen" },
    }
    for _, path in ipairs(tryPaths) do
        local node = controllers
        for _, name in ipairs(path) do
            node = node and node:FindFirstChild(name)
        end
        if node then
            local ok, mod = pcall(require, node)
            if ok and type(mod) == "table" and type(mod.Open) == "function" then
                seedPackEffectMod = mod
                return mod
            end
        end
    end
    seedPackEffectMod = false
    return nil
end

local function _triggerGameOpen(inst)
    local effect = _getSeedPackEffect()
    if not effect then return false end
    local hrp = _getHRP()
    local spawnCf = _partCFrame(inst)
    if not hrp or not spawnCf then return false end

    local label, packName = _resolveSpawnInfo(inst)

    local seedPos = _partWorldPos(inst)
    local stickPos = seedPos and Vector3.new(seedPos.X, seedPos.Y + UNDER_Y, seedPos.Z) or hrp.Position
    local ok = pcall(function()
        effect.Open(inst.Name, packName, label, stickPos, spawnCf)
    end)
    return ok
end

local function _findClickDetectorNear(nearPos)
    if not nearPos then return nil end
    local roots = {}
    local temp = workspace:FindFirstChild("Temporary")
    if temp then roots[#roots + 1] = temp end
    local map = _getMap()
    if map then
        local client = map:FindFirstChild("SeedPackSpawnClient")
        if client then roots[#roots + 1] = client end
    end

    local best, bestDist = nil, CLICK_NEAR_DIST
    for _, root in ipairs(roots) do
        for _, obj in ipairs(root:GetDescendants()) do
            if obj:IsA("ClickDetector") then
                local pos = _childWorldPos(obj.Parent) or _childWorldPos(obj:FindFirstAncestorOfClass("Model"))
                if pos then
                    local d = (pos - nearPos).Magnitude
                    if d <= bestDist then
                        best = obj
                        bestDist = d
                    end
                end
            end
        end
    end
    return best
end

local function _findProximityPromptNear(nearPos)
    if not nearPos then return nil end
    local roots = {}
    local map = _getMap()
    if map then
        local client = map:FindFirstChild("SeedPackSpawnClient")
        if client then roots[#roots + 1] = client end
    end
    local folder = _getSpawnFolder()
    if folder then roots[#roots + 1] = folder end

    local best, bestDist = nil, CLICK_NEAR_DIST
    for _, root in ipairs(roots) do
        for _, obj in ipairs(root:GetDescendants()) do
            if obj:IsA("ProximityPrompt") then
                local pos = _childWorldPos(obj.Parent)
                if pos then
                    local d = (pos - nearPos).Magnitude
                    if d <= bestDist then
                        best = obj
                        bestDist = d
                    end
                end
            end
        end
    end
    return best
end

local function _fireClickDetector(cd)
    if not cd then return false end
    local lp = _getLP()
    local fn = _getClickFn()
    local ok = false
    if fn and lp then
        ok = pcall(fn, cd, 0, lp)
        if ok then
            stats.clickOk = stats.clickOk + 1
            stats.lastMethod = "ClickDetector"
        end
    end
    return ok
end

local function _fireProximityPrompt(pp)
    if not pp then return false end
    local fn = _getPromptFn()
    if not fn then return false end
    local ok = pcall(fn, pp)
    if ok then stats.lastMethod = "ProximityPrompt" end
    return ok
end

local function _waitOpenUiClickDetector(inst, onPoll)
    local pos = _partWorldPos(inst)
    if not pos then return nil end
    local deadline = os.clock() + OPEN_UI_WAIT
    while inst.Parent and os.clock() < deadline do
        _stickUnderSeed(inst)
        local cd = _findClickDetectorNear(pos)
        if cd then return cd end
        if type(onPoll) == "function" then onPoll() end
        task.wait(OPEN_UI_POLL)
    end
    return _findClickDetectorNear(pos)
end

local function _fxNearSpawn(inst)
    if not lastFxPos or lastFxAt < claimAttemptStartedAt - 0.05 then return false end
    local pos = _spawnPosition(inst)
    if not pos then return false end
    return (lastFxPos - pos).Magnitude <= 12
end

local function _packStillActive(inst)
    if not inst or not inst.Parent then return false end
    local folder = _getSpawnFolder()
    if folder and inst.Parent ~= folder then return false end
    return _spawnHasAttrs(inst)
end

local function _resetClaimAttempt()
    claimAttemptStartedAt = os.clock()
    lastClaimedByUs = false
end

local function _waitForClaimComplete(inst, maxWait)
    maxWait = tonumber(maxWait) or CLAIM_COMPLETE_WAIT
    local deadline = os.clock() + maxWait
    local lastFire = 0

    while running and _enabled() and os.clock() < deadline do
        _stickUnderSeed(inst)
        if _weWonClaim() then return true, "claimed_event" end
        if _otherWonClaim() then return false, "lost_to_other" end

        local stillActive = inst and inst.Parent and _packStillActive(inst) and _spawnHasAttrs(inst)
        if not stillActive then
            local ok, reason = _waitClaimVerdict(CLAIM_VERDICT_WAIT, inst)
            if ok == true then return true, reason or "spawn_cleared" end
            if ok == false then return false, reason end
            if _weWonClaim() then return true, "claimed_event_late" end
            if _otherWonClaim() then return false, "lost_to_other" end
            task.wait(CLAIM_POLL_SEC)
        else
            if os.clock() - lastFire >= FOLLOW_FIRE_SEC then
                _fireClickPackBurst(inst, "wait_complete")
                lastFire = os.clock()
            end
            task.wait(CLAIM_POLL_SEC)
        end
    end

    if _weWonClaim() then return true, "claimed_event_timeout" end
    if _otherWonClaim() then return false, "lost_to_other" end
    return false, "claim_timeout"
end

local function _verifyClaimed(inst, nearPos, tag, maxWait)
    maxWait = tonumber(maxWait) or VERIFY_WAIT
    local deadline = os.clock() + maxWait
    while os.clock() < deadline do
        _stickUnderSeed(inst)
        if _weWonClaim() then return true, "claimed_event" end
        if _otherWonClaim() then return false, "lost_to_other" end
        if _fxNearSpawn(inst) then
            local ok, reason = _waitClaimVerdict(0.35, inst)
            if ok == true then return true, "fx_event" end
            if ok == false then return false, reason end
        end
        if not _packStillActive(inst) then
            local ok, reason = _waitClaimVerdict(math.max(maxWait, 0.35), inst)
            if ok == true then return true, reason end
            if ok == false then return false, reason end
            return false, "spawn_gone_pending"
        end
        task.wait(VERIFY_POLL)
    end
    if _weWonClaim() then return true, "claimed_event" end
    if _otherWonClaim() then return false, "lost_to_other" end
    if _fxNearSpawn(inst) then
        local ok, reason = _waitClaimVerdict(0.3, inst)
        if ok == true then return true, "fx_event" end
        if ok == false then return false, reason end
    end
    if not _packStillActive(inst) then
        local ok, reason = _waitClaimVerdict(0.35, inst)
        if ok == true then return true, reason end
        if ok == false then return false, reason end
        return false, "spawn_gone_pending"
    end
    return false, nil
end

local function _fireClickPackOne(id, tag)
    if not ClickPack or id == nil then return false, nil end

    if typeof(id) == "Instance" then
        local ok = false
        local err = nil
        if type(ClickPack.Fire) == "function" then
            ok, err = pcall(function() ClickPack:Fire(id) end)
        end
        if not ok and type(ClickPack.FireServer) == "function" then
            ok, err = pcall(function() ClickPack:FireServer(id) end)
        end
        if not ok and type(ClickPack.InvokeServer) == "function" then
            ok, err = pcall(function() ClickPack:InvokeServer(id) end)
        end
        if ok then
            stats.remoteOk += 1
            stats.lastClaimId = id.Name
            return true, id.Name
        end
        stats.lastError = tostring(err)
        return false, nil
    end

    local label = tostring(id)
    if label == "" or label == "Part" or label == "Model" then return false, nil end

    local ok = false
    local err = nil

    if type(ClickPack.Fire) == "function" then
        ok, err = pcall(function() ClickPack:Fire(label) end)
    end
    if not ok and type(ClickPack.FireServer) == "function" then
        ok, err = pcall(function() ClickPack:FireServer(label) end)
    end
    if not ok and type(ClickPack.InvokeServer) == "function" then
        ok, err = pcall(function() ClickPack:InvokeServer(label) end)
    end

    if ok then
        stats.remoteOk = stats.remoteOk + 1
        stats.lastClaimId = label
        return true, label
    end
    stats.lastError = tostring(err)
    return false, nil
end

local function _fireClickPackBurst(inst, tag)
    if not ClickPack or not inst then return {}, 0 end
    local firedIds = {}
    local seen = {}

    local function fireOne(id)
        if id == nil then return end
        local key = tostring(id)
        if seen[key] then return end
        seen[key] = true
        local ok, label = _fireClickPackOne(id, tag)
        if ok then firedIds[#firedIds + 1] = label end
    end

    local primary = _primaryClaimId(inst)
    fireOne(primary)
    for _, id in ipairs(_getClaimIds(inst)) do
        fireOne(id)
    end

    local root = _folderSpawnRoot(inst)
    fireOne(inst)
    if root and root ~= inst then
        fireOne(root)
    end

    return firedIds, #firedIds
end

local function _prefireRemote(inst, tag)
    _initRemotes()
    if not ClickPack or not inst then return end
    stats.prefire = stats.prefire + 1
    _fireClickPackBurst(inst, tag or "prefire")
end

local function _claimSucceeded(inst, nearPos, method, maxWait)
    local ok, reason = _verifyClaimed(inst, nearPos, method, maxWait)
    if ok then
        stats.lastMethod = method .. ":" .. reason
        return true, method
    end
    if reason == "lost_to_other" then
        stats.lastMethod = method .. ":lost_to_other"
    end
    return false, reason
end

local function _tryOpenPromptClaim(inst, nearPos, tag)
    tag = tag or "open"
    _triggerGameOpen(inst)
    _fireClickPackBurst(inst, tag .. "_burst")

    local pp = nil
    local findDeadline = os.clock() + OPEN_PROMPT_FIND_WAIT
    while not pp and inst.Parent and os.clock() < findDeadline do
        _stickUnderSeed(inst)
        pp = _findProximityPromptNear(nearPos)
        if not pp then task.wait(OPEN_UI_POLL) end
    end
    if not pp then pp = _findProximityPromptNear(nearPos) end
    if not pp then return false end

    local retryDeadline = os.clock() + OPEN_PROMPT_RETRY_SEC
    local attempt = 0
    while inst.Parent and os.clock() < retryDeadline and attempt < OPEN_PROMPT_RETRIES do
        attempt = attempt + 1
        _stickUnderSeed(inst)
        _fireClickPackBurst(inst, tag .. "_r" .. attempt)
        if not _fireProximityPrompt(pp) then
            task.wait(OPEN_UI_POLL)
        else
            stats.lastClaimId = _primaryClaimId(inst)
            local remain = retryDeadline - os.clock()
            local maxW = (remain > VERIFY_WAIT_FAST + 0.01) and VERIFY_WAIT_FAST or math.min(VERIFY_WAIT, remain)
            local ok, reason = _claimSucceeded(inst, nearPos, "open_prompt", maxW)
            if ok then return true, "open_prompt" end
            if reason == "lost_to_other" then return false, "lost_to_other" end
        end
    end
    return false
end

local function _performClaim(inst)
    _initRemotes()
    if not inst then return false, nil, {} end

    local nearPos = _partWorldPos(inst)
    local t0 = os.clock()
    local steps = {}

    local function step(name, fn)
        local ts = os.clock()
        _stickUnderSeed(inst)
        local ok, a, b = fn()
        steps[#steps + 1] = {
            step = name,
            ok = ok,
            ms = math.floor((os.clock() - ts) * 1000),
            extra = b or a,
        }
        return ok, a, b
    end

    step("prompt_fast", function()
        local pp = _findProximityPromptNear(nearPos)
        if not pp then return false end
        _fireClickPackBurst(inst, "prompt_fast")
        if not _fireProximityPrompt(pp) then return false end
        stats.lastClaimId = _primaryClaimId(inst)
        local ok, reason = _claimSucceeded(inst, nearPos, "prompt_fast", VERIFY_WAIT_FAST)
        if not ok and reason == "lost_to_other" then return false, "lost_to_other" end
        return ok
    end)
    if steps[#steps].ok then
        stats.lastMs = math.floor((os.clock() - t0) * 1000)
        return true, stats.lastMethod, steps
    end
    if steps[#steps].extra == "lost_to_other" then
        stats.lastMs = math.floor((os.clock() - t0) * 1000)
        return false, stats.lastMethod, steps
    end

    step("burst", function()
        local ids, n = _fireClickPackBurst(inst, "burst")
        if n <= 0 then return false end
        local ok, reason = _claimSucceeded(inst, nearPos, "burst", VERIFY_WAIT_FAST)
        if not ok and reason == "lost_to_other" then return false, "lost_to_other" end
        return ok
    end)
    if steps[#steps].ok then
        stats.lastMs = math.floor((os.clock() - t0) * 1000)
        return true, stats.lastMethod, steps
    end
    if steps[#steps].extra == "lost_to_other" then
        stats.lastMs = math.floor((os.clock() - t0) * 1000)
        return false, stats.lastMethod, steps
    end

    step("open_prompt", function()
        local ok, extra = _tryOpenPromptClaim(inst, nearPos, "fast")
        if not ok and extra == "lost_to_other" then return false, "lost_to_other" end
        return ok
    end)
    if steps[#steps].ok then
        stats.lastMs = math.floor((os.clock() - t0) * 1000)
        return true, stats.lastMethod, steps
    end
    if steps[#steps].extra == "lost_to_other" then
        stats.lastMs = math.floor((os.clock() - t0) * 1000)
        return false, stats.lastMethod, steps
    end

    step("burst_retry", function()
        local ids, n = _fireClickPackBurst(inst, "burst_retry")
        if n <= 0 then return false end
        local ok, reason = _claimSucceeded(inst, nearPos, "burst_retry")
        if not ok and reason == "lost_to_other" then return false, "lost_to_other" end
        return ok
    end)
    if steps[#steps].ok then
        stats.lastMs = math.floor((os.clock() - t0) * 1000)
        return true, stats.lastMethod, steps
    end
    if steps[#steps].extra == "lost_to_other" then
        stats.lastMs = math.floor((os.clock() - t0) * 1000)
        return false, stats.lastMethod, steps
    end

    step("clickdet", function()
        local cd = _findClickDetectorNear(nearPos)
        if not cd then
            cd = _waitOpenUiClickDetector(inst, function()
                _fireClickPackBurst(inst, "poll_burst")
            end)
        end
        if cd and _fireClickDetector(cd) then
            stats.lastClaimId = _primaryClaimId(inst)
            return _claimSucceeded(inst, nearPos, "ClickDetector")
        end
        return false
    end)
    if steps[#steps].ok then
        stats.lastMs = math.floor((os.clock() - t0) * 1000)
        return true, stats.lastMethod, steps
    end

    step("prompt_retry", function()
        local pp = _findProximityPromptNear(nearPos)
        if pp and _fireProximityPrompt(pp) then
            return _claimSucceeded(inst, nearPos, "ProximityPrompt")
        end
        return false
    end)
    if steps[#steps].ok then
        stats.lastMs = math.floor((os.clock() - t0) * 1000)
        return true, stats.lastMethod, steps
    end

    step("burst_final", function()
        _fireClickPackBurst(inst, "burst_final")
        return _claimSucceeded(inst, nearPos, "burst_final")
    end)
    if steps[#steps].ok then
        stats.lastMs = math.floor((os.clock() - t0) * 1000)
        return true, stats.lastMethod, steps
    end

    stats.lastMs = math.floor((os.clock() - t0) * 1000)
    return false, nil, steps
end

local function _collectSpawnEntries(folder)
    local out = {}
    if not folder then return out end
    for _, child in ipairs(folder:GetChildren()) do
        out[#out + 1] = child
    end
    return out
end

local function _countReadySpawns(folder)
    if not folder then return 0 end
    local n = 0
    for _, inst in ipairs(_collectSpawnEntries(folder)) do
        if _spawnHasAttrs(inst) and _canClaim(inst) then
            n += 1
        end
    end
    return n
end

local function _collectReadySpawns(folder)
    local out = {}
    if not folder then return out end
    for _, inst in ipairs(_collectSpawnEntries(folder)) do
        if _spawnHasAttrs(inst) and _canClaim(inst) then
            out[#out + 1] = inst
        end
    end
    return out
end

local function _pickNextReadySpawn(batch)
    if type(batch) ~= "table" or #batch == 0 then return nil end
    local best, bestD = batch[1], _distToSpawn(batch[1])
    if bestD == nil then bestD = math.huge end
    for i = 2, #batch do
        local inst = batch[i]
        local d = _distToSpawn(inst)
        if d == nil then
            if bestD == math.huge then best = inst end
        elseif d < bestD then
            best = inst
            bestD = d
        end
    end
    return best
end

local function _followClaimSeed(inst)
    if not inst or not inst.Parent or not _spawnHasAttrs(inst) then
        return false
    end

    local locked, lockKey = _claimLock(inst)
    if not locked then
        _dbgSkip("in_flight", inst.Name)
        return false
    end

    stats.attempts += 1
    _resetClaimAttempt()
    local label = _spawnLabel(inst)
    _dbg("follow start:", label, inst.Name)
    local success = false
    local t0 = os.clock()

    local okRun, errRun = pcall(function()
        _stickUnderSeed(inst)
        if AFTER_TP_SEC > 0 then task.wait(AFTER_TP_SEC) end

        local lastFire = 0
        local lastFullClaim = 0

        while running and _enabled() and inst.Parent and os.clock() - t0 < MAX_FOLLOW_SEC do
            _stickUnderSeed(inst)

            if _otherWonClaim() then
                break
            end
            if _weWonClaim() then
                success = true
                stats.lastResult = label .. " / claimed_event"
                stats.lastMethod = "claimed_event"
                break
            end

            if not _spawnHasAttrs(inst) or not _packStillActive(inst) then
                local ok, reason = _waitClaimVerdict(CLAIM_VERDICT_WAIT, inst)
                if ok then
                    success = true
                    stats.lastResult = label .. " / " .. tostring(reason or "cleared")
                    stats.lastMethod = reason
                end
                break
            end

            local now = os.clock()
            if now - lastFire >= FOLLOW_FIRE_SEC then
                lastFire = now
                _fireClickPackBurst(inst, "follow_stick")
                local nearPos = _partWorldPos(inst)
                if nearPos then
                    local pp = _findProximityPromptNear(nearPos)
                    if pp then _fireProximityPrompt(pp) end
                end
            end
            if now - lastFullClaim >= 0.5 then
                lastFullClaim = now
                pcall(function()
                    _performClaim(inst)
                end)
            end

            if _weWonClaim() then
                success = true
                stats.lastResult = label .. " / claimed_event"
                stats.lastMethod = "claimed_event"
                break
            end
            if not _spawnHasAttrs(inst) or not _packStillActive(inst) then
                local okLate, reasonLate = _waitClaimVerdict(CLAIM_VERDICT_WAIT, inst)
                if okLate then
                    success = true
                    stats.lastResult = label .. " / " .. tostring(reasonLate or "cleared_late")
                    stats.lastMethod = reasonLate
                end
                break
            end

            task.wait(STICK_SEC)
        end

        if not success and os.clock() - t0 >= MAX_FOLLOW_SEC then
            _skip("follow_timeout")
        end
    end)

    _claimUnlock(lockKey)
    if not okRun then
        stats.lastError = tostring(errRun)
        _dbg("follow error:", errRun)
    elseif success then
        _dbg("follow ok:", label, "ms=", math.floor((os.clock() - t0) * 1000))
    else
        _dbg("follow fail:", label)
    end
    return success
end

local function _processClaimSession(folder)
    if not folder or not _enabled() or claimBusy then
        return 0
    end
    if _countReadySpawns(folder) <= 0 then
        return 0
    end

    claimBusy = true
    G.__GAG2_AUTO_CLAIM_SEED_BUSY = true
    _G.__GAG2_AUTO_CLAIM_SEED_BUSY = true
    _dbg("session start | ready=", _countReadySpawns(folder))

    local claimed = 0
    local ok, err = pcall(function()
        _teleStopForClaim()

        while running and _enabled() and _countReadySpawns(folder) > 0 do
            local batch = _collectReadySpawns(folder)
            if #batch == 0 then break end

            local inst = _pickNextReadySpawn(batch)
            if not inst or not inst.Parent or not _spawnHasAttrs(inst) or not _canClaim(inst) then
                _dbg("session break | invalid spawn pick")
                break
            end

            if _followClaimSeed(inst) then
                claimed += 1
                stats.fired += 1
                _markClaimed(inst, CLAIM_COOLDOWN)
                _dbg("session claimed:", _spawnLabel(inst), "total=", claimed)
            else
                local lost = _otherWonClaim()
                if lost then
                    _markClaimed(inst, LOST_CLAIM_COOLDOWN)
                    _dbgSkip("lost_to_other", inst.Name)
                elseif inst.Parent and _spawnHasAttrs(inst) and _packStillActive(inst) then
                    _dbgSkip("claim_retry_same", inst.Name)
                    task.wait(FOLLOW_FIRE_SEC)
                else
                    _markClaimed(inst, 1.2)
                    _dbgSkip("claim_fail", inst.Name)
                end
            end
        end
    end)

    if not ok then
        stats.lastError = tostring(err)
        _dbg("session error:", err)
    end

    pcall(_teleResumeNow)
    claimBusy = false
    G.__GAG2_AUTO_CLAIM_SEED_BUSY = false
    _G.__GAG2_AUTO_CLAIM_SEED_BUSY = false
    _dbg("session end | claimed=", claimed)
    return claimed
end

local function _queueClaimSession(source)
    if claimBusy or not _enabled() then return false end
    local folder = _getSpawnFolder() or spawnFolder
    if not folder then
        _dbgSkip("no_spawn_folder")
        return false
    end
    _dbg("queue session:", tostring(source or "scan"))
    task.spawn(function()
        if claimBusy or not _enabled() then return end
        _processClaimSession(folder)
    end)
    return true
end

local function _scanFolder(folder)
    if not folder then
        _dbgSkip("no_spawn_folder")
        return 0
    end
    local entries = _collectSpawnEntries(folder)
    local readyList = {}
    for _, inst in ipairs(entries) do
        if inst and inst.Parent and _spawnHasAttrs(inst) then
            readyList[#readyList + 1] = inst
        end
    end
    lastScanInfo.count = #entries
    lastScanInfo.ready = #readyList
    lastScanInfo.at = os.clock()

    if #readyList > 0 then
        _dbg("scan ready=", #readyList, "total=", #entries, "busy=", claimBusy)
    end

    if #readyList == 0 then return 0 end
    if claimBusy then return 0 end
    return _processClaimSession(folder)
end

local function _unbindAttrWatchers()
    for inst, conns in pairs(attrConns) do
        if type(conns) == "table" then
            for _, conn in ipairs(conns) do
                if conn and conn.Disconnect then conn:Disconnect() end
            end
        end
        attrConns[inst] = nil
    end
end

local function _bindSpawnInst(inst)
    if not inst or not inst.Parent or attrConns[inst] then return end
    local conns = {}
    for _, attr in ipairs(_getWatchAttrNames(inst)) do
        local ok, sig = pcall(function() return inst:GetAttributeChangedSignal(attr) end)
        if ok and sig and type(sig.Connect) == "function" then
            conns[#conns + 1] = sig:Connect(function()
                pcall(function()
                    if _enabled() and inst.Parent and _spawnHasAttrs(inst) then
                        task.spawn(function() _prefireRemote(inst, "attr_" .. attr) end)
                        _queueClaimSession("attr:" .. attr)
                    end
                end)
            end)
        end
    end
    if #conns > 0 then attrConns[inst] = conns end
end

local function _bindFolder(folder)
    if not folder then return end
    if childConn then childConn:Disconnect() childConn = nil end
    _unbindAttrWatchers()
    for _, child in ipairs(folder:GetChildren()) do _bindSpawnInst(child) end
    childConn = folder.ChildAdded:Connect(function(child)
        if not child then return end
        _bindSpawnInst(child)
        task.spawn(function()
            if _spawnHasAttrs(child) then
                _prefireRemote(child, "child_prefire")
                _queueClaimSession("child")
                return
            end
            local deadline = os.clock() + ATTR_WAIT_SEC
            while child.Parent and os.clock() < deadline do
                if _spawnHasAttrs(child) then
                    _prefireRemote(child, "child_wait")
                    _queueClaimSession("child-wait")
                    return
                end
                task.wait(ATTR_POLL_SEC)
            end
        end)
    end)
end

local function _ensureMapWatch()
    if mapConn then return end
    local map = _getMap()
    if not map then
        mapConn = workspace.ChildAdded:Connect(function(child)
            if not child or not child.Name then return end
            if child.Name == "Map" then
                spawnFolder = nil
                _ensureWatchers()
            end
        end)
        return
    end
    mapConn = map.ChildAdded:Connect(function(child)
        if not child or not child.Name then return end
        if child.Name == "SeedPackSpawnServerLocations" then
            spawnFolder = child
            _bindFolder(child)
        end
    end)
end

local function _ensureWatchers()
    _ensureMapWatch()
    _ensureSpawnSeedPackController()
    local folder = _getSpawnFolder()
    if folder and folder ~= spawnFolder then
        spawnFolder = folder
        _bindFolder(folder)
    end
    return folder
end

local function _bindFx()
    if fxConn then return end
    _initRemotes()
    if not SeedPackFX or not SeedPackFX.OnClientEvent then return end
    fxConn = SeedPackFX.OnClientEvent:Connect(function(pos)
        lastFxAt = os.clock()
        if typeof(pos) == "Vector3" then lastFxPos = pos end
    end)
end

local function claimLoop(myId)
    loopAliveId = myId
    _initRemotes()
    _bindFx()
    _dbg("loop start | id=", myId)
    while running and loopId == myId do
        local ok, err = pcall(function()
            if not _enabled() then
                task.wait(0.5)
                return
            end
            if not _initRemotes() then
                _dbg("loop wait remote")
                task.wait(0.5)
                return
            end
            if not savedGardenCf then savedGardenCf = _getGardenCFrame() end
            local folder = _ensureWatchers()
            local claimed = _scanFolder(folder)
            if SCAN_SEC <= 0 then RunService.Heartbeat:Wait() else task.wait(SCAN_SEC) end
        end)
        if not ok then
            stats.lastError = tostring(err)
            _dbg("loop error:", err)
            task.wait(0.5)
        end
    end
    if loopAliveId == myId then loopAliveId = 0 end
    _dbg("loop stop | id=", myId)
end

function M.ClaimOnce()
    if not _enabled() then return 0 end
    return _scanFolder(_ensureWatchers())
end
M.claimOnce = M.ClaimOnce

function M.EnsureRunning()
    if not _enabled() then
        M.Stop()
        return false
    end
    if running and loopAliveId > 0 and loopAliveId == loopId then
        return true
    end
    M.Start()
    return running
end
M.ensureRunning = M.EnsureRunning

function M.Start()
    _initRemotes()
    if not _enabled() then
        running = false
        return
    end
    if running and loopAliveId > 0 and loopAliveId == loopId then
        return
    end
    running = true
    loopId = loopId + 1
    local myId = loopId
    savedGardenCf = savedGardenCf or _getGardenCFrame()
    _ensureWatchers()
    _bindFx()
    task.spawn(function() claimLoop(myId) end)
end
M.start = M.Start

function M.Stop()
    running = false
    loopId += 1
    if claimBusy then
        _teleResumeNow()
        claimBusy = false
        G.__GAG2_AUTO_CLAIM_SEED_BUSY = false
        _G.__GAG2_AUTO_CLAIM_SEED_BUSY = false
    end
    if childConn then childConn:Disconnect() childConn = nil end
    _unbindAttrWatchers()
end
M.stop = M.Stop

function M.IsRunning()
    return running == true
end

function M.ApplyRuntime(on)
    M.SetEnabled(on == true)
end
M.applyRuntime = M.ApplyRuntime

function M.SyncFromGlobals()
    M.SetEnabled(_enabled())
end
M.syncFromGlobals = M.SyncFromGlobals
M.SyncFromState = M.SyncFromGlobals
M.syncFromState = M.SyncFromGlobals

function M.SetEnabled(on)
    on = _writeEnabled(on == true)
    if on then
        M.Start()
    else
        M.Stop()
    end
end
M.setEnabled = M.SetEnabled

function M.SetDebug(on)
    on = (on == true)
    G.AUTO_CLAIM_SEED_DEBUG = on
    _G.AUTO_CLAIM_SEED_DEBUG = on
    return on
end
M.setDebug = M.SetDebug

function M.GetDebugLogPath()
    return nil
end
M.getDebugLogPath = M.GetDebugLogPath

function M.GetDiagnostics()
    _initRemotes()
    local folder = _getSpawnFolder()
    local active = {}
    if folder then
        for _, inst in ipairs(_collectSpawnEntries(folder)) do
            local ok, row = pcall(function()
                local label, openPack = _resolveSpawnInfo(inst)
                local activeBoolSeeds = {}
                for _, attr in ipairs(_getWatchAttrNames(inst)) do
                    if attr ~= "SeedPack" and _boolSeedActive(inst, attr) then
                        activeBoolSeeds[#activeBoolSeeds + 1] = attr
                    end
                end
                return {
                    name = inst.Name,
                    class = inst.ClassName,
                    claimId = _primaryClaimId(inst),
                    claimIds = table.concat(_getClaimIds(inst), ", "),
                    label = label,
                    openPack = openPack,
                    ready = _spawnHasAttrs(inst),
                    gameValidated = gameValidatedSpawns[inst] ~= nil,
                    pack = _getSpawnAttr(inst, "SeedPack"),
                    boolSeeds = table.concat(activeBoolSeeds, ", "),
                    dist = _distToSpawn(inst),
                    attrs = (function()
                        local parts = {}
                        for n, v in pairs(inst:GetAttributes()) do
                            parts[#parts + 1] = n .. "=" .. tostring(v)
                        end
                        table.sort(parts)
                        return table.concat(parts, ", ")
                    end)(),
                }
            end)
            if ok and type(row) == "table" then active[#active + 1] = row end
        end
    end
    return {
        enabled = _enabled(),
        running = running,
        remote = ClickPack ~= nil,
        remotePath = remotePath or "Networking.SeedPack.ClickPack",
        spawnFolder = folder and folder:GetFullName() or nil,
        activeSpawns = active,
        activeCount = #active,
        readyToClaim = folder and _countReadySpawns(folder) or 0,
        claimBusy = claimBusy,
        telePaused = telePaused,
        underY = UNDER_Y,
        lastScan = lastScanInfo,
        stats = stats,
        storeEnabled = type(G.__GAG2_CLAIM_SEED) == "table" and G.__GAG2_CLAIM_SEED.enabled or nil,
        spawnControllerHooked = spawnCtrlHooked,
        spawnController = SPAWN_CTRL_NAME,
        seedBoolAttrOrder = _getSeedBoolAttrOrder(),
        gameValidatedCount = (function()
            local n = 0
            for _ in pairs(gameValidatedSpawns) do n += 1 end
            return n
        end)(),
    }
end
M.getDiagnostics = M.GetDiagnostics

local function _formatSkipCounts(skipped)
    if type(skipped) ~= "table" or next(skipped) == nil then
        return "(none)"
    end
    local parts = {}
    for reason, count in pairs(skipped) do
        parts[#parts + 1] = tostring(reason) .. "=" .. tostring(count)
    end
    table.sort(parts)
    return table.concat(parts, ", ")
end

local function _formatValue(v)
    if v == nil then return "nil" end
    local t = type(v)
    if t == "string" or t == "number" or t == "boolean" then
        return tostring(v)
    end
    if t == "table" then
        local parts = {}
        for k, val in pairs(v) do
            parts[#parts + 1] = tostring(k) .. "=" .. _formatValue(val)
        end
        table.sort(parts)
        if #parts == 0 then return "{}" end
        return "{" .. table.concat(parts, ", ") .. "}"
    end
    return tostring(v)
end

function M.DebugWhyNot(_self)
    local d = M.GetDiagnostics()
    local report = {
        ok = true,
        reasons = {},
        enabled = d.enabled == true,
        running = d.running == true,
        remote = d.remote == true,
        spawnFolder = d.spawnFolder,
        readyToClaim = d.readyToClaim or 0,
        activeCount = d.activeCount or 0,
        claimBusy = d.claimBusy == true,
        telePaused = d.telePaused == true,
        lastError = d.stats and d.stats.lastError or nil,
        lastSkip = d.stats and d.stats.lastSkip or nil,
        lastResult = d.stats and d.stats.lastResult or nil,
    }

    local function fail(code, msg)
        report.ok = false
        report.reasons[#report.reasons + 1] = msg and (code .. ": " .. msg) or code
    end

    if not report.enabled then
        fail("disabled", "Enable Auto Claim Seed di tab AUTO")
    end
    if not report.remote then
        fail("no_remote", "Networking.SeedPack.ClickPack belum ready — re-execute hub")
    end
    if not report.spawnFolder then
        fail("no_spawn_folder", "Map.SeedPackSpawnServerLocations tidak ditemukan")
    end
    if report.readyToClaim <= 0 then
        fail("no_ready_seed", "Tidak ada seed pack siap claim di map")
    end
    if report.claimBusy then
        fail("busy", "Sedang proses claim — tunggu sebentar")
    end

    local lines = { "========== Auto Claim Seed DebugWhyNot ==========" }
    lines[#lines + 1] = "ok: " .. tostring(report.ok)
    lines[#lines + 1] = "enabled: " .. tostring(report.enabled)
        .. " | running: " .. tostring(report.running)
        .. " | remote: " .. tostring(report.remote)
    lines[#lines + 1] = "spawn folder: " .. tostring(report.spawnFolder or "MISSING")
    lines[#lines + 1] = "ready to claim: " .. tostring(report.readyToClaim)
        .. " | active spawns: " .. tostring(report.activeCount)
    lines[#lines + 1] = "claim busy: " .. tostring(report.claimBusy)
        .. " | tele paused: " .. tostring(report.telePaused)
    if report.lastError and tostring(report.lastError) ~= "" then
        lines[#lines + 1] = "last error: " .. tostring(report.lastError)
    end
    if report.lastSkip and tostring(report.lastSkip) ~= "" then
        lines[#lines + 1] = "last skip: " .. tostring(report.lastSkip)
    end
    if report.lastResult ~= nil then
        lines[#lines + 1] = "last result: " .. _formatValue(report.lastResult)
    end
    if #report.reasons > 0 then
        lines[#lines + 1] = "reasons:"
        for _, r in ipairs(report.reasons) do
            lines[#lines + 1] = "  - " .. r
        end
    end
    lines[#lines + 1] = "hint: AutoClaimSeed.SetDebug(true) untuk log sementara"
    lines[#lines + 1] = "================================================="
    local out = table.concat(lines, "\n")
    print(out)
    return report
end
M.debugWhyNot = M.DebugWhyNot

function M.PrintDiagnostics(_self)
    local d = M.GetDiagnostics()
    local st = type(d.stats) == "table" and d.stats or {}

    print("========== GAG2 Auto Claim Seed ==========")
    print("enabled:", d.enabled, "| running:", d.running, "| store:", d.storeEnabled)
    if d.enabled ~= true and d.running == true then
        print("warn: running=true tapi enabled=false — toggle OFF lalu ON, atau re-execute hub")
    end
    print("remote:", d.remote, "| path:", tostring(d.remotePath or "MISSING"))
    print("spawn folder:", tostring(d.spawnFolder or "MISSING"))
    print("active spawns:", tostring(d.activeCount or 0), "| ready to claim:", tostring(d.readyToClaim or 0))
    print("claim busy:", d.claimBusy, "| tele paused:", d.telePaused, "| under Y:", d.underY)
    print("spawn controller hooked:", d.spawnControllerHooked,
        "| attrs:", table.concat(d.seedBoolAttrOrder or {}, ", "))
    if type(d.lastScan) == "table" then
        print("last scan: total=", d.lastScan.count, "ready=", d.lastScan.ready)
    end

    print("-- stats --")
    print("  attempts:", st.attempts, "| fired:", st.fired, "| remoteOk:", st.remoteOk)
    print("  teleports:", st.teleports, "| clickOk:", st.clickOk, "| prefire:", st.prefire)
    print("  lastMethod:", tostring(st.lastMethod or "-"))
    print("  lastClaimId:", tostring(st.lastClaimId or "-"))
    print("  lastResult:", _formatValue(st.lastResult))
    print("  lastSkip:", tostring(st.lastSkip or "-"))
    print("  lastError:", tostring(st.lastError or "-"))
    print("  lastMs:", tostring(st.lastMs or "-"))
    print("  skipped:", _formatSkipCounts(st.skipped))

    if type(d.activeSpawns) == "table" and #d.activeSpawns > 0 then
        print("-- active spawns (max 8) --")
        for i = 1, math.min(8, #d.activeSpawns) do
            local row = d.activeSpawns[i]
            if type(row) == "table" then
                print(string.format(
                    "  [%d] %s | %s | ready=%s | dist=%s | claimId=%s",
                    i,
                    tostring(row.label or row.name or "?"),
                    tostring(row.class or "?"),
                    tostring(row.ready),
                    tostring(row.dist),
                    tostring(row.claimId or "-")
                ))
                if row.attrs and tostring(row.attrs) ~= "" then
                    print("       attrs:", row.attrs)
                end
            end
        end
        if #d.activeSpawns > 8 then
            print("  ... +" .. tostring(#d.activeSpawns - 8) .. " more")
        end
    else
        print("-- active spawns: (none) --")
    end

    print("hint: AutoClaimSeed.SetDebug(true) untuk log sementara")
    print("========================================")
    return d
end
M.printDiagnostics = M.PrintDiagnostics
M.Debug = M.PrintDiagnostics
M.debug = M.PrintDiagnostics

G.AutoClaimSeed = M
G.AutoClaimSeedModule = M
_G.AutoClaimSeed = M
_G.AutoClaimSeedModule = M

G.AUTO_CLAIM_SEED_DEBUG = false
_G.AUTO_CLAIM_SEED_DEBUG = false

task.defer(function()
    claimBusy = false
    G.__GAG2_AUTO_CLAIM_SEED_BUSY = false
    _G.__GAG2_AUTO_CLAIM_SEED_BUSY = false
    _refreshSeedBoolAttrOrder()
    _initRemotes()
    _ensureSpawnSeedPackController()
    _ensureWatchers()
    _bindFx()
    if _enabled() then
        M.EnsureRunning()
    end
end)

return M
 end,                  required = false },
    { key = "AutoHopServer",           name = "Auto Hop Server",         factory = function() -- AutoHopServer.lua — Grow A Garden 2
-- Adapted from auto_snipe_hop (NodeHub Market)
-- ✅ 1 Hop Session (serial attempts, no storm)
-- ✅ Anti IsTeleporting spam (lock window)
-- ✅ If target dead/full -> mark & try next candidate
-- ✅ TeleportData confirm -> push visited (persist)
-- ✅ PRE-HOP: mark current server JobId to visited BEFORE building candidates (STATE + FILE)
-- ✅ Candidates filter uses visited from STATE + FILE cache
-- ✅ If visited reached diffServers -> clear visited (STATE + FILE) + invalidate cache ts
-- ✅ Cache candidates to FILE per username + (placeId,targetPlayers,diffServers) to reduce 429
-- ✅ 429 backoff -> stop scan and rely on cache
-- ✅ Works with PSReconnect:HopToServer (keeps QTP gating). Fallback to TeleportToPlaceInstance if needed.

local M = {}

----------------------------------------------------------------
-- Services
----------------------------------------------------------------
local Players         = game:GetService("Players")
local TeleportService = game:GetService("TeleportService")
local HttpService     = game:GetService("HttpService")

local LP = Players.LocalPlayer

local function getLP()
    return Players.LocalPlayer or LP
end

----------------------------------------------------------------
-- Runtime status (for UI)
----------------------------------------------------------------
local _lastStatus = "idle"
local _lastSessionErr = nil
local _lastScanPages = 0
local _lastScanServers = 0
local _debug = false
local function dprint(...)
    if not _debug then return end
    print("[GAG2-AutoHop]", ...)
end

local function now() return os.clock() end
local function low(s) return string.lower(tostring(s or "")) end

----------------------------------------------------------------
-- Utils
----------------------------------------------------------------
local function clampNum(v, minv, maxv, fallback)
    local n = tonumber(v)
    if n == nil then return fallback end
    if minv ~= nil and n < minv then n = minv end
    if maxv ~= nil and n > maxv then n = maxv end
    return n
end

local function isArray(t)
    return type(t) == "table" and rawget(t, 1) ~= nil
end

local function ensureArray(t)
    if type(t) ~= "table" then return {} end
    if isArray(t) then return t end
    return {}
end

local SORT_SPLIT_TARGET = 4
local GAME_SERVER_MAX   = 8
local HOP_CURRENT_PLAYER_MIN     = 1
local HOP_CURRENT_PLAYER_DEFAULT = 1
local HOP_TELEPORT_DELAY_MIN     = 10
local HOP_TELEPORT_DELAY_DEFAULT = 10

local function clampCurrentPlayers(v)
    return clampNum(v, HOP_CURRENT_PLAYER_MIN, 100, HOP_CURRENT_PLAYER_DEFAULT)
end

local function clampTeleportDelay(v)
    return clampNum(v, HOP_TELEPORT_DELAY_MIN, 600, HOP_TELEPORT_DELAY_DEFAULT)
end

-- Auto-adapt: bandingkan Current Player Max vs Target Server
-- current > target  -> server ramai, cari lebih sepi (Asc)
-- current < target  -> server sepi, cari lebih ramai (Desc)
local function getHopMode(currentPlayers, targetPlayers)
    currentPlayers = clampCurrentPlayers(currentPlayers)
    targetPlayers = clampNum(targetPlayers, 1, 100, 1)
    if currentPlayers > targetPlayers then
        return "leave_crowded"
    end
    if currentPlayers < targetPlayers then
        return "leave_quiet"
    end
    return "balanced"
end

local function getSortOrdersForHop(currentPlayers, targetPlayers)
    local mode = getHopMode(currentPlayers, targetPlayers)
    if mode == "leave_crowded" then
        return "Asc", "Desc"
    elseif mode == "leave_quiet" then
        return "Desc", "Asc"
    end
    targetPlayers = clampNum(targetPlayers, 1, 100, 1)
    if targetPlayers <= SORT_SPLIT_TARGET then
        return "Asc", "Desc"
    end
    return "Desc", "Asc"
end

local function preferHigherPlaying(currentPlayers, targetPlayers)
    return getHopMode(currentPlayers, targetPlayers) == "leave_quiet"
end

local function getScanPagesForHop(currentPlayers, targetPlayers, isFallback)
    targetPlayers = clampNum(targetPlayers, 1, 100, 1)
    currentPlayers = clampCurrentPlayers(currentPlayers)
    local gap = math.abs(currentPlayers - targetPlayers)
    local base
    if getHopMode(currentPlayers, targetPlayers) == "leave_crowded" and targetPlayers <= SORT_SPLIT_TARGET then
        base = isFallback and 6 or 10
    else
        base = isFallback and 8 or 12
    end
    if gap >= 5 then
        base += isFallback and 2 or 4
    end
    return base
end

local function getHopTriggerHint(currentPlayers, targetPlayers)
    currentPlayers = clampCurrentPlayers(currentPlayers)
    targetPlayers = clampNum(targetPlayers, 1, 100, 1)
    local mode = getHopMode(currentPlayers, targetPlayers)
    if mode == "leave_crowded" then
        return "Hop when players >= " .. currentPlayers .. " (target ~" .. targetPlayers .. ")"
    elseif mode == "leave_quiet" then
        return "Hop when players <= " .. currentPlayers .. " (target ~" .. targetPlayers .. ")"
    end
    return "Hop when players >= " .. currentPlayers
end

----------------------------------------------------------------
-- FILE CACHE (reduce 429)
----------------------------------------------------------------
local FS_OK = (type(readfile)=="function" and type(writefile)=="function" and type(isfile)=="function")

local function ensureFolder(path)
    if type(makefolder) ~= "function" then return end
    if type(isfolder) == "function" and isfolder(path) then return end
    local parts = {}
    for seg in tostring(path):gmatch("[^/]+") do
        parts[#parts+1] = seg
        local p = table.concat(parts, "/")
        if type(isfolder) ~= "function" or not isfolder(p) then
            pcall(function() makefolder(p) end)
        end
    end
end

local CACHE_DIR = "growagarden2"

local function safeCacheUserName(s)
    s = tostring(s or "player")
    s = s:gsub("[^%w%-_.]", "_")
    s = s:gsub("_+", "_")
    return s:sub(1, 48)
end

local function getCacheFile()
    local lp = getLP()
    local user = (lp and lp.Name) or "player"
    return CACHE_DIR .. "/autohop_cache_" .. safeCacheUserName(user) .. ".json"
end

local function safeJsonDecode(s)
    local ok, t = pcall(function() return HttpService:JSONDecode(s) end)
    if ok and type(t) == "table" then return t end
    return nil
end

local function safeJsonEncode(t)
    local ok, s = pcall(function() return HttpService:JSONEncode(t) end)
    if ok and type(s) == "string" then return s end
    return nil
end

local function readCacheRoot()
    if not FS_OK then return {} end
    local cacheFile = getCacheFile()
    if not isfile(cacheFile) then return {} end
    local ok, content = pcall(function() return readfile(cacheFile) end)
    if not ok or type(content) ~= "string" then return {} end
    return safeJsonDecode(content) or {}
end

local function writeCacheRoot(root)
    if not FS_OK then return end
    ensureFolder(CACHE_DIR)
    local s = safeJsonEncode(root)
    if not s then return end
    pcall(function() writefile(getCacheFile(), s) end)
end

local function makeCacheKey(placeId, currentPlayers, targetPlayers, diffServers)
    currentPlayers = clampCurrentPlayers(currentPlayers)
    targetPlayers = clampNum(targetPlayers, 1, 100, 1)
    diffServers = clampNum(diffServers, 1, 200, 5)
    local primary = select(1, getSortOrdersForHop(currentPlayers, targetPlayers))
    return tostring(placeId)
        .. "|cur=" .. tostring(currentPlayers)
        .. "|tp=" .. tostring(targetPlayers)
        .. "|diff=" .. tostring(diffServers)
        .. "|sort=" .. primary
end

-- root[key] = { ts=os.time(), candidates={...}, visited={...} }
local function cacheLoad(placeId, currentPlayers, targetPlayers, diffServers)
    local root = readCacheRoot()
    local key  = makeCacheKey(placeId, currentPlayers, targetPlayers, diffServers)
    local rec  = (type(root[key])=="table") and root[key] or {}
    return root, key, rec
end

local function cacheSave(placeId, currentPlayers, targetPlayers, diffServers, patch)
    local root, key, rec = cacheLoad(placeId, currentPlayers, targetPlayers, diffServers)
    rec = (type(rec)=="table") and rec or {}
    patch = (type(patch)=="table") and patch or {}
    for k,v in pairs(patch) do rec[k] = v end
    root[key] = rec
    writeCacheRoot(root)
end

local function cacheGetCandidates(placeId, currentPlayers, targetPlayers, diffServers, maxAgeSec)
    maxAgeSec = tonumber(maxAgeSec) or 900
    local _, _, rec = cacheLoad(placeId, currentPlayers, targetPlayers, diffServers)
    local ts  = tonumber(rec.ts) or 0
    local arr = rec.candidates
    if type(arr) ~= "table" then return nil, "no_cache" end
    local age = os.time() - ts
    if age > maxAgeSec then
        return ensureArray(arr), "stale_cache"
    end
    return ensureArray(arr), "fresh_cache"
end

local function cacheSetCandidates(placeId, currentPlayers, targetPlayers, diffServers, candidates)
    candidates = ensureArray(candidates)
    cacheSave(placeId, currentPlayers, targetPlayers, diffServers, {
        ts = os.time(),
        candidates = candidates,
    })
end

local function cacheGetVisited(placeId, currentPlayers, targetPlayers, diffServers)
    local _, _, rec = cacheLoad(placeId, currentPlayers, targetPlayers, diffServers)
    local v = rec.visited
    if type(v) ~= "table" then return {} end
    return ensureArray(v)
end

local function cacheSetVisited(placeId, currentPlayers, targetPlayers, diffServers, visitedArr)
    visitedArr = ensureArray(visitedArr)
    cacheSave(placeId, currentPlayers, targetPlayers, diffServers, {
        visited = visitedArr,
    })
end

----------------------------------------------------------------
-- State read
----------------------------------------------------------------
local function _persistState()
    local G = (getgenv and getgenv()) or _G
    if G.__GAG2_RESETTING == true then return end

    local saveVisited = G.__GAG2_SAVE_AUTO_HOP_VISITED or rawget(_G, "__GAG2_SAVE_AUTO_HOP_VISITED")
    if type(saveVisited) == "function" then
        local visited = {}
        local main = G.MAIN or rawget(_G, "MAIN")
        if type(main) == "table" and type(main.misc) == "table"
            and type(main.misc.rejoin) == "table"
            and type(main.misc.rejoin.auto_hop) == "table"
            and type(main.misc.rejoin.auto_hop.visited) == "table" then
            visited = main.misc.rejoin.auto_hop.visited
        end
        task.defer(function()
            pcall(saveVisited, visited)
        end)
        return
    end

    if type(G.__GAG2_AUTO_SAVE) == "function" then
        task.defer(function() pcall(G.__GAG2_AUTO_SAVE) end)
    end
end

----------------------------------------------------------------
-- State read (GAG2 — MAIN.misc.rejoin.auto_hop)
----------------------------------------------------------------
local function _getState()
    local G = (getgenv and getgenv()) or _G
    local MAIN = G.MAIN or rawget(_G, "MAIN")
    MAIN = (type(MAIN) == "table") and MAIN or {}
    MAIN.misc = (type(MAIN.misc) == "table") and MAIN.misc or {}
    MAIN.misc.rejoin = (type(MAIN.misc.rejoin) == "table") and MAIN.misc.rejoin or {}
    MAIN.misc.rejoin.auto_hop = (type(MAIN.misc.rejoin.auto_hop) == "table") and MAIN.misc.rejoin.auto_hop or {}

    local AH = MAIN.misc.rejoin.auto_hop
    local saved = type(G.__AUTO_HOP_SAVED) == "table" and G.__AUTO_HOP_SAVED

    if AH.enabled == nil then
        if saved and saved.enabled ~= nil then
            AH.enabled = (saved.enabled == true)
        else
            AH.enabled = (G.AUTO_HOP_ENABLED == true)
        end
    end
    if tonumber(AH.current_player) == nil then
        AH.current_player = (saved and tonumber(saved.current))
            or tonumber(AH.current)
            or tonumber(G.AUTO_HOP_CURRENT_PLAYER)
            or HOP_CURRENT_PLAYER_DEFAULT
    end
    if tonumber(AH.max_player) == nil then
        AH.max_player = (saved and tonumber(saved.max))
            or tonumber(AH.max)
            or tonumber(G.AUTO_HOP_MAX_PLAYER)
            or 1
    end
    if tonumber(AH.teleport_delay) == nil then
        AH.teleport_delay = (saved and tonumber(saved.delay))
            or tonumber(G.AUTO_HOP_TELEPORT_DELAY)
            or HOP_TELEPORT_DELAY_DEFAULT
    end
    if tonumber(AH.minutes) == nil then AH.minutes = 8 end
    if tonumber(AH.diff_servers) == nil then AH.diff_servers = 5 end
    AH.visited = ensureArray(AH.visited)

    AH.current_player = clampCurrentPlayers(AH.current_player)
    AH.max_player   = clampNum(AH.max_player, 1, 100, 1)
    AH.teleport_delay = clampTeleportDelay(AH.teleport_delay)
    AH.minutes      = clampNum(AH.minutes, 1, 1440, 8)
    AH.diff_servers = clampNum(AH.diff_servers, 1, 200, 5)

    G.MAIN = MAIN
    _G.MAIN = MAIN

    local STATE = G.STATE or rawget(_G, "STATE")
    if type(STATE) == "table" then
        STATE.rejoin = STATE.rejoin or {}
        STATE.rejoin.auto_hop = AH
    end

    return MAIN, AH
end

local function getCfg()
    local MAIN, AH = _getState()

    local target = clampNum(AH.max_player, 1, 100, 1)

    return {
        enabled        = (AH.enabled == true),
        minutes        = clampNum(AH.minutes, 1, 1440, 8),
        diffServers    = clampNum(AH.diff_servers, 1, 200, 5),
        currentPlayers = clampCurrentPlayers(AH.current_player),
        targetPlayers  = target,
        teleportDelay  = clampTeleportDelay(AH.teleport_delay),
        AH = AH,
        MAIN = MAIN,
    }
end

local function getLocalPlayerCount()
    local n = 0
    pcall(function()
        n = #Players:GetPlayers()
    end)
    return n
end

----------------------------------------------------------------
-- visited helpers (STATE + FILE)
----------------------------------------------------------------
local function buildSetFromArray(arr)
    local set = {}
    arr = ensureArray(arr)
    for _, v in ipairs(arr) do
        local s = tostring(v or "")
        if s ~= "" then set[s] = true end
    end
    return set
end

local function resetVisitedIfNeeded(placeId, currentPlayers, targetPlayers, diffServers, AH)
    local limit = tonumber(AH and AH.diff_servers) or diffServers or 5
    AH.visited = ensureArray(AH and AH.visited)

    if #AH.visited >= limit then
        AH.visited = {}
        dprint("visited reset limit", limit)

        cacheSetVisited(placeId, currentPlayers, targetPlayers, diffServers, AH.visited)
        cacheSave(placeId, currentPlayers, targetPlayers, diffServers, { ts = 0, scanCursor = {} })
        _persistState()
        return true
    end
    return false
end

-- ✅ PRE-HOP: always mark current server to visited (STATE + FILE)
local function pushVisitedPreHop(jobId)
    local cfg = getCfg()
    local placeId = game.PlaceId

    jobId = tostring(jobId or "")
    if jobId == "" then return false end

    local AH = cfg.AH
    AH.visited = ensureArray(AH.visited)

    for _, v in ipairs(AH.visited) do
        if tostring(v) == jobId then
            return false
        end
    end

    table.insert(AH.visited, jobId)
    dprint("visited prehop +1", jobId, "count", #AH.visited)

    cacheSetVisited(placeId, cfg.currentPlayers, cfg.targetPlayers, cfg.diffServers, AH.visited)
    resetVisitedIfNeeded(placeId, cfg.currentPlayers, cfg.targetPlayers, cfg.diffServers, AH)
    _persistState()

    return true
end

local function pushVisitedConfirmed(jobId)
    local cfg = getCfg()
    local placeId = game.PlaceId

    jobId = tostring(jobId or "")
    if jobId == "" then return end

    local AH = cfg.AH
    AH.visited = ensureArray(AH.visited)
    for _, v in ipairs(AH.visited) do
        if tostring(v) == jobId then return end
    end

    table.insert(AH.visited, jobId)
    dprint("visited confirmed +1", jobId, "count", #AH.visited)

    cacheSetVisited(placeId, cfg.currentPlayers, cfg.targetPlayers, cfg.diffServers, AH.visited)
    resetVisitedIfNeeded(placeId, cfg.currentPlayers, cfg.targetPlayers, cfg.diffServers, AH)
    _persistState()
end

----------------------------------------------------------------
-- Local avoid/recent/dead trackers
----------------------------------------------------------------
local AVOID_TTL_SEC    = 240
local AVOID_TTL_DEAD   = 900
local AVOID_TTL_FULL   = 240
local RECENT_TRIED_TTL = 240

local _avoidUntil  = {}
local _recentTried = {}
local _deadUntil   = {}

local function ttlAlive(map, jobId)
    jobId = tostring(jobId or "")
    if jobId == "" then return false end
    local untilT = map[jobId]
    if not untilT then return false end
    if now() >= untilT then
        map[jobId] = nil
        return false
    end
    return true
end

local function isAvoided(jobId) return ttlAlive(_avoidUntil, jobId) end
local function isRecent(jobId)  return ttlAlive(_recentTried, jobId) end
local function isDead(jobId)    return ttlAlive(_deadUntil, jobId) end

local function markAvoid(jobId, sec)
    jobId = tostring(jobId or "")
    if jobId == "" then return end
    sec = tonumber(sec) or AVOID_TTL_SEC
    _avoidUntil[jobId] = now() + sec
end

local function markRecent(jobId, sec)
    jobId = tostring(jobId or "")
    if jobId == "" then return end
    sec = tonumber(sec) or RECENT_TRIED_TTL
    _recentTried[jobId] = now() + sec
end

local function markDead(jobId, sec)
    jobId = tostring(jobId or "")
    if jobId == "" then return end
    sec = tonumber(sec) or AVOID_TTL_DEAD
    _deadUntil[jobId] = now() + sec
end

----------------------------------------------------------------
-- Roblox API backoff (429)
----------------------------------------------------------------
local _apiBlockedUntil = 0
local _api429WinStart  = 0
local _api429Count     = 0

local function apiBackoff(sec, why)
    sec = tonumber(sec) or 30
    local jitter = math.random(0, 8)
    _apiBlockedUntil = now() + sec + jitter
    dprint("API_BACKOFF", math.floor(sec + jitter), "sec", tostring(why or ""))
end

local function httpGet(url)
    if now() < (_apiBlockedUntil or 0) then
        return false, "rate_limited_local", 429
    end

    local req =
        (syn and syn.request) or
        (http and http.request) or
        http_request or
        request or
        (fluxus and fluxus.request)

    if type(req) == "function" then
        local res = req({ Url = url, Method = "GET" })
        local body = res and (res.Body or res.body)
        local code = tonumber(res and (res.StatusCode or res.status_code)) or 0

        if _debug then dprint("http", code, url) end

        if code == 429 then
            local t = now()
            if (t - _api429WinStart) > 60 then
                _api429WinStart = t
                _api429Count = 0
            end
            _api429Count += 1

            local base = 30
            if _api429Count >= 2 then base = 45 end
            if _api429Count >= 4 then base = 75 end
            apiBackoff(base, "http_429")
            return false, "http_429", 429
        end

        if type(body) == "string" and body ~= "" then
            return true, body, code
        end
        return false, "request_failed", code
    end

    local ok, body = pcall(function()
        return HttpService:GetAsync(url)
    end)
    if ok and type(body) == "string" and body ~= "" then
        return true, body, 200
    end

    ok, body = pcall(function()
        return game:HttpGet(url)
    end)
    if not ok then
        return false, body, 0
    end
    return true, body, 200
end

local API_PAGE_LIMIT    = 50   -- limit=100 sering return kosong / cursor null (bug Roblox API)
local API_PAGE_DELAY    = 0.22 -- jeda antar page biar tidak kena 429
local SCAN_EARLY_EXIT   = 22   -- cukup kandidat bagus -> stop scan (hemat API)

local function isServerJoinable(playing, maxPlayers)
    playing = tonumber(playing) or 0
    maxPlayers = tonumber(maxPlayers) or 0
    if maxPlayers <= 0 then return true end
    return playing < maxPlayers
end

-- Target 8 + max server 8 => full (8/8) tidak bisa join; aim ke 7/8
local function scoreTargetForServer(targetPlayers, maxPlayers)
    targetPlayers = clampNum(targetPlayers, 1, 100, 1)
    maxPlayers = tonumber(maxPlayers) or 0
    if maxPlayers <= 0 then
        maxPlayers = GAME_SERVER_MAX
    end
    if targetPlayers >= maxPlayers then
        return maxPlayers - 1
    end
    return targetPlayers
end

local function popScore(playing, targetPlayers, maxPlayers)
    local aim = scoreTargetForServer(targetPlayers, maxPlayers)
    return math.abs((tonumber(playing) or 0) - aim)
end

local function getExcludeFullForTarget(targetPlayers)
    targetPlayers = clampNum(targetPlayers, 1, 100, 1)
    return targetPlayers >= (GAME_SERVER_MAX - 1)
end

local function fetchServers(placeId, cursor, sortOrder, opts)
    opts = type(opts) == "table" and opts or {}
    local limit = clampNum(opts.limit, 10, 100, API_PAGE_LIMIT)
    local excludeFull = opts.excludeFullGames
    if excludeFull == nil then
        excludeFull = getExcludeFullForTarget(opts.targetPlayers or 1)
    end

    sortOrder = (tostring(sortOrder or "Asc") == "Desc") and "Desc" or "Asc"
    local url = ("https://games.roblox.com/v1/games/%d/servers/Public?sortOrder=%s&limit=%d"):format(
        placeId, sortOrder, limit
    )
    if excludeFull then
        url = url .. "&excludeFullGames=true"
    end
    if cursor and cursor ~= "" then
        url = url .. "&cursor=" .. HttpService:UrlEncode(tostring(cursor))
    end

    local ok, body, code = httpGet(url)
    if not ok then
        return nil, nil, ("http_failed:" .. tostring(body) .. "|code=" .. tostring(code))
    end

    local decoded
    local ok2 = pcall(function()
        decoded = HttpService:JSONDecode(body)
    end)
    if not ok2 or type(decoded) ~= "table" then
        return nil, nil, "json_decode_failed"
    end

    local data = decoded.data
    local nextCursor = decoded.nextPageCursor
    if type(data) ~= "table" then data = {} end

    -- Bug Roblox: limit=100 kadang data=[] + cursor null padahal masih ada server
    if #data == 0 and limit >= 100 and not opts._retriedSmaller then
        dprint("empty page limit=100 -> retry limit=50")
        return fetchServers(placeId, cursor, sortOrder, {
            limit = 50,
            excludeFullGames = excludeFull,
            targetPlayers = opts.targetPlayers,
            _retriedSmaller = true,
        })
    end

    return data, nextCursor, nil
end

local function filterCandidates(list, visitedSet, avoidJobId, targetPlayers, currentPlayers)
    local out = {}
    list = ensureArray(list)
    visitedSet = visitedSet or {}
    avoidJobId = tostring(avoidJobId or "")
    targetPlayers = tonumber(targetPlayers) or 1
    currentPlayers = clampCurrentPlayers(currentPlayers)
    local preferHigh = preferHigherPlaying(currentPlayers, targetPlayers)

    for _, rec in ipairs(list) do
        local id = tostring(rec.id or "")
        local playing = tonumber(rec.playing) or 0
        local maxPlayers = tonumber(rec.maxPlayers) or 0

        if id ~= ""
            and id ~= avoidJobId
            and not visitedSet[id]
            and not isDead(id)
            and not isAvoided(id)
            and not isRecent(id)
        then
            if isServerJoinable(playing, maxPlayers) then
                out[#out+1] = {
                    id = id,
                    playing = playing,
                    maxPlayers = maxPlayers,
                    score = popScore(playing, targetPlayers, maxPlayers),
                }
            end
        end
    end

    table.sort(out, function(a, b)
        if a.score ~= b.score then return a.score < b.score end
        if preferHigh then
            return a.playing > b.playing
        end
        return a.playing < b.playing
    end)

    local trimmed = {}
    for i = 1, math.min(#out, 28) do
        local rec = out[i]
        trimmed[#trimmed+1] = { id=rec.id, playing=rec.playing, maxPlayers=rec.maxPlayers }
    end
    return trimmed
end

----------------------------------------------------------------
-- Build candidates (cache-first, scan-later)
----------------------------------------------------------------
local function buildCandidates(placeId, currentPlayers, targetPlayers, diffServers, visitedSet, avoidJobId)
    visitedSet = visitedSet or {}
    avoidJobId = tostring(avoidJobId or "")
    currentPlayers = clampCurrentPlayers(currentPlayers)
    targetPlayers = clampNum(targetPlayers, 1, 100, 1)

    -- ✅ merge visited from file (persist)
    do
        local vfile = cacheGetVisited(placeId, currentPlayers, targetPlayers, diffServers)
        for _, jid in ipairs(ensureArray(vfile)) do
            visitedSet[tostring(jid)] = true
        end
    end

    -- 1) cache first (fresh)
    local cached, cacheState = cacheGetCandidates(placeId, currentPlayers, targetPlayers, diffServers, 900)
    if type(cached) == "table" and #cached > 0 and cacheState == "fresh_cache" then
        local filtered = filterCandidates(cached, visitedSet, avoidJobId, targetPlayers, currentPlayers)
        if #filtered > 0 then
            dprint("use cache candidates (fresh)", #filtered, "from", #cached)
            return filtered, nil, 0, cacheState
        end
        dprint("cache fresh exhausted by filters -> scan")
    end

    -- 2) if blocked -> stale cache only
    if now() < (_apiBlockedUntil or 0) then
        if type(cached) == "table" and #cached > 0 then
            local filtered = filterCandidates(cached, visitedSet, avoidJobId, targetPlayers, currentPlayers)
            if #filtered > 0 then
                dprint("use cache candidates (blocked)", #filtered, cacheState)
                return filtered, nil, 0, cacheState
            end
            dprint("blocked + cache exhausted by filters")
        end
        return nil, "api_blocked_no_cache", 0, cacheState
    end

    -- 3) scan (primary sort, fallback sort if needed)
    local primarySort, fallbackSort = getSortOrdersForHop(currentPlayers, targetPlayers)
    local scanned = 0
    local pagesTotal = 0
    local poolAbove, poolBelow = {}, {}
    local scanErr = nil
    local preferHigh = preferHigherPlaying(currentPlayers, targetPlayers)

    local _, _, cacheRec = cacheLoad(placeId, currentPlayers, targetPlayers, diffServers)
    local scanCursor = (type(cacheRec.scanCursor) == "table") and cacheRec.scanCursor or {}

    local function pushPool(pool, rec, maxN)
        pool[#pool+1] = rec
        if #pool > maxN then
            local worstI, worstS = 1, pool[1].score
            for i = 2, #pool do
                if pool[i].score > worstS then
                    worstS = pool[i].score
                    worstI = i
                end
            end
            table.remove(pool, worstI)
        end
    end

    local function poolCount()
        return #poolAbove + #poolBelow
    end

    local function scanWithSort(sortOrder, maxPages)
        local cursor = scanCursor[sortOrder]
        if cursor == "" then cursor = nil end
        local pagesScanned = 0
        local lastErr = nil

        for page = 1, maxPages do
            local servers, nextCursor, err = fetchServers(placeId, cursor, sortOrder, {
                targetPlayers = targetPlayers,
            })
            if not servers then
                lastErr = err
                break
            end

            pagesScanned += 1
            scanned += #servers

            for _, s in ipairs(servers) do
                local id = tostring(s.id or "")
                local playing = tonumber(s.playing) or 0
                local maxPlayers = tonumber(s.maxPlayers) or 0

                if id ~= ""
                    and id ~= avoidJobId
                    and not visitedSet[id]
                    and not isDead(id)
                    and not isAvoided(id)
                    and not isRecent(id)
                    and isServerJoinable(playing, maxPlayers)
                then
                    local score = popScore(playing, targetPlayers, maxPlayers)
                    local rec = { id=id, playing=playing, maxPlayers=maxPlayers, score=score }
                    local aim = scoreTargetForServer(targetPlayers, maxPlayers)
                    if playing >= aim then
                        pushPool(poolAbove, rec, 14)
                    else
                        pushPool(poolBelow, rec, 14)
                    end
                end
            end

            cursor = nextCursor
            scanCursor[sortOrder] = cursor or ""

            if poolCount() >= SCAN_EARLY_EXIT then
                dprint("scan early exit", sortOrder, "page", pagesScanned, "pool=", poolCount())
                break
            end

            if not nextCursor or nextCursor == "" then
                scanCursor[sortOrder] = ""
                break
            end

            if page < maxPages then
                task.wait(API_PAGE_DELAY)
            end
        end

        return pagesScanned, lastErr
    end

    local p1, errPrimary = scanWithSort(primarySort, getScanPagesForHop(currentPlayers, targetPlayers, false))
    pagesTotal += p1 or 0
    scanErr = errPrimary

    if poolCount() <= 0 then
        local p2, errFallback = scanWithSort(fallbackSort, getScanPagesForHop(currentPlayers, targetPlayers, true))
        pagesTotal += p2 or 0
        if errFallback and not scanErr then
            scanErr = errFallback
        end
        dprint("fallback sort", fallbackSort, "candidates=", poolCount())
    end

    _lastScanPages = pagesTotal
    _lastScanServers = scanned
    cacheSave(placeId, currentPlayers, targetPlayers, diffServers, { scanCursor = scanCursor })

    if poolCount() <= 0 then
        if tostring(scanErr or ""):find("429") or tostring(scanErr or ""):find("code=429") then
            if type(cached) == "table" and #cached > 0 then
                local filtered = filterCandidates(cached, visitedSet, avoidJobId, targetPlayers, currentPlayers)
                if #filtered > 0 then
                    dprint("scan failed 429 -> fallback cache(filtered)", #filtered, cacheState)
                    return filtered, nil, scanned, cacheState
                end
            end
        end
        if scanErr and poolCount() <= 0 then
            return nil, scanErr, scanned, cacheState
        end
    end

    dprint("scan sort primary=", primarySort, "fallback=", fallbackSort,
        "current=", currentPlayers, "target=", targetPlayers,
        "pages=", pagesTotal, "servers=", scanned)

    local candidates = {}
    local function sortPool(pool)
        table.sort(pool, function(a, b)
            if a.score ~= b.score then return a.score < b.score end
            if preferHigh then
                return a.playing > b.playing
            end
            return a.playing < b.playing
        end)
    end
    if #poolAbove > 0 then
        sortPool(poolAbove)
        for _, rec in ipairs(poolAbove) do
            candidates[#candidates+1] = { id=rec.id, playing=rec.playing, maxPlayers=rec.maxPlayers }
        end
    end
    if #poolBelow > 0 then
        sortPool(poolBelow)
        for _, rec in ipairs(poolBelow) do
            candidates[#candidates+1] = { id=rec.id, playing=rec.playing, maxPlayers=rec.maxPlayers }
        end
    end

    if #candidates > 0 then
        cacheSetCandidates(placeId, currentPlayers, targetPlayers, diffServers, candidates)
    end

    dprint("SCAN done scanned=", scanned, "candidates=", #candidates, "target=", targetPlayers)
    return candidates, nil, scanned, cacheState
end

----------------------------------------------------------------
-- Teleport wrappers
----------------------------------------------------------------
local function teleportToJob(placeId, jobId, teleportData)
    placeId = tonumber(placeId) or game.PlaceId
    jobId = tostring(jobId or "")
    if jobId == "" then return false, "jobId_empty" end

    local opts = Instance.new("TeleportOptions")
    if type(teleportData) == "table" then
        pcall(function() opts:SetTeleportData(teleportData) end)
    end
    pcall(function() opts.ServerInstanceId = jobId end)

    local okAsync, errAsync = pcall(function()
        TeleportService:TeleportAsync(placeId, { getLP() }, opts)
    end)
    if okAsync then
        return true, "teleport_async"
    end

    local ok, err = pcall(function()
        TeleportService:TeleportToPlaceInstance(placeId, jobId, getLP(), "", teleportData)
    end)
    if not ok then
        return false, tostring(errAsync or err)
    end
    return true, "teleport_to_place_instance"
end

local function hopToServer(placeId, jobId, fromJobId)
    placeId = tonumber(placeId) or game.PlaceId
    jobId = tostring(jobId or "")
    fromJobId = tostring(fromJobId or game.JobId or "")

    if jobId == "" then return false, "jobId_empty" end

    local td = {
        __gag2_autohop = true,
        fromJobId = fromJobId,
        targetJobId = jobId,
        nonce = tostring(os.time()) .. "_" .. tostring(math.random(100000, 999999)),
    }

    local PR = rawget(_G, "PSReconnect") or rawget((getgenv and getgenv()) or _G, "PSReconnect")
    if type(PR) == "table" and type(PR.HopToServer) == "function" then
        local ok, res = PR.HopToServer(placeId, jobId, td)
        if ok then return true, res end
        dprint("psreconnect hop failed -> fallback", tostring(res))
    end

    return teleportToJob(placeId, jobId, td)
end

----------------------------------------------------------------
-- TeleportData confirm (visited only when really moved)
----------------------------------------------------------------
local _teleDataApplied = false
local function applyTeleportDataOnce()
    if _teleDataApplied then return end
    _teleDataApplied = true

    local data = nil
    pcall(function()
        data = TeleportService:GetLocalPlayerTeleportData()
    end)

    dprint("TPDATA type", typeof(data))
    if type(data) == "table" then
        dprint("TPDATA keys",
            tostring(data.__gag2_autohop),
            tostring(data.fromJobId),
            tostring(data.targetJobId),
            "here="..tostring(game.JobId)
        )
    end

    if type(data) ~= "table" then return end
    if data.__gag2_autohop ~= true then return end

    local targetJob = tostring(data.targetJobId or "")
    local fromJob   = tostring(data.fromJobId or "")
    local hereJob   = tostring(game.JobId or "")

    if targetJob ~= "" and hereJob == targetJob and hereJob ~= fromJob then
        pushVisitedConfirmed(hereJob)
        dprint("teleport confirmed from", fromJob, "to", hereJob)
    else
        dprint("teleportData ignored target", targetJob, "here", hereJob, "from", fromJob)
    end
end

----------------------------------------------------------------
-- Hop Scheduler (no spam)
----------------------------------------------------------------
local _running = false
local _thread  = nil

local _lastHopSuccessAt = 0
local _lastHopTryAt     = 0
local _cooldownHopSec   = 12
local SESSION_FAIL_COOLDOWN = 18

local _lockUntil = 0

local _session = nil
local WATCHDOG_SEC = 12
local _hopThresholdMetAt = 0

local function resetHopDelayTimer()
    _hopThresholdMetAt = 0
end

local function sessionReset()
    _session = nil
end

local function sessionActive()
    return type(_session) == "table" and _session.active == true
end

local function shouldHop(cfg)
    if not cfg or cfg.enabled ~= true then
        return false, "disabled"
    end

    if rawget(_G, "__GAG2_AUTO_HOP_NOW") == true then
        return true, "manual_flag"
    end

    local currentCount = getLocalPlayerCount()
    local currentMax = clampCurrentPlayers(cfg.currentPlayers)
    local targetMax = clampNum(cfg.targetPlayers, 1, 100, 1)
    local delaySec = clampTeleportDelay(cfg.teleportDelay)
    local mode = getHopMode(currentMax, targetMax)

    if mode == "leave_crowded" then
        if currentCount < currentMax then
            _hopThresholdMetAt = 0
            _lastStatus = ("Waiting crowded " .. currentCount .. "/" .. currentMax)
            return false, _lastStatus
        end
    elseif mode == "leave_quiet" then
        if currentCount > currentMax then
            _hopThresholdMetAt = 0
            _lastStatus = ("Waiting quieter " .. currentCount .. "/" .. currentMax)
            return false, _lastStatus
        end
    else
        if currentCount < currentMax then
            _hopThresholdMetAt = 0
            _lastStatus = ("Waiting players " .. currentCount .. "/" .. currentMax)
            return false, _lastStatus
        end
    end

    if delaySec <= 0 then
        local why
        if mode == "leave_crowded" then
            why = ("crowd_reached (" .. currentCount .. ">=" .. currentMax .. " -> " .. targetMax .. ")")
        elseif mode == "leave_quiet" then
            why = ("too_quiet (" .. currentCount .. "<=" .. currentMax .. " -> " .. targetMax .. ")")
        else
            why = ("player_threshold (" .. currentCount .. ">=" .. currentMax .. ")")
        end
        return true, why
    end

    if _hopThresholdMetAt <= 0 then
        _hopThresholdMetAt = now()
        _lastStatus = ("Delay " .. math.ceil(delaySec) .. "s before hop")
        return false, "delay_armed"
    end

    local elapsed = now() - _hopThresholdMetAt
    if elapsed < delaySec then
        local left = math.ceil(delaySec - elapsed)
        _lastStatus = ("Delay " .. left .. "s before hop")
        return false, ("delay_wait (" .. left .. "s)")
    end

    if mode == "leave_crowded" then
        return true, ("crowd_delayed (" .. currentCount .. ">=" .. currentMax .. " -> " .. targetMax .. ")")
    elseif mode == "leave_quiet" then
        return true, ("quiet_delayed (" .. currentCount .. "<=" .. currentMax .. " -> " .. targetMax .. ")")
    end
    return true, ("player_threshold_delayed (" .. currentCount .. ">=" .. currentMax .. ")")
end

local function sessionStart(reason)
    local cfg = getCfg()
    if cfg.enabled ~= true then
        _lastStatus = "disabled"
        return false, "disabled"
    end
    local lp = getLP()
    if not lp then
        _lastStatus = "no_localplayer"
        return false, "no_localplayer"
    end
    if sessionActive() then
        return false, "session_already_active"
    end

    local t = now()
    if (t - (_lastHopTryAt or 0)) < _cooldownHopSec then
        _lastStatus = "Hop cooldown"
        return false, "hop_cooldown"
    end

    local placeId   = game.PlaceId
    local fromJobId = tostring(game.JobId)

    local visitedSet = buildSetFromArray(cfg.AH.visited)
    do
        local vfile = cacheGetVisited(placeId, cfg.currentPlayers, cfg.targetPlayers, cfg.diffServers)
        for _, jid in ipairs(vfile) do
            visitedSet[tostring(jid)] = true
        end
    end
    visitedSet[fromJobId] = true

    local function tryBuild()
        return buildCandidates(placeId, cfg.currentPlayers, cfg.targetPlayers, cfg.diffServers, visitedSet, fromJobId)
    end

    local candidates, err = tryBuild()
    if (type(candidates) ~= "table" or #candidates == 0) and #ensureArray(cfg.AH.visited) > 0 then
        cfg.AH.visited = {}
        cacheSetVisited(placeId, cfg.currentPlayers, cfg.targetPlayers, cfg.diffServers, cfg.AH.visited)
        cacheSave(placeId, cfg.currentPlayers, cfg.targetPlayers, cfg.diffServers, { ts = 0, scanCursor = {} })
        _persistState()
        visitedSet = { [fromJobId] = true }
        candidates, err = tryBuild()
    end

    if type(candidates) ~= "table" or #candidates == 0 then
        local detail = ("pages=%d srv=%d limit=%d"):format(
            _lastScanPages or 0, _lastScanServers or 0, API_PAGE_LIMIT
        )
        _lastSessionErr = (err or "no_candidates") .. " (" .. detail .. ")"
        _lastStatus = tostring(_lastSessionErr)
        if tostring(err or ""):find("429") then
            apiBackoff(35, "no_candidates_429")
        end
        return false, err or "no_candidates"
    end

    _lastHopTryAt = t
    pushVisitedPreHop(fromJobId)
    _hopThresholdMetAt = 0

    _session = {
        active = true,
        reason = tostring(reason or ""),
        placeId = placeId,
        fromJobId = fromJobId,
        targetPlayers = cfg.targetPlayers,
        diffServers = cfg.diffServers,
        candidates = ensureArray(candidates),
        idx = 1,
        attemptedSet = {},
        inFlight = false,
        currentJobId = "",
        startedAt = now(),
        nextActionAt = now(),
    }

    dprint("sessionStart", "reason=", _session.reason, "candidates=", #_session.candidates)
    _lastSessionErr = nil
    _lastStatus = "teleporting"
    return true, "session_started"
end

local function sessionFinish(ok, why)
    if rawget(_G, "__GAG2_AUTO_HOP_NOW") == true then
        _G.__GAG2_AUTO_HOP_NOW = false
    end

    if ok then
        _lastHopSuccessAt = now()
        _hopThresholdMetAt = 0
    else
        _lockUntil = math.max(_lockUntil, now() + SESSION_FAIL_COOLDOWN)
    end

    dprint("sessionFinish", ok, tostring(why or ""))
    _lastSessionErr = tostring(why or "")
    _lastStatus = ok and "idle" or tostring(why or "failed")
    sessionReset()
end

local function pickNextCandidate()
    if not sessionActive() then return nil end
    local s = _session

    for i = s.idx, #s.candidates do
        local rec = s.candidates[i] or {}
        local jobId = tostring(rec.id or "")
        s.idx = i + 1

        if jobId ~= ""
            and jobId ~= s.fromJobId
            and not s.attemptedSet[jobId]
            and not isDead(jobId)
            and not isAvoided(jobId)
            and not isRecent(jobId)
        then
            s.attemptedSet[jobId] = true
            return rec, jobId
        end
    end

    return nil
end

local function startWatchdog(attemptJobId, fromJobId)
    task.delay(WATCHDOG_SEC, function()
        if not sessionActive() then return end
        local s = _session
        if s.inFlight ~= true then return end
        if s.currentJobId ~= tostring(attemptJobId) then return end

        if tostring(game.JobId) == tostring(fromJobId) then
            dprint("WATCHDOG timeout -> treat as stuck, try next")
            markAvoid(attemptJobId, AVOID_TTL_SEC)
            markRecent(attemptJobId, RECENT_TRIED_TTL)
            s.inFlight = false
            s.currentJobId = ""
            s.nextActionAt = now() + 1.0
        end
    end)
end

----------------------------------------------------------------
-- TeleportInitFailed hook (core anti spam)
----------------------------------------------------------------
local _tpFailConn = nil
local function ensureTeleportFailHook()
    if _tpFailConn then return end

    _tpFailConn = TeleportService.TeleportInitFailed:Connect(function(player, result, errMsg)
        local lp = getLP()
        if lp and player ~= lp then return end
        if not sessionActive() then return end

        local s = _session
        if s.inFlight ~= true then return end

        local msg = tostring(errMsg or "")
        local lm  = low(msg)
        local r   = tostring(result)

        dprint("TeleportInitFailed", r, msg)

        local jobId = tostring(s.currentJobId or "")
        if jobId ~= "" then
            if lm:find("gameended")
                or lm:find("could not find requested game instance")
                or lm:find("requested game instance")
            then
                markDead(jobId, AVOID_TTL_DEAD)
                markAvoid(jobId, AVOID_TTL_DEAD)
                markRecent(jobId, math.max(RECENT_TRIED_TTL, AVOID_TTL_DEAD))
                s.nextActionAt = now() + 0.8

            elseif r:find("IsTeleporting") or lm:find("previous teleport") or lm:find("in processing") then
                _lockUntil = math.max(_lockUntil, now() + 12)
                s.nextActionAt = _lockUntil + 0.2

            else
                markAvoid(jobId, AVOID_TTL_FULL)
                markRecent(jobId, RECENT_TRIED_TTL)
                s.nextActionAt = now() + 0.6
            end
        end

        s.inFlight = false
        s.currentJobId = ""
    end)
end

----------------------------------------------------------------
-- Session Tick (state machine)
----------------------------------------------------------------
local function sessionTick()
    if not sessionActive() then return end
    local s = _session

    if now() < (_lockUntil or 0) then
        return
    end

    if now() < (s.nextActionAt or 0) then
        return
    end

    if s.inFlight == true then
        return
    end

    local rec, jobId = pickNextCandidate()
    if not rec then
        sessionFinish(false, "candidates_exhausted")
        return
    end

    markRecent(jobId, RECENT_TRIED_TTL)

    s.currentJobId = jobId
    s.inFlight = true
    _lastStatus = "teleporting"

    dprint(("Hop -> job=%s playing=%s target=%s from=%s"):format(
        jobId, tostring(rec.playing or "?"), tostring(s.targetPlayers), tostring(s.fromJobId)
    ))

    local ok, res = hopToServer(s.placeId, jobId, s.fromJobId)
    if not ok then
        dprint("teleport call failed (pcall)", tostring(res))
        s.inFlight = false
        s.currentJobId = ""
        markAvoid(jobId, AVOID_TTL_SEC)
        s.nextActionAt = now() + 0.6
        return
    end

    startWatchdog(jobId, s.fromJobId)
end

----------------------------------------------------------------
-- Apply TeleportData once per server join
----------------------------------------------------------------
local function tryApplyTeleportDataAndSyncVisited()
    applyTeleportDataOnce()

    -- also sync visited file -> STATE (so UI consistent)
    local cfg = getCfg()
    local placeId = game.PlaceId

    local vfile = cacheGetVisited(placeId, cfg.currentPlayers, cfg.targetPlayers, cfg.diffServers)
    if #vfile > 0 and type(cfg.AH.visited) == "table" then
        local set = buildSetFromArray(cfg.AH.visited)
        local changed = false
        for _, jid in ipairs(vfile) do
            jid = tostring(jid or "")
            if jid ~= "" and not set[jid] then
                table.insert(cfg.AH.visited, jid)
                set[jid] = true
                changed = true
            end
        end
        if changed then
            _persistState()
        end
    end
end

----------------------------------------------------------------
-- Main loop
----------------------------------------------------------------
local function loop()
    while _running do
        local ok, err = pcall(function()
            tryApplyTeleportDataAndSyncVisited()

            local cfg = getCfg()
            local doHop, why = shouldHop(cfg)

            if doHop and not sessionActive() then
                local okS, rs = sessionStart(why)
                dprint("startHop", okS, rs)
                if not okS then
                    _lastStatus = tostring(rs or "start_failed")
                end
            end

            if not sessionActive() and not doHop then
                -- shouldHop already sets _lastStatus with mode-aware message
            end

            if sessionActive() then
                sessionTick()
            end
        end)

        if not ok then
            dprint("loop error", err)
        end

        task.wait(0.6)
    end
end

----------------------------------------------------------------
-- Public API
----------------------------------------------------------------
function M.IsRunning()
    return _running == true
end

function M.GetStatus()
    local cfg = getCfg()
    local pc = getLocalPlayerCount()
    local delaySec = clampTeleportDelay(cfg.teleportDelay)
    local delayLeft = 0
    if _hopThresholdMetAt > 0 and delaySec > 0 then
        delayLeft = math.max(0, math.ceil(delaySec - (now() - _hopThresholdMetAt)))
    end
    local primarySort, fallbackSort = getSortOrdersForHop(cfg.currentPlayers, cfg.targetPlayers)
    local hopMode = getHopMode(cfg.currentPlayers, cfg.targetPlayers)
    local st = {
        running = (_running == true),
        sessionActive = sessionActive(),
        inFlight = sessionActive() and _session.inFlight == true,
        playerCount = pc,
        currentMax = cfg.currentPlayers,
        targetMax = cfg.targetPlayers,
        hopMode = hopMode,
        sortOrder = primarySort .. ">" .. fallbackSort,
        sortPrimary = primarySort,
        sortFallback = fallbackSort,
        triggerHint = getHopTriggerHint(cfg.currentPlayers, cfg.targetPlayers),
        joinableHint = (cfg.targetPlayers >= GAME_SERVER_MAX)
            and ("< " .. tostring(GAME_SERVER_MAX) .. " player (not full)")
            or nil,
        teleportDelay = delaySec,
        delayRemaining = delayLeft,
        status = _lastStatus or "idle",
        lastError = _lastSessionErr,
        scanPages = _lastScanPages,
        scanServers = _lastScanServers,
        pageLimit = API_PAGE_LIMIT,
        candidateCount = sessionActive() and #ensureArray(_session.candidates) or 0,
    }
    return st
end

function M.SetDebug(on)
    _debug = (on == true)
end

function M.ShouldHop()
    return shouldHop(getCfg())
end

function M.ForceHopNow(reason)
    if sessionActive() then
        return false, "session_active"
    end
    local okS, rs = sessionStart(reason or "manual_force")
    return okS, rs
end

function M.Start()
    if _running then return end
    _running = true
    ensureTeleportFailHook()
    tryApplyTeleportDataAndSyncVisited()
    _thread = task.spawn(loop)
    dprint("Start()")
end

function M.Stop()
    _running = false
    _hopThresholdMetAt = 0
    sessionReset()
    dprint("Stop()")
end

function M.ReleaseTeleportLock()
    _lockUntil = 0
    if sessionActive() then
        _session.inFlight = false
        _session.currentJobId = ""
        _session.nextActionAt = now()
    end
end

function M.SetCurrentPlayer(n)
    local _, AH = _getState()
    AH.current_player = clampCurrentPlayers(n)
    local G = (getgenv and getgenv()) or _G
    G.AUTO_HOP_CURRENT_PLAYER = AH.current_player
    _G.AUTO_HOP_CURRENT_PLAYER = AH.current_player
    resetHopDelayTimer()
    return AH.current_player
end

function M.SetTeleportDelay(sec)
    local _, AH = _getState()
    AH.teleport_delay = clampTeleportDelay(sec)
    local G = (getgenv and getgenv()) or _G
    G.AUTO_HOP_TELEPORT_DELAY = AH.teleport_delay
    _G.AUTO_HOP_TELEPORT_DELAY = AH.teleport_delay
    resetHopDelayTimer()
    return AH.teleport_delay
end

M.setTeleportDelay = M.SetTeleportDelay

function M.SetMaxPlayer(n)
    local _, AH = _getState()
    AH.max_player = clampNum(n, 1, 100, 1)
    local G = (getgenv and getgenv()) or _G
    G.AUTO_HOP_MAX_PLAYER = AH.max_player
    _G.AUTO_HOP_MAX_PLAYER = AH.max_player
    resetHopDelayTimer()
    return AH.max_player
end

function M.SetEnabled(on)
    on = (on == true)
    local _, AH = _getState()
    AH.enabled = on
    local G = (getgenv and getgenv()) or _G
    G.AUTO_HOP_ENABLED = on
    _G.AUTO_HOP_ENABLED = on
    if on then
        M.Start()
    else
        M.Stop()
    end
    return on
end

function M.SyncFromGlobals()
    local G = (getgenv and getgenv()) or _G
    local enabled = (G.AUTO_HOP_ENABLED == true)
    local curP = tonumber(G.AUTO_HOP_CURRENT_PLAYER)
    local maxP = tonumber(G.AUTO_HOP_MAX_PLAYER)
    local delayP = tonumber(G.AUTO_HOP_TELEPORT_DELAY)
    if curP then
        M.SetCurrentPlayer(curP)
    end
    if maxP then
        M.SetMaxPlayer(maxP)
    end
    if delayP ~= nil then
        M.SetTeleportDelay(delayP)
    end
    M.SetEnabled(enabled)
end

M.syncFromGlobals = M.SyncFromGlobals

----------------------------------------------------------------
-- Export
----------------------------------------------------------------
local G = (getgenv and getgenv()) or _G
G.AutoHopServer = M
G.AutoHopServerModule = M
_G.AutoHopServer = M
_G.AutoHopServerModule = M
G.__GAG2_SYNC_AUTO_HOP = function()
    local applyFn = G.applyAutoHopModule or _G.applyAutoHopModule
    if type(applyFn) == "function" then
        pcall(applyFn)
    else
        M.SyncFromGlobals()
    end
end
_G.__GAG2_SYNC_AUTO_HOP = G.__GAG2_SYNC_AUTO_HOP

return M
 end,                   required = false },
    { key = "WeatherPredict",          name = "Weather Predict",         factory = function() -- WeatherPredict.lua — Grow A Garden 2
-- Live cycle + moon/map weather prediction overlay

local Players           = game:GetService("Players")
local ReplicatedStorage = game:GetService("ReplicatedStorage")

local LP = Players.LocalPlayer
local G  = (getgenv and getgenv()) or _G
local M  = {}

local COLOR_BG     = Color3.fromRGB(8, 8, 12)
local COLOR_PANEL  = Color3.fromRGB(14, 14, 20)
local COLOR_YELLOW = Color3.fromRGB(255, 211, 0)
local COLOR_LIVE   = Color3.fromRGB(120, 255, 175)
local COLOR_MUTED  = Color3.fromRGB(175, 178, 190)
local MOON_PALETTE = {
    Color3.fromRGB(255, 140, 220),
    Color3.fromRGB(255, 210, 90),
    Color3.fromRGB(255, 95, 95),
    Color3.fromRGB(180, 200, 255),
    Color3.fromRGB(140, 255, 200),
}

local running      = false
local overlayGui   = nil
local overlayGen   = 0
local initDone     = false

local cycle            = { phases = {}, cycleSec = 600, nightIdx = 3, dayIdx = 1, nightPhase = nil }
local weatherRows      = {}
local cycleWeatherRows = {}
local skipPhaseWeathers = {}
local mapWeatherSeedMult = 1000

local function _enabled()
    local MAIN = G.MAIN or rawget(_G, "MAIN")
    if type(MAIN) == "table" and type(MAIN.misc) == "table"
        and type(MAIN.misc.weather_predict) == "table"
        and MAIN.misc.weather_predict.enabled == true then
        return true
    end
    return G.WEATHER_PREDICT_ENABLED == true or rawget(_G, "WEATHER_PREDICT_ENABLED") == true
end

local function _writeEnabled(on)
    on = (on == true)
    G.WEATHER_PREDICT_ENABLED = on
    _G.WEATHER_PREDICT_ENABLED = on

    local MAIN = G.MAIN or rawget(_G, "MAIN")
    if type(MAIN) == "table" then
        MAIN.misc = MAIN.misc or {}
        MAIN.misc.weather_predict = MAIN.misc.weather_predict or {}
        MAIN.misc.weather_predict.enabled = on
        G.MAIN = MAIN
        _G.MAIN = MAIN
    end

    local STATE = G.STATE or rawget(_G, "STATE")
    if type(STATE) == "table" then
        STATE.weather_predict = STATE.weather_predict or {}
        STATE.weather_predict.enabled = on
    end
    return on
end

local function fmtSec(sec)
    sec = math.max(0, math.floor(tonumber(sec) or 0))
    local h = math.floor(sec / 3600)
    local m = math.floor((sec % 3600) / 60)
    local s = sec % 60
    if h > 0 then return string.format("%dh%02dm", h, m) end
    if m > 0 then return string.format("%dm%02ds", m, s) end
    return string.format("%ds", s)
end

local function fmtClock(unixTs)
    unixTs = math.floor(tonumber(unixTs) or 0)
    if unixTs <= 0 then return "?" end
    return os.date("%H:%M", unixTs)
end

-- Semua timing ikut server game (bukan os.time() lokal — bisa selisih ~10 menit)
local function now()
    return workspace:GetServerTimeNow()
end

local function serverNow()
    return now()
end

local function activePhase()
    return workspace:GetAttribute("ActivePhase")
end

local function activeWeather()
    return workspace:GetAttribute("ActiveWeather")
end

local function loadModule(name)
    local SM = ReplicatedStorage:FindFirstChild("SharedModules")
    if not SM then return nil end
    local ok, mod = pcall(function() return require(SM:WaitForChild(name, 5)) end)
    if not ok then return nil end
    return mod
end

local function weatherOccurrence(entry)
    if type(entry) ~= "table" then return nil end
    local occ = entry.Occurrence or entry.Occurance or entry.Chance or entry.Weight
    if type(occ) == "number" and occ > 0 then return occ end
    return nil
end

local function phaseWeatherChance(w)
    if type(w) == "number" and w > 0 then return w end
    if type(w) == "table" then
        local c = w.Chance or w.Weight or w.Occurrence or w.Occurance
        if type(c) == "number" and c > 0 then return c end
    end
    return nil
end

local function buildSkipPhaseWeathers(built)
    local skip = {}
    if not built or not built.phases then return skip end
    for _, p in ipairs(built.phases) do
        if type(p.name) == "string" then
            skip[p.name] = true
        end
        for wName in pairs(p.weathers or {}) do
            if type(wName) == "string" and wName == p.name then
                skip[wName] = true
            end
        end
    end
    return skip
end

local function isSelectableWeather(name)
    return type(name) == "string" and name ~= "" and not skipPhaseWeathers[name]
end

local function getNightMoonNames()
    local names = {}
    local night = cycle.nightPhase
    if not night then return names end
    for wName in pairs(night.weathers or {}) do
        if isSelectableWeather(wName) then
            names[#names + 1] = wName
        end
    end
    table.sort(names)
    return names
end

local function moonLineColor(moonName)
    local moons = getNightMoonNames()
    for i, name in ipairs(moons) do
        if name == moonName then
            return MOON_PALETTE[(i - 1) % #MOON_PALETTE + 1]
        end
    end
    return COLOR_MUTED
end

local function buildPhases(tcd)
    if not tcd or type(tcd.Data) ~= "table" then return nil end
    local phases = {}
    for phaseName, entry in pairs(tcd.Data) do
        if type(entry) == "table" then
            phases[#phases + 1] = {
                name = phaseName,
                duration = entry.Lasts or 0,
                order = entry.StartOrder or 99,
                weathers = entry.Weathers or {},
            }
        end
    end
    table.sort(phases, function(a, b) return a.order < b.order end)
    local cycleSec, offset = 0, 0
    for _, p in ipairs(phases) do
        p.offset = offset
        cycleSec = cycleSec + p.duration
        offset = offset + p.duration
    end
    local nightIdx, nightPhase, dayIdx = nil, nil, nil
    for i, p in ipairs(phases) do
        if p.name == "Night" then nightIdx, nightPhase = i, p end
        if p.name == "Day" or p.name == "Morning" then dayIdx = i end
    end
    if not dayIdx then dayIdx = 1 end
    return { phases = phases, cycleSec = cycleSec, nightIdx = nightIdx, dayIdx = dayIdx, nightPhase = nightPhase }
end

local function rollPhaseWeather(phase, rng)
    if not phase or not phase.weathers then return nil end
    local entries = {}
    for wName, w in pairs(phase.weathers) do
        local chance = phaseWeatherChance(w)
        if type(wName) == "string" and chance then
            entries[#entries + 1] = { name = wName, chance = chance }
        end
    end
    if #entries == 0 then return nil end
    table.sort(entries, function(a, b) return a.name < b.name end)
    local total = 0
    for _, e in ipairs(entries) do total = total + e.chance end
    if total <= 0 then return nil end
    local roll = rng:NextNumber() * total
    local acc = 0
    for _, e in ipairs(entries) do
        acc = acc + e.chance
        if roll <= acc then return e.name end
    end
    return entries[1].name
end

local function getPhaseByName(name)
    for i, p in ipairs(cycle.phases) do
        if p.name == name then return p, i end
    end
    return nil, nil
end

local function getCycleState()
    local phaseName = activePhase()
    local phaseEnd = workspace:GetAttribute("PhaseDuration")
    if not phaseName or type(phaseEnd) ~= "number" then return nil end

    local remaining = math.max(0, phaseEnd - serverNow())
    local phase, phaseIdx = getPhaseByName(phaseName)
    if not phase then return nil end

    return {
        phaseIndex = phaseIdx,
        phaseName = phaseName,
        phase = phase,
        weather = activeWeather(),
        remaining = remaining,
        elapsed = math.max(0, phase.duration - remaining),
        phaseEnd = phaseEnd,
    }
end

local function cycleIndex()
    local st = getCycleState()
    if not st or not cycle.phases or #cycle.phases == 0 then
        return math.floor(serverNow() / math.max(cycle.cycleSec, 1))
    end

    local elapsed = 0
    for i, p in ipairs(cycle.phases) do
        if i < st.phaseIndex then
            elapsed = elapsed + p.duration
        elseif i == st.phaseIndex then
            elapsed = elapsed + math.max(0, p.duration - st.remaining)
            break
        end
    end

    local cycleStart = serverNow() - elapsed
    return math.floor(cycleStart / math.max(cycle.cycleSec, 1))
end

local function predictPhaseWeather(cycleIdx, phaseIdx)
    local phase = cycle.phases[phaseIdx]
    if not phase then return nil end
    return rollPhaseWeather(phase, Random.new(cycleIdx * 1000 + phaseIdx))
end

local function weatherKey(name)
    if type(name) ~= "string" then return "" end
    return string.lower((name:gsub("[%s_%-]", "")))
end

local function weatherMatches(mapName, rolledName)
    if type(mapName) ~= "string" or type(rolledName) ~= "string" then return false end
    local mk = weatherKey(mapName)
    local rk = weatherKey(rolledName)
    if mk == "" or rk == "" then return false end
    return mk == rk
end

local function rollWeatherDataEvent(rng)
    if not rng or #weatherRows == 0 then return nil end
    local entries = {}
    for _, entry in ipairs(weatherRows) do
        if type(entry.Name) == "string" then
            local occ = entry.Occurrence or entry.Occurance or entry.Chance or entry.Weight
            if type(occ) ~= "number" or occ <= 0 then
                occ = 1
            end
            entries[#entries + 1] = { name = entry.Name, chance = occ }
        end
    end
    if #entries == 0 then return nil end
    table.sort(entries, function(a, b) return a.name < b.name end)
    local total = 0
    for _, e in ipairs(entries) do total = total + e.chance end
    if total <= 0 then return nil end
    local roll = rng:NextNumber() * total
    local acc = 0
    for _, e in ipairs(entries) do
        acc = acc + e.chance
        if roll <= acc then return e.name end
    end
    return entries[1].name
end

local function predictMapWeather(cycleIdx)
    local dayIdx = cycle.dayIdx or 1
    local rng = Random.new(cycleIdx * mapWeatherSeedMult + dayIdx)
    local fromData = rollWeatherDataEvent(rng)
    if fromData then return fromData end
    local dayPhase = cycle.phases[dayIdx]
    if dayPhase then
        return rollPhaseWeather(dayPhase, rng)
    end
    return nil
end

local function calibrateMapSeed()
    local st = getCycleState()
    if not st then return end
    local live = activeWeather()
    if type(live) ~= "string" or live == "" or not isSelectableWeather(live) then return end
    if cycle.nightIdx and st.phaseIndex == cycle.nightIdx then return end

    local ci = cycleIndex()
    local dayIdx = cycle.dayIdx or 1
    local dayPhase = cycle.phases[dayIdx]
    for _, mult in ipairs({ 1000, 10000, 1, 9973, 1337, 7777 }) do
        local rng = Random.new(ci * mult + dayIdx)
        local pred = rollWeatherDataEvent(rng)
        if pred and weatherMatches(pred, live) then
            mapWeatherSeedMult = mult
            return
        end
        if dayPhase then
            local phasePred = rollPhaseWeather(dayPhase, rng)
            if phasePred == live or weatherMatches(phasePred, live) then
                mapWeatherSeedMult = mult
                return
            end
        end
    end
end

local function predictDayWeather(cycleIdx)
    local dayIdx = cycle.dayIdx or 1
    local fromData = predictMapWeather(cycleIdx)
    if fromData and isSelectableWeather(fromData) then return fromData end
    local fromPhase = predictPhaseWeather(cycleIdx, dayIdx)
    if fromPhase and isSelectableWeather(fromPhase) then return fromPhase end
    return fromData or fromPhase
end

local function predictNightWeather(cycleIdx)
    if not cycle.nightIdx then return nil end
    return predictPhaseWeather(cycleIdx, cycle.nightIdx)
end

local function cycleStartTime(cycleIdx)
    local st = getCycleState()
    if not st then return nil end
    local ci = cycleIndex()
    local elapsed = 0
    for i, p in ipairs(cycle.phases) do
        if i < st.phaseIndex then
            elapsed = elapsed + p.duration
        elseif i == st.phaseIndex then
            elapsed = elapsed + math.max(0, p.duration - st.remaining)
            break
        end
    end
    return serverNow() - elapsed + (cycleIdx - ci) * cycle.cycleSec
end

local function phaseStartTime(cycleIdx, phaseIdx)
    local cs = cycleStartTime(cycleIdx)
    if not cs or not cycle.phases[phaseIdx] then return nil end
    return cs + (cycle.phases[phaseIdx].offset or 0)
end

local function secondsUntilPhase(cycleIdx, phaseIdx)
    local startT = phaseStartTime(cycleIdx, phaseIdx)
    if not startT then return 0 end
    return math.max(0, startT - serverNow())
end

local function upcomingPhaseWeathers(maxCount)
    maxCount = maxCount or 10
    local out = {}
    local st = getCycleState()
    if not st or #cycle.phases == 0 then return out end

    local now = serverNow()
    local ci = cycleIndex()
    local pi = st.phaseIndex
    local cyc = ci
    local limit = maxCount + #cycle.phases * 2

    for _ = 1, limit do
        pi = pi + 1
        if pi > #cycle.phases then
            pi = 1
            cyc = cyc + 1
        end
        local wName
        if pi == cycle.dayIdx then
            wName = predictDayWeather(cyc)
        elseif pi == cycle.nightIdx then
            wName = predictPhaseWeather(cyc, pi)
        end
        if wName and isSelectableWeather(wName) then
            local inSec = secondsUntilPhase(cyc, pi)
            out[#out + 1] = {
                name = wName,
                phaseName = cycle.phases[pi].name,
                cycleIdx = cyc,
                phaseIdx = pi,
                inSec = inSec,
                at = now + inSec,
            }
            if #out >= maxCount then break end
        end
    end
    return out
end

local function phaseRemaining()
    local st = getCycleState()
    return st and st.remaining or nil
end

local function dur(name, fallback)
    local p = getPhaseByName(name)
    return p and p.duration or fallback
end

local function secondsUntilNightCycle(offset)
    offset = offset or 0
    local st = getCycleState()
    if not st then return 0 end

    local rem = st.remaining
    local cur = st.phaseName
    local nightIdx = cycle.nightIdx

    if offset == 0 then
        if cur == "Night" then return 0 end
        if cur == "Sunset" then return rem end
        if cur == "Day" then return rem + dur("Sunset", 30) end
        return rem
    end

    local toCycleEnd = rem
    for i = st.phaseIndex + 1, #cycle.phases do
        toCycleEnd = toCycleEnd + cycle.phases[i].duration
    end

    local beforeNight = 0
    if nightIdx and nightIdx > 1 then
        for i = 1, nightIdx - 1 do
            beforeNight = beforeNight + (cycle.phases[i].duration or 0)
        end
    else
        beforeNight = dur("Day", 450) + dur("Sunset", 30)
    end

    return toCycleEnd + (offset - 1) * cycle.cycleSec + beforeNight
end

local function findNextMoon(moonName, maxCycles)
    maxCycles = maxCycles or 60
    local now = serverNow()
    local ci = cycleIndex()
    local cur = activePhase()
    local weather = activeWeather()

    for offset = 0, maxCycles do
        local predicted = predictNightWeather(ci + offset)
        if not weatherMatches(moonName, predicted or "") then
            -- skip cycle
        elseif offset == 0 and cur == "Night" then
            if weatherMatches(moonName, weather or "") then
                return { inSec = 0, cycleIdx = ci, live = true }
            end
        else
            local sec = secondsUntilNightCycle(offset)
            return { inSec = sec, cycleIdx = ci + offset, at = now + sec }
        end
    end
    return nil
end

local function readMapWeather(name)
    local WeatherValues = ReplicatedStorage:FindFirstChild("WeatherValues")
    if not WeatherValues then
        return { playing = false, endsIn = nil, endsAt = nil }
    end
    local playing = WeatherValues:GetAttribute(name .. "_Playing")
    local endTime = WeatherValues:GetAttribute(name .. "_EndTime")
    local startTime = WeatherValues:GetAttribute(name .. "_StartTime")
    local duration = WeatherValues:GetAttribute(name .. "_Duration")
    local now = serverNow()

    local endsIn = nil
    if playing == true then
        if type(startTime) == "number" and startTime > 1e9
            and type(duration) == "number" and duration > 0 then
            endsIn = math.max(0, (startTime + duration) - now)
        elseif type(endTime) == "number" and endTime > 1e9 then
            endsIn = math.max(0, endTime - now)
        elseif type(endTime) == "number" and endTime > 0 and endTime < 1e6 then
            endsIn = math.max(0, endTime)
        end
    end

    return {
        playing = playing == true,
        endsIn = endsIn,
        endsAt = (endsIn ~= nil) and fmtClock(now + endsIn) or nil,
    }
end

local function findNextMapWeather(mapName, maxCycles)
    maxCycles = maxCycles or 120
    local st = getCycleState()
    if not st or not cycle.dayIdx then return nil end

    local now = serverNow()
    local ci = cycleIndex()
    local dayIdx = cycle.dayIdx
    local row = readMapWeather(mapName)
    if row.playing then
        return { inSec = 0, live = true, at = now, name = mapName }
    end

    local live = activeWeather()
    if weatherMatches(mapName, live) then
        return { inSec = 0, live = true, at = now, name = live }
    end

    for offset = 0, maxCycles do
        local cyc = ci + offset
        local rolled = predictDayWeather(cyc)
        if rolled and weatherMatches(mapName, rolled) then
            local inSec = secondsUntilPhase(cyc, dayIdx)
            if offset == 0 and st.phaseIndex > dayIdx then
                -- Day phase sudah lewat di cycle ini, coba cycle berikutnya
            elseif inSec <= 0 and offset == 0 and st.phaseIndex == dayIdx then
                if weatherMatches(mapName, live) then
                    return { inSec = 0, live = true, at = now, name = rolled, cycleIdx = cyc }
                end
            else
                return {
                    inSec = inSec,
                    live = false,
                    at = now + inSec,
                    name = rolled,
                    cycleIdx = cyc,
                    phaseIdx = dayIdx,
                }
            end
        end
    end
    return nil
end

local function loadWeatherEventRows(wd)
    local rows = {}
    if not wd or type(wd.Data) ~= "table" then return rows end

    if wd.Data[1] then
        for _, entry in ipairs(wd.Data) do
            if type(entry) == "table" then rows[#rows + 1] = entry end
        end
    else
        for name, entry in pairs(wd.Data) do
            if type(entry) == "table" then
                if type(entry.Name) ~= "string" then entry.Name = name end
                rows[#rows + 1] = entry
            elseif type(name) == "string" then
                rows[#rows + 1] = { Name = name, Occurrence = entry }
            end
        end
        table.sort(rows, function(a, b) return tostring(a.Name) < tostring(b.Name) end)
    end
    return rows
end

local function loadWeatherRowsFromValues()
    local WeatherValues = ReplicatedStorage:FindFirstChild("WeatherValues")
    if not WeatherValues then return {} end
    local rows, seen = {}, {}
    for attrName in pairs(WeatherValues:GetAttributes()) do
        if type(attrName) == "string" then
            local base = attrName:match("^(.+)_Playing$")
            if base and not seen[base] then
                seen[base] = true
                rows[#rows + 1] = { Name = base, Occurrence = 1 }
            end
        end
    end
    table.sort(rows, function(a, b) return a.Name < b.Name end)
    return rows
end

local function buildCycleWeatherRows()
    local rows, seen = {}, {}
    for _, phase in ipairs(cycle.phases) do
        for wName, w in pairs(phase.weathers or {}) do
            if isSelectableWeather(wName) and not seen[wName] then
                seen[wName] = true
                rows[#rows + 1] = {
                    Name = wName,
                    Occurrence = phaseWeatherChance(w) or 1,
                    Phase = phase.name,
                    Source = "TimeCycleData",
                }
            end
        end
    end
    table.sort(rows, function(a, b) return a.Name < b.Name end)
    return rows
end

local function ensureInit()
    if initDone then return true end

    local built = buildPhases(loadModule("TimeCycleData"))
    if built then cycle = built end
    skipPhaseWeathers = buildSkipPhaseWeathers(cycle)

    weatherRows = loadWeatherEventRows(loadModule("WeatherData"))
    for _, row in ipairs(weatherRows) do
        row.Source = "WeatherData"
    end

    cycleWeatherRows = buildCycleWeatherRows()

    if #weatherRows == 0 then
        weatherRows = loadWeatherRowsFromValues()
        for _, row in ipairs(weatherRows) do
            row.Source = "WeatherValues"
        end
    end

    calibrateMapSeed()
    initDone = true
    return true
end

function M.GetLines()
    ensureInit()
    calibrateMapSeed()
    local lines = {}
    local st = getCycleState()
    local rem = st and st.remaining or phaseRemaining()
    local cur = activePhase()
    local weather = activeWeather()
    local ci = cycleIndex()

    if cur then
        local predicted = st and predictPhaseWeather(ci, st.phaseIndex) or nil
        local sub = fmtSec(rem or 0) .. " left"
        if predicted and predicted ~= weather then
            sub = sub .. " · pred ~" .. tostring(predicted)
        end
        lines[#lines + 1] = {
            text = string.format("%s · %s", cur, weather or predicted or "?"),
            sub = sub,
            live = true,
            kind = "cycle",
        }
    else
        lines[#lines + 1] = {
            text = "Waiting ActivePhase...",
            sub = "join server cycle",
            live = false,
            kind = "info",
        }
    end

    local upcoming = upcomingPhaseWeathers(10)
    if #upcoming > 0 then
        lines[#lines + 1] = { text = "Upcoming Weather", sub = "", live = false, kind = "divider" }
        for _, hit in ipairs(upcoming) do
            local liveNow = hit.inSec <= 0
            lines[#lines + 1] = {
                text = hit.name,
                sub = liveNow and "LIVE NOW"
                    or string.format("%s · %s · %s", hit.phaseName or "?", fmtSec(hit.inSec), fmtClock(hit.at)),
                live = liveNow,
                kind = "weather",
            }
        end
    end

    local nextOff = (cur == "Night") and 1 or 0
    local nightIn = secondsUntilNightCycle(nextOff)
    local nextMoon = predictNightWeather(ci + nextOff)
    lines[#lines + 1] = {
        text = "Next Night",
        sub = string.format("%s → %s", fmtSec(nightIn), nextMoon or "?"),
        live = false,
        kind = "night",
    }

    for _, moon in ipairs(getNightMoonNames()) do
        local hit = findNextMoon(moon, 60)
        if hit then
            if hit.live then
                lines[#lines + 1] = {
                    text = moon,
                    sub = "LIVE NOW",
                    live = true,
                    kind = "moon",
                    moon = moon,
                }
            else
                lines[#lines + 1] = {
                    text = moon,
                    sub = string.format("%s · ~%s", fmtSec(hit.inSec), fmtClock(hit.at)),
                    live = false,
                    kind = "moon",
                    moon = moon,
                }
            end
        end
    end

    lines[#lines + 1] = {
        text = string.format("Cycle %s · idx %d", fmtSec(cycle.cycleSec), ci),
        sub = "Tonight ~" .. tostring(predictNightWeather(ci) or "?"),
        live = false,
        kind = "meta",
    }

    lines[#lines + 1] = { text = "Map Weather", sub = "", live = false, kind = "divider" }

    for _, entry in ipairs(weatherRows) do
        local n = entry.Name
        if type(n) == "string" then
            local row = readMapWeather(n)
            if row.playing then
                lines[#lines + 1] = {
                    text = n,
                    sub = string.format("LIVE %s · %s", row.endsAt or "?", fmtSec(row.endsIn)),
                    live = true,
                    kind = "map",
                }
            else
                local hit = findNextMapWeather(n, 120)
                local sub
                if hit then
                    if hit.live then
                        sub = "LIVE NOW"
                    else
                        sub = string.format("~%s · %s", fmtSec(hit.inSec), fmtClock(hit.at))
                    end
                elseif weatherOccurrence(entry) then
                    sub = "Occ " .. weatherOccurrence(entry)
                else
                    sub = "idle"
                end
                lines[#lines + 1] = {
                    text = n,
                    sub = sub,
                    live = hit and hit.live == true or false,
                    kind = "map",
                }
            end
        end
    end

    return lines
end

function M.GetWeatherNames()
    ensureInit()
    local names, seen = {}, {}

    local function addName(n)
        if isSelectableWeather(n) and not seen[n] then
            seen[n] = true
            names[#names + 1] = n
        end
    end

    for _, entry in ipairs(weatherRows) do
        addName(entry.Name)
    end

    for _, entry in ipairs(cycleWeatherRows) do
        addName(entry.Name)
    end

    for _, entry in ipairs(loadWeatherRowsFromValues()) do
        addName(entry.Name)
    end

    table.sort(names)
    return names
end

function M.GetWeatherRows()
    ensureInit()
    local out, seen = {}, {}
    local function push(entry)
        local n = entry.Name
        if not isSelectableWeather(n) or seen[n] then return end
        seen[n] = true
        out[#out + 1] = entry
    end
    for _, entry in ipairs(weatherRows) do push(entry) end
    for _, entry in ipairs(cycleWeatherRows) do push(entry) end
    for _, entry in ipairs(loadWeatherRowsFromValues()) do
        entry.Source = entry.Source or "WeatherValues"
        push(entry)
    end
    table.sort(out, function(a, b) return tostring(a.Name) < tostring(b.Name) end)
    return out
end

function M.GetWeatherOptions()
    local names = M.GetWeatherNames()
    local items = {}
    for _, name in ipairs(names) do
        items[#items + 1] = { key = name, name = name }
    end
    return items
end

function M.GetPhaseNames()
    ensureInit()
    local names = {}
    for _, phase in ipairs(cycle.phases) do
        if type(phase.name) == "string" and phase.name ~= "" then
            names[#names + 1] = phase.name
        end
    end
    table.sort(names)
    return names
end

function M.PhaseMatches(phaseName, livePhase)
    if type(phaseName) ~= "string" or type(livePhase) ~= "string" then return false end
    return weatherKey(phaseName) == weatherKey(livePhase)
end

M.phaseMatches = M.PhaseMatches

local KICK_PREFIX_PHASE   = "P:"
local KICK_PREFIX_WEATHER = "W:"

function M.GetKickTargetOptions()
    local items = {}

    for _, opt in ipairs(M.GetWeatherOptions()) do
        local wName = opt.key or opt.name
        if type(wName) == "string" and wName ~= "" then
            items[#items + 1] = {
                key = KICK_PREFIX_WEATHER .. wName,
                name = opt.name or wName,
                kind = "weather",
                weather = wName,
            }
        end
    end

    return items
end

function M.WeatherMatches(mapName, rolledName)
    return weatherMatches(mapName, rolledName)
end

M.weatherMatches = M.WeatherMatches

function M.IsWeatherLive(name)
    ensureInit()
    name = tostring(name or "")
    if name == "" then return false, nil end

    local live = activeWeather()
    if weatherMatches(name, live or "") then
        return true, live
    end

    if readMapWeather(name).playing then
        return true, name
    end

    local st = getCycleState()
    if st then
        local ci = cycleIndex()
        if cycle.nightIdx and st.phaseIndex == cycle.nightIdx then
            local predicted = predictNightWeather(ci)
            if weatherMatches(name, predicted or "") then
                return true, predicted
            end
        end
        if cycle.dayIdx and st.phaseIndex == cycle.dayIdx then
            local predicted = predictDayWeather(ci)
            if weatherMatches(name, predicted or "") then
                return true, predicted
            end
        end
    end

    return false, nil
end

function M.GetLiveMapWeathers()
    ensureInit()
    local out = {}
    for _, entry in ipairs(weatherRows) do
        local n = entry.Name
        if type(n) == "string" and readMapWeather(n).playing then
            out[#out + 1] = n
        end
    end
    table.sort(out)
    return out
end

function M.GetSnapshot()
    local st = getCycleState()
    return {
        running = running,
        phase = st and st.phaseName or activePhase(),
        weather = st and st.weather or activeWeather(),
        remaining = st and st.remaining or phaseRemaining(),
        lines = M.GetLines(),
    }
end

local function destroyOverlay()
    overlayGen += 1

    local pg = LP and LP:FindFirstChild("PlayerGui")
    if pg then
        local old = pg:FindFirstChild("GAG2_WX_PRED")
        if old then
            pcall(function() old:Destroy() end)
        end
    end

    if overlayGui then
        pcall(function() overlayGui:Destroy() end)
        overlayGui = nil
    end
end

local function lineColor(line)
    if line.live then return COLOR_LIVE end
    if line.kind == "moon" and line.moon then
        return moonLineColor(line.moon)
    end
    if line.kind == "divider" then return COLOR_YELLOW end
    return COLOR_MUTED
end

local function createOverlay()
    local myGen = overlayGen

    local pg = LP:FindFirstChild("PlayerGui") or LP:WaitForChild("PlayerGui", 5)
    if not pg then return false end

    local gui = Instance.new("ScreenGui")
    gui.Name = "GAG2_WX_PRED"
    gui.ResetOnSpawn = false
    gui.IgnoreGuiInset = true
    gui.Enabled = true
    gui.DisplayOrder = 10050
    gui.Parent = pg
    overlayGui = gui

    local frame = Instance.new("Frame")
    frame.Name = "Panel"
    frame.Size = UDim2.fromOffset(340, 200)
    frame.Position = UDim2.new(0, 14, 0.24, 0)
    frame.BackgroundColor3 = COLOR_BG
    frame.BackgroundTransparency = 0.08
    frame.BorderSizePixel = 0
    frame.Parent = gui
    Instance.new("UICorner", frame).CornerRadius = UDim.new(0, 10)

    local stroke = Instance.new("UIStroke")
    stroke.Color = COLOR_YELLOW
    stroke.Thickness = 1.2
    stroke.Transparency = 0.35
    stroke.Parent = frame

    local accent = Instance.new("Frame")
    accent.Size = UDim2.new(1, 0, 0, 3)
    accent.BackgroundColor3 = COLOR_YELLOW
    accent.BorderSizePixel = 0
    accent.Parent = frame
    Instance.new("UICorner", accent).CornerRadius = UDim.new(0, 10)

    local header = Instance.new("TextLabel")
    header.Size = UDim2.new(1, -16, 0, 22)
    header.Position = UDim2.fromOffset(10, 8)
    header.BackgroundTransparency = 1
    header.Font = Enum.Font.GothamBold
    header.TextSize = 13
    header.TextXAlignment = Enum.TextXAlignment.Left
    header.TextColor3 = COLOR_YELLOW
    header.Text = "WEATHER PREDICT"
    header.Parent = frame

    local badge = Instance.new("TextLabel")
    badge.Size = UDim2.fromOffset(52, 16)
    badge.Position = UDim2.new(1, -60, 0, 10)
    badge.BackgroundColor3 = Color3.fromRGB(25, 55, 35)
    badge.BackgroundTransparency = 0.2
    badge.Font = Enum.Font.GothamBold
    badge.TextSize = 9
    badge.Text = "LIVE"
    badge.TextColor3 = COLOR_LIVE
    badge.Parent = frame
    Instance.new("UICorner", badge).CornerRadius = UDim.new(0, 6)

    local list = Instance.new("ScrollingFrame")
    list.Name = "List"
    list.Size = UDim2.new(1, -12, 1, -38)
    list.Position = UDim2.fromOffset(6, 34)
    list.BackgroundTransparency = 1
    list.BorderSizePixel = 0
    list.ScrollBarThickness = 3
    list.ScrollBarImageColor3 = COLOR_YELLOW
    list.CanvasSize = UDim2.new()
    list.AutomaticCanvasSize = Enum.AutomaticSize.Y
    list.Parent = frame

    local layout = Instance.new("UIListLayout")
    layout.Padding = UDim.new(0, 4)
    layout.SortOrder = Enum.SortOrder.LayoutOrder
    layout.Parent = list

    local rows = {}

    local function render()
        if myGen ~= overlayGen or not overlayGui or overlayGui ~= gui or not gui.Parent then
            return
        end
        local lines = M.GetLines()
        local yPad = 0

        for i, line in ipairs(lines) do
            local row = rows[i]
            if not row then
                row = Instance.new("Frame")
                row.BackgroundColor3 = COLOR_PANEL
                row.BackgroundTransparency = line.kind == "divider" and 1 or 0.35
                row.BorderSizePixel = 0
                row.Size = UDim2.new(1, -4, 0, line.kind == "divider" and 18 or 34)
                row.Parent = list
                Instance.new("UICorner", row).CornerRadius = UDim.new(0, 6)

                local title = Instance.new("TextLabel")
                title.Name = "Title"
                title.BackgroundTransparency = 1
                title.Position = UDim2.fromOffset(8, 4)
                title.Size = UDim2.new(1, -12, 0, 14)
                title.Font = Enum.Font.GothamMedium
                title.TextSize = 11
                title.TextXAlignment = Enum.TextXAlignment.Left
                title.Parent = row

                local sub = Instance.new("TextLabel")
                sub.Name = "Sub"
                sub.BackgroundTransparency = 1
                sub.Position = UDim2.fromOffset(8, 18)
                sub.Size = UDim2.new(1, -12, 0, 12)
                sub.Font = Enum.Font.Gotham
                sub.TextSize = 10
                sub.TextXAlignment = Enum.TextXAlignment.Left
                sub.TextColor3 = COLOR_MUTED
                sub.Parent = row

                rows[i] = { frame = row, title = title, sub = sub }
            end

            local r = rows[i]
            if not r or not r.title or not r.title.Parent then
                -- overlay destroyed mid-render
            else
            r.frame.Visible = true
            r.frame.LayoutOrder = i
            r.frame.Size = UDim2.new(1, -4, 0, line.kind == "divider" and 18 or 34)

            local col = lineColor(line)
            r.title.Text = line.text or ""
            r.title.TextColor3 = col
            r.sub.Text = line.sub or ""
            r.sub.Visible = (line.sub or "") ~= ""
            if line.kind == "divider" then
                r.title.Text = "— " .. (line.text or "") .. " —"
                r.sub.Visible = false
            end
            yPad += r.frame.AbsoluteSize.Y + 4
            end
        end

        for i = #lines + 1, #rows do
            if rows[i] then rows[i].frame.Visible = false end
        end
    end

    render()

    task.spawn(function()
        while myGen == overlayGen and overlayGui == gui and gui.Parent do
            task.wait(1)
            if myGen ~= overlayGen or overlayGui ~= gui or not gui.Parent then
                break
            end
            render()
        end
    end)

    return true
end

function M.Start()
    ensureInit()
    running = true
    _G.GAG2_WEATHER_STOP = false
    destroyOverlay()

    local ok = createOverlay()
    if not ok or not overlayGui or not overlayGui.Parent then
        running = false
        return false
    end

    G.GAG2_WEATHER = {
        cycle = cycle,
        state = getCycleState,
        predictPhase = predictPhaseWeather,
        predictMap = predictMapWeather,
        predictDay = predictDayWeather,
        predictNight = predictNightWeather,
        upcoming = upcomingPhaseWeathers,
        nextMap = findNextMapWeather,
        nextMoon = findNextMoon,
        nextNightIn = function(offset) return secondsUntilNightCycle(offset or 0) end,
        readMap = readMapWeather,
        GetLines = M.GetLines,
        GetWeatherNames = M.GetWeatherNames,
        GetWeatherOptions = M.GetWeatherOptions,
        GetPhaseNames = M.GetPhaseNames,
        GetKickTargetOptions = M.GetKickTargetOptions,
        GetWeatherRows = M.GetWeatherRows,
        WeatherMatches = M.WeatherMatches,
        IsWeatherLive = M.IsWeatherLive,
        GetLiveMapWeathers = M.GetLiveMapWeathers,
        PhaseMatches = M.PhaseMatches,
    }
    _G.GAG2_WEATHER = G.GAG2_WEATHER
    return true
end

M.start = M.Start

function M.Stop()
    running = false
    _G.GAG2_WEATHER_STOP = true
    destroyOverlay()
end

M.stop = M.Stop

function M.IsRunning()
    return running == true
end

function M.SetEnabled(on)
    on = (on == true)
    _writeEnabled(on)
    if on then
        return M.Start()
    end
    M.Stop()
    return on
end

function M.EnsureRunning()
    if _enabled() then
        M.Start()
    else
        M.Stop()
    end
end

M.ensureRunning = M.EnsureRunning

function M.SyncFromGlobals()
    M.EnsureRunning()
end

M.syncFromGlobals = M.SyncFromGlobals

G.__GAG2_SYNC_WEATHER_PREDICT = function()
    M.SyncFromGlobals()
end
_G.__GAG2_SYNC_WEATHER_PREDICT = G.__GAG2_SYNC_WEATHER_PREDICT

return M
 end,                required = false },
    { key = "ReduceFPS",               name = "Reduce FPS",              factory = function() -- ReduceFPS.lua — Grow A Garden 2
-- Event-driven: hide garden lain + plant/buah sendiri. Tanpa sweep berat tiap detik.

local Players           = game:GetService("Players")
local CollectionService = game:GetService("CollectionService")
local Lighting          = game:GetService("Lighting")

local LP = Players.LocalPlayer
local G  = (getgenv and getgenv()) or _G
local M  = {}

local HARVEST_TAG      = "HarvestPrompt"
local MARK_ATTR        = "_GAG2FPS"
local PARKED_ATTR      = "_GAG2FPS_PARK"
local PLOT_CACHE_SEC   = 5.0
local BATCH_YIELD_EVERY = 250
local VOID_POS         = Vector3.new(0, -8000, 0)
local BOOT_WAIT_MAX    = 45
local BOOT_POLL        = 0.25
local POST_READY_DELAY = 1.5

local running      = false
local bootWaitId   = 0
local conns        = {}
local plotConns    = {}
local cachedPlot   = nil
local cachedPlotAt = 0
local renderApplied = false
local sprinklerRelatedCache = setmetatable({}, { __mode = "k" })
local pendingHideDesc = {}
local pendingHideFlushScheduled = false
local statsCache = {
    plot = nil,
    otherPlots = 0,
    harvestPrompts = 0,
}

local function _cfg()
    local MAIN = rawget(_G, "MAIN") or G.MAIN
    local perf = MAIN and MAIN.misc and MAIN.misc.perf
    perf = type(perf) == "table" and perf or {}

    local enabled = (G.REDUCE_FPS_ENABLED == true)
        or (rawget(_G, "REDUCE_FPS_ENABLED") == true)
        or (perf.enabled == true)

    local hideOthers = perf.hide_others
    if hideOthers == nil then hideOthers = G.REDUCE_FPS_HIDE_OTHERS end
    if hideOthers == nil then hideOthers = rawget(_G, "REDUCE_FPS_HIDE_OTHERS") end
    if hideOthers == nil then
        hideOthers = perf.delete_others
        if hideOthers == nil then hideOthers = G.REDUCE_FPS_DELETE_OTHERS end
        if hideOthers == nil then hideOthers = rawget(_G, "REDUCE_FPS_DELETE_OTHERS") end
    end
    if hideOthers == nil then hideOthers = true end

    local hideOwn = perf.hide_own
    if hideOwn == nil then hideOwn = G.REDUCE_FPS_HIDE_OWN end
    if hideOwn == nil then hideOwn = rawget(_G, "REDUCE_FPS_HIDE_OWN") end
    if hideOwn == nil then hideOwn = true end

    local render = perf.render
    if render == nil then render = G.REDUCE_FPS_RENDER end
    if render == nil then render = rawget(_G, "REDUCE_FPS_RENDER") end
    if render == nil then render = true end

    return {
        enabled = enabled,
        hideOthers = hideOthers ~= false,
        hideOwn = hideOwn ~= false,
        render = render ~= false,
    }
end

local function _plotOwnedByLocal(plot)
    if not plot then return false end
    local uid, name = LP.UserId, LP.Name
    local function match(v)
        if v == nil then return false end
        return v == uid or v == name or tostring(v) == tostring(uid) or v == name
    end
    if match(plot:GetAttribute("OwnerId")) then return true end
    if match(plot:GetAttribute("Owner")) then return true end
    if match(plot:GetAttribute("OwnerUserId")) then return true end
    if match(plot:GetAttribute("UserId")) then return true end
    return false
end

local function getPlayerPlot()
    local now = os.clock()
    if cachedPlot and cachedPlot.Parent and (now - cachedPlotAt) <= PLOT_CACHE_SEC then
        return cachedPlot
    end

    local gardens = workspace:FindFirstChild("Gardens")
    if not gardens then
        cachedPlot = nil
        cachedPlotAt = now
        return nil
    end

    local plotId = LP:GetAttribute("PlotId")
    if plotId ~= nil then
        local byId = gardens:FindFirstChild("Plot" .. tostring(plotId))
        if byId then
            cachedPlot = byId
            cachedPlotAt = now
            statsCache.plot = byId.Name
            return byId
        end
    end

    for _, plot in ipairs(gardens:GetChildren()) do
        if _plotOwnedByLocal(plot) then
            cachedPlot = plot
            cachedPlotAt = now
            statsCache.plot = plot.Name
            return plot
        end
    end

    local byName = gardens:FindFirstChild("Plot" .. LP.Name)
    cachedPlot = byName
    cachedPlotAt = now
    statsCache.plot = byName and byName.Name or nil
    return byName
end

local function _loadingScreenActive()
    if not LP then return false end
    return LP:GetAttribute("LoadingScreenActive") == true
end

local function _hrp()
    local char = LP and LP.Character
    return char and char:FindFirstChild("HumanoidRootPart")
end

local function _plotRuntimeReady()
    if not LP or not LP.Character then return false end
    if not _hrp() then return false end

    local gardens = workspace:FindFirstChild("Gardens")
    if not gardens then return false end

    if LP:GetAttribute("PlotId") == nil then return false end

    local plot = getPlayerPlot()
    return plot ~= nil and plot.Parent ~= nil
end

local function _isGameReady()
    if _loadingScreenActive() then return false end
    return _plotRuntimeReady()
end

local function _waitForBootReady()
    bootWaitId += 1
    local myId = bootWaitId
    local deadline = os.clock() + BOOT_WAIT_MAX
    local settled = false

    while running and bootWaitId == myId do
        if not workspace:FindFirstChild("Gardens") then
            pcall(function()
                workspace:WaitForChild("Gardens", 5)
            end)
        end

        if not _loadingScreenActive() and _plotRuntimeReady() then
            if not settled then
                cachedPlot = nil
                cachedPlotAt = 0
                task.wait(POST_READY_DELAY)
                settled = true
            end
            if _plotRuntimeReady() then
                return true
            end
        end

        if os.clock() >= deadline then
            return _plotRuntimeReady()
        end

        task.wait(BOOT_POLL)
    end

    return false
end

local function _countOtherPlots()
    local gardens = workspace:FindFirstChild("Gardens")
    if not gardens then
        statsCache.otherPlots = 0
        return 0
    end
    local mine = getPlayerPlot()
    local n = 0
    for _, p in ipairs(gardens:GetChildren()) do
        if p ~= mine and not _plotOwnedByLocal(p) then
            n += 1
        end
    end
    statsCache.otherPlots = n
    return n
end

local function _isHarvestPrompt(inst)
    return inst:IsA("ProximityPrompt") and CollectionService:HasTag(inst, HARVEST_TAG)
end

local function _isEssentialPart(inst)
    if not inst or not inst:IsA("BasePart") then return false end
    local n = inst.Name:lower()
    if n == "spawn" or n == "spawnlocation" or n == "spawnpoint" or n == "can_plant" then
        return true
    end
    if CollectionService:HasTag(inst, "PlantArea") then return true end
    return false
end

local function _isSprinklerRelated(inst)
    if not inst then return false end
    local cached = sprinklerRelatedCache[inst]
    if cached ~= nil then return cached end

    if inst:IsA("Model") then
        if inst:GetAttribute("SprinklerId") ~= nil then
            sprinklerRelatedCache[inst] = true
            return true
        end
        local sn = inst:GetAttribute("SprinklerName")
        if type(sn) == "string" and sn ~= "" then
            sprinklerRelatedCache[inst] = true
            return true
        end
    end

    local current = inst.Parent
    while current and current ~= game do
        if current.Name == "Sprinklers" then
            sprinklerRelatedCache[inst] = true
            return true
        end
        if current:IsA("Model") then
            if current:GetAttribute("SprinklerId") ~= nil then
                sprinklerRelatedCache[inst] = true
                return true
            end
            local sn = current:GetAttribute("SprinklerName")
            if type(sn) == "string" and sn ~= "" then
                sprinklerRelatedCache[inst] = true
                return true
            end
        end
        current = current.Parent
    end

    sprinklerRelatedCache[inst] = false
    return false
end

local function _restoreSprinklerVisual(inst)
    if not inst or not inst.Parent or not _isSprinklerRelated(inst) then return end
    pcall(function() inst:SetAttribute(MARK_ATTR, nil) end)

    if inst:IsA("BasePart") then
        pcall(function()
            inst.LocalTransparencyModifier = 0
            if inst.Transparency >= 1 then inst.Transparency = 0 end
            inst.CastShadow = true
            inst.CanCollide = true
            inst.CanTouch = true
            inst.CanQuery = true
        end)
        return
    end

    if inst:IsA("Decal") or inst:IsA("Texture") then
        pcall(function()
            if inst.Transparency >= 1 then inst.Transparency = 0 end
        end)
        return
    end

    if inst:IsA("ParticleEmitter") or inst:IsA("Trail") or inst:IsA("Beam") or inst:IsA("Light") then
        pcall(function() inst.Enabled = true end)
        return
    end

    if inst:IsA("Highlight") then
        pcall(function() inst.Enabled = true end)
        return
    end

    if inst:IsA("BillboardGui") or inst:IsA("SurfaceGui") then
        pcall(function() inst.Enabled = true end)
    end
end

local function _unhidePlotSprinklers(plot)
    local folder = plot and plot:FindFirstChild("Sprinklers")
    if not folder then return end
    local list = folder:GetDescendants()
    local batch = 0
    for i = 1, #list do
        if not running then return end
        _restoreSprinklerVisual(list[i])
        batch += 1
        if batch >= BATCH_YIELD_EVERY then
            batch = 0
            task.wait()
        end
    end
    for _, child in ipairs(folder:GetChildren()) do
        if not running then return end
        _restoreSprinklerVisual(child)
    end
end

local function _mustKeepOwn(inst)
    if not inst then return true end
    if inst:IsA("BillboardGui") then
        if inst.Name == "_GAG2FG_ESP" or inst.Name == "_GAG2FBP_ESP" then return true end
        if inst:GetAttribute("_GAG2_ESP") == true then return true end
    end
    if _isHarvestPrompt(inst) then return true end
    if inst:IsA("ProximityPrompt") then return true end
    if _isEssentialPart(inst) then return true end
    if _isSprinklerRelated(inst) then return true end
    return false
end

local function _alreadyMarked(inst)
    if not inst then return true end
    local ok, v = pcall(function()
        return inst:GetAttribute(MARK_ATTR)
    end)
    return ok and v == true
end

local function _hideVisual(inst, keepFn)
    if not inst or not inst.Parent then return false end
    if keepFn and keepFn(inst) then return false end
    if _alreadyMarked(inst) then return false end

    pcall(function() inst:SetAttribute(MARK_ATTR, true) end)

    if inst:IsA("BasePart") then
        pcall(function()
            inst.Transparency = 1
            inst.LocalTransparencyModifier = 1
            inst.CastShadow = false
            inst.CanCollide = false
            inst.CanTouch = false
            inst.CanQuery = false
            inst.Material = Enum.Material.SmoothPlastic
        end)
        return true
    end

    if inst:IsA("Decal") or inst:IsA("Texture") then
        pcall(function() inst.Transparency = 1 end)
        return true
    end

    if inst:IsA("ParticleEmitter") or inst:IsA("Trail") or inst:IsA("Beam") or inst:IsA("Light") then
        pcall(function() inst.Enabled = false end)
        return true
    end

    if inst:IsA("Highlight") then
        pcall(function()
            inst.Enabled = false
            inst.FillTransparency = 1
            inst.OutlineTransparency = 1
        end)
        return true
    end

    if inst:IsA("BillboardGui") or inst:IsA("SurfaceGui") then
        pcall(function() inst.Enabled = false end)
        return true
    end

    return false
end

local function _walkDescendants(root, keepFn, onDone)
    if not root or not root.Parent then
        if onDone then onDone(0) end
        return
    end

    task.spawn(function()
        local changed = 0
        local batch = 0
        local list = root:GetDescendants()
        for i = 1, #list do
            if not running then break end
            if _hideVisual(list[i], keepFn) then
                changed += 1
            end
            batch += 1
            if batch >= BATCH_YIELD_EVERY then
                batch = 0
                task.wait()
            end
        end
        if running then
            _hideVisual(root, keepFn)
        end
        if onDone then onDone(changed) end
    end)
end

local function _plotParked(plot)
    if not plot then return true end
    local ok, v = pcall(function()
        return plot:GetAttribute(PARKED_ATTR)
    end)
    return ok and v == true
end

local function _parkOtherPlot(plot)
    if not plot or _plotParked(plot) then return end
    pcall(function() plot:SetAttribute(PARKED_ATTR, true) end)

    _walkDescendants(plot, nil, function()
        pcall(function()
            if plot:IsA("Model") then
                plot:PivotTo(CFrame.new(VOID_POS))
            elseif plot:IsA("BasePart") then
                plot.CFrame = CFrame.new(VOID_POS)
            end
        end)
    end)
end

local function _hideOtherGardens()
    local gardens = workspace:FindFirstChild("Gardens")
    if not gardens then return 0 end

    local myPlot = getPlayerPlot()
    local n = 0
    for _, plot in ipairs(gardens:GetChildren()) do
        if plot ~= myPlot and not _plotOwnedByLocal(plot) then
            _parkOtherPlot(plot)
            n += 1
        end
    end
    statsCache.otherPlots = n
    return n
end

local function _hideOwnGarden(plot)
    if not plot or not plot.Parent then return end
    task.spawn(function()
        _unhidePlotSprinklers(plot)
        if running then
            _walkDescendants(plot, _mustKeepOwn)
        end
    end)
end

local function _applyRenderingOnce()
    if renderApplied then return end
    renderApplied = true

    pcall(function()
        Lighting.GlobalShadows = false
        Lighting.FogEnd = 9e9
        local atm = Lighting:FindFirstChildOfClass("Atmosphere")
        if atm then atm.Density = 0 end
    end)

    pcall(function()
        local r = settings().Rendering
        r.QualityLevel = Enum.QualityLevel.Level01
        r.MeshPartDetailLevel = Enum.MeshPartDetailLevel.Level01
    end)

    pcall(function()
        local gs = UserSettings():GetService("UserGameSettings")
        gs.SavedQualityLevel = Enum.SavedQualitySetting.QualityLevel1
    end)
end

local function _refreshHarvestCount(plot)
    if not plot then
        statsCache.harvestPrompts = 0
        return
    end
    local n = 0
    for _, d in ipairs(CollectionService:GetTagged(HARVEST_TAG)) do
        if d:IsDescendantOf(plot) and not d:GetAttribute("Collected") then
            n += 1
        end
    end
    statsCache.harvestPrompts = n
end

local function _applyGardenHides()
    if not running then return end
    local cfg = _cfg()
    if cfg.hideOthers then _hideOtherGardens() end
    if cfg.hideOwn then
        local plot = getPlayerPlot()
        if plot then
            _hideOwnGarden(plot)
            task.defer(function()
                if running then _refreshHarvestCount(plot) end
            end)
        end
    end
end

local function _flushPendingHideDescendants()
    pendingHideFlushScheduled = false
    if not running or not _cfg().hideOwn then
        table.clear(pendingHideDesc)
        return
    end

    local pending = {}
    for inst in pairs(pendingHideDesc) do
        pending[#pending + 1] = inst
    end
    table.clear(pendingHideDesc)

    local batch = 0
    for i = 1, #pending do
        local inst = pending[i]
        if inst.Parent then
            if _isSprinklerRelated(inst) then
                _restoreSprinklerVisual(inst)
            else
                _hideVisual(inst, _mustKeepOwn)
                if _isHarvestPrompt(inst) and not inst:GetAttribute("Collected") then
                    statsCache.harvestPrompts = (statsCache.harvestPrompts or 0) + 1
                end
            end
        end
        batch += 1
        if batch >= BATCH_YIELD_EVERY then
            batch = 0
            task.wait()
            if not running then return end
        end
    end

    if next(pendingHideDesc) then
        pendingHideFlushScheduled = true
        task.defer(_flushPendingHideDescendants)
    end
end

local function _queueHideDescendant(desc)
    if not desc or not _isGameReady() then return end
    pendingHideDesc[desc] = true
    if not pendingHideFlushScheduled then
        pendingHideFlushScheduled = true
        task.defer(_flushPendingHideDescendants)
    end
end

function M.RunOnce()
    local cfg = _cfg()
    local stats = { hiddenOthers = 0, hiddenOwn = 0 }

    if cfg.render then _applyRenderingOnce() end
    if not cfg.hideOthers and not cfg.hideOwn then
        return stats
    end

    local function applyHides()
        if cfg.hideOthers then stats.hiddenOthers = _hideOtherGardens() end
        if cfg.hideOwn then
            local plot = getPlayerPlot()
            if plot then
                _hideOwnGarden(plot)
                _refreshHarvestCount(plot)
            end
        end
    end

    if _isGameReady() then
        applyHides()
    else
        task.spawn(function()
            if _waitForBootReady() then
                applyHides()
            end
        end)
    end
    return stats
end

local function _disconnectPlotConns()
    for _, c in ipairs(plotConns) do
        pcall(function() c:Disconnect() end)
    end
    table.clear(plotConns)
end

local function _disconnectAll()
    for _, c in ipairs(conns) do
        pcall(function() c:Disconnect() end)
    end
    table.clear(conns)
    _disconnectPlotConns()
end

local function _bindGardens(gardens)
    if not gardens then return end

    table.insert(conns, gardens.ChildAdded:Connect(function(child)
        task.defer(function()
            if not running or not _cfg().hideOthers then return end
            if not _isGameReady() then return end
            if child ~= getPlayerPlot() and not _plotOwnedByLocal(child) then
                _parkOtherPlot(child)
                _countOtherPlots()
            end
        end)
    end))
end

local function _bindOwnPlot(plot)
    _disconnectPlotConns()
    if not plot then return end

    table.insert(plotConns, plot.DescendantAdded:Connect(function(desc)
        if not running or not _cfg().hideOwn then return end
        _queueHideDescendant(desc)
    end))

    table.insert(plotConns, plot.DescendantRemoving:Connect(function(desc)
        if _isHarvestPrompt(desc) and not desc:GetAttribute("Collected") then
            statsCache.harvestPrompts = math.max(0, (statsCache.harvestPrompts or 0) - 1)
        end
    end))
end

function M.SetEnabled(on)
    on = (on == true)
    G.REDUCE_FPS_ENABLED = on
    _G.REDUCE_FPS_ENABLED = on
    if on then M.Start() else M.Stop() end
end

function M.IsEnabled()
    return running
end

function M.Start()
    if running then
        return true
    end

    running = true

    G.REDUCE_FPS_ENABLED = true
    _G.REDUCE_FPS_ENABLED = true

    _disconnectAll()

    local cfg = _cfg()
    if cfg.render then _applyRenderingOnce() end

    local gardens = workspace:FindFirstChild("Gardens") or workspace:WaitForChild("Gardens", 15)
    if gardens then _bindGardens(gardens) end

    task.spawn(function()
        if not _waitForBootReady() then return end
        if not running then return end
        _applyGardenHides()
        _bindOwnPlot(getPlayerPlot())
    end)

    table.insert(conns, LP:GetAttributeChangedSignal("PlotId"):Connect(function()
        cachedPlot = nil
        cachedPlotAt = 0
        if not running then return end
        task.spawn(function()
            if not _waitForBootReady() then return end
            if not running then return end
            local cfgNow = _cfg()
            local plot = getPlayerPlot()
            if cfgNow.hideOthers then _hideOtherGardens() end
            if cfgNow.hideOwn and plot then
                _hideOwnGarden(plot)
                _refreshHarvestCount(plot)
            end
            _bindOwnPlot(plot)
        end)
    end))

    return true
end

function M.Stop()
    running = false
    bootWaitId += 1
    table.clear(pendingHideDesc)
    pendingHideFlushScheduled = false
    _disconnectAll()
    renderApplied = false
    G.REDUCE_FPS_ENABLED = false
    _G.REDUCE_FPS_ENABLED = false
end

function M.SyncFromGlobals()
    local cfg = _cfg()
    G.REDUCE_FPS_ENABLED = cfg.enabled
    _G.REDUCE_FPS_ENABLED = cfg.enabled
    G.REDUCE_FPS_HIDE_OTHERS = cfg.hideOthers
    _G.REDUCE_FPS_HIDE_OTHERS = cfg.hideOthers
    G.REDUCE_FPS_HIDE_OWN = cfg.hideOwn
    _G.REDUCE_FPS_HIDE_OWN = cfg.hideOwn
    G.REDUCE_FPS_RENDER = cfg.render
    _G.REDUCE_FPS_RENDER = cfg.render

    if cfg.enabled then
        M.Start()
    else
        M.Stop()
    end
    return cfg
end

function M.GetStats()
    local plot = getPlayerPlot()
    return {
        enabled = running,
        plot = plot and plot.Name or statsCache.plot,
        otherPlots = statsCache.otherPlots,
        harvestPrompts = statsCache.harvestPrompts,
        voidPos = VOID_POS,
    }
end

G.ReduceFPS = M
_G.ReduceFPS = M

return M
 end,                      required = false },
    { key = "HideHarvestPrompt",       name = "Hide Harvest Prompt",     factory = function() -- HideHarvestPrompt.lua — sembunyikan UI prompt Harvest (tag HarvestPrompt)

local CollectionService = game:GetService("CollectionService")

local G = (getgenv and getgenv()) or _G
local M = {}

local HARVEST_TAG = "HarvestPrompt"
local tagConn = nil
local enabled = false

local function applyPrompt(prompt, hide)
    if not prompt or not prompt:IsA("ProximityPrompt") then return end
    if not CollectionService:HasTag(prompt, HARVEST_TAG) then return end
    pcall(function()
        prompt.Enabled = not hide
    end)
end

local function scanAll(hide)
    for _, prompt in ipairs(CollectionService:GetTagged(HARVEST_TAG)) do
        applyPrompt(prompt, hide)
    end
end

local function bindTag()
    if tagConn then return end
    tagConn = CollectionService:GetInstanceAddedSignal(HARVEST_TAG):Connect(function(inst)
        if enabled then
            applyPrompt(inst, true)
        end
    end)
