local function unbindTag()
    if tagConn then
        tagConn:Disconnect()
        tagConn = nil
    end
end

function M.SetEnabled(on)
    on = (on == true)
    if enabled == on then return end
    enabled = on
    G.HIDE_HARVEST_PROMPT_ENABLED = on
    _G.HIDE_HARVEST_PROMPT_ENABLED = on
    if on then
        bindTag()
        scanAll(true)
    else
        unbindTag()
        scanAll(false)
    end
end

function M.IsEnabled()
    return enabled
end

G.HideHarvestPrompt = M
_G.HideHarvestPrompt = M

return M
 end,              required = false },
    { key = "EspFruitBackpack",        name = "ESP Fruit Backpack",      factory = function() -- EspFruitBackpack.lua — ESP harga buah di backpack
-- UI: label slot + total coin S (backpack) + total fruit garden F (kiri)
-- Scan: versi baru (backpack buka saja, 1 detik UI, re-fetch harga 0 tiap scan, re-fetch harga >0 tiap 3 detik)

local Players           = game:GetService("Players")
local ReplicatedStorage = game:GetService("ReplicatedStorage")

local LP = Players.LocalPlayer
local G  = (getgenv and getgenv()) or _G
local M  = {}

local TAG_SLOT           = "_GAG2FBP_ESP"
local TAG_TOTAL          = "_GAG2FBP_TOTAL"
