local TAG_GARDEN_VAL     = "_GAG2FBP_GARDEN_TOTAL_VAL"

local COL_SLOT_BG      = Color3.fromRGB(18, 22, 16)
local COL_SLOT_STROKE  = Color3.fromRGB(255, 210, 60)
local COL_SLOT_TEXT    = Color3.fromRGB(255, 244, 190)
local COL_TOTAL_BG     = Color3.fromRGB(20, 24, 30)
local COL_TOTAL_STROKE = Color3.fromRGB(255, 210, 60)
local COL_TOTAL_TEXT   = Color3.fromRGB(255, 236, 120)
local COL_COIN         = Color3.fromRGB(255, 196, 45)
local COL_GARDEN_BG    = Color3.fromRGB(16, 28, 20)
local COL_GARDEN_STROKE = Color3.fromRGB(74, 222, 128)
local COL_GARDEN_TEXT  = Color3.fromRGB(187, 247, 208)
local COL_GARDEN_ICON  = Color3.fromRGB(34, 197, 94)

local SCAN_SEC = 1.0
local REFRESH_CACHED_SEC = 3.0
local FETCH_WAIT_SEC = 2.5
local GARDEN_SCAN_SEC = 1.0
local GARDEN_BADGE_MIN_SEC = 0.25

local running    = false
local scanThread = nil
local gardenThread = nil
local bpOpen     = false
local lastGardenBadgeAt = 0
local gardenHooked = false
local lastCachedRefreshAt = 0
