    if _isSeedName(name) then return true end
    return name:find("sprinkler", 1, true) ~= nil
        or name:find("sprink", 1, true) ~= nil
        or name:find("gear", 1, true) ~= nil
        or name:find("watering", 1, true) ~= nil
        or name:find("fertilizer", 1, true) ~= nil
        or name:find("trap", 1, true) ~= nil
end

local function _isVisible(inst)
    if not inst then return false end
    local cur = inst
    while cur and cur ~= game do
        if cur:IsA("GuiObject") and cur.Visible == false then return false end
        if cur:IsA("ScreenGui") and cur.Enabled == false then return false end
        cur = cur.Parent
    end
    return true
end

local function _pick(t, fields)
