    if inst:GetAttribute("FruitName") or inst:GetAttribute("Fruit") then return true end
    if inst:GetAttribute("FruitProxy") == true then return true end
    local hf = inst:GetAttribute("HarvestedFruit")
    if hf == true or (type(hf) == "string" and hf ~= "") then return true end
    return false
end

local function _toolEntry(tool)
    local fsv = _fsv()
    local name = tostring(tool:GetAttribute("FruitName") or tool:GetAttribute("Fruit") or tool.Name or "")
    if fsv and type(fsv.resolveSeedName) == "function" then
        local ok, n = pcall(fsv.resolveSeedName, tool)
        if ok and type(n) == "string" and n ~= "" then name = n end
    end
    local kg = tonumber(tool:GetAttribute("Weight")) or 0
    if fsv and type(fsv.resolveWeight) == "function" then
        local ok, w = pcall(fsv.resolveWeight, tool)
        if ok and type(w) == "number" and w > 0 then kg = w end
    end
    local multi = tonumber(tool:GetAttribute("SizeMultiplier") or tool:GetAttribute("SizeMulti")) or 0
    if fsv and type(fsv.resolveMulti) == "function" then
        local ok, m = pcall(fsv.resolveMulti, tool)
        if ok and type(m) == "number" and m > 0 then multi = m end
    end
    local bidPrice = 0
    if fsv and type(fsv.resolveBidPrice) == "function" then
        local ok, b = pcall(fsv.resolveBidPrice, tool)
        if ok and type(b) == "number" and b > 0 then bidPrice = b end
    else
        bidPrice = tonumber(tool:GetAttribute("BidPrice")) or 0
    end
    return {
        id = _fruitId(tool), name = name, kg = kg, multi = multi,
        mut = tool:GetAttribute("Mutation"), decay = tool:GetAttribute("DecayAlpha"),
        bidPrice = bidPrice, tool = tool,
    }
end

local function _layoutFruit(raw)
    if type(raw) ~= "table" then return false end
    if raw.SeedTool or raw.Pet or raw.PottedPlant == true then return false end
    if tostring(raw.MainCategory or "") == "Seed" then return false end
    local name = tostring(_pick(raw, NAME_FIELDS) or "")
    if _isNonFruitSlot(name) then return false end
    local id = _pick(raw, ID_FIELDS)
    if type(id) == "string" and #id >= 8 then return true end
    return name ~= ""
end

local function _collectLayout(layout, out, depth, seen)
    if depth > 12 or type(layout) ~= "table" or seen[layout] then return end
    seen[layout] = true
    if _layoutFruit(layout) then out[#out + 1] = layout return end
    for _, v in pairs(layout) do
        if type(v) == "table" then
            if _layoutFruit(v) then out[#out + 1] = v
            else _collectLayout(v, out, depth + 1, seen) end
        end
    end
end

local function _getLayout()
    local ok, net = pcall(function()
        return require(ReplicatedStorage.SharedModules.Networking)
    end)
    if not ok or type(net.Backpack) ~= "table" then return nil end
    local r = net.Backpack.GetLayout
    if not r then return nil end
    local ok2, layout
    if type(r) == "table" and r.Fire then ok2, layout = pcall(function() return r:Fire() end)
    elseif type(r) == "userdata" and r.InvokeServer then ok2, layout = pcall(function() return r:InvokeServer() end)
    elseif type(r) == "function" then ok2, layout = pcall(r) end
    return ok2 and type(layout) == "table" and layout or nil
end

local function _mergeFruitEntry(cur, e)
    if not cur or not e then return end
    if e.name ~= "" and (cur.name or "") == "" then cur.name = e.name end
    if e.multi > 0 and (cur.multi or 0) <= 0 then cur.multi = e.multi end
    if e.kg > 0 and (cur.kg or 0) <= 0 then cur.kg = e.kg end
    if e.mut and not cur.mut then cur.mut = e.mut end
    if e.decay ~= nil and cur.decay == nil then cur.decay = e.decay end
    if e.tool and not cur.tool then cur.tool = e.tool end
    local curBid = tonumber(cur.bidPrice) or 0
    local newBid = tonumber(e.bidPrice) or 0
    if newBid > curBid then cur.bidPrice = newBid end
end

local function _syncEntryBidFromTool(e)
    if not e or not e.tool or type(e.tool.GetAttribute) ~= "function" then return end
    if (tonumber(e.bidPrice) or 0) > 0 then return end
    local fsv = _fsv()
    local bid = 0
    if fsv and type(fsv.resolveBidPrice) == "function" then
        local ok, b = pcall(fsv.resolveBidPrice, e.tool)
        if ok and type(b) == "number" and b > 0 then bid = b end
    else
        bid = tonumber(e.tool:GetAttribute("BidPrice")) or 0
    end
    if bid > 0 then e.bidPrice = bid end
end

local function _linkBackpackTools(byId, list)
    local bp = LP:FindFirstChild("Backpack") or LP:FindFirstChildOfClass("Backpack")
    if not bp then return end
    for _, inst in ipairs(bp:GetChildren()) do
        if _isFruit(inst) then
            local id = _fruitId(inst)
            local entry = (id ~= "" and byId[id]) or nil
            if entry then
                if not entry.tool then entry.tool = inst end
                _syncEntryBidFromTool(entry)
            end
        end
    end
    for _, e in ipairs(list) do
        if e.tool and (e.tool.Parent == bp or (LP.Character and e.tool:IsDescendantOf(LP.Character))) then
            _syncEntryBidFromTool(e)
        end
    end
end

local function _allFruits()
    local byId, list = {}, {}
    local function add(e)
        if e.name == "" and e.id == "" then return end
        local id = tostring(e.id or "")
        if id ~= "" and byId[id] then
            _mergeFruitEntry(byId[id], e)
            return
        end
        list[#list + 1] = e
        if id ~= "" then byId[id] = e end
    end
    local function scanChildren(root)
        if not root then return end
        for _, inst in ipairs(root:GetChildren()) do
            if _isFruit(inst) then add(_toolEntry(inst)) end
        end
    end
    -- Instance fisik dulu (punya BidPrice + tool); layout UI hanya melengkapi metadata.
    scanChildren(LP:FindFirstChild("Backpack") or LP:FindFirstChildOfClass("Backpack"))
    scanChildren(LP.Character)
    local layout = _getLayout()
    if layout then
        local raw = {}
        _collectLayout(layout, raw, 0, {})
        for _, r in ipairs(raw) do
            add({
                id = tostring(_pick(r, ID_FIELDS) or ""),
                name = tostring(_pick(r, NAME_FIELDS) or ""),
                kg = tonumber(_pick(r, KG_FIELDS)) or 0,
                multi = tonumber(_pick(r, MULTI_FIELDS)) or 0,
                mut = _pick(r, MUT_FIELDS), decay = r.DecayAlpha, tool = nil,
            })
        end
    end
    _linkBackpackTools(byId, list)
    return list, byId
end

local function _fetchPrice(e, force)
    local mode = _syncPriceModeCache()
    local key = _priceCacheKey(e, mode)
    if not force then
        local cached = priceByKey[key]
        if cached and cached > 0 then return cached end
    end
    local fsv = _fsv()
    if not fsv then return 0 end

    local multi = e.multi or 0
    if multi <= 0 and e.tool and type(fsv.resolveMulti) == "function" then
        local ok, m = pcall(fsv.resolveMulti, e.tool)
        if ok and type(m) == "number" then multi = m end
    end

    if multi > 0 and e.name ~= "" and type(fsv.getBackpackEspPrice) == "function" then
        local fruitId = tostring(e.id or "")
        local bidPrice = tonumber(e.bidPrice) or 0
        if bidPrice <= 0 and e.tool then
            if type(fsv.resolveBidPrice) == "function" then
                local okBid, b = pcall(fsv.resolveBidPrice, e.tool)
                if okBid and type(b) == "number" and b > 0 then bidPrice = b end
            elseif type(e.tool.GetAttribute) == "function" then
                bidPrice = tonumber(e.tool:GetAttribute("BidPrice")) or 0
            end
        end
        if bidPrice > 0 then e.bidPrice = bidPrice end
        local ok, p = pcall(fsv.getBackpackEspPrice, e.name, multi, e.mut, e.decay, mode, fruitId, bidPrice)
        if ok and type(p) == "number" and p > 0 then
            priceByKey[key] = p
            return p
        end
    end
    return priceByKey[key] or 0
end

local function _usedKey(e)
    local id = tostring(e.id or "")
    if id ~= "" then return id end
    return "n:" .. _norm(e.name) .. "|" .. tostring(math.floor((e.kg or 0) * 100))
end

local function _matchFruit(uiName, uiKg, uiId, list, byId, used)
    uiId = tostring(uiId or "")
    uiKg = tonumber(uiKg) or 0
    if uiId ~= "" and byId[uiId] and not used[uiId] then
        used[uiId] = true
        return byId[uiId]
    end
    local best, bestDiff = nil, math.huge
    for _, e in ipairs(list) do
        local key = _usedKey(e)
        if not used[key] and _nameOk(uiName, e.name) then
            local diff = math.abs((e.kg or 0) - uiKg)
            if diff <= _kgTol(uiKg) and diff < bestDiff then
                bestDiff = diff
                best = e
            end
        end
    end
    if best then used[_usedKey(best)] = true return best end

    if uiName == "" then
        local bestKg, bestKgDiff = nil, math.huge
        for _, e in ipairs(list) do
            local key = _usedKey(e)
            if not used[key] then
                local diff = math.abs((e.kg or 0) - uiKg)
                if uiKg > 0 and diff <= _kgTol(uiKg) and diff < bestKgDiff then
                    bestKgDiff = diff
                    bestKg = e
                end
            end
        end
        if bestKg then used[_usedKey(bestKg)] = true return bestKg end
    end
    return nil
end

local function _parseKg(text)
    text = tostring(text or "")
    if text:match("^[xX]%d") then return nil end
    return tonumber(text:match("([%d%.]+)%s*[kK][gG]"))
end

local function _getBackpackGui()
    local pg = LP:FindFirstChild("PlayerGui")
    return pg and pg:FindFirstChild("BackpackGui")
end

local function _findInventoryHeader(inventory)
    if not inventory then return nil end
    local hdr = inventory:FindFirstChild("FruitInventory")
    if hdr and hdr:IsA("TextLabel") and hdr.Visible then return hdr end
    for _, lbl in ipairs(inventory:GetDescendants()) do
        if lbl:IsA("TextLabel") and lbl.Visible and lbl.Text:match("%d+/%d+") then
            return lbl
        end
    end
    return nil
end

local function _findBackpackContextFromGui(sg)
    local backpack = sg:FindFirstChild("Backpack")
    if not backpack then return nil end
    local inventory = backpack:FindFirstChild("Inventory")
    if not inventory or not inventory:IsA("GuiObject") then return nil end
    if not inventory.Visible or not _isVisible(inventory) then return nil end

    local scroll = inventory:FindFirstChild("ScrollingFrame")
    local grid = scroll and (scroll:FindFirstChild("UIGridFrame") or scroll)
    local search = inventory:FindFirstChild("Search")
    local searchBox = search and search:FindFirstChild("TextBox")
    local hotbar = backpack:FindFirstChild("Hotbar")

    return {
        screenGui = sg,
        searchBox = searchBox,
        fruitHeader = _findInventoryHeader(inventory),
        fruitGrid = grid,
        hotbar = hotbar,
        inventory = inventory,
    }
end

local function _findAncestorNamed(inst, name)
    local cur = inst
    while cur and cur ~= game do
        if cur.Name == name then return cur end
        cur = cur.Parent
    end
    return nil
end

local function _findBackpackContextGeneric()
    local pg = LP:FindFirstChild("PlayerGui")
    if not pg then return nil end
    for _, inst in ipairs(pg:GetDescendants()) do
        if inst:IsA("TextBox") and _isVisible(inst) then
            local hint = (inst.PlaceholderText .. " " .. inst.Text .. " " .. inst.Name):lower()
            if hint:find("search", 1, true) then
                local sg = inst:FindFirstAncestorWhichIsA("ScreenGui")
                if sg and sg.Enabled then
                    local inventory = _findAncestorNamed(inst, "Inventory")
                    if inventory and inventory:IsA("GuiObject") and inventory.Visible then
                        return _findBackpackContextFromGui(sg)
                    end
                end
            end
        end
    end
    return nil
end

local function _findBackpackContext()
    local sg = _getBackpackGui()
    if sg and sg.Enabled then
        local ctx = _findBackpackContextFromGui(sg)
        if ctx then return ctx end
    end
    return _findBackpackContextGeneric()
end

local function _isHotbarArea(inst)
    local cur = inst
    while cur and cur ~= game do
        local n = cur.Name:lower()
        if n:find("hotbar", 1, true) or n:find("toolbar", 1, true)
            or n:find("quickslot", 1, true) or n:find("bottombar", 1, true)
            or n:find("slotbar", 1, true) or n:find("equipped", 1, true) then
            return true
        end
        cur = cur.Parent
    end
    return false
end

local function _isHotbarContainer(inst)
    if not inst or not inst:IsA("GuiObject") then return false end
    return _isHotbarArea(inst)
end

local function _findHotbarRoots(ctx)
    local roots, seen = {}, {}
    if ctx and ctx.hotbar and ctx.hotbar:IsA("GuiObject") and _isVisible(ctx.hotbar) then
        roots[#roots + 1] = ctx.hotbar
        return roots
    end
    local sg = ctx and ctx.screenGui
    if not sg then return roots end

    for _, inst in ipairs(sg:GetDescendants()) do
        if inst.Name == "Hotbar" and inst:IsA("Frame") and _isVisible(inst) and not seen[inst] then
            seen[inst] = true
            roots[#roots + 1] = inst
        end
    end
    return roots
end

local function _inGrid(inst, grid)
    if not inst or not grid then return false end
    if _isHotbarArea(inst) then return false end
    return inst == grid or inst:IsDescendantOf(grid)
end

----------------------------------------------------------------
-- UI slot scan
----------------------------------------------------------------

local function _findSlotRoot(kgLabel)
    if kgLabel and kgLabel.Name == "ToolCount" then
        local p = kgLabel.Parent
        if p and (p:IsA("TextButton") or p:IsA("Frame") or p:IsA("ImageButton")) then
            return p
        end
    end
    local cur = kgLabel.Parent
    for _ = 1, 6 do
        if not cur then break end
        if cur:IsA("Frame") or cur:IsA("ImageButton") or cur:IsA("TextButton") then
            local w, h = cur.AbsoluteSize.X, cur.AbsoluteSize.Y
            if w >= 40 and h >= 40 and w <= 220 and h <= 220 then
                return cur
            end
        end
        cur = cur.Parent
    end
    return kgLabel.Parent
end

local function _slotNameFromRoot(root, kgLabel)
    if root then
        local toolName = root:FindFirstChild("ToolName")
        if toolName and toolName:IsA("TextLabel") and toolName.Visible and toolName.Text ~= "" then
            return toolName.Text
        end
    end
    if root and type(root.GetAttribute) == "function" then
        local attr = root:GetAttribute("FruitName") or root:GetAttribute("Fruit")
            or root:GetAttribute("SeedName") or root:GetAttribute("ItemName")
        if attr ~= nil and tostring(attr) ~= "" then return tostring(attr) end
    end
    local best, bestLen = nil, 0
    for _, lbl in ipairs(root:GetDescendants()) do
        if lbl:IsA("TextLabel") and lbl ~= kgLabel and lbl.Visible and lbl.Name ~= "ToolCount" then
            local t = lbl.Text
            if t ~= "" and not t:match("%d+/%d+") and not _parseKg(t) and not t:lower():find("search", 1, true) then
                if #t > bestLen then bestLen = #t best = t end
            end
        end
    end
    return best or ""
end

local function _slotId(root)
    if not root then return "" end
    return tostring(root:GetAttribute("Id") or root:GetAttribute("id")
        or root:GetAttribute("UUID") or root:GetAttribute("FruitId") or "")
end

local function _ensureSlotLabel(root)
    local lbl = root:FindFirstChild(TAG_SLOT)
    if lbl and not lbl:IsA("TextLabel") then lbl:Destroy() lbl = nil end
    if not lbl then
        lbl = Instance.new("TextLabel")
        lbl.Name = TAG_SLOT
        lbl.BorderSizePixel = 0
        lbl.Font = Enum.Font.GothamMedium
        lbl.TextSize = 10
        lbl.TextXAlignment = Enum.TextXAlignment.Center
        lbl.TextYAlignment = Enum.TextYAlignment.Center
        lbl.Parent = root
        Instance.new("UICorner", lbl).CornerRadius = UDim.new(0, 5)
        local stroke = Instance.new("UIStroke")
        stroke.Name = "_GAG2FBP_STROKE"
        stroke.Thickness = 1
        stroke.ApplyStrokeMode = Enum.ApplyStrokeMode.Border
        stroke.Parent = lbl
    end
    local stroke = lbl:FindFirstChild("_GAG2FBP_STROKE")
    if stroke and stroke:IsA("UIStroke") then
        stroke.Color = COL_SLOT_STROKE
        stroke.Transparency = 0.25
    end
    lbl.BackgroundTransparency = 0.08
    lbl.BackgroundColor3 = COL_SLOT_BG
    lbl.TextColor3 = COL_SLOT_TEXT
    lbl.TextStrokeTransparency = 1
    lbl.AnchorPoint = Vector2.new(0.5, 0.5)
    lbl.Position = UDim2.new(0.5, 0, 0.43, -2)
    lbl.Size = UDim2.new(0.86, 0, 0, 15)
    lbl.ZIndex = (root.ZIndex or 1) + 5
    return lbl
end

local function _styleTotalChildren(root, baseZ)
    local z = math.max(baseZ + 12, 2)
    root.ZIndex = z
    for _, ch in ipairs(root:GetDescendants()) do
        if ch:IsA("GuiObject") then ch.ZIndex = z + 1 end
    end
    for _, ch in ipairs(root:GetChildren()) do
        if ch:IsA("GuiObject") then ch.ZIndex = z + 2 end
    end
end

local function _gardenEspActive()
    local eg = G.EspFruitGarden or rawget(_G, "EspFruitGarden")
    if type(eg) ~= "table" or next(eg) == nil then return false end
    if type(eg.IsEnabled) == "function" then
        return eg:IsEnabled() == true
    end

    local MAIN = rawget(_G, "MAIN") or G.MAIN
    local st = MAIN and MAIN.misc and MAIN.misc.fruit_garden_esp
    st = type(st) == "table" and st or {}
    return (G.FRUIT_GARDEN_ESP_ENABLED == true)
        or (rawget(_G, "FRUIT_GARDEN_ESP_ENABLED") == true)
        or (st.enabled == true)
end

local function _getBadgeParent(searchBox, fruitHeader)
    local anchor = fruitHeader or searchBox
    if not anchor or not anchor:IsA("GuiObject") then return nil end
    local parent = anchor.Parent
    if not parent or not parent:IsA("GuiObject") then return nil end
    return parent
end

local function _detachLegacyTotalsRow(parent)
    if not parent then return end
    local row = parent:FindFirstChild("_GAG2FBP_TOTALS_ROW")
    if not row then return end
    for _, name in ipairs({ TAG_TOTAL, TAG_GARDEN_TOTAL }) do
        local ch = row:FindFirstChild(name)
        if ch then ch.Parent = parent end
    end
    pcall(function() row:Destroy() end)
end

local function _layoutTotalBadges(parent, gardenRoot, backpackRoot, searchBox, fruitHeader)
    if not parent or not parent:IsA("GuiObject") then return end

    local sx, sy, zBase
    if searchBox and searchBox:IsA("GuiObject") then
        sy = searchBox.AbsolutePosition.Y - parent.AbsolutePosition.Y - 10
        sx = (searchBox.AbsolutePosition.X - parent.AbsolutePosition.X) + searchBox.AbsoluteSize.X
        zBase = searchBox.ZIndex or 1
    elseif fruitHeader and fruitHeader:IsA("GuiObject") then
        sy = (fruitHeader.AbsolutePosition.Y - parent.AbsolutePosition.Y) + fruitHeader.AbsoluteSize.Y + 4
        sx = (fruitHeader.AbsolutePosition.X - parent.AbsolutePosition.X) + fruitHeader.AbsoluteSize.X
        zBase = fruitHeader.ZIndex or 1
    else
        return
    end

    local z = math.max(zBase, 1) + 30

    if backpackRoot and backpackRoot.Parent == parent then
        backpackRoot.AnchorPoint = Vector2.new(1, 1)
        backpackRoot.Position = UDim2.fromOffset(sx, sy)
        backpackRoot.Visible = true
        _styleTotalChildren(backpackRoot, z)
    end

    if gardenRoot and gardenRoot.Parent == parent and gardenRoot.Visible ~= false then
        gardenRoot.AnchorPoint = Vector2.new(1, 1)
        if backpackRoot and backpackRoot.Parent == parent and backpackRoot.Visible ~= false then
            local bpLeft = backpackRoot.AbsolutePosition.X - parent.AbsolutePosition.X
            gardenRoot.Position = UDim2.fromOffset(bpLeft - 8, sy)
        else
            gardenRoot.Position = UDim2.fromOffset(sx, sy)
        end
        _styleTotalChildren(gardenRoot, z)
    end
end

local function _deferLayoutBadges(parent, gardenRoot, backpackRoot, searchBox, fruitHeader)
    task.defer(function()
        if parent and parent.Parent then
            _layoutTotalBadges(parent, gardenRoot, backpackRoot, searchBox, fruitHeader)
        end
    end)
end

local function _readGardenEspSummary()
    if not _gardenEspActive() then
        return nil
    end

    local eg = G.EspFruitGarden or rawget(_G, "EspFruitGarden")
    if type(eg) ~= "table" then return nil end

    if type(eg.GetEspSummary) == "function" then
        local ok, sum = pcall(eg.GetEspSummary, eg)
        if ok and type(sum) == "table" then
            return {
                count = tonumber(sum.count) or 0,
                total = tonumber(sum.total) or 0,
            }
        end
    end

    if type(eg.SummarizeUnharvested) == "function" then
        local ok, result = pcall(eg.SummarizeUnharvested, eg)
        if ok and type(result) == "table" then
            return {
                count = tonumber(result.count) or 0,
                total = tonumber(result.total) or 0,
            }
        end
    end

    return { count = 0, total = 0 }
end

local function _hideGardenBadge(ctx)
    if not ctx then return end
    local parent = _getBadgeParent(ctx.searchBox, ctx.fruitHeader)
    if not parent then return end
    local root = parent:FindFirstChild(TAG_GARDEN_TOTAL)
    if root then root.Visible = false end
    local totalRoot = parent:FindFirstChild(TAG_TOTAL)
    _layoutTotalBadges(parent, nil, totalRoot, ctx.searchBox, ctx.fruitHeader)
end

local function _updateGardenBadge(ctx, summary)
    if not ctx then return end
    local parent = _getBadgeParent(ctx.searchBox, ctx.fruitHeader)
    if not parent then return end
    _detachLegacyTotalsRow(parent)

    local totalRoot = parent:FindFirstChild(TAG_TOTAL)
    local gardenRoot

    if not _gardenEspActive() then
        gardenRoot = parent:FindFirstChild(TAG_GARDEN_TOTAL)
        if gardenRoot then gardenRoot.Visible = false end
        _layoutTotalBadges(parent, nil, totalRoot, ctx.searchBox, ctx.fruitHeader)
        _deferLayoutBadges(parent, nil, totalRoot, ctx.searchBox, ctx.fruitHeader)
        return
    end

    gardenRoot = _ensureGardenTotalLabel(parent)
    if gardenRoot then
        gardenRoot.Visible = true
        _setGardenTotalText(gardenRoot, summary)
    end
    _layoutTotalBadges(parent, gardenRoot, totalRoot, ctx.searchBox, ctx.fruitHeader)
    _deferLayoutBadges(parent, gardenRoot, totalRoot, ctx.searchBox, ctx.fruitHeader)
end

local function _tickGardenBadge()
    if not running or not _cfg().enabled or not bpOpen then return end
    local ctx = _findBackpackContext()
    if not ctx then return end

    if not _gardenEspActive() then
        _hideGardenBadge(ctx)
        return
    end

    local summary = _readGardenEspSummary()
    if summary then
        gardenCache.count = summary.count
        gardenCache.total = summary.total
    else
        gardenCache.count = 0
        gardenCache.total = 0
    end
    pcall(_updateGardenBadge, ctx, gardenCache)
end

local function _scheduleGardenBadgeRefresh()
    if not running or not bpOpen then return end
    local now = os.clock()
    if (now - lastGardenBadgeAt) < GARDEN_BADGE_MIN_SEC then return end
    lastGardenBadgeAt = now
    task.defer(_tickGardenBadge)
end

local function _hookGardenSummary()
    local eg = G.EspFruitGarden or rawget(_G, "EspFruitGarden")
    if type(eg) ~= "table" then return false end
    eg.OnSummaryChanged = function()
        _scheduleGardenBadgeRefresh()
    end
    gardenHooked = true
    return true
end

local function _ensureGardenHook()
    if gardenHooked then return end
    _hookGardenSummary()
end

local function _unhookGardenSummary()
    local eg = G.EspFruitGarden or rawget(_G, "EspFruitGarden")
    if type(eg) == "table" then
        eg.OnSummaryChanged = nil
    end
    gardenHooked = false
end

local function _gardenLoop()
    while running do
        if _cfg().enabled and bpOpen then
            pcall(_tickGardenBadge)
        end
        task.wait(GARDEN_SCAN_SEC)
    end
end

local function _ensureGardenTotalLabel(parent)
    if not parent or not parent:IsA("GuiObject") then return nil end

    local root = parent:FindFirstChild(TAG_GARDEN_TOTAL)
    if root and root.Parent ~= parent then root.Parent = parent end
