local function _setGardenTotalText(gardenRoot, summary)
    if not gardenRoot then return end
    local valLbl = gardenRoot:FindFirstChild(TAG_GARDEN_VAL)
    if not valLbl or not valLbl:IsA("TextLabel") then return end

    local count = tonumber(summary and summary.count) or 0
    local total = tonumber(summary and summary.total) or 0
    if count <= 0 then
        valLbl.Text = "0"
        return
    end
    if total > 0 then
        valLbl.Text = tostring(count) .. " · " .. _formatPrice(total)
    else
        valLbl.Text = tostring(count)
    end
end

