    filter_rarities   = {},
    auto_refresh_list = true,
    auto_hop          = false,
}

local _lastScan = nil
local _lastListRaw = {}
local _lastList = {}
local _lastSyncOk = nil
local _lastSyncMsg = ""
local _lastListErr = ""
local _autoSyncToken = 0
local _autoRefreshToken = 0
local _autoHopFetchToken = 0
local _lastSyncFingerprint = ""
local _uiRefreshers = {}
local _uiHopRefreshers = {}
local _uiHydrated = false
local _lastUiNotifyAt = 0
local _uiNotifyScheduled = false
local _hopTargetUiFingerprint = ""
local _hopInFlight = false
local _lastAutoHopAt = 0
local _lastAutoHopJobId = ""
local _pendingHopJobId = ""
local _hopStartedAt = 0
local _hopFromJobId = ""
