----------------------------------------------------------------
-- Utils
----------------------------------------------------------------
local function getG()
    return (getgenv and getgenv()) or _G
end

local function getSectionBuyPet()
    local G = getG()
    return G.SectionAutoBuyPet or rawget(_G, "SectionAutoBuyPet")
end

local function cleanSelectedMap(map)
    local out = {}
    if type(map) ~= "table" then return out end
    for k, v in pairs(map) do
        if v == true and tostring(k) ~= "" then
            out[tostring(k)] = true
        end
    end
    return out
end

local function mapToArray(map)
    local arr = {}
    if type(map) ~= "table" then return arr end
    for k, v in pairs(map) do
        if v == true then
            arr[#arr + 1] = tostring(k)
        end
    end
    table.sort(arr)
    return arr
end

local function arrayToMap(arr)
    local out = {}
    if type(arr) ~= "table" then return out end
    for _, v in ipairs(arr) do
        if type(v) == "string" and v ~= "" then
            out[v] = true
        end
    end
    return out
end

local function shortSpawnId(uuid)
    uuid = tostring(uuid or ""):gsub("%s+", "")
    if uuid == "" then return "------" end
    if #uuid >= 6 then
        return uuid:sub(-6):upper()
    end
    return uuid:upper()
end

local function getPetListView()
    local G = getG()
    return G.PetListView or _G.PetListView
end

local function collectSeenRarities()
    local seen = {}
    local out = {}

    local function add(r)
        r = tostring(r or "")
        if r == "" or seen[r] then return end
        seen[r] = true
        out[#out + 1] = r
    end

    for _, row in ipairs(_lastListRaw or {}) do
        add(row.rarity)
    end

    if type(_lastScan) == "table" and type(_lastScan.pets) == "table" then
        for _, pet in ipairs(_lastScan.pets) do
            add(pet.rarity)
        end
    end

    return out
end

local function getRarityItems()
    local extra = collectSeenRarities()
    local PLV = getPetListView()
    if type(PLV) == "table" and type(PLV.buildRarityItems) == "function" then
        return PLV.buildRarityItems(extra)
    end

    table.sort(extra)
    local out = {}
    for _, rarity in ipairs(extra) do
        out[#out + 1] = { key = rarity, name = rarity }
    end
    return out
end

local function normalizeRarityKey(name)
    return tostring(name or ""):lower():gsub("[%s_%-]+", "")
end

local function getRarityRank(name)
    name = tostring(name or "")
    if name == "" then return 0 end

    local PLV = getPetListView()
    if type(PLV) == "table" and type(PLV.getRarityRank) == "function" then
        local r = PLV.getRarityRank(name)
        if type(r) == "number" and r > 0 then
            return r
        end
    end

    local key = normalizeRarityKey(name)
    return FALLBACK_RARITY_RANK[key] or 0
end

local function getRarityColor(name)
    local PLV = getPetListView()
    if type(PLV) == "table" and type(PLV.getRarityColor) == "function" then
        return PLV.getRarityColor(name)
    end
    return COLOR_ACCENT
end

local function countSelected(map)
    local n = 0
    if type(map) ~= "table" then return 0 end
    for _, v in pairs(map) do
        if v == true then n += 1 end
    end
    return n
end

local function normalizePetKey(name)
    return tostring(name or ""):lower():gsub("[%s_%-]+", "")
end

local function loadBuyPetTargets()
    local SectionBuyPet = getSectionBuyPet()
    local G = getG()
    local MAIN = G.MAIN or rawget(_G, "MAIN")

    local raw = nil
    local store = G.__GAG2_BUY_PET or rawget(_G, "__GAG2_BUY_PET")
    if type(store) == "table" and type(store.targets) == "table" and #store.targets > 0 then
        raw = store.targets
    end
    if not raw or #raw == 0 then
        raw = G.BUY_PET_TARGETS or rawget(_G, "BUY_PET_TARGETS")
    end
    if (not raw or #raw == 0) and type(MAIN) == "table"
        and type(MAIN.auto) == "table"
        and type(MAIN.auto.buy) == "table"
        and type(MAIN.auto.buy.pet) == "table"
        and type(MAIN.auto.buy.pet.targets) == "table"
    then
        raw = MAIN.auto.buy.pet.targets
    end

    if type(SectionBuyPet) == "table" then
        if type(SectionBuyPet.deserializeTargets) == "function" then
            raw = SectionBuyPet.deserializeTargets(raw or {})
        end
        if type(SectionBuyPet.normalizeTargets) == "function" then
            return SectionBuyPet.normalizeTargets(raw or {})
        end
    end
    return type(raw) == "table" and raw or {}
end

local function getPetTierRank(petName)
    petName = tostring(petName or "")
    if petName == "" then return 0 end
    local PLV = getPetListView()
    if type(PLV) == "table" and type(PLV.getPetRarity) == "function" then
        local rarity = PLV.getPetRarity(petName)
        if rarity and tostring(rarity) ~= "" then
            return getRarityRank(rarity)
        end
    end
    return 0
end

local function sortBuyPetTargetsByRarity(targets)
    if type(targets) ~= "table" or #targets <= 1 then return targets end
    local sorted = {}
    for i, t in ipairs(targets) do
        sorted[i] = t
    end
    table.sort(sorted, function(a, b)
        local ra = getPetTierRank(a and a.pet)
        local rb = getPetTierRank(b and b.pet)
        if ra ~= rb then return ra > rb end
        return tostring(a and a.pet or ""):lower() < tostring(b and b.pet or ""):lower()
    end)
    return sorted
end

local function buyPetTargetsFingerprint(targets)
    if type(targets) ~= "table" or #targets == 0 then return "" end
    local chunks = {}
    for _, rule in ipairs(targets) do
        if type(rule) == "table" then
            local types = mapToArray(rule.types or {})
            local sizes = mapToArray(rule.sizes or {})
            chunks[#chunks + 1] = string.format(
                "%s:%s:%s:%s:%s:%s",
                tostring(rule.pet or ""),
                rule.enabled and "1" or "0",
                table.concat(types, ","),
                table.concat(sizes, ","),
                rule.steal == true and "1" or "0",
                tostring(rule.max_steal or rule.max_steal_mult or "")
            )
        end
    end
    table.sort(chunks)
    return table.concat(chunks, "|")
end

function M.getBuyPetTargets()
    return loadBuyPetTargets()
end

function M.getEnabledBuyPetTargets()
    local SectionBuyPet = getSectionBuyPet()
    local targets = loadBuyPetTargets()
    if type(SectionBuyPet) == "table" and type(SectionBuyPet.getEnabledTargets) == "function" then
        return SectionBuyPet.getEnabledTargets(targets)
    end
    local out = {}
    for _, rule in ipairs(targets) do
        if type(rule) == "table" and rule.enabled == true then
            out[#out + 1] = rule
        end
    end
    return out
end

local function countEnabledBuyPetTargets()
    local SectionBuyPet = getSectionBuyPet()
    local targets = loadBuyPetTargets()
    if type(SectionBuyPet) == "table" and type(SectionBuyPet.countEnabledTargets) == "function" then
        return SectionBuyPet.countEnabledTargets(targets)
    end
    local n = 0
    for _, rule in ipairs(targets) do
        if type(rule) == "table" and rule.enabled == true then n += 1 end
    end
    return n
end

local function countBuyPetTargets()
    return countEnabledBuyPetTargets()
end

local function buyPetTargetNames()
    local SectionBuyPet = getSectionBuyPet()
    local targets = loadBuyPetTargets()
    local enabled = targets
    if type(SectionBuyPet) == "table" and type(SectionBuyPet.getEnabledTargets) == "function" then
        enabled = SectionBuyPet.getEnabledTargets(targets)
    else
        local out = {}
        for _, rule in ipairs(targets) do
            if type(rule) == "table" and rule.enabled == true then out[#out + 1] = rule end
        end
        enabled = out
    end
    if type(SectionBuyPet) == "table" and type(SectionBuyPet.targetsToSelected) == "function" then
        return mapToArray(SectionBuyPet.targetsToSelected(enabled))
    end
    local names = {}
    local seen = {}
    for _, rule in ipairs(enabled) do
        local n = tostring(rule.pet or "")
        if n ~= "" then
            local k = normalizePetKey(n)
            if not seen[k] then
                seen[k] = true
                names[#names + 1] = n
            end
        end
    end
    table.sort(names)
    return names
end

local function buildListFetchFilters(overrideFilters)
    local filters = overrideFilters
    if type(filters) ~= "table" then
        filters = {
            place_id = game.PlaceId,
            limit = LIST_FETCH_LIMIT,
        }
    end
    if overrideFilters == nil and _cfg.auto_hop and countBuyPetTargets() > 0 then
        filters.pet_names = buyPetTargetNames()
    end
    return filters
end

local function refreshLocalScanIfNeeded(force)
    if not force and HOP_SKIP_PRE_SCAN then
        if (os.clock() - _lastHopLocalScanAt) < HOP_LOCAL_SCAN_INTERVAL_SEC then
            return
        end
    end
    _lastHopLocalScanAt = os.clock()
    M.Scan()
end

local function getPetTypeItems()
    local PLV = getPetListView()
    if type(PLV) == "table" and type(PLV.buildPetItems) == "function" then
        return PLV.buildPetItems() or {}
    end
    return {}
end

local function buildPetAliasLookup()
    local lookup = {}
    for _, item in ipairs(getPetTypeItems()) do
        local key = tostring(item.key or item.name or "")
        if key ~= "" then
            lookup[normalizePetKey(key)] = key
            local display = tostring(item.name or "")
            if display ~= "" then
                lookup[normalizePetKey(display)] = key
            end
        end
    end
    return lookup
end

local function resolvePetCanonicalName(petName, aliasLookup)
    petName = tostring(petName or "")
    if petName == "" then return "" end
    aliasLookup = aliasLookup or buildPetAliasLookup()
    return aliasLookup[normalizePetKey(petName)] or petName
end

local function isSameServerJob(jobId)
    jobId = tostring(jobId or ""):gsub("%s+", "")
    if jobId == "" then return true end
    return jobId:lower() == tostring(game.JobId):lower()
end

local function getSheckles()
    local v = tonumber(LP:GetAttribute("Sheckles"))
    if type(v) == "number" then return v end

    local ls = LP:FindFirstChild("leaderstats")
    if ls then
        for _, name in ipairs({ "Sheckles", "Money", "Cash", "Coins" }) do
            local obj = ls:FindFirstChild(name)
            if obj and (obj:IsA("IntValue") or obj:IsA("NumberValue")) then
                return tonumber(obj.Value)
            end
        end
    end

    return nil
end

local function canAffordPrice(price)
    price = tonumber(price)
    if not price or price <= 0 then return true end
    local money = getSheckles()
    if type(money) ~= "number" then return true end
    return money >= price
end

local function markAvoidJob(jobId, ttlSec)
    jobId = tostring(jobId or ""):lower():gsub("%s+", "")
    if jobId == "" then return end
    _avoidJobs[jobId] = os.clock() + math.max(5, tonumber(ttlSec) or AVOID_JOB_TTL_FULL)
end

local function isAvoidedJob(jobId)
    jobId = tostring(jobId or ""):lower():gsub("%s+", "")
    local untilAt = _avoidJobs[jobId]
    if not untilAt then return false end
    if os.clock() >= untilAt then
        _avoidJobs[jobId] = nil
        return false
    end
    return true
end

local function classifyTeleportFail(result, errMsg)
    local msg = string.lower(tostring(errMsg or ""))
    local r = string.lower(tostring(result or ""))
    if r:find("unauthorized", 1, true)
        or msg:find("private instance", 1, true)
        or msg:find("specific joins", 1, true)
        or msg:find("not authorized", 1, true)
        or msg:find("restricted", 1, true)
        or msg:find("private", 1, true)
    then
        return "private", AVOID_JOB_TTL_DEAD
    end
    if msg:find("gameended", 1, true)
        or msg:find("game full", 1, true)
        or msg:find("could not find requested game instance", 1, true)
        or msg:find("requested game instance", 1, true)
        or msg:find("instance has shutdown", 1, true)
    then
        return "dead_or_full", AVOID_JOB_TTL_DEAD
    end
    if r:find("isteleporting", 1, true)
        or msg:find("previous teleport", 1, true)
        or msg:find("in processing", 1, true)
    then
        return "busy", AVOID_JOB_TTL_BUSY
    end
    return "other", AVOID_JOB_TTL_FULL
end

local function shortJobId(jobId)
    jobId = tostring(jobId or ""):gsub("%s+", "")
    if jobId == "" then return "?" end
    if #jobId > 8 then return jobId:sub(1, 8) .. "…" end
    return jobId
end

local function describeTeleportFail(result, errMsg)
    local kind = classifyTeleportFail(result, errMsg)
    local msg = string.lower(tostring(errMsg or ""))
    if kind == "private" then
        return "Private server", "Can't join this server (private/restricted)"
    end
    if kind == "dead_or_full" then
        if msg:find("full", 1, true) then
            return "Server full", tostring(errMsg or "Game full")
        end
        if msg:find("gameended", 1, true) or msg:find("shutdown", 1, true) then
            return "Server ended", tostring(errMsg or "Game ended")
        end
        if msg:find("could not find", 1, true) or msg:find("requested game instance", 1, true) then
            return "Server not found", tostring(errMsg or "Instance gone")
        end
        return "Server unavailable", tostring(errMsg or "Dead/full")
    end
    if kind == "busy" then
        return "Teleport busy", tostring(errMsg or "Previous teleport in progress")
    end
    return "Teleport failed", tostring(errMsg or tostring(result or "Unknown error"))
end

local function describeHopError(code, rawMsg)
    code = tostring(code or "")
    rawMsg = tostring(rawMsg or "")
    if code == "insufficient_sheckles" then
        return "Not enough sheckles", rawMsg ~= "" and rawMsg or code
    end
    if code == "already on server" then
        return "Already on this server", rawMsg ~= "" and rawMsg or code
    end
    if code == "server_avoided" then
        return "Server skipped (recent fail)", rawMsg ~= "" and rawMsg or code
    end
    if code == "job_id empty" then
        return "Invalid server ID", rawMsg ~= "" and rawMsg or code
    end
    if rawMsg ~= "" and rawMsg ~= code then
        return describeTeleportFail("", rawMsg)
    end
    if code ~= "" then
        return "Hop failed", code
    end
    return "Hop failed", "unknown"
end

local function setHopUiStatus(phase, opts)
    opts = type(opts) == "table" and opts or {}
    _hopUi.phase = tostring(phase or "idle")
    if opts.petName ~= nil then _hopUi.petName = tostring(opts.petName) end
    if opts.rarity ~= nil then _hopUi.rarity = tostring(opts.rarity) end
    if opts.jobId ~= nil then _hopUi.jobId = tostring(opts.jobId) end
    if opts.price ~= nil then _hopUi.price = tonumber(opts.price) or 0 end
    if opts.timeLeft ~= nil then _hopUi.timeLeft = tostring(opts.timeLeft) end
    if opts.failTitle ~= nil then _hopUi.failTitle = tostring(opts.failTitle) end
    if opts.failDetail ~= nil then _hopUi.failDetail = tostring(opts.failDetail) end
    _hopUi.updatedAt = os.clock()
    M._notifyUiHop()
end

function M.GetHopUiStatus()
    return {
        phase = _hopUi.phase,
        petName = _hopUi.petName,
        rarity = _hopUi.rarity,
        jobId = _hopUi.jobId,
        price = _hopUi.price,
        timeLeft = _hopUi.timeLeft,
        failTitle = _hopUi.failTitle,
        failDetail = _hopUi.failDetail,
        updatedAt = _hopUi.updatedAt,
        inFlight = (_hopInFlight == true),
    }
end

local function prepareForHopTeleport()
    local G = getG()
    local PR = rawget(_G, "PSReconnect") or G.PSReconnect
    if type(PR) == "table" and type(PR.ReleaseHopTeleportLock) == "function" then
        pcall(PR.ReleaseHopTeleportLock, PR)
    end
    local AH = G.AutoHopServer or G.AutoHopServerModule or rawget(_G, "AutoHopServer")
    if type(AH) == "table" and type(AH.ReleaseTeleportLock) == "function" then
        pcall(AH.ReleaseTeleportLock, AH)
    end
end

local function invokeHopTeleport(placeId, jobId, td)
    prepareForHopTeleport()
    placeId = tonumber(placeId) or game.PlaceId
    jobId = tostring(jobId or ""):gsub("%s+", "")

    local okLegacy, errLegacy = pcall(function()
        TeleportService:TeleportToPlaceInstance(placeId, jobId, LP, "", td)
    end)
    if okLegacy then
        return true, "teleport_to_place_instance"
    end

    local opts = Instance.new("TeleportOptions")
    pcall(function() opts:SetTeleportData(td) end)
    pcall(function() opts.ServerInstanceId = jobId end)

    local okAsync, errAsync = pcall(function()
        TeleportService:TeleportAsync(placeId, { LP }, opts)
    end)
    if okAsync then
        return true, "teleport_async"
    end

    return false, tostring(errLegacy or errAsync)
end

local function clearHopBurstTried()
    _hopBurstTried = {}
end

local function markHopBurstTried(jobId)
    jobId = tostring(jobId or ""):lower():gsub("%s+", "")
    if jobId ~= "" then
        _hopBurstTried[jobId] = true
    end
end

local function isHopBurstTried(jobId)
    jobId = tostring(jobId or ""):lower():gsub("%s+", "")
    return jobId ~= "" and _hopBurstTried[jobId] == true
end

local function scheduleAutoHopRetry(delaySec)
    delaySec = tonumber(delaySec) or 0
    _lastAutoHopAt = os.clock() - AUTO_HOP_COOLDOWN_SEC
    local function runRetry()
        M.tryAutoHopBurst(true, HOP_BURST_MAX)
    end
    if delaySec <= 0 then
        task.defer(runRetry)
        return
    end
    task.delay(delaySec, function()
        if _cfg.auto_hop then
            runRetry()
        end
    end)
end

local function startHopWatchdog(attemptJobId, fromJobId)
    attemptJobId = tostring(attemptJobId or ""):lower():gsub("%s+", "")
    fromJobId = tostring(fromJobId or "")
    if attemptJobId == "" then return end

    _hopWatchdogToken += 1
    local token = _hopWatchdogToken
    task.delay(HOP_WATCHDOG_SEC, function()
        if token ~= _hopWatchdogToken then return end
        if _pendingHopJobId == "" then return end
        if tostring(_pendingHopJobId):lower() ~= attemptJobId then return end
        if tostring(game.JobId or "") ~= fromJobId then return end

        markAvoidJob(attemptJobId, AVOID_JOB_TTL_DEAD)
        markHopBurstTried(attemptJobId)
        _hopInFlight = false
        _pendingHopJobId = ""
        setHopUiStatus("failed", {
            jobId = attemptJobId,
            failTitle = "Hop timeout",
            failDetail = "Trying next server…",
        })

        if _cfg.auto_hop then
            scheduleAutoHopRetry(0)
        end
    end)
end

function M.ensureTeleportFailHook()
    if _tpFailConn then return end
    _tpFailConn = TeleportService.TeleportInitFailed:Connect(function(player, result, errMsg)
        if LP and player ~= LP then return end

        local failedJob = _pendingHopJobId
        if failedJob == "" then return end

        local kind, ttl = classifyTeleportFail(result, errMsg)

        _hopWatchdogToken += 1
        _hopInFlight = false
        _pendingHopJobId = ""

        markAvoidJob(failedJob, ttl)

        local failTitle, failDetail = describeTeleportFail(result, errMsg)
        setHopUiStatus("failed", {
            jobId = failedJob,
            failTitle = failTitle,
            failDetail = failDetail,
        })

        if _cfg.auto_hop then
            if kind == "busy" then
                _teleportBusyUntil = os.clock() + HOP_BUSY_RETRY_SEC
                scheduleAutoHopRetry(HOP_BUSY_RETRY_SEC)
            else
                scheduleAutoHopRetry(0)
            end
        end
    end)
end

local function countSelectedRarities(map)
    return countSelected(map)
end

local function passesRarityFilter(row)
    local selected = _cfg.filter_rarities
    if countSelectedRarities(selected) <= 0 then
        return true
    end
    local rarity = tostring(row.rarity or "")
    return selected[rarity] == true
end

local function getMinSyncRarityRank()
    for _, name in ipairs({ SYNC_MIN_RARITY, "Rare", "RARE", "rare" }) do
        local r = getRarityRank(name)
        if r > 0 then return r end
    end
    return FALLBACK_RARITY_RANK.rare or 3
end

function M.rebuildDisplayList()
    local rows = {}
    for _, row in ipairs(_lastListRaw or {}) do
        if passesRarityFilter(row) then
            rows[#rows + 1] = row
        end
    end

    table.sort(rows, compareDisplayListRows)

    if LIST_LIMIT > 0 and #rows > LIST_LIMIT then
        local trimmed = {}
        for i = 1, LIST_LIMIT do
            trimmed[i] = rows[i]
        end
        rows = trimmed
    end

    _lastList = rows
end

local function getRequestFn()
    return (syn and syn.request)
        or (http and http.request)
        or http_request
        or (fluxus and fluxus.request)
        or request
end

local function buildHeaders()
    local h = {
        ["Content-Type"] = "application/json",
        ["Accept"] = "application/json",
    }
    if DEFAULT_API_KEY ~= "" then
        h["X-Api-Key"] = DEFAULT_API_KEY
    end
    return h
end

local function apiUrl()
    return tostring(DEFAULT_API_BASE):gsub("/+$", "") .. "/pet_finder_api.php"
end

local function stripNil(tbl)
    local out = {}
    for k, v in pairs(tbl) do
        if v ~= nil then
            out[k] = v
        end
    end
    return out
end

local function syncUrl()
    return apiUrl()
end

local function listUrl()
    return apiUrl()
end

local function gameNow()
    local ok, t = pcall(function()
        return workspace:GetServerTimeNow()
    end)
    if ok and type(t) == "number" then
        return math.floor(t)
    end
    return os.time()
end

local function computeSecondsLeft(row)
    if type(row) ~= "table" then return 0 end
    local expiresAt = tonumber(row.expires_at) or 0
    if expiresAt > 0 then
        return math.max(0, expiresAt - gameNow())
    end
    return math.max(0, math.ceil(tonumber(row.seconds_left) or 0))
end

local function fmtTimeLeft(secondsLeft)
    secondsLeft = math.max(0, math.ceil(tonumber(secondsLeft) or 0))
    if secondsLeft >= 3600 then
        return string.format("%dh %dm", math.floor(secondsLeft / 3600), math.floor((secondsLeft % 3600) / 60))
    end
    if secondsLeft >= 60 then
        return string.format("%dm %ds", math.floor(secondsLeft / 60), secondsLeft % 60)
    end
    return string.format("%ds", secondsLeft)
end

local function fmtPlayerCount(n)
    n = tonumber(n)
    if n == nil then return "" end
    return string.format("%d ply", math.floor(n))
end

local function fmtScannedAgo(row)
    row = type(row) == "table" and row or {}
    local scannedAt = tonumber(row.scanned_at)
    if (not scannedAt or scannedAt <= 0) and row.scanned_ago ~= nil then
        local ago = math.max(0, math.ceil(tonumber(row.scanned_ago) or 0))
        if ago <= 0 then return "" end
        return "scan " .. fmtTimeLeft(ago) .. " ago"
    end
    if not scannedAt or scannedAt <= 0 then
        return ""
    end
    local ago = math.max(0, gameNow() - scannedAt)
    if ago <= 0 then return "scan now" end
    return "scan " .. fmtTimeLeft(ago) .. " ago"
end

local function fmtListMeta(row, secLeft, spawnId, jobShort)
    local parts = {
        string.format("#%s", spawnId),
        fmtTimeLeft(secLeft) .. " left",
    }
    local ply = fmtPlayerCount(row.player_count)
    if ply ~= "" then
        parts[#parts + 1] = ply
    end
    local scanned = fmtScannedAgo(row)
    if scanned ~= "" then
        parts[#parts + 1] = scanned
    end
    parts[#parts + 1] = "srv " .. jobShort .. "…"
    return table.concat(parts, " · ")
end

local function hopMetaFromRow(row)
    row = type(row) == "table" and row or {}
    local secLeft = computeSecondsLeft(row)
    return {
        petName = tostring(row.pet_name or "?"),
        rarity = tostring(row.rarity or "?"),
        jobId = tostring(row.job_id or ""),
        price = tonumber(row.price) or 0,
        timeLeft = secLeft and fmtTimeLeft(secLeft) or "",
        playerCount = tonumber(row.player_count),
        scannedAgo = fmtScannedAgo(row),
    }
end

local function fmtPrice(n)
    n = math.floor(tonumber(n) or 0)
    local negative = n < 0
    local s = tostring(math.abs(n))
    while true do
        local k
        s, k = s:gsub("^(%d+)(%d%d%d)", "%1,%2")
        if k == 0 then break end
    end
    if negative then s = "-" .. s end
    return s
end

local function attr(inst, key, default)
    if not inst then return default end
    local v = inst:GetAttribute(key)
    if v == nil then return default end
    return v
end

local function num(v, default)
    v = tonumber(v)
    if v == nil then return default end
    return v
end

local function str(v, default)
    if v == nil then return default end
    v = tostring(v)
    if v == "" then return default end
    return v
end

local SharedData  = RS:FindFirstChild("SharedData")
local PetTypesMod = SharedData and SharedData:FindFirstChild("PetTypes")
local PetTypes    = PetTypesMod and PetTypesMod:IsA("ModuleScript") and (function()
    local ok, mod = pcall(require, PetTypesMod)
    return ok and mod or nil
end)() or nil

local function extractUuid(refName)
    refName = tostring(refName or "")
    local uuid = refName:match("(%x%x%x%x%x%x%x%x%-%x%x%x%x%-%x%x%x%x%-%x%x%x%x%-%x%x%x%x%x%x%x%x%x%x%x%x)$")
    return uuid or refName
end

local function resolvePetType(raw)
    local SectionBuyPet = getSectionBuyPet()
    if type(SectionBuyPet) == "table" and type(SectionBuyPet.resolvePetTypeRaw) == "function" then
        return SectionBuyPet.resolvePetTypeRaw(raw)
    end
    if raw == nil then return "Normal" end
    if type(raw) == "string" and raw ~= "" then return raw end
    if type(raw) == "number" and PetTypes then
        for name, val in pairs(PetTypes) do
            if val == raw then return name end
        end
    end
    return tostring(raw)
end

local PetSizesCache = nil
local function getPetSizes()
    if PetSizesCache then return PetSizesCache end
    local sd = RS:FindFirstChild("SharedData")
    local ps = sd and sd:FindFirstChild("PetSizes")
    if ps and ps:IsA("ModuleScript") then
        local ok, mod = pcall(require, ps)
        if ok and type(mod) == "table" then PetSizesCache = mod end
    end
    return PetSizesCache
end

local function resolvePetSize(raw)
    if raw == nil then return "Normal" end
    if type(raw) == "string" and raw ~= "" then return raw end
    if type(raw) == "number" then
        local petSizes = getPetSizes()
        if petSizes then
            for name, val in pairs(petSizes) do
                if val == raw then return name end
            end
        end
    end
    return tostring(raw)
end

-- Priority tampilan list: Huge > Big > Rainbow > Normal (lalu rarity, price, expiry)
local TRAIT_LIST_PRIORITY = {
    huge = 3,
    big = 2,
    rainbow = 1,
}

local function traitListPriorityFromRaw(raw, resolver)
    local k = normalizePetKey(resolver(raw))
    return TRAIT_LIST_PRIORITY[k] or 0
end

local function rowTraitListPriority(row)
    if type(row) ~= "table" then return 0 end
    local typeRaw = row.pet_type_raw
    if typeRaw == nil then typeRaw = row.pet_type end
    local sizeRaw = row.pet_size_raw
    if sizeRaw == nil then sizeRaw = row.pet_size end
    return math.max(
        traitListPriorityFromRaw(typeRaw, resolvePetType),
        traitListPriorityFromRaw(sizeRaw, resolvePetSize)
    )
end

compareDisplayListRows = function(a, b)
    local ta = rowTraitListPriority(a)
    local tb = rowTraitListPriority(b)
    if ta ~= tb then return ta > tb end
    local ra = getRarityRank(a.rarity)
    local rb = getRarityRank(b.rarity)
    if ra ~= rb then return ra > rb end
    local pa = tonumber(a.price) or 0
    local pb = tonumber(b.price) or 0
    if pa ~= pb then return pa > pb end
    local ea = tonumber(a.expires_at) or 0
    local eb = tonumber(b.expires_at) or 0
    return ea < eb
end

-- Sync ke API/DB: Rare+ semua; di bawah Rare hanya variant/size non-Normal (NULL di DB = Normal).
local function isNormalTrait(value)
    local v = normalizePetKey(value or "")
    return v == "" or v == "normal"
end

local function syncDbTrait(raw, resolver)
    local resolved = resolver(raw)
    if isNormalTrait(resolved) then return nil end
    return resolved
end

local function syncDbPetType(row)
    if type(row) ~= "table" then return nil end
    local raw = row.pet_type_raw
    if raw == nil then raw = row.pet_type end
    return syncDbTrait(raw, resolvePetType)
end

local function syncDbPetSize(row)
    if type(row) ~= "table" then return nil end
    local raw = row.pet_size_raw
    if raw == nil then raw = row.pet_size end
    return syncDbTrait(raw, resolvePetSize)
end

local function hasNonNormalVariantOrSize(row)
    return syncDbPetType(row) ~= nil or syncDbPetSize(row) ~= nil
end

local function passesSyncRarityFilter(row)
    local minRank = getMinSyncRarityRank()
    local rank = getRarityRank(row and row.rarity)
    if rank >= minRank then
        return true
    end
    return hasNonNormalVariantOrSize(row)
end

local function chipStyleForVariant(name)
    local k = normalizePetKey(name)
    if k == "rainbow" then
        return Color3.fromRGB(120, 55, 190), Color3.fromRGB(250, 230, 255)
    end
    if k == "any" or k == "normal" then
        return Color3.fromRGB(38, 40, 48), Color3.fromRGB(150, 155, 170)
    end
    return Color3.fromRGB(45, 95, 170), Color3.fromRGB(220, 235, 255)
end

local function chipStyleForSize(name)
    local k = normalizePetKey(name)
    if k == "huge" then
        return Color3.fromRGB(210, 130, 20), Color3.fromRGB(255, 245, 210)
    end
    if k == "big" then
        return Color3.fromRGB(35, 110, 210), Color3.fromRGB(220, 240, 255)
    end
    return Color3.fromRGB(38, 40, 48), Color3.fromRGB(150, 155, 170)
end

local function addListTraitChip(parent, text, bg, fg, order)
    local chip = Instance.new("TextLabel")
    chip.Name = "Chip_" .. tostring(text)
    chip.BackgroundColor3 = bg
    chip.BorderSizePixel = 0
    chip.AutomaticSize = Enum.AutomaticSize.X
    chip.Size = UDim2.fromOffset(0, 14)
    chip.Font = Enum.Font.GothamBold
    chip.TextSize = 8
    chip.TextColor3 = fg
    chip.Text = tostring(text):upper()
    chip.LayoutOrder = order
    chip.Parent = parent
    Instance.new("UICorner", chip).CornerRadius = UDim.new(0, 4)

    local chipPad = Instance.new("UIPadding")
    chipPad.PaddingLeft = UDim.new(0, 4)
    chipPad.PaddingRight = UDim.new(0, 4)
    chipPad.Parent = chip

    local chipStroke = Instance.new("UIStroke")
    chipStroke.Color = fg
    chipStroke.Transparency = 0.75
    chipStroke.Thickness = 1
    chipStroke.Parent = chip
end

local function updateListTraitChips(card, row)
    local frame = card.traitChips
    if not frame then return end
    for _, child in ipairs(frame:GetChildren()) do
        if child:IsA("TextLabel") then
            child:Destroy()
        end
    end

    local order = 0
    local pType = syncDbPetType(row)
    if pType then
        order += 1
        local bg, fg = chipStyleForVariant(pType)
        addListTraitChip(frame, pType, bg, fg, order)
    end
    local pSize = syncDbPetSize(row)
    if pSize then
        order += 1
        local bg, fg = chipStyleForSize(pSize)
        addListTraitChip(frame, pSize, bg, fg, order)
    end
    frame.Visible = order > 0
end

local function mapMatchesRowValue(refValue, allowedMap)
    if type(allowedMap) ~= "table" or not next(allowedMap) then return true end
    local canonRef = normalizePetKey(refValue or "Normal")
    if canonRef == "" then canonRef = "normal" end
    for k, v in pairs(allowedMap) do
        if v == true and normalizePetKey(k) == canonRef then return true end
    end
    return false
end

local function petNameMatchesRule(rulePet, rowPetName, aliasLookup)
    rulePet = tostring(rulePet or "")
    rowPetName = tostring(rowPetName or "")
    if rulePet == "" or rowPetName == "" then return false end
    local canonical = resolvePetCanonicalName(rowPetName, aliasLookup)
    if normalizePetKey(rulePet) == normalizePetKey(canonical) then return true end
    return normalizePetKey(rulePet) == normalizePetKey(rowPetName)
end

local function rowHasVariantSizeData(row)
    if type(row) ~= "table" then return false end
    return row.pet_type_raw ~= nil
        or row.pet_size_raw ~= nil
        or row.pet_type ~= nil
        or row.pet_size ~= nil
end

local function rowMatchesBuyPetRule(row, rule, aliasLookup)
    if type(rule) ~= "table" or type(row) ~= "table" then return false end
    if rule.enabled ~= true then return false end
    if not petNameMatchesRule(rule.pet, row.pet_name, aliasLookup) then return false end

    local needsType = type(rule.types) == "table" and next(rule.types)
    local needsSize = type(rule.sizes) == "table" and next(rule.sizes)
    if (needsType or needsSize) and not rowHasVariantSizeData(row) then
        return false
    end

    local SectionBuyPet = getSectionBuyPet()
    local typeRaw = row.pet_type_raw
    if typeRaw == nil then typeRaw = row.pet_type end
    local sizeRaw = row.pet_size_raw
    if sizeRaw == nil then sizeRaw = row.pet_size end

    if type(SectionBuyPet) == "table" and type(SectionBuyPet.variantSizeMatchesRule) == "function" then
        if not SectionBuyPet.variantSizeMatchesRule(
            resolvePetType(typeRaw),
            resolvePetSize(sizeRaw),
            rule.types,
            rule.sizes
        ) then
            return false
        end
    else
        if not mapMatchesRowValue(resolvePetType(typeRaw), rule.types) then return false end
        if not mapMatchesRowValue(resolvePetSize(sizeRaw), rule.sizes) then return false end
    end

    return true
end

local function rowMatchesBuyPetTarget(row, aliasLookup)
    if countEnabledBuyPetTargets() <= 0 then return false end
    local rules = loadBuyPetTargets()
    if #rules == 0 then return false end
    aliasLookup = aliasLookup or buildPetAliasLookup()
    for _, rule in ipairs(rules) do
        if rowMatchesBuyPetRule(row, rule, aliasLookup) then return true end
    end
    return false
end

local function getWildRefFolder()
    local map = workspace:FindFirstChild("Map")
    if not map then return nil end
    local ref = map:FindFirstChild("WildPetRef")
    return (ref and ref:IsA("Folder")) and ref or nil
end

local function getWildSpawnsFolder()
    local map = workspace:FindFirstChild("Map")
    if not map then return nil end
    local spawns = map:FindFirstChild("WildPetSpawns")
    return (spawns and spawns:IsA("Folder")) and spawns or nil
end

local function findSpawnModel(refPart, spawnsFolder)
    if not refPart or not spawnsFolder then return nil end
    local refName = refPart.Name
    local petName = attr(refPart, "PetName", "")
    local expect = "WildPet_" .. tostring(petName) .. "_" .. refName
    local direct = spawnsFolder:FindFirstChild(expect)
    if direct then return direct end
    for _, child in ipairs(spawnsFolder:GetChildren()) do
        if child:IsA("Model") and child.Name:find(refName, 1, true) then
            return child
        end
    end
    return nil
end

local function isOwnedBySelf(ownerUserId)
    return type(ownerUserId) == "number" and ownerUserId == LP.UserId
end

local function isOwnedByOther(ownerUserId)
    if ownerUserId == nil or ownerUserId == 0 then return false end
    if type(ownerUserId) ~= "number" then return false end
    return ownerUserId ~= LP.UserId
end

-- Bisa di-tame: belum ada owner (harga normal) ATAU sudah di-claim orang lain (outbid/steal ~2x).
-- Tidak bisa: sudah milik kamu sendiri.
local function canTameWildPet(ownerUserId)
    if isOwnedBySelf(ownerUserId) then return false end
    return true
end

local function isAvailable(ownerUserId)
    return canTameWildPet(ownerUserId)
end

local function isWildPetAlive(pet, now)
    if type(pet) ~= "table" then return false end
    now = now or gameNow()
    local expiresAt = tonumber(pet.expires_at) or 0
    if expiresAt > 0 and expiresAt <= now then return false end
    return true
end

-- Auto hop: stay selama pet target masih ada di WildPetRef (wandering / taming / jalan ke garden).
-- Beda dengan canTameWildPet — setelah kamu beli, owner = kamu tapi ref masih di map.
local function isWildTargetPresent(pet, aliasLookup, now)
    if not rowMatchesBuyPetTarget(pet, aliasLookup) then return false end
    return isWildPetAlive(pet, now)
end

local function getLocalStayTag(pet)
    if type(pet) ~= "table" then return "" end
    if isOwnedBySelf(pet.owner_user_id) then
        local st = string.lower(tostring(pet.state or ""))
        if st:find("garden", 1, true) or st:find("home", 1, true)
            or st:find("walk", 1, true) or st:find("tame", 1, true)
        then
            return " · going to garden"
        end
        return " · taming"
    end
    if pet.steal == true or pet.owned_by_other == true then
        return " · steal 2x"
    end
    return ""
end

local function buildServerMeta()
    return {
        place_id = game.PlaceId,
        game_id = game.GameId,
        job_id = game.JobId,
        player_count = #Players:GetPlayers(),
        scanned_at = gameNow(),
        reporter_user_id = LP.UserId,
        reporter_name = LP.Name,
    }
end

local function scanOneRef(refPart, spawnsFolder, now)
    local petName = str(attr(refPart, "PetName", nil), nil)
    if not petName then return nil end

    local spawnedAt = num(attr(refPart, "SpawnedAt", nil), nil)
    local lifetime = num(attr(refPart, "Lifetime", nil), nil)
    local expiresAt = (spawnedAt and lifetime) and (spawnedAt + lifetime) or nil
    local secondsLeft = expiresAt and (expiresAt - now) or nil
    local pos = refPart.Position
    local ownerUserId = attr(refPart, "OwnerUserId", nil)
    local spawnModel = findSpawnModel(refPart, spawnsFolder)

    local typeRaw = attr(refPart, "PetType", nil)
    local sizeRaw = attr(refPart, "PetSize", nil)

    return {
        spawn_uuid = extractUuid(refPart.Name),
        ref_name = refPart.Name,
        model_name = spawnModel and spawnModel.Name or nil,
        pet_name = petName,
        rarity = str(attr(refPart, "Rarity", nil), nil),
        pet_type_raw = typeRaw,
        pet_size_raw = sizeRaw,
        pet_type = resolvePetType(typeRaw),
        pet_size = resolvePetSize(sizeRaw),
        price = num(attr(refPart, "Price", nil), nil),
        owner_user_id = ownerUserId,
        owned_by_other = isOwnedByOther(ownerUserId),
        steal = isOwnedByOther(ownerUserId),
        available = canTameWildPet(ownerUserId),
        state = str(attr(refPart, "State", nil), nil),
        spawned_at = spawnedAt,
        lifetime = lifetime,
        expires_at = expiresAt,
        seconds_left = secondsLeft,
        time_left_text = secondsLeft and fmtTimeLeft(secondsLeft) or nil,
        pos_x = math.floor(pos.X * 10 + 0.5) / 10,
        pos_y = math.floor(pos.Y * 10 + 0.5) / 10,
        pos_z = math.floor(pos.Z * 10 + 0.5) / 10,
    }
end

function M.Scan()
    local folder = getWildRefFolder()
    local spawns = getWildSpawnsFolder()
    local now = gameNow()
    local pets = {}

    if not folder then
        _lastScan = {
            ok = false,
            error = "WildPetRef folder not found",
            server = buildServerMeta(),
            pets = {},
            count = 0,
        }
        return _lastScan
    end

    for _, child in ipairs(folder:GetChildren()) do
        if child:IsA("BasePart") then
            local rec = scanOneRef(child, spawns, now)
            if rec then
                pets[#pets + 1] = rec
            end
        end
    end

    table.sort(pets, function(a, b)
        local pa, pb = a.price or 0, b.price or 0
        if pa ~= pb then return pa > pb end
        return tostring(a.pet_name) < tostring(b.pet_name)
    end)

    local availableCount = 0
    for _, p in ipairs(pets) do
        if p.available then availableCount += 1 end
    end

    _lastScan = {
        ok = true,
        server = buildServerMeta(),
        pets = pets,
        count = #pets,
        available_count = availableCount,
    }
    return _lastScan
end

function M.findLocalTargetPets()
    if countBuyPetTargets() <= 0 then
        return {}
    end

    local scan = _lastScan
    if not scan or scan.ok ~= true or type(scan.pets) ~= "table" then
        scan = M.Scan()
    end

    local aliasLookup = buildPetAliasLookup()
    local now = gameNow()
    local found = {}

    for _, pet in ipairs(scan.pets or {}) do
        if isWildTargetPresent(pet, aliasLookup, now) then
            found[#found + 1] = pet
        end
    end

    table.sort(found, function(a, b)
        local ra = getRarityRank(a.rarity)
        local rb = getRarityRank(b.rarity)
        if ra ~= rb then return ra > rb end
        local pa = tonumber(a.price) or 0
        local pb = tonumber(b.price) or 0
        if pa ~= pb then return pa > pb end
        local ea = tonumber(a.expires_at) or 0
        local eb = tonumber(b.expires_at) or 0
        return ea < eb
    end)

    return found
end

function M.hasLocalTargetPet()
    local found = M.findLocalTargetPets()
    if #found > 0 then
        return true, found[1], #found
    end
    return false, nil, 0
end

function M.GetLastScan()
    return _lastScan
end

function M.GetLastList()
    return _lastList
end

function M.GetConfig()
    return {
        filter_rarities = cleanSelectedMap(_cfg.filter_rarities),
        auto_refresh_list = (_cfg.auto_refresh_list == true),
        auto_hop = (_cfg.auto_hop == true),
    }
end

local function rowScannedAt(row)
    row = type(row) == "table" and row or {}
    local scannedAt = tonumber(row.scanned_at)
    if scannedAt and scannedAt > 0 then
        return scannedAt
    end
    local ago = tonumber(row.scanned_ago)
    if ago and ago >= 0 then
        return gameNow() - ago
    end
    return 0
end

local function sortAutoHopRows(a, b)
    -- Race mode: laporan paling baru dulu, baru rarity/price.
    local sa = rowScannedAt(a)
    local sb = rowScannedAt(b)
    if sa ~= sb then return sa > sb end
    local ra = getRarityRank(a.rarity)
    local rb = getRarityRank(b.rarity)
    if ra ~= rb then return ra > rb end
    local pa = tonumber(a.price) or 0
    local pb = tonumber(b.price) or 0
    if pa ~= pb then return pa > pb end
    local ea = tonumber(a.expires_at) or 0
    local eb = tonumber(b.expires_at) or 0
    if ea ~= eb then return ea < eb end
    return tostring(a.job_id or "") < tostring(b.job_id or "")
end

local function refreshHopRarityIndex(rows)
    local extras = {}
    local seen = {}
    for _, row in ipairs(rows or {}) do
        local r = tostring(row.rarity or "")
        if r ~= "" and not seen[r] then
            seen[r] = true
            extras[#extras + 1] = r
        end
    end
    if #extras == 0 then return end
    local PLV = getPetListView()
    if type(PLV) == "table" and type(PLV.refreshRarityIndex) == "function" then
        pcall(PLV.refreshRarityIndex, PLV, extras)
    end
end

local function buildAutoHopCandidates()
    if not _cfg.auto_hop or countBuyPetTargets() <= 0 then
        return {}
    end

    local aliasLookup = buildPetAliasLookup()
    local raw = {}

    for _, row in ipairs(_lastListRaw or {}) do
        if rowMatchesBuyPetTarget(row, aliasLookup) and not isSameServerJob(row.job_id) then
            local expiresAt = tonumber(row.expires_at) or 0
            if expiresAt <= 0 or expiresAt > gameNow() then
                raw[#raw + 1] = row
            end
        end
    end

    if #raw == 0 then
        return {}
    end

    refreshHopRarityIndex(raw)

    local bestByJob = {}
    for _, row in ipairs(raw) do
        local jid = tostring(row.job_id or ""):lower():gsub("%s+", "")
        if jid ~= "" then
            local prev = bestByJob[jid]
            if not prev or sortAutoHopRows(row, prev) then
                bestByJob[jid] = row
            end
        end
    end

    local candidates = {}
    for _, row in pairs(bestByJob) do
        candidates[#candidates + 1] = row
    end
    table.sort(candidates, sortAutoHopRows)

    return candidates
end

function M.buildAutoHopCandidates()
    return buildAutoHopCandidates()
end

function M.pickAutoHopTarget()
    local candidates = buildAutoHopCandidates()
    if #candidates == 0 then
        return nil
    end

    for _, row in ipairs(candidates) do
        if not isAvoidedJob(row.job_id)
            and not isHopBurstTried(row.job_id)
            and canAffordPrice(row.price)
        then
            return row
        end
    end

    if next(_hopBurstTried) ~= nil then
        clearHopBurstTried()
        for _, row in ipairs(candidates) do
            if not isAvoidedJob(row.job_id) and canAffordPrice(row.price) then
                return row
            end
        end
    end
    return nil
end

function M.tryAutoHopToRow(target, forceRetry)
    target = type(target) == "table" and target or nil
    if not target then
        return false, "no_match"
    end

    M.ensureTeleportFailHook()
    if not _cfg.auto_hop then
        return false, "disabled"
    end
    if _hopInFlight then
        return false, "in_flight"
    end
    if os.clock() < (_teleportBusyUntil or 0) then
        return false, "teleport_busy"
    end

    local jobId = tostring(target.job_id or "")
    if not forceRetry
        and jobId == _lastAutoHopJobId
        and (os.clock() - _lastAutoHopAt) < AUTO_HOP_SAME_JOB_SEC
    then
        return false, "recent_same_job"
    end

    markHopBurstTried(jobId)
    _hopInFlight = true
    _lastAutoHopAt = os.clock()
    _lastAutoHopJobId = jobId
    _hopStartedAt = os.clock()
    _hopFromJobId = tostring(game.JobId or "")

    local meta = hopMetaFromRow(target)
    setHopUiStatus("match", meta)

    local ok, err = M.HopToJob(jobId, target.place_id, target.price, meta)
    if not ok then
        _hopWatchdogToken += 1
        _pendingHopJobId = ""
        _hopInFlight = false
        local failTitle, failDetail = describeHopError(err, err)
        setHopUiStatus("failed", {
            petName = meta.petName,
            rarity = meta.rarity,
            jobId = jobId,
            price = meta.price,
            timeLeft = meta.timeLeft,
            failTitle = failTitle,
            failDetail = failDetail,
        })
        if err ~= "insufficient_sheckles" then
            markAvoidJob(jobId, AVOID_JOB_TTL_BUSY)
        end
        return false, err
    end

    setHopUiStatus("teleporting", meta)
    return true, target
end

function M.tryAutoHop(forceRetry)
    M.ensureTeleportFailHook()
    if not _cfg.auto_hop then
        return false, "disabled"
    end
    if _hopInFlight then
        return false, "in_flight"
    end
    if os.clock() < (_teleportBusyUntil or 0) then
        return false, "teleport_busy"
    end
    if countBuyPetTargets() <= 0 then
        return false, "no_target_pets"
    end

    if not forceRetry then
        if HOP_SKIP_PRE_SCAN then
            refreshLocalScanIfNeeded(false)
        else
            M.Scan()
        end
    end
    local hasLocal = M.hasLocalTargetPet()
    if hasLocal then
        return false, "local_target_present"
    end

    if not forceRetry and (os.clock() - _lastAutoHopAt) < AUTO_HOP_COOLDOWN_SEC then
        return false, "cooldown"
    end

    local target = M.pickAutoHopTarget()
    if not target then
        return false, "no_match"
    end

    return M.tryAutoHopToRow(target, forceRetry)
end

function M.tryAutoHopBurst(forceRetry, maxChain)
    M.ensureTeleportFailHook()
    if not _cfg.auto_hop then
        return false, "disabled"
    end
    if _hopInFlight then
        return false, "in_flight"
    end
    if os.clock() < (_teleportBusyUntil or 0) then
        return false, "teleport_busy"
    end
    if countBuyPetTargets() <= 0 then
        return false, "no_target_pets"
    end

    if not forceRetry then
        if HOP_SKIP_PRE_SCAN then
            refreshLocalScanIfNeeded(false)
        else
            M.Scan()
        end
    end
    if M.hasLocalTargetPet() then
        return false, "local_target_present"
    end

    if not forceRetry and (os.clock() - _lastAutoHopAt) < AUTO_HOP_COOLDOWN_SEC then
        return false, "cooldown"
    end

    maxChain = math.max(1, math.floor(tonumber(maxChain) or HOP_BURST_MAX))
    local candidates = buildAutoHopCandidates()
    local tries = 0

    for _, row in ipairs(candidates) do
        if tries >= maxChain then
            break
        end
        local jid = tostring(row.job_id or "")
        if isAvoidedJob(jid) or isHopBurstTried(jid) then
            continue
        end
        if not canAffordPrice(row.price) then
            continue
        end

        tries += 1
        local ok, err = M.tryAutoHopToRow(row, forceRetry or tries > 1)
        if ok then
            return true, row
        end
        if err == "in_flight" or err == "teleport_busy" then
            return false, err
        end
        if err == "insufficient_sheckles" or err == "local_target_present"
            or err == "disabled" or err == "no_target_pets"
        then
            return false, err
        end
        forceRetry = true
    end

    if tries == 0 then
        return false, "no_match"
    end
    return false, "chain_exhausted"
end

local function buildDbPayload(fullPayload)
    local pets = {}
    for _, p in ipairs(fullPayload.pets or {}) do
        if p.spawn_uuid and p.pet_name and p.expires_at and passesSyncRarityFilter(p) then
            local entry = {
                spawn_uuid = p.spawn_uuid,
                pet_name = p.pet_name,
                rarity = p.rarity,
                price = p.price,
                lifetime = p.lifetime,
                expires_at = p.expires_at,
            }
            local dbType = syncDbPetType(p)
            local dbSize = syncDbPetSize(p)
            if dbType then entry.pet_type = dbType end
            if dbSize then entry.pet_size = dbSize end
            pets[#pets + 1] = entry
        end
    end
    return {
        server = fullPayload.server,
        pets = pets,
    }
end

local function buildSyncFingerprint(dbPayload)
    dbPayload = type(dbPayload) == "table" and dbPayload or {}
    local parts = {}
    local server = dbPayload.server or {}
    parts[#parts + 1] = tostring(server.job_id or "")

    local pets = dbPayload.pets or {}
    local sorted = {}
    for _, p in ipairs(pets) do
        sorted[#sorted + 1] = p
    end
    table.sort(sorted, function(a, b)
        return tostring(a.spawn_uuid or "") < tostring(b.spawn_uuid or "")
    end)

    for _, p in ipairs(sorted) do
        parts[#parts + 1] = string.format(
            "%s|%s|%s|%s|%s|%s|%s",
            tostring(p.spawn_uuid or ""),
            tostring(p.pet_name or ""),
            tostring(p.pet_type or ""),
            tostring(p.pet_size or ""),
            tostring(p.rarity or ""),
            tostring(p.price or ""),
            tostring(p.expires_at or "")
        )
    end

    return table.concat(parts, "\n")
end

local function decodeHttpJson(text)
    if type(text) == "table" then
        return text
    end
    if type(text) ~= "string" or text == "" then
        return nil
    end
    local ok, parsed = pcall(function()
        return HttpService:JSONDecode(text)
    end)
    if not ok or type(parsed) ~= "table" then
        return nil
    end
    return parsed
end

local function normalizeApiEnvelope(parsed)
    if type(parsed) ~= "table" then
        return nil
    end
    local success = parsed.success
    if success == nil then
        success = parsed.Success
    end
    local messages = parsed.messages
    if messages == nil then
        messages = parsed.Messages
    end
    local data = parsed.data
    if data == nil then
        data = parsed.Data
    end
    return {
        success = success,
        messages = messages,
        data = data,
    }
end

local function extractApiListRows(env)
    if type(env) ~= "table" then
        return nil, "empty response"
    end
    if env.success == false then
        return nil, tostring(env.messages or "API error")
    end
    local data = env.data
    if data == nil then
        return {}, nil
    end
    if type(data) ~= "table" then
        return nil, "data is not a table"
    end
    if data.ok ~= nil and data[1] == nil then
        return nil, "unexpected sync payload in list"
    end
    return data, nil
end

local function httpPost(url, bodyTbl)
    local reqFn = getRequestFn()
    if not reqFn then
        return false, "HTTP request not supported"
    end

    local okJson, body = pcall(function()
        return HttpService:JSONEncode(bodyTbl)
    end)
    if not okJson then
        return false, "JSON encode failed"
    end

    local ok, res = pcall(function()
        return reqFn({
            Url = url,
            Method = "POST",
            Headers = buildHeaders(),
            Body = body,
        })
    end)
    if not ok then
        return false, tostring(res)
    end

    local status = res.StatusCode or res.status or 0
    local text = res.Body or res.body or ""
    if status < 200 or status >= 300 then
        return false, ("HTTP %s: %s"):format(tostring(status), tostring(text):sub(1, 300))
    end

    local parsed = decodeHttpJson(text)
    if not parsed then
        local preview = tostring(text):gsub("%s+", " "):sub(1, 220)
        if preview:find("Fatal error", 1, true) or preview:find("<b>", 1, true) then
            return false, "PHP error: " .. preview
        end
        return false, "JSON parse failed: " .. preview
    end

    local env = normalizeApiEnvelope(parsed)
    if env and env.success == false then
        return false, tostring(env.messages or "API error")
    end

    return true, env or parsed
end

function M.Sync(payload)
    payload = payload or _lastScan or M.Scan()
    if not payload or not payload.ok then
        _lastSyncOk = false
        _lastSyncMsg = payload and payload.error or "scan failed"
        return false, _lastSyncMsg
    end

    local dbPayload = buildDbPayload(payload)
    local fingerprint = buildSyncFingerprint(dbPayload)
    if fingerprint == _lastSyncFingerprint then
        _lastSyncOk = true
        _lastSyncMsg = "cached (no pet changes)"
        return true, "skipped"
    end

    local ok, result = httpPost(syncUrl(), stripNil({
        action = "sync",
        server = dbPayload.server,
        pets = dbPayload.pets,
    }))
    _lastSyncOk = ok
    if ok then
        _lastSyncFingerprint = fingerprint
        _lastSyncMsg = "OK"
        local data = type(result) == "table" and result.data or nil
        if type(data) == "table" and data.ok ~= nil then
            _lastSyncMsg = string.format("upsert=%s stale=%s", tostring(data.upserted), tostring(data.deleted_stale))
        end
    else
        _lastSyncMsg = tostring(result)
    end
    M._notifyUi()
    return ok, result
end

function M.FetchList(overrideFilters, opts)
    opts = type(opts) == "table" and opts or {}
    local filters = buildListFetchFilters(overrideFilters)

    local ok, result = httpPost(listUrl(), stripNil({
        action = "list",
        place_id = filters.place_id,
        limit = filters.limit,
        pet_names = filters.pet_names,
    }))
    if not ok then
        _lastListErr = tostring(result)
        _lastListRaw = {}
        _lastList = {}
        M._notifyUi()
        return false, result
    end

    local rows, listErr = extractApiListRows(result)
    if rows then
        _lastListRaw = rows
        _lastListErr = ""
        clearHopBurstTried()
        M.rebuildDisplayList()
        if opts.skipAutoHop ~= true then
            M.tryAutoHopBurst(false, HOP_BURST_MAX)
        end
    else
        _lastListRaw = {}
        _lastList = {}
        _lastListErr = tostring(listErr or "invalid response")
    end
    M._notifyUi()
    return true, _lastList
end

function M.HopToJob(jobId, placeId, requiredPrice, hopMeta)
    M.ensureTeleportFailHook()
    hopMeta = type(hopMeta) == "table" and hopMeta or {}
    jobId = tostring(jobId or ""):gsub("%s+", "")
    placeId = tonumber(placeId) or game.PlaceId
    if jobId == "" then
        local t, d = describeHopError("job_id empty", "job_id empty")
        setHopUiStatus("failed", { jobId = jobId, failTitle = t, failDetail = d })
        return false, "job_id empty"
    end
    if isSameServerJob(jobId) then
        local t, d = describeHopError("already on server", "already on server")
        setHopUiStatus("failed", {
            petName = hopMeta.petName,
            rarity = hopMeta.rarity,
            jobId = jobId,
            failTitle = t,
            failDetail = d,
        })
        return false, "already on server"
    end
    if isAvoidedJob(jobId) then
        local t, d = describeHopError("server_avoided", "server_avoided")
        setHopUiStatus("failed", {
            petName = hopMeta.petName,
            rarity = hopMeta.rarity,
            jobId = jobId,
            failTitle = t,
            failDetail = d,
        })
        return false, "server_avoided"
    end
    if not canAffordPrice(requiredPrice) then
        local t, d = describeHopError("insufficient_sheckles", "insufficient_sheckles")
        setHopUiStatus("failed", {
            petName = hopMeta.petName,
            rarity = hopMeta.rarity,
            jobId = jobId,
            price = tonumber(requiredPrice) or 0,
            failTitle = t,
            failDetail = d,
        })
        return false, "insufficient_sheckles"
    end

    local td = {
        __gag2_petfinder = true,
        targetJobId = jobId,
        nonce = tostring(os.time()) .. "_" .. tostring(math.random(100000, 999999)),
    }

    _pendingHopJobId = jobId:lower()
    _hopInFlight = true
    if _hopStartedAt <= 0 then
        _hopStartedAt = os.clock()
        _hopFromJobId = tostring(game.JobId or "")
    end
    setHopUiStatus("teleporting", {
        petName = hopMeta.petName,
        rarity = hopMeta.rarity,
        jobId = jobId,
        price = hopMeta.price or tonumber(requiredPrice) or 0,
        timeLeft = hopMeta.timeLeft,
    })

    local PR = rawget(_G, "PSReconnect") or getG().PSReconnect
    if type(PR) == "table" and type(PR.HopToServer) == "function" then
        prepareForHopTeleport()
        local ok, res = PR.HopToServer(placeId, jobId, td)
        if ok then
            startHopWatchdog(jobId, _hopFromJobId)
            return true, res
        end
        local failTitle, failDetail = describeHopError(tostring(res), tostring(res))
        _hopWatchdogToken += 1
        _pendingHopJobId = ""
        _hopInFlight = false
        setHopUiStatus("failed", {
            petName = hopMeta.petName,
            rarity = hopMeta.rarity,
            jobId = jobId,
            failTitle = failTitle,
            failDetail = failDetail,
        })
        return false, tostring(res)
    end

    local okTp, errTp = invokeHopTeleport(placeId, jobId, td)
    if okTp then
        startHopWatchdog(jobId, _hopFromJobId)
        return true, errTp
    end

    _hopWatchdogToken += 1
    _pendingHopJobId = ""
    _hopInFlight = false
    local failTitle, failDetail = describeHopError(tostring(errTp), tostring(errTp))
    setHopUiStatus("failed", {
        petName = hopMeta.petName,
        rarity = hopMeta.rarity,
        jobId = jobId,
        failTitle = failTitle,
        failDetail = failDetail,
    })
    return false, tostring(errTp)
end

function M.ScanAndSync()
    local payload = M.Scan()
    return M.Sync(payload)
end

function M.StopAutoSync()
    _autoSyncToken += 1
end

function M.StartAutoSync()
    _autoSyncToken += 1
    local token = _autoSyncToken
    task.spawn(function()
        while token == _autoSyncToken do
            M.ScanAndSync()
            task.wait(SYNC_SCAN_INTERVAL_SEC)
        end
    end)
end

function M.StopAutoHopFetch()
    _autoHopFetchToken += 1
end

function M.StartAutoHopFetch()
    M.StopAutoHopFetch()
    if not _cfg.auto_hop then return end
    _autoHopFetchToken += 1
    local token = _autoHopFetchToken
    task.spawn(function()
        while token == _autoHopFetchToken and _cfg.auto_hop do
            M.FetchList(nil, { skipAutoHop = true })
            if not _hopInFlight and os.clock() >= (_teleportBusyUntil or 0) then
                M.tryAutoHopBurst(false, HOP_BURST_MAX)
            end
            task.wait(HOP_FETCH_INTERVAL_SEC)
        end
    end)
    task.spawn(function()
        while token == _autoHopFetchToken and _cfg.auto_hop do
            if not _hopInFlight and os.clock() >= (_teleportBusyUntil or 0) then
                M.tryAutoHop(false)
            end
            task.wait(HOP_FAST_POLL_SEC)
        end
    end)
end

function M.StopAutoRefreshList()
    _autoRefreshToken += 1
end

local function waitWithUiTick(token, intervalSec, shouldRun)
    local t0 = os.clock()
    while token and shouldRun() and (os.clock() - t0) < intervalSec do
        M._notifyUi()
        task.wait(UI_TICK_INTERVAL_SEC)
    end
end

function M.StartAutoRefreshList()
    _autoRefreshToken += 1
    local token = _autoRefreshToken
    task.spawn(function()
        while token == _autoRefreshToken and _cfg.auto_refresh_list do
            if not _cfg.auto_hop then
                M.FetchList(nil, { skipAutoHop = true })
            end
            waitWithUiTick(token, LIST_REFRESH_INTERVAL_SEC, function()
                return token == _autoRefreshToken and _cfg.auto_refresh_list == true
            end)
        end
    end)
end

function M.ApplyConfig(cfg)
    if type(cfg) ~= "table" then return end
    if cfg.filter_rarities ~= nil then
        _cfg.filter_rarities = cleanSelectedMap(cfg.filter_rarities)
    end
    if cfg.auto_refresh_list ~= nil then
        _cfg.auto_refresh_list = (cfg.auto_refresh_list == true)
    end
    if cfg.auto_hop ~= nil then
        _cfg.auto_hop = (cfg.auto_hop == true)
    end

    M.rebuildDisplayList()

    if _cfg.auto_hop then
        M.StartAutoHopFetch()
    else
        M.StopAutoHopFetch()
    end

    if _cfg.auto_refresh_list then
        M.StartAutoRefreshList()
    else
        M.StopAutoRefreshList()
    end
end

function M.SyncFromGlobals()
    local G = getG()
    local MAIN = G.MAIN or rawget(_G, "MAIN")
    local pf = (type(MAIN) == "table" and type(MAIN.misc) == "table" and type(MAIN.misc.pet_finder) == "table")
        and MAIN.misc.pet_finder or {}

    local rarityMap = arrayToMap(pf.filter_rarities)
    if countSelectedRarities(rarityMap) <= 0 and pf.filter_rarity and pf.filter_rarity ~= "" then
        rarityMap = { [tostring(pf.filter_rarity)] = true }
    end
    if countSelectedRarities(rarityMap) <= 0 and type(G.PET_FINDER_FILTER_RARITIES) == "table" then
        rarityMap = arrayToMap(G.PET_FINDER_FILTER_RARITIES)
    end

    M.ApplyConfig({
        filter_rarities = rarityMap,
        auto_refresh_list = pf.auto_refresh_list ~= false,
        auto_hop = pf.auto_hop == true,
    })
end

function M.WriteGlobals(cfg)
    cfg = cfg or M.GetConfig()
    local G = getG()
    local rarityArr = mapToArray(cfg.filter_rarities)
    local payload = {
        filter_rarities = rarityArr,
        auto_refresh_list = (cfg.auto_refresh_list == true),
        auto_hop = (cfg.auto_hop == true),
    }

    local State = G.__GAG2_STATE
    if type(State) == "table" and type(State.patchMisc) == "function" then
        pcall(State.patchMisc, "pet_finder", payload, { noSync = true })
    end

    G.PET_FINDER_FILTER_RARITIES = rarityArr
    G.PET_FINDER_AUTO_REFRESH_LIST = payload.auto_refresh_list
    G.PET_FINDER_AUTO_HOP = payload.auto_hop
    _G.PET_FINDER_FILTER_RARITIES = rarityArr
    _G.PET_FINDER_AUTO_REFRESH_LIST = G.PET_FINDER_AUTO_REFRESH_LIST
    _G.PET_FINDER_AUTO_HOP = G.PET_FINDER_AUTO_HOP

    G.MAIN = G.MAIN or {}
    G.MAIN.misc = G.MAIN.misc or {}
    G.MAIN.misc.pet_finder = payload
    _G.MAIN = G.MAIN
end

local function runUiRefreshers()
    for _, fn in ipairs(_uiRefreshers) do
        pcall(fn)
    end
end

-- Hanya tampilan UI — tidak mempengaruhi tryAutoHop / FetchList / pickAutoHopTarget.
function M._notifyUiHop()
    for _, fn in ipairs(_uiHopRefreshers) do
        pcall(fn)
    end
end

function M._notifyUi(force)
    if #_uiRefreshers == 0 then return end

    if force == true then
        _uiNotifyScheduled = false
        _lastUiNotifyAt = os.clock()
        runUiRefreshers()
        return
    end

    local now = os.clock()
    if (now - _lastUiNotifyAt) >= UI_NOTIFY_MIN_SEC then
        _lastUiNotifyAt = now
        runUiRefreshers()
        return
    end

    if _uiNotifyScheduled then return end
    _uiNotifyScheduled = true
    local delay = UI_NOTIFY_MIN_SEC - (now - _lastUiNotifyAt)
    if delay < 0.05 then delay = 0.05 end
    task.delay(delay, function()
        _uiNotifyScheduled = false
        if #_uiRefreshers == 0 then return end
        _lastUiNotifyAt = os.clock()
        runUiRefreshers()
    end)
end

function M.RegisterUI(ui, STATE, autoSave)
    autoSave = autoSave or function() end
    local G = getG()
    local State = G.__GAG2_STATE
    if type(State) == "table" and type(State.registerFlush) == "function" then
        pcall(State.registerFlush, "pet_finder", function()
            if _uiHydrated then
                M.WriteGlobals(M.GetConfig())
            else
                M.SyncFromGlobals()
            end
        end)
    end

    ui:RegisterSubTab("misc", "petfinder", "Pet Finder", function()
        ui:ClearSubContent()
        _uiRefreshers = {}
        _uiHopRefreshers = {}
        _hopTargetUiFingerprint = ""
        _uiHydrated = true
        M.SyncFromGlobals()

        local cfg = M.GetConfig()

        local function commitCfg(partial)
            local nextCfg = M.GetConfig()
            if type(partial) == "table" then
                for k, v in pairs(partial) do
                    nextCfg[k] = v
                end
            end
            M.ApplyConfig(nextCfg)
            M.WriteGlobals(nextCfg)
            autoSave()
        end

        local bodyHop = ui:CreateSection("Auto Hop", true)

        ui:CreateRowLabel(bodyHop, "Hop targets (from Auto Buy Pet)", nil, 1, "list")

        local hopTargetWrap = Instance.new("Frame")
        hopTargetWrap.Name = "HopBuyTargetList"
        hopTargetWrap.BackgroundTransparency = 1
        hopTargetWrap.Size = UDim2.new(1, 0, 0, 0)
        hopTargetWrap.AutomaticSize = Enum.AutomaticSize.Y
        hopTargetWrap.LayoutOrder = 2
        hopTargetWrap.Parent = bodyHop

        local hopTargetWrapLayout = Instance.new("UIListLayout")
        hopTargetWrapLayout.FillDirection = Enum.FillDirection.Vertical
        hopTargetWrapLayout.SortOrder = Enum.SortOrder.LayoutOrder
        hopTargetWrapLayout.Padding = UDim.new(0, 4)
        hopTargetWrapLayout.Parent = hopTargetWrap

        local hopTargetScroll = Instance.new("Frame")
        hopTargetScroll.Name = "TargetScroll"
        hopTargetScroll.BackgroundColor3 = Color3.fromRGB(10, 10, 12)
        hopTargetScroll.BackgroundTransparency = 0.08
        hopTargetScroll.BorderSizePixel = 0
        hopTargetScroll.Size = UDim2.new(1, 0, 0, 0)
        hopTargetScroll.AutomaticSize = Enum.AutomaticSize.Y
        hopTargetScroll.LayoutOrder = 1
        hopTargetScroll.Parent = hopTargetWrap
        Instance.new("UICorner", hopTargetScroll).CornerRadius = UDim.new(0, 8)

        local hopTargetScrollStroke = Instance.new("UIStroke")
        hopTargetScrollStroke.Color = Color3.fromRGB(42, 42, 48)
        hopTargetScrollStroke.Thickness = 1
        hopTargetScrollStroke.Transparency = 0.35
        hopTargetScrollStroke.Parent = hopTargetScroll

        local hopTargetScrollPad = Instance.new("UIPadding")
        hopTargetScrollPad.PaddingTop = UDim.new(0, 5)
        hopTargetScrollPad.PaddingBottom = UDim.new(0, 5)
        hopTargetScrollPad.PaddingLeft = UDim.new(0, 5)
        hopTargetScrollPad.PaddingRight = UDim.new(0, 5)
        hopTargetScrollPad.Parent = hopTargetScroll

        local hopTargetListLayout = Instance.new("UIListLayout")
        hopTargetListLayout.FillDirection = Enum.FillDirection.Vertical
        hopTargetListLayout.SortOrder = Enum.SortOrder.LayoutOrder
        hopTargetListLayout.Padding = UDim.new(0, 4)
        hopTargetListLayout.Parent = hopTargetScroll

        local hopTargetEmptyLbl = Instance.new("TextLabel")
        hopTargetEmptyLbl.Name = "EmptyHint"
        hopTargetEmptyLbl.BackgroundTransparency = 1
        hopTargetEmptyLbl.Size = UDim2.new(1, 0, 0, 34)
        hopTargetEmptyLbl.Font = Enum.Font.Gotham
        hopTargetEmptyLbl.TextSize = 11
        hopTargetEmptyLbl.TextColor3 = COLOR_MUTED
        hopTargetEmptyLbl.TextXAlignment = Enum.TextXAlignment.Center
        hopTargetEmptyLbl.Text = "No targets — set in Auto → Buy"
        hopTargetEmptyLbl.LayoutOrder = 0
        hopTargetEmptyLbl.Parent = hopTargetScroll

        local hopTargetCards = {}

        local function resolveHopPetIcon(petKey)
            local PLV = getPetListView()
            if type(PLV) == "table" and type(PLV.getPetIcon) == "function" then
                return PLV.getPetIcon(petKey)
            end
            return nil
        end

        local function getBuyPetStore()
            local G = getG()
            return G.__GAG2_BUY_PET or rawget(_G, "__GAG2_BUY_PET") or {}
        end

        local function chipValuesFromMap(map, fallback)
            local arr = mapToArray(map)
            if #arr == 0 then return { fallback or "Any" } end
            table.sort(arr)
            return arr
        end

        local function chipStyleForVariant(name)
            local k = normalizePetKey(name)
            if k == "rainbow" then
                return Color3.fromRGB(120, 55, 190), Color3.fromRGB(250, 230, 255)
            end
            if k == "any" or k == "normal" then
                return Color3.fromRGB(38, 40, 48), Color3.fromRGB(150, 155, 170)
            end
            return Color3.fromRGB(45, 95, 170), Color3.fromRGB(220, 235, 255)
        end

        local function chipStyleForSize(name)
            local k = normalizePetKey(name)
            if k == "huge" then
                return Color3.fromRGB(210, 130, 20), Color3.fromRGB(255, 245, 210)
            end
            if k == "big" then
                return Color3.fromRGB(35, 110, 210), Color3.fromRGB(220, 240, 255)
            end
            return Color3.fromRGB(38, 40, 48), Color3.fromRGB(150, 155, 170)
        end

        local function chipStyleForSteal(name)
            local k = normalizePetKey(name)
            if k == "steal" then
                return Color3.fromRGB(170, 45, 45), Color3.fromRGB(255, 220, 220)
            end
            return Color3.fromRGB(30, 110, 70), Color3.fromRGB(210, 255, 230)
        end

        local function chipStyleForMult()
            return Color3.fromRGB(55, 50, 30), COLOR_ACCENT
        end

        local function chipLabelForVariant(name)
            if normalizePetKey(name) == "any" then return "Any Var" end
            return tostring(name)
        end

        local function chipLabelForSize(name)
            if normalizePetKey(name) == "any" then return "Any Size" end
            return tostring(name)
        end

        local function addHopChip(parent, text, bg, fg, order)
            local chip = Instance.new("TextLabel")
            chip.Name = "Chip_" .. tostring(text)
            chip.BackgroundColor3 = bg
            chip.BorderSizePixel = 0
            chip.AutomaticSize = Enum.AutomaticSize.X
            chip.Size = UDim2.fromOffset(0, 16)
            chip.Font = Enum.Font.GothamBold
            chip.TextSize = 9
            chip.TextColor3 = fg
            chip.Text = tostring(text):upper()
            chip.LayoutOrder = order
            chip.Parent = parent
            Instance.new("UICorner", chip).CornerRadius = UDim.new(0, 4)

            local chipPad = Instance.new("UIPadding")
            chipPad.PaddingLeft = UDim.new(0, 5)
            chipPad.PaddingRight = UDim.new(0, 5)
            chipPad.Parent = chip

            local chipStroke = Instance.new("UIStroke")
            chipStroke.Color = fg
            chipStroke.Transparency = 0.75
            chipStroke.Thickness = 1
            chipStroke.Parent = chip
        end

        local function chipStyleForEnabled(on)
            if on then
                return Color3.fromRGB(30, 110, 70), Color3.fromRGB(210, 255, 230)
            end
            return Color3.fromRGB(45, 45, 50), Color3.fromRGB(130, 130, 140)
        end

        local function stealMetaForRule(rule)
            if rule.steal == true then
                return "Steal", chipStyleForSteal("steal")
            end
            return "Buy", chipStyleForSteal("buy")
        end

        local function destroyHopTargetCards()
            for _, card in ipairs(hopTargetCards) do
                if card and card.Parent then
                    card:Destroy()
                end
            end
            table.clear(hopTargetCards)
        end

        local function buildHopTargetRow(index, rule)
            local isOn = (rule.enabled == true)
            local card = Instance.new("Frame")
            card.Name = "HopBuyTarget_" .. tostring(index)
            card.BackgroundColor3 = isOn and COLOR_CARD or Color3.fromRGB(14, 14, 16)
            card.BackgroundTransparency = isOn and 0 or 0.25
            card.BorderSizePixel = 0
            card.Size = UDim2.new(1, 0, 0, 40)
            card.LayoutOrder = index
            card.Parent = hopTargetScroll
            Instance.new("UICorner", card).CornerRadius = UDim.new(0, 7)

            local cardStroke = Instance.new("UIStroke")
            cardStroke.Color = isOn and Color3.fromRGB(38, 38, 46) or Color3.fromRGB(30, 30, 34)
            cardStroke.Thickness = 1
            cardStroke.Transparency = 0.25
            cardStroke.Parent = card

            local accent = Instance.new("Frame")
            accent.Name = "Accent"
            accent.BackgroundColor3 = isOn and COLOR_ACCENT or Color3.fromRGB(70, 70, 78)
            accent.BorderSizePixel = 0
            accent.Size = UDim2.new(0, 3, 1, -8)
            accent.Position = UDim2.fromOffset(4, 4)
            accent.Parent = card
            Instance.new("UICorner", accent).CornerRadius = UDim.new(1, 0)

            local iconPad = 0
            local iconUrl = resolveHopPetIcon(rule.pet)
            if iconUrl and iconUrl ~= "" then
                iconPad = 22
                local img = Instance.new("ImageLabel")
                img.Name = "PetIcon"
                img.BackgroundTransparency = 1
                img.Size = UDim2.fromOffset(18, 18)
                img.Position = UDim2.new(0, 12, 0.5, -9)
                img.Image = iconUrl
                img.ScaleType = Enum.ScaleType.Fit
                img.Parent = card
            end

            local nameLbl = Instance.new("TextLabel")
            nameLbl.BackgroundTransparency = 1
            nameLbl.Position = UDim2.fromOffset(12 + iconPad, 0)
            nameLbl.Size = UDim2.new(0.42, -12, 1, 0)
            nameLbl.Font = Enum.Font.GothamBold
            nameLbl.TextSize = 11
            nameLbl.TextXAlignment = Enum.TextXAlignment.Left
            nameLbl.TextColor3 = isOn and COLOR_TEXT or COLOR_MUTED
            nameLbl.TextTruncate = Enum.TextTruncate.AtEnd
            nameLbl.Text = tostring(rule.pet or "?")
            nameLbl.Parent = card

            local chips = Instance.new("Frame")
            chips.Name = "Chips"
            chips.BackgroundTransparency = 1
            chips.AnchorPoint = Vector2.new(1, 0.5)
            chips.Position = UDim2.new(1, -6, 0.5, 0)
            chips.Size = UDim2.new(0.56, -8, 0, 16)
            chips.Parent = card

            local chipsLayout = Instance.new("UIListLayout")
            chipsLayout.FillDirection = Enum.FillDirection.Horizontal
            chipsLayout.HorizontalAlignment = Enum.HorizontalAlignment.Right
            chipsLayout.VerticalAlignment = Enum.VerticalAlignment.Center
            chipsLayout.SortOrder = Enum.SortOrder.LayoutOrder
            chipsLayout.Padding = UDim.new(0, 3)
            chipsLayout.Parent = chips

            local chipOrder = 0
            chipOrder += 1
            do
                local bg, fg = chipStyleForEnabled(isOn)
                addHopChip(chips, isOn and "ON" or "OFF", bg, fg, chipOrder)
            end
            for _, variant in ipairs(chipValuesFromMap(rule.types, "Any")) do
                chipOrder += 1
                local bg, fg = chipStyleForVariant(variant)
                addHopChip(chips, chipLabelForVariant(variant), bg, fg, chipOrder)
            end
            for _, sizeName in ipairs(chipValuesFromMap(rule.sizes, "Any")) do
                chipOrder += 1
                local bg, fg = chipStyleForSize(sizeName)
                addHopChip(chips, chipLabelForSize(sizeName), bg, fg, chipOrder)
            end
            chipOrder += 1
            do
                local stealTxt, stealBg, stealFg = stealMetaForRule(rule)
                addHopChip(chips, stealTxt, stealBg, stealFg, chipOrder)
            end
            local maxSteal = tonumber(rule.max_steal or rule.max_steal_mult)
            if maxSteal and maxSteal > 0 then
                chipOrder += 1
                local bg, fg = chipStyleForMult()
                addHopChip(chips, string.format("STEAL ≤%d", math.floor(maxSteal + 0.499)), bg, fg, chipOrder)
            end

            hopTargetCards[#hopTargetCards + 1] = card
        end

        local function refreshHopTargetLabel()
            local SectionBuyPet = getSectionBuyPet()
            local targets = loadBuyPetTargets()
            if type(SectionBuyPet) == "table" and type(SectionBuyPet.normalizeTargets) == "function" then
                targets = SectionBuyPet.normalizeTargets(targets)
            end
            targets = sortBuyPetTargetsByRarity(targets)
            local fp = buyPetTargetsFingerprint(targets)
            if fp == _hopTargetUiFingerprint then return end
            _hopTargetUiFingerprint = fp

            destroyHopTargetCards()
            hopTargetEmptyLbl.Visible = (#targets <= 0)
            for i, rule in ipairs(targets) do
                buildHopTargetRow(i, rule)
            end
        end

        refreshHopTargetLabel()

        ui:CreateRowToggle(bodyHop, "Auto Hop", cfg.auto_hop == true, function(on)
            commitCfg({ auto_hop = (on == true) })
        end, 3)

        local _, hopStatusLbl = ui:CreateRowLabel(bodyHop, "Set buy targets in Auto → Buy, then enable Auto Hop.", nil, 4, "info")

        local bodyList = ui:CreateSection("Pet List", true)

        local rarityRow = ui:CreateRowDropdown(bodyList, {
            label       = "Rarity",
            placeholder = "All Rarities",
            mode        = "multi",
            getItems    = function() return getRarityItems() end,
            initial     = cfg.filter_rarities,
            onChanged   = function(_, selectedMap)
                commitCfg({ filter_rarities = cleanSelectedMap(selectedMap) })
                M._notifyUi()
            end,
        })
        if rarityRow then rarityRow.LayoutOrder = 1 end

        ui:CreateRowToggle(bodyList, "Auto Refresh List", cfg.auto_refresh_list == true, function(on)
            commitCfg({ auto_refresh_list = (on == true) })
        end, 2)

        local _, listStatusLbl = ui:CreateRowLabel(bodyList, "Loading...", nil, 3, "info")

        local listHost = Instance.new("Frame")
        listHost.Name = "PetFinderListHost"
        listHost.BackgroundTransparency = 1
        listHost.Size = UDim2.new(1, 0, 0, 240)
        listHost.LayoutOrder = 4
        listHost.Parent = bodyList

        local listScroll = Instance.new("ScrollingFrame")
        listScroll.Name = "Scroll"
        listScroll.BackgroundColor3 = Color3.fromRGB(10, 10, 12)
        listScroll.BorderSizePixel = 0
        listScroll.Size = UDim2.new(1, 0, 1, 0)
        listScroll.CanvasSize = UDim2.new(0, 0, 0, 0)
        listScroll.ScrollBarThickness = 3
        listScroll.ScrollBarImageColor3 = COLOR_ACCENT
        listScroll.AutomaticCanvasSize = Enum.AutomaticSize.Y
        listScroll.Parent = listHost
        Instance.new("UICorner", listScroll).CornerRadius = UDim.new(0, 10)

        local scrollStroke = Instance.new("UIStroke")
        scrollStroke.Color = Color3.fromRGB(42, 42, 48)
        scrollStroke.Thickness = 1
        scrollStroke.Transparency = 0.35
        scrollStroke.Parent = listScroll

        local listLayout = Instance.new("UIListLayout")
        listLayout.Padding = UDim.new(0, 4)
        listLayout.SortOrder = Enum.SortOrder.LayoutOrder
        listLayout.Parent = listScroll

        local pad = Instance.new("UIPadding")
        pad.PaddingTop = UDim.new(0, 6)
        pad.PaddingBottom = UDim.new(0, 6)
        pad.PaddingLeft = UDim.new(0, 6)
        pad.PaddingRight = UDim.new(0, 6)
        pad.Parent = listScroll

        local cardRows = {}

        local function createCard()
            local frame = Instance.new("Frame")
            frame.BackgroundColor3 = COLOR_CARD
            frame.BorderSizePixel = 0
            frame.Size = UDim2.new(1, -2, 0, 56)
            frame.Parent = listScroll
            Instance.new("UICorner", frame).CornerRadius = UDim.new(0, 7)

            local stroke = Instance.new("UIStroke")
            stroke.Color = Color3.fromRGB(38, 38, 46)
            stroke.Thickness = 1
            stroke.Transparency = 0.25
            stroke.Parent = frame

            local accent = Instance.new("Frame")
            accent.Name = "Accent"
            accent.BackgroundColor3 = COLOR_ACCENT
            accent.BorderSizePixel = 0
            accent.Size = UDim2.new(0, 3, 1, -8)
            accent.Position = UDim2.fromOffset(5, 4)
            accent.Parent = frame
            Instance.new("UICorner", accent).CornerRadius = UDim.new(1, 0)

            local badge = Instance.new("TextLabel")
            badge.Name = "Badge"
            badge.BackgroundColor3 = Color3.fromRGB(30, 30, 36)
            badge.BorderSizePixel = 0
            badge.Position = UDim2.fromOffset(13, 5)
            badge.Size = UDim2.fromOffset(58, 15)
            badge.Font = Enum.Font.GothamBold
            badge.TextSize = 9
            badge.TextColor3 = COLOR_TEXT
            badge.Text = "RARE"
            badge.Parent = frame
            Instance.new("UICorner", badge).CornerRadius = UDim.new(0, 5)

            local badgeStroke = Instance.new("UIStroke")
            badgeStroke.Color = Color3.fromRGB(55, 55, 65)
            badgeStroke.Thickness = 1
            badgeStroke.Transparency = 0.4
            badgeStroke.Parent = badge

            local nameLbl = Instance.new("TextLabel")
            nameLbl.BackgroundTransparency = 1
            nameLbl.Position = UDim2.fromOffset(76, 5)
            nameLbl.Size = UDim2.new(1, -172, 0, 15)
            nameLbl.Font = Enum.Font.GothamBold
            nameLbl.TextSize = 11
            nameLbl.TextXAlignment = Enum.TextXAlignment.Left
            nameLbl.TextColor3 = COLOR_TEXT
            nameLbl.TextTruncate = Enum.TextTruncate.AtEnd
            nameLbl.Parent = frame

            local traitChips = Instance.new("Frame")
            traitChips.Name = "TraitChips"
            traitChips.BackgroundTransparency = 1
            traitChips.Position = UDim2.fromOffset(76, 22)
            traitChips.Size = UDim2.new(1, -130, 0, 14)
            traitChips.Visible = false
            traitChips.Parent = frame

            local traitLayout = Instance.new("UIListLayout")
            traitLayout.FillDirection = Enum.FillDirection.Horizontal
            traitLayout.HorizontalAlignment = Enum.HorizontalAlignment.Left
            traitLayout.VerticalAlignment = Enum.VerticalAlignment.Center
            traitLayout.SortOrder = Enum.SortOrder.LayoutOrder
            traitLayout.Padding = UDim.new(0, 3)
            traitLayout.Parent = traitChips

            local priceLbl = Instance.new("TextLabel")
            priceLbl.BackgroundTransparency = 1
            priceLbl.AnchorPoint = Vector2.new(1, 0)
            priceLbl.Position = UDim2.new(1, -62, 0, 5)
            priceLbl.Size = UDim2.fromOffset(78, 15)
            priceLbl.Font = Enum.Font.GothamMedium
            priceLbl.TextSize = 10
            priceLbl.TextXAlignment = Enum.TextXAlignment.Right
            priceLbl.TextColor3 = COLOR_ACCENT
            priceLbl.Parent = frame

            local metaLbl = Instance.new("TextLabel")
            metaLbl.BackgroundTransparency = 1
            metaLbl.Position = UDim2.fromOffset(13, 38)
            metaLbl.Size = UDim2.new(1, -72, 0, 14)
            metaLbl.Font = Enum.Font.Gotham
            metaLbl.TextSize = 9
            metaLbl.TextXAlignment = Enum.TextXAlignment.Left
            metaLbl.TextTruncate = Enum.TextTruncate.AtEnd
            metaLbl.TextColor3 = COLOR_MUTED
            metaLbl.Parent = frame

            local hopBtn = Instance.new("TextButton")
            hopBtn.BackgroundColor3 = COLOR_ACCENT
            hopBtn.BorderSizePixel = 0
            hopBtn.AnchorPoint = Vector2.new(1, 0.5)
            hopBtn.Position = UDim2.new(1, -6, 0.5, 0)
            hopBtn.Size = UDim2.fromOffset(50, 24)
            hopBtn.Font = Enum.Font.GothamBold
            hopBtn.TextSize = 9
            hopBtn.TextColor3 = Color3.fromRGB(12, 12, 12)
            hopBtn.Text = "Hop"
            hopBtn.AutoButtonColor = false
            hopBtn.Parent = frame
            Instance.new("UICorner", hopBtn).CornerRadius = UDim.new(0, 6)

            local card = {
                frame = frame,
                accent = accent,
                badge = badge,
                nameLbl = nameLbl,
                traitChips = traitChips,
                priceLbl = priceLbl,
                metaLbl = metaLbl,
                hopBtn = hopBtn,
                _jobId = "",
                _placeId = game.PlaceId,
                _price = 0,
            }

            hopBtn.MouseButton1Click:Connect(function()
                if card._jobId:lower() == tostring(game.JobId):lower() then
                    return
                end
                local meta = {
                    petName = card._petName or card.nameLbl.Text,
                    rarity = card._rarity or "?",
                    jobId = card._jobId,
                    price = card._price,
                    timeLeft = "",
                }
                setHopUiStatus("match", meta)
                M.HopToJob(card._jobId, card._placeId, card._price, meta)
            end)

            return card
        end

        local function rowListRenderKey(row)
            row = type(row) == "table" and row or {}
            return table.concat({
                tostring(row.job_id or ""),
                tostring(row.pet_name or ""),
                tostring(row.rarity or ""),
                tostring(row.price or ""),
                tostring(row.pet_type_raw or row.pet_type or ""),
                tostring(row.pet_size_raw or row.pet_size or ""),
                tostring(row.spawn_uuid or ""),
            }, "\31")
        end

        local function renderList()
            local rows = _lastList or {}
            for i, row in ipairs(rows) do
                local card = cardRows[i]
                if not card then
                    card = createCard()
                    cardRows[i] = card
                end

                local rarity = tostring(row.rarity or "Unknown")
                local rarityColor = getRarityColor(rarity)
                local secLeft = computeSecondsLeft(row)
                local spawnId = shortSpawnId(row.spawn_uuid)
                local jobShort = tostring(row.job_id or "?"):sub(1, 8)
                local renderKey = rowListRenderKey(row)

                card._jobId = tostring(row.job_id or "")
                card._placeId = tonumber(row.place_id) or game.PlaceId
                card._price = tonumber(row.price) or 0
                card._petName = tostring(row.pet_name or "?")
                card._rarity = rarity
                local sameServer = card._jobId:lower() == tostring(game.JobId):lower()
                local affordable = canAffordPrice(card._price)
                card.frame.Visible = true
                card.frame.LayoutOrder = i

                if card._renderKey ~= renderKey then
                    card._renderKey = renderKey
                    card.accent.BackgroundColor3 = rarityColor
                    card.badge.Text = rarity:upper()
                    card.badge.TextColor3 = rarityColor
                    card.nameLbl.Text = tostring(row.pet_name or "?")
                    card.priceLbl.Text = fmtPrice(row.price)
                    updateListTraitChips(card, row)
                end

                card.metaLbl.Text = fmtListMeta(row, secLeft, spawnId, jobShort)
                card.hopBtn.Text = sameServer and "Here" or (affordable and "Hop" or "Poor")
                card.hopBtn.BackgroundColor3 = sameServer and Color3.fromRGB(55, 58, 68)
                    or (affordable and COLOR_ACCENT or Color3.fromRGB(55, 58, 68))
                card.hopBtn.TextColor3 = sameServer and COLOR_MUTED
                    or (affordable and Color3.fromRGB(12, 12, 12) or COLOR_MUTED)
                card.hopBtn.Active = not sameServer and affordable
                card.hopBtn.AutoButtonColor = false
            end

            for i = #rows + 1, #cardRows do
                if cardRows[i] and cardRows[i].frame then
                    cardRows[i].frame.Visible = false
                end
            end
        end

        local function formatMatchStatus(target)
            if not target then return nil end
            local meta = hopMetaFromRow(target)
            local priceTxt = meta.price > 0 and fmtPrice(meta.price) or "?"
            local parts = {
                string.format("Match: %s (%s)", meta.petName, meta.rarity),
                priceTxt,
            }
            if meta.timeLeft ~= "" then
                parts[#parts + 1] = meta.timeLeft .. " left"
            end
            if meta.playerCount ~= nil then
                parts[#parts + 1] = tostring(math.floor(meta.playerCount)) .. " ply"
            end
            if meta.scannedAgo ~= nil and meta.scannedAgo ~= "" then
                parts[#parts + 1] = meta.scannedAgo
            end
            parts[#parts + 1] = "srv " .. shortJobId(meta.jobId)
            return table.concat(parts, " · ")
        end

        local cachedHopPickTarget = nil
        local lastHopPickAt = 0

        local function refreshHopStatus()
            if not hopStatusLbl or not hopStatusLbl.Parent then return end
            refreshHopTargetLabel()
            local liveCfg = M.GetConfig()
            if liveCfg.auto_hop ~= true then
                hopStatusLbl.Text = "Set buy targets in Auto → Buy, then enable Auto Hop."
                hopStatusLbl.TextColor3 = COLOR_MUTED
                return
            end
            if countEnabledBuyPetTargets() <= 0 then
                hopStatusLbl.Text = "Auto Hop ON — enable at least one pet in Auto → Buy."
                hopStatusLbl.TextColor3 = COLOR_ACCENT
                return
            end

            local hasLocal, localPet, localCount = M.hasLocalTargetPet()
            if hasLocal and localPet then
                local extra = (localCount or 1) > 1 and (" +" .. tostring(localCount - 1)) or ""
                local stayTag = getLocalStayTag(localPet)
                hopStatusLbl.Text = string.format(
                    "Stay — %s%s on this server (%s left)%s",
                    tostring(localPet.pet_name or "?"),
                    extra,
                    fmtTimeLeft(computeSecondsLeft(localPet)),
                    stayTag
                )
                hopStatusLbl.TextColor3 = Color3.fromRGB(255, 211, 0)
                return
            end

            local now = os.clock()
            local hopUi = M.GetHopUiStatus()
            local failAge = now - (tonumber(hopUi.updatedAt) or 0)
            if hopUi.phase == "failed" and failAge < HOP_FAIL_SHOW_SEC then
                local petPart = hopUi.petName ~= "" and (hopUi.petName .. " · ") or ""
                local detail = tostring(hopUi.failDetail or ""):gsub("%s+", " "):sub(1, 72)
                local retryTxt = liveCfg.auto_hop and " · retrying…" or ""
                hopStatusLbl.Text = string.format(
                    "Hop failed: %s%s%s%s",
                    petPart,
                    tostring(hopUi.failTitle or "Error"),
                    detail ~= "" and (" — " .. detail) or "",
                    retryTxt
                )
                hopStatusLbl.TextColor3 = COLOR_ACCENT
                return
            end

            if hopUi.phase == "teleporting" or _hopInFlight then
                local petPart = hopUi.petName ~= "" and hopUi.petName or "target pet"
                local rarityPart = hopUi.rarity ~= "" and (" (" .. hopUi.rarity .. ")") or ""
                local srvPart = hopUi.jobId ~= "" and (" · srv " .. shortJobId(hopUi.jobId)) or ""
                local hopAge = now - (_hopStartedAt or 0)
                local statusWord = hopAge >= 4 and "Waiting Roblox" or "Attempting hop"
                hopStatusLbl.Text = string.format("%s → %s%s%s…", statusWord, petPart, rarityPart, srvPart)
                hopStatusLbl.TextColor3 = Color3.fromRGB(120, 200, 255)
                return
            end

            if hopUi.phase == "match" and hopUi.petName ~= "" and failAge < 8 then
                local priceTxt = hopUi.price > 0 and fmtPrice(hopUi.price) or "?"
                hopStatusLbl.Text = string.format(
                    "Match: %s (%s) · %s · srv %s · hopping…",
                    hopUi.petName,
                    hopUi.rarity ~= "" and hopUi.rarity or "?",
                    priceTxt,
                    shortJobId(hopUi.jobId)
                )
                hopStatusLbl.TextColor3 = Color3.fromRGB(120, 255, 175)
                return
            end

            if (now - lastHopPickAt) >= 1 then
                lastHopPickAt = now
                cachedHopPickTarget = M.pickAutoHopTarget()
            end
            if cachedHopPickTarget then
                hopStatusLbl.Text = formatMatchStatus(cachedHopPickTarget) .. " · hop ready (highest rarity first)"
                hopStatusLbl.TextColor3 = Color3.fromRGB(120, 255, 175)
            else
                hopStatusLbl.Text = "Auto Hop ON — scanning for buy targets..."
                hopStatusLbl.TextColor3 = Color3.fromRGB(120, 255, 175)
            end
        end

        local function refreshStatus()
            if not listStatusLbl or not listStatusLbl.Parent then return end
            if _lastListErr ~= "" then
                listStatusLbl.Text = "Error: " .. tostring(_lastListErr):sub(1, 120)
                listStatusLbl.TextColor3 = COLOR_ACCENT
            else
                local totalRaw = #(_lastListRaw or {})
                local shown = #(_lastList or {})
                if shown ~= totalRaw then
                    listStatusLbl.Text = string.format("%d pet(s) By Rarity", shown)
                else
                    listStatusLbl.Text = string.format("%d pet(s) found", shown)
                end
                listStatusLbl.TextColor3 = Color3.fromRGB(120, 255, 175)
            end
            renderList()
            refreshHopStatus()
        end

        table.insert(_uiRefreshers, refreshStatus)
        table.insert(_uiHopRefreshers, refreshHopStatus)

        refreshHopTargetLabel()

        task.spawn(function()
            M.FetchList(nil, { skipAutoHop = not _cfg.auto_hop })
            refreshStatus()
        end)

        task.spawn(function()
            while bodyList and bodyList.Parent do
                pcall(refreshStatus)
                task.wait(UI_TICK_INTERVAL_SEC)
            end
            _uiRefreshers = {}
            _uiHopRefreshers = {}
            _hopTargetUiFingerprint = ""
        end)

        refreshStatus()
    end, 3)
end

M.SyncFromGlobals()
M.ensureTeleportFailHook()
M.StartAutoSync()
if _cfg.auto_hop then
    M.StartAutoHopFetch()
end
if _cfg.auto_refresh_list then
    M.StartAutoRefreshList()
end

return M
 end,                      required = false },
    { key = "MiscTabs",                name = "Misc Tabs",               factory = function() -- tabs_misc.lua — Grow A Garden 2
-- Main tab: MISC → sub tab: Rejoin (+ Auto Update Server)

local M = {}

function M.Register(ui, STATE)
    STATE = rawget(_G, "STATE") or STATE or {}
    local G = (getgenv and getgenv()) or _G
    G.STATE = STATE
    local State = G.__GAG2_STATE

    local function saveNow()
        if G.__GAG2_RESETTING == true then return end
        if type(State) == "table" and type(State.saveFromUi) == "function" then
            pcall(State.saveFromUi)
            return
        end
        if ui and type(ui.SaveState) == "function" then
            pcall(function() ui:SaveState() end)
        end
    end

    local function getMisc(key)
        if type(State) == "table" and type(State.getMisc) == "function" then
            local ok, result = pcall(State.getMisc, key)
            if ok and type(result) == "table" then return result end
        end
        local m = G.MAIN or rawget(_G, "MAIN")
        if type(m) == "table" and type(m.misc) == "table" then
            return m.misc[key] or {}
        end
        return {}
    end

    local function patchMisc(key, partial, syncFnOrOpts)
        local syncFn = nil
        local opts = nil
        if type(syncFnOrOpts) == "function" then
            syncFn = syncFnOrOpts
        elseif type(syncFnOrOpts) == "table" then
            opts = syncFnOrOpts
        end

        if type(State) == "table" and type(State.patchMisc) == "function" then
            pcall(State.patchMisc, key, partial, opts or {})
        else
            local m = G.MAIN or rawget(_G, "MAIN")
            if type(m) == "table" and type(partial) == "table" then
                m.misc = m.misc or {}
                local cur = type(m.misc[key]) == "table" and m.misc[key] or {}
                for k, v in pairs(partial) do
                    if type(v) == "table" and type(cur[k]) == "table" and v[1] == nil then
                        for sk, sv in pairs(v) do cur[k][sk] = sv end
                    else
                        cur[k] = v
                    end
                end
                m.misc[key] = cur
                G.MAIN = m
                _G.MAIN = m
            end
        end
        if syncFn then pcall(syncFn) end
        -- noSync/noSave: flush path inside State.saveFromUi — must not re-enter saveNow
        local skipSave = opts and (opts.noSync == true or opts.noSave == true)
        if not skipSave then
            saveNow()
        end
    end

    local function registerFlush(id, fn)
        if type(State) == "table" and type(State.registerFlush) == "function" then
            pcall(State.registerFlush, id, fn)
        end
    end

    local function unregisterFlush(id)
        if type(State) == "table" and type(State.unregisterFlush) == "function" then
            pcall(State.unregisterFlush, id)
        end
    end

    local function autoSave()
        saveNow()
    end

    G.__GAG2_AUTO_SAVE = autoSave
    G.__GAG2_PERSIST_STATE = saveNow
    _G.__GAG2_PERSIST_STATE = saveNow

    ui:RegisterMainTab("misc", "MISC", 2)

    ui:RegisterSubTab("misc", "rejoin", "Rejoin", function()
        ui:ClearSubContent()

        local sectionSetters = {}
        local function createSection(title, defaultOpen)
            local body, setExpanded = ui:CreateSection(title, defaultOpen or false)
            table.insert(sectionSetters, setExpanded)
            return body
        end

        local body1 = createSection("Auto Reconnect / Rejoin", true)

        local function syncReconnectModule()
            pcall(function()
                local R = _G.PSReconnect
                local on = (AUTO_RECONNECT_ENABLED == true)
                if R and type(R.SetEnabled) == "function" then
                    R.SetEnabled(on)
                elseif R and type(R.setEnabled) == "function" then
                    R.setEnabled(on)
                end
            end)
        end

        ui:CreateRowToggle(body1, "Auto Exec", AUTO_START_ON_REJOIN == true, function(on)
            patchMisc("rejoin", { auto_exec = (on == true) }, function()
                task.defer(function()
                    if _G.PSReconnect and _G.PSReconnect.DebugPrint then
                        _G.PSReconnect:DebugPrint()
                    end
                end)
            end)
        end)

        ui:CreateRowToggle(body1, "Auto Reconnect", AUTO_RECONNECT_ENABLED == true, function(on)
            patchMisc("rejoin", { auto_reconnect = (on == true) }, syncReconnectModule)
        end)

        ui:CreateRowToggle(body1, "Rejoin Now", false, function(on)
            if on ~= true then return end
            local R = _G.PSReconnect or (getgenv and getgenv().PSReconnect)
            if not R or type(R.RejoinNow) ~= "function" then
                warn("[GAG2] PSReconnect tidak tersedia")
                return
            end
            R:DebugPrint()
            local ok, err = R:RejoinNow()
            if ok ~= true then
                warn("[GAG2] Rejoin Now gagal:", tostring(err))
            else
                warn("[GAG2] Rejoin Now — teleport dikirim")
            end
        end)

        ----------------------------------------------------------------
        -- Auto Update Server (reserver)
        ----------------------------------------------------------------
        local envUNS = (getgenv and getgenv()) or _G

        local function peekUpdateNewServerCfg()
            local readFn = rawget(_G, "readUpdateNewServerGlobals") or rawget(envUNS, "readUpdateNewServerGlobals")
            if type(readFn) == "function" then
                return readFn()
            end
            return false, 30
        end

        local function setUpdateNewServerCfg(enabled, minute)
            local writeFn = rawget(_G, "writeUpdateNewServerGlobals") or rawget(envUNS, "writeUpdateNewServerGlobals")
            if type(writeFn) == "function" then
                writeFn(enabled, minute)
            end
        end

        local bodyReserve = createSection("Auto Update Server", false)

        local unsEnabled, unsMinute = peekUpdateNewServerCfg()

        local function syncUpdateNewServerModule()
            local applyFn = rawget(_G, "applyUpdateNewServerModule") or rawget(envUNS, "applyUpdateNewServerModule")
            if type(applyFn) == "function" then
                pcall(applyFn, unsEnabled, unsMinute)
            end
        end

        local function commitUpdateNewServerCfg()
            setUpdateNewServerCfg(unsEnabled, unsMinute)
            syncUpdateNewServerModule()
            patchMisc("rejoin", {
                update_new_server = (unsEnabled == true),
                update_new_server_minute = unsMinute,
            })
        end

        local _, jobIdLbl = ui:CreateRowLabel(bodyReserve, "Job ID: " .. tostring(game.JobId or "-"), nil, nil, "info")
        local _, timerLbl = ui:CreateRowLabel(bodyReserve, "Next update: --:--", nil, nil, "accent")

        task.spawn(function()
            while bodyReserve and bodyReserve.Parent do
                pcall(function()
                    if jobIdLbl and jobIdLbl.Parent then
                        jobIdLbl.Text = "Job ID: " .. tostring(game.JobId or "-")
                    end

                    local remainText = "Next update: --:--"
                    local UNS = rawget(_G, "UpdateNewServer") or rawget(envUNS, "UpdateNewServer")
                    if UNS and type(UNS.GetInfo) == "function" then
                        local ok, info = pcall(function()
                            return UNS:GetInfo()
                        end)
                        if ok and type(info) == "table" then
                            if info.enabled ~= true then
                                remainText = "Next update: (off)"
                            elseif type(info.remainFmt) == "string" then
                                remainText = "Next update: " .. info.remainFmt
                            else
                                local r = math.max(0, math.floor(tonumber(info.remainSec) or 0))
                                remainText = string.format(
                                    "Next update: %02d:%02d",
                                    math.floor(r / 60),
                                    r % 60
                                )
                            end
                        end
                    end

                    if timerLbl and timerLbl.Parent then
                        timerLbl.Text = remainText
                    end
                end)
                task.wait(1)
            end
        end)

        local _, setMinuteInput = ui:CreateRowInput(bodyReserve, "Interval (Minute)", tostring(unsMinute), function(text)
            text = tostring(text or ""):gsub("%s+", "")
            if text == "" then return end

            local v = tonumber(text)
            if not v then
                warn("[UpdateNewServer] Interval minute tidak valid: " .. tostring(text))
                return
            end

            v = math.floor(v + 0.5)
            if v < 1 then v = 1 end
            if v > 300 then v = 300 end

            unsMinute = v
            commitUpdateNewServerCfg()
        end)

        ui:CreateRowToggle(bodyReserve, "Auto Update Server", unsEnabled == true, function(on)
            unsEnabled = (on == true)
            commitUpdateNewServerCfg()
        end)

        pcall(function()
            local en, mi = peekUpdateNewServerCfg()
            unsEnabled = (en == true)
            unsMinute = mi
            if type(setMinuteInput) == "function" then
                setMinuteInput(tostring(mi))
            end
        end)

        bodyReserve.Destroying:Connect(function()
            if type(setMinuteInput) == "function" then
                local txt = tostring(setMinuteInput() or ""):gsub("%s+", "")
                local v = tonumber(txt)
                if v then
                    v = math.floor(v + 0.5)
                    if v < 1 then v = 1 end
                    if v > 300 then v = 300 end
                    unsMinute = v
                end
            end
            commitUpdateNewServerCfg()
        end)

        ----------------------------------------------------------------
        -- Auto Hop Server (same pattern as Auto Update Server)
        ----------------------------------------------------------------
        local bodyHop = createSection("Auto Hop Server", false)

        local function peekAutoHopCfg()
            local readFn = rawget(_G, "readAutoHopGlobals") or rawget(G, "readAutoHopGlobals")
            if type(readFn) == "function" then
                return readFn()
            end
            return false, 1, 1, 10
        end

        local function setAutoHopCfg(enabled, current, max, delay)
            local writeFn = rawget(_G, "writeAutoHopGlobals") or rawget(G, "writeAutoHopGlobals")
            if type(writeFn) == "function" then
                writeFn(enabled, current, max, delay)
            end
        end

        local hopEnabled, hopCurrent, hopMax, hopDelay = peekAutoHopCfg()

        local function getAutoHop()
            return G.AutoHopServer or _G.AutoHopServer or G.AutoHopServerModule or _G.AutoHopServerModule
        end

        local function syncAutoHopModule(forced)
            local applyFn = rawget(_G, "applyAutoHopModule") or rawget(G, "applyAutoHopModule")
            if type(applyFn) ~= "function" then return end
            if forced == true then
                pcall(applyFn, hopEnabled, hopCurrent, hopMax, hopDelay)
            else
                pcall(applyFn)
            end
        end

        local commitHopCurrent
        local commitHopMax
        local commitHopDelay
        local setHopCurrentInput
        local setHopMaxInput
        local setHopDelayInput

        local function readHopInputInt(getFn, minV, maxV, fallback)
            if type(getFn) ~= "function" then return fallback end
            local v = tonumber((tostring(getFn() or ""):gsub("%s+", "")))
            if not v then return fallback end
            v = math.floor(v + 0.5)
            if minV then v = math.max(minV, v) end
            if maxV then v = math.min(maxV, v) end
            return v
        end

        local function flushHopInputsFromUI()
            if type(commitHopCurrent) == "function" then pcall(commitHopCurrent) end
            if type(commitHopMax) == "function" then pcall(commitHopMax) end
            if type(commitHopDelay) == "function" then pcall(commitHopDelay) end
            hopCurrent = readHopInputInt(setHopCurrentInput, 1, 100, hopCurrent)
            hopMax = readHopInputInt(setHopMaxInput, 1, 100, hopMax)
            hopDelay = readHopInputInt(setHopDelayInput, 10, 600, hopDelay)
        end

        local function commitAutoHopCfg()
            flushHopInputsFromUI()
            setAutoHopCfg(hopEnabled, hopCurrent, hopMax, hopDelay)
            syncAutoHopModule(true)
            patchMisc("rejoin", {
                auto_hop = {
                    enabled = (hopEnabled == true),
                    current_player = hopCurrent,
                    max_player = hopMax,
                    teleport_delay = hopDelay,
                },
            })
        end

        local _, hopJobLbl = ui:CreateRowLabel(bodyHop, "Job ID: " .. tostring(game.JobId or "-"), nil, nil, "info")
        local _, hopStatusLbl = ui:CreateRowLabel(bodyHop, "Status: idle", nil, nil, "accent")

        task.spawn(function()
            while bodyHop and bodyHop.Parent do
                pcall(function()
                    if hopJobLbl and hopJobLbl.Parent then
                        hopJobLbl.Text = "Job ID: " .. tostring(game.JobId or "-")
                    end
                    if hopStatusLbl and hopStatusLbl.Parent then
                        local txt = "Status: off"
                        if hopEnabled == true then
                            local playerCount = #game:GetService("Players"):GetPlayers()
                            local AH = getAutoHop()
                            if type(AH) == "table" and type(AH.GetStatus) == "function" then
                                local ok, st = pcall(AH.GetStatus, AH)
                                if ok and type(st) == "table" then
                                    playerCount = tonumber(st.playerCount) or playerCount
                                    if st.inFlight == true then
                                        txt = "Status: teleporting..."
                                    elseif st.sessionActive == true then
                                        txt = "Status: hopping (" .. tostring(st.candidateCount or 0) .. " servers)"
                                    elseif (tonumber(st.delayRemaining) or 0) > 0 then
                                        txt = ("Status: delay %ds before hop (cfg %ds)"):format(
                                            tonumber(st.delayRemaining) or 0,
                                            tonumber(st.teleportDelay) or hopDelay or 0
                                        )
                                    else
                                        local modeTxt = ""
                                        if st.hopMode == "leave_crowded" then
                                            modeTxt = " [crowded->quiet " .. tostring(st.sortPrimary or "Asc") .. "]"
                                        elseif st.hopMode == "leave_quiet" then
                                            modeTxt = " [quiet->busy " .. tostring(st.sortPrimary or "Desc") .. "]"
                                        elseif type(st.sortOrder) == "string" then
                                            modeTxt = " [" .. st.sortOrder .. "]"
                                        end
                                        if st.joinableHint then
                                            modeTxt = modeTxt .. " " .. tostring(st.joinableHint)
                                        end
                                        if st.lastError and st.lastError ~= "" and st.sessionActive ~= true then
                                            txt = "Status: " .. tostring(st.lastError) .. modeTxt
                                        elseif type(st.status) == "string" and st.status ~= "idle" then
                                            txt = "Status: " .. tostring(st.status) .. modeTxt
                                        else
                                            local scanTxt = ""
                                            if (tonumber(st.scanPages) or 0) > 0 then
                                                scanTxt = (" [scan %d pages, %d servers]"):format(
                                                    tonumber(st.scanPages) or 0,
                                                    tonumber(st.scanServers) or 0
                                                )
                                            end
                                            txt = ("Status: %s (target %d players)%s"):format(
                                                tostring(st.triggerHint or "Searching"),
                                                hopMax,
                                                scanTxt
                                            )
                                        end
                                    end
                                end
                            elseif type(AH) == "table" and type(AH.IsRunning) == "function" then
                                local ok, running = pcall(AH.IsRunning, AH)
                                if running and playerCount >= hopCurrent then
                                    txt = "Status: searching ~" .. tostring(hopMax) .. " players"
                                elseif playerCount >= hopCurrent then
                                    txt = "Status: ready to hop"
                                else
                                    txt = ("Status: waiting %d/%d players"):format(playerCount, hopCurrent)
                                end
                            else
                                txt = ("Status: on (%d/%d players)"):format(playerCount, hopCurrent)
                            end
                        end
                        hopStatusLbl.Text = txt
                    end
                end)
                task.wait(1)
            end
        end)

        _, setHopCurrentInput, commitHopCurrent = ui:CreateRowInput(bodyHop, "Current Player Max", tostring(hopCurrent), function(text)
            text = tostring(text or ""):gsub("%s+", "")
            if text == "" then return end
            if text:find("/") then
                local a, b = text:match("^(%d+)%s*/%s*(%d+)$")
                if a and b then
                    hopCurrent = math.floor(math.max(1, math.min(100, tonumber(a) + 0.5)))
                    hopMax = math.floor(math.max(1, math.min(100, tonumber(b) + 0.5)))
                    if type(setHopMaxInput) == "function" then
                        setHopMaxInput(tostring(hopMax))
                    end
                    commitAutoHopCfg()
                    return
                end
                warn("[GAG2-AutoHop] Isi Current dan Max di field terpisah (bukan 3/5)")
                return
            end
            local v = tonumber(text)
            if not v then
                warn("[GAG2-AutoHop] Invalid current player: " .. tostring(text))
                return
            end
            v = math.floor(v + 0.5)
            if v < 1 then v = 1 end
            if v > 100 then v = 100 end
            hopCurrent = v
            commitAutoHopCfg()
        end)

        _, setHopMaxInput, commitHopMax = ui:CreateRowInput(bodyHop, "Max Player Target Server", tostring(hopMax), function(text)
            text = tostring(text or ""):gsub("%s+", "")
            if text == "" then return end
            local v = tonumber(text)
            if not v then
                warn("[GAG2-AutoHop] Invalid max player: " .. tostring(text))
                return
            end
            v = math.floor(v + 0.5)
            if v < 1 then v = 1 end
            if v > 100 then v = 100 end
            hopMax = v
            commitAutoHopCfg()
        end)

        _, setHopDelayInput, commitHopDelay = ui:CreateRowInput(bodyHop, "Hop Delay (sec)", tostring(hopDelay), function(text)
            text = tostring(text or ""):gsub("%s+", "")
            if text == "" then return end
            local v = tonumber(text)
            if not v then
                warn("[GAG2-AutoHop] Invalid hop delay: " .. tostring(text))
                return
            end
            v = math.floor(v + 0.5)
            if v < 10 then v = 10 end
            if v > 600 then v = 600 end
            hopDelay = v
            commitAutoHopCfg()
        end)

        ui:CreateRowToggle(bodyHop, "Auto Hop", hopEnabled == true, function(on)
            hopEnabled = (on == true)
            commitAutoHopCfg()
        end)

        pcall(function()
            local en, cur, max, dly = peekAutoHopCfg()
            hopEnabled = (en == true)
            hopCurrent = cur
            hopMax = max
            hopDelay = dly
            if type(setHopCurrentInput) == "function" then
                setHopCurrentInput(tostring(cur))
            end
            if type(setHopMaxInput) == "function" then
                setHopMaxInput(tostring(max))
            end
            if type(setHopDelayInput) == "function" then
                setHopDelayInput(tostring(dly))
            end
        end)

        registerFlush("misc_auto_hop", flushHopInputsFromUI)

        bodyHop.Destroying:Connect(function()
            unregisterFlush("misc_auto_hop")
            if type(setHopCurrentInput) == "function" then
                local v = tonumber((tostring(setHopCurrentInput() or ""):gsub("%s+", "")))
                if v then
                    v = math.floor(v + 0.5)
                    if v < 1 then v = 1 end
                    if v > 100 then v = 100 end
                    hopCurrent = v
                end
            end
            if type(setHopMaxInput) == "function" then
                local v = tonumber((tostring(setHopMaxInput() or ""):gsub("%s+", "")))
                if v then
                    v = math.floor(v + 0.5)
                    if v < 1 then v = 1 end
                    if v > 100 then v = 100 end
                    hopMax = v
                end
            end
            if type(setHopDelayInput) == "function" then
                local v = tonumber((tostring(setHopDelayInput() or ""):gsub("%s+", "")))
                if v then
                    v = math.floor(v + 0.5)
                    if v < 10 then v = 10 end
                    if v > 600 then v = 600 end
                    hopDelay = v
                end
            end
            commitAutoHopCfg()
        end)

        ----------------------------------------------------------------
        -- Auto Rejoin Weather (disconnect saat weather match → wait delay → rejoin)
        ----------------------------------------------------------------
        local function getWeatherPredict()
            return G.WeatherPredict or G.WeatherPredictModule
                or rawget(_G, "WeatherPredict") or rawget(_G, "WeatherPredictModule")
        end

        local function getKickTargetOptions()
            local items = {}
            local WP = getWeatherPredict()
            if type(WP) == "table" and type(WP.GetKickTargetOptions) == "function" then
                local ok, res = pcall(WP.GetKickTargetOptions, WP)
                if ok and type(res) == "table" then items = res end
            end
            if #items == 0 then
                local WK = G.WeatherKick or _G.WeatherKick
                if type(WK) == "table" and type(WK.GetWeatherOptions) == "function" then
                    local ok, res = pcall(WK.GetWeatherOptions, WK)
                    if ok and type(res) == "table" then items = res end
                end
            end
            local filtered = {}
            for _, item in ipairs(items) do
                if type(item) == "table" then
                    local key = tostring(item.key or "")
                    if key:sub(1, 2) == "W:" then
                        filtered[#filtered + 1] = item
                    end
                end
            end
            return filtered
        end

        local function wkArrayToMap(list)
            local map = {}
            if type(list) ~= "table" then return map end
            for _, key in ipairs(list) do
                key = tostring(key or "")
                if key:sub(1, 2) == "W:" then
                    map[key] = true
                end
            end
            return map
        end

        local function wkMapToArray(map)
            local list = {}
            for key, on in pairs(map or {}) do
                if on == true and tostring(key):sub(1, 2) == "W:" then
                    list[#list + 1] = tostring(key)
                end
            end
            table.sort(list)
            return list
        end

        local function wkCleanMap(map)
            local out = {}
            for key, on in pairs(map or {}) do
                if on == true and tostring(key):sub(1, 2) == "W:" then
                    out[tostring(key)] = true
                end
            end
            return out
        end

        local function clampWkDelay(n)
            n = math.floor(tonumber(n) or 60)
            if n < 10 then n = 10 end
            if n > 600 then n = 600 end
            return n
        end

        local function peekWeatherKickCfg()
            local readFn = rawget(_G, "readWeatherKickGlobals") or rawget(G, "readWeatherKickGlobals")
            if type(readFn) == "function" then
                local en, selected, weathers, cycles, delay = readFn()
                return en, selected, weathers, cycles, clampWkDelay(delay)
            end
            local rj = getMisc("rejoin") or {}
            local wk = type(rj.weather_kick) == "table" and rj.weather_kick or {}
            local selected = type(wk.selected) == "table" and wk.selected or {}
            return (wk.enabled == true), selected, {}, {}, clampWkDelay(wk.rejoin_delay_sec)
        end

        local function formatWeatherKickList(weathers)
            local parts = {}
            if type(weathers) == "table" then
                for _, w in ipairs(weathers) do
                    table.insert(parts, tostring(w))
                end
            end
            if #parts == 0 then return "none" end
            if #parts <= 3 then return table.concat(parts, ", ") end
            return table.concat(parts, ", ", 1, 3) .. "..."
        end

        local wkEnabled, wkSelectedList, wkWeathers, _, wkDelay = peekWeatherKickCfg()
        wkDelay = clampWkDelay(wkDelay)
        local wkSelectedMap = wkArrayToMap(wkSelectedList)

        local function getWeatherKick()
            return G.WeatherKick or _G.WeatherKick
        end

        local function syncWeatherKickModule(forced)
            local applyFn = rawget(_G, "applyWeatherKickModule") or rawget(G, "applyWeatherKickModule")
            if type(applyFn) ~= "function" then return end
            if forced == true then
                pcall(applyFn, wkEnabled, wkMapToArray(wkSelectedMap), clampWkDelay(wkDelay))
            else
                pcall(applyFn)
            end
        end

        local function commitWeatherKickCfg()
            local selected = wkMapToArray(wkSelectedMap)
            local writeFn = rawget(_G, "writeWeatherKickGlobals") or rawget(G, "writeWeatherKickGlobals")
            if type(writeFn) == "function" then
                writeFn(wkEnabled == true, selected, clampWkDelay(wkDelay))
            else
                patchMisc("rejoin", {
                    weather_kick = {
                        enabled = (wkEnabled == true),
                        selected = selected,
                        rejoin_delay_sec = clampWkDelay(wkDelay),
                    },
                }, { noSync = true })
            end
            syncWeatherKickModule(true)
            saveNow()
        end

        local bodyWeather = createSection("Auto Rejoin Weather", false)

        local _, wkLiveLbl = ui:CreateRowLabel(bodyWeather, "Phase: ? · Weather: ?", nil, nil, "info")
        local _, wkStatusLbl = ui:CreateRowLabel(bodyWeather, "Status: off", nil, nil, "accent")

        task.spawn(function()
            while bodyWeather and bodyWeather.Parent do
                pcall(function()
                    local livePhase = workspace:GetAttribute("ActivePhase")
                    local liveWeather = workspace:GetAttribute("ActiveWeather")
                    local mapLive = {}
                    local WP = getWeatherPredict()
                    if type(WP) == "table" and type(WP.GetLiveMapWeathers) == "function" then
                        local ok, list = pcall(WP.GetLiveMapWeathers, WP)
                        if ok and type(list) == "table" then
                            mapLive = list
                        end
                    end
                    if wkLiveLbl and wkLiveLbl.Parent then
                        local mapText = (#mapLive > 0) and table.concat(mapLive, ", ") or nil
                        if mapText then
                            wkLiveLbl.Text = ("Phase: %s · Weather: %s · Map: %s"):format(
                                tostring(livePhase or "?"),
                                tostring(liveWeather or "?"),
                                mapText
                            )
                        else
                            wkLiveLbl.Text = ("Phase: %s · Weather: %s"):format(
                                tostring(livePhase or "?"),
                                tostring(liveWeather or "?")
                            )
                        end
                    end
                    if wkStatusLbl and wkStatusLbl.Parent then
                        local txt = "Status: off"
                        local waitingText = formatWeatherKickList(wkWeathers)
                        if wkEnabled == true then
                            local WK = getWeatherKick()
                            if type(WK) == "table" and type(WK.GetStatus) == "function" then
                                local ok, st = pcall(WK.GetStatus, WK)
                                if ok and type(st) == "table" then
                                    local sec = tonumber(st.rejoin_delay_sec) or tonumber(wkDelay) or 60
                                    if st.kickBusy == true or st.matched == true then
                                        txt = ("Status: matched DISCONNECTING ( Waiting %d sec rejoin )"):format(sec)
                                    else
                                        txt = ("Status: waiting %s"):format(
                                            tostring(st.selected_text or waitingText)
                                        )
                                    end
                                else
                                    txt = ("Status: waiting %s"):format(waitingText)
                                end
                            else
                                txt = ("Status: waiting %s"):format(waitingText)
                            end
                        end
                        wkStatusLbl.Text = txt
                    end
                end)
                task.wait(1)
            end
        end)

        ui:CreateRowDropdown(bodyWeather, {
            label = "Weather",
            placeholder = "Select weather...",
            mode = "multi",
            deferItemLoad = true,
            getItems = getKickTargetOptions,
            initial = wkSelectedMap,
            onChanged = function(_, selectedMap)
                wkSelectedMap = wkCleanMap(selectedMap)
                wkWeathers = {}
                for _, key in ipairs(wkMapToArray(wkSelectedMap)) do
                    wkWeathers[#wkWeathers + 1] = key:sub(3)
                end
                commitWeatherKickCfg()
            end,
        })

        local _, setWkDelayInput = ui:CreateRowInput(bodyWeather, "Rejoin Delay After Disconnecting (sec)", tostring(wkDelay), function(text)
            text = tostring(text or ""):gsub("%s+", "")
            if text == "" then return end
            local v = tonumber(text)
            if not v then
                warn("[GAG2-WeatherKick] Invalid rejoin delay: " .. tostring(text))
                return
            end
            wkDelay = clampWkDelay(v)
            commitWeatherKickCfg()
        end)

        ui:CreateRowToggle(bodyWeather, "Auto Rejoin Weather", wkEnabled == true, function(on)
            wkEnabled = (on == true)
            commitWeatherKickCfg()
        end)

        pcall(function()
            local en, selected, weathers, cycles, delay = peekWeatherKickCfg()
            wkEnabled = (en == true)
            wkDelay = clampWkDelay(delay)
            wkSelectedMap = wkArrayToMap(selected)
            wkWeathers = {}
            for _, key in ipairs(selected or {}) do
                key = tostring(key)
                if key:sub(1, 2) == "W:" then
                    wkWeathers[#wkWeathers + 1] = key:sub(3)
                end
            end
            local writeFn = rawget(_G, "writeWeatherKickGlobals") or rawget(G, "writeWeatherKickGlobals")
            if type(writeFn) == "function" then
                writeFn(wkEnabled == true, wkMapToArray(wkSelectedMap), clampWkDelay(wkDelay))
            end
            if type(setWkDelayInput) == "function" then
                setWkDelayInput(tostring(wkDelay))
            end
        end)

        syncWeatherKickModule(false)

        if #sectionSetters >= 1 then
            sectionSetters[1](true)
            for i = 2, #sectionSetters do
                sectionSetters[i](false)
            end
        end

        syncReconnectModule()
        syncAutoHopModule(false)
        syncWeatherKickModule(false)
    end, 1)

    ui:RegisterSubTab("misc", "prediction", "Prediction", function()
        ui:ClearSubContent()

        local COLOR_YELLOW = Color3.fromRGB(255, 211, 0)
        local COLOR_PANEL  = Color3.fromRGB(15, 15, 15)
        local COLOR_LIVE   = Color3.fromRGB(120, 255, 175)
        local COLOR_MUTED  = Color3.fromRGB(175, 178, 190)
        local MOON_PALETTE = {
            Color3.fromRGB(255, 140, 220),
            Color3.fromRGB(255, 210, 90),
            Color3.fromRGB(255, 95, 95),
            Color3.fromRGB(180, 200, 255),
            Color3.fromRGB(140, 255, 200),
        }

        local sectionSetters = {}
        local function createSection(title, defaultOpen)
            local body, setExpanded = ui:CreateSection(title, defaultOpen or false)
            table.insert(sectionSetters, setExpanded)
            return body
        end

        local function moonLineColor(name)
            if type(name) ~= "string" then return COLOR_MUTED end
            local idx = 0
            for i = 1, #name do
                idx = (idx + string.byte(name, i)) % #MOON_PALETTE
            end
            return MOON_PALETTE[idx + 1]
        end

        local function lineColor(line)
            if line.live then return COLOR_LIVE end
            if line.kind == "moon" and line.moon then
                return moonLineColor(line.moon)
            end
            if line.kind == "divider" then return COLOR_YELLOW end
            return COLOR_MUTED
        end

        local function getWeatherPredict()
            return G.WeatherPredict or _G.WeatherPredict
                or G.WeatherPredictModule or _G.WeatherPredictModule
        end

        local bodyMain = createSection("Weather Prediction", true)

        local function syncWeatherModule(on)
            on = (on == true)
            patchMisc("weather_predict", { enabled = on }, function()
                local WP = getWeatherPredict()
                if type(WP) == "table" then
                    if on then
                        if type(WP.Start) == "function" then
                            pcall(WP.Start, WP)
                        elseif type(WP.SetEnabled) == "function" then
                            pcall(WP.SetEnabled, WP, true)
                        end
                    else
                        if type(WP.Stop) == "function" then
                            pcall(WP.Stop, WP)
                        elseif type(WP.SetEnabled) == "function" then
                            pcall(WP.SetEnabled, WP, false)
                        end
                    end
                elseif type(G.__GAG2_SYNC_WEATHER_PREDICT) == "function" then
                    pcall(G.__GAG2_SYNC_WEATHER_PREDICT)
                else
                    warn("[GAG2] WeatherPredict belum loaded — toggle disimpan, overlay nyala setelah rejoin")
                end
            end)
        end

        local enabled = (WEATHER_PREDICT_ENABLED == true)

        ui:CreateRowLabel(bodyMain, "Overlay prediksi cycle, moon & map weather.", nil, 2, "info")

        local previewHost = Instance.new("Frame")
        previewHost.Name = "WxPreviewHost"
        previewHost.BackgroundTransparency = 1
        previewHost.Size = UDim2.new(1, 0, 0, 0)
        previewHost.AutomaticSize = Enum.AutomaticSize.Y
        previewHost.LayoutOrder = 3
        previewHost.Parent = bodyMain

        local previewLayout = Instance.new("UIListLayout")
        previewLayout.Padding = UDim.new(0, 6)
        previewLayout.SortOrder = Enum.SortOrder.LayoutOrder
        previewLayout.Parent = previewHost

        local statusRow = Instance.new("Frame")
        statusRow.Name = "StatusRow"
        statusRow.BackgroundColor3 = COLOR_PANEL
        statusRow.Size = UDim2.new(1, 0, 0, 52)
        statusRow.BorderSizePixel = 0
        statusRow.LayoutOrder = 1
        statusRow.Parent = previewHost
        Instance.new("UICorner", statusRow).CornerRadius = UDim.new(0, 8)
        local statusStroke = Instance.new("UIStroke")
        statusStroke.Color = COLOR_YELLOW
        statusStroke.Thickness = 1
        statusStroke.Transparency = 0.45
        statusStroke.Parent = statusRow

        local phaseLbl = Instance.new("TextLabel")
        phaseLbl.BackgroundTransparency = 1
        phaseLbl.Position = UDim2.fromOffset(10, 8)
        phaseLbl.Size = UDim2.new(1, -20, 0, 18)
        phaseLbl.Font = Enum.Font.GothamBold
        phaseLbl.TextSize = 13
        phaseLbl.TextXAlignment = Enum.TextXAlignment.Left
        phaseLbl.TextColor3 = COLOR_YELLOW
        phaseLbl.Text = "—"
        phaseLbl.Parent = statusRow

        local subLbl = Instance.new("TextLabel")
        subLbl.BackgroundTransparency = 1
        subLbl.Position = UDim2.fromOffset(10, 28)
        subLbl.Size = UDim2.new(1, -20, 0, 16)
        subLbl.Font = Enum.Font.Gotham
        subLbl.TextSize = 11
        subLbl.TextXAlignment = Enum.TextXAlignment.Left
        subLbl.TextColor3 = COLOR_MUTED
        subLbl.Text = "—"
        subLbl.Parent = statusRow

        local monitorLbl = Instance.new("TextLabel")
        monitorLbl.BackgroundTransparency = 1
        monitorLbl.Position = UDim2.fromOffset(10, 44)
        monitorLbl.Size = UDim2.new(1, -20, 0, 14)
        monitorLbl.Font = Enum.Font.Gotham
        monitorLbl.TextSize = 10
        monitorLbl.TextXAlignment = Enum.TextXAlignment.Left
        monitorLbl.TextColor3 = COLOR_MUTED
        monitorLbl.Text = enabled and "Overlay: ON" or "Overlay: OFF"
        monitorLbl.TextColor3 = enabled and COLOR_LIVE or COLOR_MUTED
        monitorLbl.Parent = statusRow
        statusRow.Size = UDim2.new(1, 0, 0, 62)

        local function updateMonitorLabel(on)
            if not monitorLbl or not monitorLbl.Parent then return end
            monitorLbl.Text = on and "Overlay: ON" or "Overlay: OFF"
            monitorLbl.TextColor3 = on and COLOR_LIVE or COLOR_MUTED
        end

        ui:CreateRowToggle(bodyMain, "Auto Monitor", enabled, function(on)
            enabled = (on == true)
            updateMonitorLabel(enabled)
            syncWeatherModule(on == true)
        end, 1)

        local listHost = Instance.new("Frame")
        listHost.Name = "ListHost"
        listHost.BackgroundTransparency = 1
        listHost.Size = UDim2.new(1, 0, 0, 0)
        listHost.AutomaticSize = Enum.AutomaticSize.Y
        listHost.LayoutOrder = 2
        listHost.Parent = previewHost

        local listLayout = Instance.new("UIListLayout")
        listLayout.Padding = UDim.new(0, 4)
        listLayout.SortOrder = Enum.SortOrder.LayoutOrder
        listLayout.Parent = listHost

        local cardRows = {}

        local function renderPreview()
            if not previewHost or not previewHost.Parent then return end
            if not phaseLbl or not phaseLbl.Parent then return end

            local lines = {}
            local WP = getWeatherPredict()
            if type(WP) == "table" and type(WP.GetLines) == "function" then
                local ok, got = pcall(WP.GetLines, WP)
                if ok and type(got) == "table" then lines = got end
            end

            if #lines == 0 then
                phaseLbl.Text = "No data"
                subLbl.Text = "Join server / wait cycle"
                for _, row in ipairs(cardRows) do
                    if row.frame then row.frame.Visible = false end
                end
                return
            end

            local first = lines[1]
            if first and first.kind == "cycle" then
                phaseLbl.Text = tostring(first.text or "—")
                subLbl.Text = tostring(first.sub or "")
                subLbl.TextColor3 = first.live and COLOR_LIVE or COLOR_MUTED
            end

            local showIdx = 0
            for i, line in ipairs(lines) do
                if line.kind ~= "cycle" then
                    showIdx += 1
                    local card = cardRows[showIdx]
                    if not card then
                        local frame = Instance.new("Frame")
                        frame.BackgroundColor3 = COLOR_PANEL
                        frame.BackgroundTransparency = line.kind == "divider" and 1 or 0.15
                        frame.BorderSizePixel = 0
                        frame.Size = UDim2.new(1, 0, 0, line.kind == "divider" and 20 or 30)
                        frame.Parent = listHost
                        Instance.new("UICorner", frame).CornerRadius = UDim.new(0, 6)

                        local title = Instance.new("TextLabel")
                        title.BackgroundTransparency = 1
                        title.Position = UDim2.fromOffset(8, 4)
                        title.Size = UDim2.new(1, -12, 0, 14)
                        title.Font = Enum.Font.GothamMedium
                        title.TextSize = 11
                        title.TextXAlignment = Enum.TextXAlignment.Left
                        title.Parent = frame

                        local sub = Instance.new("TextLabel")
                        sub.BackgroundTransparency = 1
                        sub.Position = UDim2.fromOffset(8, 18)
                        sub.Size = UDim2.new(1, -12, 0, 12)
                        sub.Font = Enum.Font.Gotham
                        sub.TextSize = 10
                        sub.TextXAlignment = Enum.TextXAlignment.Left
                        sub.TextColor3 = COLOR_MUTED
                        sub.Parent = frame

                        card = { frame = frame, title = title, sub = sub }
                        cardRows[showIdx] = card
                    end

                    card.frame.Visible = true
                    card.frame.LayoutOrder = showIdx
                    card.frame.Size = UDim2.new(1, 0, 0, line.kind == "divider" and 20 or 30)

                    if card.title and card.sub then
                        local col = lineColor(line)
                        if line.kind == "divider" then
                            card.title.Text = "— " .. tostring(line.text or "") .. " —"
                            card.sub.Visible = false
                        else
                            card.title.Text = tostring(line.text or "")
                            card.sub.Text = tostring(line.sub or "")
                            card.sub.Visible = (line.sub or "") ~= ""
                        end
                        card.title.TextColor3 = col
                    end
                end
            end

            for i = showIdx + 1, #cardRows do
                if cardRows[i] and cardRows[i].frame then
                    cardRows[i].frame.Visible = false
                end
            end
        end

        task.spawn(function()
            while previewHost and previewHost.Parent do
                pcall(renderPreview)
                task.wait(1)
            end
        end)

        if #sectionSetters >= 1 then
            sectionSetters[1](true)
        end
    end, 2)

    local PF = G.PetFinder or _G.PetFinder or G.PetFinderModule or _G.PetFinderModule
    if type(PF) == "table" and type(PF.RegisterUI) == "function" then
        pcall(function()
            PF.RegisterUI(ui, STATE, autoSave)
        end)
    end

