        local hidePromptCfg = getMisc("hide_prompt") or {}
        local hidePromptEnabled = (hidePromptCfg.enabled == true) or (G.HIDE_PROMPT_ENABLED == true)

        ui:CreateRowToggle(bodyHidePrompt, "Hide Prompt Teleport", hidePromptEnabled, function(on)
