                if type(G.__GAG2_APPLY_UI_DEFAULTS) == "function" then
                    pcall(G.__GAG2_APPLY_UI_DEFAULTS)
                end
                local mainKey = ui.activeMainKey or "misc"
                local subKey = ui.activeSubKey or "settings"
                if type(ui._setActiveSubTab) == "function" then
                    ui:_setActiveSubTab(mainKey, subKey)
                end
            end)
        end

        G.__GAG2_ON_STATE_RESET = refreshUiAfterReset
        _G.__GAG2_ON_STATE_RESET = refreshUiAfterReset

        ui:CreateRowToggle(
            body,
            "Reset Save / State",
            false,
            function(on)
                if on ~= true then return end
                local resetFn = G.__GAG2_RESET_STATE or rawget(_G, "__GAG2_RESET_STATE")
                if type(resetFn) ~= "function" then
                    warn("[GAG2] Reset handler not available")
                    return
                end
                local ok, err = pcall(resetFn)
                if ok then
                    warn("[GAG2] Save file dihapus. Semua setting dikembalikan ke default.")
                else
                    warn("[GAG2] Reset failed:", tostring(err))
                end
            end,
            nil, nil, true
        )
    end, 4)
end

return M
 end,                      required = true },
    { key = "PSReconnect",             name = "PSReconnect",             factory = function() -- PSReconnect.lua (FULL, DEBUG + HARD GATE)
-- ✅ Rejoin (PS-safe) + optional auto reconnect
-- ✅ Auto Exec STRICT dari save file: autohatch/<username>.json -> rejoin.auto_exec
-- ✅ queue_on_teleport hanya dipanggil jika auto_exec true
-- ✅ QTP chunk cek file lagi di server baru (OFF => skip)
-- ✅ QTP chunk nulis marker file + --warn() (biar kebukti jalan / gak jalan)
-- ✅ Kalau auto_exec ON tapi QTP gagal -> CANCEL teleport (biar gak rejoin tanpa autoexec)
-- ✅ Export ke _G/getgenv: _G.PSReconnect selalu ada
-- ✅ Debounce anti spam prompt

--------------------------------------------------
-- SERVICES
--------------------------------------------------
local Players         = game:GetService("Players")
local TeleportService = game:GetService("TeleportService")
local CoreGui         = game:GetService("CoreGui")
local GuiService      = game:GetService("GuiService")
local HttpService     = game:GetService("HttpService")

local LP = Players.LocalPlayer
if not LP then
    LP = Players:GetPropertyChangedSignal("LocalPlayer"):Wait()
end
local M  = {}

--------------------------------------------------
-- PREVENT MULTI LOAD (module ini)
--------------------------------------------------
local G = (getgenv and getgenv()) or _G
if G.__PSRECONNECT_LOADED and type(G.PSReconnect) == "table"
    and type(G.PSReconnect.RejoinNow) == "function" then
    return G.PSReconnect
end

--------------------------------------------------
-- CONFIG
--------------------------------------------------
local SCRIPT_URL                ="https://golaspay.net/scv/uA55bVTKKYY3f?psreconnect=1&key=xzlncM2dOhQLfeTe"
local SAVE_DIR                   = "growagarden2"
local REJOIN_DELAY_SEC           = 1
local UPDATE_NEW_SERVER_DELAY_SEC = 30
local WEATHER_KICK_REJOIN_DELAY_SEC = 60
local SHUTDOWN_REJOIN_DELAY_SEC  = 1
local PROMPT_DISMISS_SEC         = 2
local DEBUG_PSRECONNECT          = false

local function normText(s)
    s = tostring(s or "")
    s = s:gsub("%s+", " ")
    s = s:gsub("^%s+", "")
    s = s:gsub("%s+$", "")
    return s
end

local function dprint(...)
    if not DEBUG_PSRECONNECT then return end
    print("[PSReconnect]", ...)
end

-- debounce
local _rejoinInFlight       = false
local _shutdownRejoinBusy   = false
local _lastRejoinT          = 0
local MIN_REJOIN_INTERVAL   = 6
local _teleportAntiPromptStarted = false
local _hideTeleportPromptEnabled = false

local function _hidePromptGloballyEnabled()
    if _hideTeleportPromptEnabled == true then
        return true
    end
    local ge = (getgenv and getgenv()) or _G
    return ge.HIDE_PROMPT_ENABLED == true or rawget(_G, "HIDE_PROMPT_ENABLED") == true
end

--------------------------------------------------
-- FLAGS (runtime)
--------------------------------------------------
local TELEPORT_BLOCKED       = false
local AUTO_RECONNECT_ENABLED = true

--------------------------------------------------
-- FILE HELPERS
--------------------------------------------------
local CAN_FS = (type(readfile)=="function" and type(isfile)=="function")

local function safeName(s)
    s = tostring(s or "player")
    s = s:gsub("[^%w%-_.]", "_")
    s = s:gsub("_+", "_")
    return s:sub(1, 48)
end

local function getSaveFile()
    if not LP then return nil end
    return (SAVE_DIR .. "/" .. safeName(LP.Name) .. ".json")
end

-- return: autoReconnect(bool), autoExec(bool)
local function readFlagsFromFile()
    local DEFAULT_RECONNECT = true
    local DEFAULT_EXEC      = false

    if not CAN_FS then
        return DEFAULT_RECONNECT, DEFAULT_EXEC
    end

    local f = getSaveFile()
    if not f or not isfile(f) then
        return DEFAULT_RECONNECT, DEFAULT_EXEC
    end

    local ok, txt = pcall(readfile, f)
    if not ok or type(txt) ~= "string" or txt == "" then
        return DEFAULT_RECONNECT, DEFAULT_EXEC
    end

    local ok2, data = pcall(HttpService.JSONDecode, HttpService, txt)
    if not ok2 or type(data) ~= "table" then
        return DEFAULT_RECONNECT, DEFAULT_EXEC
    end

    local r = {}
    if type(data.rejoin) == "table" then
        r = data.rejoin
    elseif type(data.main) == "table"
        and type(data.main.misc) == "table"
        and type(data.main.misc.rejoin) == "table" then
        r = data.main.misc.rejoin
    elseif type(data.state) == "table" and type(data.state.rejoin) == "table" then
        r = data.state.rejoin
    end

    local autoReconnect = (r.auto_reconnect == true)
    local autoExec      = (r.auto_exec == true)

    return autoReconnect, autoExec
end

local function isAutoReconnectOn()
    if AUTO_RECONNECT_ENABLED == true then
        return true
    end
    if rawget(_G, "AUTO_RECONNECT_ENABLED") == true then
        return true
    end
    local ge = (getgenv and getgenv()) or _G
    if ge.AUTO_RECONNECT_ENABLED == true then
        return true
    end
    return select(1, readFlagsFromFile()) == true
end

--------------------------------------------------
-- QTP RESOLVER
--------------------------------------------------
local function getQTP()
    return queue_on_teleport
        or (syn and syn.queue_on_teleport)
        or (fluxus and fluxus.queue_on_teleport)
        or queueteleport
        or queueonteleport
end

--------------------------------------------------
-- LOADER GUARD RESET (cegah loader skip)
--------------------------------------------------
local function resetLoaderGuards()
    local GG = (getgenv and getgenv()) or _G
    GG.__NODEHUB_LOADED = nil
    GG.__NODEHUB_LOADED_SESSION = nil
    GG.__NODEHUB_AUTOEXECED = nil
    GG.__MAINUI_LOADED = nil
    GG.__UI_LOADED = nil
    GG.__GROWAGARDEN2_RUNNING = nil
end

--------------------------------------------------
-- QUEUE ON TELEPORT (STRICT GATED + DEBUG MARKER)
--------------------------------------------------
local function QueueAutoExecIfEnabled()
    local _, autoExec = readFlagsFromFile()
    if autoExec ~= true then
        return false, "auto_exec=false"
    end

    local qtp = getQTP()
    if not qtp then
        return false, "qtp not found"
    end

    local template = [[
        task.wait(3)

        local url = "__URL__"
        local SAVE_DIR = "__SAVE_DIR__"

        local Players = game:GetService("Players")
        local HttpService = game:GetService("HttpService")

        --warn("[QTP] running | SAVE_DIR=", SAVE_DIR, "| url=", url)
        --warn("[QTP] fs types:", type(readfile), type(isfile), type(writefile), type(makefolder))

        local function safeName(s)
            s = tostring(s or "player")
            s = s:gsub("[^%w%-_.]", "_")
            s = s:gsub("_+", "_")
            return s:sub(1, 48)
        end

        local function readAutoExecAndFile()
            if type(readfile)~="function" or type(isfile)~="function" then
                return false, nil
            end
            local lp = Players.LocalPlayer
            if not lp then return false, nil end

            local f = (SAVE_DIR .. "/" .. safeName(lp.Name) .. ".json")
            local ex = isfile(f)
            --warn("[QTP] file=", f, "exists=", ex)

            if not ex then return false, f end

            local ok, txt = pcall(readfile, f)
            if not ok or type(txt)~="string" or txt=="" then
                return false, f
            end

            local ok2, data = pcall(HttpService.JSONDecode, HttpService, txt)
            if not ok2 or type(data)~="table" then
                return false, f
            end

            local r
            if type(data.rejoin)=="table" then
                r = data.rejoin
            elseif type(data.state)=="table" and type(data.state.rejoin)=="table" then
                r = data.state.rejoin
            else
                r = {}
            end

            return (r.auto_exec == true), f
        end

        local enabled, fpath = readAutoExecAndFile()

        -- marker: buktiin chunk jalan
        pcall(function()
            if type(writefile)=="function" then
                -- coba bikin folder kalau belum ada
                if type(makefolder)=="function" and type(isfolder)=="function" then
                    if not isfolder(SAVE_DIR) then pcall(makefolder, SAVE_DIR) end
                end
                writefile(SAVE_DIR .. "/_qtp_ran.txt", "ran@"..os.time().."\nfile="..tostring(fpath).."\nenabled="..tostring(enabled))
            end
        end)

        if enabled ~= true then
            --warn("[QTP] auto_exec OFF in new server -> skip load")
            return
        end

        -- reset guard supaya loader tidak skip
        local G = (getgenv and getgenv()) or _G
        G.__NODEHUB_LOADED = nil
        G.__NODEHUB_LOADED_SESSION = nil
        G.__NODEHUB_AUTOEXECED = nil
        G.__MAINUI_LOADED = nil
        G.__UI_LOADED = nil

        local src
        for i=1,5 do
            local ok, res = pcall(function() return game:HttpGet(url) end)
            if ok and type(res)=="string" and #res>0 then
                src = res
                break
            end
            --warn("[QTP] HttpGet fail #"..i, res)
            task.wait(1.5)
        end

        if not src then
            --warn("[QTP] no src -> abort")
            return
        end

        local ok3, err3 = pcall(function()
            loadstring(src)()
        end)

        --warn("[QTP] load result:", ok3, err3)
    ]]

    local chunk = template
        :gsub("__URL__", tostring(SCRIPT_URL))
        :gsub("__SAVE_DIR__", tostring(SAVE_DIR))

    local ok, err = pcall(function()
        qtp(chunk)
    end)

    if not ok then
        return false, tostring(err)
    end
    return true, "queued"
end

--------------------------------------------------
-- ROBLOX PROMPT AUTO-DISMISS (teleport gagal saja)
-- Pola sama UpdateNewServer: hide cepat + polling 0.05s
--------------------------------------------------
local function hidePromptFast()
    if not _hidePromptGloballyEnabled() then
        return
    end
    pcall(function()
        GuiService:ClearError()
    end)

    pcall(function()
        local gui = CoreGui:FindFirstChild("RobloxPromptGui")
        if not gui then
            return
        end

        gui.Enabled = false

        for _, v in ipairs(gui:GetDescendants()) do
            if v:IsA("GuiObject") then
                v.Visible = false
            end
        end
    end)
end

local function restorePromptGui()
    pcall(function()
        local gui = CoreGui:FindFirstChild("RobloxPromptGui")
        if not gui then
            return
        end
        gui.Enabled = true
        local overlay = gui:FindFirstChild("promptOverlay")
        if overlay and overlay:IsA("GuiObject") then
            overlay.Visible = true
        end
    end)
end

local function collectGuiText(root)
    local parts = {}
    if not root then return "" end
    for _, v in ipairs(root:GetDescendants()) do
        if v:IsA("TextLabel") or v:IsA("TextButton") or v:IsA("TextBox") then
            local txt = tostring(v.Text or "")
            if txt ~= "" then
                parts[#parts + 1] = txt
            end
        end
    end
    return normText(table.concat(parts, " "))
end

local function getPromptCombinedText()
    local gui = CoreGui:FindFirstChild("RobloxPromptGui")
    if not gui then
        return ""
    end
    return collectGuiText(gui:FindFirstChild("promptOverlay") or gui)
end

local function isShutdownText(t)
    t = string.lower(normText(t))
    return t:find("server telah dimatikan", 1, true)
        or t:find("kode error: 288", 1, true)
        or t:find("server has shut down", 1, true)
        or t:find("error code: 288", 1, true)
end

local function isUpdateNewServerKickText(t)
    t = string.lower(normText(t))
    return t:find("updatenewserver", 1, true) ~= nil
        or t:find("interval reached", 1, true) ~= nil
end

local function isWeatherKickText(t)
    t = string.lower(normText(t))
    return t:find("weatherkick", 1, true) ~= nil
end

local function isDisconnectText(t)
    t = string.lower(normText(t))
    return t:find("error", 1, true)
        or t:find("disconnected", 1, true)
        or t:find("lost connection", 1, true)
        or t:find("kicked", 1, true)
        or t:find("dikeluarkan", 1, true)
        or t:find("reconnect", 1, true)
        or t:find("koneksi terputus", 1, true)
        or t:find("hubungkan kembali", 1, true)
end

local function isTeleportProblemText(t)
    t = string.lower(normText(t))
    if t == "" then
        return false
    end

    if isShutdownText(t) or isUpdateNewServerKickText(t) or isWeatherKickText(t) then
        return false
    end

    if t:find("teleportasi gagal", 1, true)
        or t:find("teleport failed", 1, true)
        or t:find("teleportation failed", 1, true)
        or t:find("game full", 1, true)
        or t:find("server full", 1, true)
        or t:find("server penuh", 1, true)
        or t:find("gameended", 1, true)
        or t:find("previous teleport", 1, true)
        or t:find("isteleporting", 1, true)
        or t:find("in processing", 1, true)
        or t:find("unable to teleport", 1, true)
        or t:find("teleport bermasalah", 1, true)
        or t:find("join failed", 1, true)
        or t:find("unable to join", 1, true)
        or t:find("could not find requested game", 1, true)
        or t:find("requested game instance", 1, true)
        or t:find("instance has shutdown", 1, true)
        or t:find("kode eror: 772", 1, true)
        or t:find("error code: 772", 1, true)
        or t:find("kode error: 772", 1, true)
        or t:find("kode eror: 773", 1, true)
        or t:find("error code: 773", 1, true)
        or t:find("kode error: 773", 1, true)
        or t:find("dibatasi", 1, true)
        or t:find("restricted", 1, true)
        or t:find("coba lagi nanti", 1, true)
    then
        return true
    end

    if t:find("penuh", 1, true) and (t:find("server", 1, true) or t:find("game", 1, true)) then
        return true
    end

    if (t:find("teleport", 1, true) or t:find("teleportasi", 1, true))
        and (t:find("fail", 1, true) or t:find("gagal", 1, true) or t:find("problem", 1, true)
            or t:find("error", 1, true) or t:find("eror", 1, true) or t:find("masalah", 1, true))
    then
        return true
    end

    return false
end

local function maybeHideTeleportPrompt()
    if not _hidePromptGloballyEnabled() then
        return
    end
    local combined = getPromptCombinedText()
    if isTeleportProblemText(combined) then
        hidePromptFast()
    end
end

local function startTeleportAntiPrompt()
    if _teleportAntiPromptStarted then
        return
    end
    _teleportAntiPromptStarted = true

    task.spawn(function()
        local gui = CoreGui:WaitForChild("RobloxPromptGui", 120)
        if gui then
            pcall(function()
                gui.DescendantAdded:Connect(function()
                    task.defer(maybeHideTeleportPrompt)
                end)
            end)
            pcall(function()
                gui:GetPropertyChangedSignal("Enabled"):Connect(function()
                    if gui.Enabled then
                        task.defer(maybeHideTeleportPrompt)
                    end
                end)
            end)
        end
    end)

    task.spawn(function()
        while true do
            pcall(maybeHideTeleportPrompt)
            task.wait(0.02)
        end
    end)
end

--------------------------------------------------
-- TELEPORT BLOCK (private/restricted)
--------------------------------------------------
TeleportService.TeleportInitFailed:Connect(function(player, result, errMsg)
    if player ~= LP then return end
    local m = string.lower(errMsg or "")
    -- GameFull / server penuh jangan block rejoin manual
    if result == Enum.TeleportResult.GameFull
        or m:find("game full", 1, true)
        or m:find("server penuh", 1, true)
        or m:find("772", 1, true) then
        hidePromptFast()
        return
    end
    if result == Enum.TeleportResult.Unauthorized
        or m:find("restricted")
        or m:find("private")
        or m:find("not authorized") then
        TELEPORT_BLOCKED = true
    end
    hidePromptFast()
end)

--------------------------------------------------
-- REJOIN CORE
--------------------------------------------------
local function doTeleport(ignoreBlock)
    if not LP then
        return false, "no LocalPlayer"
    end
    if TELEPORT_BLOCKED and ignoreBlock ~= true then
        return false, "blocked"
    end
    local ok, err = pcall(function()
        TeleportService:Teleport(game.PlaceId, LP)
    end)
    if not ok then return false, tostring(err) end
    return true
end

local function canTriggerRejoin()
    local now = os.clock()
    if _rejoinInFlight then return false end
    if (now - _lastRejoinT) < MIN_REJOIN_INTERVAL then return false end
    _lastRejoinT = now
    return true
end

local function tryRejoin()
    if not canTriggerRejoin() then return end
    _rejoinInFlight = true

    local pendingUNS = (G.__UPDATE_NEW_SERVER_REJOIN_PENDING == true)
    local pendingWK = (G.__WEATHER_KICK_REJOIN_PENDING == true)
    if not pendingUNS and not pendingWK and not isAutoReconnectOn() then
        _rejoinInFlight = false
        return
    end
    if TELEPORT_BLOCKED then
        _rejoinInFlight = false
        return
    end

    local delaySec = REJOIN_DELAY_SEC
    if pendingUNS then
        delaySec = UPDATE_NEW_SERVER_DELAY_SEC
    elseif pendingWK then
        local cfgDelay = tonumber(G.WEATHER_KICK_REJOIN_DELAY_SEC) or tonumber(rawget(_G, "WEATHER_KICK_REJOIN_DELAY_SEC"))
        delaySec = tonumber(cfgDelay) or WEATHER_KICK_REJOIN_DELAY_SEC
    end

    task.delay(delaySec, function()
        if pendingUNS then
            G.__UPDATE_NEW_SERVER_REJOIN_PENDING = nil
            _G.__UPDATE_NEW_SERVER_REJOIN_PENDING = nil
        end
        if pendingWK then
            G.__WEATHER_KICK_REJOIN_PENDING = nil
            _G.__WEATHER_KICK_REJOIN_PENDING = nil
        end

        local okQ, reasonQ = QueueAutoExecIfEnabled()
        dprint("queue (auto) =>", okQ, reasonQ)

        if okQ then task.wait(0.8) end
        doTeleport()

        task.delay(2, function()
            _rejoinInFlight = false
        end)
    end)
end

local function tryShutdownRejoin()
    if _shutdownRejoinBusy then
        dprint("shutdown rejoin skipped: already busy")
        return
    end

    if not isAutoReconnectOn() then
        dprint("shutdown rejoin skipped: auto reconnect OFF")
        return
    end

    if TELEPORT_BLOCKED then
        dprint("shutdown rejoin skipped: teleport blocked")
        return
    end

    _shutdownRejoinBusy = true
    dprint("shutdown prompt detected -> wait", SHUTDOWN_REJOIN_DELAY_SEC, "sec")

    task.delay(SHUTDOWN_REJOIN_DELAY_SEC, function()
        local _, ax = readFlagsFromFile()

        if ax == true then
            local okQ, reasonQ = QueueAutoExecIfEnabled()
            dprint("shutdown queue =>", okQ, reasonQ)

            -- HARD GATE: kalau auto_exec ON tapi queue gagal, cancel teleport
            if not okQ then
                dprint("shutdown teleport CANCEL: QTP failed while auto_exec ON:", reasonQ)
                _shutdownRejoinBusy = false
                return
            end

            task.wait(0.8)
        end

        local okTp, errTp = doTeleport()
        dprint("shutdown teleport result =>", okTp, errTp)

        task.delay(2, function()
            _shutdownRejoinBusy = false
        end)
    end)
end

local function hookPrompt()
    task.spawn(function()
        local gui = CoreGui:WaitForChild("RobloxPromptGui", 30)
        if not gui then
            dprint("RobloxPromptGui not found")
            return
        end

        local overlay = gui:WaitForChild("promptOverlay", 30)
        if not overlay then
            dprint("promptOverlay not found")
            return
        end

        dprint("prompt hook attached")

        local function scan()
            local combined = collectGuiText(overlay)

            if isTeleportProblemText(combined) then
                hidePromptFast()
                return
            end

            for _, v in ipairs(overlay:GetDescendants()) do
                if v:IsA("TextLabel") or v:IsA("TextButton") then
                    local txt = tostring(v.Text or "")
                    if txt ~= "" then
                        dprint("label:", txt)
                    end

                    -- PRIORITAS 1: shutdown / server dimatikan / error 288
                    if isShutdownText(txt) or isShutdownText(combined) then
                        tryShutdownRejoin()
                        return
                    end

                    -- PRIORITAS 2: kick UpdateNewServer
                    if isUpdateNewServerKickText(txt) or isUpdateNewServerKickText(combined) then
                        G.__UPDATE_NEW_SERVER_REJOIN_PENDING = true
                        _G.__UPDATE_NEW_SERVER_REJOIN_PENDING = true
                        tryRejoin()
                        return
                    end

                    -- PRIORITAS 2b: kick WeatherKick
                    if isWeatherKickText(txt) or isWeatherKickText(combined) then
                        G.__WEATHER_KICK_REJOIN_PENDING = true
                        _G.__WEATHER_KICK_REJOIN_PENDING = true
                        tryRejoin()
                        return
                    end

                    -- PRIORITAS 3: disconnect umum (bukan teleport gagal)
                    if (isDisconnectText(txt) or isDisconnectText(combined))
                        and not isTeleportProblemText(combined)
                    then
                        if G.__WEATHER_KICK_REJOIN_PENDING == true
                            or _G.__WEATHER_KICK_REJOIN_PENDING == true then
                            tryRejoin()
                        elseif isAutoReconnectOn() then
                            tryRejoin()
                        end
                        return
                    end
                end
            end
        end

        scan()
        overlay.DescendantAdded:Connect(function(obj)
            dprint("DescendantAdded:", obj.ClassName, obj.Name)
            task.defer(function()
                maybeHideTeleportPrompt()
                scan()
            end)
        end)

        pcall(function()
            overlay:GetPropertyChangedSignal("Visible"):Connect(function()
                if overlay.Visible then
                    task.defer(scan)
                end
            end)
        end)

        pcall(function()
            gui:GetPropertyChangedSignal("Enabled"):Connect(function()
                if gui.Enabled then
                    task.defer(scan)
                end
            end)
        end)

        while true do
            task.wait(0.35)
            scan()
        end
    end)
end

hookPrompt()
startTeleportAntiPrompt()

--------------------------------------------------
-- INIT (ikuti file)
--------------------------------------------------
do
    local fileAutoReconnect = select(1, readFlagsFromFile())
    AUTO_RECONNECT_ENABLED = (fileAutoReconnect == true)
end

--------------------------------------------------
-- API FOR UI
--------------------------------------------------
function M.SetHideTeleportPrompt(on)
    _hideTeleportPromptEnabled = (on == true)
    G.HIDE_PROMPT_ENABLED = _hideTeleportPromptEnabled
    _G.HIDE_PROMPT_ENABLED = _hideTeleportPromptEnabled
    startTeleportAntiPrompt()
    if _hideTeleportPromptEnabled then
        hidePromptFast()
    else
        restorePromptGui()
    end
end

M.RestoreTeleportPrompt = restorePromptGui

function M.SyncFromState(state)
    state = type(state) == "table" and state or G.STATE or rawget(_G, "STATE")
    local on = _hidePromptGloballyEnabled()

    if type(state) == "table" and type(state.hide_prompt) == "table" then
        on = (state.hide_prompt.enabled == true)
    end

    local main = G.MAIN or rawget(_G, "MAIN")
    if type(main) == "table" and type(main.misc) == "table" and type(main.misc.hide_prompt) == "table" then
        on = (main.misc.hide_prompt.enabled == true)
    end

    M.SetHideTeleportPrompt(on)
end

function M.SetEnabled(a, b)
    local on = a
    if type(a) == "table" and b ~= nil then
        on = b
    end
    AUTO_RECONNECT_ENABLED = (on == true)
end

function M.SetDelay(sec)
    REJOIN_DELAY_SEC = tonumber(sec) or REJOIN_DELAY_SEC
end

function M.TryRejoinNow()
    tryRejoin()
end

function M.RejoinOnce(delaySec)
    delaySec = tonumber(delaySec) or 0
    task.delay(math.max(0, delaySec), function()
        tryRejoin()
    end)
end

function M.ClearTeleportBlock()
    TELEPORT_BLOCKED = false
    return true
end

function M.ReleaseHopTeleportLock()
    local AH = G.AutoHopServer or rawget(_G, "AutoHopServer")
    if type(AH) == "table" and type(AH.ReleaseTeleportLock) == "function" then
        pcall(AH.ReleaseTeleportLock, AH)
    end
end

function M.RejoinNow()
    _rejoinInFlight = false
    TELEPORT_BLOCKED = false
    M.ReleaseHopTeleportLock()

    local _, ax = readFlagsFromFile()

    if ax == true then
        local okQ, reasonQ = QueueAutoExecIfEnabled()
        if not okQ then
            return false, reasonQ
        end
        task.wait(0.8)
    end

    for attempt = 1, 6 do
        local ok, err = doTeleport(true)
        if ok then
            return true, "teleporting"
        end
        dprint("RejoinNow attempt", attempt, err)
        task.wait(math.min(2 + attempt * 0.5, 6))
    end

    return false, "teleport_failed"
end

function M.IsTeleportBlocked()
    return TELEPORT_BLOCKED
end

function M.HideRobloxPrompt()
    hidePromptFast()
end

function M.ScheduleHidePrompt(sec)
    task.delay(tonumber(sec) or PROMPT_DISMISS_SEC, hidePromptFast)
end

function M.DebugPrint()
    local ar, ax = readFlagsFromFile()
    dprint(
        "auto_reconnect=", tostring(ar),
        "| auto_exec=", tostring(ax),
        "| teleport_blocked=", tostring(TELEPORT_BLOCKED),
        "| qtp=", tostring(getQTP() ~= nil),
        "| save=", tostring(getSaveFile())
    )
end

local function fireTravelRemote(toTrade)
    local RS = game:GetService("ReplicatedStorage")
    local TW = RS:WaitForChild("GameEvents"):WaitForChild("TradeWorld")
    local r = TW:WaitForChild(toTrade and "TravelToTradeWorld" or "TravelToMainWorld")

    local ok, err = pcall(function()
        r:FireServer()
    end)
    return ok, err
end

function M.TravelToMarket()
    -- kalau auto_exec ON -> queue loader dulu
    local _, ax = readFlagsFromFile()
    if ax == true then
        local okQ, reasonQ = QueueAutoExecIfEnabled()
        if not okQ then
            -- HARD GATE optional: cancel travel kalau QTP gagal
            return false, "QTP failed: " .. tostring(reasonQ)
        end
        task.wait(0.2)
    end

    return fireTravelRemote(true)
end

function M.TravelToMain()
    local _, ax = readFlagsFromFile()
    if ax == true then
        local okQ, reasonQ = QueueAutoExecIfEnabled()
        if not okQ then
            return false, "QTP failed: " .. tostring(reasonQ)
        end
        task.wait(0.2)
    end

    return fireTravelRemote(false)
end

