local function defaultWeatherName()
    local WP = getWeatherPredict()
    if type(WP) == "table" and type(WP.GetWeatherNames) == "function" then
        local ok, names = pcall(WP.GetWeatherNames, WP)
        if ok and type(names) == "table" and type(names[1]) == "string" and names[1] ~= "" then
            return names[1]
        end
    end
    return ""
