    local weathers, cycles = {}, {}
    local seenW = {}
    if type(selected) ~= "table" then return weathers, cycles end
    for _, rawKey in ipairs(selected) do
        local key = tostring(rawKey or "")
        if key:sub(1, 2) == PREFIX_WEATHER then
            local name = key:sub(3)
            if name ~= "" and not seenW[name] then
                seenW[name] = true
                table.insert(weathers, name)
            end
        end
    end
    table.sort(weathers)
    return weathers, cycles
end

local function buildSelectedFromLegacy(wk)
    local selected, seen = {}, {}
    local function add(key)
        key = tostring(key or "")
        if key == "" or seen[key] then return end
        if key:sub(1, 2) ~= PREFIX_WEATHER then return end
        seen[key] = true
        table.insert(selected, key)
    end
    if type(wk.weathers) == "table" then
        for _, name in ipairs(wk.weathers) do
            add(PREFIX_WEATHER .. tostring(name))
        end
    end
    if #selected == 0 and type(wk.weather) == "string" and wk.weather ~= "" then
        add(PREFIX_WEATHER .. wk.weather)
    end
    return selected
