local function normalizeWeathers(input, legacyWeather)
    if type(input) == "table" then
        if type(input.weathers) == "table" then
            return normalizeNameList(input.weathers)
        end
        if type(input.cycles) == "table" or type(input.phases) == "table" then
            return normalizeNameList(nil)
        end
        return normalizeNameList(input, input.weather or input.selected_weather)
    end
    return normalizeNameList(input, legacyWeather)
end

local function normalizeCycles(input)
    if type(input) == "table" then
        if type(input.cycles) == "table" then
            return normalizeNameList(input.cycles)
        end
        if type(input.phases) == "table" then
            return normalizeNameList(input.phases)
        end
    end
    return normalizeNameList(input)
end

local function normalizeSelection(input, legacyWeather, legacyCycles)
    local weathers, cycles

    if type(input) == "table" and (type(input.weathers) == "table" or type(input.cycles) == "table" or type(input.phases) == "table") then
        weathers = normalizeWeathers(input)
        cycles = normalizeCycles(input)
    else
        weathers = normalizeWeathers(input, legacyWeather)
        cycles = normalizeCycles(legacyCycles)
    end

    return weathers, cycles
end

local function selectionToText(weathers)
    local parts = {}
    if type(weathers) == "table" then
        for _, name in ipairs(weathers) do
            table.insert(parts, tostring(name))
        end
    end
    if #parts == 0 then return "?" end
    if #parts <= 3 then
        return table.concat(parts, ", ")
    end
    return table.concat(parts, ", ", 1, 3) .. "..."
end

