    _G.WEATHER_KICK_SELECTED = selected or {}
    _G.WEATHER_KICK_REJOIN_DELAY_SEC = delay
end

local function getMainRejoin()
    local main = G.MAIN or _G.MAIN
    if type(main) == "table" and type(main.misc) == "table" and type(main.misc.rejoin) == "table" then
        return main.misc.rejoin
    end
    return nil
end

local function normalizeWeatherKick(wk)
    wk = type(wk) == "table" and wk or {}
    wk.enabled = (wk.enabled == true)
    if type(wk.selected) == "table" then
        wk.weathers = select(1, splitSelectedKeys(wk.selected))
