    local STATE = G.STATE or _G.STATE
    if type(STATE) == "table" and type(STATE.rejoin) == "table" and type(STATE.rejoin.weather_kick) == "table" then
        local wk = normalizeWeatherKick(STATE.rejoin.weather_kick)
        if enabled == nil then enabled = wk.enabled end
        if weathers == nil or #weathers == 0 then weathers = wk.weathers end
        if delay == nil then delay = wk.rejoin_delay_sec end
