--------------------------------------------------
-- Auto Buy globals
--------------------------------------------------
local function _normalizeBuyItems(items)
    if type(items) ~= "table" then return {} end

    local arr = {}
    for _, v in ipairs(items) do
        if v ~= nil and tostring(v) ~= "" then
            arr[#arr + 1] = tostring(v)
        end
    end
    if #arr > 0 then
        table.sort(arr)
        return arr
    end

    for k, v in pairs(items) do
        if v == true or v == 1 or v == "true" then
            arr[#arr + 1] = tostring(k)
        end
    end
    table.sort(arr)
    return arr
end

local function _normalizeBuyCategory(cat)
    cat = type(cat) == "table" and cat or { enabled = false, items = {} }
    cat.enabled = (cat.enabled == true)
    cat.items = _normalizeBuyItems(cat.items)
    return cat
end

local function _normalizeAutoBuyState(buy)
    buy = type(buy) == "table" and buy or _deepCopy(DEFAULT_AUTO.buy)
    buy.delay = nil
    buy.seed = _normalizeBuyCategory(buy.seed)
    buy.gear = _normalizeBuyCategory(buy.gear)
    buy.props = _normalizeBuyCategory(buy.props)
    buy.pet = _normalizeBuyCategory(buy.pet)
    buy.pet.auto_tame = (buy.pet.auto_tame == true)
    buy.pet.max_price_mult = nil
    local stealPrice = math.floor(tonumber(buy.pet.max_steal_price) or 100000000)
    stealPrice = math.floor((stealPrice + 12500000) / 25000000) * 25000000
    if stealPrice < 25000000 then stealPrice = 25000000 end
    if stealPrice > 500000000 then stealPrice = 500000000 end
    buy.pet.max_steal_price = stealPrice
    buy.auction = type(buy.auction) == "table" and buy.auction or {
        enabled = false, max_price = 0,
        seed = { items = {} }, gear = { items = {} },
        seedpack = { items = {} }, egg = { items = {} },
    }
    buy.auction.enabled = (buy.auction.enabled == true)
    buy.auction.max_price = math.max(0, math.floor(tonumber(buy.auction.max_price) or 0))
    for _, key in ipairs({ "seed", "gear", "seedpack", "egg" }) do
        local cat = buy.auction[key]
        if type(cat) ~= "table" then cat = { items = {} } end
        cat.items = _normalizeBuyItems(cat.items)
        buy.auction[key] = cat
    end
    return buy
end

