-- Saat save: MAIN = source of truth → snapshot (jangan timpa MAIN dari snapshot stale)
local function _syncAutoHopSnapshotFromMain()
    MAIN.misc = MAIN.misc or _deepCopy(DEFAULT_MISC)
    MAIN.misc.rejoin = MAIN.misc.rejoin or _deepCopy(DEFAULT_MISC.rejoin)
    local ah = _normalizeAutoHopState(MAIN.misc.rejoin.auto_hop)
    MAIN.misc.rejoin.auto_hop = ah

    G.__AUTO_HOP_SAVED = {
        enabled = ah.enabled,
        current = ah.current_player,
        max = ah.max_player,
        delay = ah.teleport_delay,
    }
    _G.__AUTO_HOP_SAVED = G.__AUTO_HOP_SAVED
end

-- Hop cuma update visited — jangan full save (bisa overwrite setting UI ke default)
local function saveAutoHopVisitedOnly(visited)
    if not CAN_FS or not _ensureFolder() then return end

    local out = {}
    if type(visited) == "table" then
        for _, v in ipairs(visited) do
            local s = tostring(v or "")
            if s ~= "" then out[#out + 1] = s end
        end
    end

    local data = {}
    if isfile(SAVE_FILE) then
        local ok, text = pcall(readfile, SAVE_FILE)
        if ok and type(text) == "string" and #text > 0 then
            local ok2, parsed = pcall(function()
                return HttpService:JSONDecode(text)
            end)
            if ok2 and type(parsed) == "table" then
                data = parsed
            end
        end
    end

    data.main = type(data.main) == "table" and data.main or {}
    data.main.misc = type(data.main.misc) == "table" and data.main.misc or {}
    data.main.misc.rejoin = type(data.main.misc.rejoin) == "table" and data.main.misc.rejoin or {}
    local ah = type(data.main.misc.rejoin.auto_hop) == "table" and data.main.misc.rejoin.auto_hop or {}
    data.main.misc.rejoin.auto_hop = ah

    MAIN.misc = MAIN.misc or _deepCopy(DEFAULT_MISC)
    MAIN.misc.rejoin = MAIN.misc.rejoin or _deepCopy(DEFAULT_MISC.rejoin)
    local mainAh = _normalizeAutoHopState(MAIN.misc.rejoin.auto_hop)
    MAIN.misc.rejoin.auto_hop = mainAh

    -- Merge setting dari MAIN (bukan cuma dari file stale) supaya delay/current/max tidak reset
    ah.enabled = mainAh.enabled
    ah.current_player = mainAh.current_player
    ah.max_player = mainAh.max_player
    ah.teleport_delay = mainAh.teleport_delay
    ah.minutes = mainAh.minutes
    ah.diff_servers = mainAh.diff_servers
    ah.visited = _deepCopy(out)
    ah.delay = nil

    MAIN.misc.rejoin.auto_hop.visited = _deepCopy(out)
    G.MAIN = MAIN
    _G.MAIN = MAIN

    _syncAutoHopSnapshotFromMain()

    local ok, json = pcall(function()
        return HttpService:JSONEncode(data)
    end)
    if ok and type(json) == "string" then
        pcall(writefile, SAVE_FILE, json)
    end
end

G.__GAG2_SAVE_AUTO_HOP_VISITED = saveAutoHopVisitedOnly
_G.__GAG2_SAVE_AUTO_HOP_VISITED = saveAutoHopVisitedOnly

local function _prepareMainForSave()
    local live = G.MAIN or _G.MAIN
