        MAIN = live
    end
    MAIN.auto = MAIN.auto or _deepCopy(DEFAULT_AUTO)
    MAIN.misc = MAIN.misc or _deepCopy(DEFAULT_MISC)

    _syncAutoHopSnapshotFromMain()

    _safeNormalizeMainAutoForSave()
    syncRejoinGlobalsToMain()
