    syncHidePromptGlobalsToMain()
    syncHideHarvestPromptGlobalsToMain()
    syncHideLoadingGlobalsToMain()
    _syncAllRuntimeFromMain()
    G.MAIN = MAIN
    _G.MAIN = MAIN
end

