                sell = _deepCopy(MAIN.auto.sell),
                shovelFruit = _deepCopy(MAIN.auto.shovelFruit),
                plant = _deepCopy(MAIN.auto.plant),
                trowel = _deepCopy(MAIN.auto.trowel),
                sprinkler = _deepCopy(MAIN.auto.sprinkler),
                watering = _deepCopy(MAIN.auto.watering),
                fav = _deepCopy(MAIN.auto.fav),
                unfav = _deepCopy(MAIN.auto.unfav),
                buy = _deepCopy(MAIN.auto.buy),
                claimSeed = _deepCopy(MAIN.auto.claimSeed),
                autoTele = _deepCopy(MAIN.auto.autoTele),
                gift = _deepCopy(MAIN.auto.gift),
                normalGift = _deepCopy(MAIN.auto.normalGift),
                dropItem = _deepCopy(MAIN.auto.dropItem),
