}

local function _isArrayLike(t)
    if type(t) ~= "table" then return false end
    if t[1] ~= nil then return true end
    return next(t) == nil
end

local function _mergePartialInto(target, partial)
    if type(target) ~= "table" or type(partial) ~= "table" then return target end
    for k, v in pairs(partial) do
        if type(v) == "table" and type(target[k]) == "table"
            and not _isArrayLike(v) and not _isArrayLike(target[k]) then
            _mergePartialInto(target[k], v)
        else
            target[k] = (type(v) == "table") and _deepCopy(v) or v
        end
    end
    return target
end

local function _applyAutoPatch(key, partial)
    if type(key) ~= "string" or type(partial) ~= "table" then return end
    MAIN.auto = MAIN.auto or _deepCopy(DEFAULT_AUTO)
    local cur = type(MAIN.auto[key]) == "table" and _deepCopy(MAIN.auto[key]) or _deepCopy(DEFAULT_AUTO[key] or {})
    _mergePartialInto(cur, partial)
    local norm = AUTO_NORMALIZERS[key]
    MAIN.auto[key] = norm and norm(cur) or cur
    G.MAIN = MAIN
    _G.MAIN = MAIN
end

local MISC_SYNC_FROM_MAIN = {
    rejoin              = syncRejoinGlobalsFromMain,
    weather_predict     = syncWeatherPredictGlobalsFromMain,
    pet_finder          = syncPetFinderGlobalsFromMain,
    perf                = syncReduceFpsGlobalsFromMain,
    fruit_backpack_esp  = syncFruitBackpackEspGlobalsFromMain,
    fruit_garden_esp    = syncFruitGardenEspGlobalsFromMain,
    hide_prompt         = syncHidePromptGlobalsFromMain,
    hide_harvest_prompt = syncHideHarvestPromptGlobalsFromMain,
    hide_loading        = syncHideLoadingGlobalsFromMain,
}

local function _applyMiscPatch(key, partial)
    if type(key) ~= "string" or type(partial) ~= "table" then return end
    MAIN.misc = MAIN.misc or _deepCopy(DEFAULT_MISC)
    if key == "rejoin" then
        local cur = _deepCopy(MAIN.misc.rejoin or DEFAULT_MISC.rejoin)
        local wkReplace = partial.weather_kick
        local partialCopy = _deepCopy(partial)
        if type(wkReplace) == "table" then
            partialCopy.weather_kick = nil
        end
        _mergePartialInto(cur, partialCopy)
        if type(cur.auto_hop) == "table" then
            cur.auto_hop = _normalizeAutoHopState(cur.auto_hop)
        end
        if type(wkReplace) == "table" then
            cur.weather_kick = _normalizeWeatherKickState(_deepCopy(wkReplace))
        elseif type(cur.weather_kick) == "table" then
            cur.weather_kick = _normalizeWeatherKickState(cur.weather_kick)
        end
        MAIN.misc.rejoin = cur
    elseif key == "weather_predict" then
        local cur = _deepCopy(MAIN.misc.weather_predict or DEFAULT_MISC.weather_predict)
        _mergePartialInto(cur, partial)
        cur.enabled = (cur.enabled == true)
        MAIN.misc.weather_predict = cur
    elseif key == "pet_finder" then
        local cur = _deepCopy(MAIN.misc.pet_finder or DEFAULT_MISC.pet_finder)
        _mergePartialInto(cur, partial)
        MAIN.misc.pet_finder = _snapshotPetFinderForSave(cur)
    elseif key == "perf" then
        local cur = _deepCopy(MAIN.misc.perf or DEFAULT_MISC.perf)
        _mergePartialInto(cur, partial)
        MAIN.misc.perf = _normalizePerfState(cur)
    elseif key == "fruit_backpack_esp" then
        local cur = _deepCopy(MAIN.misc.fruit_backpack_esp or DEFAULT_MISC.fruit_backpack_esp)
        _mergePartialInto(cur, partial)
        MAIN.misc.fruit_backpack_esp = _normalizeFruitBackpackEspState(cur)
    elseif key == "fruit_garden_esp" then
        local cur = _deepCopy(MAIN.misc.fruit_garden_esp or DEFAULT_MISC.fruit_garden_esp)
        _mergePartialInto(cur, partial)
        MAIN.misc.fruit_garden_esp = _normalizeFruitGardenEspState(cur)
    elseif key == "hide_prompt" then
        local cur = _deepCopy(MAIN.misc.hide_prompt or DEFAULT_MISC.hide_prompt)
        _mergePartialInto(cur, partial)
        MAIN.misc.hide_prompt = _normalizeHidePromptState(cur)
    elseif key == "hide_harvest_prompt" then
        local cur = _deepCopy(MAIN.misc.hide_harvest_prompt or DEFAULT_MISC.hide_harvest_prompt)
        _mergePartialInto(cur, partial)
        MAIN.misc.hide_harvest_prompt = _normalizeHideHarvestPromptState(cur)
    elseif key == "hide_loading" then
        local cur = _deepCopy(MAIN.misc.hide_loading or DEFAULT_MISC.hide_loading)
        _mergePartialInto(cur, partial)
        MAIN.misc.hide_loading = _normalizeHideLoadingState(cur)
    end
    G.MAIN = MAIN
    _G.MAIN = MAIN
end

function State.getMisc(key)
    if type(key) ~= "string" then return nil end
    MAIN.misc = MAIN.misc or _deepCopy(DEFAULT_MISC)
    if key == "rejoin" then return MAIN.misc.rejoin end
    if key == "weather_predict" then return MAIN.misc.weather_predict end
    if key == "pet_finder" then return MAIN.misc.pet_finder end
    if key == "perf" then return MAIN.misc.perf end
    if key == "fruit_backpack_esp" then return MAIN.misc.fruit_backpack_esp end
    if key == "fruit_garden_esp" then return MAIN.misc.fruit_garden_esp end
    if key == "hide_prompt" then
        MAIN.misc.hide_prompt = _normalizeHidePromptState(MAIN.misc.hide_prompt)
        return MAIN.misc.hide_prompt
    end
    if key == "hide_harvest_prompt" then
        MAIN.misc.hide_harvest_prompt = _normalizeHideHarvestPromptState(MAIN.misc.hide_harvest_prompt)
        return MAIN.misc.hide_harvest_prompt
    end
    if key == "hide_loading" then
        MAIN.misc.hide_loading = _normalizeHideLoadingState(MAIN.misc.hide_loading)
        return MAIN.misc.hide_loading
    end
    return nil
end

function State.patchMisc(key, partial, opts)
    opts = type(opts) == "table" and opts or {}
    if type(key) ~= "string" or type(partial) ~= "table" then
        return State.getMisc(key)
    end
    _applyMiscPatch(key, partial)
    if not opts.noSync then
        local sync = MISC_SYNC_FROM_MAIN[key]
        if sync then sync() end
    end
    return State.getMisc(key)
end

function State.getMain()
    G.MAIN = MAIN
    _G.MAIN = MAIN
    return MAIN
end

function State.getAuto(key)
    if type(key) ~= "string" then return nil end
    _applyAutoPatch(key, {})
    return MAIN.auto[key]
end

function State.patchAuto(key, partial, opts)
    opts = type(opts) == "table" and opts or {}
    if type(key) ~= "string" or type(partial) ~= "table" then
        return State.getAuto(key)
    end
    _applyAutoPatch(key, partial)
    if not opts.noSync then
        local sync = AUTO_SYNC_FROM_MAIN[key]
        if sync then sync() end
    end
    return MAIN.auto[key]
end

function State.registerFlush(id, fn)
    if type(id) == "string" and id ~= "" and type(fn) == "function" then
