 end)()
    end)
    if okFac then
        local ok, mod, state = stateFromModule(modOrErr)
        if ok then
            debuglog("STATE_OK_INLINE")
            return true, mod, state
        end
    end

    -- 2) HTTP fallback via LINK_GAG2_STATE
    if not hasUnreplacedShortcode(STATE_URL) then
        local okBody, bodyOrErr = pcall(httpRequest, STATE_URL)
        if okBody and type(bodyOrErr) == "string" and bodyOrErr ~= "" then
            local chunk, err = loadstring(bodyOrErr)
            if type(chunk) == "function" then
                local okRun, modOrErr = pcall(chunk)
                if okRun then
                    local ok, mod, state = stateFromModule(modOrErr)
                    if ok then
                        debuglog("STATE_OK_HTTP")
                        return true, mod, state
                    end
                    return false, state
                end
                return false, "state run failed: " .. tostring(modOrErr)
            end
            return false, "state loadstring: " .. tostring(err)
        end
        return false, "state http failed: " .. tostring(bodyOrErr)
    end

    return false, "GAG2_STATE inline & LINK_GAG2_STATE gagal"
end

