-- ANTIAFK EARLY (sebelum state HTTP — skip loading screen)
----------------------------------------------------------------
local EarlyAntiafk = nil
for _, def in ipairs(MODULE_DEFS) do
    if def.key == "antiafk" then
        local okRun, modOrErr = runFactory(def)
        if okRun and isValidAntiafkMod(modOrErr) then
            EarlyAntiafk = modOrErr
            G.AntiAFK = modOrErr
            G.antiafk = modOrErr
            _G.AntiAFK = modOrErr
            _G.antiafk = modOrErr
            task.defer(function()
                pcall(function()
                    if type(modOrErr.Start) == "function" then modOrErr:Start()
                    elseif type(modOrErr.start) == "function" then modOrErr:start() end
                end)
            end)
        else
            warnlog("AntiAFK early load gagal:", tostring(modOrErr))
            warnlog("Cek entry GAG2_ANTIAFK di panel (upload antiafk.lua terbaru)")
        end
        break
    end
end

----------------------------------------------------------------
-- LOAD STATE EARLY
----------------------------------------------------------------
local StateModule
local STATE

for attempt = 1, STATE_RETRY do
    local ok, modOrErr, state = loadStateOnce()
    if ok then
        StateModule = modOrErr
        STATE = state
        break
    end
    warnlog("State load gagal:", tostring(modOrErr))
    task.wait(STATE_RETRY_DELAY)
end

if type(STATE) ~= "table" then
    STATE = DEFAULT_STATE_FALLBACK
    warnlog("State fallback dipakai — cek LINK_GAG2_STATE / entry Gag2_state di panel")
end

G.STATE = STATE
_G.STATE = STATE

local function applyHideLoadingRuntime()
    local applyFn = G.applyHideLoadingModule or rawget(_G, "applyHideLoadingModule")
    if type(applyFn) == "function" then
        pcall(applyFn)
    end
end

local function applyHideHarvestPromptRuntime()
    local applyFn = G.applyHideHarvestPromptModule or rawget(_G, "applyHideHarvestPromptModule")
    if type(applyFn) == "function" then
        pcall(applyFn)
    end
end

if StateModule then
    G.__GAG2_STATE = StateModule
    _G.__GAG2_STATE = StateModule
    if type(StateModule.syncAllMisc) == "function" then
        pcall(StateModule.syncAllMisc, StateModule)
    end
    applyHideLoadingRuntime()
    applyHideHarvestPromptRuntime()
end

local function applyHidePromptRuntime()
    local applyFn = G.applyHidePromptModule or rawget(_G, "applyHidePromptModule")
    if type(applyFn) == "function" then
        pcall(applyFn)
        return
    end
    local R = G.PSReconnect or rawget(_G, "PSReconnect")
    local on = (G.HIDE_PROMPT_ENABLED == true) or (rawget(_G, "HIDE_PROMPT_ENABLED") == true)
    if type(R) == "table" and type(R.SetHideTeleportPrompt) == "function" then
        pcall(R.SetHideTeleportPrompt, R, on)
    end
end

----------------------------------------------------------------
-- LOAD MODULE WITH RETRY
----------------------------------------------------------------
local function loadOneModule(def)
    local lastErr = "unknown"
    for attempt = 1, BOOT_RETRY do
        local ok, resultOrErr = runFactory(def)
        if ok then
            return true, resultOrErr
        end
        lastErr = tostring(resultOrErr)
        warnlog(("Load gagal %s %d/%d: %s"):format(tostring(def.name), attempt, BOOT_RETRY, lastErr))
        task.wait(RETRY_DELAY)
    end
    return false, lastErr
end

local Loaded = {}

local function exposeEarlyModules()
    local env = (getgenv and getgenv()) or _G
    if type(Loaded.antiafk) == "table" then
        env.AntiAFK = Loaded.antiafk
        env.antiafk = Loaded.antiafk
        _G.AntiAFK = Loaded.antiafk
        _G.antiafk = Loaded.antiafk
    end
    if type(Loaded.PSReconnect) == "table" then
        env.PSReconnect = Loaded.PSReconnect
        _G.PSReconnect = Loaded.PSReconnect
    end
end

local function startEarlyModules()
    exposeEarlyModules()
    task.defer(function()
        moduleStart(Loaded.antiafk)
    end)
    task.defer(function()
        task.wait(0.2)
        pcall(function()
            callMethod(Loaded.PSReconnect, { "SyncFromState", "syncFromState" }, STATE)
        end)
        moduleStart(Loaded.PSReconnect)
        applyHidePromptRuntime()
    end)
end

local function loadModuleSet(label, filterFn)
    local list = {}
    for _, def in ipairs(MODULE_DEFS) do
        if filterFn(def) then
            list[#list + 1] = def
        end
    end

    for _, def in ipairs(list) do
        if def.key == "antiafk" and EarlyAntiafk then
            Loaded[def.key] = EarlyAntiafk
            continue
        end
        local ok, modOrErr = loadOneModule(def)
        if ok then
            Loaded[def.key] = modOrErr
        elseif def.required then
            failBoot(("required module failed: %s | %s"):format(tostring(def.name), tostring(modOrErr)))
        else
            warnlog("Optional module skip:", tostring(def.name), tostring(modOrErr))
            Loaded[def.key] = {}
        end
    end
end

loadModuleSet("Early", function(def) return def.early == true end)
startEarlyModules()

loadModuleSet("Module", function(def) return def.early ~= true end)

local function ensureLoadedModule(key)
    if isLoadedModule(Loaded[key]) then return Loaded[key] end
    for _, def in ipairs(MODULE_DEFS) do
        if def.key == key then
            warnlog("Retry load", tostring(def.name))
            local ok, modOrErr = loadOneModule(def)
            if ok then
                Loaded[key] = modOrErr
                return modOrErr
            end
            return nil
        end
    end
    return nil
end

G.__GAG2_ENSURE_LOADED_MODULE = ensureLoadedModule
_G.__GAG2_ENSURE_LOADED_MODULE = ensureLoadedModule

