-- UpdateNewServer + WeatherKick harus tersedia sebelum tabs_misc rejoin section
do
    local UNS = UpdateNewServerMod
    if type(UNS) == "table" then
        G.UpdateNewServer = UNS
        _G.UpdateNewServer = UNS
    end
    local WK = WeatherKickMod
    if type(WK) == "table" then
        G.WeatherKick = WK
        _G.WeatherKick = WK
    end

    local applyUNS = rawget(_G, "applyUpdateNewServerModule") or rawget(G, "applyUpdateNewServerModule")
    local readUNS  = rawget(_G, "readUpdateNewServerGlobals") or rawget(G, "readUpdateNewServerGlobals")
    if type(applyUNS) == "function" then
        if type(readUNS) == "function" then
            local en, mi = readUNS()
            pcall(applyUNS, en, mi)
        else
            pcall(applyUNS)
        end
    end

    local applyWK = rawget(_G, "applyWeatherKickModule") or rawget(G, "applyWeatherKickModule")
    local readWK  = rawget(_G, "readWeatherKickGlobals") or rawget(G, "readWeatherKickGlobals")
    if type(applyWK) == "function" then
        if type(readWK) == "function" then
            local en, selected, _, _, delay = readWK()
            pcall(applyWK, en, selected, delay)
        else
            pcall(applyWK)
        end
    end
end

