-- PSReconnect
do
    local R = PSReconnectMod
    if type(R) == "table" then
        G.PSReconnect = R
        _G.PSReconnect = R
        pcall(function()
            if type(R.SetEnabled) == "function" then
                local on = G.AUTO_RECONNECT_ENABLED
                if on == nil then on = rawget(_G, "AUTO_RECONNECT_ENABLED") end
                pcall(R.SetEnabled, on == true)
            end
            if type(R.SyncFromState) == "function" then
                R:SyncFromState(STATE)
            else
                applyHidePromptRuntime()
            end
        end)
    end
end

-- UpdateNewServer
task.defer(function()
    local env = (getgenv and getgenv()) or _G
    local UNS = rawget(_G, "UpdateNewServer") or rawget(env, "UpdateNewServer") or UpdateNewServerMod
    if type(UNS) ~= "table" then return end

    env.UpdateNewServer = UNS
    _G.UpdateNewServer = UNS

    local applyFn = rawget(_G, "applyUpdateNewServerModule") or rawget(env, "applyUpdateNewServerModule")
    local readFn  = rawget(_G, "readUpdateNewServerGlobals") or rawget(env, "readUpdateNewServerGlobals")
    if type(applyFn) == "function" then
        if type(readFn) == "function" then
            local en, mi = readFn()
            pcall(applyFn, en, mi)
        else
            pcall(applyFn)
        end
    end
end)

-- WeatherKick — sync runtime dari saved state
task.defer(function()
    local env = (getgenv and getgenv()) or _G
    local WK = rawget(_G, "WeatherKick") or rawget(env, "WeatherKick") or WeatherKickMod
    if type(WK) ~= "table" then return end

    env.WeatherKick = WK
    _G.WeatherKick = WK

    local applyFn = rawget(_G, "applyWeatherKickModule") or rawget(env, "applyWeatherKickModule")
    local readFn  = rawget(_G, "readWeatherKickGlobals") or rawget(env, "readWeatherKickGlobals")
    if type(applyFn) == "function" then
        if type(readFn) == "function" then
            local en, selected, _, _, delay = readFn()
            pcall(applyFn, en, selected, delay)
        else
            pcall(applyFn)
        end
    end
end)

